#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>
#include <iostream>

class TrieNode {
public:
    bool isEnd;
    std::unordered_map<char, TrieNode*> children;
    int chainLength;

    TrieNode() : isEnd(false), chainLength(1) {}

    ~TrieNode() {
        for (auto& child : children) {
            delete child.second;
        }
    }
};

class WordChain {
private:
    TrieNode* root;

    void insert(const std::string& word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                node->children[c] = new TrieNode();
            }
            node = node->children[c];
        }
        node->isEnd = true;
    }

    int dfs(const std::string& word, TrieNode* node) {
        TrieNode* current = node;
        int maxChainLength = 0;
        for (char c : word) {
            if (current->children.find(c) == current->children.end()) {
                return 0;
            }
            current = current->children[c];
            if (current->isEnd) {
                current->chainLength = std::max(current->chainLength, (current->chainLength == 0 ? 1 : 1 + maxChainLength));
                maxChainLength = std::max(maxChainLength, current->chainLength);
            }
        }
        return maxChainLength;
    }

public:
    WordChain(const std::vector<std::string>& words) {
        root = new TrieNode();
        for (const auto& word : words) {
            insert(word);
        }
    }

    ~WordChain() {
        delete root;
    }

    int longestChain(const std::unordered_map<std::string, std::vector<std::string>>& wordsMap) {
        int longestChainLength = 0;
        auto it = wordsMap.find("abcd");
        if (it != wordsMap.end()) {
            for (const auto& word : it->second) {
                longestChainLength = std::max(longestChainLength, dfs(word, root));
            }
        } else {
            std::cerr << "Error: 'abcd' not found in wordsMap.\n";
        }
        return longestChainLength;
    }
};

int longestWordChain(const std::vector<std::string>& words) {
    std::unordered_map<std::string, std::vector<std::string>> wordsMap;
    for (const auto& word : words) {
        wordsMap[word] = {word};
    }

    WordChain wc(words);
    return wc.longestChain(wordsMap);
}

