#include <iostream>
#include <vector>
#include <limits>
#include <algorithm>

const int INF = 1001;
const int MAX_N = 10000;

void processInputs() {
    int t;
    long long M;
    std::vector<long long> A(MAX_N);

    while (std::cin >> t) {
        if (t == -1) break;

        std::cin >> M;

        if (M <= 0 || M > MAX_N) {
            std::cerr << "Invalid value for M: " << M << ", should be in range (1, " << MAX_N << ")\n";
            continue;
        }

        for (int n = 0; n < std::min(M, MAX_N); n++) {
            if (!(std::cin >> A[n])) {
                std::cerr << "Error reading input value for A[" << n << "]\n";
                return;
            }
        }

        long long steps = INF;
        for (int N = 1; N <= M + 1; N++) {
            for (int i = 0; i < N; i++) {
                steps = M - A[i];

                if (i < N - 1) {
                    A[i] = A[i + 1];
                } else {
                    steps -= 2;
                }

                steps -= (steps > 0 ? (steps - 1) : 0);
                steps /= 2;

                A[i] = steps;
                steps += 1;
            }

            if (steps <= 0) break;
        }

        for (int i = 0; i < N; i++) {
            std::cout << A[i] << std::endl;
        }

        std::cout << std::endl;
    }
}

int main() {
    try {
        processInputs();
    } catch (const std::exception &e) {
        std::cerr << "An error occurred: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

