class MaxDiffCalculator {
public:
    static int maxDiff(const std::vector<int>& nums) {
        if (nums.size() < 2) {
            throw std::invalid_argument("Input array must contain at least two elements.");
        }

        int min_val = nums[0];
        int max_diff = std::numeric_limits<int>::min();

        for (size_t i = 1; i < nums.size(); ++i) {
            if (nums[i] < min_val) {
                min_val = nums[i];
            } else {
                int current_diff = nums[i] - min_val;
                if (current_diff > max_diff) {
                    max_diff = current_diff;
                }
            }
        }

        return (max_diff > 0) ? max_diff : -1;
    }
};

int main() {
    try {
        std::vector<int> nums = {9, 4, 3, 2};
        int result = MaxDiffCalculator::maxDiff(nums);
        std::cout << "Max difference: " << result << std::endl;  // Expected output: -1
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

