#include <iostream>
#include <vector>
#include <stdexcept>

using namespace std;

class SegmentTree {
private:
    int n;
    vector<int> tree;

public:
    SegmentTree(int n) : n(n), tree(4 * n, 0) {}

    void build(const vector<int>& arr, int node, int start, int end) {
        if (start > end || node >= tree.size()) {
            throw runtime_error("Invalid segment for building tree");
        }
        if (start == end) {
            tree[node] = arr[start];
        } else {
            int mid = (start + end) / 2;
            build(arr, 2 * node, start, mid);
            build(arr, 2 * node + 1, mid + 1, end);
            tree[node] = tree[2 * node] + tree[2 * node + 1];
        }
    }

    int query(int node, int start, int end, int l, int r) {
        if (r < start || end < l) {
            return 0;
        }
        if (l <= start && end <= r) {
            return tree[node];
        }
        int mid = (start + end) / 2;
        return query(2 * node, start, mid, l, r) + query(2 * node + 1, mid + 1, end, l, r);
    }

    void update(int node, int start, int end, int idx, int val) {
        if (start > end || node >= tree.size()) {
            throw runtime_error("Invalid segment for update");
        }
        if (start == end) {
            tree[node] += val;
        } else {
            int mid = (start + end) / 2;
            if (idx <= mid) {
                update(2 * node, start, mid, idx, val);
            } else {
                update(2 * node + 1, mid + 1, end, idx, val);
            }
            tree[node] = tree[2 * node] + tree[2 * node + 1];
        }
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n = 0, q = 0;
    if (!(cin >> n >> q) || n <= 0 || q < 0) {
        cerr << "Invalid input for n or q.\n";
        return EXIT_FAILURE;
    }

    vector<int> arr(n, 0);
    SegmentTree st(n);

    try {
        st.build(arr, 1, 0, n - 1);
    } catch (const runtime_error& e) {
        cerr << "Error during building segment tree: " << e.what() << '\n';
        return EXIT_FAILURE;
    }

    for (int i = 0; i < q; ++i) {
        char operation;
        int idx = 0, val = 0;
        if (!(cin >> operation >> idx >> val) || idx < 0 || idx >= n) {
            cerr << "Invalid operation input.\n";
            return EXIT_FAILURE;
        }

        if (operation == 'u') {
            st.update(1, 0, n - 1, idx, val);
        } else if (operation == 'q') {
            int result = st.query(1, 0, n - 1, idx, val);
            cout << "Query result: " << result << '\n';
        } else {
            cerr << "Unknown operation: " << operation << '\n';
        }
    }

    return EXIT_SUCCESS;
}

class Solution {
private:
    int dp[1000][101];

    int backtrack(int targetSeconds, int digits, int secondsPerMinute, int startAt, int moveCost, int pushCost) {
        if (digits == 0) return 0;
        if (dp[targetSeconds][digits] >= 0) return dp[targetSeconds][digits];

        int curr = targetSeconds % 10;
        int back = targetSeconds / 10;
        int ans = (curr != startAt) ? moveCost : 0;

        ans += pushCost;
        int prevAns = ans;
        int nextBack = (curr * secondsPerMinute) + back;
        ans += backtrack(nextBack, digits - 1, secondsPerMinute, startAt, moveCost, pushCost);

        dp[targetSeconds][digits] = ans;

        if (back) {
            if (back != startAt) prevAns += moveCost;
            prevAns += pushCost;
            int nextBackAlt = curr + (back * secondsPerMinute);
            prevAns += backtrack(nextBackAlt, digits - 1, secondsPerMinute, startAt, moveCost, pushCost);
            dp[targetSeconds][digits] = std::min(ans, prevAns);
        }

        return dp[targetSeconds][digits];
    }

public:
    int minCostSetTime(int startAt, int moveCost, int pushCost, int targetSeconds) {
        if (moveCost < 0 || pushCost < 0 || targetSeconds < 0) {
            throw std::invalid_argument("Costs and target seconds must be non-negative.");
        }

        int minPerHour = 60;
        int timeInMin = targetSeconds / minPerHour;
        int sec = targetSeconds % minPerHour;
        int noOfDigits = (sec < 10) ? 3 : 4;

        std::fill_n(&dp[0][0], 1000 * 101, -1);

        if (timeInMin == 0) {
            return backtrack(sec, noOfDigits, 1, startAt, moveCost, pushCost);
        }

        int ans1 = (timeInMin < 10) 
                   ? backtrack(timeInMin * 100, 4, 100, startAt, moveCost, pushCost)
                   : backtrack(targetSeconds, 4, 60, startAt, moveCost, pushCost);
        int ans2 = backtrack(targetSeconds, 3, 60, startAt, moveCost, pushCost);

        return std::min(ans1, ans2);
    }
};

