#include <iostream>
#include <vector>
#include <stdexcept>
#include <limits>

const int MAX_SUM = 1000001;
const int MAX_DIGIT = 10;
const int MAX_POS = 6;
const long long MOD = 1e9;

void calculateFortuneTable(const std::vector<long long>& F, std::vector<std::vector<std::vector<long long>>>& fortune_table) {
    for (int d = 0; d < MAX_DIGIT; ++d) {
        for (int pos = 0; pos < MAX_POS; ++pos) {
            for (int i = 0; i < F.size(); ++i) {
                fortune_table[d][pos][i] = d * F[pos]; // Assuming this is the formula for fortune
            }
        }
    }
}

std::vector<long long> computeDP(int maxN, const std::vector<std::vector<std::vector<long long>>>& fortune_table) {
    std::vector<long long> dp(maxN, -1);
    dp[0] = 0;

    for (int sum = 1; sum < maxN; ++sum) {
        for (int d = 0; d < MAX_DIGIT; ++d) {
            for (int pos = 0; pos < MAX_POS; ++pos) {
                if (sum >= d) {
                    long long potentialFortune = dp[sum - d] + fortune_table[d][pos][0]; // Assume position 0 for simplicity
                    if (dp[sum] < potentialFortune) {
                        dp[sum] = potentialFortune;
                    }
                }
            }
        }
    }
    return dp;
}

void processSheepQueries(int numQueries, const std::vector<long long>& dp) {
    for (int i = 0; i < numQueries; ++i) {
        long long n_i;
        std::cin >> n_i;

        if (n_i < 0 || n_i >= MAX_SUM) {
            std::cerr << "Query out of bounds: " << n_i << std::endl;
            continue;
        }

        std::cout << "Max fortune for sum " << n_i << ": " << dp[n_i] << std::endl;
    }
}

int main() {
    try {
        int k;
        std::cout << "Enter k: ";
        std::cin >> k;

        if (k <= 0 || k > 5) {
            throw std::invalid_argument("k must be between 1 and 5.");
        }

        std::vector<long long> F(MAX_POS);
        std::cout << "Enter fortune values (F[0] to F[5]): ";
        for (int i = 0; i < MAX_POS; ++i) {
            std::cin >> F[i];
        }

        int q;
        std::cout << "Enter number of queries: ";
        std::cin >> q;

        if (q <= 0) {
            throw std::invalid_argument("Number of queries must be greater than 0.");
        }

        std::vector<std::vector<std::vector<long long>>> fortune_table(MAX_DIGIT, std::vector<std::vector<long long>>(MAX_POS, std::vector<long long>(k + 1)));
        calculateFortuneTable(F, fortune_table);

        auto dp = computeDP(MAX_SUM, fortune_table);
        processSheepQueries(q, dp);
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}

