#include <vector>
#include <unordered_set>
#include <iostream>

class Solution {
public:
    bool canRemoveToCoverRange(const std::vector<int>& nums, int lower, int upper) {
        if (nums.empty() || lower > upper) {
            std::cerr << "Invalid input: nums is empty or lower > upper." << std::endl;
            return false;
        }

        std::unordered_set<int> numSet(nums.begin(), nums.end());
        int minNum = *std::min_element(nums.begin(), nums.end());
        int maxNum = *std::max_element(nums.begin(), nums.end());

        if ((maxNum - minNum) == (upper - lower) && numSet.count(minNum) && numSet.count(maxNum)) {
            return true;
        }

        for (int num : nums) {
            if (num >= lower && num <= upper) {
                int targetMin = num + (upper - lower);
                if (numSet.count(targetMin) && numSet.count(num)) {
                    return true;
                }
            }
        }

        return false;
    }

    int countPalindromicSubsequences(const std::string& s) {
        if (s.empty()) {
            std::cerr << "Invalid input: string is empty." << std::endl;
            return 0;
        }

        int count = 0;
        int n = s.size();
        std::vector<std::vector<bool>> dp(n, std::vector<bool>(n, false));

        for (int length = 1; length <= n; ++length) {
            for (int start = 0; start <= n - length; ++start) {
                int end = start + length - 1;
                if (length == 1) {
                    dp[start][end] = true;
                } else if (length == 2) {
                    dp[start][end] = (s[start] == s[end]);
                } else {
                    dp[start][end] = (s[start] == s[end]) && dp[start + 1][end - 1];
                }
                if (dp[start][end]) {
                    count++;
                }
            }
        }

        return count;
    }

    int maxNumOfSubarrays(const std::vector<int>& nums, int k) {
        if (nums.empty() || k <= 0) {
            std::cerr << "Invalid input: nums is empty or k <= 0." << std::endl;
            return 0;
        }

        int maxSubarrays = 0;
        std::vector<int> countPrefix(nums.size() + 1, 0);

        for (int i = 0; i < nums.size(); ++i) {
            countPrefix[i + 1] = countPrefix[i] + (nums[i] >= k ? 1 : 0);
        }

        for (int i = 0; i < countPrefix.size(); ++i) {
            for (int j = i + 1; j < countPrefix.size(); ++j) {
                if (countPrefix[j] - countPrefix[i] >= 1) {
                    maxSubarrays++;
                }
            }
        }

        return maxSubarrays;
    }

    long long maxScore(const std::vector<int>& nums, int k) {
        if (nums.empty() || k <= 0) {
            std::cerr << "Invalid input: nums is empty or k <= 0." << std::endl;
            return 0;
        }

        long long score = 0;
        for (size_t i = 0; i < nums.size(); ++i) {
            score += nums[i] < k ? 0 : nums[i];
        }

        return score;
    }
};

#include <string>
#include <iostream>

class Solution {
public:
    std::string makeFancyString(const std::string& s) {
        if (s.empty()) {
            std::cerr << "Warning: Input string is empty." << std::endl;
            return "";
        }

        std::string res;
        res.reserve(s.size()); // Optimize memory allocation
        int count = 1;

        // Start with the first character
        res += s[0];

        for (size_t j = 1; j < s.length(); ++j) {
            if (s[j] == s[j - 1]) {
                count++;
                if (count < 3) {
                    res += s[j];
                }
            } else {
                count = 1; // Reset count for new character
                res += s[j];
            }
        }

        return res;
    }
};

