#include <vector>
#include <iostream>
#include <stdexcept>

class Graph {
public:
    explicit Graph(int n) : parent(n + 1) {
        for (int i = 0; i <= n; ++i) {
            parent[i] = i;
        }
    }

    std::vector<int> findExtraEdge(const std::vector<std::vector<int>>& edges) {
        if (edges.empty()) {
            throw std::invalid_argument("Edges list cannot be empty.");
        }

        for (const auto& edge : edges) {
            if (edge.size() != 2) {
                throw std::invalid_argument("Each edge must contain exactly two nodes.");
            }
            int u = edge[0], v = edge[1];
            int pu = find(u), pv = find(v);
            if (pu == pv) {
                return edge;
            }
            parent[pu] = pv;
        }

        return { edges.back()[0], edges.back()[1] };
    }

private:
    std::vector<int> parent;

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
};

int main() {
    try {
        Graph graph(3);
        std::vector<std::vector<int>> edges = {{1, 2}, {1, 3}, {2, 3}};
        std::vector<int> extraEdge = graph.findExtraEdge(edges);
        std::cout << "Extra edge: [" << extraEdge[0] << ", " << extraEdge[1] << "]\n";
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << '\n';
    }

    return 0;
}

