#include <iostream>
#include <vector>
#include <algorithm>
#include <queue>

struct Course {
    int duration;
    int deadline;
};

class CourseScheduler {
public:
    CourseScheduler(const std::vector<std::pair<int, int>>& courses) {
        for (const auto& course : courses) {
            courseList.emplace_back(Course{course.first, course.second});
        }
    }

    int maxCourses() {
        std::priority_queue<int> maxHeap;
        std::sort(courseList.begin(), courseList.end(), [](const Course& a, const Course& b) {
            return a.deadline < b.deadline;
        });

        int currentTime = 0;

        for (const auto& course : courseList) {
            currentTime += course.duration;
            maxHeap.push(course.duration);

            if (currentTime > course.deadline) {
                if (!maxHeap.empty()) {
                    currentTime -= maxHeap.top();
                    maxHeap.pop();
                    logOverdueCourse(course.duration, currentTime);
                }
            }
        }

        return maxHeap.size();
    }

private:
    std::vector<Course> courseList;

    void logOverdueCourse(int duration, int currentTime) const {
        std::cout << "Removed a course of duration " << duration 
                  << ", current time after removal: " << currentTime << "\n";
    }
};

int main() {
    try {
        std::vector<std::pair<int, int>> courses = {{2, 4}, {3, 6}, {4, 10}, {1, 2}};
        CourseScheduler scheduler(courses);
        int result = scheduler.maxCourses();
        std::cout << "Maximum number of courses that can be taken: " << result << "\n";
    } catch (const std::exception& e) {
        std::cerr << "Error occurred: " << e.what() << "\n";
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}

#include <iostream>
#include <vector>
#include <string>
#include <iomanip>

using namespace std;

void readInput(vector<long long>& v, int count) {
    v.reserve(count);
    for (int i = 0; i < count; ++i) {
        long long temp;
        if (!(cin >> temp)) {
            cerr << "Error reading input. Please check the values." << endl;
            exit(EXIT_FAILURE);
        }
        v.push_back(temp);
    }
}

string mergeVectors(const vector<long long>& v1, const vector<long long>& v2) {
    long long sum1 = 0, sum2 = 0;
    string result;
    bool firstElement = true;

    for (const auto& val1 : v1) {
        for (const auto& val2 : v2) {
            if ((val1 > val2 && sum1 < sum2) || (firstElement && val1 > val2)) {
                result += to_string(val1) + " ";
                firstElement = false;
                sum1 += val1;
            } else if (val1 < val2 && sum2 < sum1) {
                result += to_string(val2) + " ";
                firstElement = false;
                sum2 += val2;
            }
        }
    }

    return result.empty() ? result : result.substr(0, result.size() - 1); // Trim trailing space
}

int main() {
    int n;

    if (!(cin >> n) || n <= 0) {
        cerr << "Invalid input count. Must be a positive integer." << endl;
        return EXIT_FAILURE;
    }

    vector<long long> v1, v2;

    readInput(v1, n);
    readInput(v2, n);

    string result = mergeVectors(v1, v2);
    cout << result << endl;

    return EXIT_SUCCESS;
}

