#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <unordered_set>

int calculateInitialPrice(const std::string& s) {
    int price = 0;
    for (char c : s) {
        price += (c - 'a' + 1);
    }
    return price;
}

std::string reduceStringPrice(const std::vector<std::pair<std::string, int>>& test_cases) {
    std::string result;

    for (const auto& test_case : test_cases) {
        const std::string& w = test_case.first;
        int p = test_case.second;

        int initial_price = calculateInitialPrice(w);
        if (initial_price <= p) {
            result += w + "\n";
            continue;
        }

        std::vector<std::pair<char, int>> char_values;
        for (char c : w) {
            char_values.emplace_back(c, c - 'a' + 1);
        }

        std::sort(char_values.begin(), char_values.end(), [](const auto& a, const auto& b) {
            return a.second > b.second;
        });

        int excess_price = initial_price - p;
        std::unordered_set<char> removed_chars;

        for (const auto& [char_to_remove, value] : char_values) {
            if (excess_price <= 0) {
                break;
            }
            if (removed_chars.find(char_to_remove) == removed_chars.end()) {
                excess_price -= value;
                removed_chars.insert(char_to_remove);
            }
        }

        std::string reduced_string;
        for (char c : w) {
            if (removed_chars.find(c) == removed_chars.end()) {
                reduced_string += c;
            }
        }

        result += reduced_string + "\n";
    }

    return result;
}

int main() {
    int t;
    std::cin >> t;
    std::cin.ignore();
    std::vector<std::pair<std::string, int>> test_cases;

    for (int i = 0; i < t; ++i) {
        std::string w;
        int p;
        std::getline(std::cin, w);
        std::cin >> p;
        std::cin.ignore();
        test_cases.emplace_back(w, p);
    }

    std::string output = reduceStringPrice(test_cases);
    std::cout << output;

    return 0;
}

