#include <iostream>
#include <optional>
#include <unordered_map>

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
};

std::optional<int> findMatchingValue(TreeNode* root) {
    if (!root || (!root->left && !root->right)) return std::nullopt;

    auto left = root->left;
    auto right = root->right;

    if (left && root->val == left->val)
        return findMatchingValue(right);
    if (right && root->val == right->val)
        return findMatchingValue(left);

    return std::nullopt;
}

int getSecondSmallest(TreeNode* root) {
    if (!root || !root->left || !root->right) return -1;

    auto left = root->left;
    auto right = root->right;

    return left->val < right->val ? left->val : getSecondSmallest(right);
}

int findSecondMinimumValue(TreeNode* root) {
    if (!root) return -1;
    if (root->left && root->right)
        return getSecondSmallest(root);
    if (root->left || root->right)
        return findMatchingValue(root).value_or(-1);

    return -1;
}

int countCombinations(std::vector<int>& arr, int x, std::unordered_map<int, int>& memo) {
    if (x < 0) return 0;
    if (x == 0) return 1;
    if (memo.count(x)) return memo[x];

    int count = 0;
    for (size_t i = 0; i < arr.size(); ++i) {
        count += countCombinations(arr, x - arr[i], memo);
    }

    memo[x] = count;
    return count;
}

int combinationSum(std::vector<int>& nums, int x) {
    std::unordered_map<int, int> memo;
    return countCombinations(nums, x, memo);
}

bool validateProductID(const std::string& p_id) {
    const std::string valid_symbols = "^[a-zA-Z0-9-]+$";
    if (!std::regex_match(p_id, std::regex(valid_symbols))) {
        std::cerr << "Invalid Product ID: contains invalid symbols" << std::endl;
        return false;
    }

    std::istringstream stream(p_id);
    std::string segment;
    int sub_count = 0;

    while (std::getline(stream, segment, '-')) {
        if (segment.empty() || segment.size() > 20) return false;
        sub_count++;
    }

    int hyphen_count = std::count(p_id.begin(), p_id.end(), '-');
    if (sub_count < 2 || sub_count > 4 || hyphen_count != (sub_count - 1)) {
        std::cerr << "Invalid Product ID: incorrect subsegment or hyphen count" << std::endl;
        return false;
    }

    return true;
}

