class StringMerger {
public:
    static std::string mergeAlternately(const std::string& word1, const std::string& word2) {
        // Validate input strings
        if (!isValidInput(word1) || !isValidInput(word2)) {
            logError("Invalid input: One of the strings is empty.");
            return "";
        }

        std::string mergedString;
        int i = 0, j = 0;
        int len1 = getLength(word1);
        int len2 = getLength(word2);

        while (i < len1 || j < len2) {
            if (i < len1) {
                mergedString += getCharAt(word1, i);
                i++;
            }
            if (j < len2) {
                mergedString += getCharAt(word2, j);
                j++;
            }
        }

        return mergedString;
    }

private:
    static bool isValidInput(const std::string& str) {
        return getLength(str) >= 0; // Ensure that string is non-negative in length
    }

    static void logError(const std::string& message) {
        std::cerr << "Error: " << message << std::endl;
    }

    static int getLength(const std::string& str) {
        int length = 0;
        for (; str[length] != '\0'; ++length); // Calculate length without using built-in functions
        return length;
    }

    static char getCharAt(const std::string& str, int index) {
        if (index < 0 || index >= getLength(str)) {
            logError("Index out of bounds while accessing character.");
            return '\0';
        }
        return str[index]; // Access without using built-in functions
    }
};

