const long long MOD = 1000000007;
const int MAX_SIZE = 100005;

long long modular_power(long long base, long long exponent) {
    long long result = 1;
    while (exponent > 0) {
        if (exponent & 1) result = (result * base) % MOD;
        base = (base * base) % MOD;
        exponent >>= 1;
    }
    return result;
}

long long modular_inverse(long long value) {
    return modular_power(value, MOD - 2);
}

long long compute_result(std::vector<int>& values, int size, int k, std::vector<long long>& dp) {
    int missing_count = 0;
    for (int i = 0; i < size; ++i) {
        if (values[i] == -1) {
            ++missing_count;
        } else {
            for (int j = 0; j < size; ++j) {
                if (values[j] != -1 && values[j] != values[i]) {
                    return (compute_result(values, size, k, dp) + compute_result(values, size, k, dp)) % MOD;
                }
            }
        }
    }

    long long factorial = 1;
    for (int i = 1; i <= missing_count; ++i) {
        factorial = (factorial * i) % MOD;
    }

    long long result = 0;
    for (int i = 1; i <= missing_count; ++i) {
        result = (result + factorial * modular_inverse(i) % MOD * dp[size - i]) % MOD;
        factorial = (factorial * (missing_count - i) % MOD * modular_inverse(i + 1) % MOD) % MOD;
    }
    return result;
}

void handle_input(std::vector<int>& values, int& n, int& k) {
    std::cin >> n >> k;
    if (n <= 0 || k <= 0) {
        throw std::invalid_argument("Invalid input values for n or k.");
    }
    values.resize(n);
    for (int& value : values) {
        std::cin >> value;
    }
}

void compute_dp(std::vector<long long>& dp, int n, int k) {
    dp[0] = 0;
    for (int i = 1; i <= n; ++i) {
        dp[i] = (dp[i - 1] + i * (k - 1) % MOD * modular_inverse(k)) % MOD;
        dp[i] = (dp[i] + (i - 1) * dp[i - 1] % MOD * modular_inverse(k)) % MOD;
    }
}

int main() {
