        int n, k;
        std::vector<int> values;
        handle_input(values, n, k);

        std::vector<long long> dp(n + 1);
        compute_dp(dp, n, k);

        long long result = compute_result(values, n, k, dp);
        std::cout << result << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

