void bfs() {
    memset(ans, 0, sizeof(ans)); 
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    for (int i = 0; i < n; ++i) {
        pq.push({-segments[i].second.s, i});
    }

    while (!pq.empty()) {
        int currentDistance = -pq.top().first;
        int currentIndex = pq.top().second;
        pq.pop();

        dis[currentIndex].push_back(1); 

        for (int i = 0; i < segments[currentIndex].second.s; ++i) {
            int t1 = currentDistance + dis[currentIndex][i];
            int t2 = currentDistance - (n - segments.size());

            if (t1 > 1) {
                ans[t1].push_back(currentIndex);
                ans[t2].push_back(currentIndex);
