            for (int side_number : box_parameter.second[first_box]) {
                break_coordinate_demultiplexor_for_both_boxes[box_key] = side_number;
                coordinate_demultiplexor_for_first_box[axis.at(box_parameter.first)] = side_number;

                for (int other_side_number : box_parameter.second[1 - break_coordinate_demultiplexor_for_both_boxes[box_key]][1 - first_box]) {
                    coordinate_demultiplexor_for_first_box[axis.at(snake_boxes[box_key].second[1 - first_box])] = other_side_number;

