class Solution {
public:
    int minDifference(std::vector<int>& nums) {
        if (nums.empty()) {
            throw std::invalid_argument("Input vector is empty");
        }

        int n = nums.size();
        if (n < 3) {
            throw std::invalid_argument("Input vector must have at least 3 elements");
        }

        n /= 3;

        std::partial_sum(nums.begin(), nums.end(), nums.begin());
        int total = *std::min_element(nums.begin(), nums.end());
        int min_diff = std::max((total / 2) * 2, (3 * total - std::accumulate(nums.begin(), nums.end(), 0)) / 2);

        for (size_t i = 1; i < nums.size(); ++i) {
            total -= nums[i];
            int first_partition_sum = std::accumulate(nums.begin(), nums.end() - i, 0);
            int second_partition_sum = std::accumulate(nums.begin() + i, nums.end(), 0);
            min_diff = std::min(min_diff, std::abs(first_partition_sum - second_partition_sum));
        }

        return min_diff;
    }
};

class Solution {
public:
    int largestAltitude(const vector<int>& gain) {
        if (gain.empty()) {
            throw invalid_argument("Input vector 'gain' must not be empty.");
        }

        int currentAltitude = 0;
        int highestAltitude = 0;

        for (size_t i = 0; i < gain.size(); ++i) {
            currentAltitude += gain[i];
            highestAltitude = max(highestAltitude, currentAltitude);
        }

        return highestAltitude;
    }
};

