class Chars {
public:
    int val;
    char c;

    Chars(int num) : val(num), c('a' + num - 1) {}
};

class KthLargestLetterFinder {
public:
    int kthLargestLetter(const std::string& s, int k) {
        if (k <= 0) {
            throw std::invalid_argument("k must be a positive integer.");
        }
        if (s.empty()) {
            throw std::invalid_argument("Input string cannot be empty.");
        }
        std::vector<Chars> vals;
        int num = s[0] - 'a' + 1;
        vals.emplace_back(num);

        for (size_t idx = 1; idx < s.length(); ++idx) {
            char digit = s[idx];

            if (digit < '3') {
                for (int i = 0; i < num; ++i) {
                    vals.emplace_back(num);
                }
            }

            int newNum = (digit >= '3') ? computeNewNum(num, digit) : num;
            vals.emplace_back(newNum);
            num = newNum;
        }

        return findKthLargest(vals, k);
    }

private:
    int computeNewNum(int num, char digit) const {
        std::ostringstream sb;
        sb << num;
        for (int j = 0; j < digit - '2'; ++j) {
            sb << num;
        }
        return std::stoi(sb.str());
    }

    int findKthLargest(const std::vector<Chars>& vals, int k) const {
        int total = 0, i = vals.size() - 1;

        while (total < k && i >= 0) {
            total += vals[i--].val;
            if (total >= k) {
                return vals[i + 1].c;
            }
        }

        throw std::runtime_error("Not enough letters to find the kth largest.");
    }
};

class Solution {
public:
    bool isSubtree(TreeNode* root, TreeNode* subRoot) {
        if (!root) {
            return false;
        }
        if (isSameTree(root, subRoot)) {
            return true;
        }
        return isSubtree(root->left, subRoot) || isSubtree(root->right, subRoot);
    }

    bool isSameTree(TreeNode* p, TreeNode* q) {
        if (!p && !q) {
            return true;
        }
        if (!p || !q) {
            return false;
        }
        return p->val == q->val 
            && isSameTree(p->left, q->left) 
            && isSameTree(p->right, q->right);
    }

    void logError(const std::string& msg) {
        std::cerr << "[ERROR] " << msg << std::endl;
    }

    void logMessage(const std::string& msg) {
        std::cout << "[INFO] " << msg << std::endl;
    }

    bool validateInput(TreeNode* root, TreeNode* subRoot) {
        if (!root || !subRoot) {
            logError("Input trees cannot be null.");
            return false;
        }
        return true;
    }
};

