typedef long long ll;
typedef double db;

void readTopics(int t, vector<pair<vector<db>, vector<db>>>& topics) {
    for (auto& [c, p] : topics) {
        int n;
        cin >> n;
        if (n <= 0) throw invalid_argument("Number of elements must be positive.");

        c.resize(n);
        p.resize(n);

        ll sum_c = 0, sum_p = 0;

        for (int i = 0; i < n; i++) {
            cin >> c[i];
            sum_c += c[i];
        }
        for (int i = 0; i < n; i++) {
            cin >> p[i];
            sum_p += p[i];
        }
        if (sum_p == 0) throw runtime_error("Sum of weights cannot be zero.");

        for (int i = 0; i < n; i++) {
            p[i] = static_cast<db>(p[i]) / sum_p;
        }
    }
}

vector<ll> readQueries(int q) {
    vector<ll> x(q);
    for (auto& xx : x) {
        cin >> xx;
    }
    return x;
}

db calculateBs(int id, db mi, const vector<pair<vector<db>, vector<db>>>& topics) {
    auto [c, p] = topics[id];
    int n = c.size();

    vector<db> a(n);
    vector<db> b(n);

    for (int i = 0; i < n; i++) {
        a[i] = static_cast<db>(c[i]) - mi * p[i];
        b[i] = p[i];
    }

    db tu = accumulate(a.begin(), a.end(), 0.0);
    db mau = accumulate(b.begin(), b.end(), 0.0);

    if (mi >= 0) {
        if (tu <= 0) return numeric_limits<db>::max();
        return tu / mau;
    }
    if (tu >= 0) return numeric_limits<db>::max();
    return tu / mau;
}

db ternarySearch(int id, const vector<pair<vector<db>, vector<db>>>& topics) {
    db l = 0;
    db r = 1e9;

    for (int i = 0; i < 100; i++) {
        db m1 = l + (r - l) / 3;
        db m2 = r - (r - l) / 3;

        if (calculateBs(id, m1, topics) > calculateBs(id, m2, topics)) {
            l = m1;
        } else {
            r = m2;
        }
    }
    return calculateBs(id, (l + r) / 2, topics);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t, q;
    cin >> t >> q;

    if (t <= 0 || q <= 0) {
        cerr << "Error: Number of topics and queries must be positive." << endl;
        return EXIT_FAILURE;
    }

    vector<pair<vector<db>, vector<db>>> topics(t);
    try {
        readTopics(t, topics);
    } catch (const exception& e) {
        cerr << "Error reading topics: " << e.what() << endl;
        return EXIT_FAILURE;
    }

    vector<ll> x = readQueries(q);

    for (int i = 0; i < t; i++) {
        cout << fixed << setprecision(10) << ternarySearch(i, topics) << endl;
    }

    return EXIT_SUCCESS;
}

