class PermutationGenerator {
public:
    std::vector<int> getPermutation(int n, int k) {
        if (n < 1 || k < 1 || k > factorial(n)) {
            throw std::invalid_argument("Invalid values for n or k.");
        }

        std::vector<int> ans;
        ans.reserve(n);
        std::vector<int> permutation(n, 0);
        int start = 1;

        for (int i = 0; i < n; ++i) {
            while (k > 0 && start <= permutation[i]) {
                ans.push_back(start++);
                --k;
            }
            permutation[i]++;
        }

        if (ans.size() != n) {
            throw std::logic_error("Failed to generate valid permutation.");
        }

        return ans;
    }

private:
    long long factorial(int num) {
        long long result = 1;
        for (int i = 2; i <= num; ++i) {
            result *= i;
        }
        return result;
    }
};

