public:
    WordFilter(const std::vector<std::string>& words) {
        if (words.empty()) {
            std::cerr << "Warning: No words provided to WordFilter." << std::endl;
            return;
        }

        for (size_t i = 0; i < words.size(); ++i) {
            const std::string& word = words[i];
            if (word.empty()) {
                std::cerr << "Warning: Empty string found at index " << i << std::endl;
                continue;
            }
            size_t w = word.size();
            for (size_t j = 1; j <= w; ++j) {
                for (size_t k = 1; k <= w; ++k) {
                    map[word.substr(w - j) + "#" + word.substr(0, k)] = i;
                }
            }
        }
    }

    int f(const std::string& prefix, const std::string& suffix) const {
        auto it = map.find(suffix + "#" + prefix);
        if (it != map.end()) {
            return it->second;
        }
        return -1;
    }
};

