#include <cmath>
#include <vector>
#include <algorithm>
#include <stdexcept>
#include <iostream>

struct Statistic {
    double min;
    double max;
    double mean;
    double median;
    std::vector<int> modes;
};

class Counter {
public:
    static Statistic computeStatistics(const std::vector<int>& input_data) {
        if (input_data.empty()) {
            throw std::invalid_argument("Input data cannot be empty");
        }

        std::vector<int> sorted_data = input_data;
        std::sort(sorted_data.begin(), sorted_data.end());

        size_t sample_size = sorted_data.size();
        Statistic stats;

        // Compute min and max
        stats.min = sorted_data.front();
        stats.max = sorted_data.back();

        // Calculate mean
        double total_sum = 0.0;
        for (const auto& value : sorted_data) {
            total_sum += value;
        }
        stats.mean = total_sum / sample_size;

        // Calculate median
        if (sample_size % 2 == 0) {
            stats.median = (sorted_data[sample_size / 2 - 1] + sorted_data[sample_size / 2]) / 2;
        } else {
            stats.median = sorted_data[sample_size / 2];
        }

        // Calculate mode
        std::vector<int> count(256, 0);
        for (const auto& value : sorted_data) {
            if (value >= 0 && value < 256) {
                count[value]++;
            } else {
                throw std::out_of_range("Value out of range for mode calculation");
            }
        }

        int max_count = 0;
        for (size_t i = 0; i < count.size(); ++i) {
            if (count[i] > max_count) {
                stats.modes.clear();
                stats.modes.push_back(i);
                max_count = count[i];
            } else if (count[i] == max_count && max_count > 0) {
                stats.modes.push_back(i);
            }
        }

        return stats;
    }
};

// Example usage
int main() {
    try {
        std::vector<int> data = {1, 2, 3, 2, 5, 5, 5, 3, 3};
        Statistic stats = Counter::computeStatistics(data);
        std::cout << "Min: " << stats.min << ", Max: " << stats.max
                  << ", Mean: " << stats.mean << ", Median: " << stats.median
                  << ", Modes: ";
        for (const auto& mode : stats.modes) {
            std::cout << mode << " ";
        }
        std::cout << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}

