class Solution {
public:
    std::vector<std::string> invalidTransactions(std::vector<std::string>& transactions) {
        std::unordered_set<std::string> invalidTransact;
        std::unordered_map<std::string, std::vector<std::pair<int, int>>> transactByNameCity;

        for (int i = 0; i < transactions.size(); ++i) {
            std::string name, city;
            int time, amount;
            parseTransaction(transactions[i], name, time, amount, city);

            if (amount > 1000) {
                invalidTransact.insert(transactions[i]);
            }

            int timeRounded = time / 60 * 60;
            transactByNameCity[name + "," + city].emplace_back(i, timeRounded);
        }

        for (const auto& pair : transactByNameCity) {
            const auto& similarTransactions = pair.second;
            for (int j = 0; j < similarTransactions.size(); ++j) {
                const auto& [indexI, roundedTimeI] = similarTransactions[j];
                for (int k = j + 1; k < similarTransactions.size(); ++k) {
                    const auto& [indexJ, roundedTimeJ] = similarTransactions[k];
                    if (roundedTimeJ - roundedTimeI <= 60) {
                        invalidTransact.insert(transactions[indexI]);
                        invalidTransact.insert(transactions[indexJ]);
                        break;
                    }
                }
            }
        }

        return std::vector<std::string>(invalidTransact.begin(), invalidTransact.end());
    }

private:
    void parseTransaction(const std::string& transaction, std::string& name, int& time, int& amount, std::string& city) {
        std::istringstream ss(transaction);
        std::string token;

        std::getline(ss, name, ',');
        std::getline(ss, token, ','); time = std::stoi(token);
        std::getline(ss, token, ','); amount = std::stoi(token);
        std::getline(ss, city, ',');
    }
};

