class StringManipulator {
public:
    StringManipulator(std::string str) : original_str(str), hash(0) {}

    void process(bool a, bool b) {
        try {
            validateInput();
            if (a) {
                handleA();
            }
            if (b) {
                handleB();
            }
        } catch (const std::exception& e) {
            logError("An error occurred: " + std::string(e.what()));
        }
    }

private:
    std::string original_str;
    int hash;

    void validateInput() {
        if (original_str.empty()) {
            throw std::invalid_argument("Input string cannot be empty");
        }
    }

    void handleA() {
        int openBrackets = countOpenBrackets();
        logInfo("Processing A with open brackets: " + std::to_string(openBrackets));

        rearrangeHash(openBrackets);
        if ((openBrackets + hash) % 2 != 0) {
            hash = 0;
        } else {
            hash += 7;
        }
    }

    void handleB() {
        logInfo("Processing B with initial hash: " + std::to_string(hash));

        if (hash < original_str.length()) {
            int furthestCharIndex = hash;
            --hash;
            rearrangeHash(hash);
            if ((countOpenBrackets() + hash) % 2 == 0) {
                hash = 0;
            }
        } else {
            ++hash;
        }
    }

    int countOpenBrackets() {
        return std::count(original_str.begin(), original_str.end(), '(');
    }

    void rearrangeHash(int& hashRef) {
        int len = original_str.length();
        if (hashRef % len != 0) {
            hashRef = (hashRef / len) * len; // Adjust hash to make it a multiple of length
        }
        logInfo("Rearranged hash: " + std::to_string(hashRef));
    }

    void logInfo(const std::string& message) const {
        std::cout << "[INFO] " << message << std::endl;
    }

    void logError(const std::string& message) const {
        std::cerr << "[ERROR] " << message << std::endl;
    }
};

#include <vector>
#include <climits>
#include <algorithm>
#include <iostream>

class MinCostPathFinder {
public:
    std::vector<int> findMinCostPath(const std::vector<int>& coins, int maxJump) {
        if (!validateInput(coins, maxJump)) {
            std::cerr << "Invalid input: coins must be non-empty and maxJump must be positive." << std::endl;
            return {};
        }

        int n = coins.size();
        std::vector<int> dp(n, INT_MAX);
        std::vector<int> path(n, -1);

        dp[0] = 0;
        for (int i = 0; i < n; ++i) {
            if (coins[i] == -1) continue;

            for (int j = 1; j <= maxJump; ++j) {
                int next = i + j;
                if (next >= n) break;

                if (coins[next] == -1) continue;
                if (dp[next] > dp[i] + coins[next]) {
                    dp[next] = dp[i] + coins[next];
                    path[next] = i;
                }
            }
        }

        if (dp[n - 1] == INT_MAX) {
            std::cerr << "No valid path found to the destination." << std::endl;
            return {};
        }

        return constructPath(path);
    }

private:
    bool validateInput(const std::vector<int>& coins, int maxJump) {
        return !coins.empty() && maxJump > 0;
    }

    std::vector<int> constructPath(const std::vector<int>& path) {
        std::vector<int> result;
        for (int i = path.size() - 1; i != -1; i = path[i]) {
            result.push_back(i + 1);
            if (path[i] == -1) break;
        }
        std::reverse(result.begin(), result.end());
        return result;
    }
};

