std::vector<int> find_beautiful_indices(const std::string& s, const std::string& a, const std::string& b, int k) {
    if (a.empty() || b.empty() || k < 0) {
        std::cerr << "Error: Invalid input parameters." << std::endl;
        return {};
    }

    size_t a_len = a.length(), b_len = b.length(), len_s = s.length();

    if (len_s < a_len || len_s < b_len) {
        std::cerr << "Error: String lengths are inconsistent." << std::endl;
        return {};
    }

    std::vector<int> a_indices, b_indices;

    // Collect indices for string 'a'
    for (size_t i = 0; i <= len_s - a_len; ++i) {
        if (s.substr(i, a_len) == a) {
            a_indices.push_back(i);
        }
    }

    // Collect indices for string 'b'
    for (size_t i = 0; i <= len_s - b_len; ++i) {
        if (s.substr(i, b_len) == b) {
            b_indices.push_back(i);
        }
    }

    std::unordered_set<int> beautiful_indices_set;

    // Find beautiful indices
    for (const int& a_idx : a_indices) {
        for (const int& b_idx : b_indices) {
            if (std::abs(a_idx - b_idx) <= k) {
                beautiful_indices_set.insert(a_idx);
                break; // no need to continue if one match is found
            }
        }
    }

    std::vector<int> beautiful_indices(beautiful_indices_set.begin(), beautiful_indices_set.end());
    std::sort(beautiful_indices.begin(), beautiful_indices.end());

    return beautiful_indices;
}

