class Solution {
public:
    std::vector<int> prefixScoreArray(std::vector<std::string>& words) {
        if (words.empty()) {
            std::cerr << "Error: Input words vector is empty." << std::endl;
            return {};
        }

        std::vector<int> scores;
        scores.reserve(words.size());

        // Precompute the set of words for faster look-up
        std::unordered_set<std::string> wordSet(words.begin(), words.end());

        for (const auto& word : words) {
            int score = calculateScore(word, wordSet);
            scores.push_back(score);
        }

        return scores;
    }

private:
    int calculateScore(const std::string& word, const std::unordered_set<std::string>& wordSet) {
        int score = 0;
        for (const auto& prefix : wordSet) {
            if (word.find(prefix) != std::string::npos) {
                score++;
            }
        }
        return score;
    }
};

