    std::getline(input, line);

    while (std::getline(input, line)) {
        line.erase(std::remove(line.begin(), line.end(), '\n'), line.end());
        std::vector<int> remainders(10, 0);
        bool seenDigit = false;
        bool allProcessed = true;

        for (int i = line.length() - 1; i >= 0; --i) {
            if (std::isalpha(line[i])) {
                seenDigit = false;
                allProcessed = false;
                continue;
            }
            seenDigit = true;
            remainders[line[i] - '0']++;
        }

        if (!seenDigit) {
            std::cerr << "Error: No digits found in input.\n";
            continue;
        }

        if (allProcessed) {
            if (remainders[0] > 0) {
                remainders[0]--;
