// Rotate vector {x, y} through angle (radians).
std::pair<double, double> rotateVec(double x, double y, double angle) {
    double rotated_x = x * std::cos(angle) - y * std::sin(angle);
    double rotated_y = x * std::sin(angle) + y * std::cos(angle);
    return std::make_pair(rotated_x, rotated_y);
}

// Calculates bearing of two points.
double calculateBearing(double lon1, double lat1, double lon2, double lat2) {
    lat1 *= M_PI / 180;
    lat2 *= M_PI / 180;
    double bearing = std::atan2(2 * std::cos(lat1) * std::sin((lat2 - lat1) / 2),
                                 1 + std::sin(lat1) * std::sin(lat2)) * (180 / M_PI);
    return (bearing >= 0) ? bearing : (360 + bearing);
}

long solveTest(const std::vector<std::tuple<long long, long long, long long, long long>>& people) {
    const size_t n = people.size();
    if (n == 0) {
        std::cerr << "Input vector is empty." << std::endl;
        return 0;
    }

    std::vector<std::pair<double, double>> peopleInfo;
    std::vector<double> originFactor(n, 0);
    double countAngle = 0.0;

    try {
        for (size_t i = 0; i < n; ++i) {
            const auto& person = people[i];
            double x = static_cast<double>(std::get<0>(person));
            double y = static_cast<double>(std::get<1>(person));
            double angle = static_cast<double>(std::get<3>(person)); // assuming this is the angle
            peopleInfo.push_back(rotateVec(x, y, angle));

            if (i > 0) {
                const auto& prev_person = people[i - 1];
                double bearing = calculateBearing(
                    std::get<0>(prev_person), std::get<1>(prev_person),
                    std::get<0>(person), std::get<1>(person)
                );
                originFactor[i] = bearing;
                countAngle += bearing;
            }
        }

        if (countAngle < M_PI / 4 || countAngle > 7 * M_PI / 4) {
            return 0;
        }

        double numOfPairs = 3 * (static_cast<double>(n) / 3) + 
                            (countAngle - M_PI) / M_PI * (static_cast<double>(n) * (n - 1) / 2);

        return static_cast<long>(numOfPairs);

    } catch (const std::exception& e) {
        std::cerr << "Error processing data: " << e.what() << std::endl;
        return -1; // Indicate an error
    }
}

