class Solution {
public:
    int countSubarrays(const std::vector<int>& nums, int left, int right) {
        if (left > right) {
            throw std::invalid_argument("Left boundary must not exceed right boundary.");
        }

        int counter = 0;
        int end = 0;

        for (size_t start = 0; start < nums.size(); ++start) {
            while (end < nums.size() && nums[end] < left) {
                end++;
            }
            while (end < nums.size() && nums[end] <= right) {
                counter += end - start + 1;
                ++end;
            }
        }

        return counter;
    }
};

void run(const std::vector<std::string>& arguments) {
    if (arguments.size() < 3) {
        std::cerr << "USAGE: run program <array> <left> <right>" << std::endl;
        return;
    }

    std::vector<int> array;
