int xorAndMax1(const vector<int>& a, int size1, int size2) {
    if (size1 == 0 || size2 == 0) return 0;

    int m1 = 0, n1 = 0, m2 = 0, n2 = 0;
    for (int i = 0; i < size1; ++i) 
        m1 ^= a[i];

    for (int i = 0; i < size2; ++i) 
        n1 ^= a[i];

    m2 ^= 0; // m2 not utilized; may require a different approach.
    n2 ^= 0; // n2 not utilized; may require a different approach.

    return max(0, max(m1 * n1, m2 * n2));
}

int maxComboProduct(const vector<int>& a, int n) {
    if (n == 0) return 0;
    int curMaxProd = numeric_limits<int>::min();

    for (int i = 0; i < n; ++i) {
        vector<int> c(a.begin(), a.end());
        c.erase(c.begin() + i);

        cout << "Current number: " << a[i] << endl; // light logging

        int prod = a[i] * maxComboProduct(c, n - 1);
        curMaxProd = max(curMaxProd, prod);

        int xorMax = xorAndMax1(c, n - 1, prod >> 1);
        curMaxProd = max(curMaxProd, xorMax);
    }

    return curMaxProd;
}

