class Solution {
public:
    char findRepeatedCharacter(const std::string& s) {
        if (s.empty()) {
            throw std::invalid_argument("Input string must not be empty.");
        }

        std::unordered_map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        for (auto iter = counts.rbegin(); iter != counts.rend(); ++iter) {
            if (iter->second >= 2) {
                return iter->first;
            }
        }
        return '\0';
    }

    int findMin(const std::vector<int>& nums) {
        if (nums.empty()) {
            throw std::invalid_argument("Input array must not be empty.");
        }
        return findMinInRotatedArray(nums.data(), nums.size());
    }

private:
    int findMinInRotatedArray(const int* nums, int numsSize) {
        int left = 0, right = numsSize - 1;

        while (left < right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] > nums[right]) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return nums[left];
    }

    int findClosest(int* nums, int size, int target, int left, int right) {
        if (left > right) return -1; // invalid range
        int mid = left + (right - left) / 2;

        if (mid == 0 || mid == size - 1)
            return nums[mid];

        if (isPeak(nums, mid)) 
            return nums[mid];

        if (nums[mid - 1] > nums[mid] && nums[mid + 1] > nums[mid])
            return nums[mid];

        // Go to the half that may contain the minimum
        if (nums[mid] > nums[right])
            return findClosest(nums, size, target, mid + 1, right);
        return findClosest(nums, size, target, left, mid);
    }

    bool isPeak(const int* nums, int mid) {
        return (nums[mid] > nums[mid - 1] && nums[mid] > nums[mid + 1]);
    }

    int sweepingDirection(int* nums, int leftMini, int rightMini, int numsSize, int pivot) {
        return (rightMini - nums[pivot] > 0) ? rightMini : leftMini + (rightMini - nums[pivot]);
    }

    int findBoundary(int* nums, int numsSize, int pivot, bool findLeft) {
        if (numsSize == 1) return 0;

        int boundary = (findLeft) ? -1 : numsSize;
        for (int i = (findLeft ? 0 : numsSize - 1); (findLeft ? i <= pivot : i >= pivot); 
             (findLeft ? i++ : i--)) {
            if (nums[i] == nums[pivot]) {
                boundary = findLeft ? i : boundary;
            }
        }
        return boundary;
    }

    int findLeft(int* nums, int numsSize, int pivot) {
        return findBoundary(nums, numsSize, pivot, true);
    }

    int findRight(int* nums, int numsSize, int pivot) {
        return findBoundary(nums, numsSize, pivot, false);
    }
};

class Solution {
public:
    int minimumPartition(string s, int k) {
        if (s.empty() || k <= 0) {
            return -1; // Validation for empty string or non-positive k
        }

        vector<int> dp(s.size() + 1, INT_MAX);
        dp[0] = 0;

        for (int i = 1; i <= s.size(); i++) {
            for (int j = i; j > 0 && s[j - 1] != '0'; j--) {
                try {
                    string substring = s.substr(j - 1, i - j + 1);
                    long num = stol(substring);

                    if (num <= k && dp[j - 1] != INT_MAX) {
                        dp[i] = min(dp[i], dp[j - 1] + 1);
                    }
                } catch (const std::out_of_range& e) {
                    // Logging out of range, continue to the next iteration
                    continue;
                } catch (const std::invalid_argument& e) {
                    // Logging invalid argument, skip
                    continue;
                }
            }
        }

        return dp[s.size()] == INT_MAX ? -1 : dp[s.size()];
    }
};

class Solution {
public:
    vector<int> getOrder(vector<vector<int>>& tasks) {
        if (tasks.empty()) return {};

        int n = tasks.size();
        vector<pair<pair<int, int>, int>> taskList; // (enqueueTime, processingTime, index)

        for (int i = 0; i < n; ++i) {
            taskList.emplace_back(make_pair(tasks[i][0], tasks[i][1]), i);
        }

        sort(taskList.begin(), taskList.end(), [](const auto& a, const auto& b) {
            return a.first.first < b.first.first; // sort by enqueue time
        });

        vector<int> result;
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> minHeap; // (processingTime, index)

        long long currentTime = 0;
        int idx = 0;

        while (idx < n || !minHeap.empty()) {
            // Add tasks to the minHeap that can be processed at the current time
            while (idx < n && taskList[idx].first.first <= currentTime) {
                minHeap.push({taskList[idx].first.second, taskList[idx].second});
                idx++;
            }

            if (minHeap.empty()) {
                // If no task is available, fast-forward to the next task's enqueue time
                currentTime = taskList[idx].first.first;
                continue;
            }

            // Process the next task
            auto task = minHeap.top();
            minHeap.pop();
            result.push_back(task.second);
            currentTime += task.first; // Update current time with processing time
        }

        return result;
    }
};

