class Leaderboard {
private:
    std::unordered_map<int, int> playerScores;

public:
    Leaderboard() = default;

    void addScore(int playerId, int score) {
        if (playerId <= 0 || score < 0) {
            std::cerr << "Invalid playerId or score. Must be positive." << std::endl;
            return;
        }

        playerScores[playerId] += score;
    }

    int top(int K) {
        if (K <= 0) {
            std::cerr << "Invalid value for K. Must be positive." << std::endl;
            return 0;
        }

        std::vector<int> scores;
        for (const auto& entry : playerScores) {
            scores.push_back(entry.second);
        }

        std::sort(scores.rbegin(), scores.rend());

        int total = 0;
        for (int i = 0; i < std::min(K, static_cast<int>(scores.size())); ++i) {
            total += scores[i];
        }

        return total;
    }

    void reset(int playerId) {
        if (playerId <= 0) {
            std::cerr << "Invalid playerId. Must be positive." << std::endl;
            return;
        }

        auto it = playerScores.find(playerId);
        if (it != playerScores.end()) {
            playerScores.erase(it);
        } else {
            std::cerr << "PlayerId " << playerId << " not found. No action taken." << std::endl;
        }
    }
};

