long long calculateDigitSum(long long number) {
    long long sum = 0;
    while (number > 0) {
        sum += number % 10;
        number /= 10;
    }
    return sum;
}

long long computeAnswer(long long n) {
    if (n <= 0) {
        cerr << "Error: Invalid input, n must be positive." << endl;
        return 1; // default error response
    }

    long long sum = calculateDigitSum(n);
    long long gcdValue = __gcd(n, sum);

    long long ans = 1;
    ans *= gcdValue;

    while (ans > 1) {
        ans /= 2;
    }

    return ans;
}

