    }

    void addQuery(int queryType, int x, int y, int z = 0) {
        queries.push_back({queryType, x, y, z});
    }

    void processQueries() {
        for (const auto& query : queries) {
            try {
                switch (query[0]) {
                    case 1:
                        cout << rangeSum(query[1] - 1, query[2] - 1) << endl;
                        break;
                    case 2:
                        addToReachable(query[1] - 1, query[2]);
                        break;
                    case 3:
                        swap(p[query[1] - 1], p[query[2] - 1]);
                        break;
                    default:
                        throw invalid_argument("Invalid query type.");
                }
            } catch (const exception& e) {
                cerr << "Error processing query: " << e.what() << endl;
            }
        }
    }

private:
    long long rangeSum(int l, int r) {
        return accumulate(a.begin() + l, a.begin() + r + 1, 0LL);
    }

    void addToReachable(int v, int valueToAdd) {
        initializeGraph();
        vector<bool> visited(n, false);
        dfs(v, valueToAdd, visited);
    }

    void initializeGraph() {
        for (int i = 0; i < n; ++i) {
            adj[i].clear();
            for (int j = 0; j < n; ++j) {
                if (p[j] == i) {
                    adj[i].push_back(j);
                }
            }
        }
    }

    void dfs(int u, int valueToAdd, vector<bool>& visited) {
        if (visited[u]) return;
        visited[u] = true;
        a[u] += valueToAdd;
        for (int v : adj[u]) {
            dfs(v, valueToAdd, visited);
        }
    }
};

