class StringTransformer {
public:
    bool canTransform(std::string& source, std::string& target, int maxMoves) {
        if (source.empty() || target.empty()) {
            std::cerr << "Source or target string is empty." << std::endl;
            return false;
        }

        if (target.length() > 1.5 * source.length()) {
            std::cerr << "Target string is too long to transform." << std::endl;
            return false;
        }

        std::unordered_map<char, char> charMap;
        int countUpdates = 0;

        for (char& ch : target) {
            if (charMap.find(ch) == charMap.end()) {
                if (source.find(ch) != std::string::npos) {
                    charMap[ch] = ch;
                } else {
                    std::cerr << "Character '" << ch << "' not found in source." << std::endl;
                    return false;
                }
            } else {
                countUpdates++;
            }
        }

        for (char& ch : source) {
            charMap[ch] = ch;
            countUpdates++;
        }

        if (maxMoves >= countUpdates) {
            return true;
        }

        if (countUpdates != 2 * target.length()) {
            return false;
        }

        convertToUbicArray(source, maxMoves);

        return true;
    }

private:
    void convertToUbicArray(const std::string& inputString, int index) {
        std::unordered_map<char, int> charMap;

        for (int i = 0; i < index && i < inputString.size(); i++) {
            charMap[inputString[i]] = index++;
        }
    }
};

