int getMax(const deque<int>& dq) {
    if (dq.empty()) {
        throw runtime_error("Deque is empty, cannot determine maximum.");
    }
    return *max_element(dq.begin(), dq.end());
}

void processDeque(deque<int>& dq) {
    if (dq.empty()) {
        throw runtime_error("Input deque is empty. Cannot process.");
    }

    deque<int> dq2;
    int maxi = dq.front();

    while (dq.size() > 1) {
        if (dq2.empty()) {
            dq2.push_back(dq.back());
            dq.pop_back();
            continue;
        }

        int max = getMax(dq);
        if (maxi == max) {
            while (!dq.empty()) {
                dq2.push_back(dq.back());
                dq.pop_back();
            }
        } else {
            dq2.push_back(dq.front());
            maxi = dq.front();
            dq.pop_front();
            while (!dq.empty()) {
                dq2.push_back(dq.front());
                dq.pop_front();
            }
        }
    }

    dq = dq2;

    for (int i = 0; i < 2 * dq.size(); ++i) {
        dq.push_back(i);
