using namespace std;

const int MAX_NODES = 400;
const int MAX_EDGES = 600;
const int MODULO = 998244353;

vector<int> adjacencyList[MAX_NODES + 1];

void readInput(int &nodes, int &edges) {
    if (!(cin >> nodes >> edges)) {
        throw runtime_error("Input error: Couldn't read nodes and edges count.");
    }

    if (nodes < 1 || nodes > MAX_NODES || edges < 0 || edges > MAX_EDGES) {
        throw domain_error("Input error: Nodes or edges count out of bounds.");
    }

    for (int i = 0; i < edges; ++i) {
        int a, b;
        if (!(cin >> a >> b) || a < 1 || a > nodes || b < 1 || b > nodes) {
            throw runtime_error("Input error: Invalid edge definition.");
        }
        adjacencyList[a].push_back(b);
        adjacencyList[b].push_back(a);
    }
}

void processGraph(int nodes, vector<int> &f) {
    for (int i = 1; i <= nodes; ++i) {
        if (f[i] != 0) continue; // Skip already processed nodes

        queue<int> q;
        q.push(i);
        f[i] = i; // Initialize with current node

        while (!q.empty()) {
            int currentNode = q.front();
            q.pop();

            for (int neighbor : adjacencyList[currentNode]) {
                if (f[neighbor] == 0) {
                    f[neighbor] = f[currentNode]; // Assigning group id
                    q.push(neighbor);
                }
            }
        }
    }
}

void printResults(int nodes, const vector<int> &f) {
    for (int i = 1; i <= nodes; ++i) {
        for (int j = 1; j <= nodes; ++j) {
            cout << (f[i] * f[j]) % MODULO << " ";
        }
        cout << endl;
    }
}

int main() {
    try {
        int n, m;
        readInput(n, m);

        vector<int> f(MAX_NODES + 1, 0);
        processGraph(n, f);
        printResults(n, f);
    } catch (const exception &e) {
        cerr << e.what() << endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

