#include <iostream>
#include <vector>
#include <unordered_map>
#include <set>
#include <limits>

class Solution {
public:
    int maxImportance(int n, const std::vector<std::vector<int>>& roads) {
        std::unordered_map<int, int> roadSet;
        std::unordered_map<int, std::set<int>> cityMap;
        std::unordered_map<int, int> peoplesCnt;

        try {
            int maxRoadNum = 0;
            for (const auto& roa : roads) {
                if (roa.size() != 2) {
                    throw std::invalid_argument("Invalid road specification.");
                }
                maxRoadNum = std::max(maxRoadNum, std::max(roa[0], roa[1]));
            }
            n = maxRoadNum + 1;

            for (const auto& roa : roads) {
                int start = roa[0], end = roa[1];
                cityMap[start].insert(end);
                cityMap[end].insert(start);
            }

            for (int city = 0; city < n; ++city) {
                if (roadSet.find(city) == roadSet.end()) {
                    dfs(city, roadSet, peoplesCnt, cityMap, n);
                }
            }

            int maxVal = std::numeric_limits<int>::min();
            for (const auto& pair : roadSet) {
                maxVal = std::max(maxVal, pair.second);
            }

            return (maxVal * maxRoadNum) + sum(peoplesCnt);
        } catch (const std::exception& e) {
            std::cerr << "Error: " << e.what() << std::endl;
            return -1;
        }
    }

private:
    void dfs(int city, std::unordered_map<int, int>& roadSet,
             std::unordered_map<int, int>& peoplesCnt,
             const std::unordered_map<int, std::set<int>>& cityMap, int maxRoadNum) {
        if (roadSet.find(city) != roadSet.end()) {
            return;
        }

        roadSet[city] = 0;
        peoplesCnt[city] = 0;

        for (int nextCity : cityMap.at(city)) {
            dfs(nextCity, roadSet, peoplesCnt, cityMap, maxRoadNum);
            peoplesCnt[city] += peoplesCnt[nextCity] + roadSet[nextCity];
        }

        peoplesCnt[city] += 1;
        roadSet[city]++;
    }

    int sum(const std::unordered_map<int, int>& peoplesCnt) {
        int total = 0;
        for (const auto& pair : peoplesCnt) {
            total += pair.second;
        }
        return total;
    }
};

int main() {
    Solution solution;
    int result = solution.maxImportance(5, {{0, 1}, {1, 2}, {2, 3}, {0, 2}, {1, 3}, {2, 4}});
    std::cout << "Maximum Importance: " << result << std::endl;
    return 0;
}

