typedef long long ll;
constexpr int MOD = 998244353;
constexpr int MAX_NODES = 5010;

vector<int> adj[MAX_NODES];
int n, k;

int calculate_diameter(int root) {
    vector<int> diameter(2, -1);
    queue<int> q;
    vector<bool> visited(n + 1, false);

    q.push(root);
    visited[root] = true;

    int height = -1;

    while (!q.empty()) {
        int current = q.front();
        q.pop();

        for (int neighbor : adj[current]) {
            if (!visited[neighbor]) {
                q.push(neighbor);
                visited[neighbor] = true;

                if (height == diameter[0]) {
                    diameter[1]++;
                } else {
                    diameter[0] = height;
                    diameter[1] = 1;
                }
                height++;
            }
        }
    }
    return diameter[0] + diameter[1];
}

ll modpow(ll base, ll exp, ll mod) {
    ll result = 1;
    base %= mod;

    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }

    return result;
}

int main() {
    cin >> n >> k;

    if (n <= 1) {
        cout << 1 << endl;
        return 0;
    }

    for (int i = 0; i < n - 1; i++) {
        int u, v;
        if (!(cin >> u >> v) || u < 1 || u > n || v < 1 || v > n) {
            cerr << "Invalid input for edge: " << u << " " << v << endl;
            return 1;
        }
        adj[u].emplace_back(v);
        adj[v].emplace_back(u);
    }

    int diameter = calculate_diameter(1);

    if (diameter <= k) {
        cout << modpow(2, n - 1, MOD) << endl;
    } else {
        cout << 1 << endl;
    }

    return 0;
}

