class DiskScheduler {
public:
    DiskScheduler(int capacity) : capacity(capacity), time(0), disk(0) {
        if (capacity <= 0) {
            throw std::invalid_argument("Disk capacity must be a positive integer.");
        }
    }

    void scheduleTasks(const std::vector<int>& tasks) {
        for (const auto& task : tasks) {
            if (task < 0) {
                throw std::invalid_argument("Task time cannot be negative.");
            }
            processTask(task);
        }
    }

    int getTotalTime() const {
        return time;
    }

private:
    int capacity;
    int time;
    int disk;

    void processTask(int task) {
        if (disk + task <= capacity) {
            disk += task;
            time += task + 1;
        } else {
            time += capacity - disk + 1;
            disk = task;
        }
    }
};

