class Solution {
public:
    void dfs(std::vector<std::vector<int>>& grid, int row, int col, int originalColor, int m, int n) {
        if (row < 0 || row >= m || col < 0 || col >= n || grid[row][col] != originalColor) {
            return;
        }
        grid[row][col] = 3; // Mark as visited
        dfs(grid, row + 1, col, originalColor, m, n);
        dfs(grid, row - 1, col, originalColor, m, n);
        dfs(grid, row, col + 1, originalColor, m, n);
        dfs(grid, row, col - 1, originalColor, m, n);
    }

    void fillBorder(std::vector<std::vector<int>>& grid, int row, int col, int newColor, int m, int n) {
        if (row < 0 || row >= m || col < 0 || col >= n || grid[row][col] != 3) {
            return;
        }
        grid[row][col] = newColor;
        fillBorder(grid, row + 1, col, newColor, m, n);
        fillBorder(grid, row - 1, col, newColor, m, n);
        fillBorder(grid, row, col + 1, newColor, m, n);
        fillBorder(grid, row, col - 1, newColor, m, n);
    }

    std::vector<std::vector<int>> colorBorder(std::vector<std::vector<int>>& grid, int row, int col, int color) {
        if (grid.empty() || grid[0].empty() || row < 0 || row >= grid.size() || col < 0 || col >= grid[0].size()) {
            throw std::invalid_argument("Invalid row or column index.");
        }
        int m = grid.size(), n = grid[0].size();
        int originalColor = grid[row][col];
        if (originalColor == color) return grid; // No change needed
        dfs(grid, row, col, originalColor, m, n);
        fillBorder(grid, row, col, color, m, n);
        return grid;
    }
};

class Solution {
public:
    int preimageSizeFZF(int k) {
        if (k < 0) {
            logError("Invalid input: k must be non-negative.");
            return 0;
        }

        long left = 0;
        long right = 5 * static_cast<long>(k) + 5;

        while (left <= right) {
            long mid = left + (right - left) / 2;
            long zeros = countTrailingZeros(mid);

            if (zeros == k) {
                return 5; // Valid range found
            }
            if (zeros < k) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return 0; // No valid range found
    }

private:
    long countTrailingZeros(long num) {
        long count = 0;
        while (num > 0) {
            num /= 5;
            count += num;
        }
        return count;
    }

    void logError(const std::string& message) {
        // Simple logging to console for demonstration purposes
        std::cerr << "Error: " << message << std::endl;
    }
};

class Solution {
public:
    bool canPartition(vector<int>& nums) {
        if (nums.empty()) {
            logError("Input vector is empty.");
            return false;
        }

        int sum = 0;
        for (int num : nums) {
            if (num < 0) {
                logError("Negative number found in input: " + to_string(num));
                return false; // handle negative numbers
            }
            sum += num;
        }

        if (sum % 2 != 0) {
            logInfo("Total sum is odd: " + to_string(sum));
            return false;
        }

        int target = sum / 2;
        vector<bool> dp(target + 1, false);
        dp[0] = true;

        for (int num : nums) {
            for (int i = target; i >= num; --i) {
                dp[i] = dp[i] || dp[i - num];
            }
        }

        bool result = dp[target];
        logInfo("Partition possible: " + string(result ? "true" : "false"));
        return result;
    }

private:
    void logInfo(const string& message) {
        cout << "[INFO] " << message << endl;
    }

    void logError(const string& message) {
        cerr << "[ERROR] " << message << endl;
    }
};

