            return false;
        }

        std::vector<int> removalOrder;
        if (dfs(1, -1, removalOrder)) {
            removalOrder_ = std::move(removalOrder);
            return true;
        }
        return false;
    }

    void printResult() const {
        if (removalOrder_.empty()) {
            std::cout << "NO\n";
        } else {
            std::cout << "YES\n";
            for (const auto& edge : removalOrder_) {
                std::cout << edge.first << " " << edge.second << "\n";
            }
        }
    }

private:
    int n_;
    std::vector<std::pair<int, int>> edges_;
    std::unordered_map<int, std::vector<int>> graph_;
    std::vector<std::pair<int, int>> removalOrder_;

    void buildGraph() {
        for (const auto& edge : edges_) {
            graph_[edge.first].push_back(edge.second);
            graph_[edge.second].push_back(edge.first);
        }
    }

    bool validateOddDegreeVertices() const {
        int oddCount = 0;
        for (int i = 1; i <= n_; ++i) {
            if (graph_.at(i).size() % 2 != 0) {
                ++oddCount;
            }
        }
        return oddCount <= n_ / 2;
    }

    bool dfs(int v, int parent, std::vector<std::pair<int, int>>& removalOrder) {
        int oddChildren = 0, evenChildren = 0;

        for (int neighbor : graph_[v]) {
            if (neighbor != parent) {
                if (!dfs(neighbor, v, removalOrder)) {
                    return false;
                }
                if (graph_[neighbor].size() % 2 != 0) {
                    oddChildren++;
                } else {
                    evenChildren++;
                }
            }
        }

        if (parent != -1 && oddChildren % 2 != 0) {
            return false; // Cannot remove this edge as it leads to an odd child.
        }

        for (int neighbor : graph_[v]) {
            if (neighbor != parent) {
                removalOrder.emplace_back(v, neighbor);
            }
        }
        return true;
    }
};

