class Solution {
private:
    vector<vector<pair<int, long long>>> graph;
    vector<bool> visited;
    vector<long long> values;

    void depthFirstSearch(long long node, long long parent) {
        while (!graph[node].empty()) {
            auto edge = graph[node].back();
            if (!visited[edge.first]) {
                visited[edge.first] = true;
                depthFirstSearch(edge.first, node);
                values[node] ^= values[edge.first];
            }
            graph[node].pop_back();
        }
    }

public:
    int maxXorTree(vector<int>& vals, int k, vector<vector<int>>& edges) {
        const int BIT_WIDTH = 30;
        int numNodes = vals.size();
        values.resize(numNodes);
        for (int i = 0; i < numNodes; i++) {
            values[i] = vals[i];
        }
        graph.resize(numNodes);
        for (const auto& edge : edges) {
            graph[edge[0]].emplace_back(edge[1], vals[edge[1]]);
            graph[edge[1]].emplace_back(edge[0], vals[edge[0]]);
        }

        vector<long long> result(BIT_WIDTH, -1);
        for (int bit = 0; bit < BIT_WIDTH; bit++) {
            bool includesOne = (k >> bit) & 1;
            visited.assign(numNodes, false);
            int zeroCount = 0;
            int oneCount = 0;

            for (int node = 0; node < numNodes; node++) {
                if (!visited[node]) {
                    visited[node] = true;
                    zeroCount += ((values[node] >> bit) & 1);
                }
            }
            oneCount = numNodes - zeroCount;

            if (zeroCount & 1) {
                result[bit] = max(zeroCount, oneCount);
                if (includesOne) {
                    result[bit]--;
                }
            } else {
                result[bit] = includesOne ? max(zeroCount, oneCount) : max(zeroCount - 1, oneCount + 1);
            }
        }

        int finalResult = 0;
        for (int bit = 0; bit < BIT_WIDTH; bit++) {
            finalResult += (result[bit] << bit);
        }
        return finalResult;
    }
}; 

