#include <stdexcept>

using namespace std;

class Solution {
public:
    vector<vector<int>> tree;
    vector<int> price, depth, up;
    int n, LOG;

    Solution(int nodes, const vector<int>& prices) : n(nodes), price(prices) {
        if (n <= 0) {
            throw invalid_argument("Number of nodes must be positive.");
        }
        tree.resize(n);
        LOG = log2(n) + 1;
        depth.resize(n, 0);
        up.resize(n * LOG, 0);
    }

    void addEdge(int u, int v) {
        if (u >= n || v >= n) {
            throw out_of_range("Node index out of range.");
        }
        tree[u].push_back(v);
        tree[v].push_back(u);
    }

    void dfs(int node, int parent) {
        up[node * LOG] = parent;
        for (int i = 1; i < LOG; ++i) {
            if (up[node * LOG + i - 1] != -1) {
                up[node * LOG + i] = up[up[node * LOG + i - 1] * LOG + i - 1];
            }
        }
        for (int child : tree[node]) {
            if (child != parent) {
                depth[child] = depth[node] + 1;
                dfs(child, node);
            }
        }
    }

    int lca(int u, int v) {
        if (depth[u] < depth[v]) swap(u, v);
        for (int i = LOG - 1; i >= 0; --i) {
            if (depth[up[u * LOG + i]] >= depth[v]) {
                u = up[u * LOG + i];
            }
        }
        if (u == v) return u;
        for (int i = LOG - 1; i >= 0; --i) {
            if (up[u * LOG + i] != up[v * LOG + i]) {
                u = up[u * LOG + i];
                v = up[v * LOG + i];
            }
        }
        return up[u * LOG];
    }

    vector<int> calculateTripCost(const vector<pair<int, int>>& trips) {
        vector<int> visitCount(n, 0);
        for (const auto& trip : trips) {
            int lcaNode = lca(trip.first, trip.second);
            visitCount[trip.first]++;
            visitCount[trip.second]++;
            visitCount[lcaNode]--;
            if (up[lcaNode * LOG] != -1) visitCount[up[lcaNode * LOG]]--;
        }
        return visitCount;
    }

    int minimizeTotalPrice(const vector<pair<int, int>>& trips) {
        vector<int> visitCount = calculateTripCost(trips);
        vector<pair<int, int>> benefits;

        for (int i = 0; i < n; ++i) {
            benefits.emplace_back((price[i] / 2) * visitCount[i], i);
        }
        sort(benefits.rbegin(), benefits.rend());

        vector<bool> selected(n, false);
        int minimizedCost = accumulate(price.begin(), price.end(), 0);

        for (const auto& benefit : benefits) {
            int node = benefit.second;
            if (!selected[node]) {
                selected[node] = true;
                minimizedCost -= benefit.first;
                // Mark non-adjacent nodes (simple approach)
                for (int neighbor : tree[node]) {
                    selected[neighbor] = false; // naive adjacency marking
                }
            }
        }
        return minimizedCost;
    }
};

