class DigitFinder {
public:
    static std::optional<int> secondLargestDigit(const std::string& input) {
        if (input.empty()) {
            logError("Input string is empty");
            return std::nullopt;
        }

        std::set<int> digits;

        for (char c : input) {
            if (std::isdigit(c)) {
                digits.insert(c - '0');
            }
        }

        if (digits.size() < 2) {
            logWarning("Less than two unique digits found");
            return std::nullopt;
        }

        auto it = std::next(digits.rbegin());
        return *it;
    }

private:
    static void logError(const std::string& message) {
        std::cerr << "ERROR: " << message << std::endl;
    }

    static void logWarning(const std::string& message) {
        std::cout << "WARNING: " << message << std::endl;
    }
};

