/**
 * Function to compute the power of a number modulo MOD.
 */
ll mod_pow(ll base, ll exp) {
    if (exp < 0) throw invalid_argument("Exponent must be non-negative.");
    ll result = 1;
    while (exp > 0) {
        if (exp & 1) result = result * base % MOD;
        base = base * base % MOD;
        exp >>= 1;
    }
    return result;
}

