void processQueries(int n, int q) {
    vector<int> sick(n + 1, -1);
    vector<vector<pair<int, int>>> ranges(n + 1);

    for (int i = 0; i < q; ++i) {
        int t;
        cin >> t;

        try {
            if (t == 0) {
                int l, r, x;
                cin >> l >> r >> x;

                if (l < 1 || r > n || l > r || x < 0) {
                    throw invalid_argument("Invalid range or value.");
                }

                ranges[l].emplace_back(r, 2 * x - 1);
            } else {
                int j;
                cin >> j;

                if (j < 1 || j > n) {
                    throw out_of_range("Query index out of bounds.");
                }

                int ub = 1, lb = -1;
                for (int k = 1; k <= j; ++k) {
                    if (sick[k] == 1) lb = 1;
                    if (sick[k] == 0) ub = 0;

                    for (const auto &p : ranges[k]) {
                        if (p.first < j) continue;
                        lb = max(lb, p.second + 1);
                        ub = min(ub, p.second + 1);
                    }
                }

                if (lb == 1) {
                    cout << "YES\n";
                } else if (ub == 0) {
                    cout << "NO\n";
                } else {
                    cout << "N/A\n";
                }
            }
        } catch (const exception &e) {
            cerr << "Error processing query " << i + 1 << ": " << e.what() << '\n';
        }
    }
}

