class ConnectionCostCalculator {
public:
    // Function to calculate the minimum cost of connecting two groups
    int minCostToConnectGroups(const std::vector<std::vector<int>>& cost) {
        // Validate input dimensions
        if (cost.empty() || cost[0].empty()) {
            throw std::invalid_argument("Cost matrix cannot be empty");
        }

        int n = cost.size(), m = cost[0].size();
        // Initialize matrices for connection costs with maximum integer values
        std::vector<std::vector<int>> costs2(n, std::vector<int>(m, std::numeric_limits<int>::max()));
        std::vector<std::vector<int>> subMatrix(n, std::vector<int>(m, std::numeric_limits<int>::max()));

        // Fill the subMatrix with direct connection costs
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                // Ensure the current cost is considered for connection
                subMatrix[i][j] = cost[i][j];
            }
        }

        // Calculate minimum costs to connect points from two groups
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                // Update costs2 with the minimum costs gathered from previous connections
                if (i > 0) {
                    costs2[i][j] = std::min(costs2[i][j], subMatrix[i][j] + costs2[i - 1][j]);
                }
                if (j > 0) {
                    costs2[i][j] = std::min(costs2[i][j], subMatrix[i][j] + costs2[i][j - 1]);
                }
            }
        }

        // The minimum cost to connect all points in the first group to the last point in the second group
        return costs2[n - 1][m - 1];
    }
};

int main() {
    ConnectionCostCalculator calculator;
    std::vector<std::vector<int>> cost = {{1, 3, 5}, {4, 1, 1}, {1, 5, 3}};

    try {
        int result = calculator.minCostToConnectGroups(cost);
        std::cout << result; // Output: 4
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << '\n';
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

