#include <iostream>
#include <vector>
#include <string>
#include <utility>

std::vector<std::pair<int, int>> find_balanced_substring(const std::vector<std::pair<int, std::string>>& test_cases) {
    std::vector<std::pair<int, int>> results;

    for (const auto& test_case : test_cases) {
        int n = test_case.first;
        const std::string& s = test_case.second;

        if (n <= 0 || s.length() != n) {
            std::cerr << "Error: Invalid input size or string length mismatch." << std::endl;
            results.emplace_back(-1, -1);
            continue;
        }

        bool found = false;

        for (int l = 0; l < n; ++l) {
            int count_a = 0;
            int count_b = 0;

            for (int r = l; r < n; ++r) {
                if (s[r] == 'a') {
                    count_a++;
                } else if (s[r] == 'b') {
                    count_b++;
                } else {
                    std::cerr << "Error: String contains invalid characters." << std::endl;
                    results.emplace_back(-1, -1);
                    found = true;
                    break;
                }

                if (count_a == count_b) {
                    results.emplace_back(l + 1, r + 1);
                    found = true;
                    break;
                }
            }

            if (found) {
                break;
            }
        }

        if (!found) {
            results.emplace_back(-1, -1);
        }
    }

    return results;
}

int main() {
    int t;
    std::cout << "Enter number of test cases: ";
    std::cin >> t;

    if (t <= 0) {
        std::cerr << "Error: Number of test cases must be positive." << std::endl;
        return EXIT_FAILURE;
    }

    std::vector<std::pair<int, std::string>> test_cases;
    test_cases.reserve(t);

    for (int i = 0; i < t; ++i) {
        int n;
        std::string s;
        std::cout << "Enter size of string for test case " << i + 1 << ": ";
        std::cin >> n;
        std::cout << "Enter string for test case " << i + 1 << ": ";
        std::cin >> s;

        test_cases.emplace_back(n, s);
    }

    auto results = find_balanced_substring(test_cases);
    for (const auto& result : results) {
        std::cout << result.first << " " << result.second << std::endl;
    }

    return 0;
}

