        if (isValidUrl(repositoryUrl)) {
            std::string command = "git clone " + repositoryUrl;
            if (system(command.c_str()) == 0) {
                logSuccess();
            } else {
                logError("Failed to clone repository.");
            }
        } else {
            logError("Invalid repository URL: " + repositoryUrl);
        }
