#include <vector>
#include <unordered_map>
#include <iostream>

class Solution {
public:
    std::vector<int> loudAndRich(std::vector<std::vector<int>>& richer, std::vector<int>& quiet) {
        // Initialize data structures
        std::unordered_map<int, std::vector<int>> richerGraph;
        std::vector<int> result(quiet.size(), -1);
        int n = quiet.size();

        // Build the adjacency list for the richer relationships
        for (const auto& pair : richer) {
            int u = pair[0];
            int v = pair[1];
            richerGraph[v].push_back(u);
        }

        // Helper function to perform DFS
        std::function<int(int)> dfs = [&](int person) {
            if (result[person] != -1) {
                return result[person];
            }

            int quietest = person;
            for (int richerPerson : richerGraph[person]) {
                int candidate = dfs(richerPerson);
                if (quiet[candidate] < quiet[quietest]) {
                    quietest = candidate;
                }
            }
            return result[person] = quietest;
        };

        // Iterate through each person, checking their quietness
        for (int i = 0; i < n; ++i) {
            dfs(i);
        }

        return result;
    }
};

