using namespace std;

int longestStrangeSubsequence(const vector<int>& a) {
    if (a.empty()) return 0;

    vector<int> sorted_a = a;
    sort(sorted_a.begin(), sorted_a.end());
    long long n = sorted_a.size();
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));

    for (int i = 1; i <= n; ++i) {
        dp[i][i] = 1;
        for (int j = i - 1; j >= 0; --j) {
            if (sorted_a[i - 1] - sorted_a[j] >= sorted_a[i - 1]) {
                dp[i][j] = max(dp[i][j], dp[i - 1][j + 1] + 1);
            }
        }
    }

    int max_length = 0;
    for (int i = 1; i <= n; ++i) {
        max_length = max(max_length, dp[i][n]);
    }
    return max_length;
}

int processTestCases(const vector<vector<int>>& numbers) {
