#include <iostream>
#include <vector>
#include <unordered_map>
#include <stdexcept>

class Solution {
public:
    int minimumLength(std::vector<int>& nums) {
        if (nums.empty()) {
            return 0; // Early return for empty input
        }

        std::unordered_map<int,int> indexMap;
        for (size_t i = 0; i < nums.size(); ++i) {
            indexMap[nums[i]] = i;
        }

        auto it = nums.begin();
        try {
            while (nums.size() > 0 && it != nums.end()) {
                auto next = std::next(it);
                if (next == nums.end()) {
                    break; // Avoid dereferencing end iterator
                }

                if (*it >= *next) {
                    nums.erase(it);
                    nums.erase(next);
                    it = nums.begin(); // Reset iterator to start after erase
                } else {
                    ++it;
                }

                if (indexMap.find(*it) != indexMap.end()) {
                    while (next != nums.end() && *it == *next) {
                        next = nums.erase(next);
                    }
                }
            }
        } catch (const std::exception& e) {
            std::cerr << "Error processing the array: " << e.what() << std::endl;
            return -1; // Error code for exception handling
        }

        return nums.size();
    }
};

