class Solution {
public:
    vector<int> distinctDifferenceArray(vector<int>& nums) {
        if (nums.empty()) {
            return {};
        }

        unordered_map<int, int> elementCount;
        for (const auto& num : nums) {
            elementCount[num]++;
        }

        vector<unordered_map<int, int>> prefixFrequencies(nums.size());
        for (size_t i = 0; i < nums.size(); ++i) {
            prefixFrequencies[i] = elementCount;
            if (i > 0) {
                prefixFrequencies[i][nums[i]]--;
            }
        }

        vector<unordered_map<int, int>> suffixFrequencies(nums.size());
        for (int i = nums.size() - 1; i >= 0; --i) {
            if (i != nums.size() - 1) {
                suffixFrequencies[i] = suffixFrequencies[i + 1];
            }
            suffixFrequencies[i][nums[i]]--;
        }

        vector<int> result;
        for (size_t i = 0; i < nums.size(); ++i) {
            int uniqueCountPrefix = countNonZeroFrequencies(prefixFrequencies[i]);
            int uniqueCountSuffix = countNonZeroFrequencies(suffixFrequencies[i]);

            result.push_back(uniqueCountPrefix - uniqueCountSuffix);

            prefixFrequencies[i][nums[i]]++;
            suffixFrequencies[i][nums[i]]++;
        }

        return result;
    }

private:
    int countNonZeroFrequencies(const unordered_map<int, int>& freqMap) {
        return std::count_if(freqMap.begin(), freqMap.end(), [](const auto& pair) {
            return pair.second > 0; 
        });
    }
};

