        try {
            for (size_t i = 0; i < caseCosts.size(); ++i) {
                int total = sumExpenses(caseCosts[i]);
                results.push_back(total);
                logMessage("In test case " + std::to_string(i + 1) + ", total expense is: $" + std::to_string(total));
