class UnpleasantValueCalculator {
public:
    static int minUnpleasantValue(const std::vector<int>& t, int n) {
        if (n <= 0) {
            std::cerr << "Error: size of vector must be greater than 0." << std::endl;
            return -1; // Error code
        }

        std::vector<std::vector<int>> dp(n + 1, std::vector<int>(n + 1, std::numeric_limits<int>::max()));
        dp[0][0] = 0;

        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= i; ++j) {
                dp[i][j] = std::min(dp[i - 1][j - 1] + std::abs(t[i - 1] - j), dp[i - 1][j]);
            }
        }

        int result = std::numeric_limits<int>::max();
        for (int j = 1; j <= n; ++j) {
            result = std::min(result, dp[n][j]);
        }

        return result;
    }
};

