#include <iostream>
#include <vector>
#include <stack>
#include <cstring>
#include <stdexcept>
#include <algorithm>

const int MAX_NODES = 510;
std::vector<std::vector<int>> adjMatrix(MAX_NODES);
std::stack<int> longestPathStack;
bool visited[MAX_NODES];
int parent[MAX_NODES];

void DFS(int node) {
    visited[node] = true;
    for (int adjNode : adjMatrix[node]) {
        if (!visited[adjNode]) {
            parent[adjNode] = node;
            DFS(adjNode);
            longestPathStack.push(node);
        }
    }
}

bool hasCycle() {
    if (longestPathStack.empty()) return false;
    int node = longestPathStack.top();
    longestPathStack.pop();
    return visited[parent[node]];
}

int calculateMaxGroups(int n) {
    std::memset(visited, 0, sizeof(visited));
    std::memset(parent, -1, sizeof(parent));

    for (int i = 0; i < n; ++i) {
        if (!visited[i]) {
            DFS(i);
        }
    }

    if (longestPathStack.empty()) {
        return n;
    }

    int longestDistance = 0;
    int stackSize = longestPathStack.size();
    for (int i = 0; i < stackSize; ++i) {
        longestDistance = std::max(longestDistance, stackSize - longestPathStack.top());
        longestPathStack.pop();
    }

    if (longestDistance == n) {
        return n + 1;
    }

    if (hasCycle()) {
        return n;
    }

    return -1; // Error condition
}

int main() {
    try {
        int n = 4; // Example number of nodes
        std::vector<std::vector<int>> edges = {{1, 0}, {1, 2}, {2, 3}}; // Actual edges

        for (const auto& edge : edges) {
            if (edge[0] >= MAX_NODES || edge[1] >= MAX_NODES) {
                throw std::out_of_range("Node index exceeds maximum allowed.");
            }
            adjMatrix[edge[0]].push_back(edge[1]);
            adjMatrix[edge[1]].push_back(edge[0]); // Undirected graph
        }

        int result = calculateMaxGroups(n);
        std::cout << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

