#define LL long long

void dfs(std::vector<LL>& f, std::vector<LL>& s, LL a = 0, LL b = 0) {
    LL c = std::abs(a - b);
    if (a < 1 || b < 1 || c > 1e10) return;

    f.push_back(a);
    s.push_back(b);
    s.push_back(c);

    dfs(f, s);
    dfs(f.end() - 3, s.end() - 5, c, b);
    dfs(f.end() - 4, s.end(), a, c);
    dfs(&*(f.end() - 1), s, c, *(f.end() - 1));
    dfs(f.end() + 4, s, *(f.end() + 1), a);
}

int main() {
    std::vector<LL> f;
    std::vector<LL> s;

    while (true) {
        LL t;
        std::cout << "Enter a value (0 to exit): ";
        std::cin >> t;

        if (t == 0) break;

        f.clear();
        s.clear();
        f.push_back(1e4 * t + 2);
        dfs(f, s);

        for (LL i = 1e4; i > 0; --i) {
            if (i < f.size() && f[i] > 1e6) {
                for (int j = i * t + 1; j < 1e5; j += t) {
                    std::cout << f[j - 1] << " ";
                }
                break;
            }
        }
        std::cout << std::endl;
    }
    return 0;
}

