public:
    static std::tuple<std::string, int, std::vector<std::string>> parse(const std::string &line) {
        std::istringstream iss(line);
        std::string name;
        int age;
        std::vector<std::string> emails;
        std::string email;

        try {
            if (!(iss >> std::quoted(name) >> age)) {
