class Solution {
public:
    int triangularSum(vector<int>& nums) {
        if (nums.empty()) {
            logError("Input vector is empty.");
            return 0;  // or an appropriate error code
        }

        if (nums.size() == 1) {
            return nums[0] % 10;  // single element case
        }

        while (nums.size() > 1) {
            int sz = nums.size();
            vector<int> f(sz - 1);

            for (int i = 0; i < sz - 1; ++i) {
                f[i] = (nums[i] + nums[i + 1]) % 10;
            }

            nums.swap(f);  // Efficient swap instead of copying
        }

        return nums[0];
    }

private:
    void logError(const std::string& message) {
        // A simple logging mechanism; in production, consider using a logging library.
        std::cerr << "Error: " << message << std::endl;
    }
};

class ListNode {
public:
    int val;
    ListNode* next;

    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode* next) : val(x), next(next) {}
};

class Solution {
public:
    ListNode* swapNodes(ListNode* head, int k) {
        if (!head || k <= 0) {
            logError("Invalid input: head is null or k is non-positive.");
            return nullptr;
        }

        ListNode* start = nullptr;
        ListNode* end = head;
        ListNode* current = head;

        // Traverse to find the kth node from the beginning
        for (int i = 1; i < k && current; i++) {
            current = current->next;
        }

        if (!current) {
            logError("Invalid k: exceeds the list length.");
            return nullptr;
        }

        start = current;

        // Move current to the end, and end will now point to the kth node from the end
        while (current->next) {
            current = current->next;
            end = end->next;
        }

        // Swap values of the kth nodes
        if (start != end) { // Only swap if they are different nodes
            int temp = start->val;
            start->val = end->val;
            end->val = temp;
        }

        return head;
    }

private:
    void logError(const std::string& message) {
        // Simple logging function to handle error messages (replace with actual logging as needed)
        std::cerr << "Error: " << message << std::endl;
    }
};

