constexpr int MOD = 1e9 + 7;
const int MAX_NODES = 200010;
const int LOG = 20;

std::vector<std::pair<int, int>> g[MAX_NODES];
int deep[MAX_NODES] = {0};
int down[MAX_NODES][LOG] = {0};
int dp[MAX_NODES][LOG] = {-1};
int path[MAX_NODES] = {0};
int n = 0, edge = 0;

void dfs(int x) {
    for (const auto& [y, w] : g[x]) {
        if (y == path[x]) continue;
        path[y] = x;
        deep[y] = deep[x] + 1;
        dfs(y);
    }
}

int get(int x, int y) {
    int res = 0;

    if (deep[x] < deep[y]) std::swap(x, y);
    int diff = deep[x] - deep[y];

    for (int i = 0; i < LOG; ++i) {
        if ((diff >> i) & 1) {
            res += dp[x][i];
            x = down[x][i];
        }
    }

    if (x == y) return res;

    for (int i = LOG - 1; i >= 0; --i) {
        if (down[x][i] != down[y][i]) {
            res += dp[x][i] + dp[y][i];
            x = down[x][i];
            y = down[y][i];
        }
    }
    res += dp[x][0] + dp[y][0];

    return res;
}

int solve(int u, int d) {
    if (d == 1) return 1;
    if (dp[u][d] != -1) return dp[u][d];

    dp[u][d] = 0;
    for (int i = 1; i < d; ++i) {
        dp[u][d] = (dp[u][d] + solve(down[u][i], d - i)) % MOD;
    }

    return dp[u][d];
}

