class EventCalculator {
public:
    EventCalculator(int numCases, std::vector<std::vector<int>> data)
        : numCases(numCases), data(std::move(data)) {}

    void processCases() {
        for (int t = 0; t < numCases; ++t) {
            processSingleCase(data[t]);
        }
    }

private:
    int numCases;
    std::vector<std::vector<int>> data;

    std::vector<int> foo(const std::vector<int>& l, int a, int ind) {
        std::vector<int> ans;
        int count = std::count_if(l.begin() + ind, l.end(), [a](int el) { return el <= a; });
        ans.push_back(count);
        return ans;
    }

    void processSingleCase(const std::vector<int>& l) {
        int a;
        std::cin >> a;

        if (a < 2) {
            std::cout << 0 << std::endl;
            return;
        }

        std::vector<std::vector<int>> tree;
        int n = l.size();

        for (int ind = 0; ind <= n; ++ind) {
            for (int ind2 = ind; ind2 <= n; ++ind2) {
                int sum = std::accumulate(l.begin() + ind, l.begin() + ind2, 0);

                if (sum == a) {
                    tree.push_back({a, foo(l, a, ind)[0], ind, ind2});
                } else if (sum > a) {
                    tree.push_back({a, foo(l, a, ind)[0], ind, ind2 - 1});
                    break;
                }
            }
        }

        int count = 0;
        std::vector<std::vector<int>> level = tree;
        while (level.size() > 1) {
            tree.clear();
            tree.push_back(level[0]);

            for (size_t j = 1; j < level.size(); ++j) {
                if (tree[0][0] > level[j][0]) {
                    tree.clear();
                    tree.push_back(level[j]);
                } else {
                    tree.back()[1] += level[j][1];
                }
            }
            level = tree;
            ++count;
        }

        std::cout << count << std::endl;
    }
};

