    int numCases;
    std::cin >> numCases;
    std::vector<std::vector<int>> data(numCases);

    for (int i = 0; i < numCases; ++i) {
        int n;
        std::cin >> n;
        data[i].resize(n);
        for (int j = 0; j < n; ++j) {
            std::cin >> data[i][j];
        }
    }

    EventCalculator calculator(numCases, data);
    calculator.processCases();

    return 0;
}

