class OddElementFinder {
public:
    OddElementFinder(int size) : n(size), pos(size * 4) {}

    void addElement(int index, int value) {
        if (elementMap.find(value) == elementMap.end()) {
            elementMap[value] = pos.size();
            pos.push_back({});
        }
        pos[elementMap[value]].push_back(index + 1);
    }

    int getMinOdd(int left, int right) const {
        int result = numeric_limits<int>::max();
        for (int i = 0; i < 32; ++i) {
            auto lower = lower_bound(pos[i].begin(), pos[i].end(), left);
            auto upper = upper_bound(pos[i].begin(), pos[i].end(), right);
            if ((upper - lower) % 2 != 0) {
                result = min(result, i);
            }
        }
        return (result == numeric_limits<int>::max()) ? 0 : result;
    }

private:
    int n;
    vector<vector<int>> pos;
    unordered_map<int, int> elementMap;
};

