        cerr << "Error: 'n' out of valid range." << endl;
        return 1;
    }

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    OddElementFinder finder(n);
    for (int i = 0; i < n; ++i) {
        finder.addElement(i, a[i]);
    }

    cin >> q;
    if (q < 1) {
        cerr << "Error: Invalid query count." << endl;
