class Solution {
public:
    int minimumSum(std::vector<int>& nums) {
        size_t n = nums.size();
        if (n < 3) {
            std::cerr << "Error: Input vector must have at least 3 elements." << std::endl;
            return -1;
        }

        std::vector<int> pref(n), suff(n);
        pref[0] = 1;
        suff[n - 1] = n;

        for (size_t i = 1; i < n; ++i) {
            if (nums[i] <= nums[pref[i - 1] - 1]) {
                pref[i] = static_cast<int>(i + 1);
            } else {
                pref[i] = pref[i - 1];
            }
        }

        for (size_t i = n - 2; i > 0; --i) {
            if (nums[i] >= nums[suff[i + 1] - 1]) {
                suff[i] = static_cast<int>(i);
            } else {
                suff[i] = suff[i + 1];
            }
        }

        int ans = std::numeric_limits<int>::max();
        bool found = false;

        for (size_t i = 1; i < n - 1; ++i) {
            if (pref[i - 1] < pref[i] && suff[i] > suff[i + 1] && nums[i] < nums[pref[i] - 1] && nums[i] < nums[suff[i] - 1]) {
                ans = std::min(ans, nums[i] + nums[pref[i] - 1] + nums[suff[i] - 1]);
                found = true;
            }
        }

        return found ? ans : -1;
    }

    TreeNode* recoverFromPreorder(const std::string& S) {
        std::vector<TreeNode*> path;
        size_t i = 0;

        while (i < S.length()) {
            int level = 0;

            while (i < S.length() && S[i] == '-') {
                ++level;
                ++i;
            }

            if (i >= S.length()) {
                std::cerr << "Error: Invalid input format." << std::endl;
                return nullptr;
            }

            int val = 0;
            while (i < S.length() && std::isdigit(S[i])) {
                val = val * 10 + (S[i++] - '0');
            }

            TreeNode* node = new TreeNode(val);

            if (level == path.size()) {
                if (!path.empty()) {
                    path.back()->left = node;
                }
                path.push_back(node);
            } else {
                while (path.size() > level) {
                    path.pop_back();
                }
                path.back()->right = node;
                path.push_back(node);
            }
        }

        while (path.size() > 1) {
            path.pop_back();
        }

        return path.empty() ? nullptr : path.back();
    }
};

