        int originalNumber = number;

        while (number) {
            if (number % 10 == number) {
                number /= 10;
            } else {
                int sum = calculateDigitSum(number);
                if (sum > 0) {
                    number = originalNumber; // Reset to original number if sum is valid
                    number /= sum;
                }
