#include <iostream>
#include <stdexcept>

class VectorOperations {
public:
    static int findMax(const std::vector<int>& numbers) {
        if (numbers.empty()) {
            throw std::invalid_argument("Input vector is empty.");
        }

        int maxValue = INT_MIN;
        for (const int& num : numbers) {
            if (num > maxValue) {
                maxValue = num;
            }
        }
        return maxValue;
    }

    static int findMin(const std::vector<int>& numbers) {
        if (numbers.empty()) {
            throw std::invalid_argument("Input vector is empty.");
        }

        int minValue = INT_MAX;
        for (const int& num : numbers) {
            if (num < minValue) {
                minValue = num;
            }
        }
        return minValue;
    }

    static double calculateAverage(const std::vector<int>& numbers) {
        if (numbers.empty()) {
            throw std::invalid_argument("Input vector is empty.");
        }

        long long sum = 0;
        for (const int& num : numbers) {
            sum += num;
        }
        return static_cast<double>(sum) / numbers.size();
    }

    static void displayResults(const std::vector<int>& numbers) {
        try {
            std::cout << "Max: " << findMax(numbers) << std::endl;
            std::cout << "Min: " << findMin(numbers) << std::endl;
            std::cout << "Average: " << calculateAverage(numbers) << std::endl;
        } catch (const std::invalid_argument& e) {
            std::cerr << "Error: " << e.what() << std::endl;
        }
    }
};

int main() {
    std::vector<int> numbers = {1, 2, 3, 4, 5};

    VectorOperations::displayResults(numbers);

    return 0;
}

