std::string intToString(int num) {
    if (num < 0) {
        throw std::invalid_argument("Negative numbers are not supported.");
    }
    std::string result;
    do {
        result = static_cast<char>((num % 10) + '0') + result;
        num /= 10;
    } while (num > 0);
    return result;
}

