#include <vector>
#include <unordered_set>
#include <algorithm>
#include <iostream>

class Solution {
public:
    int minMalwareSpread(std::vector<std::vector<int>>& graph, std::vector<int>& initial) {
        int n = graph.size();
        if (n == 0 || initial.empty()) {
            std::cerr << "Error: The graph is empty or no initial nodes provided." << std::endl;
            return -1; // Error code for invalid inputs
        }

        std::unordered_set<int> malwareNodes(initial.begin(), initial.end());
        std::vector<bool> visited(n, false);
        std::vector<int> malwareSpreadCount(n, 0);

        for (int node : initial) {
            if (node < 0 || node >= n) {
                std::cerr << "Error: Invalid node in initial list: " << node << std::endl;
                return -1; // Error code for invalid initial nodes
            }
            std::fill(visited.begin(), visited.end(), false);
            int count = dfs(graph, node, visited, malwareNodes);
            malwareSpreadCount[node] = count;
        }

        int minNode = *std::min_element(initial.begin(), initial.end());
        int maxSpread = 0;

        for (int node : initial) {
            if (malwareSpreadCount[node] > maxSpread ||
                (malwareSpreadCount[node] == maxSpread && node < minNode)) {
                maxSpread = malwareSpreadCount[node];
                minNode = node;
            }
        }

        return minNode;
    }

private:
    int dfs(const std::vector<std::vector<int>>& graph, int node, std::vector<bool>& visited, 
            const std::unordered_set<int>& malwareNodes) {
        if (visited[node]) return 0;
        visited[node] = true;

        int spread = malwareNodes.count(node) ? 0 : 1; 

        for (int i = 0; i < graph.size(); ++i) {
            if (graph[node][i] == 1 && !visited[i]) {
                spread += dfs(graph, i, visited, malwareNodes);
            }
        }
        return spread;
    }
};

