#include <iostream>
#include <queue>

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;

    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    TreeNode* addOneRow(TreeNode* root, int val, int depth) {
        if (depth < 1) {
            std::cerr << "Depth must be at least 1." << std::endl;
            return root;
        }

        TreeNode* newRoot = new TreeNode(0); // Temporary root for depth handling
        newRoot->left = root;

        if (depth == 1) {
            TreeNode* newNode = new TreeNode(val);
            newNode->left = root;
            return newNode;
        }

        std::queue<TreeNode*> queue;
        queue.push(newRoot);
        int currentDepth = 1;

        while (!queue.empty() && currentDepth < depth) {
            int levelSize = queue.size();
            for (int i = 0; i < levelSize; ++i) {
                TreeNode* currentNode = queue.front();
                queue.pop();

                if (currentDepth == depth - 1) {
                    TreeNode* newNode = new TreeNode(val);
                    newNode->left = currentNode->left;
                    currentNode->left = newNode;

                    newNode = new TreeNode(val);
                    newNode->right = currentNode->right;
                    currentNode->right = newNode;
                } else {
                    if (currentNode->left) {
                        queue.push(currentNode->left);
                    }
                    if (currentNode->right) {
                        queue.push(currentNode->right);
                    }
                }
            }
            ++currentDepth;
        }

        TreeNode* finalRoot = newRoot->left; 
        delete newRoot; // Clean up temporary root
        return finalRoot;
    }
};

#include <iostream>
#include <vector>
#include <algorithm>
#include <stdexcept>

class PermutationSorter {
public:
    static int min_operations_to_sort(const std::vector<int>& perm) {
        validate_permutation(perm);
        int n = perm.size();
        std::vector<int> sorted_perm = perm;
        std::sort(sorted_perm.begin(), sorted_perm.end());

        std::vector<int> indices(n);
        for (int i = 0; i < n; ++i) {
            indices[perm[i] - 1] = i; // Assume elements are 1-based
        }

        std::vector<bool> visited(n, false);
        int operations = 0;

        for (int i = 0; i < n; ++i) {
            if (visited[i] || indices[i] == i) {
                continue;
            }
            operations += count_cycle_operations(indices, visited, i);
        }

        return operations;
    }

private:
    static void validate_permutation(const std::vector<int>& perm) {
        int n = perm.size();
        std::vector<bool> present(n + 1, false);

        for (int num : perm) {
            if (num <= 0 || num > n || present[num]) {
                throw std::invalid_argument("Invalid permutation input.");
            }
            present[num] = true;
        }
    }

    static int count_cycle_operations(const std::vector<int>& indices, std::vector<bool>& visited, int start) {
        int cycle_size = 0;
        int j = start;

        while (!visited[j]) {
            visited[j] = true;
            j = indices[j];
            cycle_size++;
        }

        return (cycle_size > 0) ? (cycle_size - 1) : 0;
    }
};

int main() {
    try {
        int t;
        std::cin >> t;
        while (t--) {
            int n;
            std::cin >> n;
            std::vector<int> perm(n);
            for (int i = 0; i < n; ++i) {
                std::cin >> perm[i];
            }
            std::cout << PermutationSorter::min_operations_to_sort(perm) << std::endl;
        }
    } catch (const std::invalid_argument& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}

