class SubstringFinder {
public:
    static size_t longestSubstringWithKDistinct(const std::string& s, size_t k) {
        if (k == 0 || s.empty()) {
            return 0;
        }

        if (k >= s.length()) {
            return s.length();
        }

        size_t left = 0, right = 0, maxLength = 0;
        std::unordered_map<char, size_t> charCount;

        while (right < s.length()) {
            charCount[s[right]]++;

            while (charCount.size() > k) {
                charCount[s[left]]--;
                if (charCount[s[left]] == 0) {
                    charCount.erase(s[left]);
                }
                left++;
            }

            maxLength = std::max(maxLength, right - left + 1);
            right++;
        }

        return maxLength;
    }

    static void validateInput(const std::string& s, size_t k) {
        if (k < 0) {
            throw std::invalid_argument("k must be non-negative");
        }
    }
};

// Example usage and validation
int main() {
    try {
        std::string testString = "eceba";
        size_t k = 2;
        SubstringFinder::validateInput(testString, k);
        size_t result = SubstringFinder::longestSubstringWithKDistinct(testString, k);
        std::cout << "Longest substring length: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}

class Solution {
public:
    int minLines(vector<vector<int>>& stockPrices) {
        if (stockPrices.empty() || stockPrices[0].size() < 2) {
            throw invalid_argument("Input stockPrices must contain at least one price with two elements.");
        }

        // Sort based on price (y-coordinate)
        try {
            sort(stockPrices.begin(), stockPrices.end(), [](const vector<int>& a, const vector<int>& b) {
                return a[1] < b[1];
            });
        } catch (const exception& e) {
            cerr << "Sorting failed: " << e.what() << endl;
            throw;
        }

        int maxHeight = stockPrices[0][1];
        int lineCount = 1;

        for (size_t i = 1; i < stockPrices.size(); ++i) {
            if (stockPrices[i].size() < 2) {
                cerr << "Invalid price entry at index " << i << ": insufficient elements." << endl;
                continue; // Skip invalid entries
            }

            if (stockPrices[i][1] > maxHeight) {
                ++lineCount;
                maxHeight = stockPrices[i][1];
            }
        }

        return lineCount;
    }
};

