class PlaylistGenerator {
public:
    static int numMusicPlaylists(int n, int goal, int k) {
        // Input validation
        if (n <= 0 || goal <= 0 || k < 0 || k >= n) {
            throw std::invalid_argument("Invalid input values. Ensure n > 0, goal > 0, and 0 <= k < n.");
        }

        const int MOD = 1e9 + 7;
        std::vector<std::vector<int>> dp(goal + 1, std::vector<int>(n + 1, 0));
        dp[0][0] = 1;

        for (int g = 1; g <= goal; ++g) {
            for (int j = 1; j <= std::min(g, n); ++j) {
                dp[g][j] = (1LL * dp[g - 1][j - 1] * (n - j + 1) % MOD + 
                            1LL * dp[g - 1][j] * std::max(j - k, 0) % MOD) % MOD;
            }
        }

        return dp[goal][n];
    }
};

