bool isSortable(const std::vector<int>& p, int X) {
    size_t n = p.size();
    for (size_t i = 0; i < n; ++i) {
        for (size_t j = i + 1; j < n; ++j) {
            if ((p[i] & p[j]) == X) {
                return true;
            }
        }
    }
    return false;
}

int maxX(const std::vector<int>& p) {
    size_t n = p.size();
    int max_X = 0;
    for (int X = 0; X < static_cast<int>(n); ++X) {
        if (isSortable(p, X)) {
            max_X = std::max(max_X, X);
        }
    }
    return max_X;
}

std::vector<int> parseInput(const std::string& input) {
    std::istringstream stream(input);
    int t, n;
    if (!(stream >> t)) {
        throw std::invalid_argument("Invalid number of test cases.");
    }

    std::vector<int> results;
    while (t-- > 0) {
        if (!(stream >> n)) {
            throw std::invalid_argument("Invalid array size.");
        }

        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            if (!(stream >> p[i])) {
                throw std::invalid_argument("Invalid input for array elements.");
            }
        }

        results.push_back(maxX(p));
    }
    return results;
}

