#include <vector>
#include <set>
#include <iostream>
#include <stdexcept>

class Solution {
public:
    std::vector<int> getSurvivorHealth(std::vector<int>& positions, std::vector<int>& healths, const std::string& directions) {
        if (positions.size() != healths.size() || positions.empty() || healths.empty()) {
            throw std::invalid_argument("Positions and healths must have the same non-zero size.");
        }

        int n = positions.size();
        std::vector<int> survivors(n, -1);
        std::set<std::pair<int, int>> robots;

        for (int i = 0; i < n; i++) {
            robots.emplace(positions[i], i);
        }

        while (!robots.empty()) {
            std::set<std::pair<int, int>> newRobots;
            std::vector<std::pair<std::pair<int, int>, std::pair<int, int>>> collisionPairs;

            for (const auto& robot : robots) {
                auto nextIt = std::next(robots.find(robot));
                auto prevIt = (robot == *robots.begin()) ? robots.end() : std::prev(robots.find(robot));

                if (directions[robot.second] == 'L' && nextIt == robots.end()) continue;
                if (directions[robot.second] == 'R' && nextIt == robots.begin()) continue;

                if (directions[robot.second] == 'L' && directions[nextIt->second] == 'R') {
                    collisionPairs.emplace_back(robot, *nextIt);
                    continue;
                }

                if (directions[robot.second] == 'L') {
                    if (prevIt != robots.end()) {
                        newRobots.emplace(prevIt->first - 1, prevIt->second);
                    }
                } else {
                    newRobots.emplace(nextIt->first + 1, nextIt->second);
                }
            }

            processCollisions(collisionPairs, newRobots, healths);
            robots = std::move(newRobots);
        }

        for (int i = 0; i < n; i++) {
            if (healths[i] > 0) survivors[i] = healths[i];
        }

        return filterSurvivors(survivors);
    }

private:
    void processCollisions(const std::vector<std::pair<std::pair<int, int>, std::pair<int, int>>>& collisionPairs,
                           std::set<std::pair<int, int>>& newRobots, std::vector<int>& healths) {
        for (const auto& pair : collisionPairs) {
            const auto& r1 = pair.first;
            const auto& r2 = pair.second;
            if (healths[r1.second] > healths[r2.second]) {
                newRobots.insert(r1);
                healths[r1.second]--;
            } else if (healths[r2.second] > healths[r1.second]) {
                newRobots.insert(r2);
                healths[r2.second]--;
            }
        }
    }

    std::vector<int> filterSurvivors(const std::vector<int>& survivors) {
        std::vector<int> result;
        for (const auto& health : survivors) {
            if (health != -1) {
                result.push_back(health);
            }
        }
        return result;
    }
};

