class ModCalculator {
public:
    ModCalculator(int n, int m) : n(n), M(m) {
        initialize_dp();
    }

    void calculate() {
        for (int i = 1; i <= n; ++i) {
            update_dp(i);
        }
        output_result();
    }

private:
    int n;
    int M;
    std::vector<int> dp;

    void initialize_dp() {
        dp.resize(n + 1, 0);
        dp[0] = 1;
    }

    void update_dp(int multiplier) {
        std::vector<int> ndp(n + 1, 0);
        for (int j = 0; j <= n; ++j) {
            ndp[j] = (ndp[j] + (1LL * dp[j] * multiplier) % M) % M;
            if (j > 0) {
                ndp[j] = (ndp[j] + (1LL * dp[j - 1] * multiplier) % M) % M;
            }
        }
        dp = std::move(ndp);
    }

    void output_result() const {
        int result = 0;
        for (int value : dp) {
            result = (result + value) % M;
        }
        std::cout << result << std::endl;
    }
};

int main() {
    int n, M;
    if (!(std::cin >> n >> M) || n < 0 || M <= 0) {
        std::cerr << "Error: Invalid input. Please enter non-negative n and positive M." << std::endl;
        return 1;
    }

    ModCalculator calculator(n, M);
    calculator.calculate();
    return 0;
}

