class FenwickTree {
private:
    vector<int> tree;
    int size;

    int lowbit(int x) const {
        return x & -x;
    }

public:
    explicit FenwickTree(int n) : size(n) {
        tree.assign(n + 1, 0);
    }

    void add(int x, int d) {
        while (x <= size) {
            tree[x] += d;
            x += lowbit(x);
        }
    }

    int sum(int x) const {
        int res = 0;
        while (x > 0) {
            res += tree[x];
            x -= lowbit(x);
        }
        return res;
    }

    void reset() {
        fill(tree.begin(), tree.end(), 0);
    }
};

void solveTestCase() {
    int n;
    if (!(cin >> n) || n < 0 || n > MAX_N - 1) {
        throw invalid_argument("Invalid input for n");
    }

    vector<int> a(n + 1);
    FenwickTree fenwick(n);
    vector<vector<int>> Q(n + 1);
    vector<vector<int>> ans(n + 1, vector<int>(1, 0));

    for (int i = 1; i <= n; ++i) {
        if (!(cin >> a[i])) {
            throw invalid_argument("Invalid input for array a");
        }
        Q[n - a[i] + 1].push_back(i);
    }

    fenwick.reset();
    for (int i = n; i > 0; --i) {
        fenwick.add(i, 1);
    }

    for (int i = n; i > 0; --i) {
        for (int idx : Q[i]) {
            ans[idx].back() += 2; // Count total points

            int avg = ceil(static_cast<double>(fenwick.sum(n)) / n);
            int jc = i - avg;
            if (i <= avg) {
                idx = n;
            } else {
                fenwick.add(i, -1);
                fenwick.add(idx, 1);
                idx = avg; // Can also be idx - 1
            }
            for (int j = 1; j <= jc; ++j) {
                ans[idx].back()++;
            }
        }
    }

    // Output results if needed
    for (const auto& result : ans) {
        cout << result.back() << endl;
    }
}

