        if (u < 1 || u > n || v < 1 || v > n) {
            throw out_of_range("Node index out of range");
        }
        adj[u].push_back(v);
        adj[v].push_back(u);
        deg[u]++;
        deg[v]++;
    }

    bool isEvenDegree() const {
        for (int i = 1; i <= n; i++) {
            if (deg[i] % 2 != 0) {
                return false;
            }
        }
        return true;
    }

    void printEdges() {
        for (int i = 1; i <= n; i++) {
            for (int j : adj[i]) {
                if (deg[j] % 2 == 0) {
                    deg[i]--;
                    deg[j]--;
                    cout << i << " " << j << '\n';
                    break;
                }
            }
        }
    }

private:
    vector<vector<int>> adj;
    vector<int> deg;
    int n;
};

