    char buffer[BUFFER_SIZE], *bufferStart = buffer, *bufferEnd = buffer;

    inline int fetchInput(std::istream &input)
    {
        if (bufferStart == bufferEnd)
        {
            input.read(buffer, BUFFER_SIZE);
            bufferStart = buffer;
            bufferEnd = buffer + input.gcount();
            if (bufferStart == bufferEnd)
                return EOF;
        }
        return *bufferStart++;
    }

    inline int readInt(std::istream &input)
    {
        int number = 0;
        bool negative = false;
        int character = fetchInput(input);

        while (!std::isdigit(character))
        {
            if (character == EOF)
                throw std::runtime_error("Unexpected EOF while reading integer.");
            negative ^= (character == '-');
            character = fetchInput(input);
        }

        while (std::isdigit(character))
        {
            number = number * 10 + (character - '0');
            character = fetchInput(input);
        }
        return negative ? -number : number;
    }
}

