        if (path.empty() || path[0] != '/') {
            logError("Invalid path: must start with '/'");
            return false;
        }

        size_t slashPos = path.find_last_of('/');
        std::string parentPath = (slashPos == 0) ? "/" : path.substr(0, slashPos);

        if (m.find(parentPath) == m.end()) {
            logError("Parent path does not exist: " + parentPath);
            return false;
        }

        if (m.find(path) != m.end()) {
            logError("Path already exists: " + path);
            return false;
        }

        m[path] = value;
        logInfo("Path created: " + path + " with value: " + std::to_string(value));
        return true;
    }

