        std::cerr << "[ERROR] " << message << std::endl;
    }
};

#include <iostream>
#include <vector>
#include <set>
#include <limits.h>
#include <stdexcept>

using namespace std;

class MatrixVisitor {
public:
    MatrixVisitor(vector<vector<int>>& matrix, set<int>& limits)
        : m(matrix), limitNum(limits) {}

    int visit(int startV, int startH, int num) {
        if (startH < 0 || startH >= m.size() || startV < 0 || startV >= m[0].size()) {
            throw invalid_argument("Start indices are out of matrix bounds.");
        }

        return explore(startH, startV, num);
    }

private:
    vector<vector<int>>& m;
    set<int>& limitNum;

    int explore(int h, int v, int num) {
        m[h][v] = num;

        // Validate boundaries and apply rules
        if (h == 0) m[2][v] = num;
        if (h == 1) m[0][v] = num;
        if (v == 0) m[h][2] = num;
        if (v == 1) m[h][0] = num;

        int index = h * 2 + v;
        if (limitNum.find(index) == limitNum.end()) return INT_MAX;

        if (h == 2 && v == 2 && num < m[1][1]) {
            return num + limitNum.size();
        }

        return evaluateAdjacentCells(h, v, num);
    }

    int evaluateAdjacentCells(int h, int v, int num) {
        int minResult = INT_MAX;

        if (v + 1 < 3) {
            minResult = min(minResult, exploreRight(h, v + 1, num));
        }
        if (v - 1 >= 0) {
            minResult = min(minResult, exploreLeft(h, v - 1, num));
        }
        if (h + 1 < 3) {
            minResult = min(minResult, exploreDown(h + 1, v, num));
        }
        if (h - 1 >= 0) {
            minResult = min(minResult, exploreUp(h - 1, v, num));
        }

        return minResult;
    }

    int exploreRight(int h, int v, int num) {
        return exploreCell(h, v, num, m[h][v]);
    }

    int exploreLeft(int h, int v, int num) {
        return exploreCell(h, v, num, m[h][v]);
    }

    int exploreDown(int h, int v, int num) {
        return exploreCell(h, v, num, m[h + 1][v]);
    }

    int exploreUp(int h, int v, int num) {
        return exploreCell(h, v, num, m[h - 1][v]);
    }

    int exploreCell(int h, int v, int num, int nextNum) {
        if (limitNum.find(h * 2 + v) == limitNum.end()) return INT_MAX;

        m[h][v] = num;
        if (num < nextNum) {
            int subResult = explore(h, v, nextNum);
            if (subResult < INT_MAX) {
                num += 1;
                return min(num + limitNum.size(), subResult);
            }
        }
        return INT_MAX;
    }
};

