void depthFirstSearch(vector<vector<int>>& val, int x, int y, int n, int m) {
    if (x == 1 || x == n || y == 1 || y == m) return;

    if (val[x][y] == val[x][y - 1]) --y;
    if (val[x][y] == val[x][y + 1]) --y;
    if (val[x][y] == val[x - 1][y]) --x;
    if (val[x][y] == val[x + 1][y + 1]) ++y;
    if (val[x][y] == val[x + 1][y]) ++x;

    depthFirstSearch(val, x, y, n, m);
}

