class Solution {
public:
    std::vector<std::string> generatePuzzles(const std::vector<std::string>& phrases) {
        if (phrases.empty()) {
            std::cerr << "Error: Input phrases vector is empty." << std::endl;
            return {};
        }

        std::set<std::string> puzzles;
        const size_t n = phrases.size();

        for (size_t i = 0; i < n; ++i) {
            for (size_t j = i + 1; j < n; ++j) {
                const std::string& phraseA = phrases[i];
                const std::string& phraseB = phrases[j];

                size_t spacePos = phraseB.find(" ");
                if (spacePos == std::string::npos) {
                    std::cerr << "Warning: Phrase '" << phraseB << "' does not contain a space." << std::endl;
                    continue;
                }

                std::string puzzle = phraseA + " " + phraseB.substr(spacePos + 1);
                puzzles.insert(puzzle);
            }
        }

        std::vector<std::string> result(puzzles.begin(), puzzles.end());
        std::sort(result.begin(), result.end());

        return result;
    }
};

