void preprocessFactors(vector<bool>& f, long long int limit) {
    f[0] = f[1] = true;
    for (long long int j = 2; j <= limit; ++j) {
        if (!f[j]) {
            for (int k = j; j * k <= limit; ++k)
                f[j * k] = true;
        }
    }
}

long long int countNonFactors(const vector<bool>& f, long long int start, long long int limit) {
    long long int count = 0;
    for (long long int i = start; i <= limit; ++i) {
        if (!f[i]) count++;
    }
    return count;
}

