    long long int integerTestcases, A, B, maxIndex;

    cout << "Enter number of test cases: ";
    if (!(cin >> integerTestcases) || integerTestcases <= 0) {
        cerr << "Invalid number of test cases." << endl;
        return 1;
    }

    const long long int MAX_LIMIT = 4000000;
    vector<bool> f(MAX_LIMIT + 1, false);
    preprocessFactors(f, 2000000);

    vector<long long int> sums(2000001, 0);
    for (long long int i = 2; i <= 2000000; ++i) {
        if (f[i]) {
            for (int j = 10; i * j <= 2000000; ++j)
                f[i * j] = true;
        }

        long long int counter = 1;
        for (int u = 2; u <= i; ++u) {
            if (f[u]) counter++;
        }

        if (!f[i]) {
            if (counter < sums.size()) {
