public:
    std::vector<std::string> findAndReplacePattern(const std::vector<std::string>& words, const std::string& pattern) {
        std::vector<std::string> result;
        for (const auto& word : words) {
            if (match(pattern, word)) {
                result.push_back(word);
            }
        }
        return result;
    }

private:
    bool match(const std::string& pattern, const std::string& word) {
        if (pattern.length() != word.length()) {
            logError("Pattern and word length mismatch");
            return false;
        }

        std::unordered_map<char, char> p2w, w2p;
        std::stack<char> patternStack, wordStack;

        for (size_t i = 0; i < pattern.length(); i++) {
            char pChar = pattern[i];
            char wChar = word[i];

            if (pChar != '(' && pChar == wChar) {
                p2w[pChar] = wChar;
                w2p[wChar] = pChar;
            } else if (pChar != '(') {
                if (pattern.substr(i).length() != word.substr(i).length()) {
                    logError("Substring length mismatch at position " + std::to_string(i));
                    return false;
                } else if (pChar != wChar) {
                    if (patternStack.empty()) {
                        logError("No matching parentheses found");
                        return false;
                    } else {
                        bool equivalent = areEquivalent(patternStack, w2p);
                        if (!equivalent) {
                            logError("Equivalence check failed");
                            return false;
                        }
                        w2p.clear();
                        patternStack.clear();
                    }
                }
            } else {
                patternStack.push(pChar);
            }
        }

        if (!patternStack.empty()) {
            logError("Unmatched parentheses remain");
            throw std::invalid_argument("Unmatched parentheses in pattern");
        }

        return true;
    }

    bool areEquivalent(const std::stack<char>& patternStack, const std::unordered_map<char, char>& w2p) {
        std::unordered_map<char, int> counts;
        for (const auto& ch : patternStack) {
            counts[ch]++;
        }
        for (const auto& pair : w2p) {
            if (counts[pair.first] != counts.size()) {
                return false;
            }
        }
        return true;
    }

    void logError(const std::string& message) const {
        std::cerr << "Error: " << message << std::endl;
    }
};

#include <string>
#include <unordered_set>
#include <iostream>
#include <stdexcept>

class UniqueSplitter {
public:
    static int maxUniqueSplit(const std::string& s) {
        if (s.empty()) {
            std::cerr << "Input string is empty." << std::endl;
            return 0;
        }

        std::unordered_set<std::string> seen;
        return maxUniqueSplitHelper(s, seen, 0);
    }

private:
    static int maxUniqueSplitHelper(const std::string& s, 
                                     std::unordered_set<std::string>& seen, 
                                     int start) {
        if (start == s.size()) return 0;

        int maxUnique = 0;
        for (int end = start + 1; end <= s.size(); ++end) {
            std::string sub = s.substr(start, end - start);
            if (isValidSubstring(sub, seen)) {
                seen.insert(sub);
                maxUnique = std::max(maxUnique, 1 + maxUniqueSplitHelper(s, seen, end));
                seen.erase(sub);
            }
        }
        return maxUnique;
    }

    static bool isValidSubstring(const std::string& sub, 
                                 const std::unordered_set<std::string>& seen) {
        if (seen.find(sub) != seen.end()) {
            std::cerr << "Substring already seen: " << sub << std::endl;
            return false;
        }
        return true;
    }
};

