using namespace std;

void readInput(int &n, int &m, int &k, vector<tuple<int, int, int>> &books) {
    cin >> n >> m >> k;
    if (n <= 0 || m <= 0 || k < 0) {
        throw invalid_argument("Invalid values for n, m, or k.");
    }
    books.resize(n);
    for (int i = 0; i < n; ++i) {
        int t, a, b;
        cin >> t >> a >> b;
        books[i] = {t, a, b};
    }
}

void initializeDP(vector<vector<int>> &dp, int m, int k) {
    dp.resize(m + 1, vector<int>(k + 1, numeric_limits<int>::max()));
    dp[0][0] = 0;
}

void updateDP(const vector<tuple<int, int, int>> &books, vector<vector<int>> &dp, 
              vector<vector<vector<pair<int, int>>>> &prev, int m, int k) {
    for (int i = 0; i < books.size(); ++i) {
        int t, a, b;
        tie(t, a, b) = books[i];
        for (int j = m - 1; j >= 0; --j) {
            for (int l = k - a; l >= 0; --l) {
                int new_val = dp[j][l] + t;
                if (new_val < dp[j + 1][l + a]) {
                    dp[j + 1][l + a] = new_val;
                    prev[j + 1][l + a] = prev[j][l];
                    prev[j + 1][l + a].emplace_back(i, a);
                }
            }
        }
    }
}

void findResult(const vector<vector<int>> &dp, 
                const vector<vector<vector<pair<int, int>>>> &prev, 
                int m, int k) {
    int res = numeric_limits<int>::max();
    vector<pair<int, int>> res_books;

    for (int l1 = k; l1 <= k; ++l1) {
        if (dp[m][l1] < res) {
            res = dp[m][l1];
            res_books = prev[m][l1];
        }
    }

    if (res >= numeric_limits<int>::max()) {
        cout << -1 << endl;
    } else {
        cout << res << "\n";
        for (size_t i = 0; i < res_books.size(); ++i) {
            cout << res_books[i].first + 1;
            if (i != res_books.size() - 1) cout << " ";
        }
        cout << endl;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m, k;
    vector<tuple<int, int, int>> books;

    try {
        readInput(n, m, k, books);
        vector<vector<int>> dp;
        initializeDP(dp, m, k);

        vector<vector<vector<pair<int, int>>>> prev(m + 1, 
            vector<vector<pair<int, int>>>(k + 1));

        updateDP(books, dp, prev, m, k);
        findResult(dp, prev, m, k);
    } catch (const exception &e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}

public:
    int bulbs(vector<int>& bulbs, int k) {
        if (bulbs.empty() || k <= 0) {
            cerr << "Error: Invalid input parameters." << endl;
            return -1; 
        }

        int n = bulbs.size();
        if (k > n) {
            cerr << "Error: k cannot be greater than the number of bulbs." << endl;
            return -1;
        }

        int left = 0, right = 0;

        while (right < n) {
            if (bulbs[right] == 0) {
                left = right + 1; 
            }
            right++;

            if (right - left == k) {
                return left + 1; 
            }
        }

        return -1; 
    }
};

