#include <numeric>
#include <stdexcept>

using namespace std;

class Solution
{
public:
    vector<vector<int>> threeEqualParts(vector<int> &nums, int k)
    {
        if (nums.size() < 3 || k < 1)
            throw invalid_argument("Input array must have at least 3 elements and k must be positive.");

        int totalSum = accumulate(nums.begin(), nums.end(), 0);
        if (totalSum % 3 != 0)
            throw logic_error("The sum of the elements must be divisible by 3.");

        int targetSum = totalSum / 3;
        vector<int> parts;
        int currentSum = 0;

        for (int i = 0; i < nums.size(); ++i)
        {
            currentSum += nums[i];
            if (currentSum == targetSum)
            {
                parts.push_back(i);
                currentSum = 0;
                if (parts.size() == 2) break; // We only need two indices to split into three parts
            }
        }

        if (parts.size() < 2)
            throw logic_error("Unable to find three equal parts.");

        // Ensure each part has the same number of elements
        int partOneEnd = parts[0];
        int partTwoStart = parts[0] + 1;
        int partTwoEnd = parts[1];
        int partThreeStart = parts[1] + 1;

        vector<int> part1(nums.begin(), nums.begin() + partOneEnd + 1);
        vector<int> part2(nums.begin() + partTwoStart, nums.begin() + partTwoEnd + 1);
        vector<int> part3(nums.begin() + partThreeStart, nums.end());

        return {part1, part2, part3};
    }
};

int main()
{
    try
    {
        int len, k;
        cin >> len >> k;

        if (len < 3 || k < 1)
            throw invalid_argument("Input length must be at least 3 and k must be positive.");

        vector<int> nums(len);
        for (int i = 0; i < len; ++i)
        {
            cin >> nums[i];
        }

        Solution solution;
        vector<vector<int>> result = solution.threeEqualParts(nums, k);
        for (const auto &part : result)
        {
            for (const auto &num : part)
            {
                cout << num << " ";
            }
            cout << endl;
        }
    }
    catch (const exception &e)
    {
        cerr << "Error: " << e.what() << endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

