class BitManipulator {
public:
    static uint32_t computeAndOperation(uint32_t n, uint32_t k) {
        if (k > n || n == 0) {
            throw std::invalid_argument("Invalid arguments: ensure k is less than or equal to n and n is non-zero.");
        }

        uint32_t result = n;
        for (uint32_t i = n - 1; i >= k; --i) {
            result &= i;
            if (result == 0) {
                break;
            }
        }
        return result;
    }

    static void logResult(uint32_t n, uint32_t k, uint32_t result) {
        std::cout << "Result of AND operation from " << n << " to " << k << " is: " << result << std::endl;
    }
};

