class MatrixCounter {
public:
    int countSubmatrices(const std::vector<std::vector<int>>& grid, int k) {
        if (grid.empty() || grid[0].empty()) {
            std::cerr << "Error: Input grid is empty." << std::endl;
            return 0;
        }

        int m = grid.size();
        int n = grid[0].size();
        std::vector<std::vector<int>> dp(m, std::vector<int>(n, 0));
        int ans = 0;

        // Populate the first cell
        dp[0][0] = grid[0][0];
        if (dp[0][0] <= k) {
            ans++;
        }

        // Fill the first row
        for (int i = 1; i < n; i++) {
            dp[0][i] = dp[0][i - 1] + grid[0][i];
            if (dp[0][i] <= k) {
                ans++;
            }
        }

        // Fill the first column
        for (int i = 1; i < m; i++) {
            dp[i][0] = dp[i - 1][0] + grid[i][0];
            if (dp[i][0] <= k) {
                ans++;
            }
        }

        // Fill the rest of the dp table
        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                dp[i][j] = dp[i - 1][j] + dp[i][j - 1] - dp[i - 1][j - 1] + grid[i][j];
                if (dp[i][j] <= k) {
                    ans++;
                }
            }
        }

        return ans;
    }
};

