class Solution {
public:
    int minimumPerimeter(int neededApples) {
        validateInput(neededApples);

        if (neededApples == 0) {
            return 0;
        }

        long long neededApplesSec2 = neededApples / 2;        
        long long days = 1;

        while (true) {
            long long currentApples = (days * 12LL - neededApplesSec2) * (days * 12LL + neededApplesSec2);

            if (currentApples <= 0) {
                return calculatePerimeter(days);
            }

            if (currentApples + 6 * neededApplesSec2 > 6 * (2 * days * 5)) {
                days++;
                continue;
            } else {
                return calculatePerimeter(days);
            }
        }
        return 0; // Should not reach here
    }

private:
    void validateInput(int neededApples) {
        if (neededApples < 0) {
            throw std::invalid_argument("Negative apple count is invalid.");
        }
    }

    int calculatePerimeter(long long days) const {
        return (days * 8) + 4;
    }
};

