#include <stdexcept>

using namespace std;

class SORTracker {
public:
    SORTracker(int maxSize) : n(maxSize), size(0) {
        if (n <= 0) {
            throw invalid_argument("Size must be a positive integer");
        }
        heap.reserve(n);
    }

    void add(const string& name, int score) {
        if (size >= n) {
            cerr << "Warning: Cannot add more locations, limit reached." << endl;
            return;
        }
        locations.emplace_back(name, score, size);
        heap.push_back(size++);
        siftUp(heap.size() - 1);
    }

    string get() {
        if (size == 0) {
            cerr << "Warning: No locations to retrieve." << endl;
            return "";
        }
        string result;
        for (int i = 0; i < 1; ++i) { // assuming we want only 1 top location
            int idx = heap.front();
            result += locations[idx].first + " ";
            popMin();
        }
        return result;
    }

private:
    vector<pair<string, int, int>> locations;
    vector<int> heap;
    int size;
    int n;

    void siftUp(int i) {
        while (i > 0 && heap[getParent(i)] > heap[i]) {
            swap(heap[getParent(i)], heap[i]);
            i = getParent(i);
        }
    }

    void popMin() {
        if (size == 0) {
            cerr << "Error: No items to pop from the heap." << endl;
            return;
        }
        swap(heap[0], heap[--size]);
        heap.pop_back();
        heapifyDown(0);
    }

    void heapifyDown(int i) {
        int smallest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;

        if (left < size && heap[left] < heap[smallest]) {
            smallest = left;
        }
        if (right < size && heap[right] < heap[smallest]) {
            smallest = right;
        }

        if (smallest != i) {
            swap(heap[i], heap[smallest]);
            heapifyDown(smallest);
        }

    }

    int getParent(int i) const {
        return (i - 1) / 2;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;

    cout << "Enter the maximum number of locations: ";
    cin >> n;

    int q;
    cout << "Enter the number of queries: ";
    cin >> q;

    char c;
    cout << "Enter command (a for add, g for get): ";
    cin >> c;

    SORTracker tracker(n);
    while (q--) {
        string name;
        int score;
        cin >> name >> score;

        if (c == 'a') {
            tracker.add(name, score);
        } else if (c == 'g') {
            string result = tracker.get();
            if (!result.empty()) {
                cout << result << endl;
            }
        } else {
            cerr << "Invalid command entered." << endl;
        }
    }

    return 0;
}

public:
int maxFrequency(vector<int>& nums, int k) {
    if (nums.empty()) {
        throw invalid_argument("Input vector is empty.");
    }

    int n = nums.size();
    sort(nums.begin(), nums.end());

    int ans = 0;
    long long sum = 0; // Use long long to prevent overflow
    int left = 0;

    for (int right = 0; right < n; ++right) {
        sum += nums[right];

        // Validate the current sum and check if we can continue
        while (sum < (static_cast<long long>(nums[right]) * (right - left + 1) - k)) {
            sum -= nums[left++];
        }
        ans = max(ans, right - left + 1);
    }

    return ans;
}

