#include <vector>
#include <string>
#include <iostream>
#include <stdexcept>

class Solution {
public:
    int deleteString(const std::string& s) {
        if (s.empty()) {
            throw std::invalid_argument("Input string cannot be empty.");
        }

        int n = s.size();
        std::vector<std::vector<int>> dp(n + 1, std::vector<int>(n + 1, 0));
        std::vector<std::string> strs(n + 1, "");

        // Fill the initial structures
        for (int i = 1; i <= n; ++i) {
            strs[i] = s.substr(i - 1, n - i + 1);
            dp[i][n] = 1; // Base case
        }

        // Dynamic programming to compute maximum deletions
        for (int len = 2; len <= n; ++len) {
            for (int i = n - len + 1; i >= 1; --i) {
                for (int j = i + len - 1; j <= n; ++j) {
                    if (s[i - 1] == s[j - 1] && strs[i].substr(1) == strs[j].substr(1, strs[j].size() - 1)) {
                        dp[i][j] = std::max(dp[i][j], dp[i + len][j] + 1);
                    }
                }
            }
        }
        return dp[1][n];
    }
};

int main() {
    try {
        Solution solution;
        std::string input;
        std::cout << "Enter a string to process: ";
        std::cin >> input;
        int result = solution.deleteString(input);
        std::cout << "Maximum deletions possible: " << result << std::endl;
    }
    catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}

