class Solution {
public:
    // Comparator to sort items based on price and beauty
    static bool comp(const std::vector<int>& a, const std::vector<int>& b) {
        return (a[0] == b[0]) ? (a[1] > b[1]) : (a[0] < b[0]);
    }

    std::vector<int> maximumBeauty(const std::vector<std::vector<int>>& items, const std::vector<int>& queries) {
        std::vector<int> res;
        std::vector<std::vector<int>> sortedItems = items;

        // Sorting items based on price and then beauty
        std::sort(sortedItems.begin(), sortedItems.end(), comp);

        // Pre-calculating the maximum beauty for sorted prices
        std::vector<int> maxBeauty;
        int currentMax = 0;
        for (const auto& item : sortedItems) {
            currentMax = std::max(currentMax, item[1]);
            maxBeauty.push_back(currentMax);
        }

        // For each query, find the maximum beauty corresponding to the price
        for (int query : queries) {
            // Using binary search to find the right position
            auto it = std::lower_bound(sortedItems.begin(), sortedItems.end(), std::vector<int>{query + 1, 0}, comp);
            if (it == sortedItems.begin()) {
                res.push_back(0); // No items are affordable
            } else {
                --it; // Move to the last affordable item
                int index = std::distance(sortedItems.begin(), it);
                res.push_back(maxBeauty[index]); // Add the max beauty for the affordable items
            }
        }

        return res;
    }
};

