double findMaxAverage(const std::vector<int>& nums, int k) {
    if (k <= 0) {
        throw std::invalid_argument("k must be a positive integer.");
    }
    if (nums.size() < static_cast<size_t>(k)) {
        throw std::invalid_argument("The size of nums must be at least k.");
    }

    double sum = 0.0;

    // Calculate the sum of the first 'k' elements
    for (int i = 0; i < k; ++i) {
        sum += nums[i];
    }

    double maxSum = sum;

    // Use a sliding window to find the maximum sum of any subarray of length 'k'
    for (size_t i = k; i < nums.size(); ++i) {
        sum += nums[i] - nums[i - k];
        if (sum > maxSum) {
            maxSum = sum;
        }
    }

    // Calculate and return the maximum average
    return maxSum / k;
}

