class ResidenceStreet {
public:
    std::vector<int> kResidenceStreet(int n, int x, int y) {
        if (n <= 0 || x <= 0 || y <= 0 || x > n || y > n) {
            throw std::invalid_argument("Invalid input parameters.");
        }

        std::vector<int> res(n, 0);
        std::vector<std::vector<int>> path(n + 1, std::vector<int>(n + 1, 0));
        path[x][0]++;
        path[y][0]++;

        for (int i = 2; i <= n; ++i) {
            for (int j = 1; j <= n - (i - 2); ++j) {
                if (path[j][i - 2] > 0) {
                    int pathsToUpdate = path[j][i - 2];
                    path[j + 1][i - 2] += pathsToUpdate;
                    path[j][i - 2] = 0;

                    path[j + 1][i - 1] += pathsToUpdate;
                }
            }
            for (int j = 1; j <= n; ++j) {
                if (path[j][i - 1] > 0) {
                    res[j - 1] += path[j][i - 1];  // Update result based on paths
                }
            }
        }
        return res;
    }
};

