const int MAX_N = 2e5 + 10;
const int MOD = 1e9 + 7;

int modPow(int base, int exp) {
    if (exp < 0) throw std::invalid_argument("Exponent must be non-negative");
    int result = 1;
    while(exp > 0) {
        if (exp % 2 == 1) result = (result * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return result;
}

int modInv(int a) {
    if (a == 0) throw std::invalid_argument("Inverse of zero is undefined");
    return modPow(a, MOD - 2);
}

int nCk(int n, int k) {
    static int fact[MAX_N], ifact[MAX_N];
    if (fact[0] == 0) {
        fact[0] = 1;
        FOR(i, 1, MAX_N) fact[i] = (fact[i - 1] * i) % MOD;
        ifact[MAX_N - 1] = modInv(fact[MAX_N - 1]);
        for (int i = MAX_N - 2; i >= 0; --i)
            ifact[i] = (ifact[i + 1] * (i + 1)) % MOD;
    }
    if (k < 0 || k > n) return 0;
    return (fact[n] * ifact[k] % MOD * ifact[n - k] % MOD);
}

