const int DIRECTIONS[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};

bool canReach(const vector<vector<char>>& grid, Position start, int jumpSize, int targetX, int targetY) {
    queue<Position> q;
    vector<vector<bool>> visited(grid.size(), vector<bool>(grid[0].size(), false));
    q.push(start);
    visited[start.x][start.y] = true;

    while (!q.empty()) {
        Position current = q.front();
        q.pop();

        if (current.x == targetX && current.y == targetY) 
            return true;

        for (const auto& dir : DIRECTIONS) {
            for (int j = 1; j <= jumpSize; ++j) {
                int nx = current.x + dir[0] * j;
                int ny = current.y + dir[1] * j;

                if (nx < 0 || nx >= grid.size() || ny < 0 || ny >= grid[0].size() || grid[nx][ny] == '#') 
                    break;

                if (!visited[nx][ny]) {
                    visited[nx][ny] = true;
                    q.push(Position(nx, ny));
                }
            }
        }
    }
    return false;
}

