class LandSolver {
public:
    static std::vector<std::vector<int>> solve(const std::vector<std::vector<int>>& land) {
        validateInput(land);

        int numRows = land.size();
        int numCols = land[0].size();
        std::vector<std::vector<int>> result;

        for (int j = 0; j < numRows; ++j) {
            int columnValue = land[j][0];
            int startRow = j;
            int endRow = j;

            while (startRow < numRows) {
                // Check for bounds
                if (land[startRow][0] != columnValue) {
                    break;
                }
                endRow = startRow;

                // Move down until the value changes or out of bounds
                while (endRow < numRows && land[endRow][0] == columnValue) {
                    ++endRow;
                }

                // Store results
                result.push_back({startRow, endRow - 1, columnValue});
                startRow = endRow;
            }
        }

        return result;
    }

private:
    static void validateInput(const std::vector<std::vector<int>>& land) {
        if (land.empty() || land[0].empty()) {
            throw std::invalid_argument("Input land matrix cannot be empty.");
        }

        size_t expectedCols = land[0].size();
        for (const auto& row : land) {
            if (row.size() != expectedCols) {
                throw std::invalid_argument("All rows in land matrix must have the same number of columns.");
            }
        }
    }
};

