std::vector<int> newNumbers(std::vector<int>& nums, const std::vector<std::vector<int>>& operations) {
    if (nums.empty()) {
        throw std::invalid_argument("Input vector 'nums' must not be empty.");
    }

    std::vector<int> newVector(nums.size(), 0);

    try {
        std::for_each(nums.begin(), nums.end(), [&newVector, maxVal = 1](int num) mutable {
            if (num < 1 || num > newVector.size()) {
                throw std::out_of_range("Number is out of valid range.");
            }
            newVector[num - 1] = maxVal++;
        });

        for (const auto& op : operations) {
            if (op.size() != 2 || op[0] < 1 || op[0] > newVector.size()) {
                throw std::invalid_argument("Invalid operation format or index out of range.");
            }
            newVector[op[0] - 1] = op[1];
