using namespace std;

const int MAX_SIZE = 100050;
const int MAX_DEPTH = 31;
int tree[MAX_SIZE][MAX_DEPTH];
int N = 8;
int K = 6;

int getMax(int i, int min, int max) {
    int cur = 0;
    int res = 0;
    int a = max + 1;

    while (max != -1) {
        res = cur + max - (a << 1) + 1;
        if (res >= min) break;
        min = a;
        max--;
        a >>= 1;
    }
    return res;
}

int getMin(int i, int min, int max) {
    int cur = 0;
    int res = 0;
    int a = min;

    while (min != -1) {
        if (min != 0) {
            res = min + min - (a << 1) + 1;
        }
        a >>= 1;
        min >>= 1;
    }
    return res;
}

void update(int i, int start, int end, int li, int ri, int idx) {
    if (start > i || i > end) return;
    if (start == end) {
        if (li == -1 && ri == -1) return;
        tree[i][idx] = (li == -1) ? 0 : 1;
        return;
    }
    int left = (start + end) >> 1;
    int mid = getMax(left, li, ri) + getMax(left + 1, end - ri, ri) + 1;
    int min = getMin(left, li, ri) + getMin(left + 1, end - ri, ri) + 1;
    update(i << 1, start, start + left, li, ri, idx + 1);
    update(i << 1 | 1, start + left + 1, end, li, ri, idx + 1);
    tree[i][idx] = min + mid;
}

int query(int i, int start, int end, int li, int ri, int idx) {
    if (start > i || i > end) return 1;
    if (start == end) {
        if (li != -1 && ri != -1) {
            return min(tree[i][idx - 1], tree[i][idx - 1]);
        }
        return (li == -1) ? tree[i][idx - 1] : 0;
    }
    int left = (start + end) >> 1;
    int mid = getMax(left, li, ri) + getMax(left + 1, end - ri, ri) + 1;
    int min = getMin(left, li, ri) + getMin(left + 1, end - ri, ri) + 1;
    int L = query(i << 1, start, start + left, li, ri, idx + 1);
    int R = query(i << 1 | 1, start + left + 1, end, li, ri, idx + 1);
    return L + R;
}

