using namespace std;

const int N = 19;

struct Node {
    long long sum, maxVal, maxLeft, maxRight, maxSumLeft, maxSumRight;

    Node() : sum(0), maxVal(0), maxLeft(0), maxRight(0), maxSumLeft(0), maxSumRight(0) {}
};

void merge(const Node &a, const Node &b, Node &c) {
    c.sum = a.sum + b.sum;
    c.maxVal = max({a.maxVal, b.maxVal, a.maxRight + b.maxLeft});
    c.maxLeft = max(a.maxLeft, a.sum + b.maxLeft);
    c.maxRight = max(b.maxRight, b.sum + a.maxRight);
    c.maxSumLeft = max(a.maxSumLeft, a.sum + b.maxSumLeft);
    c.maxSumRight = max(b.maxSumRight, b.sum + a.maxSumRight);
}

void build(vector<Node> &tree, const vector<int> &data, int v, int tl, int tr) {
    if (tl == tr) {
        tree[v].sum = data[tl];
        tree[v].maxVal = tree[v].maxLeft = tree[v].maxRight = tree[v].maxSumLeft = tree[v].maxSumRight = data[tl];
    } else {
        int mid = (tl + tr) / 2;
        build(tree, data, v * 2, tl, mid);
        build(tree, data, v * 2 + 1, mid + 1, tr);
        merge(tree[v * 2], tree[v * 2 + 1], tree[v]);
    }
}

void update(vector<Node> &tree, int v, int tl, int tr, int pos, int addValue) {
    if (tl == tr) {
        tree[v].sum += addValue;
        tree[v].maxVal = tree[v].maxLeft = tree[v].maxRight = tree[v].maxSumLeft = tree[v].maxSumRight = tree[v].sum;
    } else {
        int mid = (tl + tr) / 2;
        if (pos <= mid) {
            update(tree, v * 2, tl, mid, pos, addValue);
        } else {
            update(tree, v * 2 + 1, mid + 1, tr, pos, addValue);
        }
        merge(tree[v * 2], tree[v * 2 + 1], tree[v]);
    }
}

