class ExtraCharsCalculator {
public:
    ExtraCharsCalculator(const std::unordered_set<std::string>& dict) : dictionary(dict) {}

    size_t minExtraChars(const std::string& s) {
        if (s.empty()) {
            return 0;
        }

        std::vector<size_t> dp(s.size() + 1, std::numeric_limits<size_t>::max());
        dp[0] = 0;

        for (size_t i = 1; i <= s.size(); ++i) {
            for (size_t j = 0; j < i; ++j) {
                if (dictionary.find(s.substr(j, i - j)) != dictionary.end()) {
                    dp[i] = std::min(dp[i], dp[j] + (i - j));
                }
            }
            if (dp[i] == std::numeric_limits<size_t>::max()) {
                logError("Calculation error at index " + std::to_string(i));
            }
        }
        return s.size() - dp.back();
    }

private:
    std::unordered_set<std::string> dictionary;

    void logError(const std::string& msg) {
        std::cerr << "Error: " << msg << std::endl;
    }
};

int main() {
    std::unordered_set<std::string> dictionary = {"apple", "pen", "applepen", "pine", "pineapple"};
    ExtraCharsCalculator calculator(dictionary);

    std::string input = "pineapplepenapple";
    size_t result = calculator.minExtraChars(input);

    std::cout << "Minimum extra characters: " << result << std::endl;
    return 0;
}

