using namespace std;

class Solution {
public:
    string maskPII(const string& input) {
        if (input.empty()) {
            cerr << "Error: Input string is empty." << endl;
            return "";
        }

        string s = input;
        string masked;
        bool isEmail = false;

        // Determine if the input is an email
        if (s.find('@') != string::npos) {
            isEmail = true;
            transform(s.begin(), s.end(), s.begin(), ::tolower);
            size_t atPos = s.find('@');
            string name = s.substr(0, atPos);
            string domain = s.substr(atPos);
            masked = string(1, name[0]) + "*****" + domain;
        } else { // Phone number processing
            s.erase(remove_if(s.begin(), s.end(), [](char c) { return !isdigit(c); }), s.end());
            if (s.length() == 10) {
                masked = "***-***-" + s.substr(6);
            } else if (s.length() > 10) {
                masked = "+" + string(s.length() - 10, '*') + "-***-***-" + s.substr(6);
            }
        }

        return masked;
    }
};

