#include <vector>
#include <stdexcept>
#include <iostream>

class Allocator {
public:
    Allocator(int n) 
        : freeUnits(n, 0), unitIdx(n + 1, -1), unitSize(n + 1, -1), mId2UnitId(n + 1, -1) {
        if (n <= 0) throw std::invalid_argument("Size must be greater than zero.");
        unitIdx[n] = 0;
    }

    int allocate(int size, int mID) {
        if (size <= 0) throw std::invalid_argument("Allocation size must be positive.");

        size += 1;
        int idx = mId2UnitId[mID];

        if (idx != -1) {
            return handleReallocation(size, idx);
        } else {
            return handleAllocation(size, mID);
        }
    }

private:
    std::vector<int> freeUnits;
    std::vector<int> unitIdx;
    std::vector<int> unitSize;
    std::vector<int> mId2UnitId;

    int n = unitIdx.size() - 1;

    int handleReallocation(int size, int idx) {
        int prevIdx = unitIdx[idx];

        if (unitSize[idx] + size <= unitSize[prevIdx]) {
            unitIdx[idx] = prevIdx;
        } else if (unitSize[idx] + size == unitSize[prevIdx] + 1) {
            unitIdx[prevIdx] = unitIdx[idx];
        } else {
            unitIdx[idx] = idx + 1;
        }
        unitSize[idx] += size;
        updateFreeUnits(idx, unitSize[idx]);
        unitIdx[idx + 1] = idx;
        unitSize[idx + 1] = unitSize[prevIdx] - size;

        if (unitSize[idx + 1] == 0) {
            unitIdx[prevIdx] = -1;
        }
        return prevIdx;
    }

    int handleAllocation(int size, int mID) {
        if (unitIdx[0] == n) {
            logError("Memory allocation failed: No available units.");
            return -1;
        }
        int idx = unitIdx[0];
        updateFreeUnits(idx, size);

        if (idx == 0 || size + unitSize[idx - 1] == unitSize[idx]) {
            unitSize[idx + 1] = unitSize[idx] - size;
            updateFreeUnits(idx + 1, unitSize[idx + 1]);
            mId2UnitId[mID] = idx;
            return idx;
        } else {
            int prevIdx = idx - 1;
            mId2UnitId[mID] = idx;
            unitIdx[idx + 1] = idx;
            unitSize[idx + 1] = unitSize[idx] - size;
            updateFreeUnits(idx + 1, unitSize[idx + 1]);
            unitIdx[idx] = prevIdx;
            unitSize[idx] = size;
            return prevIdx;
        }
    }

    void updateFreeUnits(int idx, int size) {
        if (size < 0) throw std::invalid_argument("Size cannot be negative.");
        freeUnits[idx] = size;
        // Log the update for tracking
        logInfo("Updated free units: Index = " + std::to_string(idx) + ", Size = " + std::to_string(size));
    }

    void logInfo(const std::string& message) {
        // Simple logging mechanism
        std::cout << "[INFO] " << message << std::endl;
    }

    void logError(const std::string& message) {
        // Error logging
        std::cerr << "[ERROR] " << message << std::endl;
    }
};

class Solution {
public:
    int closestCost(vector<int>& baseCosts, vector<int>& toppingCosts, int target) {
        int closest = INT_MAX;
        int minDiff = INT_MAX;

        try {
            for (const int& base : baseCosts) {
                int currentCost = base;
                vector<int> toppingsUsed;

                findClosest(currentCost, toppingsUsed, toppingCosts, target, closest, minDiff);
            }
        } catch (const std::exception& e) {
            std::cerr << "Error encountered: " << e.what() << std::endl;
        }

        return closest;
    }

private:
    void findClosest(int currentCost, vector<int>& toppingsUsed, const vector<int>& toppingCosts, int target, int& closest, int& minDiff, int index = 0) {
        if (index == toppingCosts.size()) {
            updateClosest(currentCost, target, closest, minDiff);
            return;
        }

        findClosest(currentCost, toppingsUsed, toppingCosts, target, closest, minDiff, index + 1); // Skip topping
        if (currentCost + toppingCosts[index] <= target + minDiff) {
            toppingsUsed.push_back(toppingCosts[index]);
            findClosest(currentCost + toppingCosts[index], toppingsUsed, toppingCosts, target, closest, minDiff, index + 1); // Add one topping
            toppingsUsed.pop_back();
        }
        if (currentCost + 2 * toppingCosts[index] <= target + minDiff) {
            toppingsUsed.push_back(toppingCosts[index]);
            toppingsUsed.push_back(toppingCosts[index]);
            findClosest(currentCost + 2 * toppingCosts[index], toppingsUsed, toppingCosts, target, closest, minDiff, index + 1); // Add two toppings
            toppingsUsed.pop_back();
            toppingsUsed.pop_back();
        }
    }

    void updateClosest(int currentCost, int target, int& closest, int& minDiff) {
        int diff = abs(currentCost - target);
        if (diff < minDiff || (diff == minDiff && currentCost < closest)) {
            closest = currentCost;
            minDiff = diff;
        }
    }
};

int calculateMaxSum(TreeNode* root, int& maxSum) {
    if (!root) {
        return 0;
    }

    int rootVal = root->val;

    if (isBstAvailable(root->left) && isBstAvailable(root->right) &&
        rootVal > (root->left ? root->left->val : INT_MIN) &&
        rootVal < (root->right ? root->right->val : INT_MAX)) {

        int leftValue = root->left ? root->left->val : 0;
        int rightValue = root->right ? root->right->val : 0;

        int currSum = leftValue + rightValue + rootVal;

        if (currSum > maxSum) {
            maxSum = currSum; 
        }

        return max(rootVal, rootVal + max(leftValue, 0) + max(rightValue, 0));
    }

    // Log error message
    std::cerr << "Invalid BST structure at node with value: " << rootVal << std::endl;

    return INT_MIN;
}

