class OwnedIvector {
protected:
    T* ptr;
    int len;
    int base;

public:
    OwnedIvector() : ptr(nullptr), len(0), base(0) {}

    OwnedIvector(const T elem[], int _len = -1, int _base = 0) : base(_base), len(_len) {
        if (_len < 0) {
