        fillUnique(elem);
    }

    ~OwnedIvector() {
        clear();
    }

    void clear() {
        delete[] ptr;
        ptr = nullptr;
    }

    void fillUnique(const T elem[]) {
        if (ptr && len > 0) {
            copy(elem, elem + len, ptr);
        }
    }

    void get(const T& pattern, int offset, T& pos, int& idx) const {
        idx = posem(pattern, ptr, len, offset, pos);
    }

    void get(const T& pattern, int offset, vector<T>& pos) const {
        int idx = -1;
        bool first = true;
        iterDefaultFill(back_inserter(pos), ptr, len, offset, pattern, first);
    }

    LL slowDistance(int x1, int y1, int x2, int y2) const {
        LL d = abs(x1 - x2) + abs(y1 - y2);
        LL a = abs(x2 - x1) + abs(y2 - y1);
        return a * a + d * d;
    }

    LL distance(int x1, int y1, int x2, int y2) const {
        return max(abs(x1 - x2), abs(y1 - y2));
    }
};

/******************************************************************************** */
// Ownership of Ivector is managed smartly between two classes for safe deletion.
class Point {
public:
    LL x, y;

    Point(LL xCoord, LL yCoord) : x(xCoord), y(yCoord) {}

    LL distance(const Point& t) const {
        return Point::distance(x, y, t.x, t.y);
    }

    static LL distance(int x1, int y1, int x2, int y2) {
        return abs(x1 - x2) + abs(y1 - y2);
    }
};

template <typename T>
LL posem(const T& pattern, const T* seq, int len, int offset, T& pos) {
    int idx = seq.roff(offset / pattern.offs);
    if (idx == len) {
        return 0;
    }
    LL totalDist = 0;
    long long off = offset;
    ++idx;

    while (idx < len) {
        int d = Point::distance(pattern, seq[idx + off], pattern, seq[idx]);
        if (d > 0) {
            totalDist += d;
        }
        ++idx;
    }

    return totalDist + posem(pattern, seq, len, off + pattern.offs, pos);
}

