    }

    std::unordered_map<int, int> frequencyMap;
    for (const int& num : q) {
        frequencyMap[num]++;
    }

    std::vector<int> differenceArray = computeDifferenceArray(q);
    std::unordered_map<int, int> differenceFrequencyMap;

    for (const int& diff : differenceArray) {
        differenceFrequencyMap[diff]++;
    }

    std::vector<int> permutation;
    for (const auto& entry : frequencyMap) {
        int value = entry.first;
        if (differenceFrequencyMap.find(value) != differenceFrequencyMap.end()) {
            permutation.push_back(value);
            differenceFrequencyMap[value]--;
            if (differenceFrequencyMap[value] == 0) {
                differenceFrequencyMap.erase(value);
            }
        }
    }

    if (!permutation.empty() && permutation.size() == frequencyMap.size()) {
        return permutation;
    } else {
        throw std::runtime_error("No valid permutation found.");
    }
}

