        if (strs.empty()) {
            throw std::invalid_argument("Input vector cannot be empty.");
        }

        size_t firstLength = strs[0].length();
        for (const auto& str : strs) {
            if (str.length() != firstLength) {
                throw std::invalid_argument("All strings must have the same length.");
            }
        }
    }
};

int minDeletionSize(const std::vector<std::string>& strs) {
    StringValidator::validateInput(strs);

    int deletionCount = 0;
    size_t stringCount = strs.size();
    size_t strLength = strs[0].length();

    for (size_t col = 0; col < strLength; ++col) {
        for (size_t row = 1; row < stringCount; ++row) {
            if (strs[row][col] < strs[row - 1][col]) {
                deletionCount++;
                break;
            }
        }
    }

    return deletionCount;
}

