class Fenwick {
public:
    explicit Fenwick(const std::vector<int>& arr) {
        if (arr.empty()) {
            throw std::invalid_argument("Input array must not be empty.");
        }
        size = arr.size();
        fn.resize(size, 0);
        build(arr);
    }

    int sum(int u) const {
        if (u < 0 || u >= size) {
            throw std::out_of_range("Index out of range.");
        }
        int ans = 0;
        int f = size - 1;

        for (int cur = size - 1; cur > u; ) {
            ans += fn[f];
            f -= fn[f];

            if (f >= 0) {
                cur += fn[f];
            } else {
                break; 
            }
        }
        return ans;
    }

private:
    int size;
    std::vector<int> fn;

    void build(const std::vector<int>& arr) {
        for (size_t i = 0; i < size; ++i) {
            fn[i] = i; // Initialize BINARY HEIGHT at each position
            int cur = i;
            while (cur > 0 && arr[cur] > 0) {
                int a = arr[cur];
                cur += a;

                if (posA(cur) < fn.size()) {
                    fn[posA(cur)] += a; // Update tree representation
                } else {
                    std::cerr << "Warning: Index out of range during build at position " << cur << std::endl;
                }
            }
        }
    }

    int posA(int i) const {
        i += size;
        while (i != 1) {
            i = 2 * posA(i >> 1);
        }
        return i;
    }
};

