class DisjointSet {
public:
    DisjointSet(int size) : parent(size), rank(size, 1) {
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (x < 0 || x >= parent.size()) {
            throw std::out_of_range("Index out of bounds in find operation.");
        }
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int px = find(x), py = find(y);
        if (px != py) {
            if (rank[px] < rank[py]) {
                parent[px] = py;
            } else if (rank[px] > rank[py]) {
                parent[py] = px;
            } else {
                parent[px] = py;
                rank[py]++;
            }
        }
    }

private:
    std::vector<int> parent;
    std::vector<int> rank;
};

int main() {
    int n = 0, q = 0;
    std::cin >> n >> q;

    if (n <= 0 || q < 0) {
        std::cerr << "Error: Invalid number of elements or queries." << std::endl;
        return EXIT_FAILURE;
    }

    std::vector<int> p(n);
    DisjointSet ds(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        if (p[i] <= 0 || p[i] > n) {
            std::cerr << "Error: Element out of bounds." << std::endl;
            return EXIT_FAILURE;
        }
    }

    for (int i = 0; i < q; ++i) {
        int t = 0;
        std::cin >> t;

        if (t == 1) {
            int x = 0, y = 0;
            std::cin >> x >> y;
            --x; --y;

            if (x < 0 || x >= n || y < 0 || y >= n) {
                std::cerr << "Error: Indices out of bounds for swap operation." << std::endl;
                continue;
            }

            std::swap(p[x], p[y]);
            if (x != y) {
                ds.unite(x, y);
            }
        } else if (t == 2) {
            int i = 0, k = 0;
            std::cin >> i >> k;
            --i;

            if (i < 0 || i >= n) {
                std::cerr << "Error: Index out of bounds for query operation." << std::endl;
                continue;
            }

            int current = i;
            for (int j = 0; j < k; ++j) {
                current = p[current] - 1;
                if (current == i) break;
            }
            std::cout << current + 1 << '\n';
        } else {
            std::cerr << "Error: Invalid query type." << std::endl;
        }
    }

    return EXIT_SUCCESS;
}

