class CircleValidator {
public:
    static bool is_within_circle(const std::vector<int>& center, int x, int y, int r) {
        if (center.size() != 2) {
            throw std::invalid_argument("Center must be a vector of size 2.");
        }
        int dx = x - center[0];
        int dy = y - center[1];
        return std::sqrt(dx * dx + dy * dy) <= r;
    }
};

class DartCircleAnalyzer {
public:
    DartCircleAnalyzer(const std::vector<std::vector<int>>& darts, int radius)
        : darts_(darts), radius_(radius) {
        if (radius < 0) {
            throw std::invalid_argument("Radius must be non-negative.");
        }
        if (darts.empty()) {
            throw std::invalid_argument("Darts cannot be empty.");
        }
    }

    int max_point_in_circle() const {
        int max_points = 0;

        for (size_t i = 0; i < darts_.size(); ++i) {
            int points_inside = 0;
            for (size_t j = 0; j < darts_.size(); ++j) {
                if (i == j) continue;

                if (CircleValidator::is_within_circle(darts_[i], darts_[j][0], darts_[j][1], radius_)) {
                    ++points_inside;
                }
            }
            max_points = std::max(max_points, points_inside);
        }

        return max_points;
    }

private:
    const std::vector<std::vector<int>>& darts_;
    int radius_;
};

