class Solution {
public:
    std::vector<int> numOfPotions(const std::vector<int>& spells, const std::vector<int>& potions, int success) {
        if (spells.empty() || potions.empty()) {
            throw std::invalid_argument("Spells and potions cannot be empty");
        }
        if (success <= 0) {
            throw std::invalid_argument("Success threshold must be a positive integer");
        }

        std::vector<int> result(spells.size(), 0);
        std::vector<int> sortedPotions = potions;
        std::sort(sortedPotions.begin(), sortedPotions.end());

        for (size_t i = 0; i < spells.size(); ++i) {
            int spellStrength = spells[i];
            if (spellStrength < 0) {
                throw std::invalid_argument("Spell strength cannot be negative");
            }

            for (size_t j = 0; j < sortedPotions.size(); ++j) {
                int potionStrength = sortedPotions[j];
                if (spellStrength * potionStrength >= success) {
                    result[i]++;
                }
                if (spellStrength * potionStrength > potionStrength) {
                    break; // Exit early since potions are sorted
                }
            }
        }

        return result;
    }
};

