class TicTacToe {
public:
    TicTacToe(const std::vector<std::vector<int>>& moves) 
        : board(3, std::vector<char>(3, 'x')), 
          playerA(0), 
          playerB(0), 
          remainingMoves(9) 
    {
        if (moves.size() != 9) {
            throw std::invalid_argument("Moves should contain exactly 9 entries.");
        }
        playGame(moves);
    }

    char getWinner() const {
        if (playerA > playerB) return 'A';
        if (playerB > playerA) return 'B';
        return 'D'; // Draw
    }

private:
    std::vector<std::vector<char>> board;
    int playerA;
    int playerB;
    int remainingMoves;

    void playGame(const std::vector<std::vector<int>>& moves) {
        for (int i = 0; i < moves.size() && remainingMoves > 0; ++i) {
            int row = moves[i][0];
            int col = moves[i][1];
            if (row < 0 || row >= 3 || col < 0 || col >= 3) {
                std::cerr << "Invalid move: (" << row << ", " << col << "). Skipping.\n";
                continue;
            }
            if (board[row][col] == 'x') {
                board[row][col] = (i % 2 == 0) ? 'A' : 'B';
                (i % 2 == 0) ? playerA++ : playerB++;
                if (checkWinner(row, col)) {
                    displayBoard();
                    return;
                }
                remainingMoves--;
            } else {
                std::cerr << "Cell already taken! Skipping move for: (" << row << ", " << col << ").\n";
            }
        }
        displayBoard();
    }

    bool checkWinner(int row, int col) {
        if (checkRow(row) || checkColumn(col) || checkDiagonals()) {
            std::cout << "Winner: " << (board[row][col] == 'A' ? "A" : "B") << "\n";
            return true;
        }
        return false;
    }

    bool checkRow(int row) {
        return (board[row][0] == board[row][1] && board[row][1] == board[row][2]);
    }

    bool checkColumn(int col) {
        return (board[0][col] == board[1][col] && board[1][col] == board[2][col]);
    }

    bool checkDiagonals() {
        return ((board[0][0] == board[1][1] && board[1][1] == board[2][2]) ||
                (board[0][2] == board[1][1] && board[1][1] == board[2][0]));
    }

    void displayBoard() const {
        for (const auto& row : board) {
            for (char cell : row) {
                std::cout << cell << " ";
            }
            std::cout << "\n";
        }
    }
};

bool isPossible(vector<int>& target) {
    if (target.empty()) {
        throw invalid_argument("Target vector cannot be empty.");
    }

    priority_queue<int> maxHeap(target.begin(), target.end());
    long total = accumulate(target.begin(), target.end(), 0L);

    while (maxHeap.top() > 1) {
        int largest = maxHeap.top();
        maxHeap.pop();
        total -= largest;

        if (total <= 0 || largest <= total || largest > 2 * total) {
            cerr << "Validation failed: largest = " << largest << ", total = " << total << endl;
            return false;
        }

        largest %= total;

        total += (largest ? largest : total);
        maxHeap.push(largest ? largest : total);
    }

    return true;
}

