class WordPuzzleSolver {
public:
    static std::vector<int> findWords(const std::vector<std::string>& words, const std::vector<std::string>& puzzles) {
        std::vector<int> result;
        std::unordered_set<std::string> wordSet(words.begin(), words.end());

        for (const auto& puzzle : puzzles) {
            if (puzzle.empty()) {
                std::cerr << "Warning: Empty puzzle encountered." << std::endl;
                result.push_back(0);
                continue;
            }

            int count = 0;
            for (const auto& word : wordSet) {
                if (isValidWord(word, puzzle)) {
                    count++;
                }
            }
            result.push_back(count);
        }

        return result;
    }

private:
    static bool isValidWord(const std::string& word, const std::string& puzzle) {
        if (word.empty() || puzzle.empty() || word[0] != puzzle[0]) {
            return false;
        }

        std::unordered_set<char> puzzleChars(puzzle.begin(), puzzle.end());
        for (char ch : puzzle) {
            if (puzzleChars.find(ch) == puzzleChars.end() || word.find(ch) == std::string::npos) {
                return false;
            }
        }
        return true;
    }
};

class Solution {
public:
    int minCost(vector<int>& startPos, vector<int>& homePos, vector<int>& rowCosts, vector<int>& colCosts) {
        if (startPos.size() != 2 || homePos.size() != 2 || rowCosts.size() <= max(startPos[0], homePos[0]) || colCosts.size() <= max(startPos[1], homePos[1])) {
            throw invalid_argument("Invalid input dimensions.");
        }

        int rowDistance = abs(startPos[0] - homePos[0]);
        int colDistance = abs(startPos[1] - homePos[1]);

        if (rowDistance > 0) {
            if (rowCosts[startPos[0]] < 0) {
                throw out_of_range("Invalid row cost at starting position.");
            }
        }

        if (colDistance > 0) {
            if (colCosts[startPos[1]] < 0) {
                throw out_of_range("Invalid column cost at starting position.");
            }
        }

        int totalCost = (rowDistance * rowCosts[startPos[0]]) + (colDistance * colCosts[startPos[1]]);
        return totalCost;
    }
};

#include <stack>
