class StockSpanner {
public:
    StockSpanner() = default;

    int next(int price) {
        validateInput(price);
        int span = 1;

        while (!priceStack.empty() && priceStack.top().first <= price) {
            span += priceStack.top().second;
            priceStack.pop();
        }

        priceStack.push(std::make_pair(price, span));
        logPrice(price, span);
        return span;
    }

private:
    std::stack<std::pair<int, int>> priceStack;

    void validateInput(int price) const {
        if (price < 0) {
            throw std::invalid_argument("Price must be non-negative.");
        }
    }

    void logPrice(int price, int span) const {
        std::cout << "Price: " << price << ", Span: " << span << std::endl;
    }
};

