// Comparator function for sorting pairs
bool comparePairs(const pair<int, int>& a, const pair<int, int>& b) {
    if (a.second == b.second) {
        return a.first > b.first;
    }
    return a.second < b.second;
}

// Function to update vector of pairs based on conditions
int update(vector<pair<int, int>>& v, int k, int y) {
    if (k <= 0 || v.empty()) {
        cerr << "Invalid arguments: k must be positive and vector must not be empty." << endl;
        return -1;
    }

    vector<vector<pair<int, int>>> aggr(k);
    int j = 0;

    // Aggregate pairs into groups
    for (size_t i = 0; i < v.size(); ++i) {
        aggr[j].push_back(v[i]);
        if (i == v.size() - 1 || (v[i].first - v[i - 1].first == k - 1)) {
            ++j;
        }
    }

    vector<int> w(k + 1, numeric_limits<int>::min());
    for (int i = 0; i < k; ++i) {
        sort(aggr[i].begin(), aggr[i].end(), comparePairs);
        if (!aggr[i].empty()) {
            w[i] = aggr[i].front().first;
        }
    }

    vector<int> ans(k, 0);
    sort(w.begin(), w.end());

    for (int i = 0; i < k; ++i) {
        for (size_t j = 0; j < aggr[i].size(); ++j) {
            bool flag = false;

            for (int m = 0; m < k; ++m) {
                if (aggr[i][j].first + y - (aggr[i][j].second - 1) == k) {
                    ans[i] += max(0, w[i] - aggr[i][j].first + aggr[i][j].second + (k - max(w[i], aggr[i][j].first)) + aggr[i][j].second - w[i - 1]);
                    flag = true;
                    break;
                }
            }
            if (!flag) {
                ans[i] += max(0, w[i] - aggr[i][j].first + aggr[i][j].second + (k - w[i - 1]) + aggr[i][j].second - w[i - 1]);
            }
        }
    }

    return 0; // Successfully updated
}

