class TestProcessor {
public:
    void processTests(const std::string& inputFilename, const std::string& outputFilename) {
        try {
            std::ifstream inputFile(inputFilename);
            std::ofstream outputFile(outputFilename);

            if (!inputFile.is_open() || !outputFile.is_open()) {
                throw std::runtime_error("Could not open input or output file.");
            }

            int numTests;
            inputFile >> numTests;

            for (int t = 0; t < numTests; ++t) {
                int n1, n2, n3;
                inputFile >> n1 >> n2 >> n3;

                std::vector<int> num1 = readNumbers(inputFile, n1);
                std::vector<int> num2 = readNumbers(inputFile, n2);

                validateInputSizes(num1.size(), num2.size(), n1, n2);

                std::deque<int> sortedNum2(num2.begin(), num2.end());
                std::sort(sortedNum2.rbegin(), sortedNum2.rend());

                std::vector<int> results = calculateResults(num1, sortedNum2, n3);

                outputFile << *std::max_element(results.begin(), results.end()) << std::endl;
            }

            inputFile.close();
            outputFile.close();
        } catch (const std::exception& e) {
            std::cerr << "Error: " << e.what() << std::endl;
        }
    }

private:
    std::vector<int> readNumbers(std::ifstream& inputFile, int count) {
        std::vector<int> numbers;
        for (int i = 0; i < count; ++i) {
            int value;
            if (inputFile >> value) {
                numbers.push_back(value);
            } else {
                throw std::runtime_error("Input file format error.");
            }
        }
        return numbers;
    }

    void validateInputSizes(size_t size1, size_t size2, int expectedSize1, int expectedSize2) {
        if (size1 != expectedSize1 || size2 != expectedSize2) {
            throw std::runtime_error("Input sizes do not match expected sizes.");
        }
    }

    std::vector<int> calculateResults(std::vector<int>& num1, std::deque<int>& num2, int& n3) {
        std::vector<int> res(2, 0);

        while (!num2.empty() && n3 > 0) {
            int num = num1.back();
            num1.pop_back();
            res[0]++;
            num++;

            while (!num2.empty() && (num + num2.front() > num2.back())) {
                res[1] += num + num2.front();
                num2.pop_front();
                num++;
                --n3;
            }
            --n3;
        }

        while (n3 > 0 && !num2.empty()) {
            res[1] += num2.front();
            num++;
            num2.pop_front();
            --n3;
        }

        res[1] += std::max(num, 0);
        return res;
    }
};

int main(int argc, char* argv[]) {
    if (argc < 3) {
        std::cerr << "Usage: " << argv[0] << " <input_file> <output_file>" << std::endl;
        return 1;
    }

    TestProcessor processor;
    processor.processTests(argv[1], argv[2]);

    return 0;
}

