class Solution {
public:
    int numRollsToTarget(int n, int k, int target) {
        const int MOD = 1e9 + 7;

        if (n <= 0 || k <= 0 || target <= 0) {
            throw std::invalid_argument("n, k, and target must be positive integers.");
        }

        std::vector<std::vector<int>> dp(n + 1, std::vector<int>(target + 1, 0));

        for (int i = 1; i <= std::min(k, target); i++) {
            dp[1][i] = 1;
        }

        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= target; j++) {
                for (int l = 1; l <= std::min(k, target - j); l++) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j + l]) % MOD;
                }
            }
        }
        return dp[n][target];
    }
};

