                throw std::invalid_argument("Input string must contain only digits");
            }

            if (c < '7') {
                res.append(1, '0'); 
            }
            res.append(1, '1');
            res.append(1, '0'); 
        }

        try {
            return std::stoi(res);
        } catch (const std::out_of_range&) {
            throw std::overflow_error("Mirror number exceeds integer limits");
        }
    }

    static int sum_k_mirror_numbers(int k, int n) {
        if (k <= 0 || n <= 0) {
            throw std::invalid_argument("k and n must be positive integers");
        }

        int sum = 0;
        std::string res = std::to_string(k);

        for (int i = 1; i <= n; ++i) {
            try {
                sum += mirror_number(res);
            } catch (const std::exception& e) {
                std::cerr << "Error processing number " << res << ": " << e.what() << std::endl;
                continue;  // Log error and continue with the next iteration
            }
            ++res; 
        }

        return sum;
    }
};

