#include <queue>
#include <limits>
#include <cmath>

using namespace std;

const int MOD = 998244353;

struct State {
    int node;
    int transpositions;
    int time;

    State(int n, int t, int c) : node(n), transpositions(t), time(c) {}

    bool operator<(const State& other) const {
        return time > other.time;
    }
};

void readInput(int& n, int& m, vector<vector<int>>& adj, vector<vector<int>>& adjT) {
    if (!(cin >> n >> m) || n <= 0 || m < 0) {
        cerr << "Invalid input for number of nodes or edges." << endl;
        exit(EXIT_FAILURE);
    }
    adj.resize(n + 1);
    adjT.resize(n + 1);

    for (int i = 0; i < m; ++i) {
        int u, v;
        if (!(cin >> u >> v) || u <= 0 || u > n || v <= 0 || v > n) {
            cerr << "Invalid edge input." << endl;
            exit(EXIT_FAILURE);
        }
        adj[u].push_back(v);
        adjT[v].push_back(u);
    }
}

void findShortestPath(int n, const vector<vector<int>>& adj, const vector<vector<int>>& adjT) {
    vector<vector<int>> dp(n + 1, vector<int>(20, numeric_limits<int>::max()));
    dp[1][0] = 0;

    priority_queue<State> pq;
    pq.push(State(1, 0, 0));

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        int node = current.node;
        int transpositions = current.transpositions;
        int time = current.time;

        if (node == n) continue;

        if (dp[node][transpositions] < time) continue;

        const vector<vector<int>>& currentAdj = (transpositions % 2 == 0) ? adj : adjT;

        for (int next : currentAdj[node]) {
            if (dp[next][transpositions] > time + 1) {
                dp[next][transpositions] = time + 1;
                pq.push(State(next, transpositions, time + 1));
            }
        }

        if (transpositions < 19) {
            int newTranspositions = transpositions + 1;
            int newTime = (time + (1 << transpositions)) % MOD;

            if (dp[node][newTranspositions] > newTime) {
                dp[node][newTranspositions] = newTime;
                pq.push(State(node, newTranspositions, newTime));
            }
        }
    }

    int result = numeric_limits<int>::max();
    for (int transpositions = 0; transpositions < 20; ++transpositions) {
        result = min(result, dp[n][transpositions]);
    }

    if (result == numeric_limits<int>::max()) {
        cout << "Unreachable node." << endl;
    } else {
        cout << result << endl;
    }
}

int main() {
    int n, m;
    vector<vector<int>> adj, adjT;

    readInput(n, m, adj, adjT);
    findShortestPath(n, adj, adjT);

    return 0;
}

