                mismatches.push_back(i);
            }
        }

        if (mismatches.empty()) {
            return 0;
        }

        std::unordered_map<int, std::vector<int>> graph;
        buildGraph(mismatches, nums1, nums2, graph);

        int total_cost = 0;
        int visited[n] = {0};

        for (int i : mismatches) {
            if (visited[i]) continue;
            total_cost += resolveComponent(i, graph, visited);
            if (total_cost == -1) return -1;  // Conflict that can't be resolved
        }

        return total_cost;
    }

private:
    void buildGraph(const std::vector<int>& mismatches, std::vector<int>& nums1, std::vector<int>& nums2, std::unordered_map<int, std::vector<int>>& graph) {
        int size = mismatches.size();
        for (int i = 0; i < size; ++i) {
            for (int j = i + 1; j < size; ++j) {
                int idx1 = mismatches[i];
                int idx2 = mismatches[j];
                if (nums1[idx1] != nums2[idx2] && nums1[idx2] != nums2[idx1]) {
                    graph[idx1].emplace_back(idx2);
                    graph[idx2].emplace_back(idx1);
                }
            }
        }
    }

    int resolveComponent(int start, const std::unordered_map<int, std::vector<int>>& graph, int visited[]) {
        int total_cost = 0;
        std::vector<int> stack = {start};
        std::vector<int> component;
        visited[start] = true;

        while (!stack.empty()) {
            int curr = stack.back();
            stack.pop_back();
            component.push_back(curr);

            for (int neighbor : graph.at(curr)) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    stack.push_back(neighbor);
                }
            }
        }

        if (component.size() == 1) {
            return -1;  // Unresolvable single node conflict
        }

        int min_cost = std::numeric_limits<int>::max();
        for (size_t i = 0; i < component.size(); ++i) {
            for (size_t j = i + 1; j < component.size(); ++j) {
                int cost = component[i] + component[j];
                min_cost = std::min(min_cost, cost);
            }
        }
        return min_cost;
    }
};

