    std::vector<int> nums1 = {1, 2, 3, 4};
    std::vector<int> nums2 = {1, 3, 2, 4};

    SwapResolver resolver;
    int result = resolver.minSwapCost(nums1, nums2);

    if (result != -1) {
        std::cout << "Minimum Swap Cost: " << result << std::endl;
    } else {
        std::cout << "Unresolvable conflict." << std::endl;
    }

    return 0;
}

#include <iostream>
