using namespace std;

const int kMaxN = 400005;
const int kMaxSwapCount = 10;

class MatrixValidator {
public:
    MatrixValidator(int rows, int cols) : n(rows), m(cols) {
        if (n <= 0 || m <= 0) {
            throw invalid_argument("Matrix dimensions must be positive.");
        }
        a.resize(n * m);
    }

    void setValue(int index, int value) {
        if (index < 0 || index >= n * m) {
            throw out_of_range("Index out of bounds.");
        }
        a[index] = value;
    }

    bool Check() {
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                set<int> neighbors;
                if (i > 0) neighbors.insert(a[(i - 1) * m + j]);
                if (i < n - 1) neighbors.insert(a[(i + 1) * m + j]);
                if (j > 0) neighbors.insert(a[i * m + j - 1]);
                if (j < m - 1) neighbors.insert(a[i * m + j + 1]);

                int current = a[i * m + j];
                if (!neighbors.empty() && neighbors.lower_bound(current) != neighbors.begin()) {
                    return false;
                }
            }
        }
        return true;
    }

    int CountSwaps() {
        if (Check()) {
            return 0;
        }

        set<pair<int, int>> swaps;
        for (int x1 = 0; x1 < n * m; ++x1) {
            for (int x2 = x1 + 1; x2 < n * m; ++x2) {
                swap(a[x1], a[x2]);
                if (Check()) {
                    swaps.emplace(min(x1, x2), max(x1, x2));
                }
                swap(a[x1], a[x2]);
            }
        }

        if (swaps.size() > kMaxSwapCount) {
            return 2;
        }
        return swaps.empty() ? 2 : 1 + swaps.size();
    }

    void ReadMatrix() {
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int value;
                cin >> value;
                setValue(i * m + j, value - 1);
            }
        }
    }

private:
    int n, m;
    vector<int> a;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    try {
        int n, m;
        cin >> n >> m;

        MatrixValidator matrixValidator(n, m);
        matrixValidator.ReadMatrix();

        int result = matrixValidator.CountSwaps();
        cout << result << '\n';
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << '\n';
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

