class SubstringCalculator {
public:
    static int uniqueSubstrings(const std::string& text) {
        if (text.length() <= 2) {
            return 2 - static_cast<int>(text.length());
        }

        std::vector<int> charCount(26, 0);
        int j = 0;
        int ans = 0;

        for (size_t i = 0; i < text.length(); ++i) {
            charCount[text[i] - 'a'] += static_cast<int>(i - j);
            if (j != static_cast<int>(i) && charCount[text[i] - 'a'] > 0) {
                ans += combination(2 * static_cast<int>(i) - j, 2);
                j = static_cast<int>(i);
            }
            charCount[text[i] - 'a'] -= 1;
        }

        return 2 * ans - calculateValue(text.substr(j));
    }

private:
    static int combination(int n, int k) {
        if (k > n || k < 0) {
            return 0;
        }
        int x = 1;
        int y = 1;
        for (int i = 0; i < std::min(k, n - k); ++i) {
            x *= n - i;
            y *= k - i;
        }
        return x / y;
    }

    static int calculateValue(const std::string& s) {
        return (static_cast<int>(s.length()) - 1) * static_cast<int>(s.length()) / 2 
               - combination(static_cast<int>(s.length()), 2);
    }
};

int main() {
    std::string input;

    std::cout << "Enter the text: ";
    std::getline(std::cin, input);

    try {
        int result = SubstringCalculator::uniqueSubstrings(input);
        std::cout << "Unique substrings count: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

