long long maximumImportance(int n, const std::vector<std::vector<int>>& roads) {
    if (n <= 0) {
        throw std::invalid_argument("The number of nodes must be positive.");
    }

    std::vector<int> degree(n, 0);

    // Calculate the degree of each node
    for (const auto& road : roads) {
        if (road.size() != 2 || road[0] < 0 || road[0] >= n || road[1] < 0 || road[1] >= n) {
            throw std::invalid_argument("Invalid road data provided.");
        }
        degree[road[0]]++;
        degree[road[1]]++;
    }

    // Using a max-heap to store degrees
    std::priority_queue<int> pq(degree.begin(), degree.end());
    long long totalImportance = 0;

    try {
        for (int i = n; i > 0; --i) {
            if (pq.empty()) {
                std::cerr << "Warning: Priority queue is empty before completion." << std::endl;
                break;
            }
            totalImportance += static_cast<long long>(pq.top()) * i;
            pq.pop();
        }
    } catch (const std::exception& e) {
        std::cerr << "Error occurred during computation: " << e.what() << std::endl;
    }

    return totalImportance;
}

