class Solution {
public:
    int singleNonDuplicate(const std::vector<int>& nums) {
        if (nums.empty()) {
            throw std::invalid_argument("Input array cannot be empty");
        }

        int left = 0;
        int right = nums.size() - 1;

        while (left < right) {
            int mid = left + (right - left) / 2;

            // Ensure mid is even for proper pairing
            if (mid % 2 == 1) {
                mid--; 
            }

            // Validating the current mid and its pair
            if (nums[mid] == nums[mid + 1]) {
                left = mid + 2; // Move to the right half
            } else {
                right = mid; // Move to the left half
            }
        }

        // At the end of the while loop, left == right is the unique element
        return nums[left];
    }

    void runTest() {
        std::vector<int> testInput = {1, 1, 2, 2, 3, 3, 4, 5, 5};
        try {
            int unique = singleNonDuplicate(testInput);
            std::cout << "Unique element found: " << unique << std::endl;
        } catch (const std::exception& e) {
            std::cerr << "Error: " << e.what() << std::endl;
        } 
    }
};

int main() {
    Solution solution;
    solution.runTest();
    return 0;
}

