struct Node {
    std::string name;
    int cnt;
};

class Solution {
public:
    std::string largestWordCount(const std::vector<std::string>& messages, const std::vector<std::string>& senders) {
        if (messages.size() != senders.size()) {
            throw std::invalid_argument("Messages and senders vectors must have the same size.");
        }

        std::map<std::string, int> senderWordCount;
        Node maxSender = {"", 0};

        for (size_t i = 0; i < messages.size(); i++) {
            int wordCount = countWords(messages[i]);
            senderWordCount[senders[i]] += wordCount;

            if (senderWordCount[senders[i]] > maxSender.cnt || 
               (senderWordCount[senders[i]] == maxSender.cnt && senders[i] > maxSender.name)) {
                maxSender.cnt = senderWordCount[senders[i]];
                maxSender.name = senders[i];
            }
        }

        return maxSender.name;
    }

private:
    int countWords(const std::string& message) const {
        int count = 0;
        bool inWord = false;

        for (char ch : message) {
            if (std::isspace(ch)) {
                if (inWord) {
                    count++;
                    inWord = false;
                }
            } else {
                inWord = true;
            }
        }

        if (inWord) {
            count++; // Count the last word if it exists
        }

        return count;
    }
};

