class Solution {
public:
    std::vector<int> sortArrayByParityV2(std::vector<int>& A) {
        if (A.empty()) {
            std::cerr << "Input array is empty." << std::endl;
            return {};
        }

        std::vector<int> evens, odds;
        for (int x : A) {
            if (x % 2 == 0) {
                evens.push_back(x);
            } else {
                odds.push_back(x);
            }
        }

        size_t evenCount = evens.size();
        size_t totalCount = A.size();
        A.clear();
        A.reserve(totalCount);

        A.insert(A.end(), evens.begin(), evens.end());
        A.insert(A.end(), odds.begin(), odds.end());

        return A;
    }

    std::vector<int> sortedSquares(std::vector<int>& A) {
