#include <iostream>
#include <vector>
#include <complex>
#include <cmath>
#include <stdexcept>
#include <algorithm>

using namespace std;

const double PI = 3.14159265358979323846;

void fft(vector<complex<double>>& x, bool invert) {
    int n = x.size();
    for (int i = 1, j = 0; i < n; ++i) {
        for (int bit = n >> 1; (j ^= bit) < bit; bit >>= 1);
        if (i < j) swap(x[i], x[j]);
    }
    for (int len = 2; len <= n; len <<= 1) {
        double angle = 2 * PI / len * (invert ? -1 : 1);
        complex<double> wlen(cos(angle), sin(angle));
        for (int i = 0; i < n; i += len) {
            complex<double> w(1);
            for (int j = 0; j < len / 2; ++j) {
                complex<double> u = x[i + j], v = x[i + j + len / 2] * w;
                x[i + j] = u + v;
                x[i + j + len / 2] = u - v;
                w *= wlen;
            }
        }
    }
    if (invert) {
        for (auto& c : x) c /= n;
    }
}

vector<double> fft_convolution(const vector<double>& a, const vector<double>& b) {
    int n = 1;
    while (n < a.size() + b.size()) n <<= 1;
    vector<complex<double>> fa(n), fb(n);
    for (size_t i = 0; i < a.size(); i++) fa[i] = complex<double>(a[i], 0);
    for (size_t i = 0; i < b.size(); i++) fb[i] = complex<double>(b[i], 0);

    fft(fa, false);
    fft(fb, false);
    for (size_t i = 0; i < n; i++) fa[i] *= fb[i];
    fft(fa, true);

    vector<double> result(a.size() + b.size() - 1);
    for (size_t i = 0; i < result.size(); i++) {
        result[i] = round(fa[i].real());
    }
    return result;
}

vector<vector<int>> process_grid(int n, int m, const vector<int>& a, const vector<int>& b) {
    vector<vector<int>> grid(n, vector<int>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            grid[i][j] = a[i] + b[j];
        }
    }
    return grid;
}

pair<int, int> classify_components(const vector<vector<int>>& grid, int x) {
    int good = 0, bad = 0;
    vector<vector<bool>> visited(grid.size(), vector<bool>(grid[0].size(), false));

    auto dfs = [&](int i, int j, bool& border) {
        if (i < 0 || i >= grid.size() || j < 0 || j >= grid[0].size() || visited[i][j])
            return;
        visited[i][j] = true;
        border |= (i == 0 || i == grid.size() - 1 || j == 0 || j == grid[0].size() - 1);
        if (grid[i][j] >= x) {
            dfs(i + 1, j, border);
            dfs(i - 1, j, border);
            dfs(i, j + 1, border);
            dfs(i, j - 1, border);
        }
    };

    for (int i = 0; i < grid.size(); ++i) {
        for (int j = 0; j < grid[0].size(); ++j) {
            if (!visited[i][j]) {
                bool border_cell = false;
                dfs(i, j, border_cell);
                if (border_cell) {
                    good++;
                } else {
                    bad++;
                }
            }
        }
    }
    return {good, bad};
}

int main() {
    int n, m, q;
    cin >> n >> m >> q;
    vector<int> a(n), b(m);

    for (int i = 0; i < n; ++i) cin >> a[i];
    for (int j = 0; j < m; ++j) cin >> b[j];

    vector<vector<int>> grid = process_grid(n, m, a, b);

    while (q--) {
        int x;
        cin >> x;
        auto [good, bad] = classify_components(grid, x);
        cout << good - bad << endl;
    }

    return 0;
}

int coverFloor(const std::string& floor, int numCarpets, int carpetLen) {
    if (carpetLen <= 0 || numCarpets < 0) {
        throw std::invalid_argument("carpetLen must be positive and numCarpets must be non-negative.");
    }

    const int N = floor.length();
    if (N == 0) {
        return 0;
    }

    int minWhiteTiles = N / 2;  
    std::vector<std::string> carpets(numCarpets);

    while (true) {
        std::fill(carpets.begin(), carpets.end(), std::string(carpetLen, ' ')); 
        int carpetCount = 0;

        for (int i = 0; i < N; ++i) {
            if (floor[i] == '0') {
                for (; i <= N - carpetLen && carpetCount < numCarpets; i += carpetLen) {
                    carpets[carpetCount] = floor.substr(i - carpetLen, carpetLen);
                    carpetCount++;
                }
            } else {
                carpets[0] = floor[i];
            }
        }

        int dust = 0;
        for (int i = 0; i < carpetCount; ++i) {
            dust += std::count(carpets[i].begin(), carpets[i].end(), '0');
        }

        if (dust < minWhiteTiles) {
            return dust;
        } else {
            minWhiteTiles = dust;
        }
    }
    return 0; 
}

