class Solution {
public:
    int minSwaps(std::vector<int>& nums) {
        if (nums.empty()) {
            throw std::invalid_argument("Input vector is empty.");
        }

        int n = nums.size();
        int numOnes = std::count(nums.begin(), nums.end(), 1);
        if (numOnes == 0) return 0;

        int currentSum = 0;
        for (int i = 0; i < numOnes; ++i) {
            currentSum += nums[i];
        }

        int maxOnes = currentSum;
        for (int i = 0; i < n; ++i) {
            currentSum += nums[(i + numOnes) % n] - nums[i];
            maxOnes = std::max(maxOnes, currentSum);
        }

        return numOnes - maxOnes;
    }
};

