class PalindromeSolver {
public:
    PalindromeSolver(int size) : size(size) {
        if (size <= 0) {
            throw std::invalid_argument("Size must be a positive integer.");
        }
        matrix.resize(size, std::vector<int>(size, 0));
    }

    void fillMatrix(const std::vector<std::vector<int>>& input) {
        if (input.size() != size || input[0].size() != size) {
            throw std::invalid_argument("Input matrix size does not match initialized size.");
        }
        matrix = input;
    }

    int findMaxSumPalindrome() {
        if (matrix.empty()) {
            throw std::runtime_error("Matrix is empty. Fill the matrix before computation.");
        }
        return recursiveMaxPalindrome(0, size - 1);
    }

private:
    int recursiveMaxPalindrome(int left, int right) {
        if (left > right) {
            return 0;
        }
        if (left == right) {
            return matrix[left][left];
        }

        if (matrix[left][right] != 0) {
            return matrix[left][right];
        }

        int maxPalindromeValue = std::max(
            matrix[left][right] + recursiveMaxPalindrome(left + 1, right - 1),
            std::max(recursiveMaxPalindrome(left + 1, right), recursiveMaxPalindrome(left, right - 1))
        );

        matrix[left][right] = maxPalindromeValue;

        return maxPalindromeValue;
    }

    int size;
    std::vector<std::vector<int>> matrix;
};

int main() {
    try {
        int size;
        std::cout << "Enter the size of the matrix: ";
        std::cin >> size;

        PalindromeSolver solver(size);

        std::vector<std::vector<int>> inputMatrix(size, std::vector<int>(size, 0));
        std::cout << "Enter the matrix values:\n";
        for (int i = 0; i < size; ++i) {
            for (int j = 0; j < size; ++j) {
                std::cin >> inputMatrix[i][j];
            }
        }

        solver.fillMatrix(inputMatrix);
        int maxPalindromeSum = solver.findMaxSumPalindrome();
        std::cout << "Maximum sum of palindrome is: " << maxPalindromeSum << std::endl;
    } catch (const std::exception& ex) {
        std::cerr << "Error: " << ex.what() << std::endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

