class Solution {
public:
    int countTriangles(const std::vector<int>& arr) {
        if (arr.size() < 3) {
            std::cerr << "Insufficient sides to form a triangle." << std::endl;
            return 0;
        }

        std::vector<int> sides = arr;
        std::sort(sides.begin(), sides.end());

        int triangleCount = 0;
        int n = sides.size();

        for (int i = 0; i < n - 2; ++i) {
            int pointer1 = i + 1, pointer2 = i + 2;

            while (pointer1 < n - 1) {
                while (pointer2 < n && sides[i] + sides[pointer1] > sides[pointer2]) {
                    pointer2++;
                }
                triangleCount += pointer2 - pointer1 - 1;
                pointer1++;
            }
        }

        return triangleCount;
    }
};

int main() {
    Solution solution;
    std::vector<int> arr = {4, 6, 3, 7};
    int result = solution.countTriangles(arr);
    std::cout << "Number of triangles: " << result << std::endl;

    return 0;
}

