#include <iostream>
#include <vector>
#include <algorithm>
#include <stdexcept>

using namespace std;

using ll = long long;
using vll = vector<ll>;
using pll = pair<ll, ll>;
using vvvll = vector<vector<vector<ll>>>;

const ll INF = 1e9;

class Solution {
public:
    string kthLargestPath(int row, int col, int k) {
        validateInput(row, col, k);

        vvvll paths(row + col);
        initializeRootPaths(paths, k);

        for (int id = k; id < row + col; ++id) {
            processPaths(paths, id, row, col);
        }

        sort(paths.begin(), paths.end(), [](const auto &l, const auto &r) {
            return l[1] < r[1];
        });

        return constructResult(paths);
    }

private:
    void validateInput(int row, int col, int k) {
        if (row <= 0 || col <= 0 || k < 0) {
            throw invalid_argument("Invalid input for row, col, or k.");
        }
    }

    void initializeRootPaths(vvvll &paths, int k) {
        for (int id = 0; id <= k; ++id) {
            paths[id] = {{0}, 0, {}, {id, {0, 0}}};
        }
    }

    void processPaths(vvvll &paths, int id, int row, int col) {
        pll p = paths[id - 1][3];
        const int dirs[2][2] = {{0, 1}, {1, 0}};

        for (const auto &dir : dirs) {
            int r = p.first + dir[0];
            int c = p.second + dir[1];

            if (r >= row || c >= col) {
                continue;
            }

            ll distance = computeDistance(p.first, p.second, r, c);
            paths[id].emplace_back(distance);
            paths[id].push_back({distance, r, c}); // maintain the structure
        }
        if (!paths[id].empty()) {
            sort(paths[id].begin(), paths[id].end());
        }
    }

    ll computeDistance(ll x1, ll y1, ll x2, ll y2) {
        return (x2 - x1) + (y2 - y1);
    }

    string constructResult(const vvvll &paths) {
        vector<ll> result;
        for (const auto &path : paths) {
            for (const auto &dist : path[0]) {
                result.push_back(dist);
            }
        }
        stringstream ss;
        for (const auto &val : result) {
            ss << val << ",";
        }
        return ss.str();
    }
};

