        for (int i = 0; i < n; ++i) {
            if (!(cin >> a[i])) {
                cerr << "Error reading input values." << endl;
                return EXIT_FAILURE;
            }
        }

        sort(a.begin(), a.end());
        int lo = 0, hi = 1000000, res = hi;

        while (lo <= hi) {
            int mid = (hi - lo) / 2 + lo;
            if (mid >= a[0] && is_perfect_square(check(a, mid))) {
                res = min(res, mid);
                hi = mid - 1;  // Corrected upper bound
            } else {
                lo = mid + 1;
            }
        }

        if (res == 1000000) {
            res = -1;
        }

        cout << res << endl;

    } catch (const exception &e) {
        cerr << "Error: " << e.what() << endl;
        return EXIT_FAILURE;
    }

    return EXIT_SUCCESS;
}

int check(const vector<int> &arr, int val) {
    int res = 1;
    int sum = 0;

    for (const int &val_elem : arr) {
        if (val == 0) throw runtime_error("Division by zero in check function.");
        sum += val_elem / val;
        res *= val_elem / val;
    }

    for (int &val_elem : arr) {
        val_elem /= sum;  // Update arr directly, might want to avoid mutation.
    }

    return res;
}

bool is_perfect_square(int n) {
    if (n < 0) return false; // Not a perfect square.
    int x = static_cast<int>(sqrt(n));
    long long y = static_cast<long long>(n);
    return (x * x == y);
}

