class Solution {
public:
    std::string longestPrefix(const std::string& s) {
        if (s.empty()) {
            logError("Input string is empty.");
            return "";
        }

        if (s.length() == 1) {
            return s;
        }

        std::string output;
        size_t height = 0;
        size_t len = s.length();

        for (size_t i = 0; i < len; ++i) {
            if (s[i] == s[len - 1 - i]) {
                height++;
                output = s.substr(0, len - 1 - i);
            } else {
                break;
            }
        }

        logMessage("Longest prefix found: " + output);
        return output;
    }

private:
    void logError(const std::string& message) const {
        std::cerr << "Error: " << message << std::endl;
    }

    void logMessage(const std::string& message) const {
        std::cout << message << std::endl;
    }
};

class MatrixSearch {
public:
    int getRow(int target, const std::vector<std::vector<int>>& matrix) {
        if (matrix.empty() || matrix[0].empty()) {
            logError("Matrix is empty or invalid.");
            return -1; // Indicating error, possibly use std::numeric_limits<int>::min() for a clearer value.
        }

        int row = my_lower_bound(matrix, target, 0, matrix.size());

        if (row < 0 || row >= matrix.size()) {
            logError("Row index out of bounds.");
            return -1; // Indicating the target is not found in any row.
        }

        return row;
    }

private:
    int my_lower_bound(const std::vector<std::vector<int>>& matrix, int target, int start, int end) {
        while (start < end) {
            int mid = start + (end - start) / 2;
            if (matrix[mid][0] < target) {
                start = mid + 1;
            } else {
                end = mid;
            }
        }
        return start;
    }

    void logError(const std::string& message) const {
        // Simple logging mechanism
        std::cerr << "Error: " << message << std::endl;
    }
};

