class RightShiftSort {
public:
    int rightShiftSort(std::vector<int>& nums) {
        if (nums.empty()) {
            std::cerr << "Input array is empty." << std::endl;
            return -1;
        }

        int n = nums.size();
        int count = 0;

        for (int i = 0; i < n; ++i) {
            int minVal = nums[i];
            int minIndex = i;
            for (int j = 1; j < n; ++j) {
                int index = (i + j) % n;
                if (nums[index] < minVal) {
                    minVal = nums[index];
                    minIndex = index;
                }
            }

            if (minIndex != i) {
                std::swap(nums[i], nums[minIndex]);
                ++count;
            }
        }

        return count;
    }
};

