            target_len = max(maxi, indx2 - indx1 + 1); 
            maxi = -1; // Reset after finding a valid target
        }
    }

    void recur(int l, int r) {
        if (l < r) {
            find_len(l, r, vector<int>(arr.begin() + l, arr.begin() + r + 1));
            if (maxi == -1) return; // If the value was reset, exit
        }

        for (int i = l; i <= r; i++) {
            vector<int> tmp(arr); // Create a copy to manipulate
            int val = arr[i]; // Store current integer
            int inlet = i + 1;

            // Shift elements to the left
            for (int dst = i; dst < r; dst++) {
                if (inlet < arr.size()) {
                    tmp[dst] = arr[inlet++];
                } else {
                    tmp[dst] = numeric_limits<int>::max(); // Set to max to indicate removal
                }
            }
            recur(i + 1, r - 1); // Recursive call
        }
    }
};

