class BallDistribution {
public:
    static int minimumSize(std::vector<int>& nums, int maxOperations);

private:
    static bool canAchieve(const std::vector<int>& nums, int maxOperations, int maxBalls);
    static void validateInputs(const std::vector<int>& nums, int maxOperations);
};

void BallDistribution::validateInputs(const std::vector<int>& nums, int maxOperations) {
    if (nums.empty()) {
        throw std::invalid_argument("Input vector is empty.");
    }
    if (maxOperations < 0) {
        throw std::invalid_argument("maxOperations must be non-negative.");
    }
}

bool BallDistribution::canAchieve(const std::vector<int>& nums, int maxOperations, int maxBalls) {
    int operations = 0;
    for (const int num : nums) {
        int requiredOperations = (num - 1) / maxBalls;
        operations += requiredOperations;
        if (operations > maxOperations) {
            return false;
        }
    }
    return true;
}

int BallDistribution::minimumSize(std::vector<int>& nums, int maxOperations) {
    validateInputs(nums, maxOperations);

    int left = 1;
    int right = *std::max_element(nums.begin(), nums.end());
    int result = right;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (canAchieve(nums, maxOperations, mid)) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}

