struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    std::vector<ListNode*> splitListToParts(ListNode* root, int k) {
        if (k <= 0) {
            std::cerr << "Error: k must be greater than 0." << std::endl;
            return {};
        }

        int size = 0;
        ListNode* curr = root;
        while (curr != nullptr) {
            size++;
            curr = curr->next;
        }

        int sizeEach = size / k;
        int leftOvers = size % k;
        std::vector<ListNode*> result(k, nullptr);
        curr = root;

        for (int i = 0; i < k; ++i) {
            ListNode* head = nullptr;
            ListNode* tail = nullptr;
            int currentPartSize = sizeEach + (i < leftOvers ? 1 : 0);

            for (int j = 0; j < currentPartSize && curr != nullptr; ++j) {
                ListNode* newNode = new ListNode(curr->val);
                if (!head) {
                    head = newNode;
                    tail = newNode;
                } else {
                    tail->next = newNode;
                    tail = tail->next;
                }
                curr = curr->next;
            }

            if (tail) {
                tail->next = nullptr; // Ensure end of the current part
            }
            result[i] = head;
        }

        return result;
    }
};

