class SequenceProcessor {
public:
    void processInput(int n, std::istream& input = std::cin) {
        if (n <= 0) {
            throw std::invalid_argument("Array size must be positive.");
        }

        int val;
        long long ans = -1;
        a.reserve(n);
        count.reserve(n);
        mx.reserve(n + 1);
        mx.push_back(-1);

        for (int i = 0; i < n; ++i) {
            input >> val;

            if (val == -1) {
                input >> val;
                if (ans == -1) ans = val;
                continue;
            }

            if (a.empty()) {
                a.push_back(val);
                count.push_back(1);
                mx.push_back(1);
            } else {
                manageValue(val);
            }
        }

        processQueries(input);
    }

private:
    std::vector<int> a;
    std::vector<int> count;
    std::vector<int> mx;

    void manageValue(int val) {
        int currentSize = a.size();
        if (a[currentSize - 1] != val) {
            a.push_back(val);
            count.push_back(1);
            mx.push_back(1);
        } else {
            count[currentSize - 1]++;
        }
        updateMax(currentSize, val);
    }

    void updateMax(int currentSize, int val) {
        for (int i = currentSize - 1; i >= 0; --i) {
            if (a[i] == val) {
                mx[i] = std::max(i + 1, mx[i + 1]);
            }
        }
    }

    void processQueries(std::istream& input) {
        int q;
        input >> q;

        while (q--) {
            int val2;
            input >> val2;
            int index = findValueIndex(val2);
            long long result = calculateResult(index);
            std::cout << result << "\n";
        }
    }

    int findValueIndex(int val) {
        for (int i = 0; i < a.size(); i++) {
            if (a[i] == val) {
                return i;
            }
        }
        return a.size();
    }

    long long calculateResult(int index) {
        if (index < a.size()) {
            return ans + (mx[index] <= index + 1 ? 0 : mx[index] - index - 1);
        }
        return ans; // Returning ans if the value was not found
    }
};

