class Solution {
public:
    int minMaxDifference(vector<int>& nums, int p) {
        if (nums.empty() || p < 0) {
            throw invalid_argument("Input list is empty or p is negative.");
        }

        int maxNum = *max_element(nums.begin(), nums.end());
        int minNum = *min_element(nums.begin(), nums.end());

        int diff = maxNum - minNum;

        if (diff == 0) {
            return 0; // Early exit if all numbers are the same
        }

        // Create a vector of frequency counts for the numbers
        vector<int> freq(10, 0);
        for (int num : nums) {
            if (num < 0 || num > 9) {
                throw out_of_range("Numbers must be between 0 and 9.");
            }
            freq[num]++;
        }

        // Calculate the min and max considering the available numbers
        int adjustedMax = maxNum;
        int adjustedMin = minNum;

        for (int i = 0; i < 10 && p > 0; i++) {
            while (p > 0 && freq[i] > 0) {
                adjustedMin = min(adjustedMin, i);
                p--;
                freq[i]--;
            }
        }

        for (int i = 9; i >= 0 && p > 0; i--) {
            while (p > 0 && freq[i] > 0) {
                adjustedMax = max(adjustedMax, i);
                p--;
                freq[i]--;
            }
        }

        return adjustedMax - adjustedMin;
    }
};

