template<class T>
T modularInverse(T a, T mod) {
    ll b = mod, u = 1, v = 0;
    if (gcd(a, mod) != 1) {
        throw runtime_error("Inverse does not exist.");
    }
    while(b) {
        ll t = a / b;
        a -= t * b;
        swap(a, b);
        u -= t * v;
        swap(u, v);
    }
    u %= mod;
    return u < 0 ? u + mod : u;
}

template<class T>
T modularExponentiation(T base, ll exponent, T mod) {
    if(mod < 2) {
        throw invalid_argument("Modulus must be >= 2.");
    }
    T result = 1;
    while(exponent > 0) {
        if(exponent & 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exponent >>= 1;
    }
    return result;
}

