class Solution {
public:
    std::string longestDiverseString(int a, int b, int c) {
        if (a < 0 || b < 0 || c < 0) {
            throw std::invalid_argument("Input counts must be non-negative.");
        }

        std::string result;
        while (a > 0 || b > 0 || c > 0) {
            if (result.size() >= 2 && result[result.size() - 1] == result[result.size() - 2]) {
                // Last two characters are the same, choose a different character
                if (a >= b && a >= c) {
                    if (b > 0) {
                        result += 'b';
                        b--;
                    } else if (c > 0) {
                        result += 'c';
                        c--;
                    } else {
                        break;
                    }
                    continue;
                } else if (b >= a && b >= c) {
                    if (a > 0) {
                        result += 'a';
                        a--;
                    } else if (c > 0) {
                        result += 'c';
                        c--;
                    } else {
                        break;
                    }
                    continue;
                } else {
                    if (a > 0) {
                        result += 'a';
                        a--;
                    } else if (b > 0) {
                        result += 'b';
                        b--;
                    } else {
                        break;
                    }
                    continue;
                }
            }

            // Choose the character that has the most remaining
            if (a >= b && a >= c) {
                result += 'a';
                a--;
            } else if (b >= a && b >= c) {
                result += 'b';
                b--;
            } else {
                result += 'c';
                c--;
            }
        }

        return result;
    }
};

