class Utility {
public:
    // Retrieve a greeting message
    static std::string helloWorld() {
        return "Hello, World!";
    }

    // Reverse the digits of a long long number
    static long long reverse(long long n) {
        if (n < 0) {
            throw std::invalid_argument("Negative numbers are not supported.");
        }

        long long result = 0;
        while (n > 0) {
            if (result > (std::numeric_limits<long long>::max() - n % 10) / 10) {
                throw std::overflow_error("Reversed number exceeds long long limits.");
            }
            result = result * 10 + n % 10;
            n /= 10;
        }
        return result;
    }

    // Simple logging function for messages
    static void log(const std::string& message) {
        std::cout << "[LOG]: " << message << std::endl;
    }
};

