import os
import sys
from io import BytesIO, IOBase

BUFSIZE = 8192
MAXSIZE = 1 << 30  # Setting a maximum size for reading lines

class FastIO(IOBase):
    def __init__(self, file):
        if not isinstance(file, IOBase):
            raise ValueError("Provided file is not a valid IOBase instance.")
        self._read_io = file
        self.buffer = BytesIO()
        self.writable = 'x' in file.mode or 'r' not in file.mode
        self.write = self.buffer.write if self.writable else None
        self.newlines = 0

    def read(self):
        while True:
            b = self._read_io.read(BUFSIZE)
            if not b:
                break
            ptr = self.buffer.tell()
            self.buffer.seek(0, 2)
            self.buffer.write(b)
            self.buffer.seek(ptr)
        return self.buffer.read()

    def readline(self):
        while self.newlines == 0:
            b = self._read_io.readline(MAXSIZE)
            self.newlines = b.count(b'\n') + (not b)
            ptr = self.buffer.tell()
            self.buffer.seek(0, 2)
            self.buffer.write(b)
            self.buffer.seek(ptr)
        self.newlines -= 1
        return self.buffer.readline()

    def flush(self):
        if self.writable:
            self._write_io.write(self.buffer.getvalue())
            self.buffer.truncate(0)
            self.buffer.seek(0)

class IOWrapper(IOBase):
    def __init__(self, file):
        self.buffer = FastIO(file)
        self.flush = self.buffer.flush
        self.writable = self.buffer.writable
        self.write = lambda s: self.buffer.write(s.encode('ascii'))
        self.read = lambda: self.buffer.read().decode('ascii')
        self.readline = lambda: self.buffer.readline().decode('ascii')

def configure_io():
    if not os.path.isfile("local.txt"):
        sys.stdin, sys.stdout = IOWrapper(sys.stdin), IOWrapper(sys.stdout)
    return lambda: sys.stdin.readline().rstrip("\r\n")

