import sys

def read_input():
    try:
        return sys.stdin.read().strip().split()
    except Exception as e:
        raise RuntimeError("Failed to read input") from e

def find_minimum_x(delta):
    x = 1
    while 2 ** (x - 1) < delta:
        x += 1
    return x

def solve_test_case(n, a):
    if n <= 0 or not a:
        raise ValueError("Invalid input: 'n' must be greater than 0 and 'a' must not be empty.")

    min_seconds = 0
    sorted_a = sorted(a)

    for i in range(n):
        if a[i] != sorted_a[i]:
            delta = sorted_a[i] - a[i]
            if delta <= 0:
                continue
            min_seconds = max(min_seconds, find_minimum_x(delta))

    return min_seconds

def process_test_cases(data):
    try:
        t = int(data[0])
        if t <= 0:
            raise ValueError("Invalid number of test cases.")

        results = []
        index = 1

        for _ in range(t):
            n = int(data[index])
            index += 1

            if n <= 0:
                raise ValueError("Number of elements `n` must be greater than 0.")

            a = list(map(int, data[index:index + n]))
            index += n

            result = solve_test_case(n, a)
            results.append(result)

        return results

    except (ValueError, IndexError) as e:
        raise RuntimeError("Error processing test cases") from e

def output_results(results):
    for result in results:
        print(result)

def main():
    data = read_input()
    results = process_test_cases(data)
    output_results(results)

