def stock_span(input_arr, n):
    arr = [0] * n
    stack = []
    arr[0] = 1
    stack.append(0)

    for i in range(1, n):
        while stack and input_arr[stack[-1]] < input_arr[i]:
            stack.pop()
        arr[i] = i + 1 if not stack else i - stack[-1]
        stack.append(i)

    return arr

