def calculate_manhattan_distance(point1, point2):
    return abs(point1[0] - point2[0]) + abs(point1[1] - point2[1])

def solve_cost(n, xy_coords):
    if n <= 0 or not xy_coords:
        raise ValueError("Invalid input: number of coordinates must be greater than zero.")

    total_cost = 0
    for i in range(n):
        for j in range(i + 1, n):
            total_cost += calculate_manhattan_distance(xy_coords[i], xy_coords[j])

    return total_cost

def calculate_optimal_cost(coords):
    if not coords:
        raise ValueError("Invalid input: coordinates list is empty.")

    unique_positions = set(coords)
    if len(unique_positions) == 1:
        return 0

    min_cost = float('inf')
    for point1 in unique_positions:
        for point2 in unique_positions:
            if point1 != point2:
                min_cost = min(min_cost, calculate_manhattan_distance(point1, point2))

    return min_cost

