def round_robin(jobs, slice, index):
    if not isinstance(jobs, list) or not all(isinstance(job, int) and job >= 0 for job in jobs):
        raise ValueError("Jobs must be a list of non-negative integers.")
    if not isinstance(slice, int) or slice <= 0:
        raise ValueError("Slice must be a positive integer.")
    if not isinstance(index, int) or not (0 <= index < len(jobs)):
        raise ValueError("Index must be a valid job index.")

    cycles = 0
    i = 0
    total_jobs = sum(jobs)

    while total_jobs > 0:
        if jobs[i] > 0:
            time_slice = min(jobs[i], slice)
            cycles += time_slice
            jobs[i] -= time_slice
            total_jobs -= time_slice

            if i == index and jobs[i] == 0:
                return cycles

        i = (i + 1) % len(jobs)

    return -1

