import heapq

def calculate_team_difference(t, test_cases):
    results = []

    for case in test_cases:
        n, s = case
        s.sort()

        if n < 2:
            results.append(0)
            continue

        min_heap, max_heap = [], []

        for teammate in s[:n//2]:
            heapq.heappush(min_heap, teammate)

        for teammate in s[n//2:]:
            heapq.heappush(max_heap, -teammate)

        answer = -heapq.heappop(max_heap) - heapq.heappop(min_heap)
        results.append(answer)

    return results

