import re
import math

class EngineeringCalculator:
    def __init__(self):
        self.logger = self.setup_logger()

    @staticmethod
    def setup_logger():
        import logging
        logger = logging.getLogger("EngineeringCalculator")
        logger.setLevel(logging.INFO)
        handler = logging.StreamHandler()
        formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
        handler.setFormatter(formatter)
        logger.addHandler(handler)
        return logger

    @staticmethod
    def _is_valid_input(input_str):
        return bool(re.match(r'^\d+([a-zA-Z]+)?$', input_str))

    @staticmethod
    def parse_input(input_str):
        match = re.match(r'(\d+)([a-zA-Z]+)?', input_str)
        if match:
            number = int(match.group(1))
            unit = match.group(2) if match.group(2) else ''
            return number, unit
        raise ValueError("Invalid input format")

    @staticmethod
    def calculate_square(number):
        return number ** 2

    def process_square_request(self, input_str):
        if not self._is_valid_input(input_str):
            self.logger.error("Invalid input: %s", input_str)
            raise ValueError("Input must be in the format 'number[letters]'")

        number, unit = self.parse_input(input_str)
        result = self.calculate_square(number)
        return f"{result}_ / {2}"

    def calculate_radix(self, base, x):
        if base <= 0:
            self.logger.error("Base must be greater than 0")
            raise ValueError("Base must be greater than 0")
        return math.factorial(int(x)) / (base ** int(x))

    def calculate_logarithm(self, base, value):
        if value <= 0 or base <= 0:
            self.logger.error("Both base and value must be greater than 0")
            raise ValueError("Both base and value must be greater than 0")
        return math.log(value, base)

    def calculate_sine(self, radians):
        return math.sin(radians)

    def calculate_exponentiation(self, base, exponent):
        return base ** exponent

