def solve(N, A):
    if not isinstance(N, int) or N <= 0:
        raise ValueError("N must be a positive integer.")
    if not isinstance(A, list) or len(A) != N or not all(isinstance(x, int) for x in A):
        raise ValueError("A must be a list of N integers.")

    MOD = 10**9 + 7

    # Calculate prefix sum
    try:
        prefix_sum = [0]
        for a in A:
            prefix_sum.append(prefix_sum[-1] + a)

        # Calculate suffix sum
        suffix_sum = [0] * (N + 1)
        for i in range(N - 1, -1, -1):
            suffix_sum[i] = suffix_sum[i + 1] + A[i]

        # Calculate the total cost for each block
        total_cost = [A[i] * (prefix_sum[i] + suffix_sum[i + 1]) for i in range(N)]

        # Sum up the total costs
        total_total_cost = sum(total_cost) % MOD
    except Exception as e:
        raise RuntimeError(f"An error occurred during calculation: {e}")

    return total_total_cost

