def min_taxi_time(a, b, n, taxis):
    import heapq

    if n <= 0 or not taxis:
        raise ValueError("Number of taxis must be greater than zero.")

    taxis = sorted(taxis, key=lambda x: (x[0], x[1]))
    min_heap = []
    total_time = 0.0

    for taxi in taxis:
        time_to_min_taxi = (a - taxi[0]) / taxi[2]
        time_to_max_taxi = (b - taxi[1]) / taxi[2]
        total_time += max(time_to_min_taxi, time_to_max_taxi)

        heapq.heappush(min_heap, taxi)

        while min_heap and time_to_min_taxi < time_to_max_taxi:
            curr_taxi = heapq.heappop(min_heap)
            if curr_taxi[0] < a or curr_taxi[1] > b:
                continue

            travel_time = ((a - curr_taxi[0]) + (b - curr_taxi[1])) / curr_taxi[2]
            total_time += travel_time

            heapq.heappush(min_heap, curr_taxi)

    return total_time

