import itertools
import heapq
import sys

class Graph:
    def __init__(self, n):
        self.n = n
        self.adjacency_list = [[] for _ in range(n)]

    def add_edge(self, a, b, c):
        self.adjacency_list[a - 1].append((b - 1, c))
        self.adjacency_list[b - 1].append((a - 1, c))

def dijkstra(graph, start):
    dist = [float('inf')] * graph.n
    dist[start] = 0
    pq = [(0, start)]

    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in graph.adjacency_list[u]:
            if dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
                heapq.heappush(pq, (dist[v], v))
    return dist

def solve(n, m, r, towns, roads):
    graph = Graph(n)

    for a, b, c in roads:
        graph.add_edge(a, b, c)

    try:
        dist = [dijkstra(graph, town - 1) for town in towns]
    except Exception as e:
        print(f"Error during Dijkstra computation: {e}", file=sys.stderr)
        return float('inf')

    min_cost = float('inf')

    for perm in itertools.permutations(range(r)):
        cost = 0
        for i in range(r - 1):
            cost += dist[perm[i]][perm[i + 1]]
        min_cost = min(min_cost, cost)

    return min_cost

