def validate_matrix(matrix):
    if not isinstance(matrix, np.ndarray):
        raise TypeError("Input must be a numpy ndarray.")
    if matrix.ndim != 2 or matrix.shape[0] != 5 or matrix.shape[1] != 5:
        raise ValueError("Matrix must be 5x5.")

def find_one_position(matrix):
    for i in range(matrix.shape[0]):
        for j in range(matrix.shape[1]):
            if matrix[i][j] == 1:
                return i, j
    raise ValueError("Matrix must contain exactly one '1'.")

def calculate_min_moves(matrix):
    validate_matrix(matrix)

    one_row, one_col = find_one_position(matrix)
    min_moves = matrix.shape[0] + matrix.shape[1] - 1

    moves_to_center = max(abs(2 - one_row), abs(2 - one_col))
    min_moves -= moves_to_center

    for i in range(4):
        if np.sum(matrix[i, :]) != np.sum(matrix[i + 1, :]):
            min_moves -= 1
            break
        if np.sum(matrix[:, i]) != np.sum(matrix[:, i + 1]):
            min_moves -= 1
            break

    return min_moves

