def power_mod(n, r, mod=10**9 + 7):
    if not isinstance(n, (int, float)):
        raise TypeError("Base 'n' must be an integer or float.")
    if not isinstance(r, int) or r < 0:
        raise ValueError("Exponent 'r' must be a non-negative integer.")

    result = 1
    base = n % mod

    while r > 0:
        if r % 2 == 1:  # If r is odd, multiply base with result
            result = (result * base) % mod
        r //= 2  # Divide r by 2
        base = (base * base) % mod  # Square the base

    return result

