def align_counter(a, b):
    try:
        results = [[0, 0]]
        m = a // b
        remainder = abs(a % b)

        for l in range(m + 1):
            results.append([l, 2 << l])

        if remainder == 0:
            return results

        remainder_value = 1 << remainder
        results.append([1, remainder_value])

        for i in range(2, len(results)):
            remainder += 1
            current_value = (remainder_value << 1) | (1 << remainder)
            results.append([i, current_value])
            remainder -= 1

        return results

    except Exception as e:
        print(f"Error in align_counter: {e}")
        return []

def min_moves_to_good_array(t, test_cases):
    results = []
    for n, a in test_cases:
        odd_indices = [i for i in range(n) if i % 2 == 1]
        even_indices = [i for i in range(n) if i % 2 == 0]
        odd_elements = [a[i] for i in odd_indices if a[i] % 2 == 1]
        even_elements = [a[i] for i in even_indices if a[i] % 2 == 0]

        if len(odd_indices) != len(odd_elements) or len(even_indices) != len(even_elements):
            results.append(-1)
            continue

        swaps = 0
        odd_elements.sort()
        even_elements.sort()

        for i in range(len(odd_indices)):
            if a[odd_indices[i]] != odd_elements[i]:
                swaps += 1

        for i in range(len(even_indices)):
            if a[even_indices[i]] != even_elements[i]:
                swaps += 1

        results.append(swaps // 2)

    return results

