def find_min_kebabs(N, M):
    if not (5 <= N < 17) or len(M) != 3:
        raise ValueError("Invalid input: N must be in range [5, 17) and M must have 3 elements.")

    try:
        base_price = max(M)
        M.remove(base_price)
        change_order = [1]

        sorted_menu_reversed = sorted(M, reverse=True)

        for price in sorted_menu_reversed:
            change_order.append(base_price // price)

        def revenue_calc(kebabs):
            revenue = sum(kebabs[i] * sorted_menu_reversed[i] for i in range(3))
            total = sum(kebabs)
            return kebabs, total, revenue, sorted_menu_reversed

        kebabs_used = 100 // base_price
        remainder = 100 % base_price

        if remainder > 0:
            n = N - kebabs_used
            if n < 0:
                raise ValueError("Insufficient guests to satisfy the budget.")
        else:
            n = N

        number_of_kebabs = [kebabs_used] + [0] * 2

        for i in range(n):
            if remainder >= sorted_menu_reversed[0]:
                number_of_kebabs[1] += 1
                remainder -= sorted_menu_reversed[0]
            elif remainder >= sorted_menu_reversed[1]:
                number_of_kebabs[2] += 1
                remainder -= sorted_menu_reversed[1]

        result = revenue_calc(number_of_kebabs)
        return result

    except Exception as e:
        print(f"Error: {str(e)}")
        return None

