def compute_gcd_counts(plankN, a):
    try:
        return Counter(gcd(a[i], a[j]) for i in range(plankN) for j in range(i + 1, plankN))
    except Exception as e:
        logging.error("Error in computing GCD counts: %s", e)
        return Counter()

def compute_grid_sides(gcd_counts):
    grid_sides = set()
    for gcdN, plane in gcd_counts.items():
        for i in range(int((plane // gcdN + 1) / 2) + 1):
            if gcdN * i <= plane:
                grid_sides.add(plane // i)
    return grid_sides

