def maximize_time(s: str) -> str:
    res = s
    n = len(res)
    ans = 0

    for i in range(1, n):
        res = max(res, next_time(res, 1))
        if i < n:
            ans = max(ans, (n - i) * ord(s[i]) - ord(s[0]))

    return ans


def next_time(s: str, d: int) -> str:
    n = len(s)
    for i in range(n - d):
        idx = i + d - 1
        if s[idx] != s[i]:
            break
    return s[i:i + d]

def reverse_number(x):
    if x < 0:
        raise ValueError("Input must be a non-negative integer.")
    ans = 0
    while x > 0:
        rem = x % 10
        ans = (ans * 10) + rem
        x //= 10
    return ans

def compute_sequences(limit=1001):
    if limit <= 0:
        raise ValueError("Limit must be a positive integer.")

    ans = [0] * limit
    arr = [0] * limit
    flag = [0] * limit

    for i in range(limit):
        arr[i] = i
        flag[i] = 1 if i == 0 else 0

        if flag[i - 1] == 1:
            for j in range(3):
                if j == 0:
                    temp = i - arr[i - 1]
                elif j == 1:
                    temp = i - reverse_number(i + 1)
                else:
                    temp = i - reverse_number(i - 1)

                if 0 < temp < limit:
                    arr[temp] = i
                    flag[temp] = 1

            if temp <= 100:
                return i

        tro = i
        while tro >= 0 and flag[tro] == 1:
            tro -= 1

        if tro >= 0:
            ans[tro + reverse_number(tro)] = ans[tro] + i

    return ans

