import numpy as np
import logging

logging.basicConfig(level=logging.INFO)

def find_colors(n, m, edges):
    try:
        graph = {u: set() for u in range(1, n + 1)}
        for u, v in edges:
            graph[u].add(v)

        colors = [None] * m

        def dfs(node, current_color):
            if colors[node] is not None:
                return colors[node]
            for neighbor in graph[node]:
                has_color = colors[neighbor] if neighbor < len(colors) else None
                if has_color is not None:
                    if (current_color == 1 and has_color == 1) or (current_color == 2 and has_color == 2):
                        edge_has_color = True
                    else:
                        edge_has_color = False
                else:
                    edge_has_color = dfs(neighbor, 3 - current_color)
                if not edge_has_color:
                    colors[node] = current_color
                    return colors[node]
                if neighbor < len(colors):
                    del colors[neighbor]
            return None

        connected_nodes = set()
        connected = True
        for node in graph:
            if node not in connected_nodes:
                connected_nodes.add(node)
                dfs(node, 1)
                if len(connected_nodes) < n:
                    connected = False
                    break

        if not connected:
            for node in graph:
                if colors[node] is None:
                    dfs(node, 2)
            for node in graph:
                if colors[node] is None:
                    dfs(node, 3)

        return colors

    except Exception as e:
        logging.error("An error occurred in find_colors: %s", str(e))
        return None  # Return None or handle as appropriate

