using namespace std;

int calculatePairs(const vector<int>& nums) {
    unordered_map<int, int> countMap;
    for (int num : nums) {
        countMap[num]++;
    }

    int pairs = 0;
    int leftovers = 0;

    for (const auto& entry : countMap) {
        pairs += entry.second / 2;
        leftovers += entry.second % 2;
    }

    return pairs * 2; // Each pair contributes two to the total
}

vector<int> findPairsAndLeftovers(const vector<int>& nums) {
    int pairs = calculatePairs(nums);
    int leftovers = nums.size() - pairs;

    return {pairs / 2, leftovers}; // Return number of pairs and leftovers
}

