def find_nth_non_divisible(n, k):
    if n <= 0 or k <= 0:
        raise ValueError("Both n and k must be positive integers")

    candidate = 1
    counter = 0

    while counter < k:
        if candidate % n != 0:
            counter += 1
        candidate += 1

    return candidate - 1  # Return the last candidate that met the condition

