def sieve(n):
    if n < 2:
        raise ValueError("Input must be at least 2")

    mods = set()

    for p in range(2, n):
        if p not in mods:
            mods.add(p)
            for q in range(p * 2, n, p):
                mods.add(q)

    return sorted([p for p in mods if p < n])

def outer(n):
    if n < 1:
        raise ValueError("Input must be at least 1")

    prime_sets = set()

    for i in range(1, n + 1):
        prime_sets.update(sieve(i))

    return prime_sets

def main():
    try:
        prime_list = sieve(200001)
        prime_sets = outer(200)

        print("Generated primes up to 200001")
        print(prime_list)

        print("Unique prime numbers generated for outer function:")
        print(prime_sets)

    except ValueError as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()

