def findXOR(l, r):
    if not isinstance(l, int) or not isinstance(r, int):
        raise ValueError("Inputs must be integers.")

    if l > r:
        raise ValueError("Lower bound 'l' must be less than or equal to upper bound 'r'.")

    if l % 4 == 0:
        return r if r % 4 == 0 else 1
    elif l % 4 == 1:
        return r if r % 4 != 0 else r ^ 1
    elif l % 4 == 2:
        return r ^ 2 if r % 4 == 0 else r ^ 1
    else:
        return r ^ 1 ^ l if r % 4 == 0 else r ^ l


class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right


class Solution:
    def lowestCommonAncestor(self, root, p, q):
        if root is None or p is None or q is None:
            raise ValueError("Root, p, and q cannot be None.")

        if not isinstance(root, TreeNode) or not isinstance(p, TreeNode) or not isinstance(q, TreeNode):
            raise TypeError("Inputs must be instances of TreeNode.")

        if p.val < root.val and q.val < root.val:
            return self.lowestCommonAncestor(root.left, p, q)
        elif p.val > root.val and q.val > root.val:
            return self.lowestCommonAncestor(root.right, p, q)

        return root


class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next


class Solution:
    def reorderList(self, head):
        if head is None:
            return

        p1, p2 = head, head
        while p2 and p2.next:
            p1 = p1.next
            p2 = p2.next.next

        pre_middle, pre_current = p1, p1.next
        pre_middle.next = None  # End first half

        # Reverse second half
        second_half = None
        while pre_current:
            next_node = pre_current.next
            pre_current.next = second_half
            second_half = pre_current
            pre_current = next_node

        # Merge two halves
        first_half, second_half = head, second_half
        while second_half:
            temp1, temp2 = first_half.next, second_half.next
            first_half.next = second_half
            second_half.next = temp1
            first_half = temp1
            second_half = temp2

