    if a + b + c > 4 and (a > 4 or b > 4 or c > 4):
        if a > c:
            if a - c < 2:
                return "Impossible"
            elif a == c:
                return f"0 0 {2 - min(2, a)}" if 4 - max(a, b) else f"0 {4 - max(a, b)} 0"
            else:
                return f"0 {a - c - 1} {a - c - 1}" if 4 - max(a, b) else f"0 {4 - max(a, c)} {4 - max(a, b)}"
        else:
            if a > b:
                return f"1 1 {b if b == c else a - c}"
            elif a == b:
                return f"{1 + c - b} 1 {1 + c - a}"
            else:
                return f"{1 + c - a} {1 + c - b} 1"
    else:
        min_bonds = max(1 + b - a, 0)
        adjustment = c if c < a else abs(a - c) if a == c else c - min(abs(a - c), 4 - max(b, a) if b < 4 else a)
