import numpy as np

def calculate_days(n, m):
    if n < 0 or m <= 0:
        raise ValueError("Input values must be n >= 0 and m > 0.")

    days = np.arange(n + m - 1) % m
    restocks = days[days == m - 1]
    days_pass = np.roll(np.cumsum(np.isin(days, restocks)), 1)

    total_days = days_pass[-1]
    return total_days

