class Solution:
    def theCuteFrog(self, words: list[str]) -> int:
        from collections import Counter

        if not words:
            raise ValueError("Input list 'words' cannot be empty.")

        try:
            char_count = Counter(char for word in words for char in word)
            min_count = min(char_count.values())

            answer = sum(1 for word in words if any(char_count[char] == min_count for char in word))
            return answer
        except Exception as e:
            raise RuntimeError(f"An error occurred during processing: {e}") from e

def anagram_distance(s):
    if not isinstance(s, (list, str)) or not all(bit in {0, 1} for bit in s):
        raise ValueError("Input must be a list or string of binary digits (0 or 1).")

    count_ones = s.count(1)
    count_zeros = s.count(0)

    if count_ones == 0 or count_zeros == 0:
        return 0  # Hamming distance is zero if all bits are the same

    # The minimum Hamming distance is determined by the smaller of the two counts
    return 1 if min(count_ones, count_zeros) > 0 else 0

