import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class DataProcessor:
    def __init__(self, data):
        self.data = data
        logging.info("DataProcessor initialized with data.")

    def validate_data(self):
        if not isinstance(self.data, list) or not all(isinstance(item, (int, float)) for item in self.data):
            logging.error("Invalid data format: expected a list of numbers.")
            raise ValueError("Data must be a list of integers or floats.")
        logging.info("Data validation passed.")

    def process_data(self):
        try:
            self.validate_data()
            # Example transformation: scale each value by 100
            processed_data = [self.scale_value(item) for item in self.data]
            logging.info(f"Processed data: {processed_data}")
            return processed_data
        except Exception as e:
            logging.error("Error during data processing: %s", e)
            raise

    @staticmethod
    def scale_value(value):
        if value < 0:
            logging.warning("Negative value encountered: %s", value)
        return value * 100

def main():
    raw_data = [3, 5, -2, 7]  # Example input
    processor = DataProcessor(raw_data)

    try:
        results = processor.process_data()
        print("Final Results:", results)
    except ValueError as ve:
        print(f"Validation error: {ve}")
    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    main()

import logging

