def check_danger(s):
    if not isinstance(s, str):
        logging.error("Input is not a string.")
        return 'INVALID INPUT'

    if len(s) < 4:
        logging.warning("Input string is too short.")
        return 'NO'

    for i in range(len(s) - 3):
        sub_s = s[i:i+4]
        if all(char == sub_s[0] for char in sub_s):
            logging.info("Danger detected: four consecutive identical characters.")
            return 'YES'

    logging.info("No danger detected.")
