def can_make_equal(a, b):
    try:
        n = len(a)
        if sum(a) != sum(b):
            return "NO"

        min_a, max_a = float('inf'), float('-inf')
        min_b, max_b = float('inf'), float('-inf')
        ind_min_a = ind_max_a = ind_min_b = ind_max_b = -1

        for i in range(n):
            if a[i] < min_a:
                min_a, ind_min_a = a[i], i
            if a[i] > max_a:
                max_a, ind_max_a = a[i], i
            if b[i] < min_b:
                min_b, ind_min_b = b[i], i
            if b[i] > max_b:
                max_b, ind_max_b = b[i], i

        min_push = max_push = 0

        for i in range(ind_min_a, ind_max_a + 1):
            k_min = min_b - a[i] + 1
            k_max = max_b - a[i] - min_push
            if k_min <= max_push or k_max >= min_push:
                return "NO"

        min_push = max(min_push, max(min_b - a[ind_min_a], a[ind_max_a] - max_b), 1)
        max_push = max(max_push, max(min_b - a[ind_max_a], a[ind_min_a] - max_b), 1)

        for i in range(ind_min_a, ind_max_a + 1):
            diff = b[i] - a[i]
            if diff > max_push:
                return "NO"

        return "YES"
    except Exception as e:
        return f"Error: {e}"

