def mex(s):
    seen = [False] * 101
    for x in s:
        if 0 <= x < 101:
            seen[x] = True
    for i in range(101):
        if not seen[i]:
            return i
    return -1  # Fallback case, should not occur with valid input

def solve(n, arr):
    if n <= 0 or len(arr) != n:
        raise ValueError("Invalid input: n must be positive and match the length of arr.")

    freq = [0] * 101
    for x in arr:
        if 0 <= x < 101:
            freq[x] += 1
        else:
            raise ValueError("Elements of arr must be in the range [0, 100].")

    A = []
    B = []

    for i in range(101):
        if freq[i] == 0:
            break
        if freq[i] == 1:
            A.append(i)
        else:
            A.append(i)
            B.append(i)

    return mex(A) + mex(B)

