class WeaponGame:
    def __init__(self):
        self.n = 0
        self.h = 0
        self.a = []

    def input_data(self):
        try:
            self.n, self.h = map(int, input("Enter number of weapons and health: ").split())
            self.a = list(map(int, input(f"Enter the damage values for {self.n} weapons: ").split()))
            if len(self.a) != self.n:
                raise ValueError("The number of damage values must match the number of weapons.")
        except ValueError as e:
            print(f"Input error: {e}")
            sys.exit(1)

    def check(self):
        return any(self.a[i] <= self.h for i in range(self.n))

    def game(self, h):
        if h <= 0:
            return 0
        if self.n == 0:
            return 1

        ans = 0
        for i in range(self.n):
            if self.a[i] <= h:
                ans = max(ans, 1 + self.game(h - self.a[i]))
        return ans

    def run(self):
        if not self.check():
            print("No weapon can damage the enemy.")
            return

        result = self.game(self.h)
        print(f"Maximum shots needed: {result}")

