import logging

logging.basicConfig(level=logging.INFO)

def maximum_match(G):
    if not G or not all(len(row) == len(G[0]) for row in G):
        logging.error("Invalid input: The input graph G must be non-empty and rectangular.")
        return 0

    M, N = len(G), len(G[0])
    parent = [-1] * N

    def find(x):
        if parent[x] == -1:
            return x
        parent[x] = find(parent[x])
        return parent[x]

    def union(a, b):
        rootA = find(a)
        rootB = find(b)
        if rootA != rootB:
            parent[rootA] = rootB

    def can_augment():
        for i in range(N):
            for j in range(M):
                if G[j][i] == 1 and parent[i] == -1:
                    return True
        return False

    def bfs():
        queue = deque()
        for j in range(M):
            if G[0][j] == 1:
                parent[j] = 0
                queue.append(j)
        while queue:
            v = queue.popleft()
            for i in range(N):
                if G[v][i] == 1 and parent[i] == -1:
                    parent[i] = v
                    if i == N - 1:
                        return True
                    queue.append(i)
        return False

    max_applications = 0
    while bfs():
        max_applications += 1
        union_list = [i for i in range(N) if parent[i] == -1]
        for job in union_list:
            for applicant in range(M):
                if G[applicant][job] == 1:
                    union(applicant, job)

    logging.info(f"Maximum applications that can be matched: {max_applications}")
    return max_applications

