def asteroid_collision(asteroids):
    """
    Simulates the collision of asteroids and returns their state after all collisions.

    Args:
    asteroids (list): A list of integers representing the size and direction of asteroids.

    Returns:
    list: A list of integers representing the state of asteroids after all collisions.
    """
    if not isinstance(asteroids, list):
        raise ValueError("Input must be a list of asteroid values.")

    if any(not isinstance(a, int) for a in asteroids):
        raise ValueError("All asteroid values must be integers.")

    stack = []

    for asteroid in asteroids:
        if asteroid > 0 or not stack or stack[-1] < 0:
            stack.append(asteroid)
        else:
            while stack and stack[-1] > 0 and stack[-1] < -asteroid:
                stack.pop()
            if not stack or stack[-1] < 0:
                stack.append(asteroid)
            elif stack[-1] == -asteroid:
                stack.pop()

    return stack

