def calculate_cost(onlynums):
    try:
        nums = [int(i) for i in onlynums]
        if len(nums) != 4:
            raise ValueError("Expected exactly four integers.")

        n, m, a, b = nums
        if n < 0 or m <= 0 or a < 0 or b < 0:
            raise ValueError("Numbers cannot be negative, and m must be greater than zero.")

        cost = a * n

        if a == b:
            return cost
        elif m > n:
            cost = b * m
            return cost
        elif cost < b * m + a:
            return cost
        else:
            x = (n + m) // m
            remainder = n % m
            cost = b * x + a * remainder
            return cost

    except ValueError as ve:
        logging.error("ValueError: %s", ve)
        return None
    except Exception as e:
        logging.error("An unexpected error occurred: %s", e)
        return None

