class Solution:
    def numRollsToTarget(self, d: int, f: int, target: int) -> int:
        MOD = 10**9 + 7

        if d <= 0 or f <= 0 or target < 0:
            raise ValueError("Invalid input: d and f must be positive, target must be non-negative.")

        cache = {}

        def dp(num_dice: int, remaining_target: int) -> int:
            if (num_dice, remaining_target) in cache:
                return cache[(num_dice, remaining_target)]
            if num_dice == 0:
                result = 1 if remaining_target == 0 else 0
                cache[(num_dice, remaining_target)] = result
                return result
            if remaining_target < 0:
                return 0

            total_ways = 0
            for i in range(1, min(f, remaining_target) + 1):
                total_ways += dp(num_dice - 1, remaining_target - i)
                total_ways %= MOD

            cache[(num_dice, remaining_target)] = total_ways
            return total_ways

        return dp(d, target)

