class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class SolutionIteratively:
    def reverseList(self, head: ListNode) -> ListNode:
        if not head:
            return head
        tail = None
        current_node = head
        while current_node:
            tmp = current_node.next
            current_node.next = tail
            tail = current_node
            current_node = tmp
        return tail

class SolutionTLE:
    def reverseList(self, head: ListNode) -> ListNode:
        if not head:
            return None
        return self.reverse(head)

    def reverse(self, node: ListNode) -> ListNode:
        if not node.next:
            return node
        new_head = self.reverse(node.next)
        node.next.next = node
        node.next = None
        return new_head

