import sys

def min_value(s):
    if not s.islower() or not s.isalpha():
        raise ValueError("Input string must contain only lowercase alphabet characters.")

    dp = [[0] * 26 for _ in range(len(s))]

    for i in range(len(s)):
        for j in range(26):
            if i == 0:
                dp[i][j] = (ord(s[i]) - 97) ** 2
                continue

            dp[i][j] = sys.maxsize
            for m in range(26):
                if m == j:
                    dp[i][j] = min(dp[i][j], dp[i - 1][j])
                else:
                    dp[i][j] = min(dp[i][j], dp[i - 1][m] + (s[i] == chr(97 + m)) ** 2)

    return min(dp[len(s) - 1])

