def get_required_drives_count(n, m, drives_capacity):
    """Determine the minimum number of USB drives needed to write the given file size."""
    if n <= 0 or m <= 0:
        raise ValueError("Number of drives and file size must be positive.")
    if len(drives_capacity) != n:
        raise ValueError("The length of drives_capacity must match the number of drives provided.")

    drives_capacity.sort(reverse=True)
    current_sum = 0
    needed_drives = 0

    for drive in drives_capacity:
        if current_sum >= m:
            break
        current_sum += drive
        needed_drives += 1

    if current_sum < m:
        raise RuntimeError("Insufficient total drive capacity to store the file.")

    return needed_drives


