def min_max_element(n, k):
    """
    Compute the minimum possible maximum element in an array of length n
    where the sum of the elements in the array is divisible by k.

    :param n: Integer, length of the array.
    :param k: Integer, the divisor that the sum of the array's elements must be divisible by.
    :return: Integer, the minimum possible maximum element in the array.
    :raises ValueError: if n or k is non-positive.
    """
    if n <= 0 or k <= 0:
        raise ValueError("Both n and k must be positive integers.")

    max_ele = n
    if k % n == 0:
        max_ele = k // n
    return max_ele

