def calculate_intersections(points):
    row_counts = defaultdict(int)
    col_counts = defaultdict(int)
    grid = defaultdict(lambda: defaultdict(int))

    for x, y in points:
        row_counts[x] += 1
        col_counts[y] += 1
        grid[x][y] = 1

    return row_counts, col_counts, grid

def compute_answer(row_counts, col_counts, grid):
    ans = 0
    for x in row_counts:
        for y in col_counts:
            if grid[x][y] == 0:
                ans += min(row_counts[x], col_counts[y]) - 1
    return ans // 2

