def can_divide_candies(a, b, c):
    try:
        total_candies = a + b + c
        if total_candies % 2 != 0:
            return "No"

        target = total_candies // 2

        if target >= max(a, b, c):
            return "Yes"

        for candy in [a, b, c]:
            if (target - candy) >= sum([x for x in [a, b, c] if x != candy]):
                return "Yes"

        return "No"

    except Exception as e:
        return f"Error: {str(e)}"

