    """
    Determine the winner of the game based on the number of rows and columns.

    Parameters:
    rows (int): Number of rows.
    columns (int): Number of columns.

    Returns:
    str: The name of the winner.
    """
    if not isinstance(rows, int) or not isinstance(columns, int):
        raise ValueError("Both rows and columns must be integers.")

    if rows < 1 or columns < 1:
        raise ValueError("Rows and columns must be positive integers.")

    min_val, max_val = min(rows, columns), max(rows, columns)

    if min_val <= 2 and max_val != 2 * min_val:
        return "Malvika"

    if min_val <= 2 and max_val == 2 * min_val:
        return "Malvika" if (rows % 2 == 1) and (columns % 2 == 1) or (rows % 2 == 0) and (columns % 2 == 0) else "Akshat"

    return "Akshat"

