def coalition(a):
    if not a or not isinstance(a, list):
        raise ValueError("Input must be a non-empty list.")

    n = len(a)
    if n < 1:
        raise ValueError("List must contain at least one element.")

    total_sum = sum(a[1:])

    if a[0] >= total_sum / 2:
        return 1

    for i in range(1, n):
        if a[0] >= a[i] * 2 and a[0] + a[i] > total_sum / 2:
            return 2

    for i in range(1, n):
        for j in range(i + 1, n):
            if all(a[0] >= a[k] * 2 for k in (i, j)) and a[0] + a[i] + a[j] > total_sum / 2:
                return 3

    return 0

