def dynamic_array(n, queries):
    if not (1 <= n <= 10**4):
        raise ValueError("n must be between 1 and 10^4")

    arr = [[] for _ in range(n)]
    last_answer = 0
    answers = []

    for i, query in enumerate(queries):
        try:
            x, y = map(int, query.split())
            if x not in (1, 2):
                raise ValueError(f"Query type must be 1 or 2, got {x}")

            idx = (x ^ last_answer) % n

            if x == 1:
                arr[idx].append(y)

            elif x == 2:
                if not arr[idx]:
                    raise IndexError(f"No elements in array at index {idx} for query {i}")
                last_answer = arr[idx][y % len(arr[idx])]
                answers.append(last_answer)

        except ValueError as ve:
            print(f"ValueError in query {i}: {ve}")
        except IndexError as ie:
            print(f"IndexError in query {i}: {ie}")
        except Exception as e:
            print(f"Unexpected error in query {i}: {e}")

    return answers

def max_consecutive_ones(n, k, s):
    if not isinstance(n, int) or not isinstance(k, int) or not isinstance(s, str):
        raise ValueError("Invalid input types: n and k should be integers and s should be a string.")

    if n <= 0 or k < 0 or len(s) != n or any(c not in '01' for c in s):
        raise ValueError("Invalid input values: Ensure n > 0, k >= 0, and s has length n consisting only of '0' or '1'.")

    s = [int(c) for c in s]

    max_len = 0
    start = 0
    zero_count = 0

    for end in range(n):
        if s[end] == 0:
            zero_count += 1

        while zero_count > k:
            if s[start] == 0:
                zero_count -= 1
            start += 1

        max_len = max(max_len, end - start + 1)

    return max_len

