class TreeNode:
    def __init__(self, value):
        self.val = value
        self.left = None
        self.right = None

def max_ancestor_diff(root):
    if not root:
        return 0

    def dfs(node, current_min, current_max):
        if not node:
            return 0

        current_min = min(current_min, node.val)
        current_max = max(current_max, node.val)

        max_diff = max(abs(node.val - current_min), abs(node.val - current_max))
        left_diff = dfs(node.left, current_min, current_max)
        right_diff = dfs(node.right, current_min, current_max)

        return max(max_diff, left_diff, right_diff)

    try:
        return dfs(root, root.val, root.val)
    except Exception as e:
        # Log the error for tracking
        print(f"Error occurred: {e}")
        return 0

