def find_closest_open_restaurant(n, s, closed_restaurants):
    if n <= 0 or s < 1 or s > n:
        raise ValueError("Invalid input: n must be positive and s must be within range [1, n].")

    closed_set = set(closed_restaurants)

    closest_distance = float('inf')

    for floor in range(1, n + 1):
        if floor not in closed_set:
            closest_distance = min(closest_distance, abs(floor - s))

    return closest_distance if closest_distance != float('inf') else -1  # return -1 if no open restaurant

