def knapsack(capacity, items):
    if capacity < 0:
        raise ValueError("Capacity must be non-negative.")
    if not items or any(size < 0 or value < 0 for size, value in items):
        raise ValueError("Items must have non-negative size and value.")

    try:
        value_to_size_ratios = [(value / size if size > 0 else 0, index) for index, (size, value) in enumerate(items)]
    except ZeroDivisionError:
        raise RuntimeError("Error calculating value-to-size ratios.")

    value_to_size_ratios.sort(reverse=True, key=lambda x: x[0])

    quantities = [0] * len(items)

    for ratio, index in value_to_size_ratios:
        size, value = items[index]
        while capacity >= size:
            quantities[index] += 1
            capacity -= size

    return quantities

