def unfair_helper(k, l):
    s = (sum(l) - k) / 2
    return s if s < 2e18 else -1

def unfair(A, B, C, K):
    if K < 0:
        raise ValueError("K must be non-negative.")
    if K % 3 == 0 or K >= 2e18:
        return 0

    if K == 0:
        return A - B

    res = unfair_helper(C, K // 3 * 2)

    while K:
        a1 = unfair_helper(res, K % 3)
        first = unfair_helper(B, K // 3 * 1)

        if a1 == -1 or first == -1:
            return "Unfair"

        res = unfair_helper(first, K // 3 * 2)
        K = K // 3 * 3

    return A - B + res * (K % 3)

