def calculate_advancers(n, k, scores):
    if n <= 0:
        raise ValueError("Number of scores must be greater than zero.")
    if len(scores) != n:
        raise ValueError("Scores list length must match the number of scores, n.")
    if not all(isinstance(score, int) for score in scores):
        raise TypeError("All scores must be integers.")

    passing_scores = sum(score >= k for score in scores)
    failing_scores = n - sum(1 for score in scores if score > k)

    if not scores:
        max_score_adjusted = 0
    else:
        max_score_adjusted = k - scores.count(max(scores))

    return passing_scores - failing_scores + max_score_adjusted

