    try:
        graph = [[] for _ in range(n + 1)]
        for u, v, c in edges:
            graph[u].append(v)
            graph[v].append(u)

        writing_integers = [None] * (n + 1)

        for i in range(1, n + 1):
            if all(c != writing_integers[j] for j in graph[i] for c in writing_integers if j < len(writing_integers)):
                for neighbor in graph[i]:
                    if writing_integers[neighbor] is None:
                        writing_integers[neighbor] = edges[(u, v)][2]
                        if all(c != writing_integers[j] for j in graph[neighbor] for c in writing_integers if j < len(writing_integers)):
