        self.validate_data()
        processed = [self._transform(item) for item in self.data]
        logger.info("Data processing completed.")
        return processed

    @staticmethod
    def _transform(value: Any) -> float:
        logger.debug(f"Transforming value: {value}")
        return float(value ** 2)

