def add(i, k):
    return i + k

def le(i, k):
    return max(0, i - k)

def process_queries(n):
    query = 0
    dk = 0

    for _ in range(n):
        user_input = input("Enter query (+ or - followed by a number): ")

        try:
            action, value = user_input.split()
            value = int(value)
            if action == '+':
                query = add(query, value)
            elif action == '-':
                query = le(query, value)
                if query == 0:
                    dk_adjustment = value - query
                    query = 0
                    dk = dk + dk_adjustment
                else:
                    dk = 0
            else:
                raise ValueError("Invalid action. Use '+' or '-'.")

        except ValueError as e:
            print(f"Error processing input: {e}. Please try again.")
        except Exception as e:
            print(f"An unexpected error occurred: {e}.")

    return query, dk

