def one_button(a, b):
    if not isinstance(a, (int, float)) or not isinstance(b, (int, float)):
        raise ValueError("Inputs must be numeric.")

    if a == b:
        return 0

    diff = abs(a - b)
    count = 0
    for i in range(5, 0, -1):
        count += diff // i
        diff %= i

    return count

