def compress_array(a):
    if len(a) < 2:
        print("Warning: Input array must have at least two elements.", file=sys.stderr)
        return []

    b = []
    queue = deque(a)

    while len(queue) > 1:
        try:
            discard1 = queue.popleft()
            discard2 = queue.popleft()
            queue.append(discard1 + discard2)
            gcd = find_gcd(b[-1] if b else 0, queue[0])
            b.append(gcd)
        except IndexError:
            print("Error: Index out of range during array compression.", file=sys.stderr)
            break
    return b

