def is_valid_brackets(string):
    stack = []
    brackets = {
        '(': ')',
        '[': ']',
        '{': '}'
    }

    for char in string:
        if char in brackets:
            stack.append(brackets[char])
        elif char in brackets.values():
            if not stack or char != stack.pop():
                return False

    return not stack

