def calculate_sum(combination):
    return sum(combination)

def find_max_even_sum(n, s):
    try:
        comb = combinations(range(0, n + 1), s)
        max_sum = -1
        for subset in comb:
            subset_sum = calculate_sum(subset)
            if subset_sum % 2 == 0 and subset_sum > max_sum:
                max_sum = subset_sum
        return max_sum if max_sum != -1 else 0  # Return 0 if no valid sum is found
    except Exception as e:
