def count_peaks(mountains):
    if not mountains or len(mountains) < 3:
        raise ValueError("Mountains list must contain at least three elements.")

    n = len(mountains)
    peaks = [0] * n

    for i in range(1, n - 1):
        if mountains[i] > mountains[i - 1] and mountains[i] > mountains[i + 1]:
            peaks[i] = 1

    return peaks

def max_peaks_and_min_starting_point(mountains, k):
    if not mountains or k < 1 or len(mountains) < k:
        raise ValueError("Mountains list must be non-empty and k must be a valid integer.")

    n = len(mountains)
    max_peaks = 0
    min_starting_point = -1

    for l in range(n - k + 1):
        peaks = count_peaks(mountains[l:l + k])
        current_peak_count = sum(peaks)

        if current_peak_count > max_peaks:
            max_peaks = current_peak_count
            min_starting_point = l

    if min_starting_point == -1:
        raise RuntimeError("No valid starting point found.")

    return max_peaks, min_starting_point

