class Solution:
    def minDifficulty(self, jobDifficulty: List[int], d: int) -> int:
        if not jobDifficulty or d > len(jobDifficulty):
            return -1

        if d == 1:
            return max(jobDifficulty)

        accum = [0] + jobDifficulty
        sums = [0] * (len(accum) + d - 1)

        for i in range(1, len(accum) + d - 2):
            prev_possible_day = max(0, i - d + 1)
            j = i + d - 1

            while prev_possible_day < j and sums[i - 1] == 0:
                prev_possible_day += 1

            while j >= 0 and sums[j + 1] == 0:
                j -= 1

            if j >= prev_possible_day:
                sums[i] = accum[j + 1] - accum[prev_possible_day]
            else:
                sums[i] = 0

        result = max(sums)
        return result if result > 0 else -1

