def perfect_numbers():
    yield from (9 * i for i in range(1, 10))  # yields 9, 18, ..., 81

    for x in range(90, 100):
        if _is_perfect(x):
            yield x

def _is_perfect(number):
    str_number = str(number)
    sums = [
        sum(int(str_number[i]) for i in range(start, 10, 3))
        for start in range(3)
    ]
    return all(s == 9 for s in sums)

