def decypher(password: str) -> str:
    """
    Decypher a password containing 2N numeric digits and return the decrypted value as a string.
    :param password: A string of numeric digits.
    :return: The decrypted value as a string.
    """

    if not isinstance(password, str) or not password.isdigit() or len(password) % 2 != 0:
        raise ValueError("Invalid password format. Expected an even-length string of numeric digits.")

    try:
        numbers = [int(digit) for digit in password]
    except ValueError as e:
        raise ValueError("Password should only contain numeric digits.") from e

    counter = numbers[0] if numbers[0] % 2 == 0 else numbers[0] - 1

    for _ in range(counter):
        end = numbers[-1] - numbers[0]
        numbers = numbers[1:-1] + [end]

    return ''.join(map(str, numbers))

def solve(n, r, b):
    if n <= 0 or r < 0 or b < 0:
        raise ValueError("Invalid input: n must be positive, r and b must be non-negative.")

    result = []
    p, q = divmod(r, b + 1)

    for i in range(b + 1):
        result.append('R' * (p + (1 if i < q else 0)))
        if i < b:
            result.append('B')

    return ''.join(result)

def main():
