from collections import deque

def read_input():
    n, m = map(int, input().split())
    grid = [input().strip() for _ in range(n)]
    x0, y0, x1, y1 = map(int, input().split())
    return n, m, grid, (x0 - 1, y0 - 1), (x1 - 1, y1 - 1)

def is_valid(x, y, n, m, grid, visited):
    return 0 <= x < n and 0 <= y < m and grid[x][y] == '.' and not visited[x][y]

def bfs(n, m, grid, start, goal):
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    visited = [[False] * m for _ in range(n)]
    queue = deque([(start, 0)])  # (current_position, current_distance)
    visited[start[0]][start[1]] = True

    while queue:
        (x, y), distance = queue.popleft()

        if (x, y) == goal:
            return distance

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if is_valid(nx, ny, n, m, grid, visited):
                visited[nx][ny] = True
                queue.append(((nx, ny), distance + 1))

    return -1

def main():
    try:
        n, m, grid, start, goal = read_input()
        if grid[start[0]][start[1]] != '.' or grid[goal[0]][goal[1]] != '.':
            print(-1)
            return

        result = bfs(n, m, grid, start, goal)
        print(result)
    except Exception as e:
        print("An error occurred:", str(e))

