class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

def arrange_c_and_v(head):
    if head is None:
        return None

    vowels = head
    consonants = head

    while vowels and vowels.next:
        if vowels.data.lower() in 'aeiou':
            vowels = vowels.next
        else:
            temp = vowels.next
            vowels.next = temp.next
            temp.next = consonants.next
            consonants.next = temp

    return head

def insert_node(linked_list, data):
    node = Node(data)
    if linked_list.head is None:
        linked_list.head = node
    else:
        current = linked_list.head
        while current.next:
            current = current.next
        current.next = node

def print_linked_list(head):
