import math
import logging

logging.basicConfig(level=logging.INFO)

def check_power(N: int) -> int:
    if not isinstance(N, int) or N <= 0:
        logging.error("Invalid input: N must be a positive integer.")
        raise ValueError("N must be a positive integer.")

    upper_limit = int(math.sqrt(N)) + 1
    for base in range(2, upper_limit):
        exponent = 2
        while True:
            power_value = base ** exponent
            if power_value == N:
                logging.info(f"Found power: {base}^{exponent} = {N}")
                return 1
            elif power_value > N:
                break
            exponent += 1

    logging.info("No powers found.")
    return 0

import re
import logging
from typing import List

logging.basicConfig(level=logging.INFO)

def censored(input_text: str, allowed_words: List[str]) -> str:

    if not isinstance(input_text, str) or not isinstance(allowed_words, list):
        logging.error("Invalid input: Expected string and list.")
        return ""

    allowed_words_set = {word.lower() for word in allowed_words}

    def replace_content(match):
        word = match.group(0).lower()
        if word not in allowed_words_set and len(word) > 2:
            return f"{word[0]}{'*' * (len(word) - 2)}{word[-1]}"
        return match.group(0)

    pattern = r'\b\w+\b'
    transformed_words = []

    for match in re.finditer(pattern, input_text):
        word_found = match.group(0)
        if match.start() > 0 and re.match(r'^[.,!?]', input_text[match.start() - 1]):
            transformed_words.append(word_found)
            continue

        censored_word = re.sub(re.escape(word_found.lower()), replace_content, word_found, flags=re.IGNORECASE)
        transformed_words.append(censored_word)

    final_output = ''.join(transformed_words)
    return final_output

