def max_candies(n: int, k: int) -> int:
    def binary_search(left: int, right: int) -> int:
        while left < right:
            mid = (left + right + 1) // 2
            if check(mid, k):
                left = mid
            else:
                right = mid - 1
        return left

    def check(mid: int, k: int) -> bool:
        low = 0
        high = mid
        children = 0
        while children < k:
            candies = min(mid, n)
            if candies < low:
                return False
            children += 1
            nonlocal n
            n -= candies
            if children > (k // 2) and mid - candies < low:
                return False
            high = max(high, candies)
            low += mid - candies
        return high - low <= 1

    return binary_search(0, n)

