import sys

def mod_pow(x, y, p):
    res = 1
    x %= p
    while y > 0:
        if y & 1:
            res = (res * x) % p
        y >>= 1
        x = (x * x) % p
    return res

def mod_inv(x, p):
    return mod_pow(x, p - 2, p)

def binom(n, k, mod):
    if k > n:
        return 0
    numerator = 1
    denominator = 1
    for i in range(k):
        numerator = (numerator * (n - i)) % mod
    for i in range(1, k + 1):
        denominator = (denominator * i) % mod
    return (numerator * mod_inv(denominator, mod)) % mod

def count_ways(n, k):
    if k > n:
        return 0
    total_ways = 0
    for i in range(k + 1):
        sign = (-1) ** (k - i)
        ways_to_choose_i = binom(n, i, MOD)
        ways_to_arrange_i = mod_pow(n - i, n, MOD)
        total_ways += sign * ways_to_choose_i * ways_to_arrange_i
        total_ways %= MOD
    return total_ways

def main():
    try:
        n, k = map(int, input().strip().split())
        if n < 0 or k < 0:
            raise ValueError("Input values must be non-negative.")
        result = count_ways(n, k)
