def restore_array(d):
    if not isinstance(d, list) or not all(isinstance(x, int) for x in d):
        raise ValueError("Input must be a list of integers.")

    n = len(d)
    if n == 0:
        raise ValueError("Input list must not be empty.")

    a = [0] * n
    a[0] = d[0]

    for i in range(1, n):
        a[i] = a[i - 1] + d[i]

    for i in range(1, n):
        if abs(a[i] - a[i - 1]) != d[i]:
