def convert_to_base_iterative(num, base):
    validate_base(base)
    digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
    stack = []
    while num:
        num, rem = divmod(num, base)
        stack.append(rem)
    return ''.join(reversed([digits[n] for n in stack]))

