class Solution:
    '''
    Time Complexity: O(N)
    Space Complexity: O(N)
    '''

    def stoneGame(self, piles: List[int]) -> bool:
        if not piles:
            raise ValueError("The piles list cannot be empty.")

        n = len(piles)
        memo: Dict[Tuple[int, int], int] = {}

        def helper(l: int, r: int) -> int:
            if l > r:
                return 0
            if (l, r) not in memo:
                if l == r:
                    memo[(l, r)] = piles[l]
                else:
                    memo[(l, r)] = max(piles[l] - helper(l + 1, r), 
                                       piles[r] - helper(l, r - 1))
            return memo[(l, r)]

        return helper(0, n - 1) > 0


