def max_gain(n, m, a):
    from functools import lru_cache
    import logging

    logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

    @lru_cache(None)
    def max_path(i, j, p, q):
        if (i, j) == (p, q):
            return max_path(i, j, i - 1, j)[0] + max_path(i, j, i, j - 1)[0], False

        if i <= 0 or j <= 0 or p > n or q > m:
            logging.warning(f'Out of bounds: {(i, j, p, q)}')
            return -float('inf'), False

        if i == 1 and j == 1:
            return a[1][1], False
        if p == n and q == 1:
            return a[n][1], False

        gain_i = max_path(i - 1, j, p, q)[0] + a[i][j] * (i != p or j != q)
        gain_j = max_path(i, j - 1, p, q)[0] + a[i][j] * (i != p or j != q)
        gain_p = max_path(i, j, p - 1, q)[0] + a[p][q] * (i != p or j != q)
        gain_q = max_path(i, j, p, q - 1)[0] + a[p][q] * (i != p or j != q)

        max_gain = max(gain_i, gain_j, gain_p, gain_q)
        return max_gain, (i, j) == (p, q)

    result = -float('inf')
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            result = max(result, max_path(n, m, i, j)[0])

    return result

