def find_two_elements(arr, n):
    if not isinstance(arr, list) or not all(isinstance(i, int) for i in arr) or not isinstance(n, int):
        raise ValueError("Invalid input: arr must be a list of integers and n must be an integer.")

    if n <= 0:
        raise ValueError("Invalid n: must be a positive integer.")

    try:
        seen_once, seen_twice = set(), set()
        for elem in arr:
            if elem < 1 or elem > n:
                raise ValueError(f"Element {elem} out of expected range (1 to {n}).")

            if elem in seen_once:
                seen_twice.add(elem)
                seen_once.discard(elem)
            else:
                seen_once.add(elem)

        missing_elements = set(range(1, n + 1)) - seen_once - seen_twice
        return list(seen_once) + list(missing_elements)

    except Exception as e:
        raise RuntimeError(f"An error occurred during processing: {str(e)}") from e

