class Palindrome:
    def palindrome_count(self, s):
        if not isinstance(s, list) or not all(isinstance(i, int) for i in s):
            raise ValueError("Input must be a list of integers.")

        n = len(s)
        ans = 0

        for i in range(n):
            temp = [n] * 26
            d2 = [0] * 26

            for j in range(i, n):
                x = ord(s[j]) - 97
                temp[x] = d2[temp[x]] + 1
                d2[x] = 0
                ans += temp[x]

        return ans

    def palindrome_substrs(self, input_str):
        if not isinstance(input_str, str):
            raise ValueError("Input must be a string.")

        s = "#" + "#".join(input_str) + "#"
        n = len(s)
        p = [0] * n
        arm_len = [0] * n
        center, right = 0, 0

        for i in range(1, n - 1):
            if right > i:
                p[i] = min(right - i, p[2 * center - i])

            while (i + 1 + p[i] < n and i - 1 - p[i] >= 0 and s[i + 1 + p[i]] == s[i - 1 - p[i]]):
                p[i] += 1

            if i + p[i] > right:
                center = i
                right = i + p[i]

        return self.palindrome_count(p)

