def sum_intervals(intervals):
    if not isinstance(intervals, list):
        raise TypeError('Input must be a list of intervals')

    total = 0
    current_end = -1
    verified_intervals = []

    for interval in intervals:
        if not isinstance(interval, (list, tuple)) or len(interval) != 2:
            raise ValueError('Each interval must be a list or tuple with exactly two elements')
        start, end = interval
        if not (isinstance(start, (int, float)) and isinstance(end, (int, float))):
            raise ValueError('Interval bounds must be numeric')
        if end < start:
            raise ValueError(f'Invalid interval: start {start} is greater than end {end}')

        verified_intervals.append((start, end))

    verified_intervals.sort()

    for start, end in verified_intervals:
        if start > current_end:
            total += end - start + 1
        elif end > current_end:
            total += end - current_end

        current_end = max(current_end, end)

    return total

