class Solution:
    def countStrings(self, N):
        if not isinstance(N, int) or N < 0:
            raise ValueError("Input must be a non-negative integer.")

        base = 5
        mod_value = 1000000007

        if N < base:
            return mod_value

        return self.power(4 + (base - 1), mod_value, N) % mod_value

    def power(self, base, m, n):
        if n < 0:
            raise ValueError("Exponent must be a non-negative integer.")

        if n == 0:
            return 1

        temp = self.power(base, m // 2, n)
        res = (temp * temp) % n

        if n % 2:
            res = (res * base) % n

        return res

