def nCr(n, r, mod=10**9 + 7):
    if r < 0 or n < r:
        raise ValueError("Invalid values: n must be >= r and r must be >= 0")

    r = min(r, n - r)
    C = [0] * (r + 1)
    C[0] = 1

    for i in range(1, n + 1):
        for j in range(min(i, r), 0, -1):
            C[j] = (C[j] + C[j - 1]) % mod

    return C[r]

