class SudokuPuzzle:
    @staticmethod
    def is_valid_grid(grid, row, col, size):
        try:
            for i in range(size):
                if grid[row][i] != 0 and grid[row][i] in [grid[j][col] for j in range(size) if j != row]:
                    return False

            for i in range(size):
                if grid[i][col] != 0 and grid[i][col] in [grid[row][j] for j in range(size) if j != col]:
                    return False

            return True
        except IndexError as e:
            logging.error("IndexError in is_valid_grid: %s", e)
            return False

    @staticmethod
    def backtrack(grid, size, n, items, removed_digits):
        try:
            if n == len(items):
                return True

            index = items[n]
            if removed_digits[index]:
                for i in range(size):
                    if grid[n // size][i] == index + 1:
                        if SudokuPuzzle.backtrack(grid, size, n + 1, items, removed_digits):
                            return True
                        removed_digits[index] = False
                        break
                return False

            possibilities = [d for d in (d for d in removed_digits if d) 
                             if d not in set(item[1] for item in items[:n])]
            if not possibilities and removed_digits[index] and SudokuPuzzle.is_valid_grid(grid, n // size, index, size):
                return True

            for number in possibilities:
                grid[n // size][index] = number
                removed_digits[index] = True
                if SudokuPuzzle.backtrack(grid, size, n + 1, items, removed_digits):
                    return True
                grid[n // size][index] = 0  # Reset on backtrack
                removed_digits[index] = False

            return False
        except Exception as e:
            logging.error("Error in backtrack: %s", e)
            return False

    @staticmethod
    def solve_sudoku(grid):
        size = len(grid)
        items = [i for i in range(size)]
        removed_digits = [True] * size

        if SudokuPuzzle.backtrack(grid, size, 0, items, removed_digits):
            logging.info("Sudoku solved successfully.")
            return grid
        else:
            logging.warning("Failed to solve Sudoku.")
            return None

