import java.util.*;

public class PermutationHammingDistance {

    public int calculate(int[] source, int[] target, List<List<Integer>> allowedSwaps) {
        if (source == null || target == null || allowedSwaps == null) {
            throw new IllegalArgumentException("Input arrays and allowed swaps cannot be null.");
        }

        if (source.length != target.length) {
            throw new IllegalArgumentException("Source and target arrays must have the same length.");
        }

        int n = source.length;
        Set<Integer> visited = new HashSet<>();
        Map<Integer, List<Integer>> adjacencyList = new HashMap<>();

        for (List<Integer> swap : allowedSwaps) {
            adjacencyList.computeIfAbsent(swap.get(0), k -> new ArrayList<>()).add(swap.get(1));
            adjacencyList.computeIfAbsent(swap.get(1), k -> new ArrayList<>()).add(swap.get(0));
        }

        int hammingDistance = 0;

        for (int i = 0; i < n; i++) {
            if (source[i] != target[i]) {
                hammingDistance++;
                if (!canSwap(source[i], target[i], adjacencyList, visited)) {
                    return -1; // Swap not possible
                }
            }
        }

        return hammingDistance;
    }

    private boolean canSwap(int sourceValue, int targetValue, Map<Integer, List<Integer>> adjacencyList, Set<Integer> visited) {
        if (sourceValue == targetValue) {
            return true;
        }
        if (visited.contains(sourceValue)) {
            return false;
        }
        visited.add(sourceValue);

        List<Integer> neighbors = adjacencyList.getOrDefault(sourceValue, Collections.emptyList());
        for (Integer neighbor : neighbors) {
            if (canSwap(neighbor, targetValue, adjacencyList, visited)) {
                return true;
            }
        }

        return false;
    }
}

