import java.util.Arrays;

public class MaxSumWithOneDeletion {
    public int maximumSum(int[] arr) {
        if (arr == null) {
            throw new IllegalArgumentException("Input array cannot be null.");
        }
        if (arr.length == 0) {
            System.err.println("Warning: Input array is empty. Returning 0.");
            return 0;
        }
        if (arr.length == 1) {
            return arr[0];
        }

        int n = arr.length;
        int[] maxEndHereWithDeletion = new int[n];
        int[] maxEndHereWithoutDeletion = new int[n];

        maxEndHereWithDeletion[0] = 0;
        maxEndHereWithoutDeletion[0] = arr[0];

        int maxSum = arr[0];

        for (int i = 1; i < n; i++) {
            maxEndHereWithoutDeletion[i] = Math.max(arr[i], maxEndHereWithoutDeletion[i - 1] + arr[i]);
            maxEndHereWithDeletion[i] = Math.max(maxEndHereWithoutDeletion[i - 1], maxEndHereWithDeletion[i - 1] + arr[i]);
            maxSum = Math.max(maxSum, Math.max(maxEndHereWithoutDeletion[i], maxEndHereWithDeletion[i]));
        }

        return maxSum;
    }

    public static void main(String[] args) {
        MaxSumWithOneDeletion solver = new MaxSumWithOneDeletion();
        int[][] testCases = {
            {1, -2, 0, 3},
            {1, -2, -2, 3},
            {-1, -1, -1, -1}
        };

        for (int[] testCase : testCases) {
            try {
                System.out.println("Maximum sum for " + Arrays.toString(testCase) + ": " + solver.maximumSum(testCase));
            } catch (IllegalArgumentException e) {
                System.err.println("Error: " + e.getMessage());
            }
        }
    }
}

