public class JumpGame {
    public boolean canReach(String s, int minJump, int maxJump) {
        if (s.charAt(s.length() - 1) != '0') {
            return false;
        }

        int length = s.length();
        boolean[] dp = new boolean[length];
        dp[0] = true;

        int windowSum = 0;
        int left = 0;

        for (int right = 1; right < length; right++) {
            windowSum += dp[right - 1];

            if (right - left > maxJump) {
                windowSum -= dp[left];
                left++;
            }

            if (windowSum > 0 && s.charAt(right) == '0') {
                dp[right] = true;
            }
        }

        return dp[length - 1];
    }

    public static void main(String[] args) {
        JumpGame jumpGame = new JumpGame();
        String testString = "011010";
        int minJump = 2;
        int maxJump = 3;

        boolean result = jumpGame.canReach(testString, minJump, maxJump);
        System.out.println("Can reach end: " + result);
    }
}

