public class GraphNodeValueAssignment {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = readTestCases(scanner);

            for (int t = 0; t < testCases; t++) {
                processTestCase(scanner);
            }
        } catch (Exception e) {
            System.err.println("Error during input processing: " + e.getMessage());
        }
    }

    private static int readTestCases(Scanner scanner) {
        if (scanner.hasNextInt()) {
            return scanner.nextInt();
        }
        throw new InputMismatchException("Expected number of test cases.");
    }

    private static void processTestCase(Scanner scanner) {
        int n = readNodeCount(scanner);
        int m = readEdgeCount(scanner);
        int[] values = readValues(scanner, n);
        int[] targets = readValues(scanner, n);
        List<List<Edge>> adjacencyList = buildAdjacencyList(scanner, n, m);

        boolean isPossible = checkValuesCanMeetTargets(adjacencyList, values, targets);
        System.out.println(isPossible ? "YES" : "NO");
    }

    private static int readNodeCount(Scanner scanner) {
        if (scanner.hasNextInt()) {
            int n = scanner.nextInt();
            if (n >= 2 && n <= 200000) return n;
            throw new IllegalArgumentException("Invalid node count: " + n);
        }
        throw new InputMismatchException("Expected node count.");
    }

    private static int readEdgeCount(Scanner scanner) {
        if (scanner.hasNextInt()) {
            int m = scanner.nextInt();
            if (m >= 1) return m; // Adjust as per constraints
            throw new IllegalArgumentException("Invalid edge count: " + m);
        }
        throw new InputMismatchException("Expected edge count.");
    }

    private static int[] readValues(Scanner scanner, int n) {
        int[] values = new int[n];
        for (int i = 0; i < n; i++) {
            if (scanner.hasNextInt()) {
                values[i] = scanner.nextInt();
            } else {
                throw new InputMismatchException("Expected integer values.");
            }
        }
        return values;
    }

    private static List<List<Edge>> buildAdjacencyList(Scanner scanner, int n, int m) {
        List<List<Edge>> adjacencyList = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            adjacencyList.add(new ArrayList<>());
        }
        for (int i = 0; i < m; i++) {
            addEdge(scanner, adjacencyList);
        }
        return adjacencyList;
    }

    private static void addEdge(Scanner scanner, List<List<Edge>> adjacencyList) {
        int u = scanner.nextInt() - 1;
        int v = scanner.nextInt() - 1;
        adjacencyList.get(u).add(new Edge(v));
        adjacencyList.get(v).add(new Edge(u));
    }

    private static boolean checkValuesCanMeetTargets(List<List<Edge>> adjacencyList, int[] values, int[] targets) {
        int n = values.length;
        boolean[] visited = new boolean[n];
        Arrays.fill(visited, false);

        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                if (!traverseAndCheck(adjacencyList, values, targets, visited, i)) {
                    return false;
                }
            }
        }
        return true;
    }

    private static boolean traverseAndCheck(List<List<Edge>> adjacencyList, int[] values, int[] targets, boolean[] visited, int startNode) {
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(startNode);
        visited[startNode] = true;

        int sumValues = 0;
        int sumTargets = 0;

        while (!queue.isEmpty()) {
            int node = queue.poll();
            sumValues += values[node];
            sumTargets += targets[node];

            for (Edge neighbor : adjacencyList.get(node)) {
                if (!visited[neighbor.target]) {
                    visited[neighbor.target] = true;
                    queue.offer(neighbor.target);
                }
            }
        }

        return sumValues == sumTargets;
    }

    private static class Edge {
        int target;

        Edge(int target) {
            this.target = target;
        }
    }
}

class Solution {
    public boolean validateBinaryTreeNodes(int n, int[] leftChild, int[] rightChild) {
        if (n <= 0 || leftChild == null || rightChild == null || leftChild.length != n || rightChild.length != n) {
            System.err.println("Invalid input: check node count and child arrays.");
            return false;
        }

        int[] parent = new int[n];
        Arrays.fill(parent, -1);

        for (int i = 0; i < n; i++) {
            if (leftChild[i] != -1) {
                if (isInvalidChild(leftChild[i], parent)) return false;
                parent[leftChild[i]] = i;
            }
            if (rightChild[i] != -1) {
                if (isInvalidChild(rightChild[i], parent)) return false;
                parent[rightChild[i]] = i;
            }
        }

        int rootCount = 0;
        int rootIndex = -1;
        for (int i = 0; i < n; i++) {
            if (parent[i] == -1) {
                rootCount++;
                rootIndex = i;
            }
        }

        if (rootCount != 1) {
            return false;
        }

        return isTreeValid(n, leftChild, rightChild, rootIndex);
    }

    private boolean isInvalidChild(int child, int[] parent) {
        if (child < 0 || child >= parent.length) {
            System.err.println("Invalid child index: " + child);
            return true;
        }
        return parent[child] != -1;
    }

    private boolean isTreeValid(int n, int[] leftChild, int[] rightChild, int root) {
        boolean[] visited = new boolean[n];
        int count = 0;
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(root);
        visited[root] = true;

        while (!queue.isEmpty()) {
            int node = queue.poll();
            count++;
            if (visitChild(node, leftChild[node], visited, queue) ||
                visitChild(node, rightChild[node], visited, queue)) {
                return false;
            }
        }

        return count == n;
    }

    private boolean visitChild(int parentNode, int childNode, boolean[] visited, Queue<Integer> queue) {
        if (childNode != -1) {
            if (visited[childNode]) {
                System.err.println("Cycle detected or duplicate child: " + childNode);
                return true;
            }
            queue.offer(childNode);
            visited[childNode] = true;
        }
        return false;
    }
}

