class Solution {
    public int minChanges(int[] nums, int k) {
        if (nums == null || nums.length == 0 || k <= 0) {
            throw new IllegalArgumentException("Input array must not be null or empty and k must be positive.");
        }

        int n = nums.length;
        int[][] changes = new int[k][1025];

        for (int i = 0; i < k; i++) {
            for (int j = 0; j < 1025; j++) {
                changes[i][j] = Integer.MAX_VALUE;
            }
        }

        for (int i = 0; i < n; i++) {
            int currentNum = nums[i];
            for (int j = i % k; j >= 0; j--) {
                for (int x = 0; x < 1025; x++) {
                    if (changes[j][x] == Integer.MAX_VALUE) continue;
                    changes[(j + 1) % k][currentNum] = Math.min(changes[(j + 1) % k][currentNum], changes[j][x] + (x == currentNum ? 0 : 1));
                }
            }
            changes[i % k][currentNum] = Math.min(changes[i % k][currentNum], 1);
        }

        int result = Integer.MAX_VALUE;
        for (int i = 0; i < 1025; i++) {
            result = Math.min(result, changes[(n - 1) % k][i]);
        }

        return result == Integer.MAX_VALUE ? -1 : result;
    }
}

