public class BeautifulIntegers {
    private static final String ERROR_MESSAGE = "Invalid input parameters.";

    public static int countBeautifulIntegers(int low, int high, int k) {
        validateInput(low, high, k);
        return countBeautifulInRange(high, k) - countBeautifulInRange(low - 1, k);
    }

    private static int countBeautifulInRange(int num, int k) {
        String s = Integer.toString(num);
        int n = s.length();
        int[][][][] dp = initializeDP(n, k);
        return dfs(0, 0, 0, 0, true, s, dp, k);
    }

    private static int[][][][] initializeDP(int n, int k) {
        int[][][][] dp = new int[n][2][n + 1][k];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 2; j++) {
                for (int l = 0; l <= n; l++) {
                    for (int m = 0; m < k; m++) {
                        dp[i][j][l][m] = -1;
                    }
                }
            }
        }
        return dp;
    }

    private static int dfs(int idx, int remainder, int balance, int len, boolean isLimit, String s, int[][][][] dp, int k) {
        if (idx == s.length()) {
            return (len > 0 && balance == 0 && remainder == 0) ? 1 : 0;
        }
        if (dp[idx][isLimit ? 1 : 0][balance + s.length()][remainder] != -1) {
            return dp[idx][isLimit ? 1 : 0][balance + s.length()][remainder];
        }
        int res = 0;
        int limit = isLimit ? s.charAt(idx) - '0' : 9;
        for (int d = 0; d <= limit; d++) {
            int newBalance = balance + (d % 2 == 0 ? 1 : -1);
            res += dfs(idx + 1, (remainder * 10 + d) % k, newBalance, len + (d > 0 ? 1 : 0), isLimit && d == limit, s, dp, k);
        }
        dp[idx][isLimit ? 1 : 0][balance + s.length()][remainder] = res;
        return res;
    }

    private static void validateInput(int low, int high, int k) {
        if (low < 0 || high < 0 || k <= 0 || low > high) {
            throw new IllegalArgumentException(ERROR_MESSAGE);
        }
    }

    public static void main(String[] args) {
        try {
            System.out.println(countBeautifulIntegers(10, 20, 3));
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

