import java.util.Arrays;

class Solution {
    public int reductionOperations(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array must not be null or empty.");
        }

        Arrays.sort(nums);
        int totalOperations = 0, distinctCount = 0;

        for (int i = 1; i < nums.length; ++i) {
            if (nums[i] != nums[i - 1]) {
                distinctCount++;
            }
            totalOperations += distinctCount;
        }

        return totalOperations;
    }
}

public class Solution {
    public int minSwaps(String s) {
        if (s == null || s.isEmpty()) {
            throw new IllegalArgumentException("Input string is null or empty");
        }

        int n = s.length();
        int blackCount = 0;

        for (char c : s.toCharArray()) {
            if (c != '0' && c != '1') {
                throw new IllegalArgumentException("Input string contains invalid characters. Only '0' and '1' are allowed.");
            }
            if (c == '1') {
                blackCount++;
            }
        }

        if (blackCount == 0) {
            return 0;
        }

        int swaps = 0;
        int windowCount = 0;

        for (int i = 0; i < n; i++) {
            if (i < blackCount) {
                windowCount += (s.charAt(i) == '1') ? 1 : 0;
            } else {
                windowCount += (s.charAt(i) == '1') ? 1 : 0;
                windowCount -= (s.charAt(i - blackCount) == '1') ? 1 : 0;
            }
        }

        swaps = blackCount - windowCount;
        return swaps > 0 ? swaps : 0;
    }
}

