import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Scanner;

public class Main {
    static class Node {
        List<Integer> adjacencyList;
        boolean visited;
        int topicNumber;

        Node(int topicNumber) {
            this.adjacencyList = new ArrayList<>();
            this.visited = false;
            this.topicNumber = topicNumber;
        }
    }

    static Node[] nodes;

    static void bfs(int vertex, List<Integer> result) {
        nodes[vertex].visited = true;
        Node current = nodes[vertex];
        List<Integer> indecies = new ArrayList<>();

        for (int i = 0; i < current.adjacencyList.size(); i++) {
            indecies.add(i);
        }

        while (!indecies.isEmpty()) {
            int minTopicIndex = -1;
            for (int i : indecies) {
                if (minTopicIndex == -1 || 
                    current.adjacencyList.get(i) < nodes[current.adjacencyList.get(minTopicIndex)].topicNumber) {
                    minTopicIndex = i;
                }
            }

            if (minTopicIndex == -1) break; // Safety check
            indecies.remove(minTopicIndex);
            result.add(current.adjacencyList.get(minTopicIndex));
            current = nodes[current.adjacencyList.get(minTopicIndex)];
            current.visited = true; // Mark as visited
        }
    }

    static List<Integer> solve() {
        List<Integer> result = new ArrayList<>();
        for (int i = 1; i < nodes.length; i++) {
            if (!nodes[i].visited) {
                bfs(i, result);
            }
        }

        for (int i = 1; i < nodes.length; i++) {
            if (!result.contains(i)) {
                result.add(i);
            }
        }
        return result;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        int m = scanner.nextInt();
        nodes = new Node[n + 1];

        for (int i = 1; i <= n; i++) {
            nodes[i] = new Node(scanner.nextInt());
        }

        for (int i = 0; i < m; i++) {
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            nodes[a].adjacencyList.add(b);
            nodes[b].adjacencyList.add(a);
        }

        List<Integer> topics = new ArrayList<>();
        for (int i = 1; i <= n; i++) {
            topics.add(nodes[i].topicNumber);
        }

        topics.sort(Integer::compareTo);
        List<Integer> result = solve();

        for (int topic : result) {
            System.out.print(topic + " ");
        }
    }
}

