import java.util.ArrayList;
import java.util.List;

public class GraphReversals {

    private List<ArrayList<Integer>> graph;

    public GraphReversals() {
        graph = new ArrayList<>();
    }

    public int calculateReversals(int node, int lastVisited) {
        if (node < 0 || node >= graph.size()) {
            throw new IllegalArgumentException("Node index out of bounds: " + node);
        }
        if (graph.get(node).isEmpty()) return 0;

        int reversals = 0;
        for (int nextNode : graph.get(node)) {
            if (nextNode != lastVisited) {
                reversals += calculateReversals(nextNode, node);
                reversals++;
            }
        }
        return reversals;
    }

    public List<Integer> getMinRevertPath(int n, int[][] edges) {
        if (n <= 0 || edges == null) {
            throw new IllegalArgumentException("Invalid input: n should be > 0 and edges cannot be null.");
        }

        initializeGraph(n, edges);
        List<Integer> reversals = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            int reversalsNeeded = calculateReversals(i, -1);
            reversals.add(reversalsNeeded);
        }

        return reversals;
    }

    private void initializeGraph(int n, int[][] edges) {
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            if (edge.length != 2) {
                throw new IllegalArgumentException("Edge must contain exactly two nodes.");
            }
            int from = edge[0], to = edge[1];
            if (from < 0 || from >= n || to < 0 || to >= n) {
                throw new IllegalArgumentException("Node indices must be within the range [0, " + (n - 1) + "]: " + from + ", " + to);
            }
            graph.get(from).add(to);
        }
    }
}

