public class GenerationCalculator {
    private static final int MAX_Y = 256; // Cap for the y array size
    private static final String ERROR_MESSAGE = "Invalid input. Please enter valid integers.";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int testCases = 0;

        try {
            System.out.print("Enter number of test cases: ");
            testCases = Integer.parseInt(scanner.nextLine().trim());
            if (testCases <= 0) {
                throw new NumberFormatException();
            }

            for (int i = 0; i < testCases; i++) {
                System.out.print("Enter values for n and k: ");
                String[] input = scanner.nextLine().split(" ");
                if (input.length != 2) {
                    throw new IllegalArgumentException(ERROR_MESSAGE);
                }

                int n = Integer.parseInt(input[0]);
                int k = Integer.parseInt(input[1]);

                if (n <= 0 || k < 0) {
                    System.out.println(ERROR_MESSAGE);
                    continue;
                }

                int[] x = new int[n];
                int[] y = new int[1 << k]; // 2^k
                int summ = 0;
                x[0] = 1;

                if (n == 1) {
                    System.out.println(summ == 0 ? 1 : 2);
                } else {
                    int count = 0;
                    int t = 1;

                    for (int j = 0; j < n - 1; j++) {
                        t *= 2;
                        int ytab = t;
                        x[ytab] = 1;
                        y[j & 0xFFFF] = 1;

                        summ = j < n - 1
                                ? calculateSum(x, y, (1 << k))
                                : y[j * ytab];

                        count += (summ == 0) ? 1 : Math.max(summ, 1);
                    }
                    System.out.println(count);
                }
            }
        } catch (NumberFormatException | IllegalArgumentException e) {
            System.err.println(ERROR_MESSAGE);
        } finally {
            scanner.close();
        }
    }

    private static int calculateSum(int[] x, int[] y, int limit) {
        int sum = 0;
        for (int i = 0; i < limit; i++) {
            if (i < x.length) {
                sum += x[y[i]];
            }
        }
        return sum;
    }
}

