import java.util.ArrayList;
import java.util.List;

public class TicketCostCalculator {

    public int mincostTickets(int[][] costs, int n) {
        if (costs == null || costs.length == 0 || n <= 0) {
            throw new IllegalArgumentException("Invalid costs or destination.");
        }

        List<Integer> minCosts = new ArrayList<>();
        int minCost = Integer.MAX_VALUE;

        for (int i = 0; i < n; i++) {
            minCosts.add(Integer.MAX_VALUE);
        }

        for (int day = 1; day <= n; day++) {
            int costForCurrentDay = costs[day - 1][0];
            if (day <= 3) {
                minCosts.set(day - 1, Math.min(minCosts.get(day - 1), costForCurrentDay + getPreviousCosts(day, minCosts)));
            } else {
                minCosts.set(day - 1, getPreviousCosts(day, minCosts));
            }

            minCost = Math.min(minCost, minCosts.get(day - 1));
        }

        return minCost;
    }

    private int getPreviousCosts(int day, List<Integer> minCosts) {
        int cost = 0;
        for (int i = 0; i < day; i++) {
            cost += minCosts.get(i);
        }
        return cost;
    }

    private int calculateCost(int size, List<Integer> Ai, List<Integer> Ai2, List<Integer> Ai3) {
        int totalCost = 0;

        for (int i = 0; i < Ai.size(); i++) {
            totalCost += Ai.get(Ai.size() - 1 - i) * (Ai.size() - i);
        }

        if (size % 2 == 0) {
            for (int i = 0; i < Ai2.size(); i++) {
                totalCost += Ai2.get(Ai2.size() - 1 - i) * (Ai2.size() - i);
                totalCost += Ai3.get(Ai3.size() - 1 - i) * (Ai3.size() - i);
            }
        } else {
            for (int i = 0; i < Ai2.size(); i++) {
                totalCost += Ai2.get(Ai2.size() - 1 - i) * (Ai2.size() - i);
            }
        }

        return totalCost;
    }
}

