class TreeNode {
    int value;
    TreeNode left;
    TreeNode right;

    TreeNode(int value) {
        this.value = value;
        left = right = null;
    }
}

public class BinaryTreeTraversal {

    public int maxSum(TreeNode root) {
        if (root == null) {
            System.err.println("Error: Root is null.");
            return 0;
        }
        return maxSumAtLevel(root, 0, new LinkedList<>());
    }

    private int maxSumAtLevel(TreeNode node, int level, LinkedList<Integer> levelSums) {
        if (node == null) {
            return 0;
        }

        if (level == levelSums.size()) {
            levelSums.add(0);
        }

        levelSums.set(level, levelSums.get(level) + node.value);

        maxSumAtLevel(node.left, level + 1, levelSums);
        maxSumAtLevel(node.right, level + 1, levelSums);

        return levelSums.stream().mapToInt(Integer::intValue).max().orElse(0);
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode(1);
        root.left = new TreeNode(2);
        root.right = new TreeNode(3);
        root.left.left = new TreeNode(4);
        root.left.right = new TreeNode(5);

        BinaryTreeTraversal traversal = new BinaryTreeTraversal();
        int result = traversal.maxSum(root);
        System.out.println("Maximum sum at any level: " + result);
    }
}

import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class DoubleSort {
    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = readPositiveInteger(scanner, "number of test cases");
            while (testCases-- > 0) {
                int arraySize = readPositiveInteger(scanner, "array size");
                int[] firstArray = readArray(scanner, arraySize);
                int[] secondArray = readArray(scanner, arraySize);
                List<String> moves = sortAndTrackMoves(firstArray, secondArray);
                printResults(moves);
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static int readPositiveInteger(Scanner scanner, String prompt) {
        int value;
        System.out.print("Enter " + prompt + ": ");
        while (true) {
            if (scanner.hasNextInt()) {
                value = scanner.nextInt();
                if (value > 0) {
                    return value;
                }
            } else {
                scanner.next(); // Clear invalid input
            }
            System.out.print("Invalid input. Please enter a positive integer for " + prompt + ": ");
        }
    }

    private static int[] readArray(Scanner scanner, int size) {
        int[] array = new int[size];
        for (int i = 0; i < size; i++) {
            array[i] = readInteger(scanner, "array element " + (i + 1));
        }
        return array;
    }

    private static int readInteger(Scanner scanner, String prompt) {
        int value;
        System.out.print("Enter " + prompt + ": ");
        while (true) {
            if (scanner.hasNextInt()) {
                return scanner.nextInt();
            } else {
                scanner.next(); // Clear invalid input
            }
            System.out.print("Invalid input. Please enter an integer for " + prompt + ": ");
        }
    }

    private static List<String> sortAndTrackMoves(int[] a, int[] b) {
        List<String> moves = new ArrayList<>();
        int n = a.length;
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                if (shouldSwap(a, b, j)) {
                    swap(a, j, b, j);
                    moves.add((j + 1) + " " + (j + 2));
                }
            }
        }
        return moves;
    }

    private static boolean shouldSwap(int[] a, int[] b, int j) {
        return a[j] > a[j + 1] || (a[j] == a[j + 1] && b[j] > b[j + 1]);
    }

    private static void swap(int[] a, int j, int[] b, int k) {
        int tempA = a[j];
        a[j] = a[k];
        a[k] = tempA;
        int tempB = b[j];
        b[j] = b[k];
        b[k] = tempB;
    }

    private static void printResults(List<String> moves) {
        if (moves.isEmpty()) {
            System.out.println(-1);
        } else {
            System.out.println(moves.size());
            moves.forEach(System.out::println);
        }
    }
}

import java.util.Scanner;
import java.util.TreeMap;

public class Main {
    private static final String ERROR_MESSAGE = "Invalid input. Please enter positive integers.";

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = readPositiveInteger(scanner);
            for (int i = 0; i < testCases; i++) {
                int n = readPositiveInteger(scanner);
                int m = readPositiveInteger(scanner);
                TreeMap<Integer, Integer> countMap = new TreeMap<>();

                for (int j = 0; j < n; j++) {
                    int a = readPositiveInteger(scanner);
                    countMap.put(a, countMap.getOrDefault(a, 0) + 1);
                }

                int minBalance = calculateMinBalance(countMap);
                System.out.println(minBalance);
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static int readPositiveInteger(Scanner scanner) {
        int value;
        while (true) {
            try {
                value = scanner.nextInt();
                if (value > 0) {
                    return value;
                } else {
                    System.err.println(ERROR_MESSAGE);
                }
            } catch (InputMismatchException e) {
                scanner.next(); // Clear invalid input
                System.err.println(ERROR_MESSAGE);
            }
        }
    }

    private static int calculateMinBalance(TreeMap<Integer, Integer> countMap) {
        while (true) {
            Map.Entry<Integer, Integer> lastEntry = countMap.lastEntry();
            int maxVal = lastEntry.getKey();
            int maxCount = lastEntry.getValue();
            int minVal = countMap.firstKey();

            if (maxVal == minVal) return 0;

            int newMinVal = computeNewMinVal(maxVal);
            if (newMinVal == maxVal) return maxVal - minVal;

            updateCountMap(countMap, maxVal, maxCount, newMinVal);
        }
    }

    private static int computeNewMinVal(int maxVal) {
        int newMinVal = maxVal;
        for (int p = 2; p * p <= maxVal; p++) {
            if (maxVal % p == 0) {
                int q = maxVal / p;
                newMinVal = Math.min(newMinVal, Math.max(p, q));
            }
        }
        return newMinVal;
    }

    private static void updateCountMap(TreeMap<Integer, Integer> countMap, int maxVal, int maxCount, int newMinVal) {
        countMap.put(maxVal, maxCount - 1);
        if (maxCount == 1) countMap.remove(maxVal);
        countMap.put(newMinVal, countMap.getOrDefault(newMinVal, 0) + 1);
    }
}

import java.io.*;
import java.math.BigInteger;

public class Main {
    public static void main(String[] args) {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
             BufferedWriter writer = new BufferedWriter(new OutputStreamWriter(System.out))) {

            int testCaseCount = Integer.parseInt(reader.readLine().trim());
            for (int i = 0; i < testCaseCount; i++) {
                BigInteger n = new BigInteger(reader.readLine().trim());
                BigInteger result = findGcdSum(n);
                writer.write(result.toString());
                writer.newLine();
            }
            writer.flush();
        } catch (IOException | NumberFormatException e) {
            System.err.println("Error processing input: " + e.getMessage());
        }
    }

    private static BigInteger findGcdSum(BigInteger n) {
        BigInteger sumOfDigits = calculateSumOfDigits(n);
        BigInteger candidate = n.add(BigInteger.ONE);
        while (true) {
            if (candidate.gcd(sumOfDigits).compareTo(BigInteger.ONE) > 0) {
                return candidate;
            }
            candidate = candidate.add(BigInteger.ONE);
        }
    }

    private static BigInteger calculateSumOfDigits(BigInteger n) {
        BigInteger sum = BigInteger.ZERO;
        while (n.compareTo(BigInteger.ZERO) > 0) {
            sum = sum.add(n.mod(BigInteger.TEN));
            n = n.divide(BigInteger.TEN);
        }
        return sum;
    }
}

import java.util.Collections;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;

public class Solution {

    public String[][] mostPopularCreatorPlusVideos(String[] creators, String[] ids, int[] views) {
        if (creators == null || ids == null || views == null || creators.length != ids.length || creators.length != views.length) {
            throw new IllegalArgumentException("Input arrays must not be null and must have the same length.");
        }

        Map<String, Map<String, Integer>> creatorVideoViewMap = new HashMap<>();

        for (int i = 0; i < creators.length; i++) {
            String creator = creators[i];
            String videoId = ids[i];
            int viewCount = views[i];

            creatorVideoViewMap
                .computeIfAbsent(creator, k -> new HashMap<>())
                .merge(videoId, viewCount, Integer::sum);
        }

        Map<String, List<String>> orderedCreatorVideoMap = creatorVideoViewMap.entrySet().stream()
            .sorted(Map.Entry.<String, Map<String, Integer>>comparingByValue(
                Comparator.comparingInt(o -> o.values().stream().mapToInt(Integer::intValue).sum()).reversed())
                .thenComparing(Map.Entry.comparingByKey()))
            .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue,
                (e1, e2) -> e1, LinkedHashMap::new));

        return createResponse(orderedCreatorVideoMap);
    }

    private String[][] createResponse(Map<String, List<String>> orderedMap) {
        String[][] response = new String[orderedMap.size()][2];
        int index = 0;

        for (Map.Entry<String, List<String>> entry : orderedMap.entrySet()) {
            String creator = entry.getKey();
            List<String> videos = entry.getValue().stream()
                .sorted(Comparator.comparingInt(viewCount -> -viewCount)) // assume we need to sort video IDs by views
                .collect(Collectors.toList());
            response[index][0] = creator;
            response[index][1] = String.join(",", videos);
            index++;
        }

        return response;
    }
}

