    private static int calculateMaxMex(String s1, String s2, int n) {
        int maxSum = 0;
        int currentSum = 0;
        boolean hasZero = false;
        boolean hasOne = false;

        for (int j = 0; j < n; j++) {
            updateFlags(s1.charAt(j), s2.charAt(j), hasZero, hasOne);

            if (s1.charAt(j) != s2.charAt(j)) {
                currentSum = updateCurrentSum(hasZero, hasOne, currentSum);
                maxSum += currentSum;
                currentSum = 0;
                hasZero = false;
                hasOne = false;
            }
        }

        currentSum = updateCurrentSum(hasZero, hasOne, currentSum);
        maxSum += currentSum;
        return maxSum;
    }

    private static void updateFlags(char char1, char char2, boolean hasZero, boolean hasOne) {
        hasZero |= (char1 == '0' || char2 == '0');
        hasOne |= (char1 == '1' || char2 == '1');
    }

    private static int updateCurrentSum(boolean hasZero, boolean hasOne, int currentSum) {
        if (hasZero && hasOne) {
            return currentSum + 2;
        } else if (hasZero || hasOne) {
            return currentSum + 1;
        }
        return currentSum;
    }
}

public class AlternatingSignSum {

    public static int findSumOfAlternatingSigns(int n) {
        String numStr = String.valueOf(n);
        int total = 0;
        int sign = 1;

        try {
            for (char digit : numStr.toCharArray()) {
                if (Character.isDigit(digit)) {
                    total += sign * Character.getNumericValue(digit);
                    sign *= -1;
                } else {
                    throw new IllegalArgumentException("Input contains non-digit characters.");
                }
            }
        } catch (Exception e) {
            System.err.println("Error processing input: " + e.getMessage());
        }

        return total;
    }

    public static void main(String[] args) {
        System.out.println(findSumOfAlternatingSigns(521));      // Output: 4
        System.out.println(findSumOfAlternatingSigns(111));      // Output: 1
        System.out.println(findSumOfAlternatingSigns(886996));   // Output: 0
    }
}

