import java.util.ArrayList;
import java.util.List;

public class ProductionCode {

    private static final int N = 505;
    private static List<Integer> primes = new ArrayList<>();
    private static boolean debug = false;

    public static void main(String[] args) {
        initializeSieve();
        int x = 10; // Example input
        if (isValidInput(x)) {
            boolean result = check(x);
            System.out.println("Check result for x=" + x + ": " + result);
        } else {
            System.out.println("Invalid input: " + x);
        }
    }

    private static void initializeSieve() {
        for (int i = 2; i < N; i++) {
            if (isPrime(i)) {
                primes.add(i);
            }
        }
    }

    private static boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) return false;
        }
        return true;
    }

    private static boolean isValidInput(int x) {
        return x > 0 && x <= primes.size();
    }

    private static boolean check(int x) {
        if (!isValidInput(x)) return false;
        int primeValue = primes.get(x - 1);
        for (int i = primeValue; i <= N; i++) {
            if (i % x == 0 && isPrime(i)) {
                primes.add(i);
            }
        }
        return isPrime(primes.size());
    }

    private static int square(int x) {
        return x * x;
    }

    private static long gcd(long a, long b) {
        while (b != 0) {
            long t = b;
            b = a % b;
            a = t;
        }
        return a;
    }

    private static int determinantSquare(int x) {
        return square(x) - square(x % N);
    }
}

