        return elements.length == size && colors.length() == size;
    }

    private static boolean canFormPermutation(int[] elements, String colors, int size) {
        int[] count = new int[2 * OFFSET + 1];
        for (int element : elements) {
            count[element + OFFSET]++;
        }

        int redCount = countRed(colors);
        return redCount == 0 
            || (redCount == 1 && count[OFFSET] > 0) 
            || areCountsEqual(count, size);
    }

    private static int countRed(String colors) {
        int count = 0;
        for (char color : colors.toCharArray()) {
            if (color == 'R') {
                count++;
            }
        }
        return count;
    }

    private static boolean areCountsEqual(int[] count, int size) {
        int blueCount = 0;
        for (int i = 1; i <= size; i++) {
            if (count[i] > 0) {
                blueCount++;
            }
        }
        return blueCount == size;
    }
}

