public class DigitMinimization {

    public static List<Integer> digitMinimization(int t, List<Integer> testCases) {
        List<Integer> results = new ArrayList<>();

        for (int n : testCases) {
            try {
                String numStr = String.valueOf(n);
                char[] digits = numStr.toCharArray();
                Arrays.sort(digits); // Sort the digits of n
                int length = digits.length;

                if (length < 2) {
                    throw new IllegalArgumentException("Input number must have at least two digits.");
                }

                int resultDigit;
                if (length == 2) {
                    // If there are only two digits, the largest after sorting is valid
                    resultDigit = Character.getNumericValue(digits[1]);
                } else {
                    // For more than two digits, take the median position
                    resultDigit = Character.getNumericValue(digits[length / 2]);
                }

                results.add(resultDigit);
            } catch (Exception e) {
                System.err.println("Error processing number " + n + ": " + e.getMessage());
            }
        }
        return results;
    }

    public static void main(String[] args) {
        List<Integer> testCases = Arrays.asList(23, 4123, 987654321);
        List<Integer> results = digitMinimization(testCases.size(), testCases);
        results.forEach(result -> System.out.println("Minimum digit: " + result));
    }
}

import java.util.*;
import java.util.logging.Level;
import java.util.logging.Logger;

class Solution {
    private static final int MOD = 1_000_000_007;
    private static final Logger logger = Logger.getLogger(Solution.class.getName());

    public int rectangleArea(int[][] rectangles) {
        if (rectangles == null || rectangles.length == 0) {
            logger.log(Level.WARNING, "Input is null or empty.");
            return 0;
        }

        List<int[]> events = createEvents(rectangles);
        Collections.sort(events, Comparator.comparingInt(a -> a[0]));

        List<int[]> active = new ArrayList<>();
        long currentY = 0;
        long currentXSum = 0;
        long area = 0;

        for (int[] event : events) {
            long y = event[0];
            if (y > currentY) {
                area = (area + currentXSum * (y - currentY)) % MOD;
                currentY = y;
            }

            try {
                processEvent(active, event);
            } catch (Exception e) {
                logger.log(Level.SEVERE, "Error processing event", e);
                return (int) (area % MOD);
            }

            currentXSum = calculateCurrentWidth(active);
        }

        return (int) area;
    }

    private List<int[]> createEvents(int[][] rectangles) {
        List<int[]> events = new ArrayList<>();
        for (int[] rect : rectangles) {
            events.add(new int[]{rect[1], 1, rect[0], rect[2]}); // start of rectangle
            events.add(new int[]{rect[3], -1, rect[0], rect[2]}); // end of rectangle
        }
        return events;
    }

    private void processEvent(List<int[]> active, int[] event) {
        if (event[1] == 1) {
            active.add(new int[]{event[2], event[3]});
        } else {
            active.removeIf(range -> range[0] == event[2] && range[1] == event[3]);
        }
        active.sort(Comparator.comparingInt(a -> a[0]));
    }

    private long calculateCurrentWidth(List<int[]> active) {
        long totalWidth = 0;
        long lastX = -1;
        for (int[] range : active) {
            totalWidth += Math.max(0, range[1] - Math.max(lastX, range[0]));
            lastX = Math.max(lastX, range[1]);
        }
        return totalWidth;
    }
}

