    // Camera coverage logic for a tree
    public int minCameraCover(TreeNode root) {
        return 1 + cover(root);
    }

    private int cover(TreeNode root) {
        if (root == null) return 0;

        int leftCoverage = cover(root.left);
        int rightCoverage = cover(root.right);

        if (root.val != 0) return leftCoverage + rightCoverage;

        int tempLeft = leftCoverage;
        int tempRight = rightCoverage;

        leftCoverage += pre(tempLeft);
        rightCoverage += pre(tempRight);

        return Math.min(leftCoverage, rightCoverage) + 1;
    }

    private int pre(int current) {
        return Math.min((current + 1) * 2, (current + 1) + 2);
    }
}

class CBTInserter {
    private int value;
    private TreeNode root;

    public CBTInserter(TreeNode root) {
        if (root == null) {
            throw new IllegalArgumentException("Root cannot be null");
        }
        this.root = root;
        this.value = 1;
        initializeTree();
    }

    public int insert(int val) {
        validateValue(val);
        if (this.value == 1) {
            this.root = new TreeNode(val);
            this.value++;
            return val;
        }

        TreeNode head = findPositionForInsertion();
        TreeNode newNode = new TreeNode(val);

        if (this.value % 2 == 1) {
            head.right = newNode;
        } else {
            head.left = newNode;
        }
        this.value++;
        return val;
    }

    public TreeNode get_root() {
        return this.root;
    }

    private void initializeTree() {
        ArrayDeque<TreeNode> queue = new ArrayDeque<>();
        queue.add(this.root);

        while (!queue.isEmpty()) {
            TreeNode current = queue.poll();
            if (current.left != null) queue.add(current.left);
            if (current.right != null) queue.add(current.right);
        }
    }

    private TreeNode findPositionForInsertion() {
        ArrayDeque<TreeNode> queue = new ArrayDeque<>();
        queue.add(root);

        while (!queue.isEmpty()) {
            TreeNode current = queue.poll();
            if (current.left == null || current.right == null) {
                return current;
            }
            queue.add(current.left);
            queue.add(current.right);
        }

        throw new IllegalStateException("No position found for insertion");
    }

    private void validateValue(int val) {
        if (val <= 0) {
            throw new IllegalArgumentException("Value must be positive");
        }
    }
}

