public class GoldCollector {

    private int totalGold;
    private int goldCount;
    private List<Integer> values;

    public int getMaximumGold(List<List<Integer>> grid) {
        if (grid == null || grid.isEmpty() || grid.get(0).isEmpty()) {
            throw new IllegalArgumentException("Grid must not be null or empty.");
        }

        int maxGold = 0;
        int rows = grid.size();
        int cols = grid.get(0).size();
        this.values = new ArrayList<>();

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                totalGold = 0;
                coin(i, j, grid);
                maxGold = Math.max(maxGold, totalGold);
            }
        }
        return maxGold;
    }

    private void coin(int x, int y, List<List<Integer>> grid) {
        totalGold++;

        if (totalGold > values.size()) {
            values.add(grid.get(x).get(y));
        } else {
            values.set(totalGold - 1, grid.get(x).get(y));
        }

        grid.get(x).set(y, 0);
        int[] dx = {-1, 0, 1, 0};
        int[] dy = {0, 1, 0, -1};

        for (int i = 0; i < 4; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];
            if (isValidMove(nx, ny, grid)) {
                coin(nx, ny, grid);
            }
        }

        if (totalGold == values.size()) {
            goldCount = 1;
        } else {
            goldCount = 0;
        }

        grid.get(x).set(y, values.get(totalGold - 1));
    }

    private boolean isValidMove(int x, int y, List<List<Integer>> grid) {
        return x >= 0 && x < grid.size() && y >= 0 && y < grid.get(0).size() && grid.get(x).get(y) != 0;
    }
}

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Main {
    private static final Logger logger = Logger.getLogger(Main.class.getName());
    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM-dd");

    public static int daysBetweenDates(String date1, String date2) {
        try {
            LocalDate localDate1 = parseDate(date1);
            LocalDate localDate2 = parseDate(date2);
            return Math.abs(java.time.temporal.ChronoUnit.DAYS.between(localDate1, localDate2));
        } catch (DateTimeParseException e) {
            logger.log(Level.SEVERE, "Date format error: " + e.getMessage(), e);
            throw new IllegalArgumentException("Invalid date format. Please use 'yyyy-MM-dd'.", e);
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Unexpected error: " + e.getMessage(), e);
            throw new RuntimeException("An unexpected error occurred while calculating date difference.", e);
        }
    }

    private static LocalDate parseDate(String date) {
        return LocalDate.parse(date, DATE_FORMATTER);
    }

    public static void main(String[] args) {
        try {
            System.out.println(daysBetweenDates("2019-06-29", "2019-06-30"));
            System.out.println(daysBetweenDates("2020-01-15", "2019-12-31"));
        } catch (IllegalArgumentException | RuntimeException e) {
            logger.log(Level.WARNING, e.getMessage());
        }
