import java.util.InputMismatchException;
import java.util.Scanner;

public class KTimeLimit {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            System.out.print("Enter number of test cases: ");
            int t = readPositiveInt(scanner);

            while (t-- > 0) {
                System.out.print("Enter a value for n: ");
                int n = readPositiveInt(scanner);
                System.out.println("Max K for " + n + " is: " + maxK(n));
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static int maxK(int n) {
        int k = 0;
        while (k < n && (n & k) != 0) {
            k++;
        }
        return k;
    }

    private static int readPositiveInt(Scanner scanner) {
        while (true) {
            try {
                int value = scanner.nextInt();
                if (value < 0) {
                    throw new IllegalArgumentException("Value must be non-negative.");
                }
                return value;
            } catch (InputMismatchException e) {
                System.err.print("Invalid input. Please enter a non-negative integer: ");
                scanner.next(); // Clear invalid input
            } catch (IllegalArgumentException e) {
                System.err.println(e.getMessage());
            }
        }
    }
}

