import java.util.HashMap;
import java.util.Map;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Solution {
    private static final Logger LOGGER = Logger.getLogger(Solution.class.getName());

    public int maxOperations(int[] nums, int k) {
        if (nums == null || nums.length == 0) {
            LOGGER.log(Level.WARNING, "Input array is null or empty");
            return 0;
        }
        if (k <= 0) {
            LOGGER.log(Level.WARNING, "k must be positive");
            return 0;
        }

        Map<Integer, Integer> frequencyMap = new HashMap<>();
        for (int num : nums) {
            frequencyMap.put(num, frequencyMap.getOrDefault(num, 0) + 1);
        }

        int operationCount = 0;
        for (Map.Entry<Integer, Integer> entry : frequencyMap.entrySet()) {
            int num = entry.getKey();
            int complement = k - num;

            if (frequencyMap.containsKey(complement)) {
                if (num == complement) {
                    int pairs = entry.getValue() / 2;
                    operationCount += pairs;
                    LOGGER.log(Level.INFO, "Found {0} pairs for number {1}", new Object[]{pairs, num});
                    continue;
                }

                int count = Math.min(entry.getValue(), frequencyMap.get(complement));
                operationCount += count;
                frequencyMap.put(num, entry.getValue() - count);
                frequencyMap.put(complement, frequencyMap.get(complement) - count);

                LOGGER.log(Level.INFO, "Found {0} pairs for numbers {1} and {2}", new Object[]{count, num, complement});
            }
        }
        return operationCount;
    }
}

public class Solution {
    public int maxSum(int[] nums) {
        if (nums == null || nums.length < 2) {
            throw new IllegalArgumentException("Input array must contain at least two elements.");
        }

        int maxSum = Integer.MIN_VALUE;

        for (int i = 0; i < nums.length; i++) {
            for (int j = i + 1; j < nums.length; j++) {
                try {
                    if (maxDigit(nums[i]) == maxDigit(nums[j])) {
                        maxSum = Math.max(maxSum, nums[i] + nums[j]);
                    }
                } catch (Exception e) {
                    System.err.println("Error processing numbers: " + nums[i] + ", " + nums[j] + " - " + e.getMessage());
                }
            }
        }

        return maxSum == Integer.MIN_VALUE ? -1 : maxSum;
    }

    private int maxDigit(int num) {
        if (num < 0) {
            throw new IllegalArgumentException("Number must be non-negative.");
        }

        int maxDigit = 0;
        while (num > 0) {
            maxDigit = Math.max(maxDigit, num % 10);
            num /= 10;
        }
        return maxDigit;
    }
}

import java.util.HashSet;
import java.util.Set;

public class CompanyNaming {

    public int numDifferentNames(String[] ideas) {
        if (ideas == null || ideas.length < 2) {
            return 0; // Early return for invalid input
        }

        Set<String> originalSet = new HashSet<>();
        Set<String> validNames = new HashSet<>();

        for (String idea : ideas) {
            if (idea != null && !idea.isEmpty()) {
                originalSet.add(idea);
            }
        }

        int n = ideas.length;
        for (int i = 0; i < n; i++) {
            String ideaA = ideas[i];
            char firstA = ideaA.charAt(0);
            String restA = ideaA.substring(1);

            for (int j = 0; j < n; j++) {
                if (i != j) {
                    String ideaB = ideas[j];
                    char firstB = ideaB.charAt(0);
                    String restB = ideaB.substring(1);

                    String newA = firstB + restA;
                    String newB = firstA + restB;

                    if (!originalSet.contains(newA) && !originalSet.contains(newB)) {
                        validNames.add(newA + " " + newB);
                    }
                }
            }
        }

        return validNames.size();
    }

    public static void main(String[] args) {
        CompanyNaming cn = new CompanyNaming();

        String[] ideas1 = {"coffee", "donuts", "time", "toffee"};
        System.out.println("Valid name pairs: " + cn.numDifferentNames(ideas1)); // Output: 6

        String[] ideas2 = {"lack", "back"};
        System.out.println("Valid name pairs: " + cn.numDifferentNames(ideas2)); // Output: 0
    }
}

