public class ComplexMultiplication {

    public static void main(String[] args) {
        String num1 = "1+1i";
        String num2 = "1+1i";
        try {
            String result = multiplyComplexNumbers(num1, num2);
            System.out.println("Result: " + result);
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static String multiplyComplexNumbers(String num1, String num2) {
        validateInput(num1);
        validateInput(num2);

        String[] parts1 = num1.split("\\+");
        String[] parts2 = num2.split("\\+");

        int real1 = Integer.parseInt(parts1[0]);
        int imaginary1 = Integer.parseInt(parts1[1].replace("i", ""));
        int real2 = Integer.parseInt(parts2[0]);
        int imaginary2 = Integer.parseInt(parts2[1].replace("i", ""));

        int realResult = (real1 * real2) - (imaginary1 * imaginary2);
        int imaginaryResult = (real1 * imaginary2) + (imaginary1 * real2);

        return realResult + "+" + imaginaryResult + "i";
    }

    private static void validateInput(String num) {
        if (num == null || !num.matches("^-?\\d+\\+-?\\d+i$")) {
            throw new IllegalArgumentException("Invalid complex number format: " + num);
        }
    }
}

class Solution {
    public boolean canPartition(String s) {
        if (s == null || s.isEmpty()) {
            return false;
        }
        return dfs(s, 0, 0, 0);
    }

    private boolean dfs(String s, int index, int sum1, int sum2) {
        if (index == s.length()) {
            return sum1 == sum2;
        }

        int charValue = s.charAt(index) - 'a' + 1;

        // Recurse by including the current character in the first partition
        if (dfs(s, index + 1, sum1 + charValue, sum2)) {
            return true;
        }

        // Recurse by including the current character in the second partition
        if (dfs(s, index + 1, sum1, sum2 + charValue)) {
            return true;
        }

        return false;
    }
}

import java.util.Arrays;
import java.util.Comparator;
import java.util.logging.Level;
import java.util.logging.Logger;

class BikePositionSorter implements Comparator<int[]> {
    @Override
    public int compare(int[] worker, int[] bike) {
        if (worker[0] == bike[0]) {
            return Integer.compare(worker[1], bike[1]);
        }
        return Integer.compare(worker[0], bike[0]);
    }
}

public class Main {
    private static final Logger logger = Logger.getLogger(Main.class.getName());

    public static int assignment(int[][] workers, int[][] bikes) {
        if (workers == null || bikes == null) {
            logger.log(Level.SEVERE, "Workers or bikes array is null.");
            throw new IllegalArgumentException("Workers and bikes cannot be null.");
        }

        if (workers.length == 0 || bikes.length == 0) {
            logger.log(Level.WARNING, "Empty workers or bikes array. Returning 0.");
            return 0;
        }

        Arrays.sort(workers, new BikePositionSorter());
        Arrays.sort(bikes, new BikePositionSorter());

        int minDistance = 0;
        int bikeIndex = 0;

        for (int workerIndex = 0; workerIndex < workers.length; workerIndex++) {
            minDistance += calculateManhattanDistance(workers[workerIndex], bikes[bikeIndex]);
            bikeIndex++;
            if (bikeIndex >= bikes.length) {
                logger.log(Level.INFO, "Reached end of bikes array.");
                break;
            }
        }

        logger.log(Level.INFO, "Total minimum distance calculated: " + minDistance);
        return minDistance;
    }

    private static int calculateManhattanDistance(int[] worker, int[] bike) {
        return Math.abs(worker[0] - bike[0]) + Math.abs(worker[1] - bike[1]);
    }

    public static void main(String[] args) {
        int[][] workers1 = {{0, 0}, {2, 1}};
        int[][] bikes1 = {{1, 2}, {3, 3}};
        logger.log(Level.INFO, "Distance for workers1 and bikes1: " + assignment(workers1, bikes1));

        int[][] workers2 = {{0, 0}, {1, 1}, {2, 0}};
        int[][] bikes2 = {{1, 0}, {2, 2}, {2, 1}};
        logger.log(Level.INFO, "Distance for workers2 and bikes2: " + assignment(workers2, bikes2));

        int[][] workers3 = {{0, 0}, {1, 0}, {2, 0}, {3, 0}, {4, 0}};
        int[][] bikes3 = {{0, 999}, {1, 999}, {2, 999}, {3, 999}, {4, 999}};
        logger.log(Level.INFO, "Distance for workers3 and bikes3: " + assignment(workers3, bikes3));
    }
}

