public class LinkCutCentroid {
    static class FastReader {
        private BufferedReader br;
        private StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        public String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    System.err.println("Error reading input: " + e.getMessage());
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }
    }

    private static List<Integer>[] adjList;
    private static boolean[] visited;
    private static int[] size;
    private static int[] centroid;
    private static int n;

    private static void dfs(int node, int parent) {
        visited[node] = true;
        size[node] = 1;
        int maxSubtree = 0;

        for (int neighbor : adjList[node]) {
            if (neighbor != parent && !visited[neighbor]) {
                dfs(neighbor, node);
                size[node] += size[neighbor];
                maxSubtree = Math.max(maxSubtree, size[neighbor]);
            }
        }

        maxSubtree = Math.max(maxSubtree, n - size[node]);
        if (maxSubtree <= n / 2) {
            centroid[node] = 1;
        }
    }

    public static void main(String[] args) {
        try {
            FastReader reader = new FastReader();
            int testCases = reader.nextInt();

            while (testCases-- > 0) {
                n = reader.nextInt();
                initializeDataStructures(n);
                readGraphEdges(reader, n);
                dfs(1, -1);
                findAndPrintCentroid();
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static void initializeDataStructures(int n) {
        adjList = new ArrayList[n + 1];
        visited = new boolean[n + 1];
        size = new int[n + 1];
        centroid = new int[n + 1];

        for (int i = 1; i <= n; i++) {
            adjList[i] = new ArrayList<>();
        }
    }

    private static void readGraphEdges(FastReader reader, int n) {
        for (int i = 1; i < n; i++) {
            int x = reader.nextInt();
            int y = reader.nextInt();
            adjList[x].add(y);
            adjList[y].add(x);
        }
    }

    private static void findAndPrintCentroid() {
        int originalCentroid = -1;
        for (int i = 1; i <= n; i++) {
            if (centroid[i] == 1) {
                if (originalCentroid == -1) {
                    originalCentroid = i;
                } else {
                    // Handle multiple centroids if necessary; currently ignored.
                }
            }
        }

        if (originalCentroid != -1) {
            System.out.println("Centroid is: " + originalCentroid);
        } else {
            System.out.println("No centroid found.");
        }
    }
}

import java.util.Scanner;

public class ArrayStabilization {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = readPositiveInteger(scanner);
            for (int i = 0; i < testCases; i++) {
                int n = readPositiveInteger(scanner);
                int d = readPositiveInteger(scanner);
                int[] array = readArray(scanner, n);

                int steps = computeStabilizationSteps(array, d);
                System.out.println(steps);
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static int readPositiveInteger(Scanner scanner) {
        int num;
        do {
            num = scanner.nextInt();
        } while (num <= 0);
        return num;
    }

    private static int[] readArray(Scanner scanner, int size) {
        int[] array = new int[size];
        for (int i = 0; i < size; i++) {
            array[i] = scanner.nextInt();
        }
        return array;
    }

    private static int computeStabilizationSteps(int[] array, int d) {
        int n = array.length;
        int steps = 0;
        boolean allZeros = false;

        while (!allZeros) {
            allZeros = true;
            int[] nextArray = new int[n];

            for (int j = 0; j < n; j++) {
                int shiftedIndex = (j + n - d) % n;
                nextArray[j] = array[j] & array[shiftedIndex];
                if (nextArray[j] == 1) {
                    allZeros = false;
                }
            }

            array = nextArray;
            steps++;
            if (steps > n) {
                return -1; // Indicating stabilization is not possible
            }
        }
        return steps - 1;
    }
}

