import java.util.logging.Level;
import java.util.logging.Logger;

public class Solution {
    private static final Logger logger = Logger.getLogger(Solution.class.getName());

    public int minCost(String s1, String s2, int x) {
        if (s1.length() != s2.length() || x < 0) {
            logger.log(Level.SEVERE, "Invalid input: String lengths must match and x must be non-negative.");
            return -1;
        }

        int n = s1.length();
        int[] dp = new int[2];
        dp[1] = Integer.MAX_VALUE / 2;

        for (int i = 0; i < n; i++) {
            int[] newDp = new int[2];
            int diff = s1.charAt(i) ^ s2.charAt(i);
            newDp[0] = dp[0] + diff * x;
            newDp[1] = dp[1] + (1 - diff) * x;

            if (i > 0) {
                newDp[0] = Math.min(newDp[0], dp[1] + 1);
                newDp[1] = Math.min(newDp[1], dp[0] + 1);
            }

            dp = newDp;
        }

        int result = dp[0] >= Integer.MAX_VALUE / 2 ? -1 : dp[0];
        if (result == -1) {
            logger.log(Level.WARNING, "Unable to compute valid cost, returning -1.");
        } else {
            logger.log(Level.INFO, "Minimum cost calculated: " + result);
        }
        return result;
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        testMinCost(sol, "1100011000", "0101001010", 2); // Expected Output: 4
        testMinCost(sol, "10110", "00011", 4); // Expected Output: -1
    }

    private static void testMinCost(Solution sol, String s1, String s2, int x) {
        int result = sol.minCost(s1, s2, x);
        System.out.println("Result for s1: " + s1 + ", s2: " + s2 + ", x: " + x + " is " + result);
    }
}

