public class ClockAngleCalculator {

    private static final int MINUTES_IN_HOUR = 60;
    private static final int DEGREES_PER_MINUTE = 6;
    private static final int DEGREES_PER_HOUR = 30;
    private static final int TOTAL_HOURS = 12;

    public double calculateAngle(int hour, int minutes) {
        validateInput(hour, minutes);

        double angleMinute = calculateMinuteAngle(minutes);
        double angleHour = calculateHourAngle(hour, minutes);

        double angleDifference = calculateAngleDifference(angleHour, angleMinute);
        return Math.abs(angleDifference);
    }

    private void validateInput(int hour, int minutes) {
        if (hour < 0 || hour >= TOTAL_HOURS) {
            throw new IllegalArgumentException("Hour must be between 0 and 11.");
        }
        if (minutes < 0 || minutes >= MINUTES_IN_HOUR) {
            throw new IllegalArgumentException("Minutes must be between 0 and 59.");
        }
    }

    private double calculateMinuteAngle(int minutes) {
        return minutes * DEGREES_PER_MINUTE;
    }

    private double calculateHourAngle(int hour, int minutes) {
        return (hour % TOTAL_HOURS) * 360.0 / TOTAL_HOURS + (minutes / (double) MINUTES_IN_HOUR) * DEGREES_PER_HOUR;
    }

    private double calculateAngleDifference(double angleHour, double angleMinute) {
        double difference = angleMinute - angleHour;
        if (difference > 180) {
            difference -= 360;
        } else if (difference < -180) {
            difference += 360;
        }
        return difference;
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
