import java.util.Set;

public class NezzarBoard {

    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in))) {
            int testCases = readInt(br);
            for (int i = 0; i < testCases; i++) {
                int n = readInt(br);
                int k = readInt(br);
                int[] nums = readNumbers(br, n);
                String result = isPossible(nums, k) ? "YES" : "NO";
                System.out.println(result);
            }
        } catch (IOException e) {
            System.err.println("Error reading input: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.err.println("Invalid number format: " + e.getMessage());
        }
    }

    private static int readInt(BufferedReader br) throws IOException {
        String line = br.readLine();
        if (line == null || line.trim().isEmpty()) {
            throw new IOException("Input cannot be null or empty");
        }
        return Integer.parseInt(line.trim());
    }

    private static int[] readNumbers(BufferedReader br, int count) throws IOException {
        String[] numStrs = br.readLine().split(" ");
        if (numStrs.length != count) {
            throw new IOException("Expected " + count + " numbers but got " + numStrs.length);
        }

        int[] nums = new int[count];
        for (int j = 0; j < count; j++) {
            nums[j] = Integer.parseInt(numStrs[j].trim());
        }
        return nums;
    }

    private static boolean isPossible(int[] nums, int k) {
        Set<Integer> numSet = new HashSet<>();
        for (int num : nums) {
            numSet.add(num);
        }
        for (int num : nums) {
            if (numSet.contains(k - 2 * num)) {
                return true;
            }
        }
        return false;
    }
}

