public int deleteGreatestValue(int[][] grid) {
    if (grid == null || grid.length == 0 || grid[0].length == 0) {
        throw new IllegalArgumentException("Input grid must be non-null and non-empty.");
    }

    int rowCount = grid.length;
    int colCount = grid[0].length;

    for (int[] row : grid) {
        if (row.length != colCount) {
            throw new IllegalArgumentException("All rows in the grid must have the same number of columns.");
        }
        Arrays.sort(row);
    }

    int totalMaxSum = 0;

    for (int colIndex = colCount - 1; colIndex >= 0; colIndex--) {
        int maxInColumn = Integer.MIN_VALUE;
        for (int rowIndex = 0; rowIndex < rowCount; rowIndex++) {
            maxInColumn = Math.max(maxInColumn, grid[rowIndex][colIndex]);
        }
        if (maxInColumn != Integer.MIN_VALUE) {
            totalMaxSum += maxInColumn;
        } else {
            System.err.println("Warning: No valid elements found in column " + colIndex);
        }
    }

    return totalMaxSum;
}

import java.util.Scanner;
import java.util.Arrays;

public class CheatersSimilarity {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            if (scanner.hasNextInt()) {
                int n = scanner.nextInt();
                int m = scanner.nextInt();
                if (n <= 0 || m <= 0) {
                    throw new IllegalArgumentException("Lengths must be positive.");
                }
                String a = scanner.next();
                String b = scanner.next();

                if (a.length() != n || b.length() != m) {
                    throw new IllegalArgumentException("Input strings do not match specified lengths.");
                }

                process(n, m, a, b);
            } else {
                System.err.println("Invalid input, expected integers.");
            }
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static void process(int n, int m, String a, String b) {
        int[] oracle = new int[n + m];
        int[] dp = new int[n + m];

        Arrays.fill(dp, -1);
        int maxScore = computeSimilarity(n, m, a, b, oracle, dp);
        System.out.println("Max Similarity Score: " + maxScore);
    }

    private static int computeSimilarity(int n, int m, String a, String b, int[] oracle, int[] dp) {
        populateOracleAndDp(n, m, a, b, oracle, dp);
        return Math.max(calculateGreedySimilarity(n, a, oracle, dp), calculateGreedySimilarity(m, b, oracle, dp));
    }

    private static void populateOracleAndDp(int n, int m, String a, String b, int[] oracle, int[] dp) {
        int i = 0, j = 0;
        while (i < n) {
            oracle[n + j] = a.charAt(i);
            dp[n + j++] = i;

            while (j < m && b.charAt(j) == oracle[n + j - 1]) {
                dp[n + j] = dp[n + j - 1];
                j++;
            }
            i = dp[n + j - 1];
        }
    }

    private static int calculateGreedySimilarity(int length, String str, int[] oracle, int[] dp) {
        int i = 0, prevChar = -1;
        while (i < length) {
            oracle[i] = str.charAt(i);
            dp[i] = (prevChar != -1 && oracle[i] == str.charAt(prevChar)) ? dp[prevChar] : i;

            if (i > 0 && oracle[i] == oracle[i - 1]) {
                dp[i] = dp[i - 1];
            }
            prevChar = i++;
        }
        return dp[length - 1] >= 0 ? dp[length - 1] : 0;
    }
}

public int countBinarySubstrings(String s) {
    if (s == null || s.isEmpty()) {
        throw new IllegalArgumentException("Input string cannot be null or empty");
    }

    int count = 0;
    int prev = 0;
    int curr = 1;

    try {
        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) == s.charAt(i - 1)) {
                curr++;
            } else {
                count += Math.min(prev, curr);
                prev = curr;
                curr = 1;
            }
        }
        count += Math.min(prev, curr);
    } catch (IndexOutOfBoundsException ex) {
        throw new RuntimeException("Index out of bounds during processing", ex);
    }

    return count;
}

