public class Main {
    public static void main(String[] args) {
        String input = "3 \n1 2 1 \n1 2 \n2 3"; // Sample input for testing
        try {
            int result = calculateTowerCost(input);
            System.out.println(result);
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static int calculateTowerCost(String input) {
        try (Scanner scanner = new Scanner(input)) {
            int n = scanner.nextInt();
            validateInput(n);

            int[] height = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                height[i] = scanner.nextInt();
            }

            int result = 0;
            boolean[] visited = new boolean[n + 1];
            int[] tower = new int[n + 1];
            Arrays.fill(tower, Integer.MAX_VALUE);
            visited[n] = true;
            tower[n] = 0;

            for (int i = n - 1; i >= 1; i--) {
                int v = scanner.nextInt();
                visited[v] = true;

                result = Math.max(result, Math.min(tower[v], height[i]) + height[v]);
                tower[v] = Math.min(tower[v], height[i]) + height[v];

                if (tower[v] >= height[v]) {
                    tower[v] = 0;
                }
            }

            if (result == 0) {
                result++;
            }
            return result;
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid input format.");
        }
    }

    private static void validateInput(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException("Number of towers must be positive.");
        }
    }
