public class ArrayArranger {

    public static boolean canArrange(int[] arr, int k) {
        if (arr.length % 2 != 0) {
            return false;
        }

        int[] count = new int[k];
        for (int num : arr) {
            int rem = ((num % k) + k) % k;  // Handle negative numbers correctly
            if (rem == 0) {
                if (count[0] < arr.length / 2) {
                    count[0]++;
                } else {
                    return false;
                }
            } else {
                count[rem]++;
            }
        }

        for (int i = 1; i <= k / 2; i++) {
            if (i * 2 != k && count[i] > count[k - i]) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println(canArrange(new int[]{1, 2, 3, 4, 5, 10, 6, 7, 8, 9}, 5)); // True
        System.out.println(canArrange(new int[]{1, 2, 3, 4, 5, 6}, 7)); // True
        System.out.println(canArrange(new int[]{1, 2, 3, 4, 5, 6}, 10)); // False
        System.out.println(canArrange(new int[]{1, 4, 1, 4, 1, 12}, 4)); // True
        System.out.println(canArrange(new int[]{1, 4, 5, 6}, 7)); // False
        System.out.println(canArrange(new int[]{1000000000, 1000000000, 1000000000, 1000000000, 1000000000, 1000000000, -1000000000, -1000000000}, 1000000000)); // True
        System.out.println(canArrange(new int[]{1, 2, 3, 4, 5, 6}, 1)); // False
        System.out.println(canArrange(new int[]{3, 3, 3, 3, 3, 3}, 9)); // False
    }
}

public class TinyTicsCalculator {

    public static double findTinyTics(int x, int y) {
        double z = y * x;
        if (z > 2000000) {
            return z * 0.1;
        }
        if (z <= 0) {
            return 0;
        }

        String zStr = String.valueOf((int) z);
        int len = zStr.length();
        int i = 0;
        int a = Character.getNumericValue(zStr.charAt(0));
        int b = 0;

        while (i < len) {
            a = Character.getNumericValue(zStr.charAt(i));
            b = (i > 0) ? Character.getNumericValue(zStr.charAt(i - 1)) : 0;
            if (a == b) {
                i++;
            } else {
                break;
            }
        }

        return z * 0.1 * (a - b) / z;
    }

    public static void main(String[] args) {
        System.out.println(findTinyTics(4, 8)); // 0.0
        System.out.println(findTinyTics(0, 2)); // 0.0
        System.out.println(findTinyTics(123, 100)); // 0.027
        System.out.println(findTinyTics(5, 5)); // 0.0
    }
}

public class Skyline {

    public static int maxIncreaseKeepingSkyline(int[][] grid) {
        int n = grid.length;
        int[] rowMax = new int[n];
        int[] colMax = new int[n];

        for (int i = 0; i < n; i++) {
            rowMax[i] = Arrays.stream(grid[i]).max().orElse(0);
            for (int j = 0; j < n; j++) {
                colMax[j] = Math.max(colMax[j], grid[i][j]);
            }
        }

        int totalIncrease = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                totalIncrease += Math.min(rowMax[i], colMax[j]) - grid[i][j];
            }
        }

        return totalIncrease;
    }

    public static void main(String[] args) {
        System.out.println(maxIncreaseKeepingSkyline(new int[][]{{3, 0, 8, 4}, {2, 4, 5, 0}, {7, 0, 0, 0}, {6, 0, 0, 2}})); // Expected output
    }
}

