import java.util.*;

public class FriendRequestCounter {
    private static final int MAX_N = 100005;
    private static long[] sizes = new long[MAX_N];
    private int currentIndex;
    private int maxIndex;

    public static void main(String[] args) {
        FriendRequestCounter counter = new FriendRequestCounter();
        counter.run();
    }

    private void run() {
        List<Integer> ages = new ArrayList<>(Arrays.asList(95, 25, 40, 99));
        int requests = numFriendRequests(ages);
        System.out.println("Total Friend Requests: " + requests);
    }

    private void build(int n) {
        Arrays.fill(sizes, 0, n, 1);
    }

    private int tryMax(int index, int n) {
        if (index >= n) return 0;
        if (sizes[index] > sizes[maxIndex]) {
            maxIndex = index;
        }
        return Math.max(tryMax(index + 1, n), tryMax(index, n));
    }

    private int getMax() {
        if (currentIndex + 1 < sizes.length && sizes[currentIndex + 1] > sizes[currentIndex]) {
            currentIndex++;
            return (int) sizes[currentIndex];
        }
        currentIndex++;
        return (int) sizes[currentIndex];
    }

    private List<Integer> compress(List<Integer> values) {
        Set<Integer> uniqueValues = new HashSet<>(values);
        List<Integer> sortedUnique = new ArrayList<>(uniqueValues);
        Collections.sort(sortedUnique);
        List<Integer> compressed = new ArrayList<>();
        for (Integer value : values) {
            compressed.add(Collections.binarySearch(sortedUnique, value));
        }
        return compressed;
    }

    public int numFriendRequests(List<Integer> ages) {
        int n = ages.size();
        build(n);
        int totalRequests = 0;

        for (int i = 0; i < n; i++) {
            currentIndex = i;
            totalRequests += Math.max(tryMax(i + 1, n), tryMax(0, n));
        }

        return totalRequests;
    }
}

public class Solution {
    private static final String ERROR_MESSAGE = "Input arrays must be of the same length and not null.";

    public int maximumNotSameNumber(int[] n1, int[] n2) {
        validateInputs(n1, n2);
        int[] xorResults = computeXor(n1, n2);
        return findMaxNonAdjacentSum(xorResults);
    }

    private void validateInputs(int[] n1, int[] n2) {
        if (n1 == null || n2 == null || n1.length != n2.length) {
            throw new IllegalArgumentException(ERROR_MESSAGE);
        }
    }

    private int[] computeXor(int[] n1, int[] n2) {
        int[] results = new int[n1.length];
        for (int i = 0; i < n1.length; i++) {
            results[i] = n1[i] ^ n2[i];
        }
        return results;
    }

    private int findMaxNonAdjacentSum(int[] arr) {
        int maxSum = Integer.MIN_VALUE;
        for (int i = 0; i < arr.length - 2; i += 2) {
            int currentSum = arr[i] + arr[i + 1] + arr[i + 2];
            maxSum = Math.max(maxSum, currentSum);
        }
        return maxSum;
    }
}

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.math.BigInteger;
import java.util.Objects;

public class Solution {

    private static final BigInteger MODULUS = new BigInteger("998244353");

    public static void main(String[] args) {
        try {
            int n = readInput();
            BigInteger[] weights = readWeights(n);
            BigInteger[] weightss = calculateWeights(n, weights);

            long ans = calculateAnswer(n, weightss);
            System.out.println(ans);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static int readInput() throws Exception {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            return new BigInteger(reader.readLine()).intValue();
        }
    }

    private static BigInteger[] readWeights(int n) throws Exception {
        BigInteger[] weights = new BigInteger[n];
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            for (int i = 0; i < n; ++i) {
                weights[i] = BigInteger.valueOf(Integer.parseInt(reader.readLine()));
            }
        }
        return weights;
    }

    private static BigInteger[] calculateWeights(int n, BigInteger[] weights) {
        BigInteger[] weightss = new BigInteger[n + 1];
        weightss[n] = BigInteger.ZERO;

        for (int i = n; i >= 0; i -= 3) {
            BigInteger wy = BigInteger.ZERO;
            for (int j = 0; j < 3; ++j) {
                wy = wy.add(weights[i - j].subtract(weights[n - j]));
            }
            if (i >= 3) {
                weightss[i - 3] = weightss[i].add(wy.multiply(BigInteger.valueOf(2)));
            }
        }
        return weightss;
    }

    private static long calculateAnswer(int n, BigInteger[] weightss) {
        BigInteger weight = weightss[0];
        long term1 = factorial(n / 3) * exponent(n / 3, MODULUS);
        long term2 = factorial(n / 3) * factorial(2 * n / 3) * exponent(n / 3, MODULUS);
        long term3 = powsum(n / 3, weight, MODULUS);

        return (term1 - term2) % MODULUS.longValue() + term3;
    }

    private static long factorial(long n) {
        validateNonNegative(n, "n should be greater than or equal to 0");
        long result = 1;
        for (long i = n; i > 0; --i) {
            result = (result * i) % MODULUS.longValue();
        }
        return result;
    }

    private static long exponent(long x, long p) {
        validateNonNegative(p, "p should be greater than or equal to 0");
        long result = 1, power = x % MODULUS.longValue();

        while (p > 0) {
            if ((p & 1) == 1) {
                result = (result * power) % MODULUS.longValue();
            }
            power = (power * power) % MODULUS.longValue();
            p >>= 1;
        }
        return result;
    }

    private static long powsum(long n, BigInteger a, BigInteger modulus) {
        validateNonNegative(n, "n should be greater than or equal to 0");
        if (a.signum() == 0) {
            throw new IllegalArgumentException("a must not be zero.");
        }

        long fac = n % modulus.longValue();
        long inc = a.mod(BigInteger.ONE).longValue() % modulus.longValue();
        long res = 0;

        for (int i = 0; i <= n; i++) {
            res = (res + fac) % modulus.longValue();
        }
        return (long) powmod(inc, fac, modulus.longValue());
    }

    private static long powmod(long a, long k, long modulus) {
        validatePositiveModulus(modulus);
        validateNonNegative(k, "k must be non-negative");
        validateNonNegative(a, "a should be non-negative and less than modulus");

        long pow = 1, base = a % modulus;

        while (k > 0) {
            if ((k & 1) == 1) {
                pow = (pow * base) % modulus;
            }
            base = (base * base) % modulus;
            k >>= 1;
        }
        return pow;
    }

    private static void validateNonNegative(long value, String message) {
        if (value < 0) throw new IllegalArgumentException(message);
    }

    private static void validatePositiveModulus(long modulus) {
        if (modulus <= 0) throw new IllegalArgumentException("Modulus must be positive.");
    }

}

