class Queue {
    private Node front = null;
    private Node rear = null;
    private Node removed = null;

    public void enqueue(int x) {
        Node newNode = new Node(x);
        if (front == null) {
            front = newNode;
            rear = newNode;
        } else {
            rear.next = newNode;
            newNode.prev = rear;
            rear = newNode;
        }
    }

    public void dequeue() {
        if (front == null) {
            System.out.println("Underflow");
            return;
        }
        Node copy = front;
        front = front.next;
        System.out.println(copy.value);
        copy = null;
    }

    public void display() {
        if (front == null) {
            System.out.println("Underflow");
            return;
        }
        Node copy = front;
        while (copy != null) {
            System.out.println(copy.value);
            copy = copy.next;
        }
        System.out.println();
    }

    public void enqueueLeft(int x) {
        Node newNode = new Node(x);
        if (front == null) {
            front = newNode;
            rear = newNode;
        } else {
            newNode.next = front;
            front.prev = newNode;
            front = newNode;
        }
    }

    public void read(int x) {
        if (front == null) {
            System.out.println("Underflow");
            return;
        }
        Node copy = front;
        while (copy != null) {
            if (copy.value == x) {
                System.out.println("Found: " + copy.value);
                return;
            }
            copy = copy.next;
        }
        System.out.println("Not Found");
    }

    public void removeLast() {
        if (removed == null) {
            System.out.println("Underflow");
            return;
        }
        Node copy = removed;
        removed = removed.prev;
        System.out.println("Removed: " + copy.value);
        copy = null;
    }

    public void processQueueOperations(String txtReader) {
        enqueue(10);
        enqueue(11);
        enqueue(12);
        enqueueLeft(14);
        dequeue();
        display();
        enqueueLeft(16);    
        display();
        removeLast();
        display();
        read(11);
    }

