public class Solution {
    public String reverseStr(String s, int k) {
        if (s == null || k <= 0) {
            throw new IllegalArgumentException("Input string must not be null and k must be positive.");
        }

        char[] chars = s.toCharArray();
        for (int i = 0; i < chars.length; i += 2 * k) {
            int start = i;
            int end = Math.min(i + k - 1, chars.length - 1);
            reverseSegment(chars, start, end);
        }
        return new String(chars);
    }

    private void reverseSegment(char[] chars, int start, int end) {
        while (start < end) {
            char temp = chars[start];
            chars[start] = chars[end];
            chars[end] = temp;
            start++;
            end--;
        }
    }
}

class Solution {
    public boolean xorGame(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array must not be null or empty.");
        }

        int xor = calculateXOR(nums);
        return xor == 0;
    }

    private int calculateXOR(int[] nums) {
        int result = 0;
        for (int num : nums) {
            if (num < 0) {
                throw new IllegalArgumentException("Array elements must be non-negative.");
            }
            result ^= num;
        }
        return result;
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigInteger;

public class ArrayBeauty {
    public static void main(String[] args) {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            int testCases = Integer.parseInt(reader.readLine().trim());
            while (testCases-- > 0) {
                int arrayLength = Integer.parseInt(reader.readLine().trim());
                int[] array = parseInputArray(reader.readLine().trim(), arrayLength);
                int queries = Integer.parseInt(reader.readLine().trim());

                for (int i = 0; i < queries; i++) {
                    int w = Integer.parseInt(reader.readLine().trim());
                    int beautyScore = calculateBeauty(array, w);
                    System.out.println(beautyScore);
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading input: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.err.println("Invalid input format: " + e.getMessage());
        }
    }

    private static int[] parseInputArray(String input, int length) {
        String[] values = input.split("\\s+");
        if (values.length != length) {
            throw new IllegalArgumentException("Input array length does not match specified length.");
        }
        int[] array = new int[length];
        for (int i = 0; i < length; i++) {
            array[i] = Integer.parseInt(values[i]);
        }
        return array;
    }

    private static int calculateBeauty(int[] array, int iterations) {
        int maxBeauty = 0;

        for (int i = 0; i < array.length; i++) {
            int beauty = calculateElementBeauty(array, i);
            maxBeauty = Math.max(maxBeauty, beauty);
        }

        for (int w = 0; w < iterations; w++) {
            array = transformArray(array);
            maxBeauty = Math.max(maxBeauty, calculateMaxBeauty(array));
        }

        return maxBeauty;
    }

    private static int calculateElementBeauty(int[] array, int index) {
        int beauty = 1;
        for (int j = 0; j < array.length; j++) {
            if (isRelated(array[index], array[j])) {
                beauty++;
            }
        }
        return beauty;
    }

    private static int calculateMaxBeauty(int[] array) {
        int maxBeauty = 0;
        for (int i = 0; i < array.length; i++) {
            int beauty = calculateElementBeauty(array, i);
            maxBeauty = Math.max(maxBeauty, beauty);
        }
        return maxBeauty;
    }

    private static int[] transformArray(int[] array) {
        int[] transformed = new int[array.length];
        for (int i = 0; i < array.length; i++) {
            transformed[i] = computeProduct(array, i);
        }
        return transformed;
    }

    private static int computeProduct(int[] array, int index) {
        int product = 1;
        for (int j = 0; j < array.length; j++) {
            if (index == j || isRelated(array[index], array[j])) {
                product *= array[j];
            }
        }
        return product;
    }

    private static boolean isRelated(int x, int y) {
        BigInteger lcm = BigInteger.valueOf(x).lcm(BigInteger.valueOf(y));
        BigInteger gcd = lcm.gcd(BigInteger.valueOf(x).divide(lcm));
        return gcd.equals(BigInteger.ONE);
    }
}

