import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;
import java.util.logging.Level;
import java.util.logging.Logger;

class Allocator {
    private static final Logger logger = Logger.getLogger(Allocator.class.getName());
    private final int[] memory;
    private final HashMap<Integer, List<Integer>> allocationMap;

    public Allocator(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException("Memory size must be greater than 0.");
        }
        memory = new int[n];
        allocationMap = new HashMap<>();
        logger.log(Level.INFO, "Allocator initialized with size: {0}", n);
    }

    public int allocate(int size, int mID) {
        if (size <= 0) {
            logger.log(Level.WARNING, "Allocation size must be greater than 0.");
            return -1;
        }
        if (mID <= 0) {
            logger.log(Level.WARNING, "Memory ID must be greater than 0.");
            return -1;
        }

        int n = memory.length;
        for (int i = 0; i <= n - size; i++) {
            if (canAllocate(i, size)) {
                allocateMemory(i, size, mID);
                logger.log(Level.INFO, "Allocated {0} units for ID {1} starting at index {2}", new Object[]{size, mID, i});
                return i;
            }
        }
        logger.log(Level.WARNING, "Allocation failed for ID {0} - not enough contiguous space.", mID);
        return -1;
    }

    public int free(int mID) {
        if (mID <= 0) {
            logger.log(Level.WARNING, "Memory ID must be greater than 0.");
            return 0;
        }

        int count = 0;
        if (allocationMap.containsKey(mID)) {
            for (int index : allocationMap.get(mID)) {
                memory[index] = 0;
                count++;
            }
            allocationMap.remove(mID);
            logger.log(Level.INFO, "Freed {0} units for ID {1}.", new Object[]{count, mID});
        } else {
            logger.log(Level.INFO, "No allocations found for ID {0}.", mID);
        }
        return count;
    }

    private boolean canAllocate(int start, int size) {
        for (int j = start; j < start + size; j++) {
            if (memory[j] != 0) {
                return false;
            }
        }
        return true;
    }

    private void allocateMemory(int start, int size, int mID) {
        for (int j = start; j < start + size; j++) {
            memory[j] = mID;
            allocationMap.computeIfAbsent(mID, k -> new ArrayList<>()).add(j);
        }
    }
}

