public class BeautifulSubstringCounter {

    public int numberOfBeautifulSubstrings(String s, int k) {
        if (s == null || k <= 0) {
            throw new IllegalArgumentException("Input string cannot be null and k must be positive.");
        }

        int ans = 0;
        int n = s.length();
        int vowelCount = 0;
        StringBuilder currentSubstring = new StringBuilder();

        for (int i = 0; i < n; i++) {
            char currentChar = s.charAt(i);
            if (isVowel(currentChar)) {
                vowelCount++;
            }
            currentSubstring.append(currentChar);

            if (vowelCount >= k && isBeautifulSubstring(currentSubstring.toString(), k)) {
                vowelCount = 0;
                currentSubstring.setLength(0); // Clear the StringBuilder
                ans++;
            }
        }

        return ans;
    }

    private boolean isVowel(char c) {
        return "aeiou".indexOf(c) >= 0;
    }

    public boolean isBeautifulSubstring(String s, int k) {
        if (s.length() < k) {
            return false;
        }

        boolean[] vowelPresence = new boolean[5]; // a, e, i, o, u
        for (char c : s.toCharArray()) {
            if (isVowel(c)) {
                vowelPresence["aeiou".indexOf(c)] = true;
            }
        }

        for (boolean present : vowelPresence) {
            if (!present) {
                return false;
            }
        }

        return isAlternating(s);
    }

    private boolean isAlternating(String s) {
        int count = 0;
        for (int i = 0; i < s.length() - 1; i++) {
            char left = s.charAt(i);
            char right = s.charAt(i + 1);
            if (isVowel(left) && isVowel(right)) {
                count++;
            } else if (isVowel(left) || isVowel(right)) {
                count--;
            }
        }
        return count >= 1; // At least one switch between vowel and consonant
    }
}

