    private static int countValidPairs(int[] arr, int n) {
        int count = 0;

        for (int i = n - 1; i > 1; i--) {
            int f = 2, s = 0;

            if (arr[i] < i) {
                while (f < i) {
                    if (arr[f] > f && arr[f] < arr[i]) {
                        break;
                    }
                    f++;
                }
            } else {
                s = (int) Math.ceil(((double) i / 2));
                f = s + 1;
            }

            if (f > i) {
                count++;
            }
        }

        return count;
    }
