public class Solution implements SolutionInterface {
    private static final Logger logger = Logger.getLogger(Solution.class.getName());

    public int shortestSubarray(int[] nums, int target) {
        TreeMap<Long, Integer> treeMap = new TreeMap<>();
        treeMap.put(0L, 1);

        long runningSum = 0;
        int minLength = Integer.MAX_VALUE;

        for (int num : nums) {
            runningSum += num;
            Long ceilingKey = treeMap.ceilingKey(runningSum + 1 - target);
            if (ceilingKey != null) {
                minLength = Math.min(minLength, (int)(runningSum - ceilingKey));
            }

            treeMap.put(runningSum + 1, treeMap.getOrDefault(runningSum + 1, 0) + 1);
        }

        return minLength == Integer.MAX_VALUE ? -1 : minLength;
    }

