import java.io.*;
import java.util.*;

class SegmentTree {
    private int[] tree, lazy;
    private static final int INITIAL_CAPACITY = 4;

    public void build(int[] values) {
        int n = values.length;
        tree = new int[INITIAL_CAPACITY * n];
        lazy = new int[INITIAL_CAPACITY * n];
        Arrays.fill(lazy, 0);
        buildRecursive(values, 1, 0, n - 1);
    }

    private void buildRecursive(int[] values, int node, int start, int end) {
        if (start == end) {
            tree[node] = values[start];
            return;
        }
        int mid = (start + end) / 2;
        buildRecursive(values, node * 2, start, mid);
        buildRecursive(values, node * 2 + 1, mid + 1, end);
        tree[node] = tree[node * 2] + tree[node * 2 + 1];
    }

    public void addRange(int left, int right, int value) {
        addRangeRecursive(left, right, value, 1, 0, tree.length / 4 - 1);
    }

    private void addRangeRecursive(int left, int right, int value, int node, int start, int end) {
        if (lazy[node] != 0) {
            tree[node] += lazy[node] * (end - start + 1);
            if (start != end) {
                lazy[node * 2] += lazy[node];
                lazy[node * 2 + 1] += lazy[node];
            }
            lazy[node] = 0;
        }

        if (start > end || start > right || end < left) {
            return;
        }

        if (start >= left && end <= right) {
            tree[node] += value * (end - start + 1);
            if (start != end) {
                lazy[node * 2] += value;
                lazy[node * 2 + 1] += value;
            }
            return;
        }

        int mid = (start + end) / 2;
        addRangeRecursive(left, right, value, node * 2, start, mid);
        addRangeRecursive(left, right, value, node * 2 + 1, mid + 1, end);
        tree[node] = tree[node * 2] + tree[node * 2 + 1];
    }

    public int query(int left, int right) {
        return queryRecursive(left, right, 1, 0, tree.length / 4 - 1);
    }

    private int queryRecursive(int left, int right, int node, int start, int end) {
        if (lazy[node] != 0) {
            tree[node] += lazy[node] * (end - start + 1);
            if (start != end) {
                lazy[node * 2] += lazy[node];
                lazy[node * 2 + 1] += lazy[node];
            }
            lazy[node] = 0;
        }

        if (start > end || start > right || end < left) {
            return 0;
        }

        if (start >= left && end <= right) {
            return tree[node];
        }

        int mid = (start + end) / 2;
        int leftSum = queryRecursive(left, right, node * 2, start, mid);
        int rightSum = queryRecursive(left, right, node * 2 + 1, mid + 1, end);
        return leftSum + rightSum;
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter number of elements: ");
        int n = scanner.nextInt();
        int[] values = new int[n];

        System.out.println("Enter elements:");
        for (int i = 0; i < n; i++) {
            values[i] = scanner.nextInt();
        }

        SegmentTree segmentTree = new SegmentTree();
        segmentTree.build(values);

