import java.util.Arrays;
import java.util.Scanner;

public class OddTriplesFinder {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = Integer.parseInt(scanner.nextLine().trim());
            for (int t = 0; t < testCases; t++) {
                int size = Integer.parseInt(scanner.nextLine().trim());
                int[] numbers = Arrays.stream(scanner.nextLine().trim().split(" "))
                                      .mapToInt(Integer::parseInt).toArray();

                Arrays.sort(numbers);
                String result = findTriples(numbers, size);
                System.out.println(result);
            }
        } catch (NumberFormatException e) {
            System.err.println("Invalid input. Please ensure that all entries are integers.");
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }

    private static String findTriples(int[] numbers, int size) {
        for (int i = 0; i < size; i++) {
            for (int j = i + 1; j < size; j++) {
                int x = numbers[i] ^ numbers[j];

                if (j + 1 < size && (numbers[j] ^ (~x)) == numbers[j + 1]) {
                    for (int k = j; k < size; k++) {
                        int total = numbers[i] + numbers[j] + numbers[k];
                        if (total % 2 != 0) {
                            return String.format("(%d, %d, %d)", i, j, k);
                        }
                    }
                }
            }
        }
        return "NO";
    }
}

