class Solution {
    public int xorOperation(int n, int start) {
        if (n <= 0) {
            throw new IllegalArgumentException("n must be positive.");
        }

        int total = start;
        int num = start;

        for (int i = 1; i < n; i++) {
            num += 2;
            total ^= num;
        }

        return total;
    }
}

public boolean checkSubarraySum(int[] nums, int k) {
    if (nums == null || nums.length < 2) {
        throw new IllegalArgumentException("Input array must contain at least two elements.");
    }

    int sum = 0;
    Map<Integer, Integer> sumMap = new HashMap<>();
    sumMap.put(0, -1); // Handle the edge case for a valid subarray starting at index 0

    for (int i = 0; i < nums.length; i++) {
        sum += nums[i];

        if (k != 0) {
            sum %= k; // To avoid division by zero
        }

        if (sumMap.containsKey(sum)) {
            if (i - sumMap.get(sum) > 1) { // Ensure subarray length is at least 2
                return true;
            }
        } else {
            sumMap.put(sum, i);
        }
    }

    return false;
}

