import java.util.*;

public class ElementSelector {

    public List<Integer> strongestKElements(int[] nums, int k) {
        if (k <= 0) {
            throw new IllegalArgumentException("k must be greater than 0.");
        }

        DelayedListStack ds = new DelayedListStack(k);
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        Integer num, removedNum;

        for (int currentNum : nums) {
            if (ds.size() == k) {
                removedNum = ds.remove();
                pq.remove(removedNum);
            }

            if (pq.isEmpty() || currentNum > (num = pq.peek())) {
                ds.push(currentNum);
                if (pq.isEmpty()) {
                    continue;
                } 
            } else {
                ds.push(currentNum);
            }

            if (ds.size() > 0) {
                removedNum = ds.remove();
                if (removedNum == null || !pq.remove(removedNum)) {
                    throw new IllegalStateException("Error: Unable to match the expected element.");
                }
                ds.push(removedNum);
            }
        }

        List<Integer> result = new LinkedList<>();
        while (!ds.isEmpty()) {
            result.add(ds.pop());
        }
        Collections.reverse(result);
        return result;
    }
}

class DelayedListStack {
    private List<Integer> stack;
    private final int capacity;

    DelayedListStack(int capacity) {
        this.capacity = capacity;
        this.stack = new ArrayList<>(capacity);
    }

    public void push(int value) {
        if (stack.size() < capacity) {
            stack.add(value);
        } else {
            throw new IllegalStateException("Stack is full.");
        }
    }

    public Integer remove() {
        return stack.isEmpty() ? null : stack.remove(stack.size() - 1);
    }

    public int size() {
        return stack.size();
    }

    public boolean isEmpty() {
        return stack.isEmpty();
    }

    public Integer peek() {
        return stack.isEmpty() ? null : stack.get(stack.size() - 1);
    }
}

import java.util.HashMap;
import java.util.Map;

public class Solution {
    public int equalPairs(int[][] grid) {
        if (grid == null || grid.length == 0) {
            throw new IllegalArgumentException("Input grid cannot be null or empty");
        }

        int n = grid.length;
        Map<String, Integer> rowMap = new HashMap<>();
        Map<String, Integer> colMap = new HashMap<>();

        for (int i = 0; i < n; i++) {
            StringBuilder rowKey = new StringBuilder();
            StringBuilder colKey = new StringBuilder();
            for (int j = 0; j < n; j++) {
                rowKey.append(grid[i][j]).append(",");
                colKey.append(grid[j][i]).append(",");
            }
            rowMap.put(rowKey.toString(), rowMap.getOrDefault(rowKey.toString(), 0) + 1);
            colMap.put(colKey.toString(), colMap.getOrDefault(colKey.toString(), 0) + 1);
        }

        int count = 0;
        for (Map.Entry<String, Integer> rowEntry : rowMap.entrySet()) {
            String key = rowEntry.getKey();
            int rowCount = rowEntry.getValue();
            count += rowCount * colMap.getOrDefault(key, 0);
        }

        return count;
    }
}

