import java.util.StringTokenizer;

public class Main {
    private static BufferedReader br;
    private static PrintWriter pw;
    private static StringTokenizer st;

    private static String nextToken() throws IOException {
        while (st == null || !st.hasMoreTokens()) {
            String line = br.readLine();
            if (line == null) throw new IOException("Unexpected end of input");
            st = new StringTokenizer(line);
        }
        return st.nextToken();
    }

    private static int nextInt() {
        return Integer.parseInt(nextTokenSafely());
    }

    private static long nextLong() {
        return Long.parseLong(nextTokenSafely());
    }

    private static String nextTokenSafely() {
        try {
            return nextToken();
        } catch (IOException e) {
            pw.println("Error reading token: " + e.getMessage());
            System.exit(1);
            return null; // Unreachable, just to satisfy compiler
        }
    }

    public static void main(String[] args) {
        try {
            br = new BufferedReader(new InputStreamReader(System.in));
            pw = new PrintWriter(System.out);
            execute();
        } catch (IOException e) {
            pw.println("Error during initialization: " + e.getMessage());
        } finally {
            pw.close();
        }
    }

    private static void execute() {
        int testCases = nextInt();
        while (testCases-- > 0) {
            processTestCase();
        }
    }

    private static void processTestCase() {
        int n = nextInt();
        int[][] pairs = new int[n][2];
        int[] countA = new int[n];
        int[] countB = new int[n];
        long result = 0;

        for (int i = 0; i < n; i++) {
            pairs[i][0] = nextInt() - 1;
            pairs[i][1] = nextInt() - 1;
            countA[pairs[i][0]]++;
            countB[pairs[i][1]]++;
        }

        result += countDistinctCombinations(n, pairs);
        result -= countSameCombinations(countA, countB, n);
        pw.println(result);
    }

    private static long countDistinctCombinations(int n, int[][] pairs) {
        long count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    if (distinctCondition(pairs, i, j, k)) {
                        count++;
                    }
                }
            }
        }
        return count;
    }

    private static boolean distinctCondition(int[][] pairs, int i, int j, int k) {
        return (pairs[i][0] != pairs[j][0] && pairs[i][0] != pairs[k][0] && pairs[j][0] != pairs[k][0]) ||
               (pairs[i][1] != pairs[j][1] && pairs[i][1] != pairs[k][1] && pairs[j][1] != pairs[k][1]);
    }

    private static long countSameCombinations(int[] countA, int[] countB, int n) {
        long sameCombinationCount = 0;
        for (int i = 0; i < n; i++) {
            sameCombinationCount += combinations(countA[i]);
            sameCombinationCount += combinations(countB[i]);
        }
        return sameCombinationCount;
    }

    private static long combinations(int count) {
        if (count < 3) return 0;
        return (long) count * (count - 1) * (count - 2) / 6;
    }
}

