import java.util.Arrays;
import java.util.InputMismatchException;
import java.util.Scanner;

public class Main {
    private static final int ARRAY_SIZE = 6;

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int[] a = new int[ARRAY_SIZE];
            readArray(scanner, a);

            int n = readSize(scanner);
            if (n <= 0) {
                System.err.println("Error: The size of the second array must be positive.");
                return;
            }

            int[] b = new int[n];
            readArray(scanner, b);

            int result = calculateMinFretDifference(a, b);
            System.out.println(result);
        } catch (InputMismatchException e) {
            System.err.println("Error: Invalid input. Please enter integers.");
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static void readArray(Scanner scanner, int[] array) {
        for (int i = 0; i < array.length; i++) {
            array[i] = scanner.nextInt();
        }
    }

    private static int readSize(Scanner scanner) {
        return scanner.nextInt();
    }

    private static int calculateMinFretDifference(int[] a, int[] b) {
        int result = Integer.MAX_VALUE;
        Arrays.sort(a);
        for (int fretValue : a) {
            int minFret = Integer.MAX_VALUE;
            int maxFret = Integer.MIN_VALUE;
            for (int note : b) {
                int fret = note - fretValue;
                minFret = Math.min(minFret, fret);
                maxFret = Math.max(maxFret, fret);
            }
            result = Math.min(result, maxFret - minFret);
        }
        return result;
    }
}

