public class MedianSubarrayCounter {
    public int countSubarraysWithMedian(int[] nums, int k) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array must not be null or empty.");
        }

        int n = nums.length;
        int[] prefixCount = new int[n + 1];

        // Build prefix sum array for elements <= k
        for (int i = 0; i < n; i++) {
            prefixCount[i + 1] = prefixCount[i] + (nums[i] <= k ? 1 : 0);
        }

        int totalCount = 0;
        Map<Integer, Integer> balanceMap = new HashMap<>();
        balanceMap.put(0, 1); // Initial state for balance

        for (int i = 0; i < n; i++) {
            try {
                int balance = prefixCount[i + 1] - (i + 1) / 2;

                // Count valid subarrays ending at index i
                totalCount += balanceMap.getOrDefault(balance, 0);

                // Update the balance in the map
                balanceMap.put(balance, balanceMap.getOrDefault(balance, 0) + 1);
            } catch (Exception e) {
                logError("Error processing index " + i + ": " + e.getMessage());
            }
        }

        return totalCount;
    }

    private void logError(String message) {
        // Simplified logging method
        System.err.println("[ERROR] " + message);
    }

    public static void main(String[] args) {
        MedianSubarrayCounter counter = new MedianSubarrayCounter();
        int[] nums = {1, 3, 2, 4, 5};
        int k = 3;

        try {
            int result = counter.countSubarraysWithMedian(nums, k);
            System.out.println("Count of subarrays with median " + k + ": " + result);
        } catch (IllegalArgumentException e) {
            System.err.println("[ERROR] " + e.getMessage());
        }
    }
}

