import java.util.StringTokenizer;

public class Main {
    private static final long MODULO = 1_000_000_007L;
    private static final int POWER_LIMIT = 42;
    private static final long[] powers = new long[POWER_LIMIT];

    static {
        powers[0] = 1;
        for (int i = 1; i < POWER_LIMIT; i++) {
            powers[i] = (2 * powers[i - 1]) % MODULO;
        }
    }

    public static long calculateAnswer(long m) {
        if (m < 1) {
            throw new IllegalArgumentException("Input must be greater than 0");
        }

        int numSevens = (int) ((m - 1) / 7);
        int numSixes = (int) (((m - 1) % 7) / 6);

        long answer = (numSevens + 1L) * powers[25] % MODULO;
        answer = (answer + numSixes * powers[26]) % MODULO;

        return answer;
    }

    public static void main(String[] args) {
        try (BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
             PrintWriter out = new PrintWriter(System.out)) {

            int numberOfCases = Integer.parseInt(in.readLine());
            for (int i = 0; i < numberOfCases; i++) {
                StringTokenizer st = new StringTokenizer(in.readLine());
                while (st.hasMoreTokens()) {
                    long m = Long.parseLong(st.nextToken());
                    out.println(calculateAnswer(m));
                }
            }
        } catch (IOException | NumberFormatException e) {
            System.err.println("Error processing input: " + e.getMessage());
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
        }
    }
}

