        List<Object> mergedDiscs = new ArrayList<>(discs);
        if (a < 0 || b < 0 || a >= discs.size() / 2 || b >= discs.size() / 2) {
            throw new IllegalArgumentException("Invalid tower indices specified.");
        }

        StringBuilder s = new StringBuilder();
        s.append(mergedDiscs.get(a)).append(mergedDiscs.get(b));
        mergedDiscs.set(a + mergedDiscs.size() / 2, s.reverse().toString());
        for (int i = 1; i < s.length(); i++) {
            mergedDiscs.set(b + mergedDiscs.size() / 2 + i, s.charAt(i));
        }

        return mergedDiscs.subList(0, mergedDiscs.size() / 2 + 1);
    }

    public static List<Integer> difficultyOfMerges(List<Object> discs, List<int[]> queries) {
        List<Integer> difficulties = new ArrayList<>();
        difficulties.add(discs.size() - 1);

        for (int i = queries.size() - 1; i >= 0; i--) {
            int[] query = queries.get(i);
            int a = query[0] - 1;
            int b = query[1] - 1;
            List<Object> newDiscs = mergeTowers(discs, a, b);
            int distance = discs.size() - newDiscs.size();
            difficulties.add(distance);
            discs = newDiscs;
        }

        return reverseList(difficulties);
    }

    private static List<Integer> reverseList(List<Integer> list) {
        List<Integer> reversed = new ArrayList<>();
        for (int i = list.size() - 1; i >= 0; i--) {
            reversed.add(list.get(i));
        }
        return reversed;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter number of towers and discs: ");
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        List<List<Integer>> towers = new ArrayList<>();

        System.out.println("Enter tower details: ");
        for (int i = 0; i < n; i++) {
            List<Integer> tower = new ArrayList<>();
            int discsCount = scanner.nextInt();
            for (int j = 0; j < discsCount; j++) {
                tower.add(scanner.nextInt());
            }
            towers.add(tower);
        }

        List<Object> discs = new ArrayList<>();
        for (int i = 0; i < towers.size(); i++) {
            for (Integer radius : towers.get(i)) {
                discs.add(radius);
            }
        }

        List<int[]> queries = new ArrayList<>();
        System.out.println("Enter queries: ");
        for (int i = 0; i < m - 1; i++) {
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            queries.add(new int[]{a, b});
        }

        List<Integer> results = difficultyOfMerges(discs, queries);
        System.out.println("Difficulties: " + results);

        scanner.close();
    }
}

