        this.val = 0;
        this.left = null;
        this.right = null;
    }

    TreeNode(int x) {
        this.val = x;
        this.left = null;
        this.right = null;
    }

    TreeNode(int x, TreeNode left, TreeNode right) {
        this.val = x;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    private int longestPath;

    public int longestUnivaluePath(TreeNode root) {
        longestPath = 0;
        findLongestUnivaluePath(root, -1);
        return longestPath;
    }

    private int findLongestUnivaluePath(TreeNode node, int parentValue) {
        if (node == null) {
            return 0;
        }

        int leftPath = findLongestUnivaluePath(node.left, node.val);
        int rightPath = findLongestUnivaluePath(node.right, node.val);

        int currentPath = 0;
        if (node.val == parentValue) {
            currentPath = 1 + leftPath + rightPath;
        }

        longestPath = Math.max(longestPath, currentPath);
        return (node.val == parentValue) ? Math.max(leftPath, rightPath) + 1 : 0;
    }
}

