public class XorSubsequence {
    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in))) {
            int testCases = readInteger(br);
            while (testCases-- > 0) {
                int length = readInteger(br);
                int[] array = readIntegerArray(br, length);
                int maxLength = computeMaxXorSubsequenceLength(array);
                System.out.println(maxLength);
            }
        } catch (IOException e) {
            System.err.println("Error reading input: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.err.println("Invalid number format: " + e.getMessage());
        }
    }

    private static int readInteger(BufferedReader br) throws IOException {
        String line = br.readLine();
        if (line == null || line.isEmpty()) {
            throw new NumberFormatException("Input cannot be null or empty");
        }
        return Integer.parseInt(line.trim());
    }

    private static int[] readIntegerArray(BufferedReader br, int length) throws IOException {
        String[] input = br.readLine().split("\\s+");
        if (input.length != length) {
            throw new IllegalArgumentException("Input array length mismatch");
        }
        return Arrays.stream(input).mapToInt(Integer::parseInt).toArray();
    }

    private static int computeMaxXorSubsequenceLength(int[] array) {
        int maxLength = 1;
        int currentLength = 1;

        for (int i = 1; i < array.length; i++) {
            int xorCurrent = array[i - 1] ^ array[i];
            int xorNext = array[i] ^ array[i - 1];
            if (xorCurrent < xorNext) {
                currentLength++;
            } else {
                maxLength = Math.max(maxLength, currentLength);
                currentLength = 1;
            }
        }

        return Math.max(maxLength, currentLength);
    }
}

