import java.util.Arrays;

class BookMyShow {
    private final int maxRow;
    private final int maxSeatsPerRow;
    private final int[][] rows;

    public BookMyShow(int n, int m) {
        this.maxRow = n;
        this.maxSeatsPerRow = m;
        this.rows = new int[maxRow + 1][m];
        initializeRows();
    }

    private void initializeRows() {
        for (int i = 0; i <= maxRow; i++) {
            Arrays.fill(rows[i], -1); // Initialize all seats to -1 (unoccupied)
        }
    }

    public int[] gather(int k, int maxRow) {
        if (k <= 0 || maxRow < 0 || maxRow > this.maxRow) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }

        int maxSeatPos = -1;
        for (int row = Math.min(this.maxRow, maxRow); row >= 0; row--) {
            int maxIndex = findFirstFreeSeat(row);
            if (maxIndex != -1 && maxIndex + k <= maxSeatsPerRow) {
                maxSeatPos = row * maxSeatsPerRow + maxIndex;
                break;
            }
        }

        if (maxSeatPos < 0) {
            return new int[0]; // No seats available
        }

        reserveSeats(maxSeatPos, k);
        return new int[]{maxSeatPos / maxSeatsPerRow, maxSeatPos % maxSeatsPerRow};
    }

    public boolean scatter(int k, int maxRow) {
        if (k <= 0 || maxRow < 0 || maxRow > this.maxRow) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }

        int[] result = new int[k];
        int count = 0;

        for (int row = Math.min(this.maxRow, maxRow); row >= 0; row--) {
            for (int i = 0; i < maxSeatsPerRow; i++) {
                if (rows[row][i] >= 0 && (count == 0 || rows[row][i] == result[count - 1] + 1)) {
                    if (count < k) {
                        result[count++] = rows[row][i];
                    } else {
                        break;
                    }
                }
                if (count == k) {
                    break;
                }
            }
            if (count == k) {
                break;
            }
        }

        if (count == k) {
            for (int seat : result) {
                rows[seat / maxSeatsPerRow][seat % maxSeatsPerRow] = -1; // Mark seats as occupied
            }
            return true;
        }
        return false;
    }

    private int findFirstFreeSeat(int row) {
        for (int i = 0; i < maxSeatsPerRow; i++) {
            if (rows[row][i] == -1) {
                return i; // return the first free seat index
            }
        }
        return -1; // No free seat found
    }

    private void reserveSeats(int maxSeatPos, int k) {
        int row = maxSeatPos / maxSeatsPerRow;
        for (int i = 0; i < k; i++) {
            rows[row][maxSeatPos % maxSeatsPerRow + i] = row * maxSeatsPerRow + maxSeatPos % maxSeatsPerRow + i; // Reserve seats
        }
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Please provide valid input: <numRows> <numSeatsPerRow>");
            return;
        }

        try {
            int n = Integer.parseInt(args[0]);
            int m = Integer.parseInt(args[1]);
            BookMyShow booking = new BookMyShow(n, m);
            int[] res1 = booking.gather(4, 0);
            int[] res2 = booking.gather(2, 0);
            boolean res3 = booking.scatter(5, 1);
            boolean res4 = booking.scatter(5, 1);
            System.out.println(Arrays.toString(res1) + " " + Arrays.toString(res2) + " " + res3 + " " + res4);
        } catch (NumberFormatException e) {
            System.err.println("Invalid number format in input.");
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
        }
    }
}

