import common.TreeNode;
import java.util.ArrayList;
import java.util.List;
import java.util.PriorityQueue;

public class Solution {

    public List<TreeNode> smallestAndLargestValue(TreeNode root, int target) {
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        PriorityQueue<Integer> maxHeap = new PriorityQueue<>((a, b) -> b - a);
        List<TreeNode> result = new ArrayList<>();

        if (root == null) {
            return List.of(new TreeNode(-1), new TreeNode(-1));
        }

        TreeNode node = root;
        List<TreeNode> stack = new ArrayList<>();

        while (node != null || !stack.isEmpty()) {
            while (node != null) {
                minHeap.offer(node.val);
                maxHeap.offer(node.val);
                stack.add(node);
                node = node.left;
            }

            if (!minHeap.isEmpty() && minHeap.peek() <= target) {
                int nextNode = minHeap.poll();
                node = stack.remove(stack.size() - 1);
                if (nextNode != node.val) {
                    stack.add(node);
                    node = node.right;
                }
            } else if (!maxHeap.isEmpty() && maxHeap.peek() >= target) {
                int nextNode = maxHeap.poll();
                node = stack.remove(stack.size() - 1);
                if (nextNode != node.val) {
                    stack.add(node);
                    node = node.right;
                }
            } else {
                return List.of(new TreeNode(-1), new TreeNode(-1));
            }
        }
        result.add(new TreeNode(maxHeap.peek()));
        result.add(new TreeNode(-minHeap.peek()));
        return result;
    }

    public List<List<Integer>> binaryTreeIndices(TreeNode root, int[] arr) {
        List<List<Integer>> ans = new ArrayList<>();
        for (int val : arr) {
            List<TreeNode> idx = smallestAndLargestValue(root, val);
            ans.add(List.of(idx.get(0).val, idx.get(1).val));
        }
        return ans;
    }

    public TreeNode searchBST1(TreeNode root, int val) {
        while (root != null) {
            if (root.val == val) {
                return root;
            } else if (root.val < val) {
                root = root.right;
            } else {
                root = root.left;
            }
        }
        return null;
    }

    public TreeNode searchBST2(TreeNode root, int val) {
        if (root == null) {
            return null;
        } else if (root.val == val) {
            return root;
        } else if (root.val < val) {
            return searchBST2(root.right, val);
        } else {
            return searchBST2(root.left, val);
        }
    }

    public TreeNode searchBST3(TreeNode root, int val) {
        TreeNode cur = root;
        while (cur != null) {
            if (cur.val == val) {
                return cur;
            } else if (cur.val < val) {
                cur = cur.right;
            } else {
                cur = cur.left;
            }
        }
        return null;
    }

    public int getMin(TreeNode node) {
        while (node.left != null) {
            node = node.left;
        }
        return node.val;
    }

    public int getMax(TreeNode node) {
        while (node.right != null) {
            node = node.right;
        }
        return node.val;
    }

    public TreeNode searchBST(TreeNode root, int val) {
        TreeNode cur = root;
        TreeNode prev = null;

        while (cur != null) {
            if (cur.val == val) {
                return cur;
            } else if (cur.val < val) {
                prev = cur;
                cur = cur.right;
            } else {
                prev = cur;
                cur = cur.left;
            }
        }

        return (prev != null) ? (prev.val < val ? new TreeNode(getMin(prev)) : new TreeNode(getMax(prev))) : null;
    }

    public TreeNode searchBST4(TreeNode root, int val) {
        TreeNode ans = null;

        while (root != null) {
            if (root.val == val) {
                ans = root;
                break;
            } else if (root.val < val) {
                root = root.right;
            } else {
                root = root.left;
            }
        }
        return ans;
    }

    public int leftMaxDepth(TreeNode root) {
        if (root == null) {
            return 0;
        }

        List<TreeNode> dp = new ArrayList<>();
        dp.add(root);
        int maxDepth = 0;

        while (!dp.isEmpty()) {
            List<TreeNode> nextDp = new ArrayList<>();
            for (TreeNode node : dp) {
                if (node.left != null) {
                    nextDp.add(node.left);
                }
            }
            maxDepth++;
            dp = nextDp;
        }
        return maxDepth;
    }
}

