import java.io.OutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.io.InputStreamReader;
import java.util.StringTokenizer;
import java.util.BufferedReader;

public class Main {

    public static void main(String[] args) {
        try (InputStream inputStream = System.in; 
             OutputStream outputStream = System.out; 
             PrintWriter out = new PrintWriter(outputStream)) {
            InputReader in = new InputReader(inputStream);
            TaskB solver = new TaskB();
            solver.solve(1, in, out);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    static class TaskB {
        private int n;

        public void solve(int testNumber, InputReader in, PrintWriter out) {
            try {
                n = in.nextInt();
                while (n > 1) {
                    int answer = handleGuesses(out, in);
                    if (answer == 0) break; // early exit if situation is invalid
                }
            } catch (Exception e) {
                out.println("Error in processing: " + e.getMessage());
            }
        }

        private int handleGuesses(PrintWriter out, InputReader in) {
            int guessesRemaining = 9;
            int current = 0;

            while (guessesRemaining > 0 && n > 1) {
                int response = getNumber(out, in);
                if (response != 0) {
                    current = response;
                } else {
                    current = (n - 1) * ((n - 1) / 2) + (current % (n - 1));
                }
                guessesRemaining--;
            }
            return current;
        }

        private int getNumber(PrintWriter out, InputReader in) {
            int total = 0;
            int maxGuess = n - 1;

            for (int guessCount = 0; guessCount < n - 1; guessCount++) {
                out.println("+ " + maxGuess);
                out.flush();
                try {
                    total += in.nextInt();
                } catch (NumberFormatException e) {
                    out.println("Invalid response received.");
                    return 0;
                }
                maxGuess--;
                if (total % n == 0) {
                    total /= n;
                    out.println("! " + total);
                    out.flush();
                }
            }
            return total;
        }
    }

    static class InputReader {
        private final BufferedReader reader;
        private StringTokenizer tokenizer;

        public InputReader(InputStream stream) {
            reader = new BufferedReader(new InputStreamReader(stream), 32768);
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException("Input reading error: " + e.getMessage());
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }
    }
}

