const minRepTileLen = function(a, b) {
    if (typeof a !== 'string' || typeof b !== 'string') {
        throw new TypeError('Both a and b must be strings.');
    }

    const m = b.length;
    const n = a.length;
    const table = new Array(m + 1).fill(Number.MAX_SAFE_INTEGER);
    table[0] = 0;

    for (let i = 1; i <= m; i++) {
        let len = 0;

        for (let j = 0; j < n; j++) {
            const start = len < n ? 0 : table[0];
            const match = (len < m && a[j % n] === b[len])
                ? table[len]
                : Math.max(...Array.from(table, (t, tIndex) => (j < n && t < m && a[(j + tIndex) % n] === b[tIndex]) ? (tIndex + 1) : Number.MIN_SAFE_INTEGER));

            const newIndex = (len < match)
                ? Math.max(match + (j - 1) / m * (j % n < m - i ? 1 : -(match > m ? match : match + (n - j + start))) : match);

            if (newIndex <= m) {
                table[len] = Math.min(table[len], (newIndex > m ? 0 : 1) + newIndex);
            }

            len = newIndex;
        }
    }

    if (table[m] === Number.MAX_SAFE_INTEGER) {
        return -1;
    }

    return table[m];
};

