import java.io.IOException;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Scanner;

public class MainClass {
    private static final int MAX_FIB_INDEX = 100;
    private static final BigInteger MODULO = new BigInteger("1000000007");

    public static void main(final String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            BigInteger[] fibonacciNumbers = generateFibonacciNumbers();
            int testCases = validateInput(scanner);
            for (int caseIndex = 0; caseIndex < testCases; caseIndex++) {
                processTestCase(scanner, fibonacciNumbers);
            }
        } catch (IOException | NumberFormatException e) {
            System.err.println("Error reading input: " + e.getMessage());
        }
    }

    private static BigInteger[] generateFibonacciNumbers() {
        BigInteger[] fib = new BigInteger[MAX_FIB_INDEX + 1];
        fib[0] = BigInteger.ZERO;
        fib[1] = BigInteger.ONE;
        for (int i = 2; i <= MAX_FIB_INDEX; i++) {
            fib[i] = fib[i - 1].add(fib[i - 2]);
        }
        return fib;
    }

    private static int validateInput(Scanner scanner) {
        if (!scanner.hasNextInt()) {
            throw new NumberFormatException("Expected number of test cases.");
        }
        int t = scanner.nextInt();
        if (t <= 0) {
            throw new IllegalArgumentException("Number of test cases must be positive.");
        }
        return t;
    }

    private static void processTestCase(Scanner scanner, BigInteger[] fibonacciNumbers) {
        if (!scanner.hasNextInt() || !scanner.hasNextInt()) {
            throw new NumberFormatException("Invalid matrix dimensions.");
        }

        int n = scanner.nextInt();
        int m = scanner.nextInt();

        if (n <= 0 || m <= 0) {
            throw new IllegalArgumentException("Matrix dimensions must be positive.");
        }

        BigInteger[][] matrix = new BigInteger[n][m];
        fillMatrix(scanner, matrix, fibonacciNumbers, n, m);

        BigInteger result = computeMatrixSum(matrix, n, m);
        System.out.println(result.mod(MODULO));
    }

    private static void fillMatrix(Scanner scanner, BigInteger[][] matrix, BigInteger[] fibonacciNumbers, int n, int m) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (!scanner.hasNextInt()) {
                    throw new NumberFormatException("Invalid matrix entry.");
                }
                int fibIndex = scanner.nextInt() - (i + j);
                if (fibIndex < 0 || fibIndex > MAX_FIB_INDEX) {
                    throw new IndexOutOfBoundsException("Fibonacci index out of bounds: " + fibIndex);
                }
                matrix[i][j] = fibonacciNumbers[fibIndex];
            }
        }
    }

    private static BigInteger computeMatrixSum(BigInteger[][] matrix, int n, int m) {
        BigInteger totalSum = BigInteger.ZERO;

        totalSum = totalSum.add(matrix[0][0]).add(matrix[0][1]).add(matrix[1][0]).add(matrix[1][1]);

        for (int i = 1; i < n; i++) {
            totalSum = totalSum.add(matrix[i][0]);
        }
        for (int j = 1; j < m; j++) {
            totalSum = totalSum.add(matrix[0][j]);
        }
        for (int i = 1; i < n; i++) {
            for (int j = 1; j < m; j++) {
                totalSum = totalSum.add(matrix[i][j]);
            }
        }
        return totalSum;
    }
}

import java.util.Arrays;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Solution {
    private static final Logger logger = Logger.getLogger(Solution.class.getName());

    public boolean makesquare(int[] matchsticks) {
        if (matchsticks == null || matchsticks.length < 4) {
            logger.log(Level.WARNING, "Invalid input: matchsticks array is null or has less than 4 elements.");
            return false;
        }

        int totalLength = Arrays.stream(matchsticks).sum();
        if (totalLength % 4 != 0) {
            logger.log(Level.INFO, "Total length is not divisible by 4.");
            return false;
        }

        int sideLength = totalLength / 4;
        Arrays.sort(matchsticks);
        if (matchsticks[matchsticks.length - 1] > sideLength) {
            logger.log(Level.WARNING, "A matchstick is longer than the side length.");
            return false;
        }

        boolean[] used = new boolean[matchsticks.length];
        boolean result = dfs(matchsticks, used, 0, 0, sideLength, 0);

        if (result) {
            logger.log(Level.INFO, "A square can be formed with the matchsticks.");
        } else {
            logger.log(Level.INFO, "A square cannot be formed with the matchsticks.");
        }

        return result;
    }

    private boolean dfs(int[] matchsticks, boolean[] used, int currentLength, int start, int sideLength, int sidesFormed) {
        if (sidesFormed == 3) {
            return true;
        }

        if (currentLength == sideLength) {
            return dfs(matchsticks, used, 0, 0, sideLength, sidesFormed + 1);
        }

        for (int i = start; i < matchsticks.length; i++) {
            if (!used[i] && currentLength + matchsticks[i] <= sideLength) {
                used[i] = true;
                if (dfs(matchsticks, used, currentLength + matchsticks[i], i + 1, sideLength, sidesFormed)) {
                    return true;
                }
                used[i] = false;
            }
        }

        return false;
    }
}

import java.util.HashMap;
import java.util.Map;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FruitBasket {
    private static final Logger logger = Logger.getLogger(FruitBasket.class.getName());
    private static final int MAX_BASKET_SIZE = 2;

    public int totalFruit(int[] fruits) {
        if (fruits == null || fruits.length == 0) {
            logger.log(Level.WARNING, "Input fruit array is null or empty.");
            return 0;
        }

        Map<Integer, Integer> basket = new HashMap<>();
        int left = 0, maxFruits = 0;

        for (int right = 0; right < fruits.length; right++) {
            int currentFruit = fruits[right];
            basket.put(currentFruit, basket.getOrDefault(currentFruit, 0) + 1);

            while (basket.size() > MAX_BASKET_SIZE) {
                int leftFruit = fruits[left];
                basket.put(leftFruit, basket.get(leftFruit) - 1);
                if (basket.get(leftFruit) == 0) {
                    basket.remove(leftFruit);
                }
                left++;
            }

            maxFruits = Math.max(maxFruits, right - left + 1);
        }

        logger.log(Level.INFO, "Max fruits collected: {0}", maxFruits);
        return maxFruits;
    }
}

class Solution {
    public int maxScoreWords(String[] words, char[] letters, int[] score) {
        if (words == null || letters == null || score == null) {
            throw new IllegalArgumentException("Input cannot be null");
        }
        return calculateMaxScore(words, letters, score, 0, 0, new int[26]);
    }

    private int calculateMaxScore(String[] words, char[] letters, int[] score, int index, int currentScore, int[] letterCount) {
        if (index == words.length) {
            return currentScore;
        }

        int maxScore = currentScore;
        int[] letterCountCopy;

        // Option 1: Include the current word
        try {
            letterCountCopy = letterCount.clone();
            int includeScore = calculateWordScore(words[index], score, letterCountCopy);
            if (includeScore >= 0) {
                maxScore = Math.max(maxScore,
                                    calculateMaxScore(words, letters, score, index + 1, currentScore + includeScore, letterCountCopy));
            }
        } catch (IllegalArgumentException e) {
            // Logging can be added here if needed
        }

        // Option 2: Exclude the current word
        maxScore = Math.max(maxScore, calculateMaxScore(words, letters, score, index + 1, currentScore, letterCount));

        return maxScore;
    }

    private int calculateWordScore(String word, int[] score, int[] letterCount) {
        int wordScore = 0;
        for (char c : word.toCharArray()) {
            int charIndex = c - 'a';
            if (letterCount[charIndex] >= letterCount.length) {
                return -1; // Not enough letters to form the word
            }
            wordScore += score[charIndex];
            letterCount[charIndex]++;
        }
        return wordScore;
    }
}

public class DistanceValueFinder {

    public int findTheDistanceValue(List<Integer> arr1, List<Integer> arr2, int d) {
        if (arr1 == null || arr2 == null) {
            throw new IllegalArgumentException("Input arrays cannot be null");
        }
        if (d < 0) {
            throw new IllegalArgumentException("Distance 'd' cannot be negative");
        }

        Collections.sort(arr2);
        int ans = 0;
        int sizeArr2 = arr2.size();

        for (int value : arr1) {
            if (isInDistance(value, arr2, d, sizeArr2)) {
                ans++;
            }
        }
        return ans;
    }

    private boolean isInDistance(int value, List<Integer> arr2, int d, int sizeArr2) {
        int index = Collections.binarySearch(arr2, value);

        if (index < 0) {
            index = -(index + 1);
        }

        boolean isValid = false;

        if (index == 0) {
            isValid = (arr2.get(index) - d) > value;
        } else if (index == sizeArr2) {
            isValid = (value > arr2.get(index - 1) + d);
        } else {
            isValid = (value > arr2.get(index - 1) + d) && (arr2.get(index) - d) > value; 
        }

        return isValid;
    }
}

