import java.util.Arrays;

public class VowelStringCount {
    private static final char[] VOWELS = {'a', 'e', 'i', 'o', 'u'};

    public static void main(String[] args) {
        try {
            String[] words = {"aba", "bcb", "ece", "aa", "e"};
            int[][] queries = {{0, 2}, {1, 4}, {1, 1}};
            int[] results = countVowelWords(words, queries);
            System.out.println(Arrays.toString(results));
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    public static int[] countVowelWords(String[] words, int[][] queries) {
        validateInput(words, queries);
        int[] ans = new int[queries.length];
        int[] wordCounts = new int[words.length];

        preprocessWords(words, wordCounts);

        for (int i = 0; i < queries.length; i++) {
            int li = queries[i][0];
            int ri = queries[i][1];
            ans[i] = getCountInRange(wordCounts, li, ri);
        }

        return ans;
    }

    private static void validateInput(String[] words, int[][] queries) {
        if (words == null || queries == null) {
            throw new IllegalArgumentException("Words and queries must not be null");
        }
        if (queries.length == 0) {
            throw new IllegalArgumentException("Queries array is empty");
        }
        for (int[] query : queries) {
            if (query.length != 2 || 
                query[0] < 0 || query[1] >= words.length || 
                query[0] > query[1]) {
                throw new IllegalArgumentException("Invalid query: " + Arrays.toString(query));
            }
        }
    }

    private static void preprocessWords(String[] words, int[] wordCounts) {
        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (startsWithVowel(word) && endsWithVowel(word)) {
                wordCounts[i]++;
            }
        }
    }

    private static boolean startsWithVowel(String word) {
        if (word == null || word.isEmpty()) return false;
        char firstChar = Character.toLowerCase(word.charAt(0));
        return Arrays.binarySearch(VOWELS, firstChar) >= 0;
    }

    private static boolean endsWithVowel(String word) {
        if (word == null || word.isEmpty()) return false;
        char lastChar = Character.toLowerCase(word.charAt(word.length() - 1));
        return Arrays.binarySearch(VOWELS, lastChar) >= 0;
    }

    private static int getCountInRange(int[] wordCounts, int li, int ri) {
        int totalCount = 0;
        for (int i = li; i <= ri; i++) {
            totalCount += wordCounts[i];
        }
        return totalCount;
    }
}

class Solution {
    public int maxSumRangeQuery(int[] nums, int[][] requests) {
        if (nums == null || nums.length == 0 || requests == null || requests.length == 0) {
            throw new IllegalArgumentException("Input arrays must not be null or empty.");
        }

        int length = nums.length;
        int[][] dp = new int[length + 1][length + 1];

        for (int[] request : requests) {
            if (request.length != 2 || request[0] < 0 || request[1] >= length || request[0] > request[1]) {
                throw new IllegalArgumentException("Invalid request range.");
            }
            dp[request[0] + 1][request[1] + 2]++;
        }

        long[] ans = new long[length + 1];
        long[] prefixSum = new long[length + 1];
        int mod = 1000000007;

        for (int i = 1; i < dp.length; i++) {
            prefixSum[i] = prefixSum[i - 1] + dp[i][i];
            ans[i] = Math.max(prefixSum[i] >> 1, ans[i - 1]);
        }

        long maxSum = 0;
        for (int i = 0; i < length; i++) {
            maxSum = (maxSum + (long) nums[i] * ans[i]) % mod;
        }

        return (int) maxSum;
    }
}

