public class Main {
    public static int calculateDistance(int[] arr) {
        if (arr == null || arr.length == 0) {
            throw new IllegalArgumentException("Input array must not be null or empty.");
        }

        int[] destination = new int[arr.length + 1];
        int totalDistance = 0, from = 1;
        destination[0] = arr[0];
        Map<Integer, Integer> indexMap = new HashMap<>();

        for (int i = 1; i < arr.length; i++) {
            if (!indexMap.containsKey(arr[i] - 1)) {
                indexMap.put(arr[i] - 1, i);
            }
        }

        Map<Integer, Integer> usedIndices = new HashMap<>();
        for (int i = 1; i <= arr.length; i++) {
            if (!indexMap.containsKey(i - 1)) {
                continue;
            }
            int nextIndex = indexMap.get(i - 1);
            if (!usedIndices.containsKey(nextIndex)) {
                totalDistance += i - from;
                from = i + 1;
            }
            usedIndices.put(nextIndex, 0);
        }

        return totalDistance;
    }

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = readPositiveInteger(scanner);
