private boolean[] visited;
private Stack<Integer> stack;

public boolean[] checkIfPrerequisite(int numCourses, int[][] prerequisites, int[][] queries) {
    if (numCourses <= 0 || prerequisites == null || queries == null) {
        throw new IllegalArgumentException("Invalid input parameters.");
    }

    visited = new boolean[numCourses];
    stack = new Stack<>();
    Map<Integer, Integer>[] graph = buildGraph(numCourses, prerequisites);
    boolean[] results = new boolean[queries.length];

    for (int i = 0; i < queries.length; i++) {
        results[i] = performDFS(numCourses, queries[i][0], queries[i][1], graph);
        resetVisited(numCourses);
    }

    return results;
}

private boolean performDFS(int numCourses, int current, int target, Map<Integer, Integer>[] graph) {
    if (current == target) {
        return true;
    }

    visited[current] = true;
    stack.push(current);

    for (Integer neighbor : graph[current].keySet()) {
        if (!visited[neighbor]) {
            if (performDFS(numCourses, neighbor, target, graph)) {
                return true;
            }
        } else if (stack.contains(neighbor)) {
            return true;
        }
    }

    stack.pop();
    return false;
}

public Map<Integer, Integer>[] buildGraph(int numCourses, int[][] prerequisites) {
    Map<Integer, Integer>[] graph = new HashMap[numCourses];
    for (int i = 0; i < numCourses; i++) {
        graph[i] = new HashMap<>();
    }
    for (int[] prerequisite : prerequisites) {
        if (prerequisite.length < 2) {
            throw new IllegalArgumentException("Invalid prerequisite pair.");
        }
        graph[prerequisite[1]].put(prerequisite[0], 1);
    }
    return graph;
}

