import java.util.HashMap;
import java.util.TreeMap;
import java.util.NoSuchElementException;

public class StockPrice {
    private final HashMap<Integer, Integer> timePrice;
    private final TreeMap<Integer, Integer> priceCount;
    private int current;

    public StockPrice() {
        this.timePrice = new HashMap<>();
        this.priceCount = new TreeMap<>();
        this.current = 0;
    }

    public void update(int timestamp, int price) {
        if (timestamp <= 0) {
            throw new IllegalArgumentException("Timestamp must be positive.");
        }

        if (timePrice.containsKey(timestamp)) {
            int oldPrice = timePrice.get(timestamp);
            if (priceCount.containsKey(oldPrice)) {
                int count = priceCount.get(oldPrice);
                if (count == 1) {
                    priceCount.remove(oldPrice);
                } else {
                    priceCount.put(oldPrice, count - 1);
                }
            }
        }

        timePrice.put(timestamp, price);
        priceCount.put(price, priceCount.getOrDefault(price, 0) + 1);
        current = Math.max(current, timestamp);
    }

    public int current() {
        if (timePrice.isEmpty()) {
            throw new NoSuchElementException("No current stock price available.");
        }
        return timePrice.get(current);
    }

    public int maximum() {
        if (priceCount.isEmpty()) {
            throw new NoSuchElementException("No prices available to determine maximum.");
        }
        return priceCount.lastKey();
    }

    public int minimum() {
        if (priceCount.isEmpty()) {
            throw new NoSuchElementException("No prices available to determine minimum.");
        }
        return priceCount.firstKey();
    }
}

