import java.util.*;

class Main {
    public static boolean isPossible(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array is null or empty");
        }

        Map<Integer, PriorityQueue<Integer>> frequencyMap = new HashMap<>();

        for (int num : nums) {
            frequencyMap.putIfAbsent(num, new PriorityQueue<>());

            PriorityQueue<Integer> previousQueue = frequencyMap.get(num - 1);
            if (previousQueue != null && !previousQueue.isEmpty()) {
                int length = previousQueue.poll();
                if (previousQueue.isEmpty()) {
                    frequencyMap.remove(num - 1);
                }
                frequencyMap.get(num).offer(length + 1);
            } else {
                frequencyMap.get(num).offer(1);
            }
        }

        for (PriorityQueue<Integer> queue : frequencyMap.values()) {
            while (!queue.isEmpty()) {
                if (queue.poll() < 3) {
                    return false;
                }
            }
        }

        return true;
    }

    public static void main(String[] args) {
        try {
            int[] nums1 = {1, 2, 3, 3, 4, 5};
            int[] nums2 = {1, 2, 3, 3, 4, 4, 5, 5};
            int[] nums3 = {1, 2, 3, 4, 4, 5};

            System.out.println(isPossible(nums1));  // Output: true
            System.out.println(isPossible(nums2));  // Output: true
            System.out.println(isPossible(nums3));  // Output: false
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

