import java.util.HashMap;
import java.util.Map;

public class LetterTileCounter {

    public static int countLetterTile(String tiles) {
        if (tiles == null || tiles.isEmpty()) {
            throw new IllegalArgumentException("Input tiles cannot be null or empty");
        }

        Map<Character, Integer> countMap = new HashMap<>();
        for (char tile : tiles.toCharArray()) {
            countMap.put(tile, countMap.getOrDefault(tile, 0) + 1);
        }

        int result = 0;
        int i = 0;
        int n = 0;
        while (i < tiles.length() - 1) {
            if (i == 0) {
                if (countMap.get(tiles.charAt(i)) <= 1) {
                    result += (1 << n);
                    n = 0;
                } else {
                    result += (1 << n) - 1;
                }
                i++;
            } else {
                if (countMap.get(tiles.charAt(i)) > 1) {
                    result += (1 << n);
                } else {
                    result += (1 << n) - 1;
                }
                n++;
            }
            i++;
        }

        if (n > 0) {
            result += (1 << n) - 1;
        }

        return result;
    }

    public static void main(String[] args) {
        try {
            int output1 = countLetterTile("AAB");
            System.out.println(output1); // 8

            int output2 = countLetterTile("AAABBC");
            System.out.println(output2); // 188

            int output3 = countLetterTile("V");
            System.out.println(output3); // 1
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }
}

