import java.util.*;

public class NetworkIdlePeriod {

    private int[] times;
    private int[] dist;

    public long networkBecomesIdle(int[][] edges, int[] patience) {
        Map<Integer, Set<Integer>> connectedMap = buildConnectionMap(edges);
        int nodeCount = patience.length;
        times = new int[nodeCount];
        dist = new int[nodeCount];
        Arrays.fill(times, Integer.MAX_VALUE);
        Arrays.fill(dist, Integer.MAX_VALUE);
        times[0] = 0;
        dist[0] = 0;

        bfs(connectedMap, nodeCount);

        return calculateIdleTime(patience);
    }

    private Map<Integer, Set<Integer>> buildConnectionMap(int[][] edges) {
        Map<Integer, Set<Integer>> map = new HashMap<>();
        for (int[] edge : edges) {
            map.computeIfAbsent(edge[0], k -> new HashSet<>()).add(edge[1]);
            map.computeIfAbsent(edge[1], k -> new HashSet<>()).add(edge[0]);
        }
        return map;
    }

    private void bfs(Map<Integer, Set<Integer>> connectedMap, int nodeCount) {
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(0);

        while (!queue.isEmpty()) {
            int currentNode = queue.poll();
            for (int neighbor : connectedMap.getOrDefault(currentNode, new HashSet<>())) {
                if (dist[neighbor] == Integer.MAX_VALUE) {
                    dist[neighbor] = dist[currentNode] + 1;
                    queue.offer(neighbor);
                }
                if (times[neighbor] == Integer.MAX_VALUE && (dist[currentNode] + 1) % (times[neighbor] + 1) != 0) {
                    times[neighbor] = dist[currentNode] + 1;
                }
            }
        }
    }

    private long calculateIdleTime(int[] patience) {
        long maxIdle = times[0];
        for (int i = 1; i < times.length; i++) {
            if (times[i] != Integer.MAX_VALUE) {
                long timeAtNode = (long) (2 * times[i] / patience[i]) * patience[i];
                maxIdle = Math.max(maxIdle, timeAtNode + times[i]);
            }
        }
        return maxIdle;
    }
}

