public class Solution {
    private int[] jobDifficulty;
    private int n, d;
    private Integer[][] memo;

    public int minDifficulty(int[] jobDifficulty, int d) {
        validateInput(jobDifficulty, d);

        this.jobDifficulty = jobDifficulty;
        this.n = jobDifficulty.length;
        this.d = d;
        this.memo = new Integer[n][d + 1];

        return computeMinDifficulty(0, 1);
    }

    private void validateInput(int[] jobDifficulty, int d) {
        if (jobDifficulty == null) {
            throw new IllegalArgumentException("Job difficulty array cannot be null.");
        }
        if (d <= 0) {
            throw new IllegalArgumentException("Number of days must be greater than zero.");
        }
        if (jobDifficulty.length < d) {
            throw new IllegalArgumentException("Not enough jobs for the given number of days.");
        }
    }

    private int computeMinDifficulty(int i, int k) {
        if (k == d) {
            return findMaxDifficulty(i, n);
        }

        if (i == n) return Integer.MAX_VALUE;

        if (memo[i][k] != null) return memo[i][k];

        int res = Integer.MAX_VALUE, max = 0;
        for (int j = i; j < n; j++) {
            max = Math.max(max, jobDifficulty[j]);
            int nextDifficulty = max + computeMinDifficulty(j + 1, k + 1);
            res = Math.min(res, nextDifficulty);
        }

        memo[i][k] = res;
        return res;
    }

    private int findMaxDifficulty(int start, int end) {
        int max = 0;
        for (int j = start; j < end; j++) {
            max = Math.max(max, jobDifficulty[j]);
        }
        return max;
    }
}

