import java.util.ArrayList;
import java.util.List;

public class Solution {

    private static final int MOD = 1000000007;

    public int numPrimeArrangements(int n) {
        if (n < 1) {
            throw new IllegalArgumentException("Input must be a positive integer.");
        }

        int[] sieve = new int[n + 1];
        List<Integer> primes = new ArrayList<>();
        calculatePrimes(n, sieve, primes);

        int primeCount = primes.size();
        long arrangements = 1;

        for (int i = 0; i < primeCount; i++) {
            arrangements = (arrangements * (primeCount - i)) % MOD;
        }

        return (int) arrangements;
    }

    private void calculatePrimes(int n, int[] sieve, List<Integer> primes) {
        for (int i = 2; i <= n; i++) {
            if (sieve[i] == 0) {
                primes.add(i);
                for (int p : primes) {
                    if (i * p > n) {
                        break;
                    }
                    sieve[i * p] = 1; 
                    if (i % p == 0) {
                        break;
                    }
                }
            }
        }
    }
}

public static String findLexSmallestString(String s, int a, int b) {
    if (s == null || a < 0 || b < 0) {
        throw new IllegalArgumentException("Invalid input: string cannot be null and a, b must be non-negative.");
    }

    String result = s;
    String rotated = rotateString(s, b);

    while (!rotated.equals(s)) {
        s = rotated;
        rotated = rotateString(s, b);
        result = chooseSmaller(result, s);
    }

    result = chooseSmallest(result, addA(s, a));
    result = chooseSmaller(result, addA(result, a));

    return result;
}

private static String addA(String s, int a) {
    StringBuilder sb = new StringBuilder();

    for (int i = 0; i < s.length(); i++) {
        if (i % 2 == 0) {
            sb.append(s.charAt(i));
        } else {
            int newChar = (s.charAt(i) - '0' + a) % 10;
            sb.append(newChar);
        }
    }

    return sb.toString();
}

private static String chooseSmaller(String str1, String str2) {
    return str1.compareTo(str2) < 0 ? str1 : str2;
}

private static String rotateString(String s, int b) {
    if (s.length() == 0 || b <= 0) {
        return s;
    }

    b = b % s.length();  // Handle rotations greater than the string length
    String str1 = s.substring(s.length() - b);
    String str2 = s.substring(0, s.length() - b);

    return str1 + str2;
}

import java.util.Arrays;

public class ProductExceptSelf {

    public static int[][] productExceptSelf(int[][] grid) {
        if (grid == null || grid.length == 0 || grid[0].length == 0) {
            throw new IllegalArgumentException("Input grid must be non-null and non-empty.");
        }

        int n = grid.length;
        int m = grid[0].length;
        int[][] result = new int[n][m];
        for (int[] row : result) {
            Arrays.fill(row, 1);
        }

        // Forward pass to calculate cumulative products
        try {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    if (i > 0) {
                        result[i][j] *= result[i - 1][j];
                    }
                    if (j > 0) {
                        result[i][j] *= result[i][j - 1];
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("Error during forward pass: " + e.getMessage());
            return new int[0][0]; // or handle as needed
        }

        // Backward pass to finalize the product except self calculation
        try {
            for (int i = n - 1; i >= 0; i--) {
                for (int j = m - 1; j >= 0; j--) {
                    if (i < n - 1) {
                        result[i][j] *= result[i + 1][j];
                    }
                    if (j < m - 1) {
                        result[i][j] *= result[i][j + 1];
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("Error during backward pass: " + e.getMessage());
            return new int[0][0]; // or handle as needed
        }

        // Update the original grid with the new values
        try {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    grid[i][j] *= result[i][j];
                }
            }
        } catch (Exception e) {
            System.err.println("Error during grid update: " + e.getMessage());
            return new int[0][0]; // or handle as needed
        }

        return grid;
    }
}

