public class GrandmasApples {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = 0;
        int p = 0;
        try {
            System.out.print("Enter number of buyers: ");
            n = Integer.parseInt(scanner.nextLine().trim());
            System.out.print("Enter price per apple: ");
            p = Integer.parseInt(scanner.nextLine().trim());

            if (n <= 0 || p <= 0) {
                throw new IllegalArgumentException("Number of buyers and price must be positive.");
            }

            String[] buyers = new String[n];
            System.out.println("Enter buyer types:");
            for (int i = 0; i < n; i++) {
                buyers[i] = scanner.nextLine().trim();
            }

            double totalMoney = calculateTotalMoney(buyers, p);
            System.out.printf("Total money earned: %.2f%n", totalMoney);
        } catch (NumberFormatException e) {
            System.err.println("Invalid input. Please enter integers for number of buyers and price.");
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
        } finally {
            scanner.close();
        }
    }

    private static double calculateTotalMoney(String[] buyers, int price) {
        int apples = 1; // Grandma starts with at least one apple
        double totalMoney = 0;

        for (String buyer : buyers) {
            int sold = apples / 2; // Half of current apples
            apples -= sold; // Update apples after the sale

            if (buyer.equalsIgnoreCase("halfplus")) {
                sold += apples / 2; // Buyer gets half plus a gift of half an apple
                apples -= apples / 2; // Update apples after giving a gift
                totalMoney += (sold + 0.5) * (price / 4.0); // Add the value of the gift
            } else {
                totalMoney += sold * (price / 2.0); // Add the value of apples sold (without gift)
            }
        }

        return totalMoney;
    }
}

