import java.util.Arrays;
import java.util.Scanner;

public class Main {
    private int[] a;
    private int n;
    private int k;
    private int[] StrictlyGreater;
    private int[] As;
    private int min;

    public Main() {
        this.min = 0;
    }

    public void flu() {
        StrictlyGreater[1] = 0;
        for (int i = 1; i <= n; i++) {
            min = Math.min(i, min);
            if (StrictlyGreater[i - 1] + As[i] == StrictlyGreater[i] - As[i]) {
                continue;
            }
            int left = i;
            int right = n;
            int iter = 0;
            while (right - left > 1) {
                int mid = (right + left) / 2;
                int b = StrictlyGreater[i] - As[mid] + As[mid + 1] - As[i + 1];
                if (b < StrictlyGreater[i] - As[i + 1]) {
                    right = mid;
                } else {
                    left = mid;
                }
                iter++;
                if (iter >= 100) {
                    logError("Iteration limit exceeded at n=" + n + ", k=" + k + ", i=" + i);
                    return;
                }
            }
        }
    }

    public int minim() {
        int lef = 0;
        int rig = n;
        int tries = 0;
        Arrays.sort(a);

        do {
            if (++tries >= 10000) {
                logError("Max tries reached during minim computation for n=" + n + ", lef=" + lef + ", rig=" + rig);
                return min;
            }
            if ((lef + rig) / 2 == min) {
                min++;
            }
            final int mid = (lef + rig) / 2;
            if (StrictlyGreater[mid - 1] - a[mid] == StrictlyGreater[mid] - a[mid]) {
                lef = mid;
            } else {
                rig = mid;
            }
        } while (lef + 1 < rig);
        return min;
    }

    public static void main(final String[] args) {
        Scanner scan = new Scanner(System.in);
        int tests = scan.nextInt();
        final Main main = new Main();

        while (tests-- > 0) {
            main.n = scan.nextInt();
            main.k = scan.nextInt();
            main.As = new int[main.n];
            for (int i = 0; i < main.n; i++) {
                main.As[i] = scan.nextInt();
            }
            try {
                main.flu();
                int result = main.minim();
                System.out.println(result);
            } catch (RuntimeException e) {
                logError("Caught exception during processing: " + e.getMessage());
                System.exit(-1);
            }
        }
        System.exit(0);
    }

    private static void logError(String message) {
        System.err.println("Error: " + message);
    }
}

int[] sortPancakes(int[] arr) {
    if (arr == null || arr.length == 0) {
        throw new IllegalArgumentException("Input array must not be null or empty.");
    }

    int n = arr.length;
    int[] flips = new int[n];

    for (int i = n - 1; i >= 1; i--) {
        int maxIndex = findMaxIndex(arr, i);

        if (maxIndex != i) {
            flip(arr, maxIndex, i);
            flips[n - i] = maxIndex + 1;
        }
    }

    return flips;
}

int findMaxIndex(int[] arr, int limit) {
    int maxIndex = 0;

    for (int j = 1; j <= limit; j++) {
        if (arr[j] > arr[maxIndex]) {
            maxIndex = j;
        }
    }

    return maxIndex;
}

void flip(int[] arr, int start, int end) {
    while (start < end) {
        swap(arr, start, end);
        start++;
        end--;
