import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Set;

public class WordPattern {
    public ArrayList<String> wordPattern(String pattern, String str) {
        ArrayList<String> result = new ArrayList<>();
        HashMap<Character, String> map = new HashMap<>();
        Set<String> set = new HashSet<>();
        String[] words = str.split("\\s+");

        if (words.length == 0 || pattern.length() != words.length) {
            throw new IllegalArgumentException("Pattern length must match the number of words.");
        }

        for (int index = 0; index < pattern.length(); index++) {
            char ch = pattern.charAt(index);
            String word = words[index];

            if (map.containsKey(ch)) {
                if (!map.get(ch).equals(word)) {
                    return result; // Early exit for mismatch
                }
            } else {
                if (set.contains(word)) {
                    return result; // Early exit if word already mapped
                }
                map.put(ch, word);
                set.add(word);
            }
        }
        result.addAll(map.values());
        return result;
    }
}

