                if (st.countTokens() < 2) {
                    pw.println("Invalid input.");
                    continue;
                }

                int rows = Integer.parseInt(st.nextToken());
                int columns = Integer.parseInt(st.nextToken());

                int result = calculateBaseValue(rows, columns);
                int initValue = determineInitialValue(rows, columns);

                for (int i = 0; i < rows * columns; i++) {
                    if (i < result) {
                        pw.print((rows == 2 && columns == 2) ? 0 : initValue);
                    } else {
                        pw.print((i + 4) / 2);
                    }
                    if (i < rows * columns - 1) {
                        pw.print(" ");
                    }
                }
                pw.println();
            }
        } catch (IOException e) {
            System.err.println("Error during input/output operation: " + e.getMessage());
