    private static int calculateBaseValue(int n, int m) {
        if (n % 2 == 1 && m % 2 == 1) {
            return 1;
        }
        return (n % 2 == 1 || m % 2 == 1) ? 2 : 0;
    }

    private static int determineInitialValue(int n, int m) {
        if (n % 2 == 1 && m % 2 == 1) {
            return 4;
        }
        return (n % 2 == 1 || m % 2 == 1) ? 3 : 2;
    }
}

