class Solution {
    public int assignBikes(int[][] workers, int[][] bikes) {
        if (workers == null || bikes == null) return -1;

        int workerCount = workers.length;
        int bikeCount = bikes.length;
        boolean[] bikeAssigned = new boolean[bikeCount];
        return assignBikesHelper(workers, bikes, bikeAssigned, 0);
    }

    private int assignBikesHelper(int[][] workers, int[][] bikes, boolean[] bikeAssigned, int workerIndex) {
        if (workerIndex == workers.length) return 0;

        int minDistance = Integer.MAX_VALUE;
        for (int i = 0; i < bikes.length; i++) {
            if (!bikeAssigned[i]) {
                bikeAssigned[i] = true;
                int distance = getDistance(workers[workerIndex], bikes[i]);
                int nextDistance = assignBikesHelper(workers, bikes, bikeAssigned, workerIndex + 1);
                if (nextDistance >= 0) {  // Check feasible assignment
                    minDistance = Math.min(minDistance, distance + nextDistance);
                }
                bikeAssigned[i] = false;  // Backtrack
            }
        }

        return minDistance == Integer.MAX_VALUE ? -1 : minDistance;
    }

    private int getDistance(int[] worker, int[] bike) {
        return Math.abs(worker[0] - bike[0]) + Math.abs(worker[1] - bike[1]);
    }
}

class Solution {
    public int minFlips(int[][] A, int[][] B) {
        if (A == null || B == null || A.length == 0 || B.length == 0) return -1;

        int flipCount = 0;
        int rowCount = A.length;
        int colCount = A[0].length;

        for (int i = 0; i < rowCount; i++) {
            for (int j = 0; j < colCount; j++) {
                if (A[i][j] != B[i][j]) {
                    flipCount++;
                    // Flip entire row
                    flipRow(A, i);
                    // Flip entire column
                    flipCol(A, j);
                }
            }
        }

        return checkEquality(A, B) ? flipCount : -1;
    }

    private void flipRow(int[][] A, int row) {
        for (int j = 0; j < A[0].length; j++) {
            A[row][j] ^= 1;
        }
    }

    private void flipCol(int[][] A, int col) {
        for (int i = 0; i < A.length; i++) {
            A[i][col] ^= 1;
        }
    }

    private boolean checkEquality(int[][] A, int[][] B) {
        for (int i = 0; i < A.length; i++) {
            for (int j = 0; j < A[0].length; j++) {
                if (A[i][j] != B[i][j]) return false;
            }
        }
        return true;
    }
}

class Solution {
    public double largestTriangleArea(int[][] points) {
        if (points == null || points.length < 3) return 0.0;

        double maxArea = 0.0;
        int n = points.length;

        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                for (int k = j + 1; k < n; k++) {
                    double area = calculateArea(points[i], points[j], points[k]);
                    maxArea = Math.max(maxArea, area);
                }
            }
        }

        return maxArea;
    }

    private double calculateArea(int[] p1, int[] p2, int[] p3) {
        return 0.5 * Math.abs(p1[0] * (p2[1] - p3[1]) + p2[0] * (p3[1] - p1[1]) + p3[0] * (p1[1] - p2[1]));
    }
}

class Solution {
    public int maxChunksToSorted(int[] arr) {
        if (arr == null || arr.length == 0) return 0;

        int chunks = 0, maxSeen = 0;
        for (int i = 0; i < arr.length; i++) {
            maxSeen = Math.max(maxSeen, arr[i]);
            if (maxSeen == i) chunks++;
        }
        return chunks;
    }
}

