class CodeJam {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        try {
            int testCaseCount = readTestCaseCount(sc);
            for (int t = 0; t < testCaseCount; t++) {
                processTestCase(sc);
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        } finally {
            sc.close();
        }
    }

    private static int readTestCaseCount(Scanner sc) {
        if (sc.hasNextInt()) {
            return sc.nextInt();
        } else {
            throw new IllegalArgumentException("Invalid input for test case count.");
        }
    }

    private static void processTestCase(Scanner sc) {
        int length = sc.nextInt();
        char mew = sc.next().charAt(0);
        char[] arr = sc.next().toCharArray();

        int[][] frequency = new int[26][2];
        int answer1 = 0, answer2 = 0, mask = 0;
        populateFrequency(arr, frequency, length);
        computeAnswer(frequency, mask, answer1, answer2);

        if (answer2 > 0) {
            printResults(answer1, answer2, frequency);
        } else {
            System.out.println(answer1);
        }
        System.out.println();
    }

    private static void populateFrequency(char[] arr, int[][] frequency, int length) {
        for (int i = 0; i < length; i++) {
            frequency[arr[i] - 'a'][i % 2]++;
        }
    }

    private static void computeAnswer(int[][] frequency, int mask, int answer1, int answer2) {
        for (int i = 0; i < 26; i++) {
            int minFreq = Math.min(frequency[i][0], frequency[i][1]);
            mask |= (1 << i);
            answer1 += minFreq;
            frequency[i][0] -= minFreq;
            frequency[i][1] -= minFreq;
        }

        int residue = findResidue(frequency, mask);
        if (residue > 0) {
            answer2 = adjustAnswerWithResidue(frequency, residue);
        }
    }

    private static int findResidue(int[][] frequency, int mask) {
        int residue = -1;
        for (int i = 0; i < 26; i++) {
            if (frequency[i][0] > 0) {
                frequency[i][1] -= frequency[i][0];
                if (frequency[i][1] < 0) {
                    residue = frequency[i][0];
                    mask = (1 << i);
                }
            }
        }
        return residue;
    }

    private static int adjustAnswerWithResidue(int[][] frequency, int residue) {
        int answer2 = 0;
        for (int i = 0; i < 26; i++) {
            if ((frequency[0][0] & (1 << i)) == 0 && frequency[i][1] > 0) {
                answer2 += (frequency[i][1] / residue);
                if (frequency[i][1] % residue > 0) {
                    answer2++;
                }
            }
        }
        return answer2;
    }

    private static void printResults(int answer1, int answer2, int[][] frequency) {
        System.out.println(answer1 + answer2);
        for (int i = 0; i < answer2; i++) {
            System.out.print(residue + " ");
        }
        for (int i = 0; i < 26; i++) {
            if ((mask & (1 << i)) > 0) {
                System.out.print(frequency[i][0] + " ");
            }
        }
    }
}

