public String smallestGoodBase(String n) {
    if (n == null || n.isEmpty()) {
        throw new IllegalArgumentException("Input cannot be null or empty");
    }

    long num;
    try {
        num = Long.parseLong(n);
    } catch (NumberFormatException e) {
        throw new IllegalArgumentException("Input must be a valid number", e);
    }

    if (num < 2) {
        throw new IllegalArgumentException("Input must be greater than 1");
    }

    int maxM = (int) Math.ceil(Math.log(num) / Math.log(2)) + 1;

    for (int m = maxM; m > 1; m--) {
        long k = (long) Math.pow(num, 1.0 / m);
        long sum = 1;
        long curr = 1;

        for (int i = 0; i < m; i++) {
            sum += curr;
            curr *= k;

            if (sum > num) {
                break;
            } else if (sum == num) {
                return String.valueOf(k);
            }
        }
    }

    return String.valueOf(num - 1);
}

import java.util.*;

public class SnakesAndLadders {
    public int snakesAndLadders(int[][] board) {
        if (board == null || board.length == 0) {
            throw new IllegalArgumentException("Board cannot be null or empty");
        }

        int n = board.length;
        Queue<Integer> queue = new LinkedList<>();
        Set<Integer> visited = new HashSet<>();
        queue.offer(1);
        visited.add(1);
        int steps = 0;

        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int curr = queue.poll();
                if (curr == n * n) {
                    return steps;
                }
                for (int j = 1; j <= 6; j++) {
                    int nextPos = curr + j;
                    if (nextPos > n * n) {
                        continue;
                    }
                    nextPos = getNextPosition(board, nextPos);
                    if (!visited.contains(nextPos)) {
                        visited.add(nextPos);
                        queue.offer(nextPos);
                    }
                }
            }
            steps++;
        }
        return -1;
    }

    private int getNextPosition(int[][] board, int pos) {
        int n = board.length;
        int row = n - 1 - (pos - 1) / n;
        int col = (pos - 1) % n;

        if (row % 2 == n % 2) {
            col = n - 1 - col;
        }

        return (board[row][col] == -1) ? pos : board[row][col];
    }
}

public class Solution {
    public int minSkips(int[] dist, int speed, int hoursBefore) {
        if (dist == null || dist.length == 0 || speed <= 0 || hoursBefore <= 0) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }

        double remainingTime = hoursBefore - ((double) dist[0] / speed);
        if (remainingTime < 0) return -1;

        int skips = 0;
        for (int i = 1; i < dist.length; i++) {
            double travelTime = Math.ceil((double) dist[i] / speed);

            if (remainingTime - travelTime < 0) {
                skips++;
                remainingTime = 0; // Reset remaining time as we've used a skip
            } else {
                remainingTime -= (travelTime >= 1 ? travelTime - 1 : 0);
            }

            remainingTime--; // Account for the time taken to move to the next segment
            if (remainingTime < 0) return -1; // No more time left to complete the journey
        }

        return skips;
    }
}

import java.util.*;
import java.io.*;

public class SpecialExchangeSolver {

    public static void main(String[] args) {
        try {
            FastScanner fs = new FastScanner(System.in);
            PrintWriter out = new PrintWriter(System.out);

            int testCases = fs.nextInt();
            validateInput(testCases);

            while (testCases-- > 0) {
                int n = fs.nextInt();
                validateInput(n);

                int[] scores = fs.nextIntArray(n);
                int exchanges = calculateExchanges(scores);

                out.println(exchanges);
            }

            out.flush();
        } catch (IOException e) {
            System.err.println("Error during input/output operations: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.err.println("Invalid number format: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }

    private static void validateInput(int value) {
        if (value < 1) {
            throw new IllegalArgumentException("Input must be greater than 0.");
        }
    }

    private static int calculateExchanges(int[] scores) {
        int exchanges = 0;

        for (int i = 1; i < scores.length; i++) {
            if (scores[i] <= scores[i - 1]) {
                exchanges += Integer.bitCount(scores[i] ^ scores[i - 1]);
            }
        }

        return exchanges;
    }

    static class FastScanner {
        private BufferedReader br;
        private StringTokenizer st;

        FastScanner(InputStream s) {
            br = new BufferedReader(new InputStreamReader(s));
        }

        String next() throws IOException {
            ensureTokenizer();
            return st.nextToken();
        }

        int nextInt() throws IOException {
            return Integer.parseInt(next());
        }

        int[] nextIntArray(int n) throws IOException {
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = nextInt();
            }
            return arr;
        }

        private void ensureTokenizer() throws IOException {
            while (st == null || !st.hasMoreTokens()) {
                String line = br.readLine();
                if (line == null) {
                    throw new IOException("End of input stream.");
                }
                st = new StringTokenizer(line);
            }
        }
    }
}

