#include <climits>

int main() {
    int testCases;
    std::cin >> testCases;

    if(testCases <= 0) {
        std::cerr << "Error: Number of test cases must be positive." << std::endl;
        return 1;
    }

    while (testCases--) {
        int n;
        std::cin >> n;

        if(n <= 0) {
            std::cerr << "Error: Array size must be positive." << std::endl;
            continue;
        }

        std::vector<int> a(n);
        for (int i = 0; i < n; i++) {
            std::cin >> a[i];
        }

        long long sum = 0;
        const int MAX = INT_MAX;
        std::vector<int> ans((n + 1) / 2, MAX);

        for (const auto& value : a) {
            sum += value;
        }

        for (int i = 1; i < n; i += 2) {
            for (int j = 0; j < n - i; j++) {
                ans[j] = std::min(ans[j], a[j + i] * a[j]);
            }
        }

        if (n % 2 == 1) {
            for (int i = n / 2; i < n; i++) {
                ans[i] = std::min(ans[i], a[i]);
            }
        }

        std::stack<int> S;
        for (int i = n - 1; i >= n / 2; i--) {
            if (S.empty() || S.top() == ans[i]) {
                S.push(a[i]);
            } else if (a[i] <= S.top()) {
                S.pop();
                S.push(ans[i]);
            }
        }

        if (S.empty()) {
            for (int i = n / 2 - 1; i >= 0; i--) {
                std::cout << ans[i] << " ";
            }
        } else {
            while (!S.empty()) {
                std::cout << S.top() << " ";
                S.pop();
            }
        }
        std::cout << std::endl;
    }
    return 0;
}

