    int min = array[0];
    for (int i = 1; i < array.length; i++) {
        if (array[i] < min) {
            min = array[i];
        }
    }

    return min;
}

import java.util.*;
import java.io.*;

class Solution {
    private static final String ERROR_MESSAGE = "Error processing input";

    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
             BufferedWriter bw = new BufferedWriter(new OutputStreamWriter(System.out))) {

            int t = Integer.parseInt(br.readLine().trim());
            StringBuilder sb = new StringBuilder();

            for (int i = 0; i < t; i++) {
                processTestCase(br, sb);
            }

            bw.write(sb.toString());
            bw.flush();
        } catch (IOException e) {
            System.err.println(ERROR_MESSAGE + ": " + e.getMessage());
        } catch (NumberFormatException e) {
            System.err.println(ERROR_MESSAGE + ": Invalid number format");
        }
    }

    private static void processTestCase(BufferedReader br, StringBuilder sb) throws IOException {
        StringTokenizer st = new StringTokenizer(br.readLine());
        int n = Integer.parseInt(st.nextToken());
        char c = st.nextToken().charAt(0);
        String s = br.readLine();

        if (isAllCharactersSame(s, n, c)) {
            sb.append(0).append("\n");
            return;
        }

        List<Integer> validDivisors = findValidDivisors(s, n, c);
        sb.append(validDivisors.size()).append(" ");
        for (int divisor : validDivisors) {
            sb.append(divisor).append(" ");
        }

        removeTrailingSpace(sb);
        sb.append("\n");
    }

    private static boolean isAllCharactersSame(String s, int n, char c) {
        for (int j = 0; j < n; j++) {
            if (s.charAt(j) != c) {
                return false;
            }
        }
        return true;
    }

    private static List<Integer> findValidDivisors(String s, int n, char c) {
        List<Integer> divisors = new ArrayList<>();
        for (int j = 1; j <= n; j++) {
            if (isValidDivisor(s, n, c, j)) {
                divisors.add(j);
            }
        }
        return divisors;
    }

    private static boolean isValidDivisor(String s, int n, char c, int divisor) {
        for (int k = 1; k <= n; k++) {
            if (k % divisor == 0 && s.charAt(k - 1) != c) {
                return false;
            }
        }
        return true;
    }

    private static void removeTrailingSpace(StringBuilder sb) {
        if (sb.length() > 0) {
            sb.deleteCharAt(sb.length() - 1);
        }
    }
}

public int findTheLongestBalancedSubstring(String s) {
    if (s == null || s.isEmpty()) {
        throw new IllegalArgumentException("Input string cannot be null or empty.");
    }

    int maxLength = 0;
    int countOnesInLastSequence = 0;
    int zeroCounter = 0;
    int oneCounter = 0;

    for (char c : s.toCharArray()) {
        if (c == '0') {
            if (oneCounter > 0) {
                maxLength = Math.max(maxLength, 2 * Math.min(zeroCounter, countOnesInLastSequence));
                countOnesInLastSequence = 0;
                zeroCounter = 0;
            }
            zeroCounter++;
        } else if (c == '1') {
            if (zeroCounter > oneCounter) {
                oneCounter = zeroCounter;
            }
            if (oneCounter < zeroCounter) {
                countOnesInLastSequence++;
            }
            oneCounter++;
        } else {
            throw new IllegalArgumentException("Invalid character found in input string. Only '0' and '1' are allowed.");
        }
    }

    maxLength = Math.max(maxLength, 2 * Math.min(zeroCounter, oneCounter));
    return maxLength;
}

