import java.util.HashMap;

public class Solution {
    private int[] nums;

    public int maximumUniqueSubarray(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array must not be null or empty.");
        }

        this.nums = nums;
        int maxSum = 0;
        int currentSum = 0;
        HashMap<Integer, Integer> seen = new HashMap<>();
        int left = 0;

        for (int right = 0; right < nums.length; right++) {
            if (seen.containsKey(nums[right])) {
                seen.put(nums[right], seen.get(nums[right]) + 1);
                currentSum += nums[right];
            } else {
                seen.put(nums[right], 1);
                currentSum += nums[right];
            }

            while (seen.get(nums[right]) > 1) {
                int leftNum = nums[left];
                seen.put(leftNum, seen.get(leftNum) - 1);
                currentSum -= leftNum;

                if (seen.get(leftNum) == 0) {
                    seen.remove(leftNum);
                }
                left++;
            }

            maxSum = Math.max(maxSum, currentSum);
        }

        return maxSum;
    }

    public static void main(String[] args) {
        Solution solution = new Solution();
        int[] testArray = {4, 2, 4, 5, 6};
        try {
            int result = solution.maximumUniqueSubarray(testArray);
            System.out.println(result == 17 ? "Pass" : "Fail");
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

