public class PerfectNumberChecker {

    private static final String ERROR_MESSAGE = "Input must be a positive integer.";

    public static boolean isPerfectNumber(int num) {
        validateInput(num);
        int sum = 1;

        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) {
                sum += i;
                if (i != num / i) {
                    sum += num / i;
                }
            }
        }

        return sum == num && num != 1;
    }

    private static void validateInput(int num) {
        if (num <= 0) {
            throw new IllegalArgumentException(ERROR_MESSAGE);
        }
    }

    public static void main(String[] args) {
        int[] testNumbers = {28, 6, 12, 496, 8128, 1, -5};

        for (int num : testNumbers) {
            try {
                boolean result = isPerfectNumber(num);
                System.out.println("Is " + num + " a perfect number? " + result);
            } catch (IllegalArgumentException e) {
                System.err.println("Error: " + e.getMessage() + " for input: " + num);
            }
        }
    }
}

