public class StringEqualityChecker {
    private static final Logger logger = Logger.getLogger(StringEqualityChecker.class.getName());

    public boolean makeStringsEqual(String s, String target) {
        if (s == null || target == null) {
            logger.log(Level.SEVERE, "Input strings cannot be null");
            return false;
        }

        int hasZeroS = 0, hasZeroT = 0, hasOneS = 0, hasOneT = 0;

        for (char c : s.toCharArray()) {
            if (c == '0') {
                hasZeroS++;
            } else {
                hasOneS++;
            }
        }

        for (char c : target.toCharArray()) {
            if (c == '0') {
                hasZeroT++;
            } else {
                hasOneT++;
            }
        }

        if (hasOneS > hasZeroS && hasOneT > hasZeroT) {
            return false;
        }
        return hasOneS > 0 || hasOneT > 0;
    }

    public void displayResults(int[] ss, int[] tt) {
        if (ss.length < 2 || tt.length < 2) {
            logger.log(Level.WARNING, "Input arrays must contain at least two elements");
            return;
        }

        logResults("ss", ss);
        logResults("tt", tt);

        int diffSS = Math.abs(ss[0] - ss[1]);
        int diffTT = Math.abs(tt[0] - tt[1]);
        logger.log(Level.INFO, "Minimum Difference: " + Math.min(diffSS, diffTT));
    }

    private void logResults(String label, int[] array) {
        logger.log(Level.INFO, label + ": " + (array[0] + array[1]) + ", Difference: " + (array[0] - array[1]));
    }
}

