public class Main {
    private static int nodeCount;
    private static List<List<Integer>> graph;

    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in))) {
            int testCases = Integer.parseInt(br.readLine().trim());
            for (int t = 0; t < testCases; t++) {
                processTestCase(br);
            }
        } catch (IOException | NumberFormatException e) {
            System.err.println("Error in input processing: " + e.getMessage());
        }
    }

    private static void processTestCase(BufferedReader br) {
        try {
            nodeCount = Integer.parseInt(br.readLine().trim());
            initializeGraph();
            readGraphEdges(br);
            System.out.println(evaluateGraph());
        } catch (IOException | NumberFormatException e) {
            System.err.println("Error processing test case: " + e.getMessage());
        }
    }

    private static void initializeGraph() {
        graph = new ArrayList<>(nodeCount);
        for (int i = 0; i < nodeCount; i++) {
            graph.add(new ArrayList<>());
        }
    }

    private static void readGraphEdges(BufferedReader br) throws IOException {
        for (int i = 0; i < nodeCount - 1; i++) {
            String line = br.readLine().trim();
            String[] vertices = line.split(" ");
            int u = Integer.parseInt(vertices[0]) - 1;
            int v = Integer.parseInt(vertices[1]) - 1;
            graph.get(u).add(v);
            graph.get(v).add(u);
        }
    }

    private static int evaluateGraph() {
        if (nodeCount == 1) {
            return 0;
        }
        for (List<Integer> neighbors : graph) {
            if (neighbors.size() > 1) {
                return 1;
            }
        }
        return 2;
    }
}

