public class Main {
    static class FastReader {
        private BufferedReader br;
        private StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        private String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    System.err.println("Error reading input: " + e.getMessage());
                    System.exit(1);
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

        public long nextLong() {
            return Long.parseLong(next());
        }

        public double nextDouble() {
            return Double.parseDouble(next());
        }

        public String nextLine() {
            String str = "";
            try {
                str = br.readLine();
            } catch (IOException e) {
                System.err.println("Error reading line: " + e.getMessage());
            }
            return str;
        }
    }

    public static void main(String[] args) {
        FastReader reader = new FastReader();
        PrintWriter writer = new PrintWriter(System.out);

        try {
            int testCases = reader.nextInt();
            while (testCases-- > 0) {
                int n = reader.nextInt();
                long[] a = new long[n];
                for (int i = 0; i < n; i++) {
                    a[i] = reader.nextLong();
                }

                long[] prefixSum = computePrefixSum(a, n);
                int result = findMaxValidLength(prefixSum, n);
                writer.println(result);
            }
        } catch (Exception e) {
            System.err.println("Error processing input: " + e.getMessage());
        } finally {
            writer.close();
        }
    }

    private static long[] computePrefixSum(long[] a, int n) {
        long[] p = new long[n];
        p[0] = a[0];
        for (int i = 1; i < n; i++) {
            p[i] = p[i - 1] + a[i];
        }
        return p;
    }

    private static int findMaxValidLength(long[] prefixSum, int n) {
        int maxLength = 1;

        for (int i = 1; i <= n; i++) {
            if (i * (i + 1) / 2 > n) {
                break;
            }
            if (isValidSegment(prefixSum, i, n)) {
                maxLength = i;
            }
        }
        return maxLength;
    }

    private static boolean isValidSegment(long[] prefixSum, int length, int n) {
        long[] segment = new long[length];

        for (int j = 0; j < length; j++) {
            segment[j] = prefixSum[j];
        }

        for (int j = length; j < n; j++) {
            if (segment[length - 1] > prefixSum[j]) {
                return false;
            }
            segment[j % length] = prefixSum[j] - prefixSum[(j - 1) % length];
        }
        return true;
    }
}

