import java.util.*;

public class SynonymFinder {
    public List<String> findSynonyms(List<List<String>> synonyms, String text) {
        if (synonyms == null || text == null || text.isEmpty()) {
            return Collections.emptyList();
        }

        Map<String, List<String>> synonymsMap = new HashMap<>();
        buildSynonymsMap(synonyms, synonymsMap);

        List<String> result = new ArrayList<>();
        Set<String> visited = new HashSet<>();
        String[] words = text.split(" ");

        for (String word : words) {
            if (word.isEmpty()) continue;
            List<String> possibleSynonyms = getSynonymsForWord(word, synonymsMap, visited);
            if (possibleSynonyms.isEmpty()) {
                result.add(word);
            } else {
                result.addAll(possibleSynonyms);
            }
        }

        return result;
    }

    private void buildSynonymsMap(List<List<String>> synonyms, Map<String, List<String>> synonymsMap) {
        for (List<String> pair : synonyms) {
            if (pair.size() != 2 || pair.get(0) == null || pair.get(1) == null) {
                continue;
            }
            synonymsMap.computeIfAbsent(pair.get(0), k -> new ArrayList<>()).add(pair.get(1));
            synonymsMap.computeIfAbsent(pair.get(1), k -> new ArrayList<>()).add(pair.get(0));
        }
    }

    private List<String> getSynonymsForWord(String word, Map<String, List<String>> synonymsMap, Set<String> visited) {
        List<String> synonyms = new ArrayList<>();
        Queue<String> queue = new LinkedList<>();

        queue.offer(word);
        visited.add(word);

        while (!queue.isEmpty()) {
            String curWord = queue.poll();
            List<String> neighbors = synonymsMap.get(curWord);

            if (neighbors != null) {
                for (String synonym : neighbors) {
                    if (!visited.contains(synonym)) {
                        visited.add(synonym);
                        queue.offer(synonym);
                        synonyms.add(synonym);
                    }
                }
            }
        }

        return synonyms.isEmpty() ? Collections.singletonList(word) : synonyms;
    }
}

public class Solution {
    public boolean isStrictlyPalindromic(int n) {
        if (n < 3) {
            logError("Input must be greater than 2.");
            return false;
        }

        for (int base = 2; base < n; base++) {
            if (!isBasePalindromic(n, base)) {
                return false;
            }
        }
        return true;
    }

    private boolean isBasePalindromic(int number, int base) {
        String numberStr = toBaseNumber(number, base);
        return isPalindrome(numberStr);
    }

    private boolean isPalindrome(String value) {
        int len = value.length();
        for (int i = 0; i < len / 2; i++) {
            if (value.charAt(i) != value.charAt(len - 1 - i)) {
                return false;
            }
        }
        return true;
    }

    private String toBaseNumber(int number, int base) {
        if (base < 2) {
            logError("Base must be at least 2.");
            return "";
        }

        StringBuilder res = new StringBuilder();
        int currNumber = number;
        while (currNumber > 0) {
            res.insert(0, currNumber % base);
            currNumber /= base;
        }
        return res.toString();
    }

    private void logError(String message) {
        // Placeholder for logging mechanism
        System.err.println("Error: " + message);
    }
}

