import java.util.Arrays;

public class MinimumLengthCalculator {

    public int minLength(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array cannot be null or empty.");
        }

        int n = nums.length;
        int[][] F = new int[n][n];
        initializeF(F, nums, n);

        int res = n;
        for (int len = 2; len <= n; len++) {
            for (int left = 0, right = len / 2; right < n; left++, right += (len + right - left) / 2) {
                if (right - left + 1 < len) break;

                if (checkCondition(F, nums, left, right, len, n)) {
                    res = Math.min(res, len);
                    break;
                }
            }
        }
        return res == Integer.MAX_VALUE ? 1 : res;
    }

    private void initializeF(int[][] F, int[] nums, int n) {
        for (int i = 0; i < n; i++) {
            F[i][i] = 1;
        }
        for (int k = 1; k < n; k++) {
            for (int i = 0, j = k; j < n; i++, j++) {
                F[i][j] = (nums[j] % nums[i] == 0 || nums[i] % nums[j] == 0) ? 1 : 0;
            }
        }
    }

    private boolean checkCondition(int[][] F, int[] nums, int left, int right, int len, int n) {
        for (int i = left; i <= right; i++) {
            for (int j = i + 1; j <= right + 1; j++) {
                if (F[i][j] != 0) {
                    int cnt = n, abst = left + right + 1;
                    boolean mark = false;

                    for (int s = left, t = i + 1; t <= right; s = t, t += (abst + right - s) / (right - i)) {
                        int tmp = t - s < len / 2 ? (t + right - s) / (right - i) - 1 : (len - 1) / 2;
                        cnt -= tmp;
                        abst += tmp * 2 - 1;

                        if (s == i && t == j || t == s + 1) tmp--;
                        mark |= F[s][t] != 0;
                    }
                    if (cnt <= 2 || mark) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
}

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class CandyDistributor {
    public static int distributeCandies(int[] candies, int k) {
        if (candies == null || k <= 0) {
            throw new IllegalArgumentException("Candies array cannot be null and k must be greater than 0.");
        }

        int total = 0;
        for (int candy : candies) {
            total += Math.max(candy, 0);
        }

        if (total == 0) {
            return 0;
        }

        List<Integer> childCandies = new ArrayList<>();
        while (k > 0 && total > 0) {
            int maxCandy = findMaxCandy(candies);
            if (maxCandy == -1) {
                break;
            }
            int index = findCandyIndex(candies, maxCandy);
            if (index == -1 || candies[index] > total / k) {
                break;
            }

            candies[index] = 0;
            childCandies.add(maxCandy);
            total -= maxCandy;
            k--;
        }
        return childCandies.size();
    }

    private static int findMaxCandy(int[] candies) {
        int maxCandy = Integer.MIN_VALUE;
        for (int candy : candies) {
            if (candy > maxCandy) {
                maxCandy = candy;
            }
        }
        return maxCandy == Integer.MIN_VALUE ? -1 : maxCandy;
    }

    private static int findCandyIndex(int[] candies, int maxCandy) {
        for (int i = 0; i < candies.length; i++) {
            if (candies[i] == maxCandy) {
                return i;
            }
        }
        return -1;
    }

    public static void main(String[] args) {
        int[] candies = {5, 1, 3, 9, 7};
        int k = 3;
        int result = distributeCandies(candies, k);
        System.out.println("Number of children who received candies: " + result);
    }
}

public class Divisors {

    public int calculateDigits(long num, long base) {
        if (base <= 1) {
            throw new IllegalArgumentException("Base must be greater than 1.");
        }
        int digitCount = 0;
        while (num > 0) {
            num /= base;
            digitCount++;
        }
        return digitCount;
    }

    public int countDivisorTypes(long num) {
        if (num <= 1) {
            return 0; // No divisors for 0 or 1
        }
        int divisorTypeCount = 0;
        int sqrt = (int) Math.sqrt(num);
        for (int j = 2; j <= sqrt; j++) {
            long quotient = num / j;
            if (j == quotient) continue;
            if (quotient * j == num) {
                divisorTypeCount++;
            } else {
                divisorTypeCount -= 2;
            }
        }
        return divisorTypeCount;
    }

    public boolean isPrime(long num) {
        if (num < 2) return false;
        if (num == 2) return true;
        if (num % 2 == 0) return false;
        for (int k = 3; k <= Math.sqrt(num); k += 2) {
            if (num % k == 0) {
                return false;
            }
        }
        return true;
    }

    public int countTriangleNumbers(int max) {
        if (max < 7) {
            return 0; // No triangle numbers available
        }
        int i = 7;
        int validPrimesCount = 0;
        while (i <= max) {
            if (isPrime(i)) {
                int multiplier = 1;
                while (i * multiplier <= max) {
                    validPrimesCount++;
                    multiplier++;
                }
            }
            i += 6;
        }
        return validPrimesCount;
    }
}

import java.util.HashMap;
import java.util.Arrays;

public class Solution {

    public int[] countOccurrences(int[] nums1, int[] nums2) {
        if (nums1 == null || nums2 == null) {
            throw new IllegalArgumentException("Input arrays cannot be null");
        }

        int[] result = new int[2];
        HashMap<Integer, Integer> countsInNums2 = new HashMap<>();

        try {
            for (int num : nums2) {
                countsInNums2.merge(num, 1, Integer::sum);
            }
            result[0] = countInArray(nums1, countsInNums2);

            // Clear previous counts for second occurrence
            countsInNums2.clear();
            for (int num : nums1) {
                countsInNums2.merge(num, 1, Integer::sum);
            }
            result[1] = countInArray(nums2, countsInNums2);
        } catch (Exception e) {
            System.err.println("Error counting occurrences: " + e.getMessage());
        }

        return result;
    }

    private int countInArray(int[] nums, HashMap<Integer, Integer> counts) {
        int count = 0;
        for (int num : nums) {
            count += counts.getOrDefault(num, 0);
        }
        return count;
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        testCountOccurrences(sol, new int[]{4, 3, 2, 3, 1}, new int[]{2, 2, 5, 2, 3, 6});
        testCountOccurrences(sol, new int[]{3, 4, 2, 3}, new int[]{1, 5});
    }

    private static void testCountOccurrences(Solution sol, int[] nums1, int[] nums2) {
        try {
            int[] answer = sol.countOccurrences(nums1, nums2);
            System.out.println("Result for nums1: " + Arrays.toString(nums1) 
                + ", nums2: " + Arrays.toString(nums2) + " => " + Arrays.toString(answer));
        } catch (IllegalArgumentException e) {
            System.err.println("Invalid input: " + e.getMessage());
        }
    }
}

import java.util.HashMap;
import java.util.Map;

class WordFilter {
    private final Map<String, Integer> wordMap;

    public WordFilter(String[] words) {
        if (words == null || words.length == 0) {
            throw new IllegalArgumentException("Words array cannot be null or empty.");
        }

        wordMap = new HashMap<>();
        populateWordMap(words);
    }

    private void populateWordMap(String[] words) {
        for (int index = 0; index < words.length; index++) {
            String word = words[index];
            if (word == null || word.isEmpty()) {
                continue; // Skip invalid words
            }
            int wordLength = word.length();
            for (int prefixLength = 1; prefixLength <= wordLength; prefixLength++) {
                for (int suffixLength = 1; suffixLength <= wordLength; suffixLength++) {
                    String key = generateKey(word, prefixLength, suffixLength);
                    wordMap.put(key, index);
                }
            }
        }
    }

    private String generateKey(String word, int prefixLength, int suffixLength) {
        String prefix = word.substring(0, prefixLength);
        String suffix = word.substring(word.length() - suffixLength);
        return prefix + "#" + suffix;
    }

    public int f(String prefix, String suffix) {
        if (prefix == null || suffix == null) {
            throw new IllegalArgumentException("Prefix and suffix cannot be null.");
        }

        String key = prefix + "#" + suffix;
        return wordMap.getOrDefault(key, -1);
    }
}

class Solution {
    public int shoppingOffers(int[] price, int[] special, int[] needs) {
        if (price == null || special == null || needs == null) {
            throw new IllegalArgumentException("Price, special, and needs cannot be null.");
        }

        if (needs.length == 0) return 0;

        int n = needs.length;
        int[] minCost = new int[n + 1];
        Arrays.fill(minCost, Integer.MAX_VALUE);
        minCost[0] = 0;

        for (int i = 0; i < n; i++) {
            minCost[i + 1] = computeMinCost(0, 0, price, needs, special, i, minCost);
        }
        return minCost[n];
    }

    private int computeMinCost(int index, int usedItems, int[] price, int[] needs, int[][] special, int offerIndex, int[] minCost) {
        if (usedItems > needs[index]) return Integer.MAX_VALUE;

        if (index == needs.length) return 0;

        if (minCost[index + 1] != Integer.MAX_VALUE) return minCost[index + 1];

        int notUsed = computeMinCost(index + 1, usedItems, price, needs, special, offerIndex, minCost);
        int offerUsed = Integer.MAX_VALUE;

        for (int j = 0; j < special[offerIndex].length; j++) {
            if (j >= needs.length) continue;

            int offerCost = special[offerIndex][j] * price[j];
            int extraItems = special[offerIndex][j];

            if (usedItems + extraItems <= needs[j]) {
                offerUsed = Math.min(offerUsed, computeMinCost(index + 1, usedItems + extraItems, price, needs, special, offerIndex, minCost) + offerCost);
            }
        }

        minCost[index + 1] = Math.min(notUsed, offerUsed);
        return minCost[index + 1];
    }
}

