import java.util.HashMap;
import java.util.Map;

class Solution {
    public boolean winnerOfGame(String colors) {
        if (colors == null || colors.length() < 3) {
            throw new IllegalArgumentException("Invalid input: Colors string must have at least three characters.");
        }

        int aScore = 0, bScore = 0;
        for (int i = 1; i < colors.length() - 1; i++) {
            char current = colors.charAt(i);
            if (colors.charAt(i - 1) == current && colors.charAt(i + 1) == current) {
                if (current == 'A') {
                    aScore++;
                } else if (current == 'B') {
                    bScore++;
                }
            }
        }
        return aScore > bScore;
    }

    public boolean canJump(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Invalid input: The nums array cannot be null or empty.");
        }

        int lastReachable = 0;
        for (int i = 0; i < nums.length; i++) {
            if (i > lastReachable) {
                return false; // not reachable
            }
            lastReachable = Math.max(lastReachable, i + nums[i]);
            if (lastReachable >= nums.length - 1) {
                return true; // reachable
            }
        }
        return false;
    }

    public int findTargetSumWays(int[] nums, int target) {
        if (nums == null) {
            throw new IllegalArgumentException("Invalid input: The nums array cannot be null.");
        }

        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        if (target > sum || (sum + target) % 2 != 0) {
            return 0;
        }

        int subsetSum = (sum + target) / 2;
        return countSubsets(nums, subsetSum);
    }

    private int countSubsets(int[] nums, int sum) {
        int n = nums.length;
        int[] dp = new int[sum + 1];
        dp[0] = 1;

        for (int num : nums) {
            for (int j = sum; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }
        return dp[sum];
    }

    public static void main(String[] args) {
        Solution solution = new Solution();

        try {
            System.out.println(solution.winnerOfGame("AAABABB")); // true
            System.out.println(solution.winnerOfGame("AA")); // IllegalArgumentException
        } catch (Exception e) {
            System.err.println(e.getMessage());
        }

        try {
            int[] nums1 = {2, 3, 1, 1, 4};
            System.out.println(solution.canJump(nums1)); // true
            int[] nums2 = {3, 2, 1, 0, 4};
            System.out.println(solution.canJump(nums2)); // false
        } catch (Exception e) {
            System.err.println(e.getMessage());
        }

        try {
            int[] nums3 = {1, 1, 1, 1, 1};
            int target = 3;
            System.out.println(solution.findTargetSumWays(nums3, target)); // 5
        } catch (Exception e) {
            System.err.println(e.getMessage());
        }
    }
}

import java.util.*;

class Solution {
    public int[] getOrder(int[][] tasks) {
        if (tasks == null || tasks.length == 0) {
            throw new IllegalArgumentException("Tasks array cannot be null or empty.");
        }

        int n = tasks.length;
        int[][] orderedTasks = new int[n][];

        for (int i = 0; i < n; i++) {
            orderedTasks[i] = new int[] {tasks[i][0], tasks[i][1], i};
        }

        Arrays.sort(orderedTasks, Comparator.comparingInt(a -> a[0]));

        PriorityQueue<int[]> taskQueue = new PriorityQueue<>(
            Comparator.comparingInt((int[] a) -> a[1])
                .thenComparingInt(a -> a[2])
        );

        int[] result = new int[n];
        int taskIndex = 0, currentTime = orderedTasks[0][0], resultIndex = 0;

        taskQueue.offer(orderedTasks[0]);

        while (resultIndex < n) {
            while (taskIndex < n && orderedTasks[taskIndex][0] <= currentTime) {
                taskQueue.offer(orderedTasks[taskIndex]);
                taskIndex++;
            }

            if (taskQueue.isEmpty()) {
                if (taskIndex < n) {
                    currentTime = orderedTasks[taskIndex][0];
                }
            } else {
                int[] currentTask = taskQueue.poll();
                result[resultIndex++] = currentTask[2];
                currentTime += currentTask[1];
            }
        }

        return result;
    }
}

public class EmployeeInformTimeCalculator {
    private int maxInformTime;

    public int numOfMinutes(int n, int headID, int[] manager, int[] informTime) {
        if (n <= 0 || headID < 0 || headID >= n || manager == null || informTime == null) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }
        maxInformTime = 0;

        for (int employeeId = 0; employeeId < n; employeeId++) {
            if (employeeId != headID) {
                maxInformTime = Math.max(maxInformTime, calculateInformTime(employeeId, headID, manager, informTime));
            }
        }
        return maxInformTime;
    }

    private int calculateInformTime(int id, int currHead, int[] manager, int[] informTime) {
        if (manager[id] != currHead) {
            int informDuration = informTime[manager[id]];
            manager[id] = currHead; // Update manager reference to avoid recomputation
            return informDuration + calculateInformTime(manager[id], currHead, manager, informTime);
        }
        return informTime[id];
    }
}

private static final int MOD = 1000000007;

public class PathCounter {
    public int countIncreasingPaths(int[][] grid) {
        validateGrid(grid);
        int[] results = new int[grid.length];
        for (int i = grid.length - 1; i >= 0; i--) {
            for (int j = 0; j < grid[i].length; j++) {
                results[j] = computePaths(i, j, grid);
            }
        }
        return computeTotalPaths(results);
    }

    private int computePaths(int row, int col, int[][] grid) {
        if (grid[row][col] == 0) return 0;
        if (isBottomRightCell(row, col, grid)) return 1;

        int pathCount = 0;
        int[] rowMoves = {-1, 0, 1, 0};
        int[] colMoves = {0, 1, 0, -1};

        for (int k = 0; k < 4; k++) {
            int newRow = row + rowMoves[k];
            int newCol = col + colMoves[k];
            if (isValidMove(newRow, newCol, grid) && grid[row][col] < grid[newRow][newCol]) {
                pathCount = (pathCount + computePaths(newRow, newCol, grid)) % MOD;
            }
        }
        return pathCount;
    }

    private boolean isBottomRightCell(int row, int col, int[][] grid) {
        return row == grid.length - 1 && col == grid[0].length - 1;
    }

    private boolean isValidMove(int row, int col, int[][] grid) {
        return row >= 0 && row < grid.length && col >= 0 && col < grid[0].length;
    }

    private int computeTotalPaths(int[] results) {
        int totalPaths = 0;
        for (int paths : results) {
            totalPaths = (totalPaths + paths) % MOD;
        }
        return totalPaths;
    }

    private void validateGrid(int[][] grid) {
        if (grid == null || grid.length == 0 || grid[0].length == 0) {
            throw new IllegalArgumentException("Grid cannot be null or empty");
        }
    }
}

