import java.util.*;

public class GameOfLife {
    private static final int[] dx = new int[]{-1, 0, 1, -1, 1, -1, 0, 1};
    private static final int[] dy = new int[]{-1, -1, -1, 0, 0, 1, 1, 1};

    public static void main(String[] args) {
        if (args.length < 3) {
            System.err.println("Usage: java GameOfLife <N> <M> <grid rows...> <cycles>");
            return;
        }

        try {
            int N = Integer.parseInt(args[0]);
            int M = Integer.parseInt(args[1]);
            char[][] grid = new char[N][M];
            boolean[][] newGrid = new boolean[N][M];

            loadGrid(grid, args, N);

            int cycles = Integer.parseInt(args[N + 2]);
            for (int cycle = 0; cycle < cycles; cycle++) {
                evolveGrid(grid, newGrid);
                copyGrid(newGrid, grid);
            }
            System.out.println("------------- Result ------------------");
            printGrid(grid);
        } catch (NumberFormatException e) {
            System.err.println("Invalid number format in input.");
        } catch (ArrayIndexOutOfBoundsException e) {
            System.err.println("Error: Not enough grid rows provided.");
        }
    }

    private static void loadGrid(char[][] grid, String[] args, int N) {
        for (int i = 0; i < N; i++) {
            if (args[i + 2].length() != grid[i].length) {
                throw new IllegalArgumentException("Grid row length mismatch.");
            }
            grid[i] = args[i + 2].toCharArray();
        }
    }

    private static void evolveGrid(char[][] grid, boolean[][] newGrid) {
        for (int i = 0; i < grid.length; i++) {
            for (int j = 0; j < grid[0].length; j++) {
                cellEvolve(grid, newGrid, i, j);
            }
        }
    }

    private static void cellEvolve(char[][] grid, boolean[][] newGrid, int x, int y) {
        int liveNeighbors = countLiveNeighbors(grid, x, y);
        if (grid[x][y] == '*' && (liveNeighbors < 2 || liveNeighbors > 3)) {
            newGrid[x][y] = false; // Dies
        } else if (grid[x][y] == '.' && liveNeighbors == 3) {
            newGrid[x][y] = true; // Comes to life
        } else {
            newGrid[x][y] = (grid[x][y] == '*'); // Remains the same
        }
    }

    private static int countLiveNeighbors(char[][] grid, int x, int y) {
        int count = 0;
        for (int d = 0; d < 8; d++) {
            int newX = x + dx[d];
            int newY = y + dy[d];
            if (isValidCell(grid, newX, newY) && grid[newX][newY] == '*') {
                count++;
            }
        }
        return count;
    }

    private static boolean isValidCell(char[][] grid, int x, int y) {
        return x >= 0 && x < grid.length && y >= 0 && y < grid[0].length;
