public class Solution {
    public int movesToMakeZigzag(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array cannot be null or empty.");
        }

        int n = nums.length;
        int resEven = 0, resOdd = 0;

        for (int i = 0; i < n; i++) {
            int minAdjacent = getMinAdjacent(nums, i, n);
            if (nums[i] > minAdjacent) {
                if (i % 2 == 0) {
                    resEven += nums[i] - minAdjacent;
                } else {
                    resOdd += nums[i] - minAdjacent;
                }
            }
        }

        return Math.min(resEven, resOdd);
    }

    private int getMinAdjacent(int[] nums, int index, int length) {
        int min = Integer.MAX_VALUE;
        if (index > 0) {
            min = Math.min(min, nums[index - 1]);
        }
        if (index < length - 1) {
            min = Math.min(min, nums[index + 1]);
        }
        return min == Integer.MAX_VALUE ? 0 : min;
    }
}

