public class LargestValues {
    private static final Scanner scanner = new Scanner(System.in);

    public static void main(String[] args) {
        StringBuilder resultBuilder = new StringBuilder();
        try {
            int testCases = validateInput(scanner);
            for (int i = 0; i < testCases; i++) {
                resultBuilder.append(processPair()).append("\n");
            }
            System.out.print(resultBuilder);
        } catch (InputMismatchException e) {
            System.err.println("Invalid input. Please ensure you're entering integers.");
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        } finally {
            scanner.close();
        }
    }

    private static int validateInput(Scanner scanner) {
        if (!scanner.hasNextInt()) {
            throw new InputMismatchException();
        }
        return scanner.nextInt();
    }

    private static int processPair() {
        try {
            int firstValue = scanner.nextInt();
            int secondValue = scanner.nextInt();
            return calculateLargestValue(firstValue, secondValue);
        } catch (InputMismatchException e) {
            System.err.println("Expected an integer input. Please try again.");
            throw e; 
        }
    }

    private static int calculateLargestValue(int firstValue, int secondValue) {
        String binaryFirst = Integer.toBinaryString(firstValue);
        String binarySecond = Integer.toBinaryString(secondValue);

        int maxLength = Math.max(binaryFirst.length(), binarySecond.length());
        int paddedBinarySecond = secondValue << maxLength;
        int binaryFirstValue = Integer.parseInt(binaryFirst, 2) << (maxLength - binarySecond.length());

        return paddedBinarySecond + binaryFirstValue;
    }
}

public int numRookCaptures(char[][] board) {
    if (board == null || board.length != 8 || board[0].length != 8) {
        throw new IllegalArgumentException("Invalid board configuration.");
    }

    int rookX = -1, rookY = -1;
    int totalCaptures = 0;

    // Locate the Rook
    for (int i = 0; i < 8; i++) {
        for (int j = 0; j < 8; j++) {
            if (board[i][j] == 'R') {
                rookX = i;
                rookY = j;
                break;
            }
        }
    }

    if (rookX == -1) {
        throw new IllegalStateException("Rook not found on the board.");
    }

    // Check the four possible directions for captures
    totalCaptures += checkDirection(board, rookX, rookY, -1, 0); // Up
    totalCaptures += checkDirection(board, rookX, rookY, 1, 0);  // Down
    totalCaptures += checkDirection(board, rookX, rookY, 0, -1); // Left
    totalCaptures += checkDirection(board, rookX, rookY, 0, 1);  // Right

    return totalCaptures;
}

private int checkDirection(char[][] board, int startX, int startY, int deltaX, int deltaY) {
    int captures = 0;
    int x = startX + deltaX;
    int y = startY + deltaY;

    while (isValidPosition(x, y)) {
        if (board[x][y] == 'B') {
            break; // Blocked by Bishop
        }
        if (board[x][y] == 'p') {
            captures++; // Capture the Pawn
            break; // Stop after capturing
        }
        x += deltaX;
        y += deltaY;
    }

    return captures;
}

private boolean isValidPosition(int x, int y) {
    return x >= 0 && x < 8 && y >= 0 && y < 8;
}

import java.util.HashSet;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Solution {
    private static final Logger LOGGER = Logger.getLogger(Solution.class.getName());

    public int findMissingNumbers(int[] nums, int lower, int upper) {
        if (nums == null) {
            LOGGER.log(Level.SEVERE, "Input array is null.");
            throw new IllegalArgumentException("Input array cannot be null.");
        }

        if (lower > upper) {
            LOGGER.log(Level.SEVERE, "Invalid bounds: lower ({0}) cannot be greater than upper ({1}).", new Object[]{lower, upper});
            throw new IllegalArgumentException("Lower bound must be less than or equal to upper bound.");
        }

        Set<Integer> uniqueNumbers = new HashSet<>();
        int count = 0;

        for (int val : nums) {
            if (val >= lower && val <= upper) {
                uniqueNumbers.add(val);
            }
        }

        for (int number : uniqueNumbers) {
            int complement = lower - number;
            if (uniqueNumbers.contains(complement)) {
                count++;
            }
        }

        LOGGER.log(Level.INFO, "Count of missing numbers is: {0}", count);
        return count;
    }
}

