import java.util.*;

class Solution {
    public String findLexSmallestString(String s, int a, int b) {
        if (s == null || s.isEmpty() || a < 0 || b < 0) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }

        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.offer(s);
        visited.add(s);

        String result = s;

        while (!queue.isEmpty()) {
            String current = queue.poll();
            result = current.compareTo(result) < 0 ? current : result;

            String addedString = addA(current, a);
            enqueueIfNotVisited(queue, visited, addedString);

            String rotatedString = rotate(current, b);
            enqueueIfNotVisited(queue, visited, rotatedString);
        }

        return result;
    }

    private void enqueueIfNotVisited(Queue<String> queue, Set<String> visited, String value) {
        if (visited.add(value)) {
            queue.offer(value);
        }
    }

    private String addA(String s, int a) {
        StringBuilder modifiedString = new StringBuilder(s);

        for (int i = 1; i < s.length(); i += 2) {
            int digit = (s.charAt(i) - '0' + a) % 10;
            modifiedString.setCharAt(i, (char) ('0' + digit));
        }

        return modifiedString.toString();
    }

    private String rotate(String s, int b) {
        int length = s.length();
        if (length == 0 || b <= 0) {
            return s;
        }
        b = b % length; 
        return s.substring(length - b) + s.substring(0, length - b);
    }
}

