public class NumberReversal {

    public static void main(String[] args) {
        try {
            System.out.println(distinctAfterReversal(new int[]{1, 13, 10, 12, 31})); // 6
            System.out.println(distinctAfterReversal(new int[]{2, 2, 2})); // 1
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    public static int distinctAfterReversal(int[] nums) {
        Set<Integer> seen = new HashSet<>();
        for (int num : nums) {
            seen.add(num);
            seen.add(reverse(num));
        }
        return seen.size();
    }

    private static int reverse(int x) {
        int res = 0;
        while (x != 0) {
            int digit = x % 10;
            x /= 10;
            if (res > (Integer.MAX_VALUE - digit) / 10) {
                return 0; // Overflow case
            }
            res = res * 10 + digit;
        }
        return res;
    }
}

class Solution {
    public int characterReplacement(String text) {
        if (text == null || text.isEmpty()) {
            return 0;
        }

        int[] charCount = new int[26];
        int maxCount = 0, maxLength = 0, allowedReplacements = 1;
        int start = 0;

        for (int end = 0; end < text.length(); end++) {
            char currentChar = text.charAt(end);
            charCount[currentChar - 'a']++;
            maxCount = Math.max(maxCount, charCount[currentChar - 'a']);

            while (end - start + 1 - maxCount > allowedReplacements) {
                char leftChar = text.charAt(start);
                charCount[leftChar - 'a']--;
                start++;
            }

            maxLength = Math.max(maxLength, end - start + 1);
        }

        return maxLength;
    }
}

private static final class Kw {
    public final String key;
    public final long weight;

    private Kw(String key, long weight) {
        this.key = key;
        this.weight = weight;
    }
}

private final Map<String, List<Kw>> entriesMap = new HashMap<>();
private final Comparator<Kw> comparator = Comparator.comparingLong(kw -> kw.weight);

public TimeMap() {}

public void set(String key, String value, int timestamp) {
    if (key == null || value == null || timestamp < 0) {
        throw new IllegalArgumentException("Invalid key, value, or timestamp.");
    }
    entriesMap.computeIfAbsent(key, k -> new ArrayList<>()).add(new Kw(value, timestamp));
}

public String get(String key, int timestamp) {
    if (key == null || timestamp < 0) {
        throw new IllegalArgumentException("Invalid key or timestamp.");
    }
    List<Kw> kvPairs = entriesMap.get(key);
    if (kvPairs == null || kvPairs.isEmpty()) {
        return "";
    }

    int index = Collections.binarySearch(kvPairs, new Kw(null, timestamp), comparator);
    if (index < 0) {
        index = -index - 2;
    }

    if (index < 0) {
        return "";
    }

    return kvPairs.get(index).key;
}

