public class Solution {
    private static final int MAX_TIME = Integer.MAX_VALUE;

    public int secondMinimum(int n, List<List<Integer>> edges, int time, int change) {
        if (n <= 0 || edges == null || edges.isEmpty() || time < 0 || change < 0) {
            throw new IllegalArgumentException("Invalid input parameters.");
        }

        List<List<Integer>> graph = createGraph(n, edges);
        int[] dp = new int[n];
        int[] dpMin = new int[n];
        Arrays.fill(dp, MAX_TIME);
        Arrays.fill(dpMin, MAX_TIME);
        dp[0] = 0;

        for (int i = 0; i < n; i++) {
            if (!processNode(graph, dp, dpMin, time, change, i)) {
                logError("Node processing failed for node: " + i);
            }
        }

        return dp[n - 1] == MAX_TIME ? -1 : dp[n - 1];
    }

    private List<List<Integer>> createGraph(int n, List<List<Integer>> edges) {
        List<List<Integer>> graph = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (List<Integer> edge : edges) {
            graph.get(edge.get(0)).add(edge.get(1));
            graph.get(edge.get(1)).add(edge.get(0));
        }
        return graph;
    }

    private boolean processNode(List<List<Integer>> graph, int[] dp, int[] dpMin, int time, int change, int start) {
        List<Integer> queue = new ArrayList<>();
        queue.add(start);

        while (!queue.isEmpty()) {
            int curr = queue.remove(queue.size() - 1);
            for (int neighbor : graph.get(curr)) {
                if (dp[neighbor] > dp[curr]) {
                    dp[neighbor] = dp[curr];
                    dpMin[neighbor] = dpMin[curr];
                } else if (dp[neighbor] > dpMin[neighbor]) {
                    dpMin[neighbor] = dp[neighbor];
                }

                int newTime = dp[neighbor] + time + change;
                if (newTime < dp[neighbor]) {
                    dp[neighbor] = newTime;
                    queue.add(neighbor);
                }
            }
        }
        return true;
    }

    private void logError(String message) {
        System.err.println("Error: " + message);
    }
}

