import java.util.*;

class Solution {
    private static final int MAX_LOG = 20;
    private Scanner sc = new Scanner(System.in);

    public void solve(int TC) {
        int n = sc.nextInt();
        List<Edge>[] graph = new ArrayList[n];
        int[][] parent = new int[n][MAX_LOG];
        int[] depth = new int[n];
        int[] newDepth = new int[n];
        int[] bestFirst = new int[n];
        Stack<Integer> stack = new Stack<>();

        initializeGraph(graph, n);
        readEdges(graph, n);
        depthFirstSearch(0, -1, 0, graph, parent, depth, stack, newDepth, bestFirst);

        List<Integer> ans = new ArrayList<>();
        while (!stack.isEmpty()) {
            int node = stack.pop();
            processNode(node, graph, newDepth, ans);
        }

        printResult(ans);
    }

    private void initializeGraph(List<Edge>[] graph, int n) {
        for (int i = 0; i < n; i++) {
            graph[i] = new ArrayList<>();
        }
    }

    private void readEdges(List<Edge>[] graph, int n) {
        for (int i = 0; i < n - 1; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            graph[u].add(new Edge(i, v));
            graph[v].add(new Edge(i, u));
        }
    }

    private void depthFirstSearch(int node, int parent, int currentDepth, List<Edge>[] graph,
                                  int[][] parentArr, int[] depth, Stack<Integer> stack,
                                  int[] newDepth, int[] bestFirst) {
        newDepth[node] = currentDepth;
        bestFirst[node] = node;
        stack.push(node);

        for (Edge edge : graph[node]) {
            if (edge.target == parent || newDepth[edge.target] > 0) continue;
            depthFirstSearch(edge.target, node, currentDepth + 1, graph, parentArr, depth, stack, newDepth, bestFirst);
        }

        updateBestFirst(node, graph, parent, newDepth, bestFirst);
    }

    private void updateBestFirst(int node, List<Edge>[] graph, int parent, int[] newDepth, int[] bestFirst) {
        for (Edge edge : graph[node]) {
            if (edge.target == parent || (newDepth[edge.target] == newDepth[node] + 1)) continue;
            if (newDepth[bestFirst[node]] < newDepth[edge.target]) {
                bestFirst[node] = edge.target;
            }
        }
    }

    private void processNode(int node, List<Edge>[] graph, int[] newDepth, List<Integer> ans) {
        for (Edge edge : graph[node]) {
            if (newDepth[edge.target] == newDepth[node] + 1) {
                ans.add(edge.target);
            }
        }
    }

    private void printResult(List<Integer> ans) {
        // Output the result as desired (e.g., print to console)
        for (int result : ans) {
            System.out.println(result + 1); // Assuming a 1-based index output
        }
    }

    class Edge {
        int index;
        int target;

        Edge(int index, int target) {
            this.index = index;
            this.target = target;
        }
    }
}

class Solution {
    public int maxConsecutive(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException("Input array cannot be null or empty");
        }

        int maxCount = 0;
        int currentCount = 0;

        for (int num : nums) {
            if (num < 0) {
                currentCount = 0; // Reset count on negative number
            } else {
                currentCount++;
                maxCount = Math.max(maxCount, currentCount);
            }
        }

        return maxCount;
    }
}

