        }

        return results;
    }

    private void buildPrerequisiteMap(int[][] prerequisites, Map<Integer, List<Integer>> courseDependencies) {
        for (int[] prereq : prerequisites) {
            courseDependencies.computeIfAbsent(prereq[1], k -> new ArrayList<>()).add(prereq[0]);
        }
    }

    private void processCourses(int numCourses, Map<Integer, List<Integer>> courseDependencies, boolean[] processed) {
        for (int course = 0; course < numCourses; course++) {
            if (!processed[course]) {
                traverseCourseDependencies(course, courseDependencies, processed);
            }
        }
    }

    private void traverseCourseDependencies(int course, Map<Integer, List<Integer>> courseDependencies, boolean[] processed) {
        if (processed[course]) return;

        processed[course] = true;

        if (courseDependencies.containsKey(course)) {
            for (int prerequisite : courseDependencies.get(course)) {
                traverseCourseDependencies(prerequisite, courseDependencies, processed);
            }
        }
    }

    private boolean checkPrerequisite(int course, int prerequisite) {
        return prerequisiteMap.getOrDefault(course, Collections.emptySet()).contains(prerequisite);
    }
}

import java.io.*;

public class Main {
    private static final int MOD = (int) 1e9 + 7;
    private static BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
    private static PrintWriter writer = new PrintWriter(System.out);

    private static int readInt() throws IOException {
        String line = reader.readLine();
        if (line == null || line.trim().isEmpty()) {
            throw new IOException("Input error: Expected an integer.");
        }
        return Integer.parseInt(line.trim());
    }

    public static void main(String[] args) {
        try {
            int T = readInt(); // Number of test cases
            for (int t = 0; t < T; t++) {
                processTestCase();
            }
        } catch (IOException e) {
            writer.println("Error reading input: " + e.getMessage());
        } finally {
            writer.flush();
            writer.close();
        }
    }

    private static void processTestCase() throws IOException {
        int n = readInt();
        int m = readInt();
        int k = readInt();

        if (!isValidInput(n, m, k)) {
            writer.println("Error: Invalid input parameters.");
            return;
        }

        int score = (int) ((long) k * m % MOD);
        int z = (n - m) / 2;
        int zmax = (n - m) % 2 == 0 ? z : z + 1;

        for (int i = 0; i < zmax; i++) {
            score = (int) ((score * k + z % 2) % MOD);
        }

        writer.println(score);
    }

    private static boolean isValidInput(int n, int m, int k) {
        return n >= 0 && m >= 0 && k >= 0 && m <= n;
    }
}

class Solution {
    public int largestPerimeter(int[] nums) {
        if (nums == null || nums.length < 3) {
            return 0;
        }

        Arrays.sort(nums);
        int n = nums.length;

        for (int i = n - 1; i >= 2; i--) {
            int sum = nums[i] + nums[i - 1];
            if (sum > nums[i - 2]) {
                return sum;
            }
        }

        return 0;
    }
}

import java.util.Arrays;
import java.util.Scanner;

public class Main {
    private int ans;

    private int absoluteValue(long value) {
        return (int) (value >= 0 ? value : -value);
    }

    private int maximum(int first, int second) {
        return (first >= second ? first : second);
    }

    private int minimum(int first, int second) {
        return (first <= second ? first : second);
    }

    private int compute(int[] array, int index, int currentSum) {
        ans += currentSum;
        if (index == array.length) {
            return ans;
        }

        if (index + 1 < array.length) {
            int nextValue = absoluteValue(array[index + 1]);
            return minimum(
                compute(array, index + 2, maximum(ans + nextValue - array[index + 1], ans + absoluteValue(array[index]))),
                compute(array, index + 2, maximum(ans + absoluteValue(array[index] + 1) - array[index], ans + nextValue))
            );
        } else {
            return compute(array, index + 1, ans);
        }
    }

    private void solve(int length, int[] array) {
        if (length <= 1) {
            System.out.println("0");
            return;
        }
        Arrays.sort(array);
        ans = 0;
        System.out.println(compute(array, 1, 0));
    }

    public static void main(String[] args) {
        Main mainInstance = new Main();
        try (Scanner scanner = new Scanner(System.in)) {
            int length = scanner.nextInt();
            if (length <= 1) {
                System.out.println("0");
                return;
            }
            int[] numbers = new int[length];
            for (int i = 0; i < length; i++) {
                numbers[i] = scanner.nextInt();
            }
            mainInstance.solve(length, numbers);
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }
}

import java.util.*;

public class AquaMoonAndTwoArrays {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = validateInput(scanner);
            for (int ti = 0; ti < testCases; ti++) {
                processTestCase(scanner);
            }
        } catch (InputMismatchException e) {
            System.err.println("Invalid input format. Please enter integers only.");
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }

    private static int validateInput(Scanner scanner) {
        if (!scanner.hasNextInt()) {
            throw new InputMismatchException("The number of test cases must be an integer.");
        }
        return scanner.nextInt();
    }

    private static void processTestCase(Scanner scanner) {
        int n = validateArraySize(scanner);
        int[] a = new int[n];
        int[] b = new int[n];
        int sumA = readArray(scanner, a);
        int sumB = readArray(scanner, b);

        if (sumA != sumB) {
            System.out.println(-1);
            return;
        }

        List<Pair> operations = findOperations(a, b);
        if (!Arrays.equals(a, b)) {
            System.out.println(-1);
        } else {
            System.out.println(operations.size());
            for (Pair op : operations) {
                System.out.println(op.i + " " + op.j);
            }
        }
    }

    private static int validateArraySize(Scanner scanner) {
        if (!scanner.hasNextInt()) {
            throw new InputMismatchException("Array size must be an integer.");
        }
        return scanner.nextInt();
    }

    private static int readArray(Scanner scanner, int[] array) {
        int sum = 0;
        for (int i = 0; i < array.length; i++) {
            if (!scanner.hasNextInt()) {
                throw new InputMismatchException("Array elements must be integers.");
            }
            array[i] = scanner.nextInt();
            sum += array[i];
        }
        return sum;
    }

    private static List<Pair> findOperations(int[] a, int[] b) {
        List<Pair> operations = new ArrayList<>();
        for (int i = 0; i < a.length; i++) {
            if (a[i] > b[i]) {
                for (int j = 0; j < a.length; j++) {
                    if (a[i] > b[i] && a[j] < b[j]) {
                        int diff = Math.min(a[i] - b[i], b[j] - a[j]);
                        a[i] -= diff;
                        a[j] += diff;
                        for (int k = 0; k < diff; k++) {
                            operations.add(new Pair(i + 1, j + 1));
                        }
                    }
                }
            }
        }
        return operations;
    }

    static class Pair {
        int i, j;

        Pair(int i, int j) {
            this.i = i;
            this.j = j;
        }
    }
}

