                StringBuilder stringT = new StringBuilder(INITIAL_STRING);

                for (int i = 0; i < queries; i++) {
                    String[] line = reader.readLine().split(" ");
                    int direction = Integer.parseInt(line[0]);
                    int repetitions = Integer.parseInt(line[1]);
