        if (s.length() < t.length()) return true;
        if (s.length() > t.length()) return false;

        for (int j = 0; j < s.length(); j++) {
            if (s.charAt(j) < t.charAt(j)) return true;
            if (s.charAt(j) > t.charAt(j)) return false;
        }
        return false;
    }
