        }
    }

    private static void processBitStrings(List<String> bitStrings) {
        for (String bitString : bitStrings) {
            int decimalValue = convertToDecimal(bitString);
            System.out.println("Binary: " + bitString + " -> Decimal: " + decimalValue);
