        int result = 0;
        for (char bit : bitString.toCharArray()) {
            result = (result << 1) | (bit == '1' ? 1 : 0);
        }
        return result;
    }
}

import java.io.*;
import java.util.*;

public class LostPermutation {
    public static void main(String[] args) {
        try (Kattio io = new Kattio()) {
            int testCases = io.nextInt();
            for (int i = 0; i < testCases; i++) {
                processTestCase(io);
            }
        } catch (IOException e) {
            System.err.println("Error processing input: " + e.getMessage());
        }
    }

    private static void processTestCase(Kattio io) {
        int m = io.nextInt();
        int s = io.nextInt();
        int[] nums = io.getIntArray(m);

        int maxNum = Arrays.stream(nums).max().orElse(0);
        int totalSum = (maxNum * (maxNum + 1)) / 2;

        if (isValidCase(m, s, totalSum)) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }

    private static boolean isValidCase(int m, int s, int totalSum) {
        if (m == 1 && s == 1) {
            return false;
        } else if (m == 1 && s > 1) {
            return true;
        } else {
            int adjustedSum = totalSum + s - m;
            if (adjustedSum < 1 || adjustedSum > 50000) {
                return false;
            }
            int newMaxNum = adjustedSum + m - s;
            return (newMaxNum * (newMaxNum + 1)) / 2 == adjustedSum;
        }
    }

    static class Kattio extends PrintWriter {
        private BufferedReader reader;
        private StringTokenizer tokenizer;

        public Kattio() {
            this(System.in, System.out);
        }

        public Kattio(InputStream inputStream, OutputStream outputStream) {
            super(outputStream);
            reader = new BufferedReader(new InputStreamReader(inputStream));
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException("Error reading input", e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

        public int[] getIntArray(int size) {
            int[] array = new int[size];
            for (int i = 0; i < size; i++) {
                array[i] = nextInt();
            }
            return array;
        }

        @Override
        public void close() {
            super.close();
            try {
                reader.close();
            } catch (IOException e) {
                System.err.println("Error closing reader: " + e.getMessage());
            }
        }
    }
}

import java.util.List;

public class PalindromeCounter {

    public int countPalindromes(List<String> words) {
        if (words == null || words.isEmpty()) {
            return 0;
        }

        int palindromeCount = 0;

        for (String word : words) {
            if (isValidWord(word) && isPalindrome(word)) {
                palindromeCount++;
            }
        }

        return palindromeCount;
    }

    private boolean isValidWord(String word) {
        return word != null && !word.trim().isEmpty();
    }

    private boolean isPalindrome(String word) {
        int left = 0;
        int right = word.length() - 1;

        while (left < right) {
            if (word.charAt(left) != word.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }

        return true;
    }
}

