interface MountainArray {
    int get(int index);
    int length();
}

class Solution {
    public int findPeakIndex(MountainArray mountainArr) {
        if (mountainArr == null || mountainArr.length() < 3) {
            throw new IllegalArgumentException("MountainArray must not be null and must have at least 3 elements.");
        }

        int left = 0;
        int right = mountainArr.length() - 1;

        while (left < right) {
            int mid = left + (right - left) / 2;

            try {
                int midVal = mountainArr.get(mid);
                int nextVal = mountainArr.get(mid + 1);

                if (midVal < nextVal) {
                    left = mid + 1;
                } else {
                    right = mid;
                }
            } catch (IndexOutOfBoundsException e) {
                throw new RuntimeException("Index out of bounds while accessing MountainArray.", e);
            }
        }

        return left;
    }
}

public class Solution {
    public int[] constructArray(int n, int k) {
        if (n < 1 || k < 1 || k >= n) {
            throw new IllegalArgumentException("Invalid input: n must be >= 1 and 1 <= k < n");
        }

        int[] array = new int[n];
        int left = 1;
        int right = n;
        int index = 0;

        try {
            while (left <= right) {
                if (k > 1) {
                    array[index++] = (k % 2 == 1) ? left++ : right--;
                    k--;
                } else {
                    array[index++] = left++;
                }
            }
        } catch (ArrayIndexOutOfBoundsException e) {
            logError("Array index out of bounds during array construction: " + e.getMessage());
        }

        return array;
    }

    private void logError(String message) {
        System.err.println("ERROR: " + message);
    }
}

