                return;
            }
            int testCases = scanner.nextInt();
            while (testCases-- > 0) {
                if (!scanner.hasNextInt()) {
                    System.err.println("Invalid input for number of trees.");
                    return;
                }
                int numberOfTrees = scanner.nextInt();
                long targetHeight = 0;

                for (int i = 0; i < numberOfTrees; i++) {
                    if (!scanner.hasNextLong()) {
                        System.err.println("Invalid input for tree height.");
                        return;
                    }
                    targetHeight = Math.max(targetHeight, scanner.nextLong());
                }

                long sumOfExtra = 0;
                for (int i = 0; i < numberOfTrees; i++) {
                    if (!scanner.hasNextLong()) {
