                        return;
                    }
                    long currentTreeHeight = scanner.nextLong();
                    sumOfExtra += calculateExtraHeight(targetHeight, currentTreeHeight);
                }
                System.out.println(sumOfExtra - 2);
            }
        } catch (Exception e) {
