import java.util.Scanner;
import java.util.List;
import java.util.ArrayList;

public class MaxDifferenceSubarray {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int testCases = inputValidation(scanner);

        while (testCases-- > 0) {
            int n = inputValidation(scanner);
            List<Integer> a = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                a.add(inputValidation(scanner));
            }
            int result = findMaxDifferenceSubarray(a);
            System.out.println(result);
        }
        scanner.close();
    }

    private static int inputValidation(Scanner scanner) {
        while (true) {
            if (scanner.hasNextInt()) {
                return scanner.nextInt();
            } else {
                scanner.next(); // clear invalid input
                System.out.println("Invalid input. Please enter a number.");
            }
        }
    }

    private static int findMaxDifferenceSubarray(List<Integer> a) {
        int maxLength = 0;
        int maxVal = a.stream().mapToInt(Integer::intValue).max().orElse(0);

        for (int i = 0; i < a.size(); i++) {
            for (int j = i + 1; j < a.size(); j++) {
                if (Math.abs(a.get(i) - a.get(j)) >= maxVal) {
                    maxLength = Math.max(maxLength, j - i);
                    break; // Exit inner loop to optimize
                }
            }
        }
        return maxLength;
    }
}

import java.util.Scanner;
import java.util.Random;
import java.util.logging.Level;
import java.util.logging.Logger;

public class BanBan {

    private static final Logger LOGGER = Logger.getLogger(BanBan.class.getName());

    public static int minOperations(int n) {
        if (n <= 0) {
            LOGGER.log(Level.WARNING, "Input n must be greater than 0.");
            return 0;
        }

        int length = n * 3;
        int[] arr = new int[length + 1];

        for (int i = 0; i < length; i += 3) {
            arr[i] = 0;
            arr[i + 1] = 1;
            arr[i + 2] = -1;
        }

        int minOps = 0;

        for (int i = 0; i < length - 2; i += 3) {
            if (arr[i] == 1 && arr[i + 1] == 1 && arr[i + 2] == -1) {
                arr[i] = -1;
                arr[i + 1] = -1;
                arr[i + 2] = 0;
                minOps++;
            } else if (arr[i] == 1 && arr[i + 2] == 1 && arr[i + 1] == -1) {
                arr[i] = -1;
                arr[i + 1] = 0;
                arr[i + 2] = -1;
                minOps++;
            } else if (arr[i + 1] == 1 && arr[i + 2] == 1 && arr[i] == -1) {
                arr[i] = 0;
                arr[i + 1] = -1;
                arr[i + 2] = -1;
                minOps++;
            }
        }

        return minOps;
    }

    private static void swapAndLog(int[] arr, int i1, int j1) {
        int temp = arr[i1];
        arr[i1] = arr[j1];
        arr[j1] = temp;
        LOGGER.log(Level.INFO, "Swapped indices: {0} and {1}", new Object[] { i1 + 1, j1 + 1 });
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        try {
            int t = scanner.nextInt();

            for (int i = 0; i < t; i++) {
                int n = scanner.nextInt();
                int minOps = minOperations(n);

                Random random = new Random();
                for (int j = 0; j < minOps; j++) {
                    int i1 = random.nextInt(n * 3);
                    int j1 = random.nextInt(n * 3);

                    while (i1 == j1 || arr[i1] == -1 || arr[j1] == 1) {
                        i1 = random.nextInt(n * 3);
                        j1 = random.nextInt(n * 3);
                    }

                    swapAndLog(arr, i1, j1);
                }
                System.out.println(minOps);
            }
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "An error occurred during execution", e);
        } finally {
            scanner.close();
        }
    }
}

