    public static class Rectangle {
        private int x;
        private int y;
        private final int rows;
        private final int cols;
        private String moves;
        private int index;

        public Rectangle(int startX, int startY, int rows, int cols, String moves) {
            this.x = startX;
            this.y = startY;
            this.rows = rows;
            this.cols = cols;
            this.moves = moves;
            this.index = 0;
        }

        public void executeMoves() {
            while (isInside() && index < moves.length()) {
                move(moves.charAt(index));
                index++;
            }
        }

        private boolean isInside() {
            return x >= 0 && x < cols && y >= 0 && y < rows;
        }

        private void move(char direction) {
            switch (direction) {
                case 'L':
                    x--;
                    break;
                case 'R':
                    x++;
                    break;
                case 'U':
                    y--;
                    break;
                case 'D':
                    y++;
                    break;
                default:
                    System.err.println("Invalid direction: " + direction);
                    break;
            }
        }

        public String getTopLeft() {
            return "(" + x + ", " + y + ")";
        }
    }
}

