public class MainB2 {

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int testCases = validateInput(scanner, "Enter number of test cases: ");
            for (int caseNumber = 0; caseNumber < testCases; caseNumber++) {
                int n = validateInput(scanner, "Enter size of array: ");
                int[] numbers = readArray(scanner, n);
                int count = processArray(numbers);
                System.out.println(count);
            }
        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }

    private static int validateInput(Scanner scanner, String message) {
        int value;
        System.out.print(message);
        while (true) {
            try {
                value = Integer.parseInt(scanner.nextLine());
                if (value <= 0) throw new NumberFormatException();
                return value;
            } catch (NumberFormatException e) {
                System.out.print("Invalid input. " + message);
            }
        }
    }

    private static int[] readArray(Scanner scanner, int size) {
        int[] array = new int[size];
        System.out.print("Enter array elements: ");
        for (int i = 0; i < size; i++) {
            while (true) {
                try {
                    array[i] = Integer.parseInt(scanner.nextLine());
                    break;
                } catch (NumberFormatException e) {
                    System.out.print("Invalid input. Enter an integer: ");
                }
            }
        }
        return array;
    }

    private static int processArray(int[] array) {
        int maxElement = Arrays.stream(array).max().orElse(0);
        int[] counts = new int[maxElement + 1];
        for (int num : array) {
            counts[num]++;
        }

        int count = 0;
        for (int num : array) {
            if (counts[num] > 0) {
                counts[num]--;
                int maxDivisor = findMaxDivisor(num, counts);
                if (maxDivisor != -1) {
                    counts[maxDivisor]--;
                    adjustCounts(num, counts);
                }
                count++;
            }
        }

        return count - Arrays.stream(counts).sum();
    }

    private static int findMaxDivisor(int number, int[] counts) {
        int maxDivisor = -1;
        for (int divisor = 2; divisor * divisor <= number; divisor++) {
            if (number % divisor == 0) {
                if (counts[divisor] > 0) {
                    maxDivisor = Math.max(maxDivisor, divisor);
                }
                if (counts[number / divisor] > 0) {
                    maxDivisor = Math.max(maxDivisor, number / divisor);
                }
            }
        }
        return maxDivisor;
    }

    private static void adjustCounts(int number, int[] counts) {
        if (number % 2 == 0 && counts[number / 2] == 0) {
            counts[number / 2]++;
        }
        int maxDivisor = number % 2 == 0 ? number / 2 : -1;
        if (maxDivisor != -1 && counts[maxDivisor] == 0) {
            counts[maxDivisor]++;
        }
    }
}

