class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;

    TreeNode(int val) {
        this.val = val;
    }
}

class Solution {
    public int longestConsecutive(TreeNode root) {
        if (root == null) {
            return 0;
        }
        return findLongestConsecutive(root, null, 0);
    }

    private int findLongestConsecutive(TreeNode current, Integer parentValue, int currentLength) {
        if (current == null) {
            return currentLength;
        }

        if (parentValue != null && current.val == parentValue + 1) {
            currentLength++;
        } else {
            currentLength = 1;
        }

        int leftLength = findLongestConsecutive(current.left, current.val, currentLength);
        int rightLength = findLongestConsecutive(current.right, current.val, currentLength);

        return Math.max(currentLength, Math.max(leftLength, rightLength));
    }
}

