public int removeAlmostEqualCharacters(String word) {
    if (word == null || word.isEmpty()) {
        throw new IllegalArgumentException("Input word must not be null or empty");
    }

    int n = word.length();
    int operations = 0;

    for (int i = 0; i < n - 1; i++) {
        char currentChar = word.charAt(i);
        char nextChar = word.charAt(i + 1);

        if (Math.abs(currentChar - nextChar) <= 1) {
            operations++;
            i++; // Skip the next character as it's already almost-equal
        }
    }

    return operations;
}

