public class ProblemB {
    public static class FastScanner {
        private StringTokenizer tokenizer;
        private final BufferedReader reader;

        public FastScanner(InputStream io) {
            reader = new BufferedReader(new InputStreamReader(io));
        }

        public String nextToken() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException("Input error", e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(nextToken());
        }
    }

    public static void main(String[] args) {
        InputStream inputStream = ProblemB.class.getResourceAsStream("problemb.in");
        OutputStream outputStream = ProblemB.class.getResourceAsStream("problemb.out") == null 
            ? System.out : new PrintStream(ProblemB.class.getResourceAsStream("problemb.out"));

        FastScanner scanner = new FastScanner(inputStream);
        try {
            int testCases = 1; 
            while (testCases-- > 0) {
                solve(scanner, outputStream);
            }
        } finally {
            if (outputStream != System.out) outputStream.close();
        }
    }

    private static ArrayList<Pair<Integer, Integer>> arr = new ArrayList<>();
    private static int shuffles;

    public static void solve(FastScanner scanner, OutputStream outputStream) {
        try {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            ArrayList<Integer> table = new ArrayList<>();
            LinkedList<Integer> tokens = new LinkedList<>();

            for (int i = 1; i < m; i++) {
                tokens.offer(scanner.nextInt());
            }

            ArrayList<Integer> current = new ArrayList<>();
            for (int i = 1; i < n; i++) {
                current.add(scanner.nextInt());
            }

            Collections.sort(current);
            long ans = n;
            for (int i = 1; i < m; i++) {
                boolean found = false;
                int elem = tokens.get(i - 1);

                while (current.contains(elem)) {
                    if (!found) {
                        shuffles++;
                        found = true;
                    }
                    tokens.offer(current.get(current.indexOf(elem)) + 1);
                    int shuffledIndex = get(current.indexOf(elem) + 1);
                    if (shuffledIndex == current.indexOf(elem) + 1) {
                        ans--;
                        break;
                    }
                    current.set(current.indexOf(elem), shuffledIndex);
                }
            }
            outputStream.write((ans + "\n").getBytes());
        } catch (IOException e) {
            throw new RuntimeException("Output error", e);
        }
    }

    public static int get(int pos) {
        return shuffle(pos);
    }

    private static int shuffle(int pos) {
        int result = pos;
        while (!arr.get(result - 1).x.equals(pos)) {
            int temp = arr.get(result - 1).x;
            arr.set(result - 1, new Pair<>(pos, arr.get(result - 1).y));
            pos = temp;
        }
        arr.set(pos - 1, new Pair<>(arr.get(pos - 1).x, arr.get(pos - 1).y));
        return pos;
    }

    public static class Pair<K, T> {
        public K x;
        public T y;

        public Pair(K x, T y) {
            this.x = x;
            this.y = y;
        }

        @Override
        public String toString() {
            return String.format("Pair(%s, %s)", x, y);
        }
    }
}

