public class GridHelper {
    private char[][] grid;
    private int[] dirX = {-1, 0, 1, 0}; // Up, Right, Down, Left
    private int[] dirY = {0, 1, 0, -1};

    public void processGrid(int m, int n, char[] s, boolean[][] vis, boolean[][] vis2, int[] cnt) {
        if (m <= 0 || n <= 0 || vis == null || vis2 == null || cnt == null) {
            throw new IllegalArgumentException("Invalid grid dimensions or parameters.");
        }

        cnt[0] = m; // Initialize move count
        Queue<Pair<Integer, Integer>> queue = new LinkedList<>();

        initializeGrid(m, n, vis, vis2, cnt, queue);

        boolean flag = true; // Loop detection flag

        while (flag) {
            boolean[] visitFlags = new boolean[4];
            int currentSize = queue.size();

            for (int i = 0; i < currentSize; i++) {
                Pair<Integer, Integer> currentNode = queue.poll();
                int x = currentNode.getKey();
                int y = currentNode.getValue();

                if (vis2[x][y]) {
                    continue; // If already processed
                }

                for (int j = 0; j < 4; j++) {
                    int newX = x + dirX[j];
                    int newY = y + dirY[j];

                    if (isOutOfBounds(newX, newY, m, n) || !vis[newX][newY]) {
                        flag = false; // Node lies outside the matrix
                        continue;
                    }

                    if (grid[newX][newY] == '#') {
                        vis[newX][newY] = false; // Mark wall as unvisitable
                        if (!vis2[newX][newY]) {
                            visitFlags[j] = false; // Wall encountered
                        }
                        continue;
                    } else if (Character.isLowerCase(grid[newX][newY])) {
                        cnt[0]--; // Decrement count for unvisited key
                        vis2[newX][newY] = true; // Mark key as visited
                    }

                    visitFlags[j] = true; // Mark the direction as visitable
                }
            }

            flag = Arrays.stream(visitFlags).anyMatch(v -> v); // Check if any directions were visitable
        }
    }

    private void initializeGrid(int m, int n, boolean[][] vis, boolean[][] vis2, int[] cnt, Queue<Pair<Integer, Integer>> queue) {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == '#') {
                    vis[i][j] = false;
                    vis2[i][j] = false;
                } else if (grid[i][j] != '.' && !vis2[i][j]) {
                    cnt[0]--; // Found a new key
                } else if (isInBounds(i, j, m, n) && grid[i][j] != '@') {
                    queue.add(new Pair<>(i, j));
                    vis[i][j] = true;
                    vis2[i][j] = false;
                }
            }
        }
    }

    private boolean isInBounds(int x, int y, int m, int n) {
        return x >= 0 && x < m && y >= 0 && y < n;
    }

    private boolean isOutOfBounds(int x, int y, int m, int n) {
        return x < 0 || x >= m || y < 0 || y >= n;
    }
}

