import java.util.*;

public class MEXOperations {

    public static int[] solveMexAndIncrement(int t, int[][] testCases) {
        int[] results = new int[t];

        for (int caseIndex = 0; caseIndex < t; caseIndex++) {
            int n = testCases[caseIndex][0];
            int[] arr = Arrays.copyOfRange(testCases[caseIndex], 1, testCases[caseIndex].length);
            results[caseIndex] = calculateMinOperations(n, arr);
        }
        return results;
    }

    private static int calculateMinOperations(int n, int[] arr) {
        int[] count = new int[n + 1];
        Stack<Integer> stack = new Stack<>();
        int operations = 0;

        for (int num : arr) {
            if (num >= 0 && num <= n) {
                count[num]++;
            }
        }

        for (int i = 0; i <= n; i++) {
            if (i > Arrays.stream(count).sum()) {
                return -1; // MEX cannot be achieved for this i
            }
            if (count[i] == 0) {
                if (stack.isEmpty()) {
                    return operations + (i - 0); // Not yet any increments possible
                }
                operations += i - stack.pop();
            }
            stack.push(i);
        }

        return operations;
    }

    public static void main(String[] args) {
        int t = 2;
        int[][] testCases = {
            {5, 2, 0, 1, 3, 4},  // Example test case 1
            {4, 0, 1, 2, 2}      // Example test case 2
        };

        int[] results = solveMexAndIncrement(t, testCases);
        for (int result : results) {
            System.out.println(result);
        }
    }
}

