public class Main {
    public static void main(String[] args) {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            int n = Integer.parseInt(reader.readLine());
            if (n <= 0) {
                System.out.println("Error: Input must be a positive integer.");
                return;
            }

            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = Integer.parseInt(reader.readLine());
                if (a[i] < 0) {
                    System.out.println("Error: Elements must be non-negative integers.");
                    return;
                }
            }

            System.out.println(minShots(a));
        } catch (IOException | NumberFormatException e) {
            System.out.println("Error: Invalid input. Please enter integers only.");
        }
    }

    public static int minShots(int[] a) {
        int n = a.length;
        int[] dp = new int[n];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = (a[0] + 1) / 2; // This accounts for both odd and even cases

        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                int cost = dp[j] + a[i] - a[j] + ((i - j <= 1) ? 1 : 0);
                dp[i] = Math.min(dp[i], cost);
            }
        }

        int minShots = Arrays.stream(dp).min().orElse(Integer.MAX_VALUE);
        return (minShots == Integer.MAX_VALUE) ? -1 : minShots;
    }
}

public class Solution {
    private static final String ERROR_MESSAGE = "Input must be a positive integer.";

    public boolean isThree(int n) {
        validateInput(n);
        return countDivisors(n) == 3;
    }

    private void validateInput(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException(ERROR_MESSAGE);
        }
    }

    private int countDivisors(int n) {
        int count = 0;
        for (int i = 1; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                count += (i * i == n) ? 1 : 2; // Count divisors in pairs
            }
        }
        return count;
    }
}

