public class Solution {
    private static final String ERROR_MESSAGE = "Input array must not be null and should contain at least one element.";

    public int minOperations(int[] nums) {
        validateInput(nums);

        int totalOperations = 0;
        int maximumValue = 0;

        for (int num : nums) {
            totalOperations += countMostSignificantBit(num);
            totalOperations += countTrailingZeroes(num);
            maximumValue = Math.max(maximumValue, getHighestValue(num));
        }

        totalOperations += String.valueOf(maximumValue).length() - 1;

        return totalOperations;
    }

    private void validateInput(int[] nums) {
        if (nums == null || nums.length == 0) {
            throw new IllegalArgumentException(ERROR_MESSAGE);
        }
    }

    private int countMostSignificantBit(int num) {
        int count = 0;
        while (num != 0) {
            num >>= 1;
            count++;
        }
        return count;
    }

    private int countTrailingZeroes(int num) {
        int count = 0;
        while (num % 2 == 0 && num != 0) {
            num /= 2;
            count++;
        }
        return count;
    }

    private int getHighestValue(int num) {
        return num != 0 ? num : Integer.MIN_VALUE; // Prevents incorrect max comparison
    }
}

