import java.util.Arrays;
import java.util.Comparator;

public class ProductPurchaseOptimizer {

    static class Product {
        int requiredItems;
        int discountThreshold;

        Product(int requiredItems, int discountThreshold) {
            this.requiredItems = requiredItems;
            this.discountThreshold = discountThreshold;
        }
    }

    public static void main(String[] args) {
        Product[] products = {
            new Product(10, 5),
            new Product(15, 3),
            // Add more products as needed
        };
        try {
            int minCost = calculateMinCost(products);
            System.out.println("Minimum cost to purchase all products: " + minCost);
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static int calculateMinCost(Product[] products) {
        validateProducts(products);
        Arrays.sort(products, Comparator.comparingInt(p -> p.discountThreshold));

        int totalItemsNeeded = Arrays.stream(products).mapToInt(p -> p.requiredItems).sum();
        int totalItemsBought = 0;
        int totalCost = 0;

        int start = 0;
        int end = products.length - 1;

        while (start <= end) {
            if (totalItemsBought >= products[end].discountThreshold) {
                totalCost += buyAtDiscount(products[end], totalItemsBought);
                totalItemsBought += products[end].requiredItems;
                end--;
            } else {
                totalCost += buyAtFullPrice(products[start]);
                totalItemsBought += products[start].requiredItems;
                start++;
            }
        }
        return totalCost;
    }

    private static int buyAtDiscount(Product product, int totalItemsBought) {
        int itemsToBuy = product.requiredItems - Math.max(0, totalItemsBought);
        return itemsToBuy * 1; // Price with discount
    }

    private static int buyAtFullPrice(Product product) {
        return product.requiredItems * 2; // Full price
    }

    private static void validateProducts(Product[] products) {
        if (products == null || products.length == 0) {
            throw new IllegalArgumentException("Product list cannot be null or empty.");
        }
        for (Product product : products) {
            if (product.requiredItems < 0 || product.discountThreshold < 0) {
                throw new IllegalArgumentException("Invalid product: requirements must be non-negative.");
            }
        }
    }
}

import java.io.*;
import java.util.*;

public class Main {
    private static final int MOD = 1000000007;

    public static void main(String[] args) {
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
             BufferedWriter bw = new BufferedWriter(new OutputStreamWriter(System.out))) {
            int testCaseCount = Integer.parseInt(br.readLine().trim());
            validateInput(testCaseCount);

            while (testCaseCount-- > 0) {
                int nodeCount = Integer.parseInt(br.readLine().trim());
                validateInput(nodeCount);
                List<Integer>[] adjacencyList = createAdjacencyList(nodeCount);
                readEdges(br, adjacencyList, nodeCount);

                int primeCount = Integer.parseInt(br.readLine().trim());
                validateInput(primeCount);
                int[] primes = readPrimes(br, primeCount);
                long[] dp = initializeDPArray(nodeCount);

                long result = performDFS(1, -1, adjacencyList, primes, dp);
                bw.write(result + "\n");
            }
            bw.flush();
        } catch (IOException e) {
            System.err.println("I/O error: " + e.getMessage());
        } catch (NumberFormatException | IllegalArgumentException e) {
            System.err.println("Input error: " + e.getMessage());
        }
    }

    private static void validateInput(int value) {
        if (value <= 0) throw new IllegalArgumentException("Input must be a positive integer.");
    }

    private static List<Integer>[] createAdjacencyList(int nodeCount) {
        List<Integer>[] adj = new ArrayList[nodeCount + 1];
        for (int i = 1; i <= nodeCount; i++) {
            adj[i] = new ArrayList<>();
        }
        return adj;
    }

    private static void readEdges(BufferedReader br, List<Integer>[] adj, int nodeCount) throws IOException {
        for (int i = 0; i < nodeCount - 1; i++) {
            String[] line = br.readLine().trim().split(" ");
            int u = Integer.parseInt(line[0]);
            int v = Integer.parseInt(line[1]);
            adj[u].add(v);
            adj[v].add(u);
        }
    }

    private static int[] readPrimes(BufferedReader br, int primeCount) throws IOException {
        int[] primes = new int[primeCount];
        for (int i = 0; i < primeCount; i++) {
            primes[i] = Integer.parseInt(br.readLine().trim());
        }
        return primes;
    }

    private static long[] initializeDPArray(int nodeCount) {
        long[] dp = new long[nodeCount + 1];
        Arrays.fill(dp, -1);
        dp[1] = 0;
        return dp;
    }

    private static long performDFS(int u, int parent, List<Integer>[] adj, int[] primes, long[] dp) {
        if (dp[u] != -1) {
            return dp[u];
        }

        long result = 0;
        for (int v : adj[u]) {
            if (v == parent) continue;
            long sum = performDFS(v, u, adj, primes, dp);
            result = (result + sum) % MOD;
        }

        for (int v : adj[u]) {
            if (v == parent) continue;
            long sum = performDFS(v, u, adj, primes, dp);
            long additional = (sum + 1) % MOD;
            for (int prime : primes) {
                additional = (additional * prime) % MOD;
            }
            result = (result + additional) % MOD;
        }

        dp[u] = result;
        return result;
    }
}

import java.util.Scanner;
import java.util.InputMismatchException;
import java.util.logging.Level;
import java.util.logging.Logger;

public class Main {
    private static final Logger logger = Logger.getLogger(Main.class.getName());

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            System.out.print("Enter number of test cases: ");
            int t = readPositiveInteger(scanner);
            for (int i = 0; i < t; i++) {
                System.out.print("Enter a number: ");
                int n = readPositiveInteger(scanner);
                int result = minMovesToOne(n);
                if (result != -1) {
                    System.out.println("Minimum moves to reduce " + n + " to 1: " + result);
                } else {
                    System.out.println("Cannot reduce " + n + " to 1.");
                }
            }
        } catch (Exception e) {
            logger.log(Level.SEVERE, "An error occurred: " + e.getMessage(), e);
        }
    }

    private static int minMovesToOne(int n) {
        int moves = 0;
        while (n != 1) {
            if (n % 6 == 0) {
                n /= 6;
            } else if (n % 3 == 0) {
                n *= 2;
            } else {
                logger.warning("Invalid state reached for n: " + n);
                return -1;
            }
            moves++;
        }
        return moves;
    }

    private static int readPositiveInteger(Scanner scanner) {
        while (true) {
            try {
                int value = scanner.nextInt();
                if (value <= 0) {
                    throw new InputMismatchException("Value must be positive.");
                }
                return value;
            } catch (InputMismatchException e) {
                logger.warning("Invalid input. Please enter a positive integer.");
                scanner.next(); // Clear the invalid input
            }
        }
    }
}

public class ArrayFinder {

    public int[] findArray(int[] pref) {
        validateInput(pref);

        int[] result = new int[pref.length];
        result[0] = pref[0];

        for (int i = 1; i < pref.length; ++i) {
            result[i] = computeElement(pref[i - 1], pref[i]);
        }

        return result;
    }

    private void validateInput(int[] pref) {
        if (pref == null) {
            throw new IllegalArgumentException("Input array cannot be null.");
        }
        if (pref.length == 0) {
            throw new IllegalArgumentException("Input array cannot be empty.");
        }
    }

    private int computeElement(int previous, int current) {
        return previous ^ current;
    }
}

import java.util.*;

public class Solution {
    public List<String> spellchecker(String[] wordlist, String[] queries) {
        if (wordlist == null || queries == null) {
            throw new IllegalArgumentException("Wordlist and queries must not be null.");
        }

        Set<String> wordsSet = new HashSet<>(Arrays.asList(wordlist));
        Map<String, String> caseMap = new HashMap<>();
        Map<String, String> vowelMap = new HashMap<>();

        for (String word : wordlist) {
            String lowerCaseWord = word.toLowerCase();

            // Store original words for case-insensitive matches
            caseMap.putIfAbsent(lowerCaseWord, word);

            // Replace vowels with '#' for vowel-insensitive matches
            String devoweledWord = lowerCaseWord.replaceAll("[aeiou]", "#");
            vowelMap.putIfAbsent(devoweledWord, word);
        }

        List<String> results = new ArrayList<>();
        for (String query : queries) {
            results.add(findCorrectWord(query, wordsSet, caseMap, vowelMap));
        }

        return results;
    }

    private String findCorrectWord(String query, Set<String> wordsSet, 
                                    Map<String, String> caseMap, Map<String, String> vowelMap) {
        if (wordsSet.contains(query)) {
            return query;
        }

        String lowerCaseQuery = query.toLowerCase();
        if (caseMap.containsKey(lowerCaseQuery)) {
            return caseMap.get(lowerCaseQuery);
        }

        String devoweledQuery = lowerCaseQuery.replaceAll("[aeiou]", "#");
        return vowelMap.getOrDefault(devoweledQuery, "");
    }
}

