public class Solution {
    private static final int MOD = (int) 1e9 + 7;

    public int rearrangeSticks(int n, int k) {
        if (n < 1 || k < 0 || k > n) {
            throw new IllegalArgumentException("Invalid input: n must be >= 1 and 0 <= k <= n.");
        }

        long[][] dp = new long[n + 1][k + 1];
        for (int i = 0; i <= k; i++) {
            dp[1][i] = 1;
        }

        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= k; j++) {
                long rightmost = (j - 1 >= 0) ? dp[i - 1][j - 1] : 0;
                long leftmost = (i - 2 >= 0) ? dp[i - 2][j] : 0;
                dp[i][j] = (rightmost + leftmost) % MOD;
            }
        }
        return (int) (dp[n][k] % MOD);
    }

    public int advancedRearrangement(int n, int k) {
        if (n < 1 || k < 0 || k > n) {
            throw new IllegalArgumentException("Invalid input: n must be >= 1 and 0 <= k <= n.");
        }

        long answer = 1;
        if (k + 1 >= n - k) {
            answer = (k + 1) * factorial(n) % MOD + (n - k - 1) * n * factorial(n - 1) % MOD;
        } else {
            answer = (n - k) * (n + 1) % MOD * k * 2 % MOD + (n - k) * (n + 1) % MOD * factorial(n - 1) % MOD;
        }

        return (int) (answer % MOD);
    }

    private long factorial(int num) {
        if (num < 0) {
            throw new IllegalArgumentException("factorial input must be >= 0");
        }
        long result = 1;
        for (int i = 2; i <= num; i++) {
            result = result * i % MOD;
        }
        return result;
    }
}

