            for (int j = i; j < n; j++) {
                subarray.add(a.get(j));
                mexesSet.add(calcMex(subarray));
            }
        }

        List<Integer> mexesList = new ArrayList<>(mexesSet);
        return calcMex(mexesList);
    }

