public class HammingDistanceCalculator {

    public static long totalHammingDistance(List<Integer> nums) {
        if (nums == null || nums.isEmpty()) {
            throw new IllegalArgumentException("Input list must not be null or empty.");
        }

        long totalDistance = 0;
        int numLength = Integer.toBinaryString(nums.stream().mapToInt(Integer::intValue).max().orElse(0)).length();

        for (int i = 0; i < numLength; i++) {
            int bitCount = 0;

            for (Integer num : nums) {
                if ((num >> i) & 1) != 0) {
                    bitCount++;
                }
            }

            totalDistance += (long) bitCount * (nums.size() - bitCount);
        }

        return totalDistance;
    }

    public static void main(String[] args) {
        try {
            List<Integer> nums1 = List.of(4, 14, 2);
            System.out.println("Total Hamming Distance: " + totalHammingDistance(nums1)); // Output: 6

