class Solution {
    public int maxSatisfaction(int[] satisfaction) {
        if (satisfaction == null || satisfaction.length == 0) {
            throw new IllegalArgumentException("Input array is null or empty.");
        }

        Arrays.sort(satisfaction);
        int maxSum = 0;
        int currentSum = 0;

        for (int i = satisfaction.length - 1; i >= 0; i--) {
            currentSum += satisfaction[i];
            if (currentSum < 0) {
                break;
            }
            maxSum += currentSum;
        }

        return maxSum;
    }
}

import java.util.*;

public class Solution {
    public List<List<String>> deleteDuplicateFolder(List<List<String>> paths) {
        if (paths == null || paths.isEmpty()) {
            return Collections.emptyList();
        }

        Map<String, Integer> pathToId = new HashMap<>();
        int id = 0;

        for (List<String> path : paths) {
            if (path == null || path.isEmpty()) {
                throw new IllegalArgumentException("Path cannot be null or empty.");
            }
            StringBuilder sb = new StringBuilder();
            for (String folder : path) {
                sb.append(folder).append(",");
                pathToId.computeIfAbsent(sb.toString(), k -> id++);
            }
        }

        List<List<Integer>> tree = new ArrayList<>(Collections.nCopies(id, new ArrayList<>()));

        for (List<String> path : paths) {
            int parentId = pathToId.get(path.get(0) + ",");
            for (int i = 1; i < path.size(); i++) {
                String parentKey = String.join(",", path.subList(0, i)) + ",";
                int currentId = pathToId.get(parentKey);
                String childKey = String.join(",", path.subList(0, i + 1)) + ",";
                int childId = pathToId.get(childKey);
                tree.get(currentId).add(childId);
            }
        }

        int rootId = pathToId.get(paths.get(0).get(0) + ",");

        Map<Integer, String> idToPath = new HashMap<>();
        for (Map.Entry<String, Integer> entry : pathToId.entrySet()) {
            idToPath.put(entry.getValue(), entry.getKey());
        }

        Set<Integer> marked = new HashSet<>();
        performDFS(rootId, tree, marked, idToPath);

        List<List<String>> result = new ArrayList<>();
        for (List<String> path : paths) {
            StringBuilder sb = new StringBuilder();
            boolean isUnique = true;
            for (String folder : path) {
                sb.append(folder).append(",");
                if (marked.contains(pathToId.get(sb.toString()))) {
                    isUnique = false;
                    break;
                }
            }
            if (isUnique) {
                result.add(path);
            }
        }

        return result;
    }

    private void performDFS(int id, List<List<Integer>> tree, Set<Integer> marked, Map<Integer, String> idToPath) {
        List<Integer> children = tree.get(id);
        if (children.isEmpty()) {
            return;
        }
        Map<String, Integer> childFrequencyMap = new HashMap<>();
        for (int child : children) {
            String childPath = idToPath.get(child);
            childFrequencyMap.put(childPath, childFrequencyMap.getOrDefault(childPath, 0) + 1);
        }

        for (int child : children) {
            performDFS(child, tree, marked, idToPath);
            if (childFrequencyMap.get(idToPath.get(child)) > 1) {
                marked.add(child);
            }
        }
    }
}

