import java.util.HashSet;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;

public class UniqueDigitCounter {

    private static final Logger LOGGER = Logger.getLogger(UniqueDigitCounter.class.getName());

    public int countNumbersWithUniqueDigits(int n) {
        if (n < 0) {
            LOGGER.log(Level.SEVERE, "Input cannot be negative: " + n);
            return 0;
        }

        int counter = 0;

        for (int i = 1; i <= n; i++) {
            if (!hasUniqueDigits(i)) {
                counter++;
            }
        }

        return counter;
    }

    private boolean hasUniqueDigits(int number) {
        Set<Integer> digitSet = new HashSet<>();
        while (number > 0) {
            int digit = number % 10;
            if (!digitSet.add(digit)) {
                return false;
            }
            number /= 10;
        }
        return true;
    }

    public int countDigitRepetitions(int n) {
        if (n < 11) {
            LOGGER.log(Level.INFO, "No repetitions for n < 11: " + n);
            return 0;
        }

        int count = 0;
        for (int i = 11; i <= n; i++) {
            if (hasRepDigit(i)) {
                count++;
            }
        }
        return count;
    }

    private boolean hasRepDigit(int number) {
        int prevDigit = -1;
        int seenCount = 0;

        while (number > 0) {
            int currentDigit = number % 10;
            if (currentDigit == prevDigit) {
                seenCount++;
                if (seenCount > 0) {
                    return true;
                }
            } else {
                seenCount = 0;
            }
            prevDigit = currentDigit;
            number /= 10;
        }
        return false;
    }

    public int solutionOptimized(int n) {
        return countDigitRepetitions(n);
    }
}

