import java.util.logging.Level;
import java.util.logging.Logger;

public class MinimumSkipsToArriveOnTime {
    private static final Logger LOGGER = Logger.getLogger(MinimumSkipsToArriveOnTime.class.getName());

    public int minSkips(int[] dist, int speed, int hoursBefore) {
        if (dist == null || dist.length == 0 || speed <= 0 || hoursBefore <= 0) {
            LOGGER.log(Level.WARNING, "Invalid input parameters.");
            return -1; // Invalid parameters
        }

        int n = dist.length;
        double timeTaken = 0;
        int skips = 0;

        for (int i = 0; i < n; i++) {
            double travelTime = dist[i] / (double) speed;
            timeTaken += travelTime;

            if (i < n - 1) {
                double timeToNextHour = Math.ceil(timeTaken) - timeTaken;

                if (timeTaken + timeToNextHour > hoursBefore) {
                    skips++;
                    timeTaken += travelTime; // Skipping requires immediate addition of travel time
                } else {
                    timeTaken += timeToNextHour; // Wait until the next hour
                }
            }
        }

        if (timeTaken <= hoursBefore) {
            return skips;
        } else {
            LOGGER.log(Level.INFO, "Impossible to arrive on time.");
            return -1;
        }
    }

    public static void main(String[] args) {
        MinimumSkipsToArriveOnTime solver = new MinimumSkipsToArriveOnTime();

        testExample(solver, new int[]{1, 3, 2}, 4, 2, 1);
        testExample(solver, new int[]{7, 3, 5, 5}, 2, 10, 2);
        testExample(solver, new int[]{7, 3, 5, 5}, 1, 10, -1);
    }

    private static void testExample(MinimumSkipsToArriveOnTime solver, int[] dist, int speed, int hoursBefore, int expected) {
        int result = solver.minSkips(dist, speed, hoursBefore);
        if (result != expected) {
            LOGGER.log(Level.SEVERE, "Test failed. Expected: " + expected + ", but got: " + result);
        } else {
            LOGGER.log(Level.INFO, "Test passed. Skips required: " + result);
        }
    }
}

