import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;

public class VowelChecker {

    private static final HashSet<Character> VOWELS = new HashSet<>(
            List.of('a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U')
    );

    public boolean halvesAreAlike(String s) {
        if (s == null || s.length() % 2 != 0) {
            throw new IllegalArgumentException("Input must be a non-null string with an even length.");
        }

        int mid = s.length() / 2;
        int vowelCountA = countVowels(s, 0, mid);
        int vowelCountB = countVowels(s, mid, s.length());

        return vowelCountA == vowelCountB;
    }

    private int countVowels(String s, int start, int end) {
        int count = 0;
        for (int i = start; i < end; i++) {
            if (VOWELS.contains(s.charAt(i))) {
                count++;
            }
        }
        return count;
    }

    public boolean halvesAreAlikeWithMap(String s) {
        if (s == null || s.length() % 2 != 0) {
            throw new IllegalArgumentException("Input must be a non-null string with an even length.");
        }

        int mid = s.length() / 2;
        Map<Integer, List<Integer>> indexMap = new HashMap<>();
        indexMap.put(0, List.of(mid));

        int vowelCountA = 0, vowelCountB = 0;

        for (int i = 0; i < mid; i++) {
            if (isVowel(s.charAt(i))) {
                vowelCountA++;
            }
        }

        for (int i = mid; i < s.length(); i++) {
            if (isVowel(s.charAt(i))) {
                vowelCountB++;
            }
        }

        return vowelCountA == vowelCountB;
    }

    private boolean isVowel(char c) {
        return VOWELS.contains(c);
    }
}

