public class AppealCalculator {

    public static void main(String[] args) {
        try {
            String testString1 = "abbca";
            System.out.println("Appeal of '" + testString1 + "': " + computeAppeal(testString1)); // 28

            String testString2 = "code";
            System.out.println("Appeal of '" + testString2 + "': " + computeAppeal(testString2)); // 20
        } catch (Exception e) {
            System.err.println("Error during computation: " + e.getMessage());
        }
    }

    public static int computeAppeal(String s) {
        if (s == null || s.isEmpty()) {
            throw new IllegalArgumentException("Input string cannot be null or empty.");
        }

        Map<Character, Integer> frequencyMap = new HashMap<>();
        long appealSum = 0;

        for (char ch : s.toCharArray()) {
            frequencyMap.put(ch, frequencyMap.getOrDefault(ch, 0) + 1);
        }

        int substringCount = s.length();

        for (int start = 0; start < substringCount; start++) {
            HashSet<Character> uniqueChars = new HashSet<>();
            for (int end = start; end < substringCount; end++) {
                uniqueChars.add(s.charAt(end));
                appealSum += uniqueChars.size();
            }
        }

        return (int) appealSum;
    }
}

