import java.util.Arrays;

public class BossKillingStrategy {
    public static void main(String[] args) {
        int[] bosses = {1, 0, 1, 1, 0, 0}; // Example input; actual input should be passed here
        try {
            int result = minimumSkipPoints(bosses);
            System.out.println("Minimum skip points required: " + result);
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    public static int minimumSkipPoints(int[] bosses) {
        if (bosses == null || bosses.length == 0) {
            throw new IllegalArgumentException("Bosses array cannot be null or empty.");
        }

        int n = bosses.length;
        int[] dp = new int[n + 1];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[n] = 0; // Base case

        for (int i = n - 1; i >= 0; i--) {
            int skipForOne = (bosses[i] == 1) ? 1 : 0;
            if (i + 1 < n) {
                dp[i] = Math.min(dp[i], skipForOne + dp[i + 1]);
            } 
            if (i + 1 < n) {
                int skipForTwo = skipForOne + ((bosses[i + 1] == 1) ? 1 : 0);
                dp[i] = Math.min(dp[i], skipForTwo + dp[i + 2]);
            }
        }

        return dp[0];
    }
}

class Solution {
    public int numSubmatrixSumTarget(int[][] grid, int target) {
        if (grid == null || grid.length == 0 || grid[0].length == 0) {
            throw new IllegalArgumentException("Input grid cannot be null or empty.");
        }

        int rows = grid.length;
        int cols = grid[0].length;

        // Compute prefix sums
        for (int i = 0; i < rows; i++) {
            for (int j = 1; j < cols; j++) {
                grid[i][j] += grid[i][j - 1];
            }
        }

        int result = 0;

        for (int left = 0; left < cols; left++) {
            for (int right = left; right < cols; right++) {
                Map<Integer, Integer> sumCountMap = new HashMap<>();
                sumCountMap.put(0, 1);
                int currentSum = 0;

                for (int i = 0; i < rows; i++) {
                    currentSum += grid[i][right] - (left > 0 ? grid[i][left - 1] : 0);

                    result += sumCountMap.getOrDefault(currentSum - target, 0);
                    sumCountMap.put(currentSum, sumCountMap.getOrDefault(currentSum, 0) + 1);
                }
            }
        }

        return result;
    }
}

import java.util.InputMismatchException;
import java.util.Scanner;

public class GabrielAndCaterpillar {
    private static final int HOURS_IN_DAY = 10;

    public static void main(String[] args) {
        try (Scanner scanner = new Scanner(System.in)) {
            int h1 = getInput(scanner, "Enter initial height (h1): ");
            int h2 = getInput(scanner, "Enter target height (h2): ");
            int a = getInput(scanner, "Enter upward speed (a): ");
            int b = getInput(scanner, "Enter downward speed (b): ");

            int positionAt10PM = calculatePositionAt10PM(h1, a, b);
            if (positionAt10PM >= h2) {
                System.out.println(0);
                return;
            }

            int effectiveClimbPerDay = calculateEffectiveClimbPerDay(a, b);
            if (effectiveClimbPerDay <= 0) {
                System.out.println(-1);
                return;
            }

            int remainingDistance = h2 - positionAt10PM;
            int daysNeeded = calculateDaysNeeded(remainingDistance, effectiveClimbPerDay);

            System.out.println(daysNeeded + 1);
        } catch (InputMismatchException e) {
            System.err.println("Invalid input. Please enter integer values.");
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }

    private static int getInput(Scanner scanner, String prompt) {
        System.out.print(prompt);
        while (true) {
            try {
                return scanner.nextInt();
            } catch (InputMismatchException e) {
                System.err.println("Invalid input. Please enter an integer.");
                scanner.next(); // Clear the invalid input
            }
        }
    }

    private static int calculatePositionAt10PM(int initialHeight, int upwardSpeed, int downwardSpeed) {
        return initialHeight + upwardSpeed * HOURS_IN_DAY - downwardSpeed * HOURS_IN_DAY;
    }

    private static int calculateEffectiveClimbPerDay(int upwardSpeed, int downwardSpeed) {
        return upwardSpeed * HOURS_IN_DAY - downwardSpeed * HOURS_IN_DAY;
    }

    private static int calculateDaysNeeded(int distance, int effectiveClimbPerDay) {
        return (distance + effectiveClimbPerDay - 1) / effectiveClimbPerDay;
    }
}

class Solution {
    public int minChanges(String word) {
        if (word == null || word.isEmpty()) {
            throw new IllegalArgumentException("Input word must not be null or empty.");
        }

        int n = word.length();
        int[][] dp = new int[n + 1][26];

        initializeDpArray(dp, n);

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < 26; j++) {
                for (int k = 0; k < 26; k++) {
                    if (Math.abs(j - k) > 1) {
                        dp[i][k] = Math.min(dp[i][k], dp[i - 1][j] + (word.charAt(i - 1) - 'a' != k ? 1 : 0));
                    }
                }
            }
        }

        return findMinimumChanges(dp, n);
    }

    private void initializeDpArray(int[][] dp, int n) {
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < 26; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }

        for (int i = 0; i < 26; i++) {
            dp[0][i] = 0;
        }
    }

    private int findMinimumChanges(int[][] dp, int n) {
        int minChanges = Integer.MAX_VALUE;
        for (int i = 0; i < 26; i++) {
            minChanges = Math.min(minChanges, dp[n][i]);
        }
        return minChanges;
    }
}

