import java.util.Arrays;

public class HappinessCalculator {

    public static int maxHappiness(int[] happiness, int k) {
        if (happiness == null || k <= 0) {
            throw new IllegalArgumentException("Invalid input: happiness array cannot be null and k must be positive.");
        }

        int n = happiness.length;
        int[] prefixSums = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSums[i + 1] = prefixSums[i] + happiness[i];
        }

        int[][] children = new int[n][2];
        for (int i = 0; i < n; i++) {
            children[i][0] = happiness[i];
            children[i][1] = i;
        }
        Arrays.sort(children, (a, b) -> Integer.compare(b[0], a[0]));

        int[] dp = new int[k + 1];
        Arrays.fill(dp, Integer.MIN_VALUE);
        dp[0] = 0;

        for (int i = 0; i < n; i++) {
            for (int j = k; j > 0; j--) {
                int currentHappiness = children[i][0];
                int index = children[i][1];
                int happinessReduction = (index > 0) ? (prefixSums[index] - prefixSums[index - 1]) : 0;

                if (dp[j - 1] != Integer.MIN_VALUE) {
                    dp[j] = Math.max(dp[j], dp[j - 1] + currentHappiness - happinessReduction);
                }
            }
        }

        return dp[k] < 0 ? 0 : dp[k];
    }

    public static void main(String[] args) {
        try {
            int[] happiness = {1, 2, 3, 4, 5};
            int k = 3;
            int result = maxHappiness(happiness, k);
            System.out.println("Maximum Happiness: " + result);
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("An unexpected error occurred: " + e.getMessage());
        }
    }
}

