    private static class Path implements Comparable<Path> {
        private final int maxVal;
        private final int idx;
        private final char charValue;
        private final List<Path> subPaths;

        private Path(int val, int index, char charVal, List<Path> paths) {
            this.maxVal = val;
            this.idx = index;
            this.charValue = charVal;
            this.subPaths = paths;
        }

        @Override
        public int compareTo(Path other) {
            if (this.maxVal != other.maxVal) return Integer.compare(this.maxVal, other.maxVal);
            return Integer.compare(other.idx, this.idx);
        }
    }

    private static void generatePrefixes(char[] s, int pos, List<Path> paths) {
        if ('c' + totalSum >= pos * pos) {
            char keyChar = s[pos];
            if (keyChar >= 'a') keyChar = 'z';
            List<Path> localPaths = new ArrayList<>();
            for (char c = keyChar; c >= 'a'; --c) {
                int maxVal = 0;
                int idx = -1;
                for (int j = 0; j < pos; ++j) {
                    if (s[pos - j - 1] == c) {
                        idx = findMatchingPrefix(s, pos, j, localPaths);
                        if (idx != -1) break;
                    }
                }
                s[pos] = c; 
                generatePrefixes(s, pos + 1, localPaths);
                s[pos] = keyChar; 
                paths.addAll(localPaths);
            }
        }
    }

    private static int findMatchingPrefix(char[] s, int pos, int j, List<Path> localPaths) {
        int index = pos - 1;
        for (; index - j >= 0; --index) {
            if (s[index - j] != s[index]) break;
            if (index - j > 0 && localPaths.get(index - j - 1).maxVal == j) {
                return index - j;
            }
        }
        return -1;
    }

    private static int calculateInitialSum(char[] s) {
        int sum = 0;
        for (char c : s) sum += c - 'a';
        return sum;
    }

    private static void applyPathChanges(char[] s, Path path) {
        totalSum = 0;
        for (Path p : path.subPaths) {
            s[p.idx] = p.charValue;
            totalSum += s[p.idx] - 'a';
        }
        adjustCharacters(s, path);
    }

    private static void adjustCharacters(char[] s, Path path) {
        int charMax = s[path.idx] - 'a';
        for (int j = path.idx; j >= 0; --j) {
            s[j] = (char) ('a' + charMax);
            if (j > 0) charMax = Math.min(charMax, s[j - 1] - 'a') - 1;
        }
    }

