import java.util.HashSet;

public class StringOperations {

    public static int minOperationsToUnifyStrings(String a, String b) {
        if (a == null || b == null || a.isEmpty() || b.isEmpty()) {
            throw new IllegalArgumentException("Input strings must not be null or empty.");
        }

        int[] aToB = new int[a.length()];
        int[] bToA = new int[b.length()];

        for (int i = 0; i < a.length(); i++) {
            aToB[i] = a.charAt(i) - a.charAt(0);
        }

        for (int i = 0; i < b.length(); i++) {
            bToA[i] = b.charAt(i) - b.charAt(0);
        }

        int minDiff = Integer.MAX_VALUE;

        for (int op = 0; op < 26; op++) {
            int minOperationsToMatchAllA = calculateOperations(aToB, op, true);
            int minOperationsToMatchAllB = calculateOperations(bToA, op, false);
            minDiff = Math.min(minDiff, Math.min(minOperationsToMatchAllA, minOperationsToMatchAllB));
        }

        for (int op = 1; op < 26; op++) {
            int minOperationsToDistinctChars = calculateDistinctOperations(aToB, bToA, op);
            minDiff = Math.min(minDiff, minOperationsToDistinctChars);
        }

        return minDiff;
    }

    private static int calculateOperations(int[] arr, int op, boolean isA) {
        int count = 0;
        int max = findMax(arr);
        for (int diff : arr) {
            if (isA ? (max - diff > op) : (diff - findMin(arr) > op)) {
                count++;
            }
        }
        return count;
    }

    private static int calculateDistinctOperations(int[] aToB, int[] bToA, int op) {
        int count = 0;
        for (int diff : aToB) {
            if (findMax(aToB) - diff != op) {
                count++;
            }
        }
        for (int diff : bToA) {
            if (diff - findMin(bToA) != op) {
                count++;
            }
        }
        return count;
    }

    private static int findMax(int[] arr) {
        int max = Integer.MIN_VALUE;
        for (int value : arr) {
            max = Math.max(max, value);
        }
        return max;
    }

    private static int findMin(int[] arr) {
        int min = Integer.MAX_VALUE;
        for (int value : arr) {
            min = Math.min(min, value);
        }
        return min;
    }

    public static void main(String[] args) {
        try {
            System.out.println(minOperationsToUnifyStrings("aba", "caa")); // Output: 2
            System.out.println(minOperationsToUnifyStrings("dabadd", "cda")); // Output: 3
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

import java.util.Arrays;

class Solution {
    public int maxProfitAssignment(int[] difficulty, int[] profit, int[] worker) {
        if (difficulty == null || profit == null || worker == null ||
            difficulty.length != profit.length || difficulty.length == 0) {
            throw new IllegalArgumentException("Invalid input: Ensure all inputs are non-null and of the same length.");
        }

        Job[] jobs = createJobs(difficulty, profit);
        Arrays.sort(jobs, (a, b) -> Integer.compare(a.difficulty, b.difficulty));
        int[] maxProfit = computeMaxProfit(jobs);

        return calculateTotalProfit(worker, jobs, maxProfit);
    }

    private Job[] createJobs(int[] difficulty, int[] profit) {
        Job[] jobs = new Job[difficulty.length];
        for (int i = 0; i < difficulty.length; i++) {
            jobs[i] = new Job(difficulty[i], profit[i]);
        }
        return jobs;
    }

    private int[] computeMaxProfit(Job[] jobs) {
        int[] maxProfit = new int[jobs.length];
        maxProfit[0] = jobs[0].profit;

        for (int i = 1; i < jobs.length; i++) {
            maxProfit[i] = Math.max(maxProfit[i - 1], jobs[i].profit);
        }
        return maxProfit;
    }

    private int calculateTotalProfit(int[] worker, Job[] jobs, int[] maxProfit) {
        int totalProfit = 0;

        for (int ability : worker) {
            int index = binarySearch(jobs, ability);
            if (index >= 0) {
                totalProfit += maxProfit[index];
            }
        }
        return totalProfit;
    }

    private int binarySearch(Job[] jobs, int ability) {
        int left = 0, right = jobs.length - 1;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (jobs[mid].difficulty <= ability) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return right;
    }

    private static class Job {
        final int difficulty;
        final int profit;

        Job(int difficulty, int profit) {
            this.difficulty = difficulty;
            this.profit = profit;
        }
    }
}

int robotPosition(vector<int>& robot, vector<vector<int>>& factory, int pos, int count) {
    if (factory.empty()) {
        return 0;
    }

    int minimumPos = numeric_limits<int>::max();
    int currentDistance = 0;
    int robotInPosition = 0;

    for (size_t i = 0; i < factory.size(); i++) {
        if (factory[i][0] == pos + currentDistance) {
            currentDistance += (abs(robot[i] - pos) + factory[i][1]) + 
                               abs(robot[i] - minimumPos);
            robotInPosition++;

            if (robotInPosition >= factory[i][1]) {
                currentDistance--;
            }
        }
    }
    return currentDistance;
}

int minimumDistance(vector<int>& robot, vector<vector<int>>& factory) {
    if (robot.empty()) {
        return 0; 
    }

    int minDistance = INT_MAX;

    for (size_t i = 0; i < robot.size(); i++) {
        vector<int> friends;

        for (size_t j = 0; j < factory.size(); j++) {
            if (robot[i] - factory[j][0] <= factory[j][1]) {
                friends.push_back(factory[j][1] - (factory[j][0] - robot[i]));
            }
        }

        if (factory.empty()) {
            minDistance = min(robot[i] + robot[i], minDistance);
        } else {
            int currentDistance = minDistance + robot[i];

            for (size_t l = 0; l < factory.size(); l++) {
                int newDistance = currentDistance + factory[l][1] - robot[i];
                currentDistance = min(newDistance, currentDistance);
            }

            minDistance = min(currentDistance, minDistance);
        }
    }

    return minDistance;
}

public class Solution { 
    private static final int[][] DIRECTIONS = { { 0, 1 }, { 1, 0 }, { 0, -1 }, { -1, 0 } }; 

    public int numIslands2(int[][] grid) { 
        if (grid == null || grid.length == 0 || grid[0].length == 0) {
            return 0; 
        }

        boolean[][] visited = new boolean[grid.length][grid[0].length]; 
        int surroundedCells = 0; 

        for (int i = 0; i < grid.length; i++) { 
            for (int j = 0; j < grid[0].length; j++) { 
                if (grid[i][j] == 1 && !visited[i][j] && isValidLand(grid, i, j)) { 
                    surroundedCells += dfs(grid, i, j, visited); 
                } 
            } 
        } 
        return surroundedCells; 
    } 

    private int dfs(int[][] grid, int i, int j, boolean[][] visited) { 
        visited[i][j] = true; 
        int count = 1; 

        for (int[] dir : DIRECTIONS) { 
            int ni = i + dir[0], nj = j + dir[1]; 

            if (isInBounds(grid, ni, nj) && grid[ni][nj] == 1 && !visited[ni][nj]) { 
                count += dfs(grid, ni, nj, visited); 
            } 
        } 
        return count; 
    } 

    private boolean isInBounds(int[][] grid, int i, int j) { 
        return i >= 0 && i < grid.length && j >= 0 && j < grid[0].length; 
    } 

    private boolean isValidLand(int[][] grid, int i, int j) { 
        for (int[] dir : DIRECTIONS) { 
            int ni = i + dir[0], nj = j + dir[1]; 
            if (isInBounds(grid, ni, nj) && grid[ni][nj] == 0) { 
                return true; 
            } 
        } 
        return false; 
    } 
}

