        while (a > 0 && !minHeap.empty()) {
            int power = minHeap.top();
            minHeap.pop();

            // Debug: Print current power and available serum
            std::cout << "Current power: " << power << ", Available a: " << a << std::endl;

            power += green_serum * (power / 2) + blue_serum * (power / 3);
            a += green_serum * (power / 2);
            a += blue_serum * (power / 3);

            // Debug: Print serum contribution
            std::cout << "Green Serum Contribution: " << green_serum * (power / 2) 
                      << ", Blue Serum Contribution: " << blue_serum * (power / 3) << std::endl;

            if (a < power) {
                minHeap.push(power); // Push back if we cannot absorb
                if (green_serum == 0) {
                    blue_serum++; // Increment blue serum if no green serum
                } else {
                    a += power - a; // Adjust a
                    green_serum = 0; // Reset green
                    blue_serum += 2; // Increment blue serum
                }
            } else {
                absorb_count++; // Successful absorption
                a -= power; // Deduct absorbed power
            }

            // Debug: Print updated a and serum counts
            std::cout << "Updated a: " << a << ", Absorb count: " << absorb_count 
                      << ", Blue serum: " << blue_serum << ", Green serum: " << green_serum << std::endl;
        }

        // Output the number of absorptions
        std::cout << absorb_count << std::endl;
    }
}

