class Solution {
public:
    // Depth-first search to mark border pixels
    void dfs(vector<vector<int>>& grid, int row, int col, int color, int m, int n) {
        // Base case: out of bounds or different color
        if (row < 0 || row >= m || col < 0 || col >= n || grid[row][col] != color) {
            return;
        }
        // Mark the cell visited with a temporary value
        grid[row][col] = 3;  // Temporary marker
        // Recursive calls for adjacent cells
        dfs(grid, row + 1, col, color, m, n);
        dfs(grid, row - 1, col, color, m, n);
        dfs(grid, row, col + 1, color, m, n);
        dfs(grid, row, col - 1, color, m, n);
    }

    // Depth-first search to restore color on the actual border
    void dfs2(vector<vector<int>>& grid, int row, int col, int color, int m, int n) {
        // Base case: out of bounds or not a marked cell
        if (row < 0 || row >= m || col < 0 || col >= n || grid[row][col] != 3) {
            return;
        }
        // Restore the original color
        grid[row][col] = color;
        // Recursive calls for adjacent cells
        dfs2(grid, row + 1, col, color, m, n);
        dfs2(grid, row - 1, col, color, m, n);
        dfs2(grid, row, col + 1, color, m, n);
        dfs2(grid, row, col - 1, color, m, n);
    }

    // Main function to color the border of the region
    vector<vector<int>> colorBorder(vector<vector<int>>& grid, int row, int col, int color) {
        int m = grid.size(), n = grid[0].size();

        // TODO: Instrumentation - log grid state before marking
        // Print grid state for debugging
        // printGrid(grid);

        dfs(grid, row, col, grid[row][col], m, n);

        // TODO: Instrumentation - log grid state after marking
        // printGrid(grid);

        dfs2(grid, row, col, color, m, n);

        // TODO: Instrumentation - log final grid state
        // printGrid(grid);

        return grid;
    }

    // Debugging function to print the grid state
    void printGrid(const vector<vector<int>>& grid) {
        for (const auto& row : grid) {
            for (int val : row) {
