// Function to calculate the minimum steps to clean a dirty cell
int calculateMinSteps(int rows, int cols, int robotRow, int robotCol, int dirtyRow, int dirtyCol) {
    // Direction vectors for navigating the grid
    int directionRow = 1, directionCol = 1; 
    int stepCount = 0;

    // Auxiliary function to check if the robot has hit the row or column of the dirty cell
    auto reachedDirtyCell = [&](int currentRow, int dirtyRowInput, int targetRow, int adjacentCol) {
        if (currentRow == dirtyRowInput || currentRow == targetRow) {
            for (int i = 1; i <= abs(adjacentCol - targetRow); ++i) {
                cout << "Cleaning " << (currentRow == dirtyRowInput ? currentRow : 'N/A') << " " << i << '\n';
                ++stepCount;
            }
            return true;
        }
        return false;
    };

    // Initialize distance and visited matrices
    vector<vector<int>> distance(rows + 1, vector<int>(cols + 1, INT_MAX));
    vector<vector<bool>> visited(rows + 1, vector<bool>(cols + 1, false));

    distance[robotRow][robotCol] = 0;

    for (int iterations = 1; iterations <= rows * cols && !reachedDirtyCell(robotRow, dirtyRow, dirtyRow, dirtyCol); ++iterations) {
        for (int i = 1; i <= rows; ++i) {
            for (int j = 1; j <= cols; ++j) {
                if (visited[i][j]) continue;

                int nextRow = i + directionRow, nextCol = j + directionCol;

                // Explore all potential movements
                for (int direction = 1; direction <= 3; ++direction) { 
                    int currentRow = direction == 1 ? i : nextRow + (-directionRow * (direction == 2 ? 1 : -1));
                    int currentCol = direction == 1 ? j : nextCol + (-directionCol * (direction == 2 ? -1 : 1));

                    if (currentRow < 1 || currentCol < 1 || currentRow > rows || currentCol > cols || distance[currentRow][currentCol] <= distance[i][j] + 1) continue;

                    // Update distance and mark as visited
                    distance[currentRow][currentCol] = distance[i][j] + 1;
                    visited[currentRow][currentCol] = true;
                }
            }
        }

        // Adjust directions for the next round
        int nextDirectionRow = directionRow, nextDirectionCol = directionCol;
        directionRow = -directionRow;
        directionCol = -directionCol;

        if (distance[robotRow + directionRow][robotCol + directionCol] <= distance[robotRow][robotCol]) {
            nextDirectionRow = directionRow;
            nextDirectionCol = directionCol;
        } else {
            nextDirectionRow = directionRow;
            nextDirectionCol = (directionCol == -directionCol) ? -directionCol : directionCol;
        }
        directionRow = nextDirectionRow;
        directionCol = nextDirectionCol;
    }

    // Return the total steps taken to reach the dirty cell
    return stepCount;
}

