class Solution {
public:
    vector<string> generateConcatenatedWords(vector<string>& words, int lower, int upper) {
        // Research function for generating concatenated words within specified length bounds
        vector<string> res;
        // Print boundaries for debugging purposes
        cout << "Generating concatenated words with lower: " << lower << ", upper: " << upper << endl;
        if (lower == upper) {
            // Collecting words of exact specified length
            for (const string& s : words) {
                if (s.size() == lower) {
                    res.push_back(s);
                    // Debug print to track found words
                    cout << "Found word of exact length: " << s << endl;
                }
            }
        } else {
            // Explore words with different lengths
            for (const string& s : words) {
                if (s.size() > lower) {
                    // Recursive call to explore larger lengths
                    auto subRes = generateConcatenatedWords(words, lower + 1, upper - 1 + s.size());
                    res.insert(res.end(), subRes.begin(), subRes.end());
                } else if (s.size() == lower) {
                    res.push_back(s);
                    // Debug print to track found words
                    cout << "Found word of exact length: " << s << endl;
                }
            }
        }
        return res;
    }

    vector<string> wordBreak(string s, unordered_set<string> wordDict) {
        // Research function for breaking words using a dictionary
        vector<string> res;
        // Transform word dictionary to vector for processing
        vector<string> wordsDict(wordDict.begin(), wordDict.end());
        // Trigger concatenated word generation
        cout << "Starting word break for: " << s << endl;
        generateConcatenatedWords(wordsDict, 1, s.size());

        // Attempt to find valid segments of 's'
        for (const string& w : res) {
            if (s.find(w) == 0) {
                // Found a prefix match
                if (s.size() == w.size()) {
                    // If the full word matches, return it
                    res.push_back(s);
                    cout << "Complete match found: " << s << endl;
                    return res;
                } else {
                    string rest = s.substr(w.size());
                    // Recursive call to break down the rest of the string
                    vector<string> tmp = wordBreak(rest, wordDict);
                    // Construct the valid combinations
                    for (const string& temp : tmp) {
                        res.push_back(w + " " + temp);
                        // Debug print to show combinations
                        cout << "Forming combination: " << w + " " + temp << endl;
                    }
                    return res; // Early return is crucial here
                }
            }
        }
        // Final return if no combinations found
        cout << "No valid combinations found for: " << s << endl;
        return res;
    }
};

