class Solution {
public:
    // Function to find the nth magical number that can be formed using 'a' and 'b'
    int nthMagicalNumber(int n, int a, int b) {
        // Calculate the least common multiple (LCM) of 'a' and 'b'
        long lcm = std::lcm(a, b);

        // Debug: output the calculated LCM
        std::cout << "LCM of " << a << " and " << b << " is: " << lcm << std::endl;

        // Initialize binary search limits
        long lo = 2, hi = (long)1e15;
        long mod = 1e9 + 7;

        // Binary search to find the nth magical number
        while (lo < hi) {
            long mid = (lo + hi) / 2;

            // Calculate the count of magical numbers less than or equal to 'mid'
            long count = mid / a + mid / b - mid / lcm;

            // Debug: output the current search bounds and count
            std::cout << "Searching... lo: " << lo << ", hi: " << hi << ", mid: " << mid << ", count: " << count << std::endl;

            // Adjust search bounds based on the count
            if (count < n) {
                lo = mid + 1; // Move to the right side
            } else {
                hi = mid; // Move to the left side
            }
        }

        // Return the result with modulo
        return lo % mod;
    }
};

