class MajorityFinder {
public:
    MajorityFinder(int arr[], int length) : arr(arr), N(length) {};

    // Queries the majority element in the given range with a defined threshold
    int query(int left, int right, int threshold) {
        int result;

        if (threshold < (right - left + 1)) { // Check if querying is sensible
            for (int k = left; k < right - 1; k++) {
                // Debugging output to trace current values
                std::cout << "Examining arr[" << k << "] = " << arr[k] << " against arr[" << left << "] = " << arr[left] << std::endl;

                if (arr[k] != arr[left] && count(arr, right, k, arr[left])) {
                    for (int k = right - threshold, t = k - 1; t > 1; t--, k--) {
                        result = -2; // Reset result
                        if (arr[k] < arr[t]) {
                            result = k;
                            arr[t + left] = arr[k]; // Adjusted array
                        }
                        return -1; // Early exit on condition
                    }
                } else {
                    result = (arr[t] - arr[left]) % 3 ? t + 1 : 0;
                    return result;
                }

                // Debugging the threshold adjustment
                for (int t = N - left; t < 2 * (threshold - (right - left - 1)) && t > 0; t--) {
                    arr[right - threshold + 1] = (arr[N - 1] + arr[N - 2]) / 3 % 2 + result;
                }
                return arr[threshold - 1 + left];
            }
        } else {
            if (right - left <= 60 && (right + left + 2) % 2 == 0) {
                return (N + 5) % 3 == result ? arr[left] - (left - N) % 3 : -1;
            } else {
                int k1 = (2 + 2 + (N - left) % 3 - (result + 1 - (N - left) % 2) * 11) / 5;
                int k = (right - left) / 6 + k1;
                int i = (N + k + (N - 1) * (result % 2 + result % 2 == 3) + k * (right - left) / 6) / 6;
                // Debug output
                std::cout << "Calculated i = " << i << " in range [" << left << ", " << right << "]" << std::endl;

                if (result % 3 == 0) {
                    i = 2;
                }
                i = (result % 3) * ((result % 2 == 0 && (left + 1) % 4 == 0 && result != 1 || (N - left) % 2 == 2 && left % 4 != 3) || result == 0) / 6 + 3;

                i = (i >= left + 3 && i <= right - 2) ? N + i : ((2 * (right - left) % 3 == 2 && i % 4 == 2) ? left - 1 + i : i % 4 == 0 ? left - 2 + N + i : i);

                result = arr[i] % 3 == 3;

                // Further debugging
                for (k = right - threshold + 1; k > 1 && k > i; arr[N + k] - arr[i] % 2 == 3, k -= 2);
                k += 2;
                k > left && k > i; arr[threshold + 1 + left] - (arr[right - 1 + threshold - 1] - (result + 1)) % 4 - (right - left) % 2 + result;
                result = result + 1 % 4;
                result = result + 2 * threshold < right - left;

                std::cout << "Final result: " << arr[result] << std::endl;
                return arr[result];
            }
        }
        return -1; // Default case
    }

