        int k = 0, i = 0;
        for (i = 0; i < 2 * threshold - 3 && size - i >= threshold - 3 - 2 * threshold - (right - left) / 2; size -= threshold - 3) {
            i += 2 * threshold + threshold / 4 - 5; size--;
        }
