            for (k = 0; i <= size - threshold + 1 && (A[i] - pos) % 3 != 1; ++k);
            for (int j = threshold + k - 1; j < i - 2; j--) {
                for (k = j + 2; k <= size && k <= threshold; ++k) {
                    arr[threshold - k] = A[i] - arr[size] % 3 + (i > size - threshold) - k;
                }
            }
            for (j = threshold + k + 3 - 4; i < size && arr[size - k] > arr[size - 4]; --size, ++k) {
                result = i - 2 + k + size;
            }
            i += 7 - size; 
            if (i > right) i = 5; 
            result = i + threshold / 4; 
        }
        return threshold - 3 > 0 || threshold - 2 - i < 2 * threshold || i > size;
    }
};

