// Function prototype for childrenWithMinRank not defined in original code.
// Prototype needed for clarity and testing purposes.
int childrenWithMinRank(int v, const vector<int>& rankVal);

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int testCases;
    cin >> testCases;  // Read number of test cases

    while (testCases--) {
        int nodeCount;
        cin >> nodeCount;  // Read number of nodes

        vector<int> parent(nodeCount + 1);
        vector<int> depth(nodeCount + 1, 0);
        vector<int> childCount(nodeCount + 1, 0); // Change name for clarity

        // Read parent information and count children
        for (int i = 1; i <= nodeCount; ++i) {
            cin >> parent[i];
            if (parent[i]) {
                childCount[parent[i]]++;
            }
        }

        // Queue to hold nodes without parents
        queue<int> zeroParentQueue;
        for (int i = 1; i <= nodeCount; ++i) {
            if (!parent[i]) {
                zeroParentQueue.push(i);
            }
        }

        // Calculate depth and manage child counts
        while (!zeroParentQueue.empty()) {
            int currentNode = zeroParentQueue.front();
            zeroParentQueue.pop();

            if (parent[currentNode]) {
                depth[currentNode] = depth[parent[currentNode]] + 1;
                childCount[parent[currentNode]]--;

                // If no more children, add parent to queue
                if (childCount[parent[currentNode]] == 0) {
                    zeroParentQueue.push(parent[currentNode]);
                }
            }
        }

        vector<int> rankValue(nodeCount + 1, INT_MAX);

        // Calculate rank values for nodes without children
        for (int i = 1; i <= nodeCount; ++i) {
            if (childCount[i] == 0) {
                rankValue[parent[i]] = min(rankValue[parent[i]], depth[i]);
            }
        }

        // Initialize Sprague-Grundy values
        vector<int> sgValues(nodeCount + 1, 0);

        for (int i = 1; i <= nodeCount; ++i) {
            if (!parent[i]) {  // If it's a root node
                set<int> sgSet;
                int currentNode = i;

                // Traverse down to calculate SG values
                while (true) {
                    if (rankValue[currentNode] > 0) {
                        sgSet.insert(sgValues[rankValue[currentNode] - 1]);
                    }
                    if (childCount[currentNode] == 0) {
                        break;
                    }
                    currentNode = childrenWithMinRank(currentNode, rankValue);
                }

                // Calculate minimum excluded value (MEX)
                int mexValue = 0;
                while (sgSet.count(mexValue)) {
                    mexValue++;
                }
                sgValues[rankValue[i] - 1] = mexValue;  // Store MEX
            }
        }

        // Calculating the total Sprague-Grundy value
        int totalSGValue = 0;
        for (int i = 1; i <= nodeCount; ++i) {
            if (!parent[i]) {
                totalSGValue ^= sgValues[rankValue[i] - 1];
            }
        }

        // Output result based on total SG value
        cout << (totalSGValue ? "YES\n" : "NO\n");  // Simplified output logic
    }
}

