// Function to calculate the average of top five scores for each student.
vector<vector<int>> topFiveAverage(const vector<pair<int, int>>& items) {
    // Mapping student ID to their scores
    unordered_map<int, vector<int>> students;

    // Populate each student's scores
    for (const auto& item : items) {
        int id = item.first;
        int score = item.second;
        students[id].push_back(score);
    }

    vector<vector<int>> result;

    // Sort students by ID and compute top 5 average score
    for (auto& entry : students) {
        int id = entry.first;
        vector<int>& scores = entry.second;

        // Sort scores in descending order to find top five
        sort(scores.begin(), scores.end(), greater<int>());
        vector<int> top_five_scores(scores.begin(), scores.begin() + min(5, static_cast<int>(scores.size())));

        // Calculate the average of the top five scores
        int top_five_average = 0;
        for (int score : top_five_scores) {
            top_five_average += score;
        }
        // Note: Dividing by 5 assuming there are at least 5 scores, needs checking!
        top_five_average /= 5;

        result.push_back({id, top_five_average});

        // Debug prints
        cout << "Student ID: " << id << ", Top 5 average: " << top_five_average << endl;
    }

    return result;
}

