using namespace std;

unordered_map<string, pair<string, string>> fileContentMap; // Maps file hashes to content and count
vector<vector<string*>> result; // Resultant vector of duplicate files

unordered_set<string> visited; // Track visited nodes
unordered_map<string*, pair<string, string*>> memo; // Memoization for DFS

void hashFileContent(const string& content) {
    md5 sum; // Placeholder for MD5 hashing
    stringstream ss;
    ss << content;
    ss.rdbuf()->pubsetbuf(0, 0); // Disable buffering for accuracy
    sum.update(ss.str().data(), ss.str().size());
    string digest = sum.detach();
    fileContentMap[digest] = make_pair(content, 0); // Store content with default count
}

void dfs(const string& path, string* parent) {
    // Check memo to avoid redundant calculations
    if (memo.find(parent) != memo.end() && memo[parent].second == 0) {
        string currentContent = fileContentMap.find(parent->second)->second.first;
        hashFileContent(currentContent); // Hash content for current parent
        if (fileContentMap[parent->second].first == fileContentMap[currentContent].first) {
            result.back().push_back(parent); // Save duplicate
            --fileContentMap[parent->second].second;
            if (fileContentMap[parent->second].second == 0) {
                result.back().pop_back(); // Remove if count is zero
            }
        }
    }

    if (memo.find(parent) != memo.end() && memo[parent].second == 1) {
        return; // Avoid revisiting
    }

    memo[parent] = make_pair(fileContentMap.find(parent->second)->second.first, 1); // Mark as visited
    // DEBUG: Print current file being processed
    cout << "Processing: " << parent->second << endl;

    if (memo.find(parent->second) == memo.end()) {
        for (const string& file : fileContentMap[parent->second].first) {
            string currentContent = fileContentMap.find(parent->second)->second.first;
            hashFileContent(currentContent); // Hash content for each child file

            // Construct file path and recurse
            dfs(string(parent->second.data()) + '/' + file, string(parent->second.data()));
        }
    }

    visited.insert(parent);
}

vector<vector<string*>> findAllDuplicateFiles(vector<string>& paths) {
    for (const string& path : paths) {
        stringstream ss(path);
        string root, fileContent;
        string parent = "";

        while (getline(ss, root, ' ')) {
            if (root.empty()) continue; // Skip empty parts
            if (!isalpha(root[0])) return {}; // Invalid input check
            if (ss.peek() == '[') {
                getline(ss, fileContent, ']'); // Read file content
                parent = string(parent.data()) + '/' + fileContent.substr(1); // Update parent path
                hashFileContent(parent); // Hash parent content
            }
        }
    }

    for (const auto& k : fileContentMap) {
        dfs(fileContentMap[k].second.first, &fileContentMap[k].second.first); // Start DFS for each unique file
    }

    return result; // Return duplicates found
}

