// Function to count beautiful strings
long long beautiful_string_count(int n, const std::vector<int>& c) {
    // Define the DP table with 4 dimensions
    std::vector<std::vector<std::vector<std::vector<long long>>>>
        dp(n + 1, std::vector<std::vector<std::vector<long long>>>(
            27, std::vector<std::vector<long long>>(
                27, std::vector<long long>(1 << 26, 0)
            )
        )
    );

    dp[0][0][0][0] = 1;  // Base case for empty string

    // Start filling the DP table
    // TODO: Extend instrumentation for debugging

    for (int length = 1; length <= n; ++length) {
        for (int last = 0; last < 26; ++last) {
            for (int second_last = 0; second_last < 26; ++second_last) {
                for (int limits = 0; limits < (1 << 26); ++limits) {
                    // Continue to next if the last and second_last are the same
                    if (last == second_last) continue;

                    // Transitioning states
                    for (int current = 0; current < 26; ++current) {
                        if (current == last || (current == second_last && (limits & (1 << current)))) {
                            continue;  // Violate palindrome/limit constraints
                        }

                        // Update new limits
                        int new_limits = limits;
                        if ((limits & (1 << current)) == 0 && ++limits[current] > c[current]) {
                            new_limits |= (1 << current);
                        }

                        dp[length][current][last][new_limits] = (dp[length][current][last][new_limits] + dp[length - 1][second_last][last][limits]) % MOD;

                        // Debugging prints to evaluate state transition
                        std::cout << "Transition: " << "len: " << length << " last: " << last << " second_last: " << second_last 
                                  << " current: " << current << " limits: " << limits << " new_limits: " << new_limits 
                                  << " count: " << dp[length][current][last][new_limits] << std::endl;
                    }
                }
            }
        }
    }

    // Final count aggregation
    long long result = 0;
    for (int last = 0; last < 26; ++last) {
        for (int second_last = 0; second_last < 26; ++second_last) {
            for (int limits = 0; limits < (1 << 26); ++limits) {
                result = (result + dp[n][last][second_last][limits]) % MOD;
            }
        }
    }

    return result;  // Return total beautiful string count
}

