#include <unordered_map>
#include <string>
#include <limits>
#include <iostream>

class Solution {
public:
    std::string minWindow(std::string s, std::string t) {
        // TODO: Validate inputs for empty strings and length constraints
        if (t.empty() || t.length() > s.length()) return "";

        std::unordered_map<char, int> t_map;
        for (const auto& i : t) t_map[i]++;

        int l = 0, r = -1;
        int min_l = -1, min_len = std::numeric_limits<int>::max();

        while (true) {
            // Expand the right boundary
            while (r + 1 < s.length()) {
                r++;
                char c = s[r];

                if (t_map.find(c) != t_map.end()) {
                    t_map[c]--;
                }

                // Check if current window covers all characters from t
                if (judge(t_map)) break;
            }

            if (r + 1 >= s.length()) break;

            // Contract the left boundary
            while (l <= r) {
                char c = s[l];
                if (t_map.find(c) != t_map.end()) {
                    t_map[c]++;
                }
                l++;

                // Check if we still have a valid window
                if (!judge(t_map)) break;

                // Update minimum length if current window is valid
                int win_len = r - l + 2; // +2 because l has already moved
                if (min_len > win_len) {
                    min_l = l - 1; // adjust for the last increment in the loop
                    min_len = win_len;
                }
            }
        }

        // Print debug info
        if (min_l != -1) {
            std::cout << "Minimum window found: " << s.substr(min_l, min_len) << " with length: " << min_len << std::endl;
        } else {
            std::cout << "No valid window found." << std::endl;
        }

        return min_l == -1 ? "" : s.substr(min_l, min_len);
    }

private:
    bool judge(std::unordered_map<char, int>& t_map) {
        for (const auto& [ch, fre] : t_map) {
            if (fre > 0) return false;
        }
        return true; // All required characters are present
    }
};

