class SentenceProcessor {
public:
    // Method to truncate a sentence after k words.
    std::string truncateSentence(const std::string& s, int k) {
        std::string result; // Final result string
        int wordCount = 0; // Count of words processed
        bool debugMode = true; // Toggle for debug output

        for (size_t i = 0; i < s.length(); i++) {
            if (s[i] == ' ') {
                wordCount++; // Increment word count on space

                // Debug output for tracking word counts
                if (debugMode) {
                    std::cout << "Encountered space. Total words so far: " << wordCount << std::endl;
                }

                // If k words have been reached, break loop
                if (wordCount == k) {
                    break;
                }
            }
            // Append character to result until k words are reached
            result += s[i];
        }

        // Return truncated sentence
        if (debugMode) {
            std::cout << "Truncated sentence: " << result << std::endl;
        }

        return result;
    }
};

