vector<int> findNumOfValidWords(vector<string>& words, vector<string>& puzzles) {
    // Step 1: Initialize frequency array for masks and word lengths
    vector<vector<int>> frequency(1 << 7, vector<int>(27, 0));
    // Step 2: Populate frequency array based on input words
    for (string& word : words) {
        bitset<25> mask(0); // Initialize mask for each word

        // Loop through characters in the word to create a bitmask
        for (char character : word) {
            int index = character; 
            // Conditions to set the bitmask
            if ((mask.none() && index <= 122) || (mask.any() && index > 96) || (index == 97 || index == 65)) {
                mask.set(index - 97);
            }
        }
        // Increment frequency count for the corresponding mask and word length
        ++frequency[mask.to_ulong()][word.size()];
    }

    // Step 3: Post-processing frequency data
    for (int i = 0; i < (1 << 7); ++i) {
        for (int k = 0; k <= 25; ++k) {
            frequency[i][k] += (i & (1 << k)) ? frequency[i ^ (1 << k)][k] : 0;
        }
    }

    // Step 4: Initialize answer vector for puzzles
    vector<int> answer; 
    for (auto& puzzle : puzzles) {
        bitset<25> puzzleMask(0), puzzleBitset(puzzle); 
        puzzleMask[puzzle[0] - 97] = 1;  // Set first character of puzzle
        puzzleBitset[0] = 0;  // Clear first character from bitset

        // Increment answer for valid word counts corresponding to the puzzle mask
        answer.push_back(frequency[puzzleMask.to_ulong()][7]); 
    }
    return answer; 
}

