// TODO: Implement DFS to determine root nodes and visited state
void dfs(int node, int upto = -1) {
    if (upto != -1)
        root[node] = true; // Mark as root if traversing
    for (int neighbor : graph[node]) {
        if (neighbor == upto) continue; // Avoid going back to parent
        if (!visited[neighbor]) {
            dfs(neighbor, node);
        }
    }
}

// TODO: Dynamic Programming approach to evaluate edges
void dp(int node) {
    if (visited[node]) return; // Prevent reprocessing
    visited[node] = true;
    ans[node] = -1; // Initialization for outcome

    for (int neighbor : graph[node]) {
        dp(neighbor); // Recursive DP call
    }

    // Determine if the node has any non-root children
    if (root[node]) {
        isEdge[node] = true; // Node is part of edge
    } else {
        for (int i = 0; i < graph[node].size(); ++i) {
            if (ans[graph[node][i]] == -1)
                isEdge[node] &= true; // Keep edge status if undetermined
            else
                isEdge[node] &= (ans[graph[node][i]] == (i + 1)); // Check correctness
        }
    }
}

