int min_moves(int n) {
    std::string binary = std::bitset<64>(n).to_string();
    binary.erase(0, binary.find_first_not_of('0')); // Remove leading zeros
    std::vector<std::string> powers_of_two = {
        "1", "10", "100", "1000", "10000", 
        "100000", "1000000", "10000000", "100000000", 
        "1000000000", "10000000000", "100000000000", 
        "1000000000000", "10000000000000", "100000000000000", 
        "1000000000000000", "10000000000000000", 
        "100000000000000000", "1000000000000000000"
    };

    int min_moves = std::numeric_limits<int>::max();
    // Instrumentation: print binary of n
    std::cout << "Binary representation of " << n << ": " << binary << std::endl;

    for (const auto& p : powers_of_two) {
        int i = 0, j = 0, count = 0;
        // Debug print: current power of two
        std::cout << "Comparing with: " << p << std::endl;

        while (i < binary.length() && j < p.length()) {
            if (binary[i] == p[j]) {
                i++;
                j++;
            } else {
                count++;
                i++;
            }
        }
        count += binary.length() - i; // Remaining characters in binary
        count += p.length() - j;      // Remaining characters in power of two
        min_moves = std::min(min_moves, count);

        // Debug print: current min_moves
        std::cout << "Current min_moves after comparing with " << p << ": " << min_moves << std::endl;
    }

    return min_moves;
}

