std::vector<std::vector<int>> analyzeLand(std::vector<std::vector<int>> &land) {
    int rowCount = land.size();
    int colCount = land[0].size();
    int startRow, startCol, endRow, endCol;
    std::vector<std::vector<int>> result;

    // Iterating while there are columns left to process
    while (colCount) {
        // Debugging - print current column being processed
        std::cout << "Processing column count: " << colCount << std::endl;

        for (int j = 0; j < rowCount; j++) {
            startCol = land[j][0];
            startRow = j;
            endRow = j;
            // For debugging - track rows being analyzed
            std::cout << "Start Position - Row: " << startRow << " Col: " << startCol << std::endl;

            // Inner loop to manage row transitions
            for (; j < rowCount; j++) {
                // Debug print to observe values being compared
                std::cout << "Evaluating land[" << j << "][0] = " << land[j][0] << " against startCol = " << startCol << std::endl;

                if (land[j][0] == startCol) {
                    endRow = j;  // Maintain endRow if condition is satisfied
                } else {
                    // Finalizing once a different value is encountered - record the segment
                    std::vector<int> segment = {startRow, endRow, startCol};
                    result.push_back(segment);
                    // Debug output for segmented results
                    std::cout << "Segment found: StartRow: " << startRow << " EndRow: " << endRow << " Value: " << startCol << std::endl;
                    break;  // Exit since we have processed a segment
                }
            }
        }
        colCount--;  // Decrease the column count for next iteration
    }
    return result;  // Return the collected results for analysis
}

