// Function to calculate the maximum profit from events
int maxEvents(vector<tuple<int, int, int>>& events) {
    // Sort events based on their end time
    sort(events.begin(), events.end(), [](const tuple<int, int, int>& a, const tuple<int, int, int>& b) {
        return get<1>(a) < get<1>(b);
    });

    // Initialize dp array
    vector<int> dp(events.size() + 1, 0);

    // Debug: Print initial state of events
    cout << "Sorted Events: ";
    for (const auto& event : events) {
        cout << "[" << get<0>(event) << "," << get<1>(event) << "," << get<2>(event) << "] ";
    }
    cout << endl;

    // Calculate maximum profit
    for (size_t i = 1; i <= events.size(); ++i) {
        // Calculate max profit for the current event
        dp[i] = 0; // Reset dp[i] in each iteration
        for (size_t j = 0; j < i; ++j) {
            if (get<1>(events[j]) <= get<0>(events[i - 1])) {
                // Possible to attend this event
                dp[i] = max(dp[i], dp[j] + get<2>(events[i - 1]));
            }
        }
        // Instrumentation: Debug - print current dp state
        cout << "After Event " << i << ": dp = ";
        for (const auto& val : dp) {
            cout << val << " ";
        }
        cout << endl;
    }

    return dp.back();
}

int main() {
    // Test cases to validate the maxEvents function
    cout << "Max Events Profit (Test 1): " << maxEvents(vector<tuple<int, int, int>> {{1, 3, 2}, {4, 5, 2}, {2, 4, 3}}) << endl; // Expected: 4
    cout << "Max Events Profit (Test 2): " << maxEvents(vector<tuple<int, int, int>> {{1, 3, 2}, {4, 5, 2}, {1, 5, 5}}) << endl; // Expected: 5
    cout << "Max Events Profit (Test 3): " << maxEvents(vector<tuple<int, int, int>> {{1, 5, 3}, {1, 5, 1}, {6, 6, 5}}) << endl; // Expected: 8

