class Solution {
public:
    // This function counts the overlapping days between Alice and Bob's stays
    int countDaysTogether(string arriveAlice, string leaveAlice, string arriveBob, string leaveBob) {

        // Array to hold the number of days in each month
        int month[12] {31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};

        // Variables to track the total days of stay for both Alice and Bob
        int total_days_overlap = 0;

        // Ensure arriveBob is after or on the same day as arriveAlice
        if (arriveBob < arriveAlice) {
            swap(arriveBob, arriveAlice);
            swap(leaveBob, leaveAlice); // Ensure leaving days are also swapped correspondingly
        }

        // Debug prints to monitor string values
        cout << "Alice arrives: " << arriveAlice << ", leaves: " << leaveAlice << endl;
        cout << "Bob arrives: " << arriveBob << ", leaves: " << leaveBob << endl;

        // Parsing arrival and leave dates
        int arriveAlice_month = stoi(arriveAlice.substr(0, 2));
        int leaveAlice_month = stoi(leaveAlice.substr(0, 2));
        int arriveBob_month = stoi(arriveBob.substr(0, 2()));
        int leaveBob_month = stoi(leaveBob.substr(0, 2));

        // Iterate through the months
        for (int month_index = 0; month_index < 12; month_index++) {
            // Only count days during months Alice is present
            if (month_index + 1 < arriveAlice_month || month_index + 1 > leaveAlice_month) {
                continue; // Skip months outside Alice's range
            }

            // Calculate overlap: check how many days within the range for both
            for (int day = 1; day <= month[month_index]; day++) {
                // Check if the day falls within both Alice's and Bob's stay
                if ((month_index + 1 >= arriveAlice_month && month_index + 1 <= leaveAlice_month
                     && day >= stoi(arriveAlice.substr(3, 2)) && day <= stoi(leaveAlice.substr(3, 2)))
                    && (month_index + 1 >= arriveBob_month && month_index + 1 <= leaveBob_month
                     && day >= stoi(arriveBob.substr(3, 2)) && day <= stoi(leaveBob.substr(3, 2))) 
                    ) {
                    total_days_overlap++;
                }
            }
        }

        // Debug print to check total overlapping days
        cout << "Total overlapping days: " << total_days_overlap << endl;

        return total_days_overlap;
    }
};

