        int count_one = 0;   // Count of '1's
        int count_zero = 0;  // Count of '0's
        // Research: Iteration to count '0's and '1's
        for (auto a : answerKey) {
            if (a == '0') {
                count_one++;
            } else {
                count_zero++;
            }
        }

        // Experimental Logic: Check counts to determine the maximum consecutive answers
        if (count_zero >= count_one) {
            // Check replacement feasibility
            if (count_zero == k) {
                return count_zero;
            } else {
                return count_zero + count_one - k;
            }
        } else {
            if ((count_one + count_one - k) >= count_zero) {
                return count_one + count_one - k;
            } else if ((count_one + 1) >= count_zero) {
                return count_one + 1;
            } else {
                return count_one;
            }
        }
    }
};

// Research: Binary Search Tree (BST) Construction from Preorder Traversal
struct node {
    int key;
    struct node *left, *right;
};

// Node Creation Function
struct node* newNode(int item) {
    struct node *temp = (struct node *)malloc(sizeof(struct node));
    temp->key = item;
    temp->left = temp->right = NULL;
    return temp;
}

// Experimental Search Function
int search(const vector<int> &pre, int x) {
    for (int i = 0; i < pre.size(); ++i) {
        if (pre[i] == x) {
            return i;
        }
    }
    return -1;
}

// Constructing Tree Function
struct node* constructTree(const vector<int> pre) {
    if (pre.empty() || pre[0] == '\0') return NULL; // Research: Base case

    struct node *root = newNode(pre[0]);  // Create root node
    if (pre.size() == 1) return root;      // One-node tree return

    int i = search(pre, pre[1]); // Finding right boundary for left subtree
    if (i != -1) {
        vector<int> left(pre.begin() + 1, pre.begin() + i + 1);
        root->left = constructTree(left);
        vector<int> right(pre.begin() + i + 1, pre.end());
        root->right = constructTree(right);
    } else {
        root->right = constructTree(pre);  // No left; just continue right
    }
    return root;
}

// Main Function to Test Tree Construction
