    const vector<int> pre = { 10, 30, -1, -1, 20, 50, -1, -1, 40, 70, -1, -1, 60, 80, -1, -1, 90 };
    cout << "Starting Tree Construction from Preorder: \n";
    struct node* root = constructTree(pre);
    cout << "Tree creation completed...\n";
    cout << "Root Value is: " << root->key << "\n";
}

