// Function to calculate the maximum sum of two non-overlapping subarrays
long long maxBeauty(const std::vector<int>& a, int left, int right) {
    if (left > right) return 0;

    // Variables to track max values
    long long leftMax = a[left];
    long long rightMax = a[left];
    long long maxEndingHere = a[left];

    // Compute max subarray sum for full array between left and right
    for (int i = left + 1; i <= right; ++i) {
        maxEndingHere = std::max(static_cast<long long>(a[i]), maxEndingHere + a[i]);
        leftMax = std::max(leftMax, maxEndingHere);
    }

    // Calculate crossing subarrays
    long long crossingSum = 0;
    maxEndingHere = 0;
    for (int i = right; i >= left; --i) {
        maxEndingHere += a[i];
        crossingSum = std::max(crossingSum, maxEndingHere);
    }

    return leftMax + crossingSum;
}

// Recursive function to calculate beauty for given subsegment
long long subsegmentBeauty(const std::vector<int>& a, int left, int right) {
    if (left == right) {
        return a[left] % MOD; // Single element case, beauty is its own value
    }
    int mid = left + (right - left) / 2;

    // Recursively compute maximum beauty values in segments
    long long leftBeauty = subsegmentBeauty(a, left, mid);
    long long rightBeauty = subsegmentBeauty(a, mid + 1, right);
    long long crossingBeauty = maxBeauty(a, left, right);

    // Combine results
    return (leftBeauty + rightBeauty + crossingBeauty) % MOD;
}

// Debug function to print the array
void debugPrint(const std::vector<int>& a) {
    std::cout << "Array contents: ";
    for (const auto& val : a) {
        std::cout << val << " ";
    }
    std::cout << std::endl;
}

// Main function to process test cases (placeholder for experimentation)
int main() {
    std::vector<int> testArray = {1, -2, 3, 4, -5, 6};

    debugPrint(testArray); // Debugging array contents

    long long totalBeauty = subsegmentBeauty(testArray, 0, testArray.size() - 1);

    std::cout << "Total beauty of all subsegments: " << totalBeauty << std::endl;

    return 0;
}

