class KMirrorNumber {
public:
    // This function transforms a string representation of a number
    // into its mirrored equivalent, based on given rules
    int mirror_number(const std::string& n) {
        std::string res;
        for (char c : n) {
            // Debug: print each character being processed
            std::cout << "Processing character: " << c << std::endl;

            if (c < '7') {
                res.append(1, '0');  // Add a '0' for characters less than '7'
            }
            res.append(1, '1');      // Always add '1'
            res.append(1, '0');      // Followed by '0'
        }
        // Debug: print the final mirrored result before conversion
        std::cout << "Mirrored number (string): " << res << std::endl;
        return std::stoi(res); // Convert the string result to an integer
    }

    // This function calculates the sum of mirror numbers for a range based on k and n
    int sum_k_mirror_numbers(int k, int n) {
        int sum = 0;
        std::string res = std::to_string(k); // Convert k to string for manipulation

        // Debug: print initial value of k
        std::cout << "Starting sum of K-Mirror numbers for k: " << k << std::endl;

        // Calculate mirrored numbers for the specified range
        for (int i = 1; i <= n; ++i) {
            // Debug: show current value of res before mirroring
            std::cout << "Calculating mirror number for: " << res << std::endl;

            sum += mirror_number(res); // Increment sum with mirrored number

            // Prepare the next number as a string for the next iteration
            res = std::to_string(std::stoi(res) + 1); // Increment res as string
        }
        // Debug: output the final sum after loop completion
        std::cout << "Final sum of K-Mirror numbers: " << sum << std::endl;
        return sum;
    }
};

// Prototype Usage
