#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

// Research function to answer queries based on the nums vector and queries list.
vector<int> answerQueries(vector<int>& nums, vector<vector<int>>& queries) {
    int n = nums.size();
    vector<int> marked(n, 0); // Array to keep track of marked indices.
    vector<int> answer; // To store the results of each query.

    // Iterate through each query to process.
    for (auto& query : queries) {
        int idx = query[0];
        int k = query[1];

        // Mark the index of the current query.
        if (!marked[idx]) {
            marked[idx] = 1; // Mark this index
            k++; // Increase k since we're marking this index.
        }

        vector<pair<int, int>> unmarked; // To store unmarked elements.
        for (int i = 0; i < n; i++) {
            if (!marked[i]) {
                unmarked.emplace_back(nums[i], i); // Store value and index.
            }
        }

        // Sort unmarked elements in non-decreasing order.
        sort(unmarked.begin(), unmarked.end());

        // Debug: Print unmarked elements to verify sorting.
        cout << "Unmarked elements (before selection): ";
        for (const auto& p : unmarked) {
            cout << "(" << p.first << ", " << p.second << ") ";
        }
        cout << endl;

        // Select the first k unmarked elements to mark.
        for (int i = 0; i < min(k, static_cast<int>(unmarked.size())); i++) {
            marked[unmarked[i].second] = 1; // Mark the selected indices.
        }

        // Calculate the sum of remaining unmarked elements.
        int sum = 0;
        for (int i = 0; i < n; i++) {
            if (!marked[i]) {
                sum += nums[i]; // Accumulate the sum of unmarked elements.
            }
        }
        answer.push_back(sum); // Store result for the current query.

        // Debug: Output current sum.
        cout << "Sum after processing query [" << idx << ", " << query[1] << "]: " << sum << endl;
    }

    return answer; // Final results for all queries.
}

int main() {
    // Sample data for experimentation.
    vector<int> nums = {1, 2, 2, 1, 2, 3, 1}; 
    vector<vector<int>> queries = {{1, 2}, {3, 3}, {4, 2}};

    // Invoking the answerQueries function.
    vector<int> result = answerQueries(nums, queries);

    // Output the results to examine the behavior.
    cout << "Results: ";
    for (int val : result) {
        cout << val << " "; // Display each result.
    }
    cout << endl;

    return 0; // End of main function.
}

#include <string>
