std::string findSmallestSubsequenceWithRepetition(const std::string& input, int k, char targetChar, int requiredRepetition) {
    // Dynamic Programming structure for tracking subsequences
    std::vector<std::vector<char>> dp(input.length() + 1, std::vector<char>(k + 1, '\0'));
    std::string output = "";

    for (int i = 1; i <= input.length() && dp[i][k] == '\0'; ++i) {
        dp[i][0] = input[i - 1]; // Initialize first column with characters from the input

        for (int j = 1; j <= k && j <= i && dp[i][j - 1] != '\0'; ++j) {
            char prevChar = dp[i][j - 1];
            if (prevChar == '*' || (prevChar != targetChar && prevChar != dp[i][j - 1] || dp[i][j - 1] == '*')) {
                dp[i][j] = prevChar; // Carry forward the character
            } else if (input[i - 1] == targetChar && i - requiredRepetition >= 0 && dp[i - requiredRepetition][j - 1] == targetChar) {
                dp[i][j] = '*'; // Replace with placeholder for repetition
            } else {
                dp[i][j] = input[i - 1]; // Update with current character
            }
        }

        // Instrumentation: Check if we have a valid subsequence
        bool isValid = true;
        for (int j = 1; j <= k; ++j) {
            if (dp[i][j - 1] != targetChar && (dp[i][j - 1] != '\0' || output.empty())) {
                isValid = false;
                break; // Exit loop if invalid
            }
        }

        // Debug Print: Current state of DP and Valid Status
        std::cout << "DP State at index " << i << ": ";
        for (int j = 0; j <= k; ++j) {
            std::cout << dp[i][j] << " ";
        }
        std::cout << " | Valid: " << isValid << "\n";

        // Update result based on validity condition
        if (isValid && j == k) {
            output = input.substr(i - k, k); // Extract valid subsequence
        }
    }

    // Final debug statement for output
    std::cout << "Final Output: " << (output.empty() ? input : output) << "\n";
    return output.empty() ? input : output; // Return result or original string
}

#include <iostream>
#include <algorithm>

int calculateMaxProtection(int numShields, int maxMovableShields, bool shieldArray[]) {
    int highestProtection = 0;

    // Iterating through all possible movements of shields
    for (int movementCount = 0; movementCount <= maxMovableShields; ++movementCount) {
        int currentShieldCount = 0;
        int currentProtection = 0;

        // Counting the number of active shields
        for (int index = 0; index < numShields; ++index) {
            if (shieldArray[index]) {
                currentShieldCount++;
            }
        }

        // Calculating protection based on movable shields
        if (currentShieldCount > 0) {
            int shieldsToRelocate = std::min(currentShieldCount, maxMovableShields - movementCount);
            currentProtection += shieldsToRelocate * (shieldsToRelocate - 1) / 2;
            maxMovableShields -= shieldsToRelocate;
        }

        // Track the maximum protection achieved
        highestProtection = std::max(highestProtection, currentProtection);
    }

    return highestProtection;
}

int main() {
    int totalShields;
    std::cout << "Enter number of shields: ";
    std::cin >> totalShields;

    bool shieldConfiguration[totalShields];
    std::cout << "Input shield states (1 for active, 0 for inactive): ";
    for (int i = 0; i < totalShields; ++i) {
        std::cin >> shieldConfiguration[i];
    }

    // Experiment with different numbers of movable shields
    for (int movableVal = 0; movableVal <= (totalShields * (totalShields - 1)) / 2; ++movableVal) {
        int computedProtection = calculateMaxProtection(totalShields, movableVal, shieldConfiguration);
        std::cout << computedProtection << " ";

        // Debugging print statements for insight
        std::cout << "[Debug] Movable Shields: " << movableVal 
                  << ", Computed Protection: " << computedProtection << std::endl;
    }

    return 0;
}

