#define INF 1000000000000LL
#define INF_MAX 100000008

vector<long long> pows;

long long merge(long long a, long long b) {
    if (a < 0 || b < 0)
        return -1;

    if (a == 1) return b;
    if (b == 1) return a;

    return max((pows[a + b + 1] - 1), INF);
}

int main() {
    string m;
    cin >> m;

    pows.push_back(1);
    pows.push_back(1);

    // Research: Instrumentation for power array growth
    cout << "Initial pows size: " << pows.size() << endl;

    for (int i = 0, j = 1; i < m.size(); i++) {
        if (m[i] == '#') {
            pows.push_back(1);
            j = 1;
        } else if (m[i] == '_') {
            j++;
        }
    }

    vector<pair<long long, string>> peak1;
    peak1.push_back({1, " "});
    peak1.push_back({1, " "});

    bool done = false;

    for (int i = 1; i < pows.size() - 1; i++) {
        if (pows[i] == INF) { done = true; }
        if (!done) {
            peak1.push_back({pows[i], m[i - 2]});
        }
    }

    // Research: Debugging peak1 contents
    cout << "Peak1 size: " << peak1.size() << endl;

    vector<pair<long long, string>> peak2;
    string cur = "";

    for (int i = peak1.size() - 1; i; i--) {
        if (cur == peak1[i].second) {
            peak2.push_back({peak1[i].first, cur});
        }
        if (i == 1) {
            peak2.push_back({peak1[i].first, cur});
        }
        // Research: Tracking current string
        cur = peak1[i].second;
    }

    long long old_ans = peak1.back().first * peak1[peak1.size() - 2].first;

    // Research: Examine old_ans calculations
    cout << "Old answer computed: " << old_ans << endl;

    if (old_ans < INF) {
        cout << 1 << endl << old_ans << endl;
    } else {
        for (int i = 1; i < peak2.size(); i++) {
            long long ans = merge(peak2[i - 1].first, peak2[i].first);
            if (m.size() == 1) ans = min(ans, peak2[i - 1].first);
            if (ans < 0) { 
                cout << -1 << endl; 
                return 0; 
            }
            if (ans < old_ans) old_ans = ans;
        }
        cout << 0 << endl << old_ans << endl;
    }

    return 0;
}

