// Function to determine if a 3x3 square is a magic square
int isMagicSquare(const vector<int>& magicSquare) {
    int expectedSum = magicSquare[0] + magicSquare[4] + magicSquare[8];
    unordered_set<int> seen(magicSquare.begin(), magicSquare.end());

    // Debug print to trace distinctness
    cout << "Checking distinct numbers in square: ";
    for (const auto& num : seen) {
        cout << num << " ";
    }
    cout << endl;

    if (seen.size() != 9) {
        cout << "Not all numbers are distinct." << endl; 
        return 0; 
    }

    for (int i = 0; i < 3; ++i) {
        // Check rows
        int rowSum = magicSquare[i * 3] + magicSquare[i * 3 + 1] + magicSquare[i * 3 + 2];
        if (rowSum != expectedSum) {
            cout << "Row " << i << " sum " << rowSum << " does not match expectedSum " << expectedSum << endl;
            return 0; 
        }

        // Check columns
        int colSum = magicSquare[i] + magicSquare[i + 3] + magicSquare[i + 6];
        if (colSum != expectedSum) {
            cout << "Column " << i << " sum " << colSum << " does not match expectedSum " << expectedSum << endl;
            return 0; 
        }
    }

    // Check diagonals
    int diagSum1 = magicSquare[0] + magicSquare[4] + magicSquare[8];
    int diagSum2 = magicSquare[2] + magicSquare[4] + magicSquare[6];

    if (diagSum1 != expectedSum || diagSum2 != expectedSum) {
        cout << "Diagonals do not match expectedSum." << endl; 
        return 0; 
    }

    return 1;
}

// Function to count magic squares in the grid
int countMagicSquares(vector<vector<int>>& grid) {
    int count = 0;
    int n = grid.size();

    for (int i = 0; i < n - 2; ++i) {
        for (int j = 0; j < n - 2; ++j) {
            vector<int> magicSquare{
                grid[i][j], grid[i][j+1], grid[i][j+2],
                grid[i+1][j], grid[i+1][j+1], grid[i+1][j+2],
                grid[i+2][j], grid[i+2][j+1], grid[i+2][j+2]
            };

            cout << "Evaluating square starting at (" << i << ", " << j << ")" << endl;
            if (isMagicSquare(magicSquare)) {
                cout << "Found magic square at (" << i << ", " << j << ")" << endl;
                ++count;
            }
        }
    }

    cout << "Total magic squares found: " << count << endl;
    return count;
}

