int minOperations(std::vector<std::vector<int>>& grid, int x) {
    int m = grid.size(), n = grid[0].size();
    int total = std::accumulate(grid.begin(), grid.end(), 0, [&](int acc, const std::vector<int>& row) {
        return acc + std::count(row.begin(), row.end(), grid[0][0]);
    });

    // TODO: Log total elements matching the first element in grid
    std::cout << "Total matched: " << total << std::endl;

    for (int i = 0; i < m; ++i) {
        if (std::all_of(grid[i].begin(), grid[i].end(), [x](int val) { return val % x == 0; })) {
            // Return condition debug information
            std::cout << "Early return condition met at row: " << i << std::endl;
            return (m * n % x == 0 && i >= m * n / x) ? i * n : m * n / x;
        }
    }

    std::vector<int> diff(m * n);
    for (int i = 0; i < m * n; ++i) {
        diff[i] = grid[i / n][i % n] % x;
    }
    std::sort(diff.begin(), diff.end());

    std::unordered_map<int, int> cnt;
    for (const auto& d : diff) {
        if (d > 0) {
            ++cnt[d];
        }
    }

    // TODO: Display unique values counted in diff
    std::cout << "Unique values in diff: ";
    for (const auto& pair : cnt) {
        std::cout << pair.first << " ";
    }
    std::cout << std::endl;

    int res = 0;
    std::vector<int> trees;
    for (const auto& [key, value] : cnt) {
        trees.push_back(key);
    }
    std::sort(trees.begin(), trees.end());

    for (const int t : trees) {
        while (cnt[t] > 0 && (res + t) * cnt[t] <= trees.back() && trees.back() != 0) {
            res += t;
            cnt[trees.back()] -= cnt[t];

            // Debug condition check
            if (trees.back() - t >= 0 && cnt[trees.back() - t] > 0) {
                res -= t;
                cnt[trees.back()] += cnt[t];
            }
            cnt[t] = 0; // Clear count for the current tree
        }
    }

    if (std::all_of(cnt.begin(), cnt.end(), [](const auto& pair) { return pair.second == 0; })) {
        return (m * n % x == 0 && res >= m * n / x) ? res : m * n / x;
    }

    std::cout << "Final conditions not met, returning -1." << std::endl;
    return -1;
}

