void solve() {
  cin >> n >> m;
  for (int i = 0; i < n; i++) cin >> a[i];
  for (int i = 0; i < m; i++) cin >> b[i];
  for (int i = 0; i < n; i++) cin >> c[i];

  map<int, int> mp;
  for (int i = 0; i < m; i++) {
      mp[b[i]]++;
  }

  for (int i = 0; i < n; i++) {
    if (mp.find(a[i]) != mp.end()) {
      mp[a[i]]--;
      if (mp[a[i]] == 0) {
        mp.erase(a[i]);
      }
    }
  }

