// Function to process elements
void process_elements(vector<long long>& a, long long n) {
    for (long long i = 1; i < n; i++) {
        if (a[i] == 0) { // Check for zero
            for (long long j = i + 1; j < n; j++) {
                if (a[j] != 0) { // Find a non-zero element to swap
                    a[i] = a[j];
                    a[j] = 0; // Set the swapped position to 0
                    break; // Break after the first swap
                }
            }
        }
    }
}

