public:
    vector<vector<int>> allCellsDistOrder(int R, int C, int r0, int c0) {
        // Research goal: Determine cell distances from a source cell (r0, c0)

        vector<vector<int>> dist(R, vector<int>(C, INT_MAX)); // Initialize distance matrix
        for (int r = 0; r < R; r++) dist[r][r] = 0; // Set diagonal to zero
        for (int c = 0; c < C; c++) dist[c][c] = 0; // Redundant for clarity

        // Calculate initial Manhattan distances from (r0, c0)
        for (int r = 0; r < R; r++) {
            for (int c = 0; c < C; c++) {
                int currentDist = abs(r - r0) + abs(c - c0);
                if (currentDist < dist[r][c]) {
                    dist[r][c] = currentDist;
                    // Debug print for distance updates
                    cout << "Updated dist[" << r << "][" << c << "] to " << currentDist << endl;
                }
            }
        }

        // Floyd-Warshall-like update to potentially find shorter paths (experimental)
        for (int k = 0; k < R; k++) {
            for (int r = 0; r < R; r++) {
                for (int c = 0; c < C; c++) {
                    if (dist[r][c] > dist[r][k] + dist[k][c]) {
                        dist[r][c] = dist[r][k] + dist[k][c];
                        // Debug print for path updates
                        cout << "Updated dist[" << r << "][" << c << "] via node " << k 
                             << " to " << dist[r][c] << endl;
                    }
                }
            }
        }

        // Compiling results for output
        vector<vector<int>> ans;
        for (int r = 0; r < R; r++) {
            for (int c = 0; c < C; c++) {
                ans.push_back({r, c});
                // Instrumentation: log each cell being added
                cout << "Adding cell: (" << r << ", " << c << ")" << endl;
            }
        }

        // Sort output based on distance, using custom comparator
        sort(ans.begin(), ans.end(), [&](const vector<int>& a, const vector<int>& b) {
            return dist[a[0]][a[1]] < dist[b[0]][b[1]];
        });

        return ans;
    }
};

public:
    int numTriplets(vector<int>& a, vector<int>& b) {
        // Sort input arrays for systematic pairing
        sort(a.begin(), a.end());
        sort(b.begin(), b.end());

        // Count triplets in both orders
        int totalCount = count(a, b) + count(b, a);

        // Debug statement to verify total counts
        cout << "Total triplets found: " << totalCount << endl;

        return totalCount;
    }

    int count(vector<int>& a, vector<int>& b) {
        long ans = 0; // Initialize answer counter
        unordered_map<long, long> frequencyMap; // To map square values of b

        // Initialize frequency map with unique squares of elements in b
        for (int i = 0; i < b.size(); i++) {
            if (i == 0 || b[i] != b[i - 1]) {
                frequencyMap[b[i]] = 0; 
            }
        }

        // Count frequency of unique elements in b
        for (int i = 0; i < b.size(); i++) {
            if (i == 0 || b[i] != b[i - 1]) {
                frequencyMap[b[i]]++; 
            }
            long requiredValue = b[i] * (long)b[i]; // Calculate the square requirement
            long previous = 0; // Previous value to avoid duplicates

            for (int j = 0; j < a.size(); j++) {
                if (previous == a[j]) continue; // Skip if value is the same as before
                previous = a[j]; 

                // Develop instrumentation for square checks
                long aSquare = a[j] * (long)a[j];

                // Research note: Check if square of b[i] can be divided by square of a[j]
                if (frequencyMap.count(aSquare)) {
                    ans += frequencyMap[requiredValue / aSquare]; // Update answer
                    // Debug statement for every successful match
                    cout << "Match found: a[" << j << "]=" << a[j] << " b[" << i << "]=" << b[i] << " count=" << frequencyMap[requiredValue / aSquare] << endl;
                }

                // Break if the square of the current a[j] exceeds square of b[i]
                if (aSquare > requiredValue) break; 
            }
        }

        // Final debug statement to summarize trips counted for current configuration
        cout << "Triplets counted for configurations: " << ans << endl;

        return ans; // Return total triplet count for this configuration
    }

