using namespace std;

// Function to identify the first unsorted element
int findFirstUnsorted(const vector<int>& arr, int l, int r) {
    int i = r - 1;
    while(i >= l && arr[i] >= arr[i + 1]) {
        i--;
    }
    return i;
}

// Function to find the smallest unsorted permutation
void deriveSmallestUnsortedPermutation(vector<int>& arr, int l, int r) {
    int i = findFirstUnsorted(arr, l, r);
    if(i == l - 1) return;

    int j = r;
    while(j > i && arr[j] < arr[i]) {
        j--;
    }

    swap(arr[i], arr[j]);
    reverse(arr.begin() + i + 1, arr.begin() + r + 1);
}

// Function to calculate the next permutation in place
int computeNextPermutation(vector<int>& arr) {
    int n = arr.size();
    if(n <= 1) return -1;

    deriveSmallestUnsortedPermutation(arr, 0, n - 1);

    int i = 0, j = n - 2;
    while(i < j) {
        if(arr[i] < arr[j]) break;
        i++;
        j--;
    }

    if(i == j) return -1;

    swap(arr[i], arr[j]);

    for(int k = i + 1; k < n - 1; k++) {
        if(arr[k] > arr[i]) {
            swap(arr[k], arr[i + 1]);
            break;
        }
    }
    return 0;
}

// Function to perform a range sum query
int sumRange(const vector<int>& arr, int l, int r) {
    return accumulate(arr.begin() + l, arr.begin() + r + 1, 0);
}

