class Solution {
public:
    int numSpecialPositions(std::vector<std::vector<int>>& mat) {
        int rows = mat.size();
        int cols = mat[0].size();
        std::priority_queue<std::pair<int, int>> queue; // Using pair instead for clarity
        std::vector<std::pair<int, int>> result;

        // Initial queue setup
        for (int i = 0; i < rows; i++) {
            queue.push({i, 0});
        }

        while (!queue.empty()) {
            auto cell = queue.top();
            queue.pop();
            int row = cell.first;
            int col = cell.second;

            // Debugging output
            std::cout << "Processing cell: (" << row << ", " << col << ")" << std::endl;

            if (row < rows && mat[row][col] == 1) {
                // Check for left
                if (col > 0 && mat[row][col - 1] == 1 && mat[row][col] == 0 && mat[row][col + 1] == 0) {
                    queue.push({row, col - 1});
                    std::cout << "Detected left special position at: (" << row << ", " << col - 1 << ")" << std::endl;
                }
                // Check for top
                if (row > 0 && mat[row - 1][col] == 1 && mat[row][col] == 0 && mat[row + 1][col] == 0) {
                    queue.push({row - 1, col});
                    std::cout << "Detected top special position at: (" << row - 1 << ", " << col << ")" << std::endl;
                }
                // Check for right
                if (col < cols - 1 && mat[row][col + 1] == 1 && mat[row][col] == 0 && mat[row][col - 1] == 0) {
                    queue.push({row, col + 1});
                    std::cout << "Detected right special position at: (" << row << ", " << col + 1 << ")" << std::endl;
                }
                // Check for bottom
                if (row < rows - 1 && mat[row + 1][col] == 1 && mat[row][col] == 0 && mat[row + 1][col + 1] == 0) {
                    queue.push({row + 1, col});
                    std::cout << "Detected bottom special position at: (" << row + 1 << ", " << col << ")" << std::endl;
                }
            }

            if (!queue.empty())
                result.push_back(cell);
        }

        // Final result: count special positions
        std::cout << "Total special positions found: " << result.size() << std::endl;
        return result.size();
    }
};

