public:
    // Experimenting with the method to compute values based on n and k.
    int solve(int n, int k) {
        // Debug output to track the dimensions of the DP table
        std::cout << "Initializing DP table with dimensions: k = " << k << ", n = " << n << std::endl;

        long long dp[k + 1][n + 1]; // Dynamic programming table

        // Base cases
        dp[0][0] = 1;  // There's one way to fill 0 slots with 0 parts
        dp[1][1] = 1;  // One way to fill 1 slot with 1 part

        // Filling dp for 1 part (k=1)
        for (int i = 2; i <= n; i++) {
            dp[1][i] = 1; // Only one way to fill multiple slots with a single part
        }

        // Main DP loop to calculate number of ways to partition
        for (int i = 2; i <= k; i++) {
            dp[i][0] = 0; // No way to fill 0 slots with more than 0 parts

            // Inner loop for filling dp array
            for (int j = 1; j <= n; j++) {
                if (i >= j) {
                    // Experimental debug output for tracking state
                    std::cout << "dp[" << i << "][" << j << "] using i >= j: "
                              << "dp[" << i - 1 << "][" << j - 1 << "] + dp[" << i - 1 << "][" << j << "]." << std::endl;

                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1] + dp[i - 1][j]) % MOD;
                } else {
                    // Experimental debug output for different state
                    std::cout << "dp[" << i << "][" << j << "] using i < j: "
                              << "dp[" << i << "][" << j - 1 << "] + dp[" << i - 1 << "][" << j - 1 << "]." << std::endl;

                    dp[i][j] = (dp[i][j] + dp[i][j - 1] + dp[i - 1][j - 1]) % MOD;
                }
            }
        }

        // Debug output for final result
        std::cout << "Final result: dp[" << k << "][" << n << "] = " << dp[k][n] << std::endl;

        return (int)dp[k][n]; // Return the computed number of ways
    }
};

