std::string findTheOdd(const std::vector<std::string>& words) {
    // Step 1: Initialize a dictionary to hold the differences
    std::unordered_map<std::tuple<int, int>, std::vector<std::string>> dictD;

    // Step 2: Process each word to calculate differences
    for (const auto& word : words) {
        // Create a vector to hold the differences between characters
        std::vector<int> diff;
        for (size_t i = 1; i < word.length(); ++i) {
            int difference = static_cast<int>(word[i]) - static_cast<int>(word[i - 1]);
            diff.push_back(difference);
        }

        // Convert vector to tuple to use as a key in the map
        auto tup = std::make_tuple(diff.begin(), diff.end());

        // Step 3: Store words in the dictionary based on their character differences
        dictD[tup].push_back(word);
    }

    // Step 4: Search for the unique word with a specific difference signature
    for (const auto& [k, v] : dictD) {
        // Debug: Print the key and the corresponding words
        std::cout << "Key: ";
        for (const auto& d : k) {
            std::cout << d << " ";
        }
        std::cout << "Words: ";
        for (const auto& w : v) {
            std::cout << w << " ";
        }
        std::cout << std::endl;

        if (v.size() == 1) {
            // Return the first character of the unique word
            return std::string(1, v[0][0]);
        }
    }

    return ""; // Default return empty string if no unique word is found
}

