    for (int i = 0; i < t; ++i) {
        std::vector<int> input = reader();
        int num = input[0], hour = input[1], minu = input[2];
        std::vector<std::pair<int, int>> alarms;

        for (int j = 0; j < num; ++j) {
            input = reader();
            int h = input[0], m = input[1];
            alarms.emplace_back((hour + h) % 24, (minu + m) % 60);
        }

        int earliest_self_hours = -1;
        int earliest_self_minu = -1;

        for (const auto& alarm_time : alarms) {
            int hours = alarm_time.first;
            int minutes = alarm_time.second;

            if (hours == hour && minutes == minu) {
                if (earliest_self_hours == -1) {
                    earliest_self_hours = hours;
                    earliest_self_minu = minutes;
                } else {
                    earliest_self_minu = std::min(minutes, earliest_self_minu);
                }
            }
        }

        std::cout << (earliest_self_hours != -1 
            ? std::to_string(earliest_self_hours - hour) + " " + std::to_string(earliest_self_minu - minu)
            : "0 0") << std::endl;
    }
}

