// TODO: Implement Extended Euclidean algorithm to find GCD
bool computeGCD(int a, int b, int &x, int &y) {
    // Base case for recursion
    if (b == 0) {
        x = a;
        y = 1;
        return true;
    } else {
        int x1, y1;
        // Recursive call
        if (computeGCD(b, a % b, x1, y1)) {
            x = y1 - (a / b) * x1; // Coefficient update
            y = x1;
            return true;
        } else {
            x = a;
            y = b;
            return false;
        }
    }
}

