bool isConfigurationPossible(vector<int>& target) {
    int size = target.size();

    // Step 1: Sort the target array - necessary for analysis
    sort(target.begin(), target.end());
    int currentMaxLength = 0;
    int exceedCount = 0;

    // Step 2: Analyze from the start to determine valid segments
    for (int index = 0; index < size; index++) {
        if (currentMaxLength < index + 1) // Check if we've exceeded current max length
            exceedCount++;
        currentMaxLength = max(target[index], currentMaxLength); // Update current max length
    }

    // Debugging instrument: Monitor exceeded segments count
    cout << "Exceed count (first half): " << exceedCount << endl;

    // Condition check based on the first half analysis
    if (exceedCount > (size + 1) / 2)
        return false;

    currentMaxLength = 0; // Reset for the backward analysis
    exceedCount = 0; // Reset count

    // Step 3: Analyze from the end for final validation
    for (int index = size - 1; index >= 0; index--) {
        currentMaxLength = max(target[index], currentMaxLength); // Update with the current value
        // Check if we exceed allowable segment length
        if (currentMaxLength > size - index)
            exceedCount++;
        currentMaxLength = max(currentMaxLength, index + 1); // Ensure current max captures index increment
    }

    // Debugging instrument: Output exceed count from the second half
    cout << "Exceed count (second half): " << exceedCount << endl;

    // Final condition check
    if (exceedCount > (size + 1) / 2)
        return false;

    // Overall check passed
    return true;
}

