long long exp(long long a, long long n, const long long mod) {
    long long ans = 1;
    while (n > 0) {
        if (n % 2) {
            ans = (ans * a) % mod;
        }
        a = (a * a) % mod;
        n /= 2;
    }
    return ans;
}

