bool isEveryKSubstrContainedInS(const std::string& s, int k) {
    // TODO: Investigate edge cases where k > length of s
    if (k > s.length()) {
        return false; // too long to contain
    }

    // TODO: Consider if we should handle single character cases differently
    if (k == 1) {
        std::unordered_set<char> uniqueChars(s.begin(), s.end());
        return uniqueChars.size() == 2; // both '0' and '1' must be present
    }

    // For k >= 2, we need to check substrings
    for (size_t i = 0; i <= s.length() - k; ++i) {
        std::string substr = s.substr(i, k);
        // Output the current substring for debugging
        std::cout << "Checking substring: " << substr << std::endl;

        // Check if substr is either "00...0" or "11...1"
        std::string neededZeroes = '0' + std::string(k - 1, '0');
        std::string neededOnes = '1' + std::string(k - 1, '1');

        if (substr != neededZeroes && substr != neededOnes) {
            std::cout << "Failed for substring: " << substr << std::endl; // Debug print
            return false;
        }
    }

    return true; // All conditions satisfied
}

