    int operationCount = 0; // Tracks the number of operations performed

    for (const auto& log : logs) {
        // Debug print to trace log entries
        cout << "Processing log: " << log << endl;

        if (log == "./") {
            // Staying in the same directory, no changes to operation count
            cout << "Current operation count: " << operationCount << " (No change for './')" << endl;
        } 
        else if (log == "../") {
            // Attempting to go up one directory level
            if (operationCount > 0) {
                operationCount--; // Valid operation - moving up
                cout << "Going up one directory, new operation count: " << operationCount << endl;
            } else {
                cout << "Cannot go up, already at root level." << endl;
            }
