#include <iostream>
#include <vector>
#include <unordered_set>
#include <string>

class SafeCracker {
public:
    std::string crackSafe(int n, int k) {
        std::string h = std::string(n - 1, '0');
        std::vector<std::string> res;
        std::vector<std::vector<int>> g(k * k, std::vector<int>());

        // Prepare the graph representation
        setupGraph(g, k);

        std::unordered_set<std::string> visited;
        visited.insert(h);

        // Start DFS
        dfs(h, g, visited, res, n);

        // Result
        std::string result = joinResult(res);
        return result;
    }

private:
    void dfs(const std::string& node, const std::vector<std::vector<int>>& g, 
             std::unordered_set<std::string>& visited, 
             std::vector<std::string>& res, int n) {
        if (res.size() == n) {
            std::cout << "Found a valid combination: " << node << std::endl; // Debug
            res.push_back(node);
            return;
        }
        for (int v : g[std::stoi(node)]) {
            std::string nextNode = node + std::to_string(v % 10);  // Add last digit
            if (visited.find(nextNode) == visited.end()) {
                visited.insert(nextNode);
                dfs(nextNode, g, visited, res, n);
                visited.erase(nextNode);  // Backtrack
            }
        }
    }

    void setupGraph(std::vector<std::vector<int>>& g, int k) {
        for (int i = 0; i < k; ++i) {
            for (int j = 0; j < k; ++j) {
                for (int x = 0; x < k; ++x) {
                    if (x != j) {
                        g[i * k + j].push_back(i * k + x);
                    }
                }
            }
        }
    }

    std::string joinResult(const std::vector<std::string>& res) {
        std::string finalResult;
        for (const auto& str : res) {
            finalResult += str;
        }
        return finalResult;
    }
};

int main() {
    SafeCracker sc;
    int n = 3; // Number of digits
    int k = 2; // Base
    std::cout << "Cracked safe combination: " << sc.crackSafe(n, k) << std::endl;
    return 0;
}

