            cin >> a[i];
        for (int i = 0; i < n; ++i)
            cin >> b[i];

        // Create position array
        vector<int> pos_array, elem;
        for (int i = 0; i < n; ++i) {
            auto it = find(a.begin(), a.end(), b[i]);
            if (it != a.end()) {
                pos_array.push_back(distance(a.begin(), it)); // Capture position
            } else {
                pos_array.push_back(-1); // Handle not found
            }
            elem.push_back(b[i]);
        }

        // Initialize sadness calculation
        int sadness = 0;
        for (int i = 0; i < n; ++i) {
            if (elem[i] == i + 1) {
                sadness += n - pos_array[i] - 1;
            } else {
                sadness += b.size() - pos_array[i] - 1;
            }
        }

        // Debug print the initial sadness
        cout << "Initial sadness: " << sadness << endl;

        int max_sadness = sadness;
        for (int i = n - 1; i >= 0; --i) {
            sadness -= n - elem[i] - 1;
            sadness += b.size() - pos_array[i] - 1;

            // Update max sadness
            max_sadness = max(max_sadness, sadness);
            // Debug print current sadness
            cout << "Current sadness at i=" << i << ": " << sadness << endl;
        }

        // Output results
        cout << (max_sadness == sadness ? "AC" : "WA") << '\n';
        // Additional debug print for verification
        cout << "Max sadness: " << max_sadness << ", Final sadness: " << sadness << endl;
    }

    return 0;
}

class Solution {
public:
