        // Step 1: Initialize the result string with 'a's
        string res(n, 'a');
        k -= n; // Adjust k for the contribution of 'a's
        int i = n - 1; // Start filling from the end 

        // Step 2: while there's remaining value to distribute
        while (k > 0) {
            // Calculating how much to increment
            int add = min(k, 25);
            // Debug print: Current index and value to add
            cout << "Distributing: position " << i << ", adding " << add << endl;

            res[i--] = 'a' + add; // Update the character in the result
            k -= add; // Reduce k accordingly

            // Debug print: Remaining value of k
            cout << "Remaining k: " << k << endl;
        }

        // Final result debug print
        cout << "Final result string: " << res << endl;

        return res; // Return the constructed string
    }
};

