    int sum = 0;

    // TODO: Instrumentation to monitor the frequency of numbers
    std::cout << "Counting occurrences of each number...\n";
    for (int num : nums) {
        ++count[num]; // Increment the counter for the number
    }

    // TODO: Investigate the structures of counted numbers
    std::cout << "Number occurrences:\n";
    for (const auto& pair : count) {
        std::cout << "Number: " << pair.first << ", Count: " << pair.second << std::endl;
    }

    // Calculate the sum of unique elements (whose count is 1)
    std::cout << "Calculating the sum of unique elements...\n";
    for (const auto& pair : count) {
        if (pair.second == 1) {
            sum += pair.first; // Add to sum if only one occurrence
            std::cout << "Adding unique number: " << pair.first << " to sum.\n";
        } else {
            std::cout << "Skipping number: " << pair.first << " (count: " << pair.second << ")\n";
