int main() {
    // Input variables representing number of watches, their timings, and start/end positions
    int numWatches, totalWatches, startPos, finalPos;
    cin >> numWatches >> totalWatches >> startPos >> finalPos;

    // Vector to hold watch information
    vector<Watch> watches(totalWatches);
    for (int i = 0; i < totalWatches; ++i) {
        cin >> watches[i].time >> watches[i].left >> watches[i].right;
    }

    // Initialize state variables
    int currentPos = startPos;
    int timeStep = 1;
    int watchIndex = 0;
    vector<char> movementActions;

    // Start processing movements until final position is reached
    while (currentPos != finalPos) {
        // Check for any watches' triggering time at the current time step
        if (watchIndex < totalWatches && watches[watchIndex].time == timeStep) {
            cout << "Debug: Moment: " << timeStep << ", Current Position: " << currentPos << endl; // Debug

            // Check if current position is within any watch's left and right bounds
            if (currentPos > watches[watchIndex].left - 1 && currentPos < watches[watchIndex].right + 1) {
                movementActions.push_back('X'); // Marked position as 'X' due to watch detection
            } else {
                // Adjust position towards final position
                if (currentPos < finalPos) {
                    currentPos++;
                    movementActions.push_back('R'); // Move right
                } else {
                    currentPos--;
                    movementActions.push_back('L'); // Move left
                }
            }
            watchIndex++; // Move to the next watch
        } else {
            // Move towards final position without watch interference
            if (currentPos < finalPos) {
                currentPos++;
                movementActions.push_back('R'); // Move right
            } else {
                currentPos--;
                movementActions.push_back('L'); // Move left
            }
        }
        timeStep++; // Increment time step
    }

    // Output all movement actions executed
    printActions(movementActions);

    return 0;
}

