    for (size_t i = 0; i < timePoints.size(); ++i) {
        std::string time = timePoints[i];
        time.erase(remove(time.begin(), time.end(), ':'), time.end()); // Removing ':'
        arr[i] = std::stoi(time);

        // Debug output to examine conversion
        std::cout << "Converted MIN:" << i << " " << timePoints[i] << " -> " << arr[i] << std::endl;
