    // Step 2: Sort the integer time points
    std::sort(arr.begin(), arr.end());

    // Step 3: Calculate the minimum time difference
    int ans = arr[1] - arr[0]; // Initialize with first difference
    for (size_t i = 0; i < arr.size() - 1; ++i) {
        ans = std::min(ans, arr[i + 1] - arr[i]);

        // Debug output to see current differences
        std::cout << "Current ANS:" << i << " Diff between " << arr[i + 1] << " and " << arr[i] << std::endl;
