using namespace std;

// Function to explore the grid and determine the time taken to reach all cells
long long exploreGrid(const vector<vector<int>>& grid) {
    int m = grid[0].size();  // Get the number of columns
    long long time = 0;  // Initialize the elapsed time to 0
    vector<vector<bool>> visited(2, vector<bool>(m, false));  // Track visited cells
    visited[0][0] = true;  // Start at the top-left corner
    int row = 0, col = 0;  // Current position

    while (true) {
        // Debug prints to trace current position and time
        cout << "Current Position: (" << row << ", " << col << "), Time: " << time << endl;

        // Move right if possible
        if (col + 1 < m && grid[row][col + 1] <= time && !visited[row][col + 1]) {
            visited[row][col + 1] = true;  // Mark as visited
            col++;  // Move right
        }
        // Move down if possible
        else if (row + 1 < 2 && grid[row + 1][col] <= time && !visited[row + 1][col]) {
            visited[row + 1][col] = true;  // Mark as visited
            row++;  // Move down
        }
        // Move left if possible
        else if (col - 1 >= 0 && grid[row][col - 1] <= time && !visited[row][col - 1]) {
            visited[row][col - 1] = true;  // Mark as visited
            col--;  // Move left
        }
        // Move up if possible
        else if (row - 1 >= 0 && grid[row - 1][col] <= time && !visited[row - 1][col]) {
            visited[row - 1][col] = true;  // Mark as visited
            row--;  // Move up
        } else {
            // No valid moves; calculate next available time
            int nextTime = 1e9 + 1;  // Initialize to a large number
            if (col + 1 < m && !visited[row][col + 1]) {
                nextTime = min(nextTime, (long long)grid[row][col + 1]);  // Consider right cell
            }
            if (row + 1 < 2 && !visited[row + 1][col]) {
                nextTime = min(nextTime, (long long)grid[row + 1][col]);  // Consider down cell
            }
            if (col - 1 >= 0 && !visited[row][col - 1]) {
                nextTime = min(nextTime, (long long)grid[row][col - 1]);  // Consider left cell
            }
            if (row - 1 >= 0 && !visited[row - 1][col]) {
                nextTime = min(nextTime, (long long)grid[row - 1][col]);  // Consider up cell
            }
            // Debug print for next time
            cout << "Next Time to Unlock: " << nextTime << endl;

            // If no more valid moves, break the loop or wait until next unlock
            if (nextTime > 1e9) break;  // Exit condition
            time = nextTime;  // Update time to the next unlock time
        }
    }
    return time;  // Return the time taken
}

