class TreeNode {
public:
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

std::vector<std::string> result;

std::string shortestTraversal(TreeNode* node, int prev) {
    if (!node) {
        return "";
    }

    result.push_back(std::to_string(node->val));

    if (node->val == 1) {  // Assuming destValue is 1 for initial testing
        if (result.size() > 1) {
            for (size_t i = 2; i < result.size(); ++i) {
                if (result[i] != result[i - 1]) {
                    if (result[i - 1] == result[i - 2]) {
                        result.pop_back();
                        result.push_back("U");
                    } else {
                        result.pop_back();
                        result.push_back("R");
                    }
                } else {
                    result.pop_back();
                }
            }
        }
        return std::string(result.begin(), result.end());
    } 
    else if (prev < node->val) {
        return shortestTraversal(node->left, node->val).empty() ?
               shortestTraversal(node->right, node->val) : 
               shortestTraversal(node->left, node->val);
    } 
    else {
        return shortestTraversal(node->right, node->val).empty() ?
               shortestTraversal(node->left, node->val) : 
               shortestTraversal(node->right, node->val);
    }
}

void performTests() {
    TreeNode* root1 = new TreeNode(5);
    root1->left = new TreeNode(1);
    root1->right = new TreeNode(2);
    root1->left->left = new TreeNode(3);
    root1->right->left = new TreeNode(4);
    root1->right->right = new TreeNode(6);

    // Debug print for initial test
    std::string result1 = shortestTraversal(root1, 1);
    std::cout << "Test 1 Result: " << (result1 == "URL") << " (Expected: URL, Got: " << result1 << ")\n";

    TreeNode* root2 = new TreeNode(2);
    root2->left = new TreeNode(1);

    // Debug print for second test
    std::string result2 = shortestTraversal(root2, 1);
    std::cout << "Test 2 Result: " << (result2 == "L") << " (Expected: L, Got: " << result2 << ")\n";

    // Cleanup
    delete root1->left->left;
    delete root1->left;
    delete root1->right->left;
    delete root1->right->right;
    delete root1->right;
    delete root1;

    delete root2->left;
    delete root2;
}

