std::vector<std::vector<int>> highFive(std::vector<std::vector<int>>& items) {
    // Step 1: Initialize a map to store top scores
    std::unordered_map<int, std::priority_queue<int, std::vector<int>, std::greater<int>>> scores;

    // Step 2: Populate the map with scores
    for (const auto& item : items) {
        scores[item[0]].push(item[1]);
        // Maintain only top 5 scores using a min-heap
        if (scores[item[0]].size() > 5) {
            scores[item[0]].pop();
        }
    }

    // Step 3: Process the scores to compute average of top 5 scores
    std::vector<std::vector<int>> result;
    for (auto& [id, pq] : scores) {
        int sum = 0;
        int count = 0; // Counter for top scores
        while (!pq.empty()) {
            sum += pq.top();
            pq.pop();
            count++;
        }

        // Debug: Print sum and count for each user ID
        std::cout << "ID: " << id << ", Total Sum: " << sum << ", Count: " << count << std::endl;

        // Record the average of top 5 scores
        if (count > 0) {
            result.push_back({id, sum / count});
        } else {
            // TODO: Handle case where count is 0 (no scores)
            result.push_back({id, 0});
        }
    }

    // Step 4: Sort the results for final output
    // Debug: Print unsorted results for clarity
    std::cout << "Unsorted Results: ";
    for (const auto& entry : result) {
        std::cout << "[" << entry[0] << ", " << entry[1] << "] ";
    }
    std::cout << std::endl;

    std::sort(result.begin(), result.end());

    // Step 5: Debug: Print sorted results
    std::cout << "Sorted Results: ";
    for (const auto& entry : result) {
        std::cout << "[" << entry[0] << ", " << entry[1] << "] ";
    }
    std::cout << std::endl;

    return result;
}

