    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

class Test1229M {
public:
    // Compute the height of a binary tree
    int computeHeight(TreeNode* root) {
        if (root == nullptr) return 0;
        // TODO: Consider debugging output for tree structure
        return std::max(computeHeight(root->left), computeHeight(root->right)) + 1;
    }

    // Remove a node by value and return the height of the resulting tree
    int removeByValue(TreeNode* root, int val) {
        if (root == nullptr) return 0; // Base case: node is null
        if (root->val == val) {
            // TODO: Log removal of node with value
            return computeHeight(root->left) + computeHeight(root->right);
        }

        root->left = removeByValue(root->left, val);
        root->right = removeByValue(root->right, val);

        return computeHeight(root);
    }

    // Process the queries against the tree
    std::vector<int> processTreeQueries(TreeNode* root, std::vector<int>& queries) {
        std::vector<int> results;
        for (const int& query : queries) {
            // Record the height after removing the value
            int heightAfterRemoval = removeByValue(root, query);
            results.push_back(heightAfterRemoval);
            // DEBUG: Output the height after removal for current query
            // std::cout << "Height after removing " << query << ": " << heightAfterRemoval << std::endl;
        }
        return results;
    }
};

