int MergeSort(vector<int> &arr) {
    int n = arr.size();
    if (n <= 1) return 0;

    vector<int> left(arr.begin(), arr.begin() + n / 2);
    vector<int> right(arr.begin() + n / 2, arr.end());

    // TODO: Instrumentation - check sizes of left and right
    cout << "Left size: " << left.size() << ", Right size: " << right.size() << endl;

    return MergeSort(left) + MergeSort(right) + calc(left, right, arr.begin());
}

int calc(vector<int> left, vector<int> right, int out[]) {
    int nl = left.size();
    int nr = right.size();
    int count = 0;

    // TODO: Debug prints for merging procedure
    cout << "Merging arrays...\n";

    for (int i = 0, j = 0; i < nl || j < nr;) {
        if (i >= nl) {
            for (; j < nr; j++) {
                out[count++] = right[j];
            }
            return count;
        }

        if (j >= nr) {
            for (; i < nl; i++) {
                out[count++] = left[i];
            }
            return count;
        }

        if (left[i] < right[j]) {
            out[count++] = left[i++];
        } else {
            out[count++] = right[j++];
        }
    }

    return count;
}

