class ResearchPrototype {
public:
    // Task: Investigate if a number has exactly three divisors
    bool hasExactlyThreeDivisors(int n) {
        int divisorCount = 0;

        for (int i = 2; divisorCount < 3 && i * i <= n; i++) {
            // Count the number of divisors
            if (n % i == 0) {
                divisorCount++;
                divisorCount += (n / i == i); // Check for perfect square
            }
        }

        // Debugging output for tracking divisor count
        std::cout << "Number: " << n << ", Divisor Count: " << divisorCount << std::endl;
        return divisorCount == 3;
    }

    void conductExperiment() {
        // Testing numbers for exactly three divisors
        std::vector<int> testNumbers = {4, 9, 15, 16, 25, 27};

        for (int number : testNumbers) {
            bool result = hasExactlyThreeDivisors(number);
            std::cout << "Does " << number << " have exactly three divisors? " << (result ? "Yes" : "No") << std::endl;
        }
    }
};

int main() {
    ResearchPrototype experiment;
    experiment.conductExperiment();
    return 0;
}

