// Function to estimate the number of flips needed to sort the deck
int computeFlips(int numCards, const vector<vector<int>>& deck) {
    // Initialize vectors to record front and back values
    vector<int> frontValues(numCards), backValues(numCards);
    vector<bool> encountered(2 * numCards, false);

    // Populate front and back arrays, also track seen values
    for (int idx = 0; idx < numCards; ++idx) {
        frontValues[idx] = deck[idx][0];
        backValues[idx] = deck[idx][1];
    }

    // Validate all front-back combos are present
    for (int idx = 0; idx < numCards; ++idx) {
        if (encountered[frontValues[idx]] && !encountered[backValues[idx]]) 
            return -1; // Unmatched pair found
        encountered[frontValues[idx]] = true;
        encountered[backValues[idx]] = true;
    }

    // Investigate potential max min-max pair advantages
    int optimalPairs = 0;
    for (int start = 0; start < numCards; ++start) {
        int minFrontValue = INT_MAX, minBackValue = INT_MAX;
        for (int end = start; end < numCards; ++end) {
            minFrontValue = min(minFrontValue, frontValues[end]);
            minBackValue = min(minBackValue, backValues[end]);
            optimalPairs = max(optimalPairs, minFrontValue + (numCards - end - 1) * (numCards - 1) - minBackValue);
        }
    }

    return optimalPairs - numCards; // Adjust for total count
}

// Entry point for execution
int main() {
    int numCards;
    cin >> numCards;

    // Create a matrix to hold card values
    vector<vector<int>> cardDeck(numCards);
