public:
    // Function to validate parentheses
    bool isValid(string s) {
        stack<char> st; // Stack to track opened parentheses
        for (char ch : s) {
            // TODO: Log current character
            if (ch == '(') {
                st.push('(');  // Open parenthesis found, push to stack
            }
            else {
                // Debug print: checking if stack is empty
                if (st.empty()) return false; // If no matching opening, return false
                st.pop(); // Closing parenthesis found, pop from stack
            }
        }
        // Final state debug: stack should be empty if valid
        return st.empty(); // Check if all opened parentheses are closed
    }

    // Function to validate path in a grid
    bool isValidPath(vector<vector<char>>& grid) {
        int m = grid.size(), n = grid[0].size(); // Grid dimensions
        vector<vector<bool>> visited(m, vector<bool>(n, false)); // Matrix for visited cells
        queue<pair<int, int>> q; // Queue for BFS
        q.push(make_pair(0, 0)); // Start from top-left corner
        visited[0][0] = true; // Mark starting cell as visited
        // TODO: Experiment with different starting points

        while (!q.empty()) {
            pair<int, int> u = q.front(); // Current position
            q.pop();
            // Debug print: current position
            if (u.first == m - 1 && u.second == n - 1) {
                // End point found, validate parentheses
                if (isValid(grid[u.first][u.second])) return true; // Return true if valid
            }
            // Check the right and down cells for valid path
            if (u.first + 1 < m && !visited[u.first + 1][u.second] && grid[u.first + 1][u.second] == '(') {
                q.push(make_pair(u.first + 1, u.second)); // Move down
                visited[u.first + 1][u.second] = true; // Mark visited
                // TODO: Log movement to down position
            }
            if (u.second + 1 < n && !visited[u.first][u.second + 1] && grid[u.first][u.second + 1] == '(') {
                q.push(make_pair(u.first, u.second + 1)); // Move right
                visited[u.first][u.second + 1] = true; // Mark visited
                // TODO: Log movement to right position
            }
        }
        return false; // No valid path found
    }
};

