// Prototype function to compute the k-th number not divisible by n
long long kthNotDivisibleByN(long long n, long long k) {
    // Calculate the largest multiple of n less than or equal to k
    long long nthMultipleOfN = (k / (n - 1)) * n; 
    // Find the count of numbers divisible by n up to k
    long long countOfDivisibleByN = k - (k / (n - 1));
    // The k-th number not divisible by n is adjusted by the count of divisible numbers
    long long kthNotDivisible = nthMultipleOfN - countOfDivisibleByN;
    return kthNotDivisible;
}

