// Function to compute minimum changes to achieve zero XOR in segments
int minChangesToZeroXOR(std::vector<int>& nums, int k) {
    int n = nums.size();
    int changes = 0;
    std::cout << "Starting minChangesToZeroXOR with n: " << n << ", k: " << k << std::endl;

    // Iterate through the vector in segments of size k
    for (int i = 0; i < n; i += k) {
        if (i + k > n) {
            std::cout << "Breaking: Segment exceeds array bounds at index: " << i << std::endl;
            break; 
        }

        int segmentXOR = 0; 
        std::cout << "Calculating XOR for segment starting at index: " << i << std::endl;

        // Calculate XOR for the current segment
        for (int j = i; j < i + k; ++j) {
            segmentXOR ^= nums[j];
            std::cout << "nums[" << j << "] = " << nums[j] << ", segmentXOR = " << segmentXOR << std::endl;
        }

        // Check if the current segment needs changes
        if (segmentXOR != 0) {
            std::cout << "Segment XOR: " << segmentXOR << " - Applying changes." << std::endl;
