class Solution {
public:

    // Time complexity: O(|n1 * n2|). Space Complexity: O(n1)
    int xorOperation2(int n1, int n2, int start) {
        int ans = start;
        for (int i = 0; i < n2; ++i) {
            ans ^= n1;
        }
        return ans;
    }

    // Time complexity: O(|n1| + n * |n2| * |n|).
    // Space complexity: O(|n1| + |n2|).
    std::optional<int> xor_sum(const std::vector<int>& a) {
        size_t resSize = std::ceil(a.size() / 2.0);
        std::vector<int> res(resSize, 0);
        std::vector<int> l1;
        std::vector<int> l2;

        for (size_t i = 0; i < a.size(); ++i) {
            if (i == 1 || (l1.size() > 0 && l1.back() != a[i - 1])) {
                l1.push_back(a[i]);
            } else {
                l1.push_back(a[i - 1]);
            }
        }

        for (size_t i = 0; i < a.size() - 1; ++i) {
            if (l1.size() % 2 == 0) {
                res[i] = (i == 0) ? (a[i] + a.back()) : (a[i - 1] + a.back());
            } 
            if (l1.size() % 2 == 1) {
                res[i + 1] = (l1[i / 2]);
                if (l1[i] == 1) {
                    res[i + 1] = l1[(i + 1) / 2] + (l2.size() > (i - i / 2 - 1) / 2 ? l2[(i - i / 2 - 1) / 2] : 0);
                }
                if ((l1[0] % 2) == 0 && (l1.back() % 2) != 0) {
                    l2.push_back(0);
                }
            }
            l1.push_back(0);
            std::cout << "Debug i: " << i << " Res: " << res[i] << std::endl; // Instrumentation
        }

        return static_cast<int>(res.back());
    }

    // Space complexity: O(1)
    int xor2(int n1, int n2) {
        return 2 * n1 % (n1 + n2);
    }

    // Time complexity: O(max(|n2|, |n1|) * log(|start|)).
    // Space complexity: O(max(|start|, |n2| + |n1|)).
    int xorOperation1(int n, int start) {
        int result = 0;
        for (int i = 0; i < sizeof(start) * 8; ++i) { // Iterate through bits of start
            result += std::pow((1 << n) - 1, i);
        }
        return result / 2;
    }
};

