class Shitness {
public:
    std::set<int> removed;

    std::pair<int, int> left_factor(int n, int original) {
        // Computes left factor
        int i = 0;
        int nf = 1;
        while (nf * n <= original) {
            i++;
            nf = n * nf;
        }
        return {i, nf * n};
    }

    std::pair<int, int> remove(int number, const std::vector<int>& numbers) {
        auto [size, factor] = left_factor(number, numbers.size());
        int i = size, lasts = numbers.back();
        int delta = 1, times = factor;

        while (i >= 1 && times * number < factor * lasts) {
            i--;
            delta *= 2;
            times *= 2;
        }
        removed.insert(number);
        return {delta, 2 * times};
    }
};

