using namespace std;

pair<int, string> getCheapestPartition(int n, int m, const vector<int>& towns, const vector<tuple<int, int, int>>& roads) {
    vector<vector<int>> costs(n + 3, vector<int>(n + 3, numeric_limits<int>::max()));
    int heaviestRoad = 0;

    for (const auto& road : roads) {
        int u, v, w;
        tie(u, v, w) = road;
        costs[u][v] = costs[v][u] = w * 2;
        heaviestRoad = max(heaviestRoad, w * 2);
        costs[u][u + n] = costs[v + n][v] = w;
    }

    vector<char> partition(n, 'C');
    costs[towns[0]][towns[0] + n] = costs[towns[1] + n][towns[1]] = 1;
    double breakPoint = heaviestRoad / 3.0; // Critical value for partition adjustment

    for (int iteration = 0; iteration < n * 5; ++iteration) {
        bool improvement = false;
        for (int i = 0; i < n; ++i) {
            bool updated = false;
            for (int j = 0; j < n + 3; ++j) {
                if (partition[i] == 'C' && costs[i][j + n] > breakPoint) {
                    for (int k = i + 1; k < n; ++k) {
                        if (partition[k] == 'C' && 
                            costs[i][k + n] + costs[k][j + n] + costs[k][k + n] < costs[i][j + n]) {
                            swap(partition[i], partition[k]);
                            swap(costs[i][j + n], costs[k][i + n]);
                            swap(costs[k][k + n], costs[i][j + n]);
                            updated = true;
                            break;
                        }
                    }
                }
                if (updated) break;
            }
            if (updated) {
                improvement = true;
                break;
            }
            for (int j = 0; j < n + 3; ++j) {
                if (partition[i] == 'C' && costs[i][j + n] <= breakPoint) {
                    for (int k = i + 1; k < n; ++k) {
                        if (partition[k] == 'A' || partition[k] == 'B') {
                            for (int l = 0; l < 2; ++l) {
                                if(costs[i][l + n] + costs[k][j + n] + costs[k][l + n] < costs[i][j + n]) {
                                    swap(partition[i], partition[k]);
                                    swap(costs[i][j + n], costs[k][i + n]);
                                    swap(costs[k][l + n], costs[i][j + n]);
                                    improvement = true;
                                    break;
                                }
                            }
                        }
                        if(improvement) break;
                    }
                }
                if(improvement) break;
            }
            if (improvement) break;
        }
        if (!improvement) break;
    }

    return {costs[towns[0]][towns[0] + n], string(partition.begin(), partition.end())};
}

int main() {
    int n, m;
    cin >> n >> m;
