#include <iostream>
#include <vector>
#include <string>
#include <cmath>

std::vector<std::string> longest_subsequence(int n, std::vector<std::string>& words, std::vector<int>& groups) {
    std::vector<std::string> result;  // Initialize the result list
    int current_index = 0;            // Initialize the current index

    while (current_index < n) {
        result.push_back(words[current_index]); // Add the current word to the result list

        int next_index = current_index + 1; // Find the next index
        bool found_next = false; // Flag to check if a valid next index is found

        while (next_index < n) {
            // Check if the groups are unequal and the Hamming distance is 1
            if (groups[current_index] != groups[next_index] && hamming_distance(words[current_index], words[next_index]) == 1) {
                current_index = next_index; // Update the current index
                found_next = true; // Set flag to true if a valid next index is found
                break;
            }
            next_index++; // Increment the next index
        }

        if (!found_next) { // If no valid next index is found, break the loop
            break; 
        }
    }

    return result; // Return the resulting subsequence
}

int hamming_distance(const std::string& s1, const std::string& s2) {
    int distance = 0; // Initialize the Hamming distance
    for (int i = 0; i < std::min(s1.size(), s2.size()); ++i) {
        if (s1[i] != s2[i]) {
            distance++; // Increment distance for differing characters
        }
    }
    distance += std::abs(static_cast<int>(s1.size()) - static_cast<int>(s2.size())); // Include length difference
    return distance; // Return calculated Hamming distance
}

