struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

class Solution {
public:
    // Main function to reorder a linked list
    void reorderList(ListNode* head) {
        if (!head || !head->next) return; // Early exit for empty or single-node lists

        vector<ListNode*> nodeVector; // Vector to store nodes
        ListNode *cur = head;
        while (cur) { // Traverse the linked list to populate nodeVector
            nodeVector.push_back(cur);
            cur = cur->next;
        }

        // Initial pointers for reordering
        ListNode *first = head;
        ListNode *second = nodeVector.back(); // Start from the last node
        size_t n = nodeVector.size(); // Store size for iteration

        for (size_t i = 0; i < n / 2; ++i) {
            ListNode* temp1 = first->next; // Save the next node of first
            ListNode* temp2 = second->next; // Save the next node of second

            first->next = second; // Point first to second
            second->next = temp1; // Link second back to the next of first

            first = temp1; // Move first to the next node
            second = temp2; // Move second to its next

            // Debug print to monitor progress
            // cout << "Reordering: " << first->val << ", " << (second ? second->val : -1) << endl;
        }

        // Handle the case for even or odd number of nodes
        if (n % 2 == 0) 
            second->next = nullptr;
        else 
            first->next = nullptr;
    }

    // Debug function to print the linked list
    void printList(ListNode* head) {
        while (head) {
            cout << head->val << " -> ";
            head = head->next;
        }
        cout << "null" << endl;
    }
};

