class Solution {
public:
    double maxAverageRatio(vector<vector<int>>& classes, int extraStudents) {
        priority_queue<pair<double, int>> pq;

        // Initialize the priority queue with average ratios of each class
        for (int i = 0; i < classes.size(); i++) {
            double avg = static_cast<double>(classes[i][0]) / classes[i][1];
            pq.push({avg, i});
        }

        // Iterate through the number of extra students to distribute
        for (int i = 1; i <= extraStudents; i++) {
            // Retrieve the class with the highest average ratio
            double entry = pq.top().first;
            int index = pq.top().second;
            pq.pop();

            double n_classes = 0;
            double n_passes = 0;

            // Debug print to monitor the current class and its average
            cout << "Distributing extra student to class index: " << index << " with initial avg: " << entry << endl;

            // Increment the number of passes as long as we can
            for (int j = 1; j <= classes[index][1]; j++) {
                if (classes[index][0] + 1 <= classes[index][1]) {
                    classes[index][0]++;
                    n_classes += 1.0;
                    n_passes += 1.0;

                    // Debug print to show the new count of passes
                    cout << "New passes for class " << index << ": " << classes[index][0] << endl;
                } else {
                    break;
                }
            }

            double old = entry;
            entry = static_cast<double>(classes[index][0] + n_passes) / (classes[index][1] + n_classes);
            pq.push({entry, index});

            // Check if the new entry is better and if so, return immediately
            if (old < entry) {
                cout << "Improved avg for class " << index << ": " << entry << endl;
                return entry;
            }

            // Special handling for cases less than current number of students
            if (static_cast<size_t>(pq.size()) < i) {
                const pair<double, int>& top = pq.top();
                double top_entry = top.first;
                int top_index = top.second;

                entry = static_cast<double>(static_cast<int>(top_entry * 1e10 + 0.5)) / 1e10;
                double result = max(static_cast<double>(classes[top_index][0]) / classes[top_index][1], entry);

                cout << "Early-returning max avg: " << result << endl;
                return result;
            }
        }

        // Aggregate the maximum average after all extra students have been distributed
        double max_average = 0;
        while (!pq.empty()) {
            pair<double, int> top = pq.top();
            double entry = static_cast<double>(top.first);
            int index = top.second;
            pq.pop();

            // Debug print the entry being summed
            cout << "Summing avg for class index: " << index << " with avg: " << entry << endl;
            max_average += entry;
        }

        // Final average calculation
        return max_average / static_cast<double>(classes.size());
    }
};

