int minModifications(const std::string& s) {
    std::vector<char> chars(s.begin(), s.end());
    int minimum = INT_MAX;

    for (size_t c = 0; c < chars.size(); ++c) {
        for (char i = 'a'; i <= 'z'; ++i) {
            std::vector<char> temp_s = chars; // Create a copy of the original string

            if (temp_s[c] != i) {
                temp_s[c] = i; // Modify the character
                std::string modified_str(temp_s.begin(), temp_s.end());
                int temp = 0;

                // Debug: Print modified string
                std::cout << "Modified String: " << modified_str << std::endl;

                for (size_t j = 0; j < modified_str.size(); ++j) {
                    for (size_t k = j + 1; k <= modified_str.size(); ++k) {
                        if (k - j > temp) {
                            temp = k - j; // Find maximum substring length
                        }
                    }
                }

                // Keep track of the minimum found
                if (temp < minimum) {
                    minimum = temp;
                    // Debug: Log current minimum
                    std::cout << "New Minimum: " << minimum << " (for replacement at index " << c << ")" << std::endl;
                }
            }
        }
    }

    return minimum;
}

