struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

// TODO: Investigate more efficient traversal methods, implement this as a prototype.
int accumulateAndFlatten(TreeNode* node, int& accumulatedSum) {
    // Base case - if the node is null, terminate recursion.
    if(node == nullptr) return 0;

    int currentVal = node->val;

    // Recursive call to right child first to ensure sum includes values from right subtree.
    currentVal += accumulateAndFlatten(node->right, accumulatedSum);

    // Update the current node's value with the accumulated sum.
    node->val = currentVal + accumulatedSum;

    // Update accumulated value for the next left node.
    accumulatedSum += currentVal;

    // Explore the left subtree.
    return currentVal + accumulateAndFlatten(node->left, accumulatedSum);
}

// Debug function to print tree values in pre-order.
void debugPrintTree(TreeNode* node) {
    if (node == nullptr) return;
    std::cout << node->val << " ";
    debugPrintTree(node->left);
    debugPrintTree(node->right);
}

// Prototype to flatten the tree into accumulating sums.
void flattenTree(TreeNode* root) {
    // Check if the tree is empty
    if (root == nullptr) {
        std::cout << "Tree is empty.\n";
        return;
    }

    int accumulatedSum = 0;
    accumulateAndFlatten(root, accumulatedSum);

    // TODO: Testing: Output the modified tree structure
    std::cout << "Tree after flattening: ";
    debugPrintTree(root);
    std::cout << std::endl;
}

