class Solution {
public:
    // Research Objective: To trace the path of a 'ball' through a grid.
    vector<int> findBall(vector<vector<int>>& grid) {
        int numCols = grid[0].size();
        int numRows = grid.size();
        vector<int> results(numCols, -1); // Initializing result vector

        // Experiment: Iterating through each column as a starting point for the ball.
        for (int startCol = 0; startCol < numCols; ++startCol) {
            int currentCol = startCol;
            bool stuck = false; // Flag for when the ball gets stuck

            for (int row = 0; row < numRows; ++row) {
                // Debug Print: Current position of the ball
                cout << "Row: " << row << " Current Column: " << currentCol << endl;

                // Check the direction of the current cell
                if (grid[row][currentCol] == 1) { // Right
                    if (currentCol + 1 < numCols && grid[row][currentCol + 1] == 1) {
                        currentCol++; // Move right
                    } else {
                        stuck = true; // Ball is stuck
                        break;
                    }
                } else { // Left
                    if (currentCol - 1 >= 0 && grid[row][currentCol - 1] == -1) {
                        currentCol--; // Move left
                    } else {
                        stuck = true; // Ball is stuck
                        break;
                    }
                }
            }

            // Store the result if the ball is not stuck
            results[startCol] = stuck ? -1 : currentCol;

            // Debug Print: Result for this starting column
            cout << "Starting Column: " << startCol << " Final Column: " << results[startCol] << endl;
        }

        return results;
    }
};

