using namespace std;

constexpr int MaxN = 2e5 + 5;

int n, msg[MaxN], maxRead[MaxN], pinned[MaxN];
bool used[MaxN];

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    // Step 1: Input reading
    cin >> n;
    for (int i = 1; i <= n; ++i) {
        cin >> msg[i] >> maxRead[i];
    }

    // Step 2: Initialize Expectation and Potential variables
    double expected = 0.0, potential = 0.0;
    int toPin = 0;

    // Step 3: Calculate expected values and determine the best `toPin`
    for (int i = 1; i <= n; ++i) {
        // Debug Output: Current msg and maxRead
        // cout << "Current message: " << msg[i] << ", maxRead: " << maxRead[i] << endl;

        expected += min(maxRead[i], (double)toPin) / (double)maxRead[i];
        potential += toPin;

        if (potential > maxRead[i]) {
            potential = maxRead[i];
            toPin = i;
        }
    }

    // Output the index of the message to pin
    printf("Index to pin: %d\n", toPin);

    // Step 4: Process pinning logic
    pinned[toPin] = 1;
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= maxRead[i]; ++j) {
            if (!used[msg[i] - 1] && (pinned[msg[i] - 1] == 0)) {
                used[msg[i] - 1] = true;
                if (j <= potential)
                    pinned[msg[i] - 1] = 1;
            }
        }
    }

    // Step 5: Output pinned messages
    cout << "Pinned messages: ";
    for (int i = 1; i <= n; ++i) {
        if (pinned[i - 1]) cout << msg[i] << " ";
    }
    cout << endl;

    return 0;
}

