using namespace std;

class Solution {
public:
    // Maintains the count of nodes visited
    int nodeCount = 0; 
    // Holds the cumulative value for computing median
    int cumulativeValue = 0; 

    // Helper function that performs in-order traversal
    void traverse(TreeNode* node) {
        if (node == nullptr) return;

        traverse(node->left); 

        // Logic for median calculation
        if (nodeCount % 2 == 0) { 
            cumulativeValue += node->val; 
        }
        nodeCount++; 

        // Early exit to optimize processing
        if (nodeCount > (nodeCount + 1) / 2) return; 

        traverse(node->right); 
    }

    // Public method to compute the median
    double computeMedian(TreeNode* root) {
        nodeCount = 0; 
        cumulativeValue = 0; 
        traverse(root);

        // Handling even/odd count of nodes for median calculation
        if (nodeCount % 2 == 0) {
            return cumulativeValue * 1.0; 
        }
        return cumulativeValue * 1.0 / 2;  
    }
};

// Experimental class for longest repeating substring
class LongestSubstring {
public:
    // Main function to find longest repeating substring
    int findLongestRepeating(string input) {
        string tempSubstring; 
        string longestSubstring; 

        for (int i = 0; i < input.size(); i++) {
            tempSubstring.clear(); 
            tempSubstring = string(1, input[i]); 
            for (int j = i + 1; j < input.size(); j++) {
                tempSubstring.append(input, j, 1); 

                // Validate if the current substring has repeating elements
                if (isSubstringRepeating(tempSubstring, input)) { 
                    if (tempSubstring.length() > longestSubstring.length()) {
                        longestSubstring = tempSubstring; 
                    }
                } else {
                    break; 
                }
            }
        }

        return longestSubstring.length(); 
    }

    // Function to check if current substring has repeating characters
    bool isSubstringRepeating(string subStr, string original) {
        int firstPtr = 0; 
        int secondPtr = 0; 
        int charIndex = 0; 
        int loopCount = 1; 

        while (loopCount < subStr.size() && charIndex < original.size()) {
            if (subStr[loopCount++] == subStr[firstPtr++]) {
                while (loopCount < subStr.size() && charIndex < original.size()) {
                    firstPtr = loopCount++;
                    secondPtr = charIndex++;
                    if (subStr[firstPtr] != original[secondPtr]) break; 
                }
            } else {
                break; 
            }
        }

        return (loopCount == subStr.size()); 
    }
};

