    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

int helper(TreeNode* root, int max_so_far, int count) {
    if (!root) {
        return count;
    }

    int new_max_so_far = std::max(root->val, max_so_far);
    count += (max_so_far == new_max_so_far) ? 1 : 0;

    // Debug printing for instrumentation
    std::cout << "Visiting Node: " << root->val 
              << ", Current Max: " << max_so_far 
              << ", New Max: " << new_max_so_far 
              << ", Good Count: " << count << std::endl;

    count = helper(root->left, new_max_so_far, count);
    count = helper(root->right, new_max_so_far, count);

    return count;
}

int goodNodes(TreeNode* root) {
    // Initial Conditions
    std::cout << "Starting goodNodes computation..." << std::endl;
    return helper(root, root ? root->val : INT_MIN, 0);
}

