class Solution {
public:
    std::vector<int> maxScoreIndices(std::vector<int>& nums) {
        // Step 1: Initialize necessary variables for scoring.
        int totalOnes = std::accumulate(nums.begin(), nums.end(), 0);
        int totalZeros = 0;
        int maxScore = 0;

        // Step 2: Set up a vector to hold the scores for the divisions.
        std::vector<int> scores(nums.size() + 1, 0); // Include one more for after the last element.

        // Step 3: Calculate scores for each possible division point.
        for (size_t i = 0; i <= nums.size(); ++i) {
            // Calculate score at each division point
            scores[i] = totalZeros + totalOnes;
            if (i < nums.size()) {
                // Update counts based on the current element
                if (nums[i] == 1) {
                    totalOnes--;
                } else {
                    totalZeros++;
                }
            }
        }

        // Step 4: Find the maximum score achieved.
        maxScore = *std::max_element(scores.begin(), scores.end());

        // Step 5: Collect all division points achieving max score.
        std::vector<int> result;
        for (size_t i = 0; i < scores.size(); ++i) {
            // Debugging output - can be removed or commented out later
            std::cout << "Score at index " << i << ": " << scores[i] << std::endl;
            if (scores[i] == maxScore) {
                result.push_back(i);
            }
        }

        return result;
    }
};

