int largestUniqueNumber(std::vector<int>& nums) {
    // Step 1: Frequency map to track occurrences
    std::unordered_map<int, int> frequencyMap;
    std::vector<int> identifiedUniqueNumbers;

    // TODO: Consider adding debug print to see frequency distribution
    for (int num : nums) {
        frequencyMap[num]++;
    }

    // Debugging print to observe frequency map contents
    std::cout << "Frequency Map: \n";
    for (const auto& pair : frequencyMap) {
        std::cout << "Number: " << pair.first << " Count: " << pair.second << "\n";
    }

    // Step 2: Gather numbers that appear exactly once
    for (int num : nums) {
        if (frequencyMap[num] == 1) {
            identifiedUniqueNumbers.push_back(num);
        }
    }

    // Check if we have any unique numbers
    if (identifiedUniqueNumbers.empty()) {
        std::cout << "No unique numbers found.\n";
        return -1;
    }

    // Step 3: Sort unique numbers in descending order for retrieval
    std::sort(identifiedUniqueNumbers.begin(), identifiedUniqueNumbers.end(), std::greater<int>());

    // TODO: Instrumentation - check the sorted unique numbers
    std::cout << "Sorted Unique Numbers: ";
    for (int uniqNum : identifiedUniqueNumbers) {
        std::cout << uniqNum << " ";
    }
    std::cout << "\n";

    // Return the largest unique number
    return identifiedUniqueNumbers[0];
}

