#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>
using namespace std;

const double EPSILON = 1e-9; // Tolerance for floating-point comparisons

struct Point {
    double x, y; // Coordinates of the point
};

struct Segment {
    Point a, b; // Two endpoints of the segment
};

// Function to compute the Euclidean distance between two points
double computeDistance(Point p1, Point p2) {
    return hypot(p1.x - p2.x, p1.y - p2.y); // Using hypotenuse function for accuracy
}

// Function to calculate the shortest distance from point to segment
double closestDistanceToSegment(Point p, Segment s) {
    double segmentLengthSquared = computeDistance(s.a, s.b);
    if (segmentLengthSquared == 0.0) return computeDistance(p, s.a); // Avoid dividing by zero

    double dotProductAP = (p.x - s.a.x) * (s.b.x - s.a.x) + (p.y - s.a.y) * (s.b.y - s.a.y);
    if (dotProductAP <= 0.0) return computeDistance(p, s.a); // Before segment

    double dotProductBP = (p.x - s.b.x) * (s.a.x - s.b.x) + (p.y - s.b.y) * (s.a.y - s.b.y);
    if (dotProductBP <= 0.0) return computeDistance(p, s.b); // After segment

    double projectionFactor = dotProductAP / segmentLengthSquared; // Projection onto the segment
    double closestX = s.a.x + projectionFactor * (s.b.x - s.a.x);
    double closestY = s.a.y + projectionFactor * (s.b.y - s.a.y);
    return computeDistance(p, {closestX, closestY}); // Distance from point to closest point on segment
}

int main() {
    int numPoints, radius;
    cin >> numPoints >> radius; // Input number of points and radius
    vector<Point> points(numPoints); // Vector to store input points

    // Read points from input
    for (int i = 0; i < numPoints; ++i) {
        cin >> points[i].x >> points[i].y;
    }

    int validSegmentCount = 0; // Count of valid segments
    // Iterate through all pairs of points to form segments
    for (int i = 0; i < numPoints; ++i) {
        for (int j = i + 1; j < numPoints; ++j) {
            Segment s = {points[i], points[j]}; // Create segment from two points
            bool isValid = true; // Flag for current segment validity

            // Check all points against the segment
            for (int k = 0; k < numPoints; ++k) {
                if (closestDistanceToSegment(points[k], s) > radius + EPSILON) {
                    isValid = false; // Point is outside radius
                    break; // No need to check further
                }
            }

            if (isValid) {
                ++validSegmentCount; // Increment count of valid segments
            }
        }
    }

    cout << validSegmentCount << endl; // Output the count of valid segments

    // TODO: Consider implementing more efficient algorithms for larger datasets
    // TODO: Add more debugging information for understanding performance
    // TODO: Explore edge cases and their impact on distance calculations

    return 0; // End of the program
}

