        // Instrumented check for potential overflow scenarios
        if ((1ll << d) > n) {
            cout << ans << endl;
            continue;
        }

        ll rem = n;
        ll bhar = 0;
        bool found = false;

        while (rem) {
            if (d <= bhar) {
                cout << ans << endl;
                found = true;
                break;
            }
            rem -= (1ll << bhar);
            bhar++;
            if (bhar >= 63) {
                break; // Prevent overflow in remaining calculations
            }
        }

        if (!found && !rem) {
            // Adjust answer based on conditions
            ans += (ans < 0) ? -(x - 1) : (x - 1);
            cout << ans << endl;
        }

        // Debug: Track progress through iterations
        cout << "Current answer: " << ans << endl;
        if (ans > 1000000000) {
            cout << "Large computation detected: ans = " << ans << endl;
        }
    }
