struct Node {
    bool exists;
    Node* left;
    Node* right;
    Node(bool e) : exists(e), left(nullptr), right(nullptr) {}
};

class AuthenticationManager {
    Node* root;
    int clock;
    int seq;
    int cur;
    int mn;
    std::map<int, int> totalTokens;

public:
    // Initialization of the authentication manager
    AuthenticationManager(int timeToLive) 
        : root(new Node(false)), clock(1), seq(0), cur(0), mn(timeToLive) {}

    // Generate a new token
    std::string generate(std::string tokenId, int currentTime) {
        clock++;
        cur++;

        if (cur <= mn) {
            root = insert(root, currentTime, tokenId, cur, seq++);
        } else {
            root = renew(root, currentTime, totalTokens[currentTime], currentTime + mn);
        }

        Node* result = preorder(root);
        // Debug assertion to ensure correct state
        assert(result->left != nullptr && !result->left->exists && !result->right->exists);
        return result->tokenId; // Assuming 'tokenId' is part of the Node structure
    }

    // Renew the token with given tokenId
    void renew(std::string tokenId, int currentTime) {
        clock++;
        cur++;
        root = renew(root, currentTime, totalTokens[currentTime], currentTime + mn);
        // Potential debugging print
        std::cout << "Renewed token: " << tokenId << " at time: " << currentTime << "\n";
    }

    // Count unexpired tokens
    int countUnexpiredTokens(int currentTime) {
        return countTokens(root, endTime(currentTime), startTime(currentTime))->num;
    }

    // Start time calculation
    int startTime(int t) const {
        return t + mn - 2 * clock + 1;
    }

    // End time calculation
    int endTime(int t) const {
        return t + mn - clock + 1;
    }

    Node* insert(Node* root, int currentTime, std::string tokenId, int newKey, int seq) {
        assert(newKey > startTime(currentTime));
        if (!root) return new Node(true);

        if (root->val == 0) {
            root->val = newKey;
            root->left = insert(root->left, newKey, tokenId, seq, startTime(currentTime));
            root->right = insert(root->right, newKey, tokenId, seq, startTime(currentTime));
        } else if (newKey < root->val) {
            root->left = insert(root->left, newKey, tokenId, seq, startTime(currentTime));
        } else {
            root->right = insert(root->right, newKey, tokenId, seq, startTime(currentTime));
        }
        return root;
    }

    Node* modifyRoot(Node* root, int key, std::string tokenId, int newKey, int seq) {
        assert(newKey > startTime(key));
        if (root && root->left && root->left->val == key) {
            root->val = newKey;
            root->left = insert(root->left, newKey, tokenId, seq, startTime(key));
            root->right = insert(root->right, newKey, tokenId, seq, startTime(key));
        }
        return root;
    }

    int getTotalTokens(Node* root) const {
        return countTokens(root, endTime(clock), startTime(clock))->num;
    }

    Node* featureSearch(Node* root, int maxValue, int feature, int n) const {
        if (root && root->left) {
            if (root->Lrej == (maxValue + 1)) {
                if (root->num <= n && root->num != 0) {
                    return root;
                }
                return root->right;
            }
        }
        // Additional debugging information can be included here
        // std::cout << root->val << " " << root->Lrej << " rej " << feature << " " << n << "\n";
        return nullptr;
    }
};

int maxDiff(int num) {
    // Convert the input number to string for digit manipulation
    string original = to_string(num);
    // Create mutable copies of the original string
    string maxString = original, minString = original;

    // Initialize variables to track the first encountered significant digits
    char maxDigit = '0', minDigit = '1';

    // Iterate over each character in the string representation
    for (int i = 0; i < original.size(); ++i) {
        // Identify the first digit greater than '0' for max conversion
        if (maxString[i] > '0' && maxDigit == '0') {
            maxDigit = maxString[i];
            // Debug print: Observe which digit is chosen for max conversion
            cout << "Max digit identified: " << maxDigit << " at index " << i << endl;
        }

        // Identify the first digit greater than '1' for min conversion
        if (minString[i] > '1' && minDigit == '1') {
            minDigit = minString[i];
            // Debug print: Observe which digit is chosen for min conversion
            cout << "Min digit identified: " << minDigit << " at index " << i << endl;
        }

        // Replace digits in the max string with '9' where the significant digit was found
        if (maxString[i] == maxDigit) {
            maxString[i] = '9';
            // Debug print: Show the transformation in max string
            cout << "Max string updated at index " << i << ": " << maxString << endl;
        }

        // Replace digits in the min string with '1' where the significant digit was found
        if (minString[i] == minDigit) {
            minString[i] = '1';
            // Debug print: Show the transformation in min string
            cout << "Min string updated at index " << i << ": " << minString << endl;
        }
    }

    // Convert modified strings back to integers to compute the difference
    int maxNum = stoi(maxString);
    int minNum = stoi(minString);

    // Debug prints for final numbers derived
    cout << "Max number formed: " << maxNum << endl;
    cout << "Min number formed: " << minNum << endl;

    // Return the difference
    return maxNum - minNum;
}

