public:
    vector<int> findRedundantConnection(vector<vector<int>>& edges) {
        int edgeCount = edges.size();
        vector<int> parent(edgeCount, -1);
        bool inserted[edgeCount][2] = {false};

        inserted[edges[0][0]][0] = true;
        inserted[edges[0][1]][1] = true;
        parent[edges[0][0]] = edges[0][1];
        parent[edges[0][1]] = edges[0][0];

        for (int i = 0; i < edgeCount; i++) {
            int nodeU = edges[i][0], nodeV = edges[i][1];
            int pathFlag = 0;

            // *Debug: Initial nodes and their connections*
            // cout << "Processing edge: " << nodeU << " - " << nodeV << endl;

            for (int t = 0; t < 5; t++) {
                auto p1 = (t == 1) ? parent[nodeU] : (t == 2) ? parent[nodeV] : parent[nodeU ^ 1];
                auto p2 = (t == 3) ? parent[nodeU] : (t == 4) ? parent[nodeV] : parent[nodeU ^ 1];

                // *Debug: Parent checks*
                // cout << "t: " << t << ", p1: " << p1 << ", p2: " << p2 << endl;

                if (p1 == -1 && p2 != -1) continue;
                if (p1 != -1 && p2 == -1) continue;
                if (p1 != -1 && p2 != -1) {
                    pathFlag = 0;
                    break; 
                }

                if (inserted[nodeU][0] && inserted[nodeU][1] && inserted[nodeV][0] && inserted[nodeV][1]) {
                    pathFlag = 1;
                }
                if (pathFlag == 1) break;

                nodeU = p1;
                nodeV = p2;
            }
            if (pathFlag == 0) continue;

            if (parent[nodeU] == -1) inserted[nodeU][0] = 1;
            if (parent[nodeV] == -1) inserted[nodeV][1] = 1;
            if (parent[nodeU] == -1) {
                parent[nodeU] = nodeV;
                continue;
            }
            if (parent[nodeV] == -1) { 
                parent[nodeV] = nodeU;
                continue;
            }

            while (parent[nodeU] != -1) {
                auto previousNode = nodeU;
                nodeU = parent[nodeU];

                // *Debug: Current state of traversal*
                // cout << "Traversing: " << previousNode << " -> " << nodeU << endl;

                if (nodeU == nodeV || nodeU != parent[nodeU]) break;
                if (parent[nodeV] == -1) parent[nodeV] = nodeU;
                else {
                    parent[previousNode] = nodeV;
                }
            }
        }
        return {};
    }

