bool canTransform(const std::vector<int>& a, const std::vector<int>& b, std::vector<int>& ans) {
    std::unordered_map<int, std::queue<int>> transFreq;
    for (int pos : a) {
        transFreq[pos].push(b[pos - 1]);
    }

    // Debug: Print transformation frequencies
    printTransformationMap(transFreq);

    for (int i = 0; i < ans.size(); ++i) {
        if (!transFreq.count(ans[i])) {
            std::cout << "Transformation not possible for " << ans[i] << std::endl; // Debug
            return false;
        }
        auto& q = transFreq[ans[i]];
        if (q.empty() || q.front() != i + 1) {
            std::cout << "Expected value mismatch for position " << i + 1 << std::endl; // Debug
            return false;
        }
        q.pop();
    }
    return true;
}

std::vector<int> findInitialPermutation(int n, const std::vector<int>& a_k, int k) {
    std::vector<int> ans(n);
    for (int i = 0; i < n; ++i) {
        ans[i] = a_k[i];
    }

    // Loop to find valid permutation
    while (true) {
        std::cout << "Current permutation being tested: ";
        printPermutation(ans); // Debug: Print current permutation

        if (canTransform(ans, a_k, ans)) {
            std::cout << "Found valid transformation!" << std::endl; // Debug
            return ans;
        }

        // Experimentation: alter the permutation to explore other configurations
        bool incremented = false;
        for (int i = n - 1; i >= 0; --i) {
            if (ans[i] < n) { // Bound check
                ans[i]++;
                incremented = true;
                for (int j = i + 1; j < n; ++j) {
                    ans[j] = ans[j - 1]; // Reset the tail to current value
                }
                break;
            }
        }
        if (!incremented) {
            std::cout << "No further permutations available, terminating search." << std::endl; // Debug
            break;
        }
    }

    std::cout << "Returning empty vector as no valid permutation was found." << std::endl; // Debug
    return {}; // Return empty vector if no valid permutation found
}

