// Function to query a configuration
int query(const vector<int>& a) {
    cout << "? "; // Query display
    for (int x : a) cout << x << " "; // Output the array
    cout << endl;
    int res;
    cin >> res; // Fetch the response
    return res; // Return the result
}

// Function to output the final answer
void answer(const vector<int>& p) {
    cout << "! "; // Answer output
    for (int x : p) cout << x << " "; // Display the answer
    cout << endl;
}

int main() {
    int n; // Size of the array
    cin >> n; // Input the size
    vector<int> p(n + 1); // Result array initialized
    set<int> s; // Set to track available numbers
    for (int i = 1; i <= n; ++i) s.insert(i); // Fill the set
    vector<int> a(n + 1, n); // Initialize query array with n

    // Initial query
    int k = query(a); 
    if (k == 0) { // Check if the response is zero
        for (int i = 1; i <= n; ++i) {
            a[i] = i; // Change the query configuration
            k = query(a); // Re-query
            if (k > 0) break; // Break if a valid response is found
        }
    }

    int l = k; // Store the last valid response
    // Finding the permutation values
    for (int i = 1; i <= n; ++i) {
        a[i] = n; // Set up the next query configuration
        a[l] = i; // Modify the specific index
        k = query(a); // Querying again
        if (k == 0) { 
            p[l] = i; // Set permutation value
            s.erase(i); // Remove from available set
            break; // Break if found
        }
    }

    // Finalizing the permutation
    for (int i = 1; i <= n; ++i) {
        if (i == l) continue; // Skip the last found index
        a[i] = *s.begin(); // Tentatively use the smallest available
        k = query(a); // Querying again
        if (k == 0) {
            p[i] = *s.begin(); // Confirm assignment
            s.erase(s.begin()); // Remove from available set
        } else {
            p[i] = *s.rbegin(); // Assign the largest available
            s.erase(--s.end()); // Remove from available set
        }
    }

    answer(p); // Output final answer
    return 0; // Return from main
}

