class Solution {
public:
    int threeSumMulti(vector<int>& arr, int target) {
        if (arr.size() < 3)
            return 0; // Ensure we have at least 3 elements

        const int MOD = 1e9 + 7;
        unordered_map<int, int> count;

        // Counting occurrences of each number
        for (const auto& num : arr) {
            count[num]++;
        }

        int result = 0;

        // Debug: Print the count map
        cout << "Count Map: ";
        for (const auto& pair : count) {
            cout << "(" << pair.first << ": " << pair.second << ") ";
        }
        cout << endl;

        // Iterate through count map in descending order
        for (auto iterox = count.rbegin(); iterox != count.rend(); ++iterox) {
            for (auto iterpy = iterox; iterpy != count.rend(); ++iterpy) {
                if (iterox == iterpy && iterox->second < 2) 
                    continue; // Skip if not enough of the same number

                int remainder = target - (iterox->first + iterpy->first);
                auto iterpz = count.find(remainder);

                // Check if the remainder exists and handle indices carefully
                if (iterpz != count.end()) {
                    if (iterpz == iterox && iterpz == iterpy) {
                        // All three numbers are the same
                        if (iterox->second >= 3) {
                            result += (iterox->second * (iterox->second - 1) * (iterox->second - 2)) / 6; // Combination C(n, 3)
                        }
                    } else if (iterpz == iterox) {
                        // iterox and iterpy are the same, while iterpz is different
                        result += (iterox->second * (iterox->second - 1) / 2) * iterpy->second; // Combination C(n, 2) * m
                    } else if (iterpz == iterpy) {
                        // iterox is different, iterpy and iterpz are the same
                        result += (iterpy->second * (iterpy->second - 1) / 2) * iterox->second; // Combination C(m, 2) * n
                    } else {
                        // All different
                        result += iterox->second * iterpy->second * iterpz->second;
                    }
                }
                result %= MOD; // Handle overflow
            }
        }
        return result;
    }
};

