class Solution {
public:
    int pairSum(ListNode* head) {
        // Step 1: Extract values from linked list into a vector for analysis.
        std::vector<int> values;
        ListNode* current = head;

        // TODO: Consider measuring the time taken for linked list traversal.
        while (current) {
            values.push_back(current->val);
            current = current->next;
        }

        int n = values.size();
        int maxTwinSum = 0;

        // Step 2: Evaluate twin sums between pairs.
        for (int i = 0; i < n / 2; ++i) {
            int twinSum = values[i] + values[n - 1 - i];
            // Debug print: output twin sums for each pair
            std::cout << "Pair: (" << values[i] << ", " << values[n - 1 - i] << ") -> Twin Sum: " << twinSum << std::endl;

            maxTwinSum = std::max(maxTwinSum, twinSum);
            // TODO: Implement an experiment to track how maxTwinSum evolves with varying input sizes.
        }

        // Final result output
        std::cout << "Maximum Twin Sum: " << maxTwinSum << std::endl;
        return maxTwinSum;
    }
};

class Solution {
public:
    int maximumScore(vector<int>& nums) {
        // Research task: Optimize calculation based on prefix sums
        int n = nums.size();
        vector<int> prefixSum(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefixSum[i + 1] = prefixSum[i] + nums[i];
        }

        // DP table initialization
        vector<vector<int>> dp(2 * n, vector<int>(2 * n, 0));
        // Debug info: track operations
        cout << "Initializing DP table and computing values...\n";

        for (int i = 0; i <= n; ++i) {
            for (int j = i; j < i + n; ++j) {
                if (j >= n) continue; // Skip invalid indices

                // Set the diagonal condition
                if (j == i) {
                    dp[j][i + j] = prefixSum[j];
                }

                // Transition, setup max score calculation
                if (i > 0 && j > 0) {
                    dp[i][j] = max(dp[i - 1][j], prefixSum[i] - dp[i - 1][j - 1] - prefixSum[j]);
                }

                // Debug info: show current state
                cout << "dp[" << i << "][" << j << "] = " << dp[i][j] << "\n";
            }
        }

        cout << "Final DP table computed.\n";
        // Return the final score calculation
        return dp[n][n];
    }
};

