std::vector<int> mostVisited(int n, std::vector<int>& rounds) {
    // Step 1: Initialize a vector to track visits to each position
    std::vector<int> visited(n + 1, 0);

    // Step 2: Start counting from the initial round
    int start = rounds[0];
    visited[start]++;
    std::cout << "Initial position: " << start << std::endl;

    // Step 3: Iterate through rounds to track visits
    for (size_t i = 1; i < rounds.size(); ++i) {
        int end = rounds[i];
        std::cout << "From round " << i-1 << " to round " << i << ", moving from " << start << " to " << end << std::endl;

        // Move through each position until we reach the next round's start
        while (start != end) {
            start = (start % n) + 1;
            visited[start]++;
            std::cout << "Visiting position: " << start << ", Total visits: " << visited[start] << std::endl;
        }
    }

    // Step 4: Find the maximum number of visits to determine most visited positions
    int maxVisits = *std::max_element(visited.begin(), visited.end());
    std::cout << "Maximum visits: " << maxVisits << std::endl;

    // Step 5: Collect all positions with the maximum visit count
    std::vector<int> result;
    for (int i = 1; i <= n; ++i) {
        if (visited[i] == maxVisits) {
            result.push_back(i);
            std::cout << "Position " << i << " is one of the most visited with " << maxVisits << " visits." << std::endl;
        }
    }

    // Return the resultant vector of most visited positions
    return result;
}

