        // Check positions to the left
        for (int j = i - 1; j >= 0; j--) {
            int dist = a[i] - a[j];  // Calculate distance
            if (dist > d + (1e6)) break;  // Early exit if too far
            if (abs(dist - d) <= (1e6)) {
                reachable[j] = true;  // Mark j as reachable
