// Function to find the minimum maximum value based on given conditions
int minMaxValue(const std::vector<int>& nums) {
    // Step 1: Define search space
    int left = 0; 
    int right = *std::max_element(nums.begin(), nums.end());

    // Step 2: Implement binary search within the defined space
    while (left < right) {
        int mid = left + (right - left) / 2; // Avoid overflow
        int fill = 0;

        // Step 3: Calculate fill based on current mid value
        for (int num : nums) {
            fill += std::max(0, num - mid); // Accumulating excess values
        }

        // Step 4: Count zeros in the input
        int zeroCount = std::count(nums.begin(), nums.end(), 0);

        // Step 5: Determine next search bounds
        if (fill > nums.size() - zeroCount) {
            left = mid + 1; // Too much fill, increase mid
        } else {
            right = mid; // Valid fill, decrease mid
        }

        // Debugging output: mid value and current fill for research purposes
        std::cout << "Debug: mid=" << mid << ", fill=" << fill << ", left=" << left << ", right=" << right << std::endl;
    }

    // Final output of optimal minimum maximum value
    return left;
}

