class Solution {
public:
    // TODO: Implement the largest 1-bordered square function
    int largest1BorderedSquare(vector<vector<int>>& grid) {
        // Check for empty grid case
        if (grid.empty()) return 0;

        int n = grid.size(); // Number of rows
        int m = grid[0].size(); // Number of columns
        int maxSize = 0; // Variable to keep track of the maximum size found
        vector<vector<int>> dp(n, vector<int>(m, 0)); // DP table initialization

        // Iterate through the grid
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                // Only proceed if the current cell is 1
                if (grid[i][j] == 0) continue;

                // Base case: On the borders
                if (i == 0 || j == 0) {
                    dp[i][j] = 1; // Initialize border cells
                } else {
                    // Compute dp value using previously calculated subproblems
                    dp[i][j] = min(dp[i - 1][j - 1], min(dp[i - 1][j], dp[i][j - 1])) + 1;
                }

                // Update maximum size found
                maxSize = max(maxSize, dp[i][j]);

                // Debug instrumentation: Print current cell information
                cout << "i: " << i << ", j: " << j << ", dp[i][j]: " << dp[i][j] << ", maxSize: " << maxSize << endl;
            }
        }
        // Return the area of the largest 1-bordered square
        return maxSize * maxSize; // Area calculation
    }
};

