using namespace std;

// Function to calculate minimum distance
long computeMinDistance(string word, string remainingWords, set<string>& deleteSet) {
    // Base case: if no remaining words, return a high value as a placeholder
    if (remainingWords.empty()) return LONG_MAX;

    long dist = LONG_MAX; // Initialize distance to a large value for comparison

    // Iterate through remaining words
    for (size_t i = 0; i < remainingWords.size(); ++i) {
        string currentString = remainingWords.substr(i, 1); // Current character as a string

        // Debug print: Current string for analysis
        cout << "Current String: " << currentString << endl;

        if (word.length() > 1 || word.length() == 0 || currentString.length() == 0) continue;

        char ch = remainingWords[remainingWords.size() - 1];
        string newWord = currentString + ch;

        // Recursive call to calculate distance with modified remaining words
        auto newDist = computeMinDistance(word, remainingWords.substr(0, i + 1), deleteSet);
        dist = min(dist, newDist);

        // Check conditions to insert into deleteSet
        if (ch == word[word.size() - 1] && dist + currentString.length() + 1 < (long)remainingWords.length())
            deleteSet.insert(word + newWord);

        if (currentString == word[word.size() - 1] && dist + 1 < (long)newWord.length())
            deleteSet.insert(word);
    }

    // Return the minimum distance calculated for the current state
    return dist + currentString.length() + 1 < remainingWords.length()
           ? min(dist + currentString.length() + 1, (long)remainingWords.length())
           : dist;
}

int main() {
    string word{}, remainingWords{};

    // Input: Read word from the user
    cout << "Enter the word: ";
    getline(cin, word);
    remainingWords = word;

    set<string> deleteSet; // Set to store strings to be deleted or tracked

    // Compute minimum distance
    auto result = computeMinDistance(remainingWords, remainingWords, deleteSet);

    // Output the result
    cout << "Minimum distance: " << result << endl;

    // Debug print: Content of deleteSet
    cout << "Strings in deleteSet: ";
    for (const auto& str : deleteSet) {
        cout << str << " ";
    }
    cout << endl;

    return 0;
}

