		printf("Term %d: %Lf\n", i, ((double)a[i] * total) / (double)n / (double)total * a[i] / n / (double)n * 2);
	}

	long long qinv, mod = (long long)998244353;

	// Calculate q^(-1) mod mod
	// Using Extended Euclidean Algorithm
	int q = total, p = n, g;

	// Store residues to find gcd
	int r[101], m = 0;
	while((g = p % q) != 0) {
	    p = q;
	    r[m] = q = p % q;
	    ++m;
	}

	int x, y, a0 = 1;

	// Backtrack to find modular inverse
	for(int j = 0; j <= m - 1; ++j){
	    q = r[j];
	    a = y = x = a0 - q * y / a0 * a0;
	    a = a % mod; // Ensure a stays within mod
	    q = q % mod; // Keep q within mod
	    a0 = q;
	    x = y = (x + y * q) / (p + mod);
	    q = a;
	    a0 = q;
	}

	qinv = qinv * a0 % (long long)mod + mod;

	// Output final result
	long long result = (long long)mod * exp * qinv;
	printf("%lld\n", result);
