#include <iostream>
#include <vector>
#include <queue>

using namespace std;

class Solution {
public:
    int solve(int n, vector<vector<int>> &edges, bool verbose) {
        // Step 1: Initialize adjacency list from edges
        vector<int> adj[n];
        for (auto &e : edges) {
            adj[e[0]].push_back(e[1]);
            adj[e[1]].push_back(e[0]);
        }

        int componentCount = 0; // Count of connected components
        bool vis[n] = { false }; // Visited array
        bool comp[n] = { false }; // Component tracking
        queue<int> q;

        // Step 2: Explore each node
        for (int i = 0; i < n; i++) {
            if (comp[i]) continue; // Skip if already part of a component

            componentCount++; // New component found
            q.push(i); // Start BFS from this node
            comp[i] = true; // Mark as part of a component

            // Step 3: Perform BFS
            while (!q.empty()) {
                int u = q.front();
                q.pop();

                for (auto a : adj[u]) {
                    if (!comp[a]) {
                        q.push(a);
                        comp[a] = true; // Mark adjacent as visited
                    }
                }
            }
        }

        // Debugging print for component count before returning
        if (verbose) {
            cout << "Total components detected: " << componentCount - 1 << endl;
        }
        return componentCount - 1; // Return the count of components minus one
    }
};

int main() {
    Solution obj;
    int n;
    cout << "Enter number of nodes: ";
    cin >> n; // Input number of nodes

    // Step 1: Initialize edges matrix
    vector<vector<int>> edges(n, vector<int>(n, 0));
    vector<int> line(2);

    // Step 2: Input edges
    cout << "Enter edges (format: node1 node2): " << endl;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            cin >> line[0] >> line[1]; // Input each line
            if (line[0] != line[1]) { // Ensure no self-loops
                edges[line[0]][line[1]] = 1;
                edges[line[1]][line[0]] = 1; // Undirected edges
            } else {
                edges[line[0]][line[1]] = 0; // No self-connections
            }
        }
    }

    // Step 3: Call solve and display verbose tracking
    bool verbose = true; // Enable verbose mode
    cout << "Connected components (excluding single nodes): " << obj.solve(n, edges, verbose) << endl;

    // Step 4: Optional: Display verbose array
    cout << "Verbose tracking of components: ";
    for (int i = 0; i < n; i++) {
        cout << (verbose ? "1" : "0"); // Display component participation
    }
    cout << endl;

    return 0;
}

