class MaxValueMinimizer {
public:
    int findMinPossibleMax(std::vector<int>& nums) {
        int n = nums.size();
        if (n == 0) return 0; // Edge case

        int max_element = *std::max_element(nums.begin(), nums.end());
        int min_possible_max = max_element / n;

        while (min_possible_max <= max_element) {
            int mid = min_possible_max + (max_element - min_possible_max) / 2;
            std::cout << "Testing mid value: " << mid << std::endl;

            if (canAchieveMax(nums, mid)) {
                std::cout << "Possible to achieve max as " << mid << std::endl;
                max_element = mid - 1; // Adjust upper bound
            } else {
                std::cout << "Not possible to achieve max as " << mid << std::endl;
                min_possible_max = mid + 1; // Adjust lower bound
            }
        }

        std::cout << "Final minimized max value found: " << min_possible_max << std::endl;
        return min_possible_max;
    }

private:
    bool canAchieveMax(std::vector<int>& nums, int max_value) {
        int extra = 0;
        for (int i = 0; i < nums.size(); ++i) {
            if (nums[i] > max_value) {
                int excess = nums[i] - max_value;
                std::cout << "Element " << nums[i] << " exceeds max, excess: " << excess << std::endl;
                extra += excess;
            } else {
                int available = max_value - nums[i];
                std::cout << "Element " << nums[i] << " within range, available to push: " << available << std::endl;
                int to_push = std::min(extra, available);
                extra -= to_push; // Reduce available excess
            }
            std::cout << "Current extra: " << extra << std::endl;
        }
        // If we finish evaluating elements and still have excess
        if (extra > 0) {
            std::cout << "Excess remaining after balancing: " << extra << std::endl;
        }
        return extra <= 0; // Returns true if excess is handled
    }
};

