// Node structure to handle custom operations
struct Node {
    LL s, c;
    Node(LL s = 0, LL c = 0) : s(s), c(c) {}

    // Overloading less than for custom comparison
    bool operator<(const Node& rhs) const {
        return s * rhs.c < rhs.s * c;
    }
};

// Segment tree structure for efficient range queries
struct Tree {
    LL s, c; // Parameters for modification
    vector<Node> t; // Tree nodes

    // Modify function for updating segment tree
    void modify(int l, int r, int L, int R, int x, LL y) {
        if (l >= L && r <= R) {
            t[x].s += s * (R - L + 1);
            t[x].c += c * (R - L + 1);
            return;
        }
        int mid = (l + r) >> 1;
        if (mid >= L) modify(l, mid, L, R, x << 1, y);
        if (mid < R) modify(mid + 1, r, L, R, x << 1 | 1, y);
    }

    // Combine children nodes
    void pushup(int x) {
        t[x] = max(t[x << 1], t[x << 1 | 1]);
    }

    // Build the segment tree
    void build(int l, int r, int x) {
        t.resize(r * 4 + 10);
        if (l == r) {
            t[x] = Node(r, 1);
            return;
        }
        int mid = (l + r) >> 1;
        build(l, mid, x << 1);
        build(mid + 1, r, x << 1 | 1);
        pushup(x);
    }
} T;

// First DFS to calculate frequency values
void dfs(int u, int fa) {
    for (int v : g[u]) {
        if (v == fa) continue; // Prevent traversing back
        dfs(v, u);
        f[u] += f[v]; // Aggregate frequencies from children
    }
    f[u]++;
    T.modify(1, n, f[u], n, 1, u); // Update segment tree
}

// Second DFS to propagate values
void dfs2(int u, int fa) {
    for (int v : g[u]) {
        if (v == fa) continue; // Avoid backtracking
        // TODO: Investigate propagation logic to children
        T.modify(1, n, f[v], n, 1, u); // Adjust segment tree for child
        dfs2(v, u); // Recursive call
    }
}

