int findGreatestCommonDivisor(const std::vector<int>& arr) {
    if (arr.empty()) {
        std::cerr << "Input array is empty." << std::endl;
        return -1; // Error case for empty input
    }

    // Step 1: Determine the minimum and maximum values in the array
    int k = *std::min_element(arr.begin(), arr.end());
    int m = *std::max_element(arr.begin(), arr.end());

    int greatest_common_divisor = 1; // Step 2: Initialize GCD placeholder
    std::cout << "Finding GCD in the range: [" << k << ", " << m << "]" << std::endl;

    // Step 3: Iterate through the range to find GCD
    for (int i = k; i <= m; ++i) {
        // Check if i is a divisor for all elements
        bool is_common_divisor = true;
        for (int x : arr) {
            if (i % x != 0) {
                is_common_divisor = false; // i is not a common divisor
                break;
            }
        }

        if (is_common_divisor) {
            greatest_common_divisor = i; // Update if common divisor found
            std::cout << "New GCD found: " << greatest_common_divisor << " for i = " << i << std::endl;
        }
    }

    return greatest_common_divisor; // Step 4: Return result
}

