int mod(int value, int x) {
    if (value < 0) {
        value += x;
    }
    return (value % x + x) % x;
}

int abs(int x) {
    return (x < 0) ? -x : x;
}

int sum(const std::vector<int>& numbers) {
    int total = 0;
    for (int num : numbers) {
        total += num;
    }
    return total;
}

int findTargetValue(const std::vector<std::vector<int>>& grid, int x) {
    int total = 0;
    for (const auto& row : grid) {
        total += sum(row);
    }
    if (grid.empty() || grid[0].empty()) {
        return 0; // Handle edge case
    }
    int targetVal = mod(total / (grid.size() * grid[0].size()), x);
    return targetVal;
}

int calculateOperations(const std::vector<std::vector<int>>& grid, int x, int targetValue) {
    int totalOperations = 0;
    for (const auto& row : grid) {
        int rowOperations = 0;
        for (int num : row) {
            rowOperations += mod(abs(num - targetValue), x);
        }
        totalOperations += rowOperations;
    }
    return totalOperations;
}

int MinOperationsToUnivValue(const std::vector<std::vector<int>>& grid, int x) {
    if (grid.empty() || grid[0].empty()) {
        return -1; // Handle empty case
    }

    int targetValue = findTargetValue(grid, x);
    if (targetValue == 0) {
        return -1; // Return if no valid target
    }

    int operations = calculateOperations(grid, x, targetValue);

    return operations;
}

