vector<int> numMovesStonesII(vector<int>& stones) {
    sort(stones.begin(), stones.end());
    int n = stones.size();

    // Debug: Print sorted stones for verification
    cout << "Sorted stones: ";
    for (const auto& stone : stones) {
        cout << stone << " ";
    }
    cout << endl;

    // Calculate maximum moves possible
    int max_moves = max(stones[n-1] - stones[1] - n + 2, stones[n-2] - stones[0] - n + 2);

    // Setting min_moves initially to max_moves
    int min_moves = max_moves;

    // Iterate through the stones to find minimum moves
    int j = 0;
    for (int i = 0; i < n; ++i) {
        // Move j to the right while stones[j] is within the range
        while (j < n && stones[j] - stones[i] + 1 <= n) {
            j++;
        }
        int already_stones = j - i - 1; // Count of already placed stones in range

        // Debug: Print state of i, j, and already_stones
        cout << "i: " << i << ", j: " << j << ", already_stones: " << already_stones << endl;

        // Check for special cases to adjust minimum moves
        if (already_stones == n - 2 && stones[j-1] - stones[i] + 1 == n - 1) {
            min_moves = min(min_moves, 2); // Special case
        } else {
            min_moves = min(min_moves, n - already_stones); // General case
        }
    }

    // Debug: Final results
    cout << "Minimum moves: " << min_moves << ", Maximum moves: " << max_moves << endl;

    return {min_moves, max_moves}; // Returning result as a vector
}

