using Answer = std::tuple<int, int>;

class Solution {
public:
    Answer fairCandies(const std::vector<int>& aliceSizes, const std::vector<int>& bobSizes) {
        // Calculate total candies for Alice and Bob
        int a = std::accumulate(aliceSizes.begin(), aliceSizes.end(), 0);
        int b = std::accumulate(bobSizes.begin(), bobSizes.end(), 0);
        int diff = std::abs(a - b);

        // Debug prints to trace computation
        std::cout << "Total Alice: " << a << ", Total Bob: " << b << ", Diff: " << diff << std::endl;

        // Iterate through Alice's candy sizes to find the fair exchange
        for (size_t i = 0; i < aliceSizes.size(); ++i) {
            if (aliceSizes[i] == diff) {
                // Found direct match
                std::cout << "Direct match found at index " << i << ": " << aliceSizes[i] << std::endl;
                return std::make_tuple(aliceSizes[i], diff);
            } else {
                int potentialExchange = b - aliceSizes[i];
                if (potentialExchange == diff) {
                    // Found a match with Bob's candies
                    std::cout << "Potential exchange found at index " << i << ": " << aliceSizes[i] 
                              << " with Bob's candy: " << potentialExchange << std::endl;
                    return std::make_tuple(aliceSizes[i], potentialExchange);
                }
            }
        }

        // No fair exchange found, return a default response
        std::cout << "No fair exchange found, returning diff values" << std::endl;
        return std::make_tuple(diff, diff);
    }
};

