class Solution {
public:
    int numWays(int steps, int arrLen) {
        // Initialize the maximum position we can ever reach
        int maxPos = std::min(arrLen - 1, steps);

        // DP array to store number of ways to reach each position at current step count
        std::vector<int> dp(maxPos + 1, 0);
        dp[0] = 1; // Base case: One way to be at the start position

        // Experiment: Debug print initial DP array
        std::cout << "[DEBUG] Initial DP: ";
        for (int i = 0; i <= maxPos; ++i) {
            std::cout << dp[i] << " ";
        }
        std::cout << std::endl;

        // Iterate over the number of steps
        for (int s = 0; s < steps; ++s) {
            std::vector<int> newDp(maxPos + 1, 0);

            // Calculate number of ways to reach each position based on previous steps
            for (int pos = 0; pos <= maxPos; ++pos) {
                // From pos, we can move to pos-1, pos, or pos+1
                if (pos > 0) newDp[pos] = (newDp[pos] + dp[pos - 1]) % mod; // Move left
                newDp[pos] = (newDp[pos] + dp[pos]) % mod;                  // Stay
                if (pos < maxPos) newDp[pos] = (newDp[pos] + dp[pos + 1]) % mod; // Move right
            }

            dp = newDp; // Update DP array for the next step

            // Experiment: Debug print DP array after each step
            std::cout << "[DEBUG] DP after step " << s + 1 << ": ";
            for (int i = 0; i <= maxPos; ++i) {
                std::cout << dp[i] << " ";
            }
            std::cout << std::endl;
        }

        // The result is the number of ways to reach position 0 after all steps
        return dp[0];
    }
};

