#include <vector>
#include <algorithm>
#include <limits>
#include <iostream>

std::vector<int> countPeople(const std::vector<int>& heights) {
    int n = heights.size();
    std::vector<int> answer(n, 0);
    std::vector<int> maxRight(n, 0);
    std::vector<int> minLeft(n, std::numeric_limits<int>::max());

    int maxSeen = 0;

    // Backward pass to populate answer[i] and maxRight
    for (int i = n - 1; i >= 0; --i) {
        int currentHeight = heights[i];
        answer[i] = maxSeen; // Store number of taller people seen to the right
        maxSeen = std::max(maxSeen, currentHeight); // Update maxSeen

        if (i < n - 1) {
            maxRight[i] = std::max(maxRight[i + 1], answer[i]);
        } else {
            maxRight[i] = answer[i]; // Initialize for the last element
        }

        // DEBUG: Printing current maximum seen and the answer vector
        std::cout << "i: " << i << ", currentHeight: " << currentHeight
                  << ", answer[i]: " << answer[i] 
                  << ", maxSeen: " << maxSeen << "\n";

        int temp = currentHeight;
        // Iterate to update minLeft for shorter people
        for (int j = i - 1; j >= 0; --j) {
            if (heights[j] < temp) {
                minLeft[j] = std::min(minLeft[j], currentHeight);
            }
        }
    }

    // Adjust answer based on minLeft values
    for (int i = 0; i < n; ++i) {
        answer[i] -= minLeft[i];

        // DEBUG: Output the adjustments made based on minLeft
        std::cout << "i: " << i << ", minLeft[i]: " << minLeft[i]
                  << ", adjusted answer[i]: " << answer[i] << "\n";
    }

    return answer;
}

