// Function to determine maximum possible sum from elements
vector<int> solve(int n, int m, vector<int> a) { 
    priority_queue<pair<int, int>> maxHeap; 

    // Inserting elements and their indices into maxHeap
    for(int i = 0; i < n; ++i) {
        maxHeap.push({a[i], i});
    } 

    // Sorting in descending order for potential secondary use
    sort(a.begin(), a.end(), greater<int>());

    int i = 0, j = 0, sum = 0, maxS = 0;
    bool flag = true;

    // Iterating until maxHeap is empty
    while (!maxHeap.empty()) { 
        int sum1 = sum;
        pair<int, int> top = maxHeap.top(); 
        maxHeap.pop(); 

        // Debug print: current max element being processed
        cout << "Processing element: " << top.first << " at index " << top.second << endl;

        // Alternating summands based on flag
        if (flag) {
            sum += top.first + a[i++];
            maxS = max(maxS, sum - sum1);
            // Debug print: sum after addition when flag is true
            cout << "Flag true -> New sum: " << sum << ", maxS: " << maxS << endl;
        } else {
            sum += top.first + a[j++];
            maxS = max(maxS, sum - sum1);
            // Debug print: sum after addition when flag is false
            cout << "Flag false -> New sum: " << sum << ", maxS: " << maxS << endl;
        }

        flag = !flag; // Toggle flag
    }

    vector<int> res = {maxS}; // Record maximum sum found
    return res;
}

