    vector<int> res = solve(a.size(), 0, a);

    // Output result
    cout << "Maximum sum result: ";
    for (int i = 0; i < res.size(); ++i)
        cout << res[i] << " ";

    cout << endl; // Ensuring clean output
    return 0;
}

