// Function to calculate maximum beauty of the tree
void dfs(int nodeId) {
    TreeNode& node = tree[nodeId];
    int l = node.bounds[0].first; // Retrieve the lower bound
    int r = node.bounds[0].second; // Retrieve the upper bound

    // Debug info
    cout << "Visiting node " << nodeId << " with bounds (" << l << ", " << r << ")\n";

    // Recursive DFS for children
    for (int childId : node.children) {
        dfs(childId);
        int childL = tree[childId].bounds[0].first;
        int childR = tree[childId].bounds[0].second;

        // Calculate difference contribution from this edge
        maxDifferenceSum += max(abs(r - childL), abs(l - childR));
        cout << "Edge (" << nodeId << ", " << childId << ") contributes max difference: " << max(abs(r - childL), abs(l - childR)) << "\n";
    }
}

