// Structure definition for binary tree nodes.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

class Solution {
private:
    bool isLeftNode = true; // Flag to indicate if the current node is a left node.

public:
    int sumOfLeftLeaves(TreeNode* root) {
        // Starting the traversal from root with total sum initialized to zero
        return computeSum(root, 0, true);
    }

private:
    int computeSum(TreeNode* root, int currentSum, bool left) {
        isLeftNode = left;
        if (!root) {
            return currentSum; // If the node is null, return current sum.
        }

        // Check if it is a leaf node
        if (!root->left && !root->right) {
            // If it is a left leaf node, add its value to the sum
            return left ? root->val : currentSum;
        }

        // Recursive call to the left child, adding any left leaf value found
        int leftLeafSum = computeSum(root->left, computeSum(root->right, currentSum, false) + (isLeftNode ? root->val : 0), true);

        // Return total sum including left contributions.
        return leftLeafSum + (isLeftNode ? root->val : 0);
    }
};

