int gcd(int a, int b) {
    while (b != 0) {
        int t = b;
        b = a % b;
        a = t;
    }
    return a;
}

int calculate_gcd_of_numbers(const std::vector<int>& numbers) {
    return std::reduce(numbers.begin(), numbers.end(), numbers[0], gcd);
}

std::vector<int> max_elements_in_set(const std::vector<std::pair<int, std::vector<int>>>& test_cases) {
    std::vector<int> results;

    for (const auto& test_case : test_cases) {
        int n = test_case.first;
        const auto& numbers = test_case.second;

        // TODO: Investigate performance for large n
        int gcd_of_set = calculate_gcd_of_numbers(numbers);

        // TODO: Check if gcd_of_set is zero to avoid division by zero
        int max_elements = (gcd_of_set != 0) ? (*std::max_element(numbers.begin(), numbers.end()) / gcd_of_set) : 0;

        results.push_back(max_elements);

        // Debug prints for tracking progress 
        std::cout << "Test case with n=" << n << " results in max_elements=" << max_elements 
                  << " for gcd_of_set=" << gcd_of_set << std::endl;
    }

    return results;
}

