string shortestCommonSupersequence(string str1, string str2) {
    int n = str1.size();
    int m = str2.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));

    // Building the DP table
    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= m; j++) {
            if(str1[i - 1] == str2[j - 1]) {
                dp[i][j] = 1 + dp[i - 1][j - 1];
                // Debug: Matching characters
                cout << "Match: " << str1[i - 1] << " at (" << i << ", " << j << ")\n";
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
                // Debug: Selecting max from previous computations
                cout << "No Match: Selecting max at (" << i << ", " << j << "), values: "
                     << dp[i - 1][j] << ", " << dp[i][j - 1] << "\n";
            }
        }
    }

    string res = "";
    int i = n, j = m;

    // Constructing the result from the DP table
    while(i > 0 && j > 0) {
        if(str1[i - 1] == str2[j - 1]) {
            res += str1[i - 1];
            i--;
            j--;
        } else if(dp[i - 1][j] > dp[i][j - 1]) {
            res += str1[i - 1];
            i--;
        } else {
            res += str2[j - 1];
            j--;
        }
    }
    // Adding remaining characters if any
    while(i > 0) {
        res += str1[i - 1];
        i--;
    }
    while(j > 0) {
        res += str2[j - 1];
        j--;
    }

    reverse(res.begin(), res.end());

    // TODO: Assess the correctness of the results with test cases
    cout << "Final SCS: " << res << endl; // Debug: Output the final supersequence
    return res;
}

