// Union-Find Structure
struct DSU {
    vector<int> parent;
    DSU(int n) {
        parent.resize(n);
        iota(parent.begin(), parent.end(), 0); // Initialize parent to self
    }

    int find(int x) {
        // Path compression for efficiency
        if (x != parent[x]) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool merge(int x, int y) {
        x = find(x);
        y = find(y);
        if (x != y) {
            parent[x] = y; // Union operation
            return true; // Successful merge
        }
        return false; // Already in the same set
    }
};

int n, m;
vector<int> tree(1 << 21); // Sparse segment tree for range operations
DSU dsu(1 << 21); // Initialize DSU structure

void build(int v, int tl, int tr) {
    if (tl == tr) {
        tree[v] = tl;
        return;
    }
    int tm = (tl + tr) / 2;

    // Recursive build of the segment tree
    build(v * 2, tl, tm);
    build(v * 2 + 1, tm + 1, tr);

    // Log current state for debugging
    cout << "Building node " << v << " from [" << tl << ", " << tr << "], "
         << "left child: " << tree[v * 2] << ", right child: " << tree[v * 2 + 1] << endl;

    if (tree[v * 2] && tree[v * 2 + 1]) {
        dsu.merge(tree[v * 2], tree[v * 2 + 1]); // Merge sets if both children are valid
    }
    tree[v] = dsu.find(tree[v * 2]) != dsu.find(tree[v * 2 + 1]) ? tree[v * 2] : tree[v * 2 + 1];
}

void update(int v, int tl, int tr, int l, int r) {
    if (l > r) {
        return; // Base case; no overlapping segment
    }
    if (tl == l && tr == r) {
        tree[v] = 0; // Mark as updated
        cout << "Updating node " << v << " to 0 for range [" << l << ", " << r << "]" << endl;
        return;
    }
    int tm = (tl + tr) / 2;

    // Recursive updates
    update(v * 2, tl, tm, l, min(r, tm));
    update(v * 2 + 1, tm + 1, tr, max(l, tm + 1), r);

    // Merge updates and log
    if (tree[v * 2] && tree[v * 2 + 1]) {
        dsu.merge(tree[v * 2], tree[v * 2 + 1]);
    }

    // Update current node based on merged state
    tree[v] = dsu.find(tree[v * 2]) != dsu.find(tree[v * 2 + 1]) ? tree[v * 2] : tree[v * 2 + 1];
}

