int main() {
    // Input number of nodes in the graph
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> graph(n, std::vector<int>(n));

    // Read graph adjacency matrix from input
    for (int i = 0; i < n; ++i) {
        std::string row;
        std::cin >> row;
        for (int j = 0; j < n; ++j) {
            graph[i][j] = row[j] - '0'; // Convert char to int
        }
    }

    std::vector<int> counter(1 << (n - 1), 0); // Initialize counter

    // Count edges present in the graph for all pairs (i, j)
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (graph[i][j] == 1) {
                // Examine all subsets of the graph
                for (int k = 0; k < (1 << (n - 1)); ++k) {
                    if ((k & (1 << (i - 1))) && (k & (1 << (j - 1)))) {
                        counter[k] += 1; // Increment counter for this subset
                    }
                }
            }
        }
    }

    // Output result
    std::vector<int> out;
    for (int i = 0; i < (1 << (n - 1)); ++i) {
        // Calculate number of ways to select pairs
        int cnt = counter[i];
        int ways = (cnt + 1) * cnt / 2;
        out.push_back(ways);
    }

    // Print output with debug information
    for (const auto& c : out) {
        std::cout << c << " "; // Output way counts
    }
    std::cout << std::endl; // New line after output

    return 0;
}

