public:
    bool isPrintable(vector<vector<int>>& a) {
        // TODO: Check matrix dimensions for edge cases
        if(a.size() == 1) return true; // Single row case
        if(a[0].size() == 1) return true; // Single column case

        unordered_set<int> uniqueValues;

        // Collect unique values from the matrix
        for(int i = 0; i < a.size(); ++i) {
            for(int j = 0; j < a[0].size(); ++j) { // Fix bounds
                uniqueValues.insert(a[i][j]);
            }
        }

        vector<int> distinctValues(uniqueValues.begin(), uniqueValues.end());

        // Iterate through each unique value for processing
        for(int k = 0; k < distinctValues.size(); ++k) {
            int currentValue = distinctValues[k];
            bool isPrintableFlag = true;

            // For every occurrence of the current value in the matrix
            for(int i = 0; i < a.size(); ++i) {
                for(int j = 0; j < a[0].size(); ++j) {
                    if(a[i][j] == currentValue) {
                        int rowEnd = i, colEnd = j;

                        // Extend to the right
                        while(colEnd < a[0].size() && a[i][colEnd] == currentValue) {
                            colEnd++;
                        }
                        colEnd--; // Adjust for last increment

                        // Extend downwards
                        while(rowEnd < a.size() && a[rowEnd][j] == currentValue) {
                            rowEnd++;
                        }
                        rowEnd--; // Adjust for last increment

                        // Debug information
                        cout << "Analyzing value: " << currentValue << " at position: " << i << "," << j << " Extents: " << rowEnd << "," << colEnd << endl;

                        // Check for disjoint occurrences of current value
                        for(int ii = rowEnd + 1; ii < a.size(); ++ii) {
                            for(int jj = j + 1; jj < a[0].size(); ++jj) {
                                if(a[ii][jj] == currentValue) {
                                    isPrintableFlag = false; // Found another occurrence
                                    break;
                                }
                            }
                            if(!isPrintableFlag) break;
                        }

                        if(isPrintableFlag) {
                            for(int ii = rowEnd + 1; ii < a.size(); ++ii) {
                                if(a[ii][j] == currentValue) {
                                    isPrintableFlag = false;
                                    break;
                                }
                            }
                        }

                        // Optional: Early exits if non-printable
                        if(!isPrintableFlag) {
                            cout << "Value: " << currentValue << " is not printable due to overlaps." << endl;
                            break;
                        }
                    }
                }
                if(!isPrintableFlag) break; // Exit outer loop if flag is false
            }

            if(!isPrintableFlag) return false; // Return false if any value fails
        }

        return true; // All checks passed
    }

