int minSwapsToBalance(std::string s) {
    int imbalance = 0; // Tracks the imbalance of `]` before `[`
    int swaps = 0;     // Counts the number of swaps needed

    std::cout << "Starting balance computation for string: " << s << std::endl;

    for (char c : s) {
        if (c == '[') {
            imbalance++; // Found an opening bracket
            std::cout << "Found '[': Imbalance increased to " << imbalance << std::endl;
        } else if (c == ']') {
            imbalance--; // Found a closing bracket
            std::cout << "Found ']': Imbalance decreased to " << imbalance << std::endl;
            if (imbalance < 0) {
                // We have more `]` than `[` at this point
                swaps++;   // A swap is needed
                std::cout << "Imbalance negative, a swap is needed. Total swaps now: " << swaps << std::endl;
                imbalance = 0; // Reset imbalance after swapping
            }
        } else {
            std::cout << "Encountered an unexpected character: " << c << std::endl;
        }
    }

    std::cout << "Final swap count: " << swaps << std::endl;
    return swaps; // Returning the total number of swaps needed
}

