void depth_first_search(int x, int y) {
    if (x == 1 || x == n) return;
    if (y == 1 || y == m) return;

    if (val[x][y] == val[x][y - 1]) y--;
    if (val[x][y] == val[x][y + 1]) y--;
    if (val[x][y] == val[x - 1][y]) x--;
    if (val[x][y] == val[x + 1][y + 1]) y++;
    if (val[x][y] == val[x + 1][y]) x++;

    depth_first_search(x, y);
}

