    std::vector<int> dp(n);
    dp[n - 1] = prefix[n - 1];

    // Compute dynamic programming values
    for (int i = n - 2; i >= 1; --i) {
        dp[i] = std::max(prefix[i] - dp[i + 1], dp[i + 1]);
        std::cout << "DP value at index " << i << ": " << dp[i] << std::endl;  // Debug print
    }

    std::cout << "Final result: " << dp[1] << std::endl;  // Output final result
    return dp[1];
}

