def min_time(r, g, b):
    if g > b / 2 or (r + g + b) % 3 != 0:
        return [-1]

    r *= 30
    g *= 30
    b *= 30

    if r < 0 or g < 0 or b < 0:
        return [-1]

    while r > 0 or g > 0 or b > 0:
        lowest = get_lowest(r, g, b)
        # Instrumentation for debugging
        print(f'Lowest value determination: {lowest} with R={r}, G={g}, B={b}')

        if lowest == 0:
            return [get_nth_min(r, g, b, 0)]
        elif lowest == 1:
            break
        elif lowest == 2:
            return [get_nth_min(r, g, b, 3) + get_nth_min(r, g, b, 2)]
        elif lowest == 3:
            return [get_nth_min(r, g, b, 0) + get_nth_min(r, g, b, 1) + get_nth_min(r, g, b, 2)]

    return [0]

def get_nth_min(r, g, b, n):
    if r <= 0 and g <= 0 and b <= 0:
        return -1

    lst = [30, 31, 32]
    if n == 0:
        if r > 0:
            return 1
        else:
            return lst[1] - lst[0]
    elif n == 1:
        if g > 0:
            return 1
        else:
            return lst[1] - lst[0]
    elif n == 2:
        if b > 0:
            return 1
        else:
            return lst[1] - lst[0]
    elif r == 0 and g == 0 and b > 0:
        return lst[2] - lst[0]
    elif g == 0 and b == 0 and r > 0:
        return lst[2] - lst[0]
    elif b == 0 and r == 0 and g > 0:
        return lst[2] - lst[0]
    elif b > 0 and g > 0 and r > 0:
        return lst[2] - lst[0]

    return -1

def get_lowest(r, g, b):
    min_value = min(r, g, b)
    # Debug statement to track the counts after min extraction
    print(f'Before min extraction: R={r}, G={g}, B={b}. Min={min_value}')

    r -= min_value
    g -= min_value
    b -= min_value

    if r > g:
        return 0
    elif g == r:
        return 3
    else:
        return 1

