def calculate_total_amount(n, planks, length, breath):
    # Function to compute sum of digits
    def sum_of_digits(number):
        return sum(int(digit) for digit in str(number))

    # Function to calculate rate based on planks
    def calculate_rate(number):
        return number * sum_of_digits(number)

    # Function to apply discounts based on quantity
    def apply_discount(rate, number):
        if 1 <= number <= 10:
            return round(rate * 0.75)
        elif 11 <= number <= 20:
            return round(rate * 0.70)
        else:
            return round(rate * 0.80)

    # Initialize total cost variable
    total_cost = 0
    area_per_plank = length * breath

    # Iterate over each plank to calculate discounted rates
    for plank in planks:
        rate = calculate_rate(plank)
        discounted_rate = apply_discount(rate, plank)
        total_cost += discounted_rate * area_per_plank

        # Debugging: Outputs for each plank
        print(f"Plank: {plank}, Rate: {rate}, Discounted Rate: {discounted_rate}, Area Cost: {discounted_rate * area_per_plank}")

    return total_cost

