def can_sort_with_one_reverse(arr):
    import bisect
    decreasing_sub = []

    # Identify decreasing segments in the array
    for num in arr:
        if decreasing_sub and num < decreasing_sub[-1][1]:
            decreasing_sub[-1][1] = num  # Update the end of the last segment
        else:
            decreasing_sub.append([num, num])  # Start a new segment

    # Debug: Print the detected decreasing segments
    print("Detected decreasing segments:", decreasing_sub)

    # Check if we have less than two segments
    if len(decreasing_sub) < 2:
        print("Only one or no decreasing segment. Array is sortable.")
        return "yes", (-1, -1)

    # Check boundary conditions for the first and last segments
    if decreasing_sub[0][0] > decreasing_sub[1][0] or decreasing_sub[-1][0] < decreasing_sub[-2][0]:
        print("Decreasing segments at array boundaries, cannot sort.")
        return "no", (-1, -1)

    # Extract start and end of the first decreasing segment
    start = decreasing_sub[0][0]
    end = decreasing_sub[0][1]
    print("Potential reverse segment identified:", start, end)

    # Evaluate if reversing can result in a sorted array
    if start == decreasing_sub[1][0] - 1 and end == decreasing_sub[1][0]:
        return "yes", (start, end)

    if decreasing_sub[0][0] == 1 and decreasing_sub[0][1] == decreasing_sub[1][0] - 1:
        return "yes", (start, end)

    # Create the array post-reversal of the identified segment
    after_reverse = arr[:bisect.bisect_right(arr, decreasing_sub[0][1])] + arr[bisect.bisect_right(arr, decreasing_sub[0][1]):][::-1]
    print("Array after potential reversal:", after_reverse)

    # Check if the reversed array is sorted
    if after_reverse == sorted(arr):
        print("Reversal leads to sorted array.")
        return "yes", (start, end)

    print("Reversal does not lead to sorted array.")
    return "no", (-1, -1)

