class UnionFind:
    def __init__(self, array):
        self.id = {x: x for x in array}
        self.count = len(array)

    def add_link(self, p, q):
        i = self.find(p)
        j = self.find(q)
        if i == j:
            return
        self.id[q] = i
        self.count -= 1

    def find(self, p):
        """Find the root of the element p."""
        if self.id[p] != p:
            raise Exception(f"Downstream root found while querying root number. Number = {p}")
        while p != self.id[p]:
            old_p = p
            p = self.id[p]
            self.id[old_p] = self.id[p]  # Path compression
        return p

    def num_links(self):
        """Count the number of unique links in the set."""
        return sum(1 for key in self.id if self.id[key] == key)

    def is_linkage(self, p, q):
        """Check if p and q are linked."""
        if p == q:
            return True
        return p in self.id and q in self.id

    def find_n(self, p):
        """Find the root and count number of links."""
        if self.id[p] != p:
            raise Exception(f"Downstream root found while querying root number. Number = {p}")
        num_ones = 0
        while p != self.id[p]:
            self.id[p] = self.id[self.id[p]]  # Path compression
            if p == self.id[p]:
                num_ones += 1
                return p, num_ones
            p = self.id[p]
        return self, sum_graph(p, self.id, self.id[p], self)

    def make_component(self, root, p):
        """Make a connected component containing p."""
        parents = []
        while p != root:
            parents.append(p)
            p = self.id[p]
        for key in parents:
            self.id[key] = root

    def compute(self, root):
        """Compute the roots and sizes of connected components."""
        num_components = self.num_links()
        parent = {}
        size = {}
        for key, value in self.id.items():
            if key == root or value == key:
                self.id[key] = root
                parent[key] = key
                size[key] = 1
            else:
                self.id[key] = root

        for key in self.id.keys():
            p = self.find_n(key)
            if p[1] == 1:
                continue
            parent[p[0]] = p[0]
            parent[key] = p[0]
            size[key] += size.get(p[0], 0)

