def printCousins(root, node):
    # Early exit if tree is empty
    if root is None:
        return [-1]

    # Function to determine the level of a target node
    def findLevel(current_node, target, current_level):
        if current_node is None:
            return -1
        if current_node == target:
            return current_level
        left_level = findLevel(current_node.left, target, current_level + 1)
        if left_level != -1:
            return left_level
        return findLevel(current_node.right, target, current_level + 1)

    # Function to gather nodes at the same level as the target node
    def findNodesAtSameLevel(current_node, target, current_level):
        if current_node is None:
            return []
        if current_level == findLevel(current_node, target, 0):
            return [current_node]
        left_nodes = findNodesAtSameLevel(current_node.left, target, current_level + 1)
        right_nodes = findNodesAtSameLevel(current_node.right, target, current_level + 1)
        return left_nodes + right_nodes

    # Function to verify if two nodes are cousins (i.e., have different parents)
    def haveDifferentParents(node1, node2, parent1, parent2):
        if node1 is None or node2 is None:
            # Instrumentation for debugging
            print(f"One of the nodes is None: {node1}, {node2}")
            return False
        if node1 == node2:
            return False
        return parent1 != parent2

    # Gather all nodes on the same level as the target node
    sameLevelNodes = findNodesAtSameLevel(root, node, 0)

    cousins = []

    # Gather the values of the cousin nodes
    for candidate in sameLevelNodes:
        if candidate != node.parent:
            # Debug print for checking parent relationships
            print(f"Examining nodes: candidate={candidate.value}, target parent={node.parent.value}")
            if haveDifferentParents(candidate, node.parent, node.parent.parent, node.parent.parent):
                cousins.append(candidate.value)

    # Return the found cousins or -1 if none found
    result = cousins if cousins else [-1]
    # Final debug statement
    print(f"Cousins found: {result}")
    return result

