    for i in range(1, R):
        M[i][0] += M[i-1][0]
        print(f"Updated M[{i}][0]: {M[i][0]}")  # Debugging: print prefix sums for first column

    for j in range(1, C):
        M[0][j] += M[0][j-1]
        print(f"Updated M[0][{j}]: {M[0][j]}")  # Debugging: print prefix sums for first row

    for i in range(1, R):
        for j in range(1, C):
            M[i][j] += M[i][j-1] + M[i-1][j] - M[i-1][j-1]
            print(f"Updated M[{i}][{j}]: {M[i][j]}")  # Debugging: print the accumulated values

    max_sum = M[0][0]
    print(f"Initial max_sum: {max_sum}")  # Debugging: initial value for max_sum

    # Iterate through all rectangles and calculate sums
    for l in range(R):
        for b in range(l, R):
            for t in range(C):
                for r in range(t, C):
                    # Calculate sum of current rectangle
                    temp = M[b][r]
                    if l > 0:
                        temp -= M[l-1][r]
                    if t > 0:
                        temp -= M[b][t-1]
                    if l > 0 and t > 0:
