class BinarySearchTree:
    def __init__(self):
        self.root = None
        # Debugging: Initialization complete
        print("[DEBUG] Binary Search Tree initialized.")

    def insert(self, key):
        if self.root is None:
            self.root = Node(key)
            # Debugging: Inserted first key into BST
            print(f"[DEBUG] Inserted root key: {key}")
        else:
            self._insert(self.root, key)

    def _insert(self, node, key):
        # Debugging: Insert operation in progress
        print(f"[DEBUG] Attempting to insert key: {key} at node with key: {node.key}")
        if key < node.key:
            if node.left is None:
                node.left = Node(key)
                print(f"[DEBUG] Inserted key: {key} to the left of node with key: {node.key}")
            else:
                self._insert(node.left, key)
        else:
            if node.right is None:
                node.right = Node(key)
                print(f"[DEBUG] Inserted key: {key} to the right of node with key: {node.key}")
            else:
                self._insert(node.right, key)

    def find(self, key):
        result = self._find(self.root, key)
        # Debugging: Find operation result
        print(f"[DEBUG] Find operation for key: {key}, result: {result}")
        return result

    def _find(self, node, key):
        if node is None:
            return "no"
        elif key == node.key:
            return "yes"
        elif key < node.key:
            return self._find(node.left, key)
        else:
            return self._find(node.right, key)

    def inorder(self):
        inorder_keys = self._inorder(self.root)
        print(f"[DEBUG] Inorder traversal result: {inorder_keys}")
        return inorder_keys

    def _inorder(self, node):
        if node is not None:
            return self._inorder(node.left) + [node.key] + self._inorder(node.right)
        else:
            return []

    def preorder(self):
        preorder_keys = self._preorder(self.root)
        print(f"[DEBUG] Preorder traversal result: {preorder_keys}")
        return preorder_keys

    def _preorder(self, node):
        if node is not None:
            return [node.key] + self._preorder(node.left) + self._preorder(node.right)
        else:
            return []

