        int result = 0;

        // Debug: Log sorted coins
        System.out.println("Sorted coins: " + coins);

        int zeroIndex = coins.indexOf(0); // Find index of zero (if it exists)

        // Condition where target is outside possible coin range
        if (target < coins.get(0)) {
            System.out.println("Target is less than the smallest coin.");
            return result; 
        }

        // Tail condition, target greater than max coin
        if (target > coins.get(zeroIndex)) {
            System.out.println("Target exceeds available coin value.");
            return result + 1; 
        }

        if (target >= coins.get(zeroIndex)) {
            result = ++zeroIndex;
        } else {
            // Implement divide and conquer to find valid coin combination
            int f = lowerBound(coins.subList(0, zeroIndex), target);
            int b = upperBound(coins.subList(zeroIndex, coins.size()), target);

            result = 0;
            if (zeroIndex < f) {
                result = ++zeroIndex; // Valid combination found
            } else {
                // Recursive call to find minimum coins
                result = Math.min(result, 1 + minCoins(coins, target - coins.get(b) - 1));
            }
        }
        return result;
    }

    // Debug print for lower bound search
    public int lowerBound(List<Integer> v, int target) {
        Collections.sort(v);
        // Debug: Log search details
        System.out.println("Lower bound search for target: " + target + " in " + v);

        int curIndex = Collections.binarySearch(v, target);
        if (curIndex < 0) curIndex = -curIndex - 1; // Convert to insertion point

        if (curIndex > 0 && target <= v.get(curIndex - 1)) {
            return 1 + Collections.frequency(v, target - v.get(curIndex - 1)) + 1; // Count occurrences
        } else {
            return 0; // No valid lower bound found
        }
    }

    // Debug print for upper bound search
    public int upperBound(List<Integer> v, int target) {
        Collections.sort(v);
        // Debug: Log search details
        System.out.println("Upper bound search for target: " + target + " in " + v);

        int curIndex = Collections.binarySearch(v, target);
        if (curIndex < 0) curIndex = -curIndex - 1; // Convert negative to insertion point

        if (curIndex - 1 >= 0 && v.get(curIndex - 1).equals(target)) {
            return curIndex - 1; // Last valid coin before target
        } else {
            return 0; // No valid upper bound found
        }
    }

