        if (nums.empty()) return 0; // Early exit for empty input
        int count = pow(2, log2(k)); // Determining base count from k
        vector<int> power(nums.size() + 1, 0); // Initialize power array
        reverse(nums.begin(), nums.end()); // Reverse nums for processing

        // Developing power values from the diff of consecutive nums
        for (int i = 1; i < nums.size(); ++i) {
            power[i] = power[i - 1] + (nums[i] - nums[i - 1]);
        }

        // Main logic to calculate the final count
        for (int i = nums.size(); i >= 1; --i) {
            int j = i - 1;
            int countZero = 0, countOne = 0;

            // Investigate conditions under which we can increment countZero
            while (power[j] % k == 0) {
                if (power[j] % k == 0 && power[j - 1] > 0 && power[j] < k) {
                    countZero++; // Increment countZero if conditions are met
                }
                power[j] = power[j] - power[j - 1]; // Update the current power
                power[j - 1] = power[j - 1] + (nums[j - 1] - nums[j]); // Update previous power
            }

            // Debug output: print intermediate counts
            cout << "i: " << i << ", countZero: " << countZero << ", countOne: " << countOne << endl; 

            // Modulo operator to keep numbers manageable
            count = (count + pow(power[i], countZero) * pow(power[i] + countOne, countZero)) % (1000000007);
        }

        // Final result output
        return count;
    }
};

