public class ShortestPathResearch {

    public static void findShortest(int n, int[] a) {
        // Initializing infinity and dp array
        final int INF = Integer.MAX_VALUE;
        int[] dp = new int[n + 1];

        // Assuming initial state
        for (int i = 1; i <= n; i++) {
            dp[i] = INF;
        }
        dp[0] = 0; // Base case

        // Debug print to track dp array state
        System.out.println("Initial DP State: " + dp[0]);

        // Main logic for finding the shortest path
        for (int i = 1; i < n; i++) {
            if (a[i - 1] != a[i]) {
                dp[i] = Math.min(dp[i], dp[i - 1]);
            }
            if (i > 1 && a[i - 2] != a[i]) {
                dp[i] = Math.min(dp[i], dp[i - 2] + 1);
            } else {
                dp[i] = Math.min(dp[i], dp[i - 1] + 1);
            }

            // Debug print to glance over each step
            System.out.println("DP State at index " + i + ": " + dp[i]);
        }

        // Final output print
        System.out.println("Final DP Result: " + dp[n - 1]);
