class Solution {
    public String longestSubsequenceRepeatedK(String s, int k) {
        int n = s.length();
        String res = "";

        // TODO: Optimize mask generation; consider limiting potential duplicates.
        for (int mask = 0; mask < (1 << n); mask++) {
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    sb.append(s.charAt(i));
                }
            }
            String sub = sb.toString();
            // DEBUG: Print current subsequence
            System.out.println("Checking subsequence: " + sub);
            if (isRepeatedKTimes(s, sub, k) && 
                (sub.length() > res.length() || 
                (sub.length() == res.length() && sub.compareTo(res) > 0))) {
                // DEBUG: Found a longer or lexicographically better subsequence
                System.out.println("New best subsequence: " + sub);
                res = sub;
            }
        }
        // DEBUG: Final result
        System.out.println("Final result: " + res);
        return res;
    }

    private boolean isRepeatedKTimes(String s, String sub, int k) {
        int idx = 0;
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (idx < sub.length() && c == sub.charAt(idx)) {
                sb.append(c);
                idx++;
                if (idx == sub.length()) {
                    idx = 0; // Reset index to start matching again
                }
            }
        }

        // Construct the repeated string for comparison
        String repeated = "";
        for (int i = 0; i < k; i++) {
            repeated += sub; // TODO: Consider using StringBuilder for efficiency
        }

        // DEBUG: Comparing generated string with expected repetition
        System.out.println("Comparing: " + sb.toString() + " with: " + repeated);
        return sb.toString().equals(repeated);
    }
}

