public class Solution {
    public int[][] findSubstring(String text, String[] words) {
        // TODO: Consider edge cases where text or words array might be empty.
        Map<String, Integer> wordMap = new HashMap<>();

        // Initialize word map to track frequency of each word
        for (String word : words) {
            wordMap.put(word, wordMap.getOrDefault(word, 0) + 1);
        }

        // Experimental: Debug prints to understand the content of the word map
        System.out.println("Initial word frequency map: " + wordMap);

        int textLength = text.length();
        int wordLength = words[0].length();
        List<int[]> result = new ArrayList<>();

        // Loop through the text to find substrings
        for (int i = 0; i <= textLength - (wordLength * words.length); i++) {
            // Temporary map to track words found in the current substring
            Map<String, Integer> tempMap = new HashMap<>(wordMap);
            boolean validSubstring = true;

            // Check segments of text for valid word combinations
            for (int j = 0; j < words.length; j++) {
                // Determine the substring for current word
                int start = i + j * wordLength;
                String currentWord = text.substring(start, start + wordLength);

                // Experimental: Debug prints to see the current word being processed
                System.out.println("Checking word: " + currentWord + " at index: " + start);

                // If the word is valid, update the temporary map
                if (tempMap.containsKey(currentWord) && tempMap.get(currentWord) > 0) {
                    tempMap.put(currentWord, tempMap.get(currentWord) - 1);
                } else {
                    validSubstring = false;
                    break;
                }
            }

            // If a valid combination was found, save the indices
            if (validSubstring) {
                result.add(new int[]{i, i + (wordLength * words.length) - 1});
                // Experimentation: Output the found valid indices
                System.out.println("Valid substring found from index: " + i + " to " + (i + (wordLength * words.length) - 1));
            }
        }

        // Prepare the result for return and sort it based on indices
        int[][] sortedResult = result.toArray(new int[0][]);
        Arrays.sort(sortedResult, (a, b) -> {
            // Sorting criteria
            return (a[0] != b[0]) ? Integer.compare(a[0], b[0]) : Integer.compare(a[1], b[1]);
        });

        return sortedResult;
    }
}

