import java.util.*;

public class RestrictedPathCounter {

    private static final int MAX_VALUE = 1000;
    private List<List<int[]>> graph;

    public int countRestrictedPaths(int n, int[][] edges) {
        // Step 1: Construct the graph from edges
        initializeGraph(n, edges);

        // Step 2: Calculate shortest paths from node n to all other nodes
        int[] distance = bellmanFord(n);

        // Step 3: Count restricted paths
        return countPaths(distance);
    }

    private void initializeGraph(int n, int[][] edges) {
        graph = new ArrayList<>(n + 1);
        for (int i = 0; i <= n; i++) {
            graph.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            graph.get(edge[0]).add(new int[]{edge[1], edge[2]});
            graph.get(edge[1]).add(new int[]{edge[0], edge[2]}); // Undirected graph
        }
    }

    private int[] bellmanFord(int n) {
        int[] dist = new int[n + 1];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[n] = 0; // Start from node n

        boolean updated;
        for (int i = 0; i < n - 1; i++) {
            updated = false;
            for (int u = 1; u <= n; u++) {
                for (int[] neighbor : graph.get(u)) {
                    int v = neighbor[0], weight = neighbor[1];
                    if (dist[u] != Integer.MAX_VALUE && dist[u] + weight < dist[v]) {
                        dist[v] = dist[u] + weight;
                        updated = true;
                    }
                }
            }
            if (!updated) break; // No updates means we've converged
        }

        return dist;
    }

    private int countPaths(int[] distance) {
        // Step 4: Utilize depth-first search with memoization
        int n = distance.length - 1; 
        Map<Integer, Integer> memo = new HashMap<>();
        return dfs(1, n, distance, memo);
    }

    private int dfs(int current, int target, int[] distance, Map<Integer, Integer> memo) {
        // Base case: if we reach the target node
        if (current == target) {
            return 1;
        }
        if (memo.containsKey(current)) {
            return memo.get(current);
        }

        int totalPaths = 0;
        for (int[] neighbor : graph.get(current)) {
            int nextNode = neighbor[0];
            // Only proceed to neighbors that have greater distance
            if (distance[current] > distance[nextNode]) {
                totalPaths += dfs(nextNode, target, distance, memo);
            }
        }
        memo.put(current, totalPaths);
        System.out.println("Current Node: " + current + " Total Paths: " + totalPaths);
        return totalPaths;
    }

    public static void main(String[] args) {
        int n = 5;
        int[][] edges = {
                {1, 2, 3},
                {2, 3, 4},
                {3, 4, 5},
                {4, 5, 6},
                {1, 3, 2},
                {2, 4, 1}
        };
        RestrictedPathCounter rpc = new RestrictedPathCounter();
        int result = rpc.countRestrictedPaths(n, edges);
        System.out.println("Number of Restricted Paths: " + result);
    }
}

