        // Debug: Initial weights in the queue
        System.out.println("Initial stone weights: " + stoneWeights);

        // Perform the game until one or zero stones are left
        while (stoneWeights.size() > 1) {
            int stone1 = stoneWeights.poll(); // Get the heaviest stone
            int stone2 = stoneWeights.poll(); // Get the second heaviest stone

            // Debug: Print out the stones being smashed
            System.out.println("Smashing stones: " + stone1 + " and " + stone2);

            // Calculate the result of the smash
            if (stone1 != stone2) {
                int newWeight = stone1 - stone2;
                // Debug: New stone weight after smash
                System.out.println("New stone weight: " + newWeight);
                stoneWeights.add(newWeight); // Add the remaining stone back to the queue
            } else {
                // Debug: Both stones destroyed
                System.out.println("Both stones destroyed");
            }
        }

        // Final result: either the last remaining stone or 0 if no stones are left
        int result = stoneWeights.isEmpty() ? 0 : stoneWeights.poll();
        // Debug: Final result
        System.out.println("Last remaining stone's weight: " + result);

        return result;
    }
}

