    Node left, right;

    Node(int key, int value) {
        this.key = key;
        this.value = value;
        this.left = this.right = null;
    }
}

class BST {
    Node root;

    BST(Node root) {
        this.root = root;
    }

    Node insert(Node node) {
        Node current = root;
        Node parent = null;

        while (current != null) {
            parent = current;
            if (node.key > current.key) {
                current = current.right;
            } else {
                current = current.left;
            }
        }

        if (node.key < parent.key) {
            parent.left = node;
        } else {
            parent.right = node;
        }
        return node;
    }

    int findMaxDiff(Node refNode) {
        Node currentNode = refNode;

        if (currentNode.right != null) {
            currentNode = currentNode.right;
        } else {
            while (currentNode.left != null) {
                currentNode = currentNode.left;
            }
        }

        // Ensure parent is handled correctly (not present in original code).
        while (currentNode != null) {
            currentNode = currentNode.parent;  // Note: parent field should be added
        }

        return currentNode.key ^ root.key;  // XOR with the root's key
    }
}

class Solution {
    List<Integer> execute(int[] parent, int[][] queries) {
        BST bst = new BST(new Node(parent[0], 0));

        for (int i = 1; i < parent.length; i++) {
            bst.insert(new Node(parent[i], i));
        }

        Node node = bst.root;
        List<Integer> results = new ArrayList<>();

        for (int[] q : queries) {
            if (q[1] == 1) {
                int depthCounter = 0;
                Node current = node;

                while (current != null) {
                    current = (node.value > current.value) ? current.left : current.right;
                    depthCounter++;
                }
                results.add(depthCounter);
            }
        }
        return results;
    }
}

