public int[][] deriveSkyline(int[][] inputGrid) {
        int size = inputGrid.length;
        int[][] pointData = new int[2 * size * size][3];
        int pointIndex = 0;

        // Gathering points
        for (int row = 0; row < size; row++) {
            for (int col = 0; col < size; col++) {
                pointData[pointIndex][0] = row;
                pointData[pointIndex][1] = col;
                pointData[pointIndex][2] = inputGrid[row][col]; // height
                pointIndex++;
                pointData[pointIndex][0] = row; // additional point for zero height
                pointData[pointIndex][1] = col;
                pointData[pointIndex][2] = 0; 
                pointIndex++;
            }
        }

        // Sorting points perhaps to facilitate the skyline calculation
        Arrays.sort(pointData, (pointA, pointB) -> 
            (pointA[2] == pointB[2] ? pointA[0] - pointB[0] : pointA[2] - pointB[2])
        );

        List<int[]> skylinePoints = new ArrayList<>();
        int leftIndex = 0, rightIndex = 0;

        // Iterating through points for skyline construction
        for (int i = 0; i < pointData.length; i++) {
            int[] currentPoint = pointData[i];
            int rowIndex = currentPoint[0], colIndex = currentPoint[1], heightValue = currentPoint[2];

            // Debugging instrumentation
            System.out.printf("Examining point at (%d, %d) with height %d\n", rowIndex, colIndex, heightValue);

            // Advanced iteration with skyline formation logic
            while (leftIndex < size && rightIndex < size && inputGrid[rowIndex][colIndex] != heightValue) {
                if (inputGrid[rowIndex][colIndex] > heightValue) {
                    inputGrid[rowIndex][colIndex] = 0; // Flattening
                    rightIndex++;
                } else {
                    inputGrid[rowIndex][colIndex] = heightValue; // Restoring height
                    leftIndex++;
                }
                skylinePoints.add(new int[]{rowIndex, colIndex});
                // Debugging skyline growth
                System.out.printf("Skyline updated with point (%d, %d)\n", rowIndex, colIndex);
            }
        }

        // Converting list to array to return
        return skylinePoints.stream().toArray(int[][]::new);
    }

