public class Solution {

    // TODO: Implement and document the peak index search for a mountain array
    public int peakIndexInMountainArray(int[] arr) {
        // Initialize left and right pointers
        int left = 0;
        int right = arr.length - 1;

        // Begin binary search for peak
        while (left <= right) {
            int mid = (left + right) / 2;

            // Check if mid is peak
            if (isPeak(arr, mid)) {
                return mid;
            } else if (arr[mid] > arr[mid - 1]) {
                // Move to the right half
                left = mid + 1;
            } else {
                // Move to the left half
                right = mid - 1;
            }
        }

        // Debug output: Peak was not found (should not happen in a valid mountain array)
        System.out.println("Peak not found!");  
        return -1;
    }

    private boolean isPeak(int[] arr, int mid) {
        return arr[mid] > arr[mid - 1] && arr[mid] > arr[mid + 1];
    }

    // TODO: Implement the longest palindromic substring search
    public String longestPalindrome(String s) {
        if (s == null || s.length() == 0) return "";

        int start = 0, end = 0;

        for (int i = 0; i < s.length(); i++) {
            // Experiment: Check odd-length palindromes
            int len1 = expandAroundCenter(s, i, i);
            // Experiment: Check even-length palindromes
            int len2 = expandAroundCenter(s, i, i + 1);
            int length = Math.max(len1, len2);

            // Update start and end indices for longest palindrome found
            if (length > end - start) {
                start = i - (length - 1) / 2;
                end = i + length / 2;
            }
        }

        return s.substring(start, end + 1);
    }

    private int expandAroundCenter(String s, int left, int right) {
        // Expand while within bounds and characters match
        while (left >= 0 && right < s.length() && s.charAt(left) == s.charAt(right)) {
            left--;
            right++;
        }
        return right - left - 1; // Return length of palindrome
    }

