        // Run second algorithm: O(n log n) time complexity (not optimal for space)
        int[] sortedData = inputData.clone();
        quickSort(sortedData, 0, sortedData.length - 1);
        System.out.println("Sorted Array: " + java.util.Arrays.toString(sortedData));
