    // Hypothetical efficient function to find max value in O(n) time & O(1) space
    private static int findMaxInPlace(int[] array) {
        int max = array[0];
        for (int i = 1; i < array.length; i++) {
            if (array[i] > max) {
                max = array[i]; // updates max only when a larger value is found
            }
        }
        return max; // returns the maximum value found in the array
    }

    // QuickSort implementation for O(n log n) complexity
    private static void quickSort(int[] array, int start, int end) {
        if (start < end) {
            int partitionIndex = partition(array, start, end);
            quickSort(array, start, partitionIndex - 1);
            quickSort(array, partitionIndex + 1, end);
        }
    }

    // Partition method used in QuickSort
    private static int partition(int[] array, int start, int end) {
        int pivot = array[end]; // Selecting the last element as the pivot
        int i = (start - 1); // Pointer for the smaller element

        for (int j = start; j < end; j++) {
            // If current element is smaller than or equal to pivot
            if (array[j] <= pivot) {
                i++; // increment index of smaller element
                swap(array, i, j); // swap the elements
            }
        }
        swap(array, i + 1, end); // swap the pivot element to the correct position
        return i + 1; // return the partition index
    }

    // Method to swap two elements in an array
    private static void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp; // swap the elements
    }
}

