    static class Solution {
        static final int MOD = 998244353;

        public void solve(int testNumber, InputReader in, PrintWriter out) {
            int n = in.nextInt();
            String s = in.next();
            // TODO: Log initial input parameters for debugging
            System.out.printf("Debug - Test case %d: n = %d, s = %s%n", testNumber, n, s);

            out.println(dfs(1, s).x);
        }

        private Result dfs(int u, String s) {
            // Debug: Check current depth
            System.out.printf("Debug - Entering dfs at depth: %d, Current index: %d%n", u, u * 2);
            if (u * 2 > s.length()) {
                // Base case reached
                return new Result(1, s.substring(u - 1, u));
            }

            Result left = dfs(u * 2, s);
            Result right = dfs(u * 2 + 1, s);

            Result res = new Result(left.x * right.x % MOD, s.substring(u - 1, u) + left.s + right.s);

            // Experiment: Consider how different subtree values affect result
            if (!left.s.equals(right.s)) {
                res.x = res.x * 2 % MOD;
                // Debug: Log when different values are found
                System.out.printf("Debug - Different subtrees at index %d: left = %s, right = %s, res.x = %d%n", u, left.s, right.s, res.x);
            }

            if (left.s.compareTo(right.s) > 0) {
                String temp = left.s;
                left.s = right.s;
                right.s = temp;
            }

            res.s = s.substring(u - 1, u) + left.s + right.s;

            // Debug: Log result of current dfs node
            System.out.printf("Debug - Leaving dfs at depth: %d, Result: %s, Count: %d%n", u, res.s, res.x);

            return res;
        }

        class Result {
            int x;
            String s;

            Result(int x, String s) {
                this.x = x;
                this.s = s;
            }
        }
    }

