import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;

class Solution {
    private HashMap<Integer, List<Integer>> graph = new HashMap<>();
    private HashSet<Integer> specialNodes = new HashSet<>();

    // For debugging: to track node connections
    private void debugGraph() {
        System.out.println("Graph connections:");
        for (var entry : graph.entrySet()) {
            System.out.println("Node " + entry.getKey() + " connects to " + entry.getValue());
        }
    }

    public int countSpecialNodes(int n, int[][] edges) {
        // Construct graph from edges
        for (int[] edge : edges) {
            graph.putIfAbsent(edge[0], new ArrayList<>());
            graph.putIfAbsent(edge[1], new ArrayList<>());
            graph.get(edge[0]).add(edge[1]);
            graph.get(edge[1]).add(edge[0]);
        }

        debugGraph(); // Call debugging to check construction

        // Check each node for special status
        for (int i = 0; i < n; i++) {
            if (isSpecialNode(i)) {
                specialNodes.add(i);
            }
        }

        return specialNodes.size();
    }

    private boolean isSpecialNode(int node) {
        List<Integer> connections = graph.get(node);

        // Check for the number of children nodes
        if (connections.size() <= 1) {
            return false; // Not a fork if <= 1 connection
        }

        // Assume it is special until proven otherwise
        boolean isSpecial = true;

        // Analyze connections
        for (int neighbor : connections) {
            if (graph.get(neighbor).size() < 2) {
                isSpecial = false; // Not special if a direct child has less than 2 connections
                break;
            }
        }

        return isSpecial;
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        int n1 = 4;
        int[][] edges1 = {{0, 1}, {0, 2}, {1, 3}, {2, 3}};
        System.out.println("Special nodes count for example 1: " + sol.countSpecialNodes(n1, edges1));

        int n2 = 5;
        int[][] edges2 = {{0, 1}, {0, 2}, {0, 3}, {1, 2}};
        System.out.println("Special nodes count for example 2: " + sol.countSpecialNodes(n2, edges2));

        int n3 = 7;
        int[][] edges3 = {{0, 1}, {1, 2}, {3, 1}, {4, 0}, {0, 5}, {5, 6}};
