    public int determineMaxArea(int m, int n, List<Integer> deletedX) {
        // Handle edge cases
        if (deletedX.isEmpty() || m <= 1 || n <= 1) {
            System.out.println("Edge case detected: returning default area.");
            return (m - 1) * (n - 1);
        }

        int effectiveM = m - 1;
        int effectiveN = n - 1;
        int[][] memo = new int[effectiveM][effectiveN];

        // Initiate calculation of the maximum area
        return calculateArea(m, n, deletedX, memo);
    }

    private int calculateArea(int m, int n, List<Integer> deletedX, int[][] memo) {
        int effectiveM = m - 1, effectiveN = n - 1;

        // Check if already calculated
        if (memo[0][0] != 0) {
            System.out.println("Using memoized result for area.");
            return memo[0][0];
        }

        // Handle corner cases and record findings
        if ((m == 1 && n == 1) || (deletedX.get(0) == 1 && effectiveN == 1)) {
            memo[effectiveM][effectiveN] = 1;
            System.out.println("Corner case 1: area is 1.");
            return 1;
        }
        if ((deletedX.get(0) == 1 && effectiveM == 1)) {
            memo[effectiveM][effectiveN] = 1;
            System.out.println("Corner case 2: area is 1.");
            return 1;
        }

        // Conditional calculations based on deleted dimensions
        if (deletedX.get(0) < 2) {
            System.out.println("Recursively building area - reducing height.");
            memo[0][0] = calculateArea(m - 1, n, deletedX, memo);
        }
        if (deletedX.get(0) >= 2) {
            // Handle scenarios for available horizontal and vertical spaces
            int minM = m - deletedX.get(0);
            int minN = n - deletedX.get(0);
            System.out.println("Exploring area with minM: " + minM + " minN: " + minN);

            if (deletedX.get(0) <= effectiveM || deletedX.get(0) <= effectiveN) {
                System.out.println("Removing cells to maximize area - calling recursive function.");
                memo[0][0] = calculateArea(m - minM, n - minN, deletedX, memo);
            }

            // More detailed branches for specific scenarios
            if (deletedX.get(0) == effectiveM && deletedX.get(0) == effectiveN + 1) {
                System.out.println("Case: reducing both dimensions, calling recursive function.");
                memo[0][0] = calculateArea(m - deletedX.get(0), n - minN, deletedX, memo);
            }
            if (deletedX.get(0) == effectiveM + 1 && deletedX.get(0) == effectiveN) {
                System.out.println("Case: reducing both dimensions, calling recursive function.");
                memo[0][0] = calculateArea(m - minM, n - deletedX.get(0), deletedX, memo);
            }
