public class ResearchSolution {
    public static void main(String[] args) throws FileNotFoundException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
        // Initialize data structures for stacks
        Map<Integer, Integer> stack1 = new HashMap<>();
        Map<Integer, Integer> stack2 = new HashMap<>();

        // Capture input data
        String[] input = in.readLine().split(" ");
        int n = Integer.parseInt(input[0]);
        int[] a = Arrays.stream(in.readLine().split(" ")).map(Integer::parseInt).toArray();

        // Populate stacks with values
        for (int i = 0; i < a.length; i++) {
            stack1.put(a[i], a[i]);
            stack1.put(i, a[i]);
        }

        // Initialize tracking variables
        int winner = 0;
        double t = 0; // Time
        double h = 0; // Height

        // Begin game simulation
        while (t > 0 && h > 0) {
            if (stack1.isEmpty()) {
                t--; // Decrement time
                winner = 1; // Update winner status
            } else if (stack2.isEmpty()) {
                // Perform removal function on stack1
                stack1 = removeWinning(stack1);
                h--; // Decrement height
            } else {
                // Perform removals from both stacks
                stack1 = removeWinning(stack1);
                stack2 = removeWinning(stack2);
                t--; // Decrement time for turn
            }
        }

        // Output results based on game state
        if (t > 0) {
            System.out.println("T");
        } else {
            System.out.println("HL");
        }
    }

    static Map<Integer, Integer> removeWinning(Map<Integer, Integer> stones) {
        int remove = Integer.MIN_VALUE; // Initialize to minimum value

        // Find the appropriate value to remove
        while (stones.containsKey(remove)) remove = stones.get(remove);

        // Prepare the resultant map
        Map<Integer, Integer> result = new HashMap<>();
        for (int i = 0; i < stones.size(); i++) {
            stones.remove(remove); // Remove the identified value
            result.put(remove, i); // Log the removal
        }
        return result;
    }
}

