        for (int i = 0; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }
        return graph;
    }

    private static void populateGraph(Scanner sc, List<Integer>[] graph, int n) {
        for (int i = 0; i < n - 1; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            graph[u].add(v);
            graph[v].add(u);
            // Debug info: edge addition
            System.out.printf("Edge added between %d and %d%n", u, v);
        }
    }

    private static void processQuery(Scanner sc, List<Integer>[] graph) {
        int x = sc.nextInt();
        int y = sc.nextInt();
        int a = sc.nextInt();
        int b = sc.nextInt();
        int k = sc.nextInt();

        // Analyze query parameters
        System.out.printf("Processing query: x=%d, y=%d, a=%d, b=%d, k=%d%n", x, y, a, b, k);

        if (k == 1) {
            evaluateCondition(graph, a, x, y);
        } else {
            manageTemporaryConnection(graph, a, x, y);
        }
    }

    private static void evaluateCondition(List<Integer>[] graph, int a, int x, int y) {
        if (graph[a].contains(x) && graph[a].contains(y)) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }

    private static void manageTemporaryConnection(List<Integer>[] graph, int a, int x, int y) {
        if (graph[a].contains(x) && graph[a].contains(y)) {
            establishConnection(graph, x, y);
            evaluateCondition(graph, a, x, y);
            removeConnection(graph, x, y);
        } else {
            System.out.println("NO");
        }
    }

    private static void establishConnection(List<Integer>[] graph, int x, int y) {
        graph[x].add(y);
        graph[y].add(x);
        // Debug info: connection established
        System.out.printf("Connection established between %d and %d%n", x, y);
    }

    private static void removeConnection(List<Integer>[] graph, int x, int y) {
        graph[x].remove((Integer) y);
        graph[y].remove((Integer) x);
        // Debug info: connection removed
        System.out.printf("Connection removed between %d and %d%n", x, y);
    }
}

