import java.util.Scanner;

public class WebOfLiesResearch {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int nobles = scanner.nextInt();  // Number of nobles
        int friendships = scanner.nextInt();  // Initial friendships
        boolean[][] friendshipMatrix = new boolean[nobles + 1][nobles + 1];  // Adjacency matrix for friendships

        // Reading friendships and populating the matrix
        for (int i = 0; i < friendships; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            friendshipMatrix[u][v] = true;
            friendshipMatrix[v][u] = true;
        }

        int queries = scanner.nextInt();  // Number of queries
        int remainingNobles = nobles;  // Track remaining nobles

        // Processing each query
        for (int i = 0; i < queries; i++) {
            int queryType = scanner.nextInt();  // Type of query
            if (queryType == 1) {  // Add friendship
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                friendshipMatrix[u][v] = true;
                friendshipMatrix[v][u] = true;

                // Check vulnerability and adjust noble count
                if (isVulnerable(u, friendshipMatrix)) {
                    remainingNobles--;
                    System.out.println("Noble " + u + " vulnerable, remaining: " + remainingNobles);
                }
                if (isVulnerable(v, friendshipMatrix)) {
                    remainingNobles--;
                    System.out.println("Noble " + v + " vulnerable, remaining: " + remainingNobles);
                }
            } else if (queryType == 2) {  // Remove friendship
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                friendshipMatrix[u][v] = false;
                friendshipMatrix[v][u] = false;

                // Re-evaluate nobility status
                if (!isVulnerable(u, friendshipMatrix) && hasFriends(u, friendshipMatrix)) {
                    remainingNobles++;
                    System.out.println("Noble " + u + " no longer vulnerable, remaining: " + remainingNobles);
                }
                if (!isVulnerable(v, friendshipMatrix) && hasFriends(v, friendshipMatrix)) {
                    remainingNobles++;
                    System.out.println("Noble " + v + " no longer vulnerable, remaining: " + remainingNobles);
                }
            } else {  // Output remaining nobles
                System.out.println("Remaining nobles: " + remainingNobles);
            }
        }
    }

    // Check if noble is vulnerable
    private static boolean isVulnerable(int u, boolean[][] friendshipMatrix) {
        for (int v = 1; v < friendshipMatrix.length; v++) {
            if (friendshipMatrix[u][v] && u > v) {
                return false;
            }
        }
        return hasFriends(u, friendshipMatrix);
    }

    // Check if noble has friends
    private static boolean hasFriends(int u, boolean[][] friendshipMatrix) {
        for (int v = 1; v < friendshipMatrix.length; v++) {
            if (friendshipMatrix[u][v]) {
                return true;
            }
        }
        return false;
    }
}

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;

    public TreeNode() {}

    public TreeNode(int val) {
        this.val = val;
    }

    public TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    // Research: Aim to identify if there's a pair with a sum of k in the binary tree.
    public boolean findTarget(TreeNode root, int k) {
        Set<Integer> seenValues = new HashSet<>();
        // Debug print to monitor start of finding target process.
        System.out.println("Starting to find target: " + k);
        return findTarget(root, k, seenValues);
    }

    private boolean findTarget(TreeNode root, int k, Set<Integer> seenValues) {
        // Base case: if the node is null, exit the recursion.
        if (root == null) {
            return false;
        }

        // Checking if the complement exists in the set.
        if (seenValues.contains(k - root.val)) {
            System.out.println("Found a pair: " + root.val + " + " + (k - root.val) + " = " + k);
            return true;
        }

        // Adding current value to the set for future reference.
        seenValues.add(root.val);
        System.out.println("Adding value: " + root.val + " to seen values.");

        // Recursive calls to left and right children
        boolean foundInLeft = findTarget(root.left, k, seenValues);
        boolean foundInRight = findTarget(root.right, k, seenValues);

        // Returning true if found in either subtree.
        return foundInLeft || foundInRight;
    }
}

