import static java.lang.Math.*;
import java.util.HashMap;

class Solution {
    public long sellingWood(int m, int n, int[][] prices) {
        // Initialize memoization map for price lookups
        HashMap<Long, Long> memo = new HashMap<>();
        for (int[] price : prices) {
            long key = ((long) price[0] * 1000000) + price[1];
            memo.put(key, (long) price[2]);
        }

        // Initialize dynamic programming table
        long[][] dp = new long[m + 1][n + 1];

        // Fill the DP table
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                long cutHere = memo.getOrDefault((i * 1000000) + j, 0);

                // Experimental cuts vertically
                for (int x = 1; x < i; x++) {
                    cutHere = max(cutHere, dp[x][j] + dp[i - x][j]);
                }

                // Experimental cuts horizontally
                for (int y = 1; y < j; y++) {
                    cutHere = max(cutHere, dp[i][y] + dp[i][j - y]);
                }

                dp[i][j] = cutHere; // Store the max value for current dimension
                // Debug print statement to monitor DP values
                System.out.printf("DP[%d][%d] = %d\n", i, j, dp[i][j]);
            }
        }

        // Final return value, total maximum profit
        return dp[m][n];
    }
}

