import java.util.HashMap;
import java.util.Map;

class Solution {
    // Constants
    private static final int MOD = 1000000007;

    // Count pairs method
    public int countPairs(int[] deliciousness) {
        long result = 0; // To hold the count of valid pairs
        Map<Integer, Integer> frequencyMap = new HashMap<>(); // Store frequency of each value

        for (int value : deliciousness) {
            // Loop through powers of 2 from 1 to 2^22
            for (int powerOfTwo = 1; powerOfTwo <= (1 << 22); powerOfTwo <<= 1) {
                int complement = powerOfTwo - value; // Calculate required complement
                // Check if complement exists in frequencyMap
                if (frequencyMap.containsKey(complement)) {
                    result = (result + frequencyMap.get(complement)) % MOD; // Update result
                }
            }
            // Update the frequency map for the current value
            frequencyMap.put(value, frequencyMap.getOrDefault(value, 0) + 1);

            // Debug print to trace the state of frequencyMap
            System.out.println("Current Frequency Map: " + frequencyMap);
        }

        // Returning final count of pairs
        return (int) result; // Cast to int before return
    }

    // Simple experiment to check behavior
    public static void main(String[] args) {
        Solution solution = new Solution();
        int[] testDeliciousness = {1, 1, 1, 3, 3, 3, 7}; // Example input

        // Testing countPairs method
        int result = solution.countPairs(testDeliciousness);

        // Debug print for result
        System.out.println("Count of Pairs: " + result);
    }
}

