public class ResearchSolution {
    public int findCommonNode(int[] edges, int node1, int node2) {
        int numNodes = edges.length;
        int[] parent = new int[numNodes];
        int[] distanceToLeader = new int[numNodes];

        // Step 1: Initialize each node to be its own parent
        for (int i = 0; i < numNodes; i++) {
            parent[i] = i;
            distanceToLeader[i] = 0; // Initialize distances
        }

        // TODO: Identify Cycle Roots and Component Leaders
        // Simple DFS or BFS to determine leaders
        // For now, assuming we use DFS

        for (int i = 0; i < numNodes; i++) {
            if (parent[i] == i) {
                // Debug: Output current node being checked
                System.out.println("Checking component lead for node: " + i);
                dfsFindLeaders(edges, i, parent, distanceToLeader);
            }
        }

        // Step 2: Collect paths to leaders from both node1 and node2
        // Creating a set to store visited nodes for paths
        Set<Integer> pathToNode1 = new HashSet<>();
        Set<Integer> pathToNode2 = new HashSet<>();

        tracePathToLeader(node1, parent, pathToNode1, distanceToLeader);
        tracePathToLeader(node2, parent, pathToNode2, distanceToLeader);

        // Step 3: Calculate distances and identify potential common nodes
        int minMaxDistance = Integer.MAX_VALUE;
        int commonNode = -1;

        // Evaluate potential common nodes
        for (int node : pathToNode1) {
            if (pathToNode2.contains(node)) {
                // Calculate maximum distance
                int maxDistance = Math.max(distanceToLeader[node1], distanceToLeader[node2]);

                // Debug: Print potential common node and max distance
                System.out.println("Potential common node: " + node + ", Max Distance: " + maxDistance);

                if (maxDistance < minMaxDistance) {
                    minMaxDistance = maxDistance;
                    commonNode = node;
                } else if (maxDistance == minMaxDistance && node < commonNode) {
                    commonNode = node; // Lower index preferred
                }
            }
        }

        return commonNode;  // Result output
    }

    private void dfsFindLeaders(int[] edges, int current, int[] parent, int[] distance) {
        // TODO: Implement DFS to find leaders
        // Marking node as visited and finding cycles
        // For now, assuming proper cycle detection

        if (edges[current] != -1) {
            int next = edges[current];
            // Simple cycle detection logic
            if (parent[next] != current) {
                parent[next] = current; // Set the leader
                distance[next] = distance[current] + 1; // Increment distance
                dfsFindLeaders(edges, next, parent, distance); // Continue DFS
            }
        }
    }

    private void tracePathToLeader(int startNode, int[] parent, Set<Integer> visited, int[] distance) {
        // Trace back from the node to find all nodes leading to its leader
        while (parent[startNode] != startNode) {
            visited.add(startNode);
            startNode = parent[startNode];
        }
        visited.add(startNode); // Add leader itself
    }
}

