public class ResearchPrototype {
    private static final FastScanner input = new FastScanner();
    private static final PrintWriter output = new PrintWriter(System.out);
    private static final PrintWriter errorOutput = new PrintWriter(System.err);

    public static void main(String[] args) {
        int testCases = input.nextInt();
        for (int caseIndex = 0; caseIndex < testCases; caseIndex++) {
            performCalculation();
        }
        output.close();
        errorOutput.close();
    }

    private static void performCalculation() {
        int dimension = input.nextInt();
        int total = input.nextInt();
        int[][] matrix = new int[dimension][dimension];

        // Initial matrix setup with 1's based on the total
        for (int index = 0; index < total; index++) {
            int rowIndex = index % dimension;
            int colIndex = (index / dimension) % dimension;
            matrix[rowIndex][colIndex] = 1; // Note: possible optimization here
        }

        // Establish row metrics
        int highestRow = 0;
        int lowestRow = dimension;
        for (int row = 0; row < dimension; row++) {
            int currentRowSum = 0;
            for (int col = 0; col < dimension; col++) {
                currentRowSum += matrix[row][col];
            }
            highestRow = Math.max(currentRowSum, highestRow);
            lowestRow = Math.min(currentRowSum, lowestRow);
        }

        // Establish column metrics
        int highestCol = 0;
        int lowestCol = dimension;
        for (int col = 0; col < dimension; col++) {
            int currentColSum = 0;
            for (int row = 0; row < dimension; row++) {
                currentColSum += matrix[row][col];
            }
            highestCol = Math.max(currentColSum, highestCol);
            lowestCol = Math.min(currentColSum, lowestCol);
        }

        // Calculate the final value based on matrix metrics
        int resultValue = (highestRow - lowestRow) * (highestRow - lowestRow) + 
                          (highestCol - lowestCol) * (highestCol - lowestCol);
        output.println(resultValue);

        // Debug: visualize the matrix
        for (int row = 0; row < dimension; row++) {
            for (int col = 0; col < dimension; col++) {
                output.print(matrix[row][col]);
            }
            output.println();
        }
    }

    private static class FastScanner {
        private final BufferedReader bufferedReader = new BufferedReader(new InputStreamReader(System.in));
        private StringTokenizer tokenizer = new StringTokenizer("");

        String next() {
            // Enhanced token fetcher
            while (!tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(bufferedReader.readLine());
                } catch (IOException e) {
                    errorOutput.println("Input error: " + e.getMessage());
                }
            }
            return tokenizer.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }
}

