import java.util.ArrayList;
import java.util.List;

class Solution {
    // Method to determine if the sequence is strictly increasing
    static boolean isStrictlyIncreasing(List<Integer> seq) {
        for (int i = 0; i < seq.size() - 1; i++) {
            if (seq.get(i) >= seq.get(i + 1)) {
                return false;
            }
        }
        return true;
    }

    // Method to delete an element at a specific index
    static List<Integer> deleteElement(List<Integer> seq, int ind) {
        List<Integer> newSeq = new ArrayList<>();
        for (int i = 0; i < seq.size(); i++) {
            if (i != ind) {
                newSeq.add(seq.get(i));
            }
        }
        return newSeq;
    }

    // Main method to determine if we can make the sequence strictly increasing
    static boolean canFormStrictlyIncreasing(List<Integer> nums) {
        if (isStrictlyIncreasing(nums)) {
            return true;
        }
        for (int ind = 0; ind < nums.size(); ind++) {
            List<Integer> modifiedSeq = deleteElement(nums, ind);
            if (isStrictlyIncreasing(modifiedSeq)) {
                return true;
            }
        }
        return false;
    }

    // Debugging
    public static void main(String[] args) {
        System.out.println("Test 1: " + canFormStrictlyIncreasing(List.of(1, 2, 10, 5, 7))); // Expect true
        System.out.println("Test 2: " + canFormStrictlyIncreasing(List.of(2, 3, 1, 2))); // Expect false
        System.out.println("Test 3: " + canFormStrictlyIncreasing(List.of(1, 1, 1))); // Expect false
        System.out.println("Test 4: " + canFormStrictlyIncreasing(List.of(1, 2, 1, 1))); // Expect false
    }
}

