public class LeapYearChecker {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int year;

        System.out.println("Enter year to check whether it is a leap year or not: ");
        year = scanner.nextInt();

        // Explore: Check if the year is a leap year
        boolean isLeapYear = isLeapYear(year);
        System.out.println("Year " + year + " is " + (isLeapYear ? "a leap year." : "not a leap year."));

        // TODO: Experiment with different years or user input scenarios
        // Debug print: Display intermediate calculations for leap year determination
        if (isLeapYear) {
            System.out.println("DEBUG: " + year + " is divisible by 4 and not by 100 or by 400.");
        } else {
            System.out.println("DEBUG: " + year + " fails leap year conditions.");
        }

        scanner.close();
    }

    private static boolean isLeapYear(int year) {
        // Leap year condition: Divisible by 4, not divisible by 100, or divisible by 400
        return (year % 4 == 0 && year % 100 != 0) || (year % 400 == 0);
    }
}

