        Map<Integer, Integer> count = new HashMap<>(); // Frequency map
        for (int right = 0; right < nums.length; right++) {
            count.put(nums[right], count.getOrDefault(nums[right], 0) + 1); // Update count

            // Debug print to monitor distinct elements
            System.out.println("Right pointer at: " + right + ", current count map: " + count);

            while (count.size() > k) { // Shrinking window when we exceed k distinct elements
                count.put(nums[left], count.get(nums[left]) - 1);
                if (count.get(nums[left]) == 0) {
                    count.remove(nums[left]);
                }
                left++; // Move left pointer to shrink window
                // Debug print to observe shrinking action
                System.out.println("Left pointer moved to: " + left + ", current count map: " + count);
            }
            // Counting valid subarrays
            res += right - left + 1;
            // Debug print for each valid subarray count addition
            System.out.println("Current result: " + res + ", from left: " + left + " to right: " + right);
        }
        // Final result for the current k
        return res;
    }

