public class Solution {
    private Vector<Integer> nums;
    private int k;

    public int findMaxScore() {
        // Initialize result to a min value for comparison.
        int result = Integer.MIN_VALUE;

        // Start the depth-first search.
        result = dfs(0, 0, new ArrayList<>());
        return result;
    }

    private int dfs(int remainingK, int currentScore, List<Integer> pathsTaken) {
        if (remainingK <= 0) {
            // Debug: Print the current score and paths taken
            System.out.println("Final Score: " + (currentScore + sum(pathsTaken)));
            return currentScore + sum(pathsTaken);
        }

        int maxScore = 0;
        for (int i = 0; i < nums.size(); i++) {
            // Identify the next element to work with.
            int element = nums.get(i);

            // Modify the element and conduct the next recursive call.
            nums.set(i, element ^ 1); // Flip the bit for processing
            int resScore = dfs(remainingK - 1, currentScore + 1, new ArrayList<>(pathsTaken) {{ add(element); }}); 
            nums.set(i, element ^ 1); // Restore the original element

            // Debug: Log the maximum score after processing this element
            System.out.println("Processed Element: " + element + ", Current Max Score: " + Math.max(maxScore, resScore));
            maxScore = Math.max(maxScore, resScore);
        }

        return maxScore;
    }

    private int sum(List<Integer> list) {
        // Simple sum implementation for integers in the list
        int total = 0;
        for (int num : list) {
            total += num;
        }
        return total;
    }
}

