    // For each node, aggregate incident counts and node counts.
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++)
            root.aggregateNodeCounts(i, temporaryStorage[j]); // Aggregateing node counts.
        root.aggregateIncidentCounts(i, pairsCount.getOrDefault((j << 16) | i, 0));
    }

    // Prepare results based on the given queries.
    int[] resultArray = new int[queries.length];
    for (int i = 0; i < queries.length; i++) {
