public int minFallingPathSum(int[][] matrix) {
    int n = matrix.length;
    // Step 1: Initialize DP table
    int[][] dp = new int[n][n];

    // Fill the first row from the matrix
    for (int i = 0; i < n; i++) {
        dp[0][i] = matrix[0][i];
    }

    // Step 2: Populate the DP table based on falling paths
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < n; j++) {
            int min = Integer.MAX_VALUE; // Reset min to max int value for each cell
            // Looking at cells directly above (i-1)
            for (int k = Math.max(0, j - 1); k <= Math.min(n - 1, j + 1); k++) {
                min = Math.min(min, dp[i - 1][k]); // Find the minimum in the range
            }
            dp[i][j] = min + matrix[i][j]; // Update dp with min path sum
            // Debug output to track state
            System.out.println("dp[" + i + "][" + j + "] updated to " + dp[i][j]);
        }
    }

    // Step 3: Finding the minimum path sum from the last row
    int minSum = Integer.MAX_VALUE; // Initialize to a large value
    for (int i = 0; i < n; i++) {
        minSum = Math.min(minSum, dp[n - 1][i]);
        // Debug output for last row
        System.out.println("Checking last row dp[" + (n - 1) + "][" + i + "] = " + dp[n - 1][i]);
    }

    // Final result, debug output for minimum sum
    System.out.println("Minimum Falling Path Sum: " + minSum);
    return minSum;
}

public long kSum(int[] nums, int k) {
    // TODO: Investigate the impact of input order on performance
    Arrays.sort(nums);

    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[0] - b[1], a[0] - a[1]));

    long maxSum = 0;
    for (int i = 0; i < nums.length; i++) {
        // Debug print: Checking value of nums[i]
        System.out.println("Current number: " + nums[i]);

        if (nums[i] >= 0) {
            maxSum += nums[i];
        } else {
            // Debug print: Adding negative number to the queue
            System.out.println("Adding to queue: " + (maxSum + nums[i]));
            pq.offer(new long[] {maxSum + nums[i], nums[i]});
        }
    }

    long kthLargest = maxSum;
    // Experiment: Measure execution time for k iterations
    long startTime = System.nanoTime();

    for (int i = 0; i < k - 1; i++) {
        if (!pq.isEmpty()) {
            long[] currSum = pq.poll();
            System.out.println("Current k-th largest: " + currSum[0]);
            pq.offer(new long[] {currSum[0] - currSum[1], -currSum[1]});
            kthLargest = currSum[0];
        } else {
            // TODO: Handle case where k exceeds available sums
            System.out.println("Queue is empty before reaching k! Exiting.");
            break;
        }
    }

    long elapsedTime = System.nanoTime() - startTime;
    // Debug print: Execution time for finding k-th largest
    System.out.println("Elapsed time: " + elapsedTime + " nanoseconds");
    return kthLargest;
}

