public int[] findNumOfValidWords(String[] words, String[] puzzles) {
    TreeSet<Character>[] wordsByFirstLetter = new TreeSet[26];
    for (int i = 0; i < 26; i++) wordsByFirstLetter[i] = new TreeSet<Character>();

    // Build character array based on words
    for (String word : words) {
        char firstChar = word.charAt(0);
        int index = firstChar - 'a';
        if (wordsByFirstLetter[index].isEmpty()) 
            wordsByFirstLetter[index].add('z' + 1);  // Adding sentinel
        wordsByFirstLetter[index].addAll(word.toCharArray());
    }

    int[] output = new int[puzzles.length];

    // Loop through each puzzle
    for (int puzzleIndex = 0; puzzleIndex < puzzles.length; puzzleIndex++) {
        String puzzle = puzzles[puzzleIndex];
        if (wordsByFirstLetter[puzzle.charAt(0) - 'a'].isEmpty()) {
            output[puzzleIndex] = 0;
            continue;
        }

        char[] charArray = puzzle.toCharArray();
        boolean allMatch = true;

        // Check each character in the puzzle
        for (int i = 1; i < charArray.length; i++) {
            int charIndex = charArray[i] - 'a';
            if (wordsByFirstLetter[charIndex].isEmpty() || !wordsByFirstLetter[charIndex].contains(charArray[i])) {
                allMatch = false;
                break;
            } else {
                if (wordsByFirstLetter[charIndex].first() > charArray[i])
                    charArray[i] = wordsByFirstLetter[charIndex].first();
            }
        }

        if (allMatch && !wordsByFirstLetter[puzzle.charAt(0) - 'a'].isEmpty()) {
            output[puzzleIndex] = wordsByFirstLetter[puzzle.charAt(0) - 'a']
                                   .tailSet(puzzle.charAt(0), true).size();
        } else {
            output[puzzleIndex] = 0;
        }

        // Debug Info: Output the puzzle being processed and intermediate results
        System.out.println("Puzzle: " + puzzle + " | Valid Words Count: " + output[puzzleIndex]);
    }

    // Final Output Verification
    for (int i = 0; i < output.length; i++) {
        System.out.println("Puzzle " + puzzles[i] + " has " + output[i] + " valid words.");
    }

    return output;
}

import java.util.Scanner;

public class ArmchairsResearch {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter number of chairs:");
        int n = scanner.nextInt();
        int[] a = new int[n];
        System.out.println("Enter chair states (0 or 1):");
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }

        int result = evaluateArmchairConfiguration(n, a);
        System.out.println("Minimum time to rearrange: " + result);
    }

    private static int evaluateArmchairConfiguration(int n, int[] a) {
        int occupied = 0;

        // Counting occupied chairs
        for (int i = 0; i < n; i++) {
            if (a[i] == 1) occupied++;
        }

        // If no chairs are occupied, no time is needed
        if (occupied == 0) return 0;

        int[][] dp = new int[2][occupied + 1];
        for (int[] row : dp) {
            for (int i = 1; i <= occupied; i++) {
                row[i] = Integer.MAX_VALUE; // Initialize to MAX value for comparison
            }
        }

        int occupiedIdx = 0; // Tracks occupied chair indices
        for (int i = 0; i < n; i++) {
            if (a[i] == 1) {
                // Iterating to update the DP table
                for (int j = occupiedIdx + 1; j >= 1; j--) {
                    int cost = dp[i % 2][j] + 2 * (i + 1) - j * 2 + 1;
                    dp[(i + 1) % 2][j] = Math.min(dp[(i + 1) % 2][j], cost);
                }

                dp[(i + 1) % 2][1] = i; // Set first occupied index
                occupiedIdx++; // Update how many occupied chairs we've found
            } else {
                // Transitioning the row for unoccupied chairs
                for (int j = 0; j <= occupied; j++) {
                    dp[(i + 1) % 2][j] = dp[i % 2][j];
                }
            }
        }

        // Final result: minimum time for all occupied chairs
        return dp[n % 2][occupied];
    }
}

