import java.util.*;

public class UndergroundSystem {
    private Map<Integer, CheckInInfo> checkIns;
    private Map<Pair<String, String>, List<Integer>> travelTimes;

    public UndergroundSystem() {
        checkIns = new HashMap<>();
        travelTimes = new HashMap<>();
    }

    public void checkIn(int id, String stationName, int t) {
        System.out.println("Checking in user: " + id + " at " + stationName + " at time " + t);
        checkIns.put(id, new CheckInInfo(stationName, t));
    }

    public void checkOut(int id, String stationName, int t) {
        CheckInInfo info = checkIns.get(id);
        if (info == null) {
            System.out.println("Error: User " + id + " not checked in.");
            return;
        }
        System.out.println("Checking out user: " + id + " at " + stationName + " at time " + t);
        String startStation = info.stationName;
        int startTime = info.time;
        int travelTime = t - startTime;

        Pair<String, String> route = new Pair<>(startStation, stationName);
        travelTimes.putIfAbsent(route, new ArrayList<>());
        travelTimes.get(route).add(travelTime);

        // Debug information
        System.out.println("Travel time from " + startStation + " to " + stationName + " recorded: " + travelTime);
    }

    public double getAverageTime(String startStation, String endStation) {
        Pair<String, String> route = new Pair<>(startStation, endStation);
        List<Integer> times = travelTimes.get(route);
        if (times == null || times.isEmpty()) {
            System.out.println("No travel data available for this route.");
            return 0;
        }

        double average = times.stream().mapToInt(Integer::intValue).average().orElse(0);
        System.out.println("Average travel time from " + startStation + " to " + endStation + ": " + average);

        return average;
    }

    // Inner class to hold check-in information
    private static class CheckInInfo {
        String stationName;
        int time;

        CheckInInfo(String stationName, int time) {
            this.stationName = stationName;
            this.time = time;
        }
    }

    // Simple pair class for storing station pairs
    private static class Pair<K, V> {
        K first;
        V second;

        Pair(K first, V second) {
            this.first = first;
            this.second = second;
        }
    }
}

