import java.util.*;

class CycleResearch {
    public int discoverShortestCycle(int totalNodes, int[][] connections) {
        // Step 1: Initialize a graph representation as an adjacency list.
        List<List<Integer>> adjacencyList = new ArrayList<>();
        for (int index = 0; index < totalNodes; index++) {
            adjacencyList.add(new ArrayList<>());
        }

        // Step 2: Populate the graph with edges.
        for (int[] connection : connections) {
            adjacencyList.get(connection[0]).add(connection[1]);
            adjacencyList.get(connection[1]).add(connection[0]);
        }

        // Step 3: Variable for tracking the minimum cycle length found.
        int smallestCycle = Integer.MAX_VALUE;

        // Step 4: Experimenting with each node as a starting point.
        for (int node = 0; node < totalNodes; node++) {
            int[] distances = new int[totalNodes];
            Arrays.fill(distances, -1);
            distances[node] = 0;
            Queue<Integer> bfsQueue = new LinkedList<>();
            bfsQueue.offer(node);

            // Step 5: Performing BFS to explore graph connectivity.
            while (!bfsQueue.isEmpty()) {
                int currentNode = bfsQueue.poll();
                for (int adjacent : adjacencyList.get(currentNode)) {
                    if (distances[adjacent] == -1) { // Not yet visited
                        distances[adjacent] = distances[currentNode] + 1;
                        bfsQueue.offer(adjacent);
                    } else if (distances[adjacent] >= distances[currentNode]) {
                        // Found a back edge forming a cycle
                        smallestCycle = Math.min(smallestCycle, distances[currentNode] + distances[adjacent] + 1);
                    }
                }
            }
        }

        // Step 6: Analyzing results - return the smallest cycle length or indication of no cycles.
        // DEBUGGING: Print found cycles
        if (smallestCycle == Integer.MAX_VALUE) {
            System.out.println("No cycles found.");
            return -1;
        } else {
            System.out.println("Shortest cycle length found: " + smallestCycle);
            return smallestCycle;
        }
    }
}

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;

    // Default constructor
    TreeNode() {}

    // Constructor with value
    TreeNode(int val) { 
        this.val = val; 
    }

    // Constructor with value and children
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val; 
        this.left = left; 
        this.right = right; 
    }
}

class Solution {
    // Main function to compute the max ancestor difference
    public int maxAncestorDiff(TreeNode root) {
        int[] result = {0}; // Using an array to hold result for inner function access
        dfs(root, root, Integer.MIN_VALUE, Integer.MAX_VALUE, result); // Initiate DFS with root
        return result[0];
    }

    // Depth-first search helper method
    private static void dfs(TreeNode currentNode, TreeNode ancestorNode, 
                            int minPath, int maxPath, int[] result) {

        if (currentNode == null) {
            return; // End of branch
        }

        // Update the path min and max
        minPath = Math.min(minPath, currentNode.val);
        maxPath = Math.max(maxPath, currentNode.val);

        // Calculate difference with ancestor
        int ancestorDiff = Math.abs(currentNode.val - ancestorNode.val);
        result[0] = Math.max(result[0], ancestorDiff);

        // Debug print for current state
        System.out.println("Current Node: " + currentNode.val + 
                           ", Min Path: " + minPath + 
                           ", Max Path: " + maxPath + 
                           ", Result So Far: " + result[0]);

        // Traverse left and right children
        dfs(currentNode.left, ancestorNode, minPath, maxPath, result);
        dfs(currentNode.right, ancestorNode, minPath, maxPath, result);
    }
}

