import java.time.LocalTime;
import java.util.*;

public class Solution {
    public List<String> alertNames(String[] keyName, String[] keyTime) {
        // Prototype: Add debug output to monitor key time processing
        System.out.println("Initializing key time processing...");

        List<LocalTime> keyTimeList = createListFromStrings(keyTime);
        List<String> keyNameList = Arrays.asList(keyName);

        // Debug output for lists
        System.out.println("Key Names: " + Arrays.toString(keyName));
        System.out.println("Parsed Key Times: " + keyTimeList);

        // Sort both lists for better management
        keyTimeList.sort(Comparator.naturalOrder());
        keyNameList.sort(Comparator.naturalOrder());

        // Initialize a map to track frequency of key events for each worker
        HashMap<String, int[]> events = new HashMap<>();

        // Process time entries and count key events
        for (int i = 0; i < keyNameList.size(); i++) {
            String name = keyNameList.get(i);
            LocalTime time = keyTimeList.get(i);

            // Check intervals of 30 minutes for alerts
            int start = time.getHour() * 60 + time.getMinute() - 30;
            int end = time.getHour() * 60 + time.getMinute() + 19;

            // Log intervals for debugging
            System.out.println("Processing: " + name + " at " + time + " (Interval: " + start + " to " + end + ")");

            // Count events only within valid intervals
            if (start >= 0 && end < 24 * 60) {
                events.compute(name, (k, v) -> {
                    if (v == null) {
                        return new int[]{1, 0}; // Events and alerts
                    } else {
                        v[0]++;
                        if (v[0] >= 3) {
                            v[1]++;
                            return null; // Alerted name cannot be counted again
                        }
                    }
                    return v;
                });
            }
        }

        // Experiment: Collect names that triggered alerts
        List<String> result = new ArrayList<>();
        for (Map.Entry<String, int[]> entry : events.entrySet()) {
            if (entry.getValue()[1] >= 1) {
                result.add(entry.getKey());
                System.out.println("Alerted: " + entry.getKey());
            }
        }

        // Sort result before returning
        Collections.sort(result);
        return result;
    }

    private List<LocalTime> createListFromStrings(String[] timeStrings) {
        List<LocalTime> timeList = new ArrayList<>();
        for (String time : timeStrings) {
            timeList.add(LocalTime.parse(time));
        }
        return timeList;
    }
}

