import java.util.*;

class Solution {
    public int largestInteger(int num) {
        List<Integer> digits = new ArrayList<>();
        // Extracting digits from the number
        while (num > 0) {
            digits.add(num % 10);
            num /= 10;
        }
        Collections.reverse(digits); // Reversing to maintain original order

        List<Integer> odd = new ArrayList<>();
        List<Integer> even = new ArrayList<>();

        // Categorizing digits into odd and even
        for (int digit : digits) {
            if (digit % 2 == 0) {
                even.add(digit);
            } else {
                odd.add(digit);
            }
        }

        // Sort and prepare to maximize the number
        Collections.sort(even); 
        Collections.reverse(even); // Largest even values first

        // Debugging: printing sorted odd and even lists
        System.out.println("Odd digits: " + odd);
        System.out.println("Even digits: " + even);

        // Attempting to replace odd digits with even digits
        for (int i = 0; i < odd.size(); i++) {
            int evenIndex = Collections.binarySearch(even, odd.get(i));
            if (evenIndex < 0) {
                evenIndex = -(evenIndex + 1); // Find the insertion point if not found
            }
            if (evenIndex < even.size()) {
                // Perform the swap
                digits.set(digits.indexOf(odd.get(i)), even.get(evenIndex));
                even.remove(evenIndex); // Remove used even digit
            }
        }

        // Constructing final number
        int result = 0;
        for (int i = 0; i < digits.size(); i++) {
            result = result * 10 + digits.get(i);
        }

        // Debugging: final result
        System.out.println("Resulting largest integer: " + result);

        return result;
    }
}

