// Interface for representing an interval; implementation hidden
interface Interval {
    public int start();
    public int end();
}

class Solution {

    // Main function to merge overlapping intervals 
    public List<Interval> merge(List<Interval> intervals) {
        // TODO: Check if intervals list is null or empty; return early if so
        if (intervals == null || intervals.isEmpty()) {
            // Debug print: Received empty or null intervals
            System.out.println("Received empty or null intervals.");
            return new ArrayList<>();
        }

        // TODO: Sort intervals by start time; consider edge cases like single intervals or already sorted
        Collections.sort(intervals, (a, b) -> Integer.compare(a.start(), b.start()));

        // Initialize merged intervals list
        List<Interval> merged = new ArrayList<>();

        // First interval should always be added
        merged.add(intervals.get(0));

        // Experiment: Keeping track of comparisons for performance analysis
        int comparisons = 0;

        // Iterate through intervals and merge where necessary
        for (int i = 1; i < intervals.size(); i++) {
            Interval current = intervals.get(i);
            Interval lastMerged = merged.get(merged.size() - 1);

            // Increment comparisons for debug purpose
            comparisons++;

            // Check if there is an overlap; we merge if there is
            if (current.start() <= lastMerged.end()) {
                // Debug print: Merging intervals
                System.out.println("Merging intervals: [" + lastMerged.start() + ", " + lastMerged.end() + "] and [" + current.start() + ", " + current.end() + "]");
                lastMerged = new Interval() {
                    public int start() { return lastMerged.start(); }
                    public int end() { return Math.max(lastMerged.end(), current.end()); }
                };
                merged.set(merged.size() - 1, lastMerged);
            } else {
                // No overlap; add current interval to merged list
                merged.add(current);
                // Debug print: Adding new interval
                System.out.println("Adding new interval: [" + current.start() + ", " + current.end() + "]");
            }
        }

        // Suggestion: Return the comparison count for efficiency analysis in the future
        // debug print: Total comparisons performed during the merge
        System.out.println("Total comparisons: " + comparisons);

        return merged;
    }
}

import java.util.*;

public class ResearchMain {

    public static void main(String[] args) {
        // Initialize Scanner for input
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter the size of the array:");

        // Read the size of the array
        int n = scanner.nextInt();
        int[] array = new int[n];

        // Populate the array with input values
        System.out.println("Enter the elements of the array:");
        for (int i = 0; i < n; i++)
            array[i] = scanner.nextInt();

        // Debug: Print initial array
        System.out.println("Initial array: " + Arrays.toString(array));

        long result = computeResult(array, array.clone());

        // Experiment: Modify boundary conditions if n > 2
        if (n > 2) {
            for (int i = 0; i < n; i++)
                array[i] = (i == 0 || i == n - 1) ? 0 : array[i];

            // Debug: Print modified array
            System.out.println("Modified array for boundary conditions: " + Arrays.toString(array));
            result = Math.min(result, computeResult(array, array.clone()));
        }

        // Output the result
        System.out.println("Final Result: " + result);
    }

    static long computeResult(int[] left, int[] right) {
        // Debug: Print arrays before processing
        System.out.println("Processing arrays left: " + Arrays.toString(left) + ", right: " + Arrays.toString(right));

        for (int i = 1; i < left.length; i++) {
            // Calculate values for left and right arrays
            left[i] = Math.max(0, left[i] - left[i - 1]);
            right[i] = Math.min(left[i], right[i]);
            left[i - 1] -= right[i];
        }

        long answer = 0;
        int minValue = Integer.MAX_VALUE;

        for (int i = 0; i < left.length - 1; i++) {
            // Track minimum value
            minValue = Math.min(minValue, left[i]);

            // Aggregate results
            if (minValue <= 0) {
                answer += minValue;
                minValue = Integer.MAX_VALUE; // Reset for next segment
            }
        }

        // Debug: Show intermediate values
        System.out.println("Intermediate answer value: " + answer);
        // Compute the final value using a separate method
        return -2 * answer + calculateSum(right);
    }

    static long calculateSum(int[] array) {
        long sum = 0;
        for (int number : array) sum += number;
        // Debug: Show calculated sum
        System.out.println("Calculated sum: " + sum);
        return sum;
    }
}

