import java.util.HashMap;
import java.util.Map;

public class PaintFenceResearch {
    private static final int MOD = 1000000007;

    public static void main(String[] args) {
        int n = 5000; // Target fence sections
        System.out.println("Starting calculation for " + n + " sections...");
        int ways = numWays(n);
        System.out.println("Number of ways to paint the fence: " + ways);
    }

    static int numWays(int n) {
        // Memoization storage for precomputed results
        Map<Integer, Integer> memoization = new HashMap<>();
        // Base cases initialized
        memoization.put(1, 12);
        memoization.put(2, 120);
        memoization.put(3, 720);
        memoization.put(4, 5040);
        memoization.put(5, 40320);

        // Check if result is already computed
        if (memoization.containsKey(n)) {
            System.out.println("Memoized value found for n=" + n + ": " + memoization.get(n));
            return memoization.get(n);
        }

        // Recursive calls to compute the number of ways
        System.out.println("Calculating numWays(" + (n - 1) + ") and numWays(" + (n - 2) + ")...");
        int prevOne = numWays(n - 1);
        int prevTwo = numWays(n - 2);

        // Applying the formula to find result
        int result = ((12 * prevOne) % MOD - (9 * prevTwo) % MOD + MOD) % MOD;        
        System.out.println("Computed result for n=" + n + ": " + result);

        // Storing the computed result for future reference
        memoization.put(n, result);

        return result;
    }
}

import java.util.*;
import java.text.*;

public class ResearchSolution {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Input experimentation
        int testCases = scanner.nextInt();
        int matrixSize = scanner.nextInt();
        int arraySize = scanner.nextInt();

        int[] inputArray = new int[arraySize];
        for (int index = 0; index < arraySize; index++) {
            inputArray[index] = scanner.nextInt();
        }

        // Initialize matrices
        int[][] matrixB = new int[matrixSize][matrixSize];
        int[][] dynamicProgramming = new int[matrixSize][matrixSize];

        // Constructing matrixB based on input array
        for (int row = 0; row < matrixSize; row++) {
            for (int col = 0; col < matrixSize; col++) {
                if (row == col) {
                    matrixB[row][col] = inputArray[row];
                } else if (row == 0) {
                    matrixB[row][col] = (col == 0) ? inputArray[row] : inputArray[row] + inputArray[col - 1];
                } else if (col == 0) {
                    matrixB[row][col] = inputArray[row - 1] + inputArray[col];
                } else {
                    matrixB[row][col] = inputArray[row - 1] + inputArray[col - 1];
                }
            }
        }

        // Debugging: Output constructed matrixB
        System.out.println("Constructed matrixB:");
        printMatrix(matrixB);

        // Fill dynamicProgramming matrix
        for (int row = 0; row < matrixSize; row++) {
            for (int col = 0; col < matrixSize; col++) {
                dynamicProgramming[row][col] = (row == 0 || col == 0) ? 1 : dynamicProgramming[row - 1][col] + dynamicProgramming[row][col - 1];
            }
        }

        // Finding the minimum value in dynamicProgramming matrix
        int minimumValue = Integer.MAX_VALUE;
        for (int row = 0; row < matrixSize; row++) {
            for (int col = 0; col < matrixSize; col++) {
                if (dynamicProgramming[row][col] < minimumValue) {
                    minimumValue = dynamicProgramming[row][col];
                }
            }
        }

        // Outputting results
        System.out.println("Minimum value found: " + minimumValue);
        System.out.println("Dynamic Programming matrix:");
        printMatrix(dynamicProgramming);
    }

    private static void printMatrix(int[][] matrix) {
        for (int[] row : matrix) {
            for (int val : row) {
                System.out.print((val == 0 ? "0 " : val + " "));
            }
            System.out.println();
        }
    }
}

