public class ResearchPrototype {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter number of elements: ");
        int n = scanner.nextInt();        
        List<Integer> l = new ArrayList<>(n);

        System.out.println("Input your elements:");
        for (int i = 0; i < n; i++) {
            l.add(scanner.nextInt());
        }

        int w = 1; // Initial weight
        boolean continueLoop = true;

        while (continueLoop) {
            int h = 0; // Counter for height

            for (int i = 0; i < n; i++) {
                // Debug print for current weight and element
                System.out.printf("Current weight: %d, Element: %d\n", w, l.get(i));

                if (w >= l.get(i) + 1) {
                    w += l.get(i) + 1; // Update weight if condition met
                } else {
                    h++; // Increment height
                    w = l.get(i) + 1; // Set weight to current element + 1
                }
            }

            if (h == 0) { // No height increment means the process is done
                continueLoop = false;
            }
            w++; // Increment weight for the next round

            // Debug print for height and weight after each outer iteration
            System.out.printf("Height in this round: %d, Incremented weight: %d\n", h, w);
        }

        System.out.printf("Final weight: %d\n", w); // Output final weight
        scanner.close();
    }
}

