public class Solution {
    public int minDeletions(int[] nums) {
        int n = nums.length;
        int minIndex = 0;
        int maxIndex = 0;

        // TODO: Explore potential optimizations for finding min/max indices
        for (int i = 1; i < n; i++) {
            if (nums[i] < nums[minIndex]) {
                minIndex = i; // Update minIndex
            }
            if (nums[i] > nums[maxIndex]) {
                maxIndex = i; // Update maxIndex
            }
        }

        // DEBUG: Print the indices of min and max elements
        System.out.println("Min Index: " + minIndex + ", Max Index: " + maxIndex);

        // Calculate the minimum deletions required
        int index1 = Math.min(minIndex, maxIndex);
        int index2 = Math.max(minIndex, maxIndex);

        // DEBUG: Log the calculated indices
        System.out.println("Index1: " + index1 + ", Index2: " + index2);

        // Calculate deletions by removing from the front
        int deletionsFromFront = index2 + 1; // Deletions when removing from front
        // DEBUG: Investigate behavior of deletionsFromFront
        System.out.println("Deletions from front: " + deletionsFromFront);

        // Calculate deletions by removing from the back
        int deletionsFromBack = n - index1; // Deletions when removing from back
        // DEBUG: Investigate behavior of deletionsFromBack
        System.out.println("Deletions from back: " + deletionsFromBack);

        // Return the minimum of the two strategies, validate results
        int result = Math.min(deletionsFromFront, deletionsFromBack);
        // DEBUG: Document final decision
        System.out.println("Minimum deletions required: " + result);

        return result; // Return the minimum deletions 
    }
}

