public class ResearchSolution {
    public int[] computeAverages(int[] data, int radius) {
        int length = data.length;
        int[] averages = new int[length];
        Arrays.fill(averages, -1);

        // TODO: Handle edge cases
        if (radius == 0) {
            return data;
        }

        // Critical condition for calculations
        if (2 * radius + 1 > length) {
            return averages; // Mean cannot be computed
        }

        long[] cumulativeSum = new long[length + 1];
        for (int index = 0; index < length; index++) {
            cumulativeSum[index + 1] = cumulativeSum[index] + data[index];
        }

        // Main calculation for averages
        for (int index = radius; index < length - radius; index++) {
            long total = cumulativeSum[index + radius + 1] - cumulativeSum[index - radius];
            averages[index] = (int) (total / (2 * radius + 1));
            // TODO: Instrumentation for debug
            System.out.println("Index: " + index + " Total: " + total + " Average: " + averages[index]);
        }

        return averages; // Return computed averages
    }

