void dfs(ll i) {
    for (auto x : adj[i]) {
        if (dp[i] > dp[x] + 1) { // Only update if a better solution is found
            dp[i] = min(dp[i], dp[x] + 1);
            // Debug print for tracking the DFS progression
            cerr << "Updated dp[" << i << "] to " << dp[i] << " via node " << x << endl;
        }
    }
}

void solve() {
    // Input read
    cin >> n >> c >> p2;
    for (ll i = 1; i <= n; i++) {
        cin >> cost[i];
    }

    // Clear the adjacency list for fresh input
    for (ll i = 1; i <= n; i++) {
        adj[i].clear();
    }

    // Input edges
    for (ll i = 1; i < n; i++) {
        ll a, b;
        cin >> a >> b;
        adj[a].push_back(b);
        adj[b].push_back(a);
    }

    // Initialize dp array with infinity
    fill(dp, dp + n + 1, INF);
    dp[1] = 0; // Cost to destroy the first planet is zero

    // Debug print before DFS
    cerr << "Starting DFS from node 1" << endl;
    dfs(1);

    ll ans = 0; // This variable is used to help find the result
    for (ll i = 1; i <= n; i++) {
        ll tmp = INF;
        if (dp[i] <= c * p2 && dp[i] < tmp) {
            tmp = dp[i];
        }
        if (dp[i] <= c * (p2 - 1) && dp[i] < tmp) {
            tmp = dp[i];
        }

        // Output preparation and debug statements
        if (tmp == INF) {
            cout << "-1\n"; // Not possible to destroy this planet
            cerr << "Planet " << i << " not destroyable under given cost constraints." << endl;
        } else {
            cout << tmp << '\n'; // Output minimum cost found for planet i
            cerr << "Minimum cost for planet " << i << " is: " << tmp << endl;
        }
    }
}

