// Node class definition for linked list
class Node {
    constructor(val, next) {
        this.val = (val === undefined ? 0 : val);
        this.next = (next === undefined ? null : next);
    }
}

// List class for managing linked list operations
class List {
    constructor() {
        this.head = null;
        this.tail = null;
    }

    pop() {
        // Returns the value of the tail node and removes it
        if (this.head) {
            const deleted = this.tail.val;
            let currentNode = this.head;

            // Traverse to the second-to-last node
            while (currentNode.next.next) {
                currentNode = currentNode.next;
            }

            this.tail = currentNode;  // Update tail
            currentNode.next = null;   // Disconnect the last node

            console.log(`Popped value: ${deleted}`); // Debugging print
            return deleted;
        }
        return null; // List was empty
    }

    prepend(value) {
        // Adds a new node at the head of the list
        const newNode = new Node(value);

        if (this.head) {
            newNode.next = this.head;
            this.head = newNode;
        } else {
            this.head = this.tail = newNode;  // First node case
        }
        console.log(`Prepended value: ${value}`); // Debugging print
    }
}

var deleteMiddle = function(head) {
    let lst = new List();
    let nodesCount = 0;

    // Build the list from the input linked list
    while (head) {
        nodesCount++;
        lst.prepend(head.val);
        head = head.next;
    }

    console.log(`Total nodes counted: ${nodesCount}`); // Debugging print

    // Adjust count for odd nodes
    if (nodesCount % 2 !== 0) { nodesCount++; }
    let middleIndex = nodesCount / 2 - 1;
    let resultList = new List();

    // Remove nodes up to the middle
    while (middleIndex > 0) {
        resultList.prepend(lst.pop());
        middleIndex--;
    }

    // Condition to ensure we do not lose our only node
    if (nodesCount > 1) { 
        resultList.prepend(null); 
    }

    resultList.prepend(lst.pop()); // Final node that remains
    console.log(`Final list head value: ${resultList.head ? resultList.head.val : null}`); // Debugging print
    return resultList.head;
};

module.exports = deleteMiddle;

