import java.util.LinkedList;
import java.util.Queue;

public class CarCollisions {
    // Main function to calculate total collisions
    public int totalCollisions(String directions) {
        // Queue to track indices of cars moving left
        Queue<Integer> leftCars = new LinkedList<>();
        int collisionCount = 0; // To count total collisions
        int lastRightCarIndex = -1; // Last known right-moving car index

        // Loop through each character in the directions string
        for (int i = 0; i < directions.length(); i++) {
            char currentDirection = directions.charAt(i); // Get direction of the current car

            // If the current car is moving left
            if (currentDirection == 'L') {
                leftCars.add(i); // Track the left-moving car's index
            }

            // Check for collisions with previously queued left-moving cars
            if (!leftCars.isEmpty() && leftCars.peek() > lastRightCarIndex) {
                leftCars.poll(); // Remove left-cars as they won't collide
            }

            // Handle potential collisions where cars have intersected
            while (!leftCars.isEmpty() && leftCars.peek() < lastRightCarIndex) {
                int collidingCarIndex = leftCars.poll(); // Get index of the left car that collided
                collisionCount++; // Increment collision count

                // If the current car is not the colliding car, track it
                if (i != collidingCarIndex) {
                    leftCars.add(i); // Add current car index to queue
                }
            }
            lastRightCarIndex = i; // Update last right-moving car index
        }

        return collisionCount; // Return total collision count
    }

    // Experimental and debugging methods
    public static void main(String[] args) {
        CarCollisions cc = new CarCollisions();
        String testDirections = "RSLRSLLR"; // Sample test input

        // Run the collision count method
        int result = cc.totalCollisions(testDirections);
        System.out.println("Total number of collisions for '" + testDirections + "': " + result);

        // Additional test cases for research purposes
        System.out.println("Testing edge case: 'R'");
        System.out.println(cc.totalCollisions("R")); // Expected: 0

        System.out.println("Testing edge case: 'L'");
        System.out.println(cc.totalCollisions("L")); // Expected: 0

        System.out.println("Testing edge case: 'S'");
        System.out.println(cc.totalCollisions("S")); // Expected: 0

        System.out.println("Testing input involving stops: 'RSLRLS'");
        System.out.println(cc.totalCollisions("RSLRLS")); // Conduct and analyze output

        // Experiment with longer strings or difficult patterns to further analyze behaviors
        String complexTest = "RLRLSLLRSLR"; // Complex input for scenario analysis
        System.out.println("Complex test case output: " + cc.totalCollisions(complexTest)); // Conduct investigation

