public class ResearchNoobscript {
    public static void main(String[] args) {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        try {
            String inputLine = br.readLine();
            int testCases = Integer.parseInt(inputLine);
            for (int caseNum = 0; caseNum < testCases; caseNum++) {
                String[] parameters = br.readLine().split(" ");
                int N = Integer.parseInt(parameters[0]);
                int M = Integer.parseInt(parameters[1]);
                String[] matrixRows = new String[N];

                for (int rowIndex = 0; rowIndex < N; rowIndex++) {
                    matrixRows[rowIndex] = br.readLine();
                }

                String result = analyzeMatrix(matrixRows, N, M);
                System.out.println(result);
            }
            System.out.println("All test cases processed successfully.");
        } catch (Exception e) {
            System.err.println("Error processing input: " + e.getMessage());
        }
    }

    public static String analyzeMatrix(String[] matrixRows, int N, int M) {
        StringBuilder result = new StringBuilder();
        boolean mismatchFound = false;

        for (int columnIndex = 0; columnIndex < M; columnIndex++) {
            char referenceChar = matrixRows[0].charAt(columnIndex);
            for (int rowIndex = 1; rowIndex < N; rowIndex++) {
                char currentChar = matrixRows[rowIndex].charAt(columnIndex);
                if (currentChar != referenceChar) {
                    mismatchFound = true;
                    break;
                }
            }
            if (mismatchFound) {
                result.append("-1");
                break;
            } else {
                result.append(referenceChar);
            }
        }

        return mismatchFound ? "-1" : result.toString();
    }
}

