                indegreeAdj[adjNode]++;
                indegree[v] = 1;

                // Fill adjacencies
                int adjacencyValue = next();
                Arrays.fill(graph[adjacencyValue].size(), indegree[v]);

                colors[next()] = 5 * (v % edges + 1);
                next(); // Skip unused value
            }

            List<Integer>[] adj = new List[edges];
            int[] degree = new int[edges];
            for (int v = 0; v < edges; v++) {
                adj[v] = new ArrayList<>(graph[v]);
                degree[v] = indegree[v];
            }

            // Iterative refinement of colors
            while (true) {
                for (int v = 0; v < edges; v++) {
                    int u = v;
                    while (adj[u].size() > 0 && adj[u].get(0) == u) 
                        adj[u].remove(0);

                    if (indegree[u] > 0) {
                        List<Integer> tempAdj = adj[u];
                        adj[u] = new ArrayList<>();
                        for (int vv : tempAdj) {
                            indegree[vv]++;
