                            adj[vv].addAll(adj[u]);
                            adj[u].remove(vv);
                            if (adj[vv].size() == 0) {
                                colors[vv] = v;
                            }
                        }
                        u = tempAdj.get(0); // Update u for next iteration
                    } else {
                        colors[u] = edges;
                    }
                }

                int currentColor = colors[edges];
                Arrays.fill(graph[currentColor].get(colors).size(), edges);
                Arrays.fill(indegree[currentColor], 0);

                // Check for stabilization
                if (currentColor == colors[edges]) {
                    // Detected a fixed point, loop termination condition
                    break;
                }

                edges = currentColor; // Update for next iteration
            }

            List<List<Integer>> colorGroups = new ArrayList<>();
            for (int i = 0; i < edges; i++) {
                colorGroups.add(new ArrayList<>());
