                        int tempColor = colors[u];
                        colors[u] = colors[v];
                        colors[v] = tempColor;
                    }
                }

                // Building the chain of colors
                if (colors[v] != edges) {
                    List<Integer> chain = new ArrayList<>();
                    while (colors[v] != edges) {
                        chain.add(v);
                        v = colors[v];
                    }

                    int[] tempSumArray = new int[chain.size()];

                    for (int i = 0; i < chain.size(); i++) {
