            int leftIndex = index; 
            int rightIndex = leftIndex + requiredElements - 1; 
            if (rightIndex > size) break; // Early exit for invalid range

            int currentDifference = sortedArray[rightIndex] - sortedArray[leftIndex - 1]; 
            if (currentDifference < minDifference) {
                minDifference = currentDifference; 
                leftBound = sortedArray[leftIndex - 1]; 
                rightBound = sortedArray[rightIndex]; 
            }
        }

        outputWriter.println(leftBound + " " + rightBound); 
