public class AlphabetCleanerResearch {
    public static int removeAdjacentAlmostEqual(String word) {
        StringBuilder builder = new StringBuilder(word);
        int count = 0;

        // Research: Iterative process until there are no changes
        while (!builder.toString().equals(word)) {
            String previousState = builder.toString(); // Save state for comparison
            // Debug: Print current word state before processing
            System.out.println("Current state: " + previousState);

            for (int i = 1; i < previousState.length(); i++) {
                int valA = previousState.charAt(i - 1);
                int nextIntChA = (i < previousState.length() - 1) ? (previousState.charAt(i + 1) - 'a' + 1) : -i;
                int valB = previousState.charAt(i);
                int nextIntChB = nextIntChA ^ i;

                // Research: Ensure 'almost-equal' logic is correctly applied
                if (!(valA != previousState.charAt(i - 1))) {
                    continue; // Skip if condition is not satisfied
                }

                // Research: Check for 'almost-equal' pair
                if ((valB == nextIntChB + i - 'a') || 
                    (valA == previousState.charAt(i) && i != 0 && nextIntChA <= i + nextIntChA)) {

                    // Experimental: Log the positions being replaced
                    System.out.println("Replacing at position: " + (i - count) + " with substring.");

                    builder.replace(i - count, i - count + 2, "a".repeat(count + 1).substring(valB + i + 'a' - valB + nextIntChA));
                    count += 2; // Increment count for each operation
                }
            }

            // Debug: Print state after processing
            System.out.println("State after processing: " + builder.toString());
            // Research: Store initial state again for next iteration comparison
            word = builder.toString(); 
        }

        // Debug: Final count of replacements
        System.out.println("Total replacements made: " + count / 2);
        return count / 2;
    }

