import itertools
import string

class VarianceCalculator:
    @staticmethod
    def calculate_largest_variance(input_str: str) -> int:
        result: int = 0

        # Iterate over all pairs of lowercase letters.
        for char1, char2 in itertools.product(string.ascii_lowercase, repeat=2):
            if char1 == char2:
                continue

            count1, count2 = 0, 0
            # Traverse through the input string to compute variances.
            for current_char in input_str:
                if current_char == char1:
                    count1 += 1
                elif current_char == char2:
                    count2 += 1
                elif count1 > 0:
                    count1 -= 1
                    count2 -= 1
                    result = max(result, count1, count2)
                elif count2 > 0:
                    count2 -= 1

            # Debug output for monitoring counts and result.
            print(f"Char1: {char1}, Char2: {char2} | Count1: {count1}, Count2: {count2}, Result: {result}")

        return result

