    public void solution() {
        in = createReader();
        int cases = in.nextInt(); // Reading number of test cases
        while (cases-- > 0) {
            int x = in.nextInt();
            int y = in.nextInt();
            String s = in.next(); // Assuming input string
            // Initial computations
            int result = computeMinCost(s, x, y);
            out.println(result); // Output result for current test case
        }
    }

    private int computeMinCost(String s, int x, int y) {
        // Debugging purposes
        System.out.println("Input string: " + s + ", x: " + x + ", y: " + y);
        int cnt0 = countChar(s, '0');
        int cnt1 = countChar(s, '1');

        // Experiment with outputs
        System.out.println("Count of '0': " + cnt0 + ", Count of '1': " + cnt1);

        int cost01 = cnt0 * x; 
        int cost101 = calculateCostForPattern(s, x, y);

        // Final result calculation
        int minCost = cost01 + cost101; 
        return minCost; 
    }

    private int calculateCostForPattern(String s, int x, int y) {
        // Custom logic to evaluate the specific pattern "101"
        int patternCost = 0; // Initial pattern cost
        for (int i = 0; i < s.length() - 2; i++) {
            if (s.substring(i, i + 3).equals("101")) {
                patternCost += y; // Increment cost based on the pattern found
            }
        }
        // Debugging patterns found
        System.out.println("Pattern cost for '101': " + patternCost);
        return patternCost;
    }

    private int countChar(String s, char c) {
        int count = 0;
        for (char ch : s.toCharArray()) {
            if (ch == c) count++;
        }
        return count;
    }

