class Experiment {
public:
    // Function to count subarrays with product less than k
    int numSubarrayProductLessThanK(vector<int>& nums, int k) {
        // Initialize count and product
        int count = 0;
        int product = 1; // Start with a multiplicative identity

        for (int left = 0, right = 0; right < nums.size(); ++right) {
            product *= nums[right]; // Expand the window

            // Shrink the window until product is less than k
            while (left <= right && product >= k) {
                product /= nums[left++];
            }
            // Count subarrays ending at right
            count += (right - left + 1);
            // Debug print to check current values
            cout << "Window: [" << left << ", " << right << "] Count: " << count << endl;
        }
        // Final output count
        return count;
    }
};

