class Main {
    public static String convertToBinary(int n) {
        // A Binary object to help with string manipulations
        Binary binaryRepresentation = new Binary();

        // Check if the number is a palindrome
        if (binaryRepresentation.isPalindrome(n)) {
            // If it is a palindrome, process accordingly
            while (n != 0) {
                char digit = (char) ((n % 10) + '0');
                binaryRepresentation.add(digit);
                n /= 10;
            }
            // Reverse for palindrome
            System.out.println("Palindrome detected, reversing...");
            binaryRepresentation.reverse();
        } else {
            // Process normally for non-palindrome
            while (n != 0) {
                char digit = (char) ((n % 10) + '0');
                binaryRepresentation.add(digit);
                n /= 10;
            }
        }
        // Output the binary string
        return binaryRepresentation.convert();
    }

