class Binary {
    private StringBuffer stringBuffer;

    public Binary() {
        stringBuffer = new StringBuffer();
    }

    public void reverse() {
        String original = stringBuffer.toString();
        int length = original.length();
        StringBuilder reversedString = new StringBuilder();
        for (int i = length - 1; i >= 0; i--) {
            reversedString.append(original.charAt(i));
        }
        stringBuffer = new StringBuffer(reversedString.toString());
        System.out.println("Reversed string: " + stringBuffer);
    }

    public void add(char character) {
        stringBuffer.append(character);
    }

    public String convert() {
        return stringBuffer.toString();
    }

    public boolean isPalindrome(final int number) {
        // Simplified palindrome check using string representation
        String str = Integer.toString(number);
        int length = str.length();
        for (int i = 0; i < length / 2; i++) {
            if (str.charAt(i) != str.charAt(length - 1 - i)) {
                return false; // Not a palindrome
            }
        }
        return true; // Is a palindrome
    }
}

