      // DEBUG print to trace swaps
      System.out.println("Swapped indices " + a + " and " + b + ": " + java.util.Arrays.toString(nums1));
    }

    // TODO: Explore possible optimizations for cost calculation, e.g., using priority queues
    public int minCost(int[] nums1, int[] nums2) {
        int n = nums1.length;
        int totalCost = 0;
        HashMap<Integer, Integer> map = new HashMap<>();

        // Initial cost and frequency mapping
        for (int i = 0; i < n; i++) {
            totalCost += Math.abs(nums1[i] - nums2[i]);
            map.put(nums2[i], map.getOrDefault(nums2[i], 0) + 1);
            // DEBUG print to observe cost at each step
            System.out.println("At index " + i + ": totalCost = " + totalCost + ", map = " + map.toString());
        }

        int misplaceCount = 0;
        for (Integer key : map.keySet()) {
            if (map.get(key) < n - misplaceCount) {
                misplaceCount += map.get(key);
            } else {
                totalCost -= map.get(key) - (n - misplaceCount);
                misplaceCount = n; // Reached max misplacement
                // DEBUG print for decision-making process
                System.out.println("Key " + key + " exceeded limits; adjusted totalCost to " + totalCost);
            }
        }

        // TODO: Investigate edge cases where misplaceCount equals n
        if (misplaceCount >= n) {
            System.out.println("Misplacement count exceeded or met: " + misplaceCount);
            return -1; // Return -1 for specific edge cases
        }

        // Final debug print
        System.out.println("Final totalCost: " + totalCost);
        return totalCost; // Result reflecting the calculated cost
    }
}

