            prefixSumSquares1[index] = prefixSumSquares1[index - 1] + (long) (array1[index - 1] - array2[index - 1]) * (array1[index - 1] - array2[index - 1]);
            prefixSumSquares2[index] = prefixSumSquares2[index - 1] + (long) (array2[index - 1] - array1[index - 1]) * (array2[index - 1] - array1[index - 1]);
        }

        long minimalValue = initialSum;
        System.out.println("Initial Sum of Squares: " + initialSum); // Debug: Initial sum of squares

        // Experimenting with possible increments
        for (int i = 0; i <= length; i++) {
