                long updatedSum1 = initialSum - (prefixSumSquares1[i] - prefixSumSquares1[i - j]) + 
                                    prefixSumSquares1[length] - (prefixSumSquares1[length] - prefixSumSquares1[i]) + 
                                    2 * (prefixSumSquares1[length] - prefixSumSquares1[i]);

                long updatedSum2 = initialSum - (prefixSumSquares2[i] - prefixSumSquares2[i - j]) + 
