                System.out.println("Second mismatch at index: " + second);
            } else {
                System.out.println("More than two mismatches found, returning false.");
                return false;
            }
        }
    }

    // Ensure two mismatches were found and check for character swaps
    boolean result = first != -1 && second != -1 && s1.charAt(first) == s2.charAt(second) && s1.charAt(second) == s2.charAt(first);
    System.out.println("Final result: " + result);
    return result;
