public class TitleCapitalizer {

    // Research note: Capitalizes words in the title based on specific rules.
    // TODO: Review logic for starting letter conditions for better clarity.

    public String capitalizeTitle(String title) {

        StringBuilder capitalizedTitle = new StringBuilder(); // Use StringBuilder for memory efficiency
        String[] words = title.split(" ");

        for (String word : words) {
            if (word.isEmpty()) continue; // Ignore empty words

            // TODO: Consider edge cases for punctuation handling.
            char firstChar = word.charAt(0);
            StringBuilder tempWord = new StringBuilder();

            if (word.length() < 2) {
                tempWord.append(word.toUpperCase());
            } else {
                // Apply transformation
                tempWord.append(Character.toUpperCase(firstChar)); // Capitalize first letter
                tempWord.append(word.substring(1).toLowerCase()); // Lowercase remaining letters
            }

            // Append space before new word, but avoid leading space
            if (capitalizedTitle.length() > 0) {
                capitalizedTitle.append(" ");
            }
            capitalizedTitle.append(tempWord); // Append modified word
        }

        // Debug print: Verify result before returning
        System.out.println("Capitalized Title: " + capitalizedTitle.toString());

        return capitalizedTitle.toString(); // Final output
    }

