  public static int kSum(int[] nums, int k) {
    if (nums == null) {
      throw new IllegalArgumentException("Input array must not be null.");
    }

    int len = nums.length;
    if (len < 1) {
      System.out.println("Array is empty; returning 0.");
      return 0; // Early exit for empty arrays.
    }

    // Array to hold all possible sums of subsequences.
    int[] sumsArray = new int[1 << len]; // Total combinations: 2^len
    int index = 0;

    // Debug: Start calculating sums
    System.out.println("Calculating sums for array: " + Arrays.toString(nums));

    // Populate sumsArray with sums of all subsequences
    for (int i = 0; i < len; i++) {
      for (int j = 0; j < (1 << i); j++) {
        sumsArray[index] = sumsArray[index - (1 << i)] + nums[i];
        index++;
      }
    }

    // Debug: Show all computed sums before sorting
    System.out.println("Unsorted sums: " + Arrays.toString(sumsArray));

    // Sorting to find the k-th largest
    Arrays.sort(sumsArray);

    // Debug: Display sorted sums
    System.out.println("Sorted sums: " + Arrays.toString(sumsArray));

    // Return the k-th maximum sum
    if (k > sumsArray.length) {
      System.out.println("k exceeds number of sums; returning 0.");
      return 0; // Ensure k is within bounds
    }

    return sumsArray[sumsArray.length - k]; // k-th largest sum
