import java.util.*;

public class ItemSorter {

    public List<Integer> sortItems(int n, int m, int[] group, List<List<Integer>> beforeItems) {
        // Step 1: Assign items to groups; create new groups for items without groups
        Map<Integer, List<Integer>> groupItems = new HashMap<>();
        for (int i = 0; i < n; i++) {
            if (group[i] == -1) {
                group[i] = m++;
            }
            groupItems.putIfAbsent(group[i], new ArrayList<>());
            groupItems.get(group[i]).add(i);
        }

        // Step 2: Build the item graph and calculate the in-degrees
        int[] itemInDegree = new int[n];
        Map<Integer, List<Integer>> itemGraph = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int before : beforeItems.get(i)) {
                itemGraph.putIfAbsent(before, new ArrayList<>());
                itemGraph.get(before).add(i);
                itemInDegree[i]++;
            }
        }

        // Step 3: Build the group graph and calculate group in-degrees
        int[] groupInDegree = new int[m];
        Map<Integer, List<Integer>> groupGraph = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int before : beforeItems.get(i)) {
                if (group[i] != group[before]) {
                    groupGraph.putIfAbsent(group[before], new ArrayList<>());
                    groupGraph.get(group[before]).add(group[i]);
                    groupInDegree[group[i]]++;
                }
            }
        }

        // Step 4: Topological sort for groups
        List<Integer> groupOrder = topologicalSort(m, groupInDegree, groupGraph);
        if (groupOrder.isEmpty()) {
            System.out.println("Cycle detected in group dependencies.");
            return Collections.emptyList();
        }

        // Step 5: Topological sort within each group
        List<Integer> result = new ArrayList<>();
        for (int g : groupOrder) {
            List<Integer> items = groupItems.getOrDefault(g, Collections.emptyList());
            List<Integer> sortedItems = topologicalSort(items, itemInDegree, itemGraph);
            if (sortedItems.isEmpty()) {
                System.out.println("Cycle detected within group: " + g);
                return Collections.emptyList();
            }
            result.addAll(sortedItems);
        }

        System.out.println("Final sorted result: " + result);
        return result;
    }

    private List<Integer> topologicalSort(int n, int[] inDegree, Map<Integer, List<Integer>> graph) {
        List<Integer> sortedList = new ArrayList<>();
        Queue<Integer> queue = new LinkedList<>();

        for (int i = 0; i < n; i++) {
            if (inDegree[i] == 0) {
                queue.offer(i);
            }
        }

        while (!queue.isEmpty()) {
            int node = queue.poll();
            sortedList.add(node);
            if (graph.containsKey(node)) {
                for (int neighbor : graph.get(node)) {
                    inDegree[neighbor]--;
                    if (inDegree[neighbor] == 0) {
                        queue.offer(neighbor);
                    }
                }
            }
        }

        return sortedList.size() == n ? sortedList : Collections.emptyList();
    }
}

