import java.util.ArrayList;

public class DataAnalyzer {

    private ArrayList<Integer> data;

    public DataAnalyzer() {
        this.data = new ArrayList<>();
    }

    public void addData(int value) {
        data.add(value);
        System.out.println("Data added: " + value);
    }

    public double calculateMean() {
        if (data.isEmpty()) {
            System.out.println("Data set is empty. Cannot calculate mean.");
            return 0;
        }
        int sum = 0;
        for (int num : data) {
            sum += num;
        }
        double mean = (double) sum / data.size();
        System.out.println("Calculated mean: " + mean);
        return mean;
    }

    public double calculateVariance() {
        if (data.isEmpty()) {
            System.out.println("Data set is empty. Cannot calculate variance.");
            return 0;
        }
        double mean = calculateMean();
        double temp = 0;
        for (int num : data) {
            temp += (num - mean) * (num - mean);
        }
        double variance = temp / data.size();
        System.out.println("Calculated variance: " + variance);
        return variance;
    }

    public void runExperiments() {
        // TODO: Add more experimentation here, possibly with different sets of data
        for (int i = 1; i <= 10; i++) {
            addData(i * 10); // Adding sample data
        }

        System.out.println("Running analysis...");

        double mean = calculateMean();
        double variance = calculateVariance();

        // Simple debugging print statements
        System.out.println("Final Mean: " + mean);
        System.out.println("Final Variance: " + variance);
    }

    public static void main(String[] args) {
        DataAnalyzer analyzer = new DataAnalyzer();
        analyzer.runExperiments();
    }
}

