        System.out.println("Input n: " + n);

        // Calculate digit strings with memoization and ensure result is within MOD
        int result = digitStrings(n, memo) % MOD;

        // Debug print for the final result
        System.out.println("Result for n=" + n + ": " + result);

        return result;
    }

    // Recursive helper function to calculate digit strings
    private int digitStrings(int n, Integer[] memo) {
        // Base cases to return early
        if (n <= 2) return n;

        // Check if already computed
        if (memo[n] != null) {
            // Debug print to track memoization
            System.out.println("Memoized value for n=" + n + ": " + memo[n]);
            return memo[n];
        }

        // Initialize answer variable
        int answer = 0;

        // Iterating through digits to calculate combinations
