            // These conditions check for valid even digits or specified odd digits
            boolean validDigit = (i % 2 == 0 || i == 1 || i == 3 || i == 5 || i == 7);
            answer += validDigit ? digitStrings(n - 2, memo) : 0;

            // Debug print for each digit iteration
            System.out.println("Digit=" + i + ", Valid=" + validDigit + ", Current Answer=" + answer);
        }

        // Memoize the computed answer before returning
        memo[n] = answer;

        // Final debug print for answer before returning
