public int maxScoreNodes(int[] parents) {
    int n = parents.length;
    int[] score = new int[n];
    int[] size = new int[n];
    int[] maxScore = new int[n];
    int[] maxScoreIndex = new int[n];

    // Research note: Initialize arrays
    Arrays.fill(maxScore, Integer.MIN_VALUE);
    Arrays.fill(maxScoreIndex, -1);

    int maxScoreCount = 0;

    // Debug: Print initial state
    System.out.println("Initial maxScore: " + Arrays.toString(maxScore));

    for (int i = 0; i < n; i++) {
        int parent = parents[i];

        // Debug: Print current node and its parent
        System.out.println("Node: " + i + ", Parent: " + parent);

        if (parent == -1) {
            size[i] = 1; // Root node
            score[i] = 1;
        } else {
            size[i] = 1 + size[parent];
            score[i] = size[parent] * (size[i] + 1);

            // Research note: Update maxScore if current score is higher
            if (score[i] > maxScore[maxScoreIndex[parent]]) {
                maxScore[maxScoreIndex[parent]] = score[i];
                maxScoreIndex[parent] = i;
            }
        }

        // Update score for the current node itself
        if (score[i] > maxScore[maxScoreIndex[i]]) {
            maxScore[maxScoreIndex[i]] = score[i];
            maxScoreIndex[i] = i;
        }

        // Count how many times the max score occurs
        if (maxScore[maxScoreIndex[i]] == score[i]) {
            maxScoreCount++;
        }

        // Debug: Print score and size arrays after each iteration
        System.out.println("Scores: " + Arrays.toString(score));
        System.out.println("Sizes: " + Arrays.toString(size));
        System.out.println("Max Scores: " + Arrays.toString(maxScore));
        System.out.println("Max Score Indices: " + Arrays.toString(maxScoreIndex));
    }

    // Research note: Final maxScoreCount
    System.out.println("Total max score count: " + maxScoreCount);
    return maxScoreCount;
}

public boolean validWordAbbreviation(String word, String abbr) {
    // Initialization of variables
    List<Integer> positionList = new ArrayList<>();
    int currentIndex = 0, abbreviationLength = abbr.length();

    // Traverse through each character of the abbreviation
    for (int i = 0; i < abbreviationLength; i++) {
        char currentChar = abbr.charAt(i);

        // Check if the character is a digit
        if (Character.isDigit(currentChar)) {
            // Added debug prints for tracing
            System.out.println("Digit found: " + currentChar);

            int numberStart = i; // Mark start of the number

            // Handle multi-digit numbers
            while (i < abbreviationLength && Character.isDigit(abbr.charAt(i))) {
                i++;
            }

            // Converting number substring to integer
            int num = Integer.parseInt(abbr.substring(numberStart, i));
            currentIndex += num; // Increment current index based on number

            // Added print to see index progression
            System.out.println("Index progressed by: " + num + ", new index: " + currentIndex);
            i--; // Adjust index because of the outer loop increment

            // Early exit if current index exceeds word length
            if (currentIndex > word.length()) {
                return false;
            }
        } else {
            // Check if current character matches expected character in the word
            if (currentIndex < word.length() && currentChar == word.charAt(currentIndex)) {
                currentIndex++; // Move to next character in word
            } else {
                // Mismatch found; returning false
                System.out.println("Mismatch at index: " + currentIndex + ", expected: " + word.charAt(currentIndex) + ", found: " + currentChar);
                return false;
            }
        }
    }

    // After processing abbreviation, check if indices align
    boolean isValid = currentIndex == word.length();

    // Print debug information
    System.out.println("Final index: " + currentIndex + ", Word length: " + word.length() + ", Is valid: " + isValid);

    return isValid;
