public int findMaxDivisibility(int[] nums, int[] divisors) {
    int maxDiv = Integer.MIN_VALUE; // Initialize max divisor count
    for (int i = 0; i < divisors.length; ++i) { // Iterate through divisors
        int count = 0; // Reset count for each divisor
        for (int j = 0; j < nums.length; ++j) { // Iterate through nums
            if (nums[j] % divisors[i] == 0) { // Check divisibility
                count++; // Increment count if divisible
            }
        }
        System.out.println("Divisor: " + divisors[i] + ", Count: " + count); // Debug print
        if (count > maxDiv) { // Check if current count exceeds maxDiv
            maxDiv = count; // Update maxDiv if true
        }
    }
    System.out.println("Max Divisibility Count: " + maxDiv); // Final debug print
    return maxDiv; // Return maximum divisor count
}

