import java.util.Arrays;

public class Fancy {
    private final int[] seq;
    private final int mod = 1000000007;
    private final int capacity = 400001;

    // Debug print to track initialization
    public Fancy() {
        seq = new int[capacity];
        Arrays.fill(seq, 0);
        System.out.println("Initialized Fancy with capacity: " + capacity);
    }

    // Appends valu to the end and maintains the half-capacity structure
    public void append(int val) {
        if (val == 0) return;
        seq[capacity / 2++] += val;
        System.out.println("Appended value: " + val + ", new position: " + (capacity / 2 - 1));
    }

    // Increments all existing values by inc using the same structure
    public void addAll(int inc) {
        int incMod = (inc % mod + mod) % mod;
        System.out.println("Incrementing all by: " + incMod);
        for (int i = 0; i < seq.length / 2; i++) {
            seq[i] = (seq[i] + incMod) % mod;
            System.out.println("seq[" + i + "] after increment: " + seq[i]);
        }
    }

    // Multiplies all existing values by m
    public void multAll(int m) {
        System.out.println("Multiplying all by: " + m);
        for (int i = 0; i < seq.length / 2; i++) {
            long product = (long) seq[i] * m;
            seq[i] = (int) (product % mod);
            System.out.println("seq[" + i + "] after multiplication: " + seq[i]);
        }
    }

    // Returns the current value at index idx modulo mod, or -1 if out of range
    public int getIndex(int idx) {
        if (idx >= seq.length / 2) {
            System.err.println("Index out of range: " + idx);
            return -1;
        }
        int sum = 0;
        for (int i = idx; i < seq.length / 2; i += idx + 1) {
            sum = (sum + seq[i]) % mod;
            System.out.println("Summing seq[" + i + "]: current sum = " + sum);
        }
        return (sum >= mod) ? sum : sum; // Ensure the result is within the modulo limit
    }
}

