            String result = lexicographicallySmallest(s);
            // Debug print: Output the final result
            System.out.println("Lexicographically smallest: " + result);
        }
        sc.close();
    }

    // Function that computes the lexicographically smallest string based on described operations
    private static String lexicographicallySmallest(String s) {
        char[] chars = s.toCharArray();
        Map<Character, List<Integer>> indexMap = new HashMap<>();

        // Step 2: Build a map of indices for each character
        for (int i = 0; i < chars.length; i++) {
            indexMap.putIfAbsent(chars[i], new ArrayList<>());
            indexMap.get(chars[i]).add(i);
        }

        // Step 3: Trying out operations
        for (Map.Entry<Character, List<Integer>> entry : indexMap.entrySet()) {
            char current = entry.getKey();
            List<Integer> indices = entry.getValue();

            if (indices.size() > 1) {
                // Step 4: Perform operations to minimize the characters
                for (int idx : indices) {
                    // Increment character and wrap around if necessary
                    chars[idx] = (char) ((current - '0' + 1) % 10 + '0');
                }
                // Step 5: Update the map after changes
                indexMap.clear(); // Clear for recalculating
                for (int i = 0; i < chars.length; i++) {
                    indexMap.putIfAbsent(chars[i], new ArrayList<>());
                    indexMap.get(chars[i]).add(i);
                }
            }
        }

        // Debug print: Show character map after operations
        System.out.println("Character map after operations: " + indexMap);

        // Step 6: Return the final string
        return new String(chars);
    }
}

