    static class ResearchSolver {
        public String calculateCheapestString(String input, int price) {
            // Debugging: Output the initial price calculation
            System.out.println("Initial price: " + price + ", Expected minimum fill: " + minRequiredFill(input));

            if (price < minRequiredFill(input)) {
                return "";
            } else {
                if ((price - minRequiredFill(input)) % 2 == 0) {
                    return input;
                } else {
                    return modifyInput(input, (price - minRequiredFill(input)) / 2);
                }
            }
        }

        private int minRequiredFill(String input) {
            int[] priceArray = new int[26];

            for (int i = 0; i < input.length(); ++i) {
                priceArray[input.charAt(i) - 97]++;
            }
            int minimumSum = 0;

            // Debugging: Track the sum calculation
            for (int i = 0; i < priceArray.length; ++i) {
                minimumSum += priceArray[i] * (i + 1);
                // Debugging: Output current minimum fill contribution
                System.out.println("Character index: " + i + ", Contribution: " + (priceArray[i] * (i + 1)));
            }
            return minimumSum;
        }

        private String modifyInput(String str, int reduction) {
            List<Set<Integer>> buckets = new ArrayList<>();

            // Research note: Populate buckets based on character indices
