import java.util.Arrays;

public class ResearchSolution {
    public int clumsyFactorial(int n) { 
        // TODO: Investigate edge cases and their handling
        if (n == 0 || n == 1) return 1; 

        int[] sequence = new int[n + 1];
        sequence[1] = 1;

        // Initialize index for factorial computation
        int i = 2; 

        // Compute the factorial iteratively
        while (i <= n) {
            sequence[i] = (i - 1) * sequence[i - 1];
            i++;
        }

        System.out.println("Factorial sequence computed: " + Arrays.toString(sequence)); // Debug print

        // Implement 'clumsy' operation: multiplication, division, addition, subtraction
        int result = 0; 
        for (int operation : new int[] {1, 0, -1, 0}) {
            int sign = operation;
            float temp = result;

            // Perform clumsy factorial operations
            while (i > 0) {
                int next = (i - 1) * sequence[--i];
                System.out.println("Current operation: " + sign + ", Next value: " + next); // Debug print

                if (sign == 1) {
                    temp *= next;
                } else if (sign == 0) {
                    temp /= next; // Note: considering floor division
                } else if (sign == -1) {
                    temp += next;
                }

                // Rotate the operation
                operation = (operation + 1) % 4; 
                sign = new int[] {1, 0, -1, 0}[operation]; // Update sign for next operation
            }
            result = (int) temp; // Note: casting might lose precision in some cases
            System.out.println("Intermediate result after operation: " + result); // Debug print
        }

        return result;
    }

    // Example usage for empirical observation
    public static void main(String[] args) {
        ResearchSolution solution = new ResearchSolution();

        // Conducting simple experiments
        System.out.println("Clumsy Factorial of 4: " + solution.clumsyFactorial(4)); // Expected: 7
        System.out.println("Clumsy Factorial of 10: " + solution.clumsyFactorial(10)); // Expected: 12

        // TODO: Add more test cases to validate behavior
    }
}

import java.util.*;

// Definition for a binary tree node.
public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;

    TreeNode(int x) { val = x; }
}

public class Solution {
    public TreeNode transformBinaryTree(TreeNode root) {
        if (root == null) return null;

        Queue<TreeNode> queue = new LinkedList<>();
        queue.offer(root);

        // Print initial tree (for debugging)
        System.out.println("Starting transformation on the binary tree");

        while (!queue.isEmpty()) {
            int size = queue.size();
            int levelSum = 0;
            // Debug: print the current level size
            System.out.println("Current level size: " + size);

            for (int i = 0; i < size; i++) {
                TreeNode node = queue.poll();

                if (i > 0) {
                    // Node has cousins.
                    levelSum += node.val;
                }

                // Debug: print the value of the current node
                System.out.println("Visiting node with value: " + node.val);

                // Queue next level children
                if (node.left != null) {
                    queue.offer(node.left);
                    // Debug: node.left value
                    System.out.println("Adding left child with value: " + node.left.val);
                }
                if (node.right != null) {
                    queue.offer(node.right);
                    // Debug: node.right value
                    System.out.println("Adding right child with value: " + node.right.val);
                }
            }

            // Update node values at the current level
            // Experiment: Alternatively can calculate average
            for (int i = 0; i < size; i++) {
                TreeNode node = (i == 0 ? queue.poll() : null); // Null where needed
                if (node != null) {
                    int newValue = levelSum - node.val;
                    node.val = newValue;
                    // Debug: new value assigned
                    System.out.println("Updating node value from " + (levelSum + node.val) + " to " + newValue);
                }
            }
        }

        // Print final tree state (for debugging)
        System.out.println("Transformation complete.");
        return root;
    }
}

