public class SecretKnowledgeResearch {

    private static final int MOD = 1000000007;

    public static int secretKnowledgeCount(int n, int delay, int forget) {
        // Step 1: Initialize a dp array to track the number of people knowing the secret each day
        int[] dp = new int[n + 1];
        dp[1] = 1; // Day 1: 1 person knows the secret

        // Step 2: Iterate through each day to calculate the number of new people knowing the secret
        for (int day = 2; day <= n; day++) {
            // Step 3: Calculate number of people who can share the secret today
            // This includes people who knew the secret at least `delay` days ago
            // and have not forgotten it yet (within the `forget` days).
            // TODO: Optimize sum calculation (consider prefix sums for efficiency)

            long peopleWhoCanShare = 0;
            for (int j = Math.max(day - delay, 1); j <= Math.max(day - forget, 0); j++) {
                peopleWhoCanShare = (peopleWhoCanShare + dp[j]) % MOD;
            }

            // Step 4: Update dp array for today
            dp[day] = (dp[day - 1] + (int) peopleWhoCanShare) % MOD;

            // DEBUG: Print state of dp array to trace values
            System.out.println("Day " + day + ": " + dp[day] + " people know the secret.");
        }

        // Step 5: Return the number of people who know the secret on the last day
        return dp[n];
    }

    public static void main(String[] args) {
        // Step 6: Example usage and testing the function with various inputs
        System.out.println("Output for (6, 2, 4): " + secretKnowledgeCount(6, 2, 4)); // Expected: 5
        System.out.println("Output for (4, 1, 3): " + secretKnowledgeCount(4, 1, 3)); // Expected: 6
        // TODO: Consider edge cases and larger inputs for performance testing
    }
}

