/**
 * Research: An analysis of train arrival times
 * Author: kartikbhambri
 */
public class Solution 
{
    public static void main(String[] args) throws NumberFormatException, IOException
    {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int testCases = Integer.parseInt(br.readLine());

        for (int caseIndex = 0; caseIndex < testCases; caseIndex++)
        {
            // Read the number of trains
            int numTrains = Integer.parseInt(br.readLine());
            int[] travelTime = new int[numTrains];
            int[] arrivalTime = new int[numTrains];
            int[] departureTime = new int[numTrains];

            // Read arrival times
            String[] arrivalInput = br.readLine().split(" ");
            // Read departure times
            String[] departureInput = br.readLine().split(" ");
            // Read travel times
            String[] travelInput = br.readLine().split(" ");

            for (int trainIndex = 0; trainIndex < numTrains; trainIndex++)
            {
                // Parse input to integer arrays
                travelTime[trainIndex] = Integer.parseInt(travelInput[trainIndex]);
                arrivalTime[trainIndex] = Integer.parseInt(arrivalInput[trainIndex]);
                departureTime[trainIndex] = Integer.parseInt(departureInput[trainIndex]);
            }
            // Call the function to compute total time to reach the last station
            computeArrivalTime(numTrains, departureTime, arrivalTime, travelTime);
        }
    }

    static void computeArrivalTime(int numTrains, int[] departureTime, int[] arrivalTime, int[] travelTime)
    {
        int totalTravel = departureTime[0];

        for (int trainIndex = 1; trainIndex < numTrains; trainIndex++)
        {
            // Calculate total time based on arrival and previous departure
            totalTravel += Math.ceil((arrivalTime[trainIndex] - departureTime[trainIndex - 1] + travelTime[trainIndex - 1]) / 2.0);
        }

        // Add the last train's travel time
        totalTravel += travelTime[numTrains - 1];

        // Debug print statement for experimentation purposes
        System.out.println("Total time to reach last station: " + totalTravel);
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int testCases = scanner.nextInt();
        StringBuilder output = new StringBuilder();

        for (int caseIndex = 0; caseIndex < testCases; caseIndex++) {
            long heroHealth = scanner.nextLong();
            long damagePerHitHero = scanner.nextLong();
            long monsterHealth = scanner.nextLong();
            long damagePerHitMonster = scanner.nextLong();
            int coinsAvailable = scanner.nextInt();
            int weaponUpgradeAmount = scanner.nextInt();
            long healthUpgradeAmount = scanner.nextLong();

            // Research step: Determine the initial number of weapon upgrades
            int upgradesToMaxDamage = Math.min(coinsAvailable, (int) Math.ceil((double)(monsterHealth + damagePerHitHero - 1) / damagePerHitHero) - 1);
            int coinsAfterDamageUpgrade = coinsAvailable - upgradesToMaxDamage;
            damagePerHitHero += upgradesToMaxDamage * weaponUpgradeAmount;

            // Debug output: Current state after weapon upgrades
            System.out.println("After weapon upgrades: Damage = " + damagePerHitHero + ", Coins left = " + coinsAfterDamageUpgrade);

            // Research calculation for required health upgrades, if needed
            long healthRequired = (long) Math.ceil((double) (damagePerHitMonster + damagePerHitHero) / damagePerHitHero) * damagePerHitMonster - heroHealth; 
            long upgradesForHealth = Math.min(coinsAfterDamageUpgrade, (int) Math.ceil((double)(healthRequired + healthUpgradeAmount - 1) / healthUpgradeAmount));

            heroHealth += upgradesForHealth * healthUpgradeAmount;

            // Debug output: Current state after health upgrades
            System.out.println("After health upgrades: Hero Health = " + heroHealth + ", Monster Health = " + monsterHealth);

            // Research finding: Determine if the monster can still be defeated
            boolean canDefeatMonster = (heroHealth > 0 && monsterHealth > 0 && (monsterHealth + damagePerHitHero - 1) / damagePerHitHero <= (heroHealth + damagePerHitMonster - 1) / damagePerHitMonster);
            output.append(canDefeatMonster ? "YES" : "NO").append("\n");
        }

        // Final output of results
        System.out.print(output);
        scanner.close();
    }
}

import java.util.Map;
import java.util.HashMap;

/**
 * Research Class: Statistics of Number Frequencies in Specified Ranges
 * TODO: Further investigate performance with large datasets
 * TODO: Implement logging for debugging
 * 
 * dCache: Caching frequency data to avoid re-computation
 */
public class NumberFrequencyStats {
    private int numberOfTotalNumbers; 
    private int[][] frequencyData; 

    // Frequency mapping to hold frequency of numbers
    private Map<Integer, Integer> frequencyMap;

    public NumberFrequencyStats() {
        frequencyData = new int[100001][2]; 
        frequencyMap = new HashMap<>(); 
    }

    // Experimental Method: Assess frequency range
    public boolean evaluateFrequency(int left, int right) {
        int rangeSize = right - left + 1; 
        System.out.println("Evaluating frequency for range: [" + left + ", " + right + "]");

        return frequencyCheckHelper(frequencyData, left, right, rangeSize); 
    }

    // Private Helper: Core logic for frequency evaluation
    private boolean frequencyCheckHelper(int[][] data, int left, int right, int targetSize) {
        int key = searchKey(data, left, right, targetSize);
        return key != -1 && (key - data[key][0] >= right - data[key][1]); 
    }

    // Key Search: Binary search to locate relevant frequency data
    private int searchKey(int[][] data, int left, int right, int targetSize) {
        int start = 0, end = data.length - 1; 
        while (start <= end) {
            int midIndex = (start + end) / 2; 
            if (data[midIndex][0] > targetSize) {
                end = midIndex - 1; 
            } else if (data[midIndex][0] == targetSize) {
                System.out.println("Found key at index: " + midIndex);
                return data[midIndex][1]; 
            } else {
                start = midIndex + 1; 
            }
        }
        System.out.println("No matching key found");
        return -1; 
    }

    // TODO: Potential optimization for frequency updates
    public void updateFrequency(int number) {
        frequencyMap.put(number, frequencyMap.getOrDefault(number, 0) + 1); 
        // Debug print: Show updated frequency
        System.out.println("Updated frequency for number " + number + ": " + frequencyMap.get(number));
    }

    // Experimental Method: Clear frequency data
    public void clearFrequencyData() {
        frequencyMap.clear(); 
        System.out.println("Cleared frequency data");
    }
}

