import java.util.*;

public class GregorPawnsSimulation {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int t = scanner.nextInt(); // Number of test cases
        while (t-- > 0) {
            int n = scanner.nextInt(); // Board size
            char[] enemy = scanner.next().toCharArray(); // Enemy pawns
            char[] grigor = scanner.next().toCharArray(); // Gregor's pawns

            int pawnsReached = 0;
            System.out.println("Debug: Starting simulation for test case.");

            // Iterate over each of Gregor's pawns in the last row
            for (int j = 0; j < n; j++) {
                if (grigor[j] == '1') { // Found a Gregor's pawn
                    boolean moved = false;

                    // Direct move up
                    if (j > 0 && enemy[j - 1] == '0' && enemy[j] == '0') {
                        pawnsReached++;
                        grigor[j] = '0'; // Mark as moved
                        moved = true;
                        System.out.println("Debug: Pawn at " + j + " moved directly up.");
                    } else if (enemy[j] == '0') { // No enemy directly above
                        pawnsReached++;
                        grigor[j] = '0'; // Mark as moved
                        moved = true;
                        System.out.println("Debug: Pawn at " + j + " moved directly up (no enemy).");
                    }

                    // Diagonal moves
                    if (!moved) { // Only check diagonal if not moved yet
                        if (j > 0 && enemy[j - 1] == '1') { // Diagonal up-left
                            pawnsReached++;
                            grigor[j] = '0'; // Mark as moved
                            enemy[j - 1] = '0'; // Remove the enemy pawn
                            System.out.println("Debug: Pawn at " + j + " moved diagonally up-left.");
                        } 
                        else if (j < n - 1 && enemy[j + 1] == '1') { // Diagonal up-right
                            pawnsReached++;
                            grigor[j] = '0'; // Mark as moved
                            enemy[j + 1] = '0'; // Remove the enemy pawn
                            System.out.println("Debug: Pawn at " + j + " moved diagonally up-right.");
                        }
                    }
                }
            }

            System.out.println("Total pawns reached: " + pawnsReached);
            System.out.println(); // New line for clarity between test cases
        }

        scanner.close();
    }
}

