class MaximalSimilarity {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // TODO: Read input values for lengths of strings and the strings themselves
        int n = scanner.nextInt(); // length of string A
        int m = scanner.nextInt(); // length of string B
        scanner.nextLine(); // consume the newline

        // TODO: Initialize strings for comparison
        String A = scanner.nextLine(); // string A
        String B = scanner.nextLine(); // string B

        // DEBUG: Print lengths of strings
        System.out.println("Length of A: " + n);
        System.out.println("Length of B: " + m);

        // Initialize 2D array for Longest Common Substring (LCS) values
        int[][] LCS = new int[n + 1][m + 1];

        // TODO: Calculate LCS using dynamic programming
        int maxLength = 0; // Variable to store the maximum length found
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                // Check if characters match
                if (A.charAt(i - 1) == B.charAt(j - 1)) {
                    LCS[i][j] = LCS[i - 1][j - 1] + 1;
                    maxLength = Math.max(maxLength, LCS[i][j]); // Update maximum length if necessary
                } else {
                    LCS[i][j] = 0; // Reset if characters do not match
                }

                // DEBUG: Print LCS table content for tracking
                System.out.printf("LCS[%d][%d]: %d\n", i, j, LCS[i][j]);
            }
        }

        // FINAL RESULT: Output the maximum length of substring similarity
        System.out.println("Maximal Similarity Score: " + maxLength);
    }
}

