        int top = 0;
        int[] result = new int[100000];

        // To track the list traversal
        ListNode current = head;

        // Main loop to populate the stack
        while (current != null) {
            // Debug print: Current node value being processed
            System.out.printf("Processing node with value: %d%n", current.value);

            // Pop stack if current node value is greater than the top of the stack
            while (top != 0 && current.value > stack[top - 1].value) {
                // Debug print: Popping node with value: stack[top-1].value
                System.out.printf("Popping node with value: %d%n", stack[top - 1].value);
                stack[top - 1].next = current; // Setting the next to the current node
                top--; // Decrementing the stack pointer
            }

            // Push the current node onto the stack
            stack[top++] = current;
            current = current.next; // Move to the next node
        }

        // Cleanup remaining nodes in the stack
        while (top > 1 && stack[top - 2] != null) {
            // Debug print: Setting next for node: stack[top-2].value
            System.out.printf("Setting next for node: %d to 0%n", stack[top - 2].value);
            stack[top - 2].next = new ListNode(0); // Final node next should be 0
            top--;
        }

        // Fill result array with node values from the stack
        while (top > 0) {
            // Debug print: Adding to result array value of node: stack[top-1].value
            System.out.printf("Adding to result array value: %d%n", stack[top - 1].value);
            result[top - 1] = stack[--top].value; // Fill in the result
        }

        // Return the resultant array
        return result;
    }

