        ListNode listNode2 = new ListNode(3);
        listNode2.next = new ListNode(2);
        listNode2.next.next = new ListNode(2);

        // Perform the next larger nodes operation
        int[] data = nextLargerNodes(listNode2);

        // Debug output of result
        System.out.println("Result array: " + Arrays.toString(data));
    }
}

