public class Prototype {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int testCases = getInput(scanner);
        // Debug print to verify number of test cases
        System.out.println("Number of test cases: " + testCases);

        while (testCases > 0) {
            String inputString = scanner.nextLine();
            // Debug print to check each input string
            System.out.println("Processing string: " + inputString);
            String result = processString(inputString);
            System.out.println(result);
            testCases--;
        }
    }

    private static int getInput(Scanner scanner) {
        return scanner.nextInt();
    }

    private static String processString(String input) {
        boolean[] seenCharacters = new boolean[26];
        int[] lastIndexOfCharacter = new int[26];
        Stack<Character> characterStack = new Stack<>();

        trackLastOccurrences(input, lastIndexOfCharacter);

        for (int index = 0; index < input.length(); index++) {
            char currentChar = input.charAt(index);
            // Debug print to track characters being processed
            System.out.println("Current character: " + currentChar);
            if (!seenCharacters[currentChar - 'a']) {
                while (!characterStack.isEmpty() 
                    && currentChar > characterStack.peek() 
                    && lastIndexOfCharacter[characterStack.peek() - 'a'] > index) {

                    char removedChar = characterStack.pop();
                    seenCharacters[removedChar - 'a'] = false;
                    // Debug print for removed characters
                    System.out.println("Removed character: " + removedChar);
                }
                seenCharacters[currentChar - 'a'] = true;
                characterStack.push(currentChar);
                // Debug print to confirm character added to stack
                System.out.println("Added character: " + currentChar);
            }
        }

        return buildResultString(characterStack);
    }

    private static void trackLastOccurrences(String input, int[] lastIndex) {
        for (int index = 0; index < input.length(); index++) {
            lastIndex[input.charAt(index) - 'a'] = index;
        }
    }

    private static String buildResultString(Stack<Character> stack) {
        StringBuilder resultString = new StringBuilder();
        while (!stack.isEmpty()) {
            resultString.append(stack.pop());
        }
        // Debug print to show constructed result string
        System.out.println("Constructed result string: " + resultString.reverse().toString());
        return resultString.reverse().toString();
    }
}

