import java.io.InputStream;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.InputMismatchException;

class ResearchMain {
    public static void main(String[] args) {
        FastScanner s = new FastScanner();
        PrintWriter p = new PrintWriter(System.out);

        // Capture input dimensions
        int n = s.nextInt(); 
        int m = s.nextInt(); 

        int res[] = new int[n];
        // Starting backtrack exploration with debug prints
        if (runBacktrack(s, new int[n], new int[n], new int[n + 1], new int[n + 1], new boolean[n + 1], res, 0, n, m, 1)) {
            for (int i = 0; i < n; i++) {
                p.print(res[i]);
                if (i < n - 1) {
                    p.print(' ');
                }
            }
        } else {
            p.print(-1);
        }

        p.flush();
    }

    static boolean runBacktrack(FastScanner s, int blog[], int topic[], int g[][], int gt[], boolean[] used, int res[], int ci, int n, int m, int cur) {
        if (ci == n) {
            return true; // All configurations found
        }

        Arrays.fill(g, 0);
        Arrays.fill(gt, 0);
        Arrays.fill(used, false);

        // Graph construction
        for (int i = 0; i < n - 1; i++) {
            int a = blog[i];
            int b = blog[i + 1];
            g[a][++gt[a]] = b; // Edge from a to b
            g[b][++gt[b]] = a; // Edge from b to a
        }

        // Debug print for graph representation
        System.out.println("Graph at ci = " + ci + ": " + Arrays.deepToString(g));

        for (int i = 0; i < n; i++) {
            used[i + 1] = true;
            for (int j = 1; j <= gt[ci + 1]; j++) {
                if (i + 1 != g[ci + 1][j]) {
                    int nei = g[ci + 1][j];
                    int nt = topic[nei - 1];
                    if (nt == (i + 1)) {
                        break; // Prevent conflict and move to other
                    }
                }
            }
            used[i + 1] = false;
        }

        // Explore topic selections via backtracking
        for (int i = 0; i < n; i++) {
            if (topic[ci] == (i + 1)) {
                if ((!used[i + 1]) && runBacktrack(s, blog, topic, g, gt, used, res, ci + 1, n, m, i + 1)) {
                    return true; // Valid configuration found
                }
            }
        }

        // Try current configuration if within limits
        if (cur <= n) {
            topic[ci] = cur; 
            used[cur] = true;
            res[ci] = cur; 
            if (runBacktrack(s, blog, topic, g, gt, used, res, ci + 1, n, m, cur)) {
                return true; // Successful backtrack continuation
            } else {
                topic[ci] = 0; // Reset if unsuccessful
            }
        }

        // Default false return case
        return false; 
    }
}

