public class ResearchMain {
    static final long MOD = 1000000007L; // Modulo value for large number handling
    static final int INF = 10000000; // Infinite value for comparison
    static final int NINF = -100000; // Negative infinite value for comparison

    public static void main(String[] args) {
        // Fast input reading
        FastScanner sc = new FastScanner();
        PrintWriter pw = new PrintWriter(System.out); // Writer for output

        int Q = sc.ni(); // Number of queries
        for (int q = 0; q < Q; q++) {
            int N = sc.ni(); // Number of elements
            long W = sc.nl(); // Weight threshold
            long[] nums = new long[N]; // Array to hold the numbers

            // Reading input numbers
            for (int i = 0; i < N; i++) {
                nums[i] = sc.nl();
            }

            ArrayList<Integer> ans = new ArrayList<>(); // To store the result indices
            long sum = 0; // Accumulated sum of selected numbers

            // Iterating through numbers to find valid selections
            for (int i = 0; i < N; i++) {
                // Debug prints to analyze the selection process
                System.out.println("Current number: " + nums[i]);

                if (nums[i] > W) continue; // Skip numbers exceeding weight

                // Check if number falls in the desired range
                if (nums[i] >= (W + 1) / 2 && nums[i] <= W) {
                    ans.add(i + 1);
                    System.out.println("Selected index (single): " + (i + 1));
                    break; // Valid selection found
                } 
                // Check if sum can still be valid with current number
                else if (nums[i] < (W + 1) / 2 && sum < (W + 1) / 2) {
                    ans.add(i + 1);
                    sum += nums[i];
                    System.out.println("Adding index (accumulative): " + (i + 1) + ", updated sum: " + sum);
                }
            }

            // Checking the final result conditions
            if (sum < (W + 1) / 2 || ans.size() == 0) {
                pw.println(-1); // No valid selections found
                System.out.println("Result: -1");
            } else {
                // Print the result size and indices
                pw.println(ans.size());
                for (int a : ans) 
                    pw.print(a + " ");
                pw.println();
                System.out.println("Result: " + ans.size() + " indices found: " + ans);
            }
        }
        pw.close(); // Close the writer
    }

    // Fast input scanner class
    static class FastScanner {
        BufferedReader br; // Buffered reader for input
        StringTokenizer st; // Tokenizer for parsing input

        public FastScanner() {
            br = new BufferedReader(new InputStreamReader(System.in)); // Initialize reader
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine()); // Read a new line
                } catch (IOException e) {
                    e.printStackTrace(); // Handle potential IO exceptions
                }
            }
            return st.nextToken(); // Get the next token
        }

        int ni() {
            return Integer.parseInt(next()); // Read next integer
        }

        long nl() {
            return Long.parseLong(next()); // Read next long
        }

        double nd() {
            return Double.parseDouble(next()); // Read next double
        }

        String nextLine() {
            String str = "";
            try {
                str = br.readLine(); // Read a complete line
            } catch (IOException e) {
                e.printStackTrace(); // Handle exceptions
            }
            return str; // Return the line read
        }
    }
}

