    public int minSumOfLengths(int[] arr, int target) {
        // Step 1: Preparing the prefix sum array
        int[] prefixSum = new int[arr.length + 1];
        prefixSum[0] = 0;
        for (int i = 1; i <= arr.length; i++) {
            prefixSum[i] = prefixSum[i - 1] + arr[i - 1];
            // Debug print to track prefix sums
            System.out.println("PrefixSum[" + i + "]: " + prefixSum[i]);
        }

        // Maps to track left and right limits
        Map<Integer, Integer> leftLimit = new HashMap<>();
        Map<Integer, Integer> rightLimit = new HashMap<>();

        // Variables to track current states and results
        int currentLeft = 0, currentRight = 0, shortestLeft = 0, shortestRight = 0;
        int minLength = Integer.MAX_VALUE;
        int minSum = Integer.MAX_VALUE;

        // Step 2: Main processing loop
        for (int j = 1; j < prefixSum.length; j++) {
            currentRight = j;
            target -= prefixSum[j - 1];

            currentLeft = j - 1;
            // Check if target sum matches current right limit
            if (target == prefixSum[currentRight]) {
                if (currentRight > currentLeft + 1) {
                    minLength = Math.min(currentRight, currentLeft + 1);
                    minSum = Math.min(minSum, minLength + rightLimit.getOrDefault(currentLeft + 1, Integer.MAX_VALUE));
                    // Experimental inclusion of previous results
                    if (target + prefixSum[currentRight] == arr[shortestLeft]) {
                        minLength = Math.min(shortestRight + shortestLeft + 1, minLength);
                    }
                }
            }

            // Adjusting current left boundary until we find a suitable match
            while (currentLeft > 0 && target != prefixSum[currentLeft]) {
                target += arr[currentLeft];
                currentLeft--;
            }

            // Updating maps with current state for later access
            rightLimit.put(target, currentRight);
            leftLimit.put(target, currentLeft);
            if (currentLeft != 0 && target == 0) {
                shortestLeft++;
            }
            shortestRight++;

            // Debug prints for intermediate states
            System.out.println("CurrentLeft: " + currentLeft + ", CurrentRight: " + currentRight + ", MinLength: " + minLength + ", MinSum: " + minSum);
        }

        // Final adjustment if no valid pairs were found
        if (minSum == Integer.MAX_VALUE) minSum = -1;
        return minSum;
    }
}

