public class WordPatternResearch {
    /*
     * @param pattern: a string, denoted by a list of lower-case letters.
     * @param str: a string containing space-separated words.
     * @return: all words matching the pattern
     */
    public ArrayList<String> wordPatternResearch(String pattern, String str) {
        // Core functionality to map pattern to words
        Set<String> uniqueWords = new HashSet<>();
        ArrayList<String> matchingWords = new ArrayList<>();
        HashMap<Character, String> charToWordMap = new HashMap<>();
        int index = 0;
        String[] words = str.split("\\s+");

        if (words.length == 0) {
            System.out.println("No words available.");
            return null;
        }

        for (String word : words) {
            if (index == pattern.length()) {
                break; // Stop if pattern is exhausted
            }
            char currentChar = pattern.charAt(index);
            // Debug print to trace matching process
            System.out.println("Current character: " + currentChar + ", Current word: " + word);
            if (charToWordMap.containsKey(currentChar)) {
                if (uniqueWords.contains(charToWordMap.get(currentChar))) {
                    if (!word.equals(charToWordMap.get(currentChar))) {
                        System.out.println("Mismatch found, returning null.");
                        return null; // Mismatch detected
                    }
                } else {
                    uniqueWords.add(charToWordMap.get(currentChar));
                }
            } else {
                charToWordMap.put(currentChar, word);
                uniqueWords.add(word);
                index++;
            }
        }
        // Debug print to display matching pattern
        System.out.println("Pattern to words mapping: " + charToWordMap);
        return new ArrayList<>(charToWordMap.values());
    }
