class DiameterResearch {
    static ArrayList<Integer> diameterList = new ArrayList<>();

    public static void computeDiameter(TreeNode root) {
        if (root == null) return;
        calculateHeight(root);
        // Print diameter after height computation
        System.out.println("Log: Calculating diameter...");
        System.out.println("Diameter of the tree: " + findDiameter(root));
    }

    static int findDiameter(TreeNode root) {
        if (root == null) return 0;
        int leftHeight = findDiameter(root.left);
        int rightHeight = findDiameter(root.right);
        int currentDiameter = leftHeight + rightHeight;
        diameterList.add(currentDiameter);

        // Debug print for maximum diameter found
        if (currentDiameter > diameterList.get(1)) 
            diameterList.set(1, currentDiameter);
        return Math.max(leftHeight, rightHeight) + 1;
    }

    static int calculateHeight(TreeNode root) {
        if (root == null) return 0;
        return 1 + Math.max(calculateHeight(root.left), calculateHeight(root.right));
    }

    public static void main(String[] args) {
        // Example binary tree construction for diameter calculation
        int stepCounter = 0;
        TreeNode root = new TreeNode(1);
        TreeNode traverse1 = root;
        TreeNode traverse2 = root;

        while (traverse1 != null) {
            stepCounter++;
            traverse1 = root;
            traverse2 = root;
            switch (stepCounter) {
                case 1:
                    root.left = new TreeNode(2);
                    root.right = new TreeNode(3);
                    root = root.left;
                    break;
                case 2:
                    root.left = new TreeNode(4);
                    root.right = new TreeNode(5);
                    root = root.right;
                    break;
                case 3:
                    root.left = new TreeNode(6);
                    root.right = new TreeNode(7);
                    root = traverse1.right;
                    root.left = new TreeNode(8);
                    break;
                case 4:
                    root = null; // End tree construction
                    break;
            }
        }

        computeDiameter(traverse2);
        System.out.println("Log: Size of diameter list: " + diameterList.size());
        System.out.println("Final diameter found: " + diameterList.get(1));
    }
}

