class Solution {
    public boolean canPartition(String s) {
        // Starting depth-first search
        System.out.println("Starting partitioning for string: " + s);
        boolean result = dfs(s, 0, 0, 0);
        System.out.println("Result of partitioning: " + result);
        return result;
    }

    private boolean dfs(String s, int i, int l1, int l2) {
        // Debugging current state
        System.out.printf("DFS at index %d: l1 = %d, l2 = %d\n", i, l1, l2);

        if (i == s.length()) {
            boolean isEqual = l1 == l2;
            System.out.printf("Reached end: l1 = %d, l2 = %d, equal = %b\n", l1, l2, isEqual);
            return isEqual;
        }

        // Investigating both choices: adding current character to l1 or l2
        boolean useForL1 = dfs(s, i + 1, l1 + s.charAt(i) - 'a' + 1, l2);
        if (useForL1) {
            System.out.printf("Character '%c' at index %d added to l1, path leads to a solution.\n", s.charAt(i), i);
            return true;
        }

        boolean useForL2 = dfs(s, i + 1, l1, l2 + s.charAt(i) - 'a' + 1);
        if (useForL2) {
            System.out.printf("Character '%c' at index %d added to l2, path leads to a solution.\n", s.charAt(i), i);
            return true;
        }

        System.out.printf("Backtracking at index %d: no solution found.\n", i);
        return false;
    }
}

