public List<List<Integer>> generateCombinations(List<Integer> baseNums, int combinationSize) {
    List<List<Integer>> combinations = new ArrayList<>();

    if (combinationSize == 1) {
        for (Integer num : baseNums) {
            List<Integer> singleElementList = new ArrayList<>();
            singleElementList.add(num);
            combinations.add(singleElementList);
        }
        return combinations;
    }

    List<Integer> tempCombination = new ArrayList<>();

    for (int i = 0; i <= baseNums.size() - combinationSize; i++) {
        tempCombination.addAll(baseNums.subList(i, i + combinationSize));
        List<List<Integer>> smallerCombinations = generateCombinations(tempCombination, combinationSize - 1);

        for (List<Integer> subset : smallerCombinations) {
            subset.add(0, baseNums.get(i));
            combinations.add(subset);
        }

        tempCombination.clear(); // Clear temporary list for next iterations
    }

    return combinations;
}

public int calculateMaxHeight(int[] sequence, boolean isOrdered) {
    int maxHeight = 0;
    int previousMax = 0;

    for (int number : sequence) {
        if (number > previousMax) {
            maxHeight += number; // Add current number if it's larger than previous max
        } else {
            maxHeight += previousMax; // Else, add previous max
        }
        previousMax = Math.max(previousMax, number);
    }

    int resultHeight = (sequence.length == 1) ? sequence[0] : maxHeight;

    if (isOrdered) {
        System.out.println("Sequence: " + Arrays.toString(sequence) + " | Max Height: " + resultHeight);
    }

    return resultHeight;
}

