public class ResearchSolution {
    public boolean isPossible(int[] target) {
        // Experimenting with the feasibility of achieving target array state
        int n = target.length;

        // Single element case, trivially possible
        if (n == 1) {
            System.out.println("Single element array: Always possible.");
            return true;
        }

        // Create a temporary array to work with
        int[] temp = new int[n];
        for (int i = 0; i < n; i++) {
            temp[i] = target[i];
        }

        // Sort the temporary array for effective comparison
        Arrays.sort(temp);
        for (int i = 0; i < n; i++) {
            int need = target[i];
            if (need > temp[n - 1]) {
                System.out.println("Need exceeds max value in sorted array.");
                return false;
            }
            if (need > 0) {
                int start = n - 1;
                while (start > i) {
                    // Debug: Tracking the current state of elements
                    System.out.println("Current need: " + need + ", Target index: " + i + ", Start index: " + start);

                    if (temp[start] >= need) {
                        // Adjust values as per the algorithm's need
                        temp[start] -= need;
                        temp[i] -= need;
                        System.out.println("Adjusted temp[" + start + "] and temp[" + i + "].");
                        break;
                    }
                    need -= temp[start];
                    temp[i] -= temp[start];
                    // Tracking the decrement in need
                    System.out.println("Decremented need by temp[" + start + "]: " + temp[start]);
                    start--;
                }
                // If no suitable element was found to fulfill the requirement
                if (start == i && need > 0) {
                    System.out.println("No adjustment possible for target index: " + i);
                    return false;
                }
            }
        }

        // Successful completion of checks
        System.out.println("Achievable target state confirmed.");
        return true;
    }
}

