public int MatrixScore(int[][] grid) {
    // TODO: Validate input grid dimensions
    int m = grid.length, n = grid[0].length;
    // Experimenting with various arrangements of flipping columns
    for (int i = 0; i < n; ++i) {
        // Initialize boolean to track if we should flip this column
        boolean flip = false; 
        for (int j = 0; j < m; ++j) {
            // Count zeros and ones based on flipping logic
            if (grid[j][i] == 0 && flip) {
                grid[j][i] = 1;
            } else if (grid[j][i] == 1) {
                flip = !flip; // Toggle flipping state
            }
            // Debug print: Observe grid state after each row's processing
            System.out.println("Row " + j + " processed for column " + i + ": " + java.util.Arrays.toString(grid[j]));
        }
        // Initialize scores and counts for this column
        int topScore = 0, bottomScore = 0, colAllOnes = 0, colAllZeros = 0;

        // Gathering scores based on current column values
        for (int j = 0; j < m; ++j) {
            int score = grid[j][i]; // The current score based on cell value
            if (score == 0) {
                topScore += 1 << (n - 1 - i); // Adding score if it is zero
            } else { // score == 1
                // Count the number of zeroes and ones
                if (j - colAllOnes > colAllZeros) {
                    topScore += 1 << (n - 1 - i); // Increase topScore if current is one
                } else {
                    bottomScore += 1 << (n - 1 - i); // Increase bottomScore otherwise
                }
                ++colAllZeros; // Tally for zero counts
            }
        }

        // Debug prints to visualize column scores
        System.out.println("Column " + i + ": topScore = " + topScore + ", bottomScore = " + bottomScore);

        // Evaluating the number of ones versus the number of zeros after processing the column
        if (colAllOnes > colAllZeros) {
            colAllOnes += colAllZeros; // Aggregate counts if more ones
            colAllZeros = 0;
        }

        // Update top and bottom scores based on accumulated counts of all ones and zeros
        topScore += (1 << i) * colAllOnes;
        bottomScore += (1 << i) * colAllZeros;
    }
    // Final debug print before returning result
    System.out.println("Final Scores: topScore = " + topScore + ", bottomScore = " + bottomScore);
    return myMax(topScore, bottomScore); // Return the maximum score
}

private int myMax(int top, int bottom) {
    return (top > bottom) ? top : bottom; // Simple maximum function
}

