                                  (badTriangleIndex / size + 1), 
                                  ((badTriangleIndex % size) / size + 2), 
                                  ((badTriangleIndex + (size - (badTriangleIndex / size) - 1)) / size + 1));
            } else {
                System.out.println("No bad triangle found");
            }
        }
