                int dy = p.y == d0.y ? 0 : (Math.abs(d0.y - p.y) / 2);
                x0 += (p.x * d0.x) / Math.sqrt(p.x * p.x + p.y * p.y) + 
                       (y0 + d0.y) / Math.sqrt(p.x * p.x + p.y * p.y) * (dx - dy);
                y0 += (y0 + d0.y) / Math.sqrt(p.x * p.x + p.y * p.y) +
                       (p.x * d0.x) / Math.sqrt(p.x * p.x + p.y * p.y) * (dy - dx);
            }
        }

        double b = Math.sqrt(Math.pow(con[0] - x0, 2) + Math.pow(con[1] - y0, 2));
