public class ResearchPrototype {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);

        // Initialize test case count
        int t = Integer.parseInt(br.readLine());
        System.out.println("Number of test cases: " + t);

        while (t-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            System.out.println("Processing grid of size: " + n + "x" + m);

            char[][] grid = new char[n][m];
            for (int i = 0; i < n; i++) {
                grid[i] = br.readLine().toCharArray();
            }

            List<List<Integer>> results = new ArrayList<>();
            System.out.println("Initial grid:");
            printGrid(grid);

            // Begin process of finding pairs
            for (int i = 0; i < n - 1; i++) {
                for (int j = 0; j < m - 1; j++) {
                    if (grid[i][j] == '1') {
                        processPair(i, j, grid, results);
                    }
                }
            }

            // Check for rightmost column
            for (int i = 0; i < n - 1; i++) {
                if (grid[i][m - 1] == '1') {
                    processRightColumnPair(i, m, grid, results);
                }
            }

            // For debugging purposes, show the results
            System.out.println("List of pairs processed: " + results);
            pw.flush();
        }
        pw.close();
    }

    private static void processPair(int i, int j, char[][] grid, List<List<Integer>> results) {
        List<Integer> coordinates = new ArrayList<>();
        coordinates.add(i); coordinates.add(j);
        coordinates.add(i); coordinates.add(j + 1);
        coordinates.add(i + 1); coordinates.add(j + 1);
        results.add(coordinates);

        coordinates = new ArrayList<>();
        coordinates.add(i); coordinates.add(j);
        coordinates.add(i + 1); coordinates.add(j);
        coordinates.add(i + 1); coordinates.add(j + 1);
        results.add(coordinates);

        // Toggle the values in the grid
        grid[i][j] = '0';
        flipValue(grid, i, j + 1);
        flipValue(grid, i + 1, j);
        flipValue(grid, i + 1, j + 1);
    }

    private static void processRightColumnPair(int i, int m, char[][] grid, List<List<Integer>> results) {
        List<Integer> coordinates = new ArrayList<>();
        coordinates.add(i); coordinates.add(m - 1);
        coordinates.add(i + 1); coordinates.add(m - 1);
        coordinates.add(i + 1); coordinates.add(m - 2);
        results.add(coordinates);
    }

    private static void flipValue(char[][] grid, int i, int j) {
        grid[i][j] = (char) ('0' + (1 - (grid[i][j] - '0')));
    }

    private static void printGrid(char[][] grid) {
        for (char[] row : grid) {
            System.out.println(Arrays.toString(row));
        }
    }
}

import java.util.*;

class Solution {
    public String findLexSmallestString(String s, int a, int b) {
        // TODO: Initialize structures for tracking visited strings and BFS queue
        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.offer(s);
        visited.add(s);

        // Initialize result with the input string
        String result = s;

        // Perform BFS
        while (!queue.isEmpty()) {
            String current = queue.poll();

            // Debug print: Current string under evaluation
            System.out.println("Evaluating: " + current);

            // Check if current string is lexicographically smaller
            if (current.compareTo(result) < 0) {
                result = current;
                System.out.println("Found new minimum: " + result);
            }

            // Generate new string by adding 'a'
            String addA = addA(current, a);
            if (!visited.contains(addA)) {
                queue.offer(addA);
                visited.add(addA);
                // Debug print: Added string via addA
                System.out.println("Adding via addA: " + addA);
            }

            // Generate new string by rotating
            String rotate = rotate(current, b);
            if (!visited.contains(rotate)) {
                queue.offer(rotate);
                visited.add(rotate);
                // Debug print: Added string via rotation
                System.out.println("Adding via rotation: " + rotate);
            }
        }

        // Final output string
        return result;
    }

    // Function to add 'a' to odd indexed digits
    private String addA(String s, int a) {
        // TODO: Consider edge cases for string modification
        StringBuilder sb = new StringBuilder(s);
        for (int i = 1; i < s.length(); i += 2) {
            int digit = (s.charAt(i) - '0' + a) % 10;
            sb.setCharAt(i, (char) ('0' + digit));
        }
        return sb.toString();
    }

    // Function to rotate the string by 'b' positions
    private String rotate(String s, int b) {
        // Normalize b to prevent unnecessary rotations
        b = b % s.length();
        return s.substring(s.length() - b) + s.substring(0, s.length() - b);
    }
}

import java.util.LinkedList;

class AVLNode {
    int order;
    int seatNumber;
    int height;
    AVLNode left, right;

    AVLNode(int order, int seatNumber) {
        this.order = order;
        this.seatNumber = seatNumber;
        this.height = 1;
    }
}

class AVLTree {
    private AVLNode root;

    int getHeight(AVLNode node) {
        return node == null ? 0 : node.height;
    }

    int getBalance(AVLNode node) {
        return node == null ? 0 : getHeight(node.left) - getHeight(node.right);
    }

    AVLNode rightRotate(AVLNode y) {
        AVLNode x = y.left;
        AVLNode T2 = x.right;

        x.right = y;
        y.left = T2;

        y.height = Math.max(getHeight(y.left), getHeight(y.right)) + 1;
        x.height = Math.max(getHeight(x.left), getHeight(x.right)) + 1;

        return x;
    }

    AVLNode leftRotate(AVLNode x) {
        AVLNode y = x.right;
        AVLNode T2 = y.left;

        y.left = x;
        x.right = T2;

        x.height = Math.max(getHeight(x.left), getHeight(x.right)) + 1;
        y.height = Math.max(getHeight(y.left), getHeight(y.right)) + 1;

        return y;
    }

    AVLNode insert(AVLNode node, int order, int seatNumber) {
        if (node == null) {
            System.out.println("Inserting order: " + order + ", seatNumber: " + seatNumber);
            return new AVLNode(order, seatNumber);
        }

        if (order < node.order) {
            node.left = insert(node.left, order, seatNumber);
        } else if (order > node.order) {
            node.right = insert(node.right, order, seatNumber);
        } else {
            System.out.println("Duplicate order found: " + order);
            return node; // Duplicate orders not allowed
        }

        node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right)));

        int balance = getBalance(node);
        if (balance > 1 && order < node.left.order) return rightRotate(node);
        if (balance < -1 && order > node.right.order) return leftRotate(node);
        if (balance > 1 && order > node.left.order) {
            node.left = leftRotate(node.left);
            return rightRotate(node);
        }
        if (balance < -1 && order < node.right.order) {
            node.right = rightRotate(node.right);
            return leftRotate(node);
        }

        return node;
    }

    AVLNode minNode(AVLNode node) {
        System.out.println("Finding minNode");
        AVLNode current = node;
        while (current.left != null) {
            current = current.left;
        }
        return current;
    }

    AVLNode deleteNode(AVLNode root, int order) {
        if (root == null) {
            System.out.println("Node to delete not found: " + order);
            return root;
        }

        if (order < root.order) {
            root.left = deleteNode(root.left, order);
        } else if (order > root.order) {
            root.right = deleteNode(root.right, order);
        } else {
            System.out.println("Deleting node: " + root.order);
            if ((root.left == null) || (root.right == null)) {
                AVLNode temp = root.left != null ? root.left : root.right;
                root = temp;
            } else {
                AVLNode temp = minNode(root.right);
                root.order = temp.order;
                root.seatNumber = temp.seatNumber;
                root.right = deleteNode(root.right, temp.order);
            }
        }

        if (root == null) {
            return root;
        }

        root.height = 1 + Math.max(getHeight(root.left), getHeight(root.right)));

        int balance = getBalance(root);
        if (balance > 1 && getBalance(root.left) >= 0) return rightRotate(root);
        if (balance > 1 && getBalance(root.left) < 0) {
            root.left = leftRotate(root.left);
            return rightRotate(root);
        }
        if (balance < -1 && getBalance(root.right) <= 0) return leftRotate(root);
        if (balance < -1 && getBalance(root.right) > 0) {
            root.right = rightRotate(root.right);
            return leftRotate(root);
        }

        return root;
    }

    void displayInOrder(AVLNode node) {
        if (node != null) {
            displayInOrder(node.left);
            System.out.println("Order: " + node.order + ", Seat: " + node.seatNumber);
            displayInOrder(node.right);
        }
    }

    void runExperiments() {
        root = insert(root, 3, 1);
        root = insert(root, 1, 2);
        root = insert(root, 2, 5);
        root = insert(root, 3, 4);

        System.out.println("In-order traversal after insertions:");
        displayInOrder(root);

        root = deleteNode(root, 3);
        System.out.println("In-order traversal after deletion:");
        displayInOrder(root);
    }
}

public class Main {
    public static void main(String[] args) {
        AVLTree avlTree = new AVLTree();
        avlTree.runExperiments();
    }
}

