        }
        out.close();
    }

    private static boolean isConfigurationPossible(int k, int max, TreeSet<Integer> uniqueValues) {
        while (!uniqueValues.isEmpty()) {
            // Initialize an array to hold current k elements
            int[] chosenElements = new int[k];
            Iterator<Integer> iterator = uniqueValues.iterator();
            for (int i = 0; i < k && iterator.hasNext(); i++) {
                chosenElements[i] = iterator.next();
            }
            int min = Integer.MAX_VALUE;
            // Finding the minimum among chosen elements
            for (int num : chosenElements) {
                min = Math.min(min, num);
            }
            boolean foundPair = false;
            // Check configuration feasibility
            for (int i = 0; i < k; i++) {
                if (chosenElements[i] == min && !uniqueValues.isEmpty()) {
                    // Additional debug print - configuration attempt
                    System.err.println("Attempting configuration with k=" + k + " and min=" + min);
                    foundPair = true;
                    uniqueValues.remove(chosenElements[i]);
                    break; // Exit after processing current min
                }
            }
            // If no valid pair is found with the current k, return false
            if (!foundPair) {
                return false;
            }
        }
        return true; // Valid configuration found
    }
}

