class Solution {
    public List<Boolean> canMakePaliQueries(String s, int[][] queries) {
        List<Boolean> result = new ArrayList<>();

        // Step 1: Initialize frequency table
        int[][] frequency = new int[s.length()][26];
        for (int i = 0; i < s.length(); i++) {
            char currentChar = s.charAt(i);
            frequency[i][currentChar - 'a'] = i == 0 ? 1 : frequency[i - 1][currentChar - 'a'] + 1;

            // Copy previous values and update current character count
            for (int j = 0; j < 26; j++) {
                frequency[i][j] = frequency[i][j] + (j == currentChar - 'a' ? 0 : frequency[i - 1][j]);
            }
        }

        // Step 2: Process each query
        for (int[] query : queries) {
            int left = query[0], right = query[1], maxChanges = query[2];
            // Calculate character frequencies in the substring s[left:right+1]
            int oddCount = 0; // To track the number of characters with odd frequencies

            for (int j = 0; j < 26; j++) {
                int charFrequency = frequency[right][j] - (left == 0 ? 0 : frequency[left - 1][j]);
                if (charFrequency % 2 != 0) {
                    oddCount++;
                }
            }

            // Check if we can make a palindrome based on odd counts and allowed changes
            // Debug printing for verification
            System.out.printf("Query [%d, %d, %d]: Odd Counts = %d\n", left, right, maxChanges, oddCount);

            if (oddCount / 2 <= maxChanges) {
                result.add(true);
            } else {
                result.add(false);
            }
        }

        // Final result
        return result;
    }
}

