            return 0;  // Termination condition
        // Recursive calculation with memoization potential
        return (calculateDP(a, n, i + 1, j, l) > 1 ? calculateDP(a, n, i + 1, j, l) + 1 : 0) + 
               (calculateDP(a, n, i, j + 1, l) > 1 ? calculateDP(a, n, i, j + 1, l) + 1 : 0);
    }

    static void extractMaxSum(int matrix[][], int detail, List<Integer> left, List<Integer> right, int m) 
    {
        int max_size = 1;
        if(matrix[m - 1][m - 1] == -1) return;  // Early return for invalid matrix values

        if(detail > max_size) 
        {
            left.clear();
            right.clear();
            int[] nextMaxSum = new int[13];
            int[] nextLeft = new int[13];
            nextMaxSum[m - detail] = matrix[m - detail][m - 1]; // Track maximum sums
            int j = Math.min(m - detail + 1, matrix.length - 2);
            while(j >= 1 && left.get(j) == m - j + 1)
            {
                j--;
            }

            nextLeft[j] = left.get(j) + 1;
            int i = j - detail + 1; 
            while(i >= 1 && right.get(i) == m - i + (m - i) + 1)
            {
                i--;
            }
            nextRight[i] = right.get(i) + 1;
            // Determine path based on lengths of sides
            if(nextLeft[i] >= nextRight[i]) 
            {
                i = nextRight[i];
                j = nextLeft[i];
