public class UniquePalindromicSubstrings {

    // TODO: Optimize to reduce space complexity, if required.
    public static int countSubstrings(String s) {
        int n = s.length();
        boolean[][] dp = new boolean[n][n];
        int ans = 0;

        // DEBUG: Initial state of DP array.
        System.out.println("Initial DP array: " + Arrays.deepToString(dp));

        for (int i = n - 1; i >= 0; i--) {
            for (int j = i; j < n; j++) {
                dp[i][j] = (s.charAt(i) == s.charAt(j)) && ((j - i + 1 < 3) || dp[i + 1][j - 1]);
                if (dp[i][j]) {
                    ans++; // Count unique palindromic substring.
                }
            }
        }

        // DEBUG: Final state of DP array and result.
        System.out.println("Final DP array: " + Arrays.deepToString(dp));
        return ans;
    }

    public static void main(String[] args) {
        // TODO: Test performance with longer strings to study behavior.
        String s = "aabca";
        System.out.println("Number of unique palindromic substrings: " + countSubstrings(s));
    }
}


