class Solution {
    public double[] calcEquation(String[][] equations, double[] values, String[][] queries) {
        // Initialize a graph representation for the equations
        HashMap<String, HashMap<String, Double>> graph = new HashMap<>();

        // Populate the graph with equations and their corresponding values
        for (int i = 0; i < equations.length; i++) {
            String[] equation = equations[i];
            String x = equation[0];
            String y = equation[1];

            // Debug: Tracking insertion into graph
            System.out.println("Inserting: " + x + " / " + y + " = " + values[i]);

            // For each equation, create edges in the graph
            graph.putIfAbsent(x, new HashMap<>());
            graph.get(x).put(y, values[i]);
            graph.putIfAbsent(y, new HashMap<>());
            graph.get(y).put(x, 1 / values[i]);
        }

        // Prepare results for the queries
        double[] res = new double[queries.length];
        for (int i = 0; i < queries.length; i++) {
            String[] query = queries[i];
            String x = query[0];
            String y = query[1];

            // Debug: Current query being processed
            System.out.println("Processing query: " + x + " / " + y);
            res[i] = dfs(graph, x, y, new HashSet<>());
            // Debug: Result of the query
            System.out.println("Query result: " + res[i]);
        }
        return res;
    }

    public double dfs(HashMap<String, HashMap<String, Double>> graph, String node, String goal, HashSet<String> visited) {
        // Check if the node exists in the graph
        if (!graph.containsKey(node)) {
            return -1; // Node not found case
        }

        // Check if we've already visited this node to avoid cycles
        if (visited.contains(node)) {
            return -1; // Cyclic path
        }

        // If the node is the goal, return the multiplicative identity
        if (node.equals(goal)) {
            return 1;
        }

        visited.add(node); // Mark node as visited
        double res = -1;

        // Explore all edges from the current node
        for (String neighbor : graph.get(node).keySet()) {
            double weight = graph.get(node).get(neighbor);
            // Debug: Exploring neighbor
            System.out.println("Exploring: " + node + " -> " + neighbor + " with weight " + weight);
            double currRes = dfs(graph, neighbor, goal, visited);
            if (currRes != -1) {
                res = weight * currRes; // Calculate resultant value
                break; // Path found, exit loop
            }
        }

        visited.remove(node); // Unmark node on backtrack
        return res; // Return result of dfs
    }
}

