import java.util.LinkedList;
import java.util.List;

public class WordSeparator {

    // TODO: Investigate the efficiency of this method for larger input sizes
    public List<String> split(List<String> words, char separator) {
        List<String> result = new LinkedList<>();
        // Debug: Track the number of words processed
        System.out.println("Total words to process: " + words.size());

        for (String w : words) {
            // TODO: Handle edge cases for null or empty strings
            if (w == null || w.isEmpty()) {
                System.out.println("Skipping empty string");
                continue;
            }

            // Debug: Print current word being processed
            System.out.println("Processing word: " + w);
            int index = w.indexOf(separator);
            while (index != -1) {
                String part = w.substring(0, index).trim();
                // Debug: Print the part extracted
                System.out.println("Extracted part: '" + part + "'");

                if (!part.isEmpty()) {
                    result.add(part);
                }

                index = w.indexOf(separator, index + 1);
            }
            // Add the trimmed word after processing
            result.add(w.trim());
        }

        // Debug: Print final result for verification
        System.out.println("Resulting split parts: " + result);
        return result;
    }

    static List<String> separate(List<String> words, char separator) {
        List<String> separatedWords = new LinkedList<>();
        // Debug: Track overall processing
        System.out.println("Beginning separation of words. Total: " + words.size());

        for (int i = 0; i < words.size(); i++) {
            String currentWord = words.get(i);
            // TODO: Validate that currentWord is not null
            if (currentWord == null) {
                System.out.println("Found null word at index " + i);
                continue;
            }

            // Debug: Log index of separator for current word
            System.out.println("Current word: " + currentWord);
            int index = currentWord.indexOf(separator);

            // Debug: Check the presence of separator
            if (index != -1) {
                System.out.println("Separator found at index: " + index);
            }

            for (; index != -1; index = currentWord.indexOf(separator, index + 1)) {
                String part = currentWord.substring(0, index).trim();
                if (!part.isEmpty()) {
                    separatedWords.add(part);
                    // Debug: Show each part added
                    System.out.println("Part added: '" + part + "'");
                }
            }
            // Trim and add the last part of the word
            separatedWords.add(currentWord.trim());
        }

        // Debug: Final output for separation
        System.out.println("Separated words: " + separatedWords);
        return separatedWords;
    }
}

